function Deps.detect_platform()
  local os_str  = reaper.GetOS() or ""
  local app_ver = reaper.GetAppVersion() or ""
  -- Capture EVERYTHING after the last slash, hyphens included. REAPER's
  -- Linux build labels arch as e.g. "7.20/linux-aarch64", and the
  -- previous /([%w_]+)$ pattern (no hyphens in class) failed to match
  -- the prefixed form -- silently falling through to linux-x64 on ARM.
  local arch = app_ver:match("/([^/]+)$") or ""
  if os_str == "Win64" then
    return arch:find("x86", 1, true) and not arch:find("x86_64", 1, true)
           and "win-x86" or "win-x64"
  elseif os_str == "Win32" then
    return "win-x86"
  elseif os_str == "OSX64" then
    return "mac-x64"
  elseif os_str == "OSX32" then
    return "mac-x86"
  elseif os_str == "macOS-arm64" then
    return "mac-arm64"
  elseif os_str == "Other" then
    -- Substring checks rather than equality so "linux-aarch64",
    -- "aarch64", "linux-armv7l", "armv7l" etc. all map cleanly.
    if     arch:find("aarch64", 1, true) then return "linux-arm64"
    elseif arch:find("armv7",   1, true) then return "linux-arm32"
    elseif arch:find("i686",    1, true) or arch:find("i386", 1, true) then
      return "linux-x86"
    else return "linux-x64"  -- best guess for x86_64 / x64 / unspecified
    end
  end
  return nil
end

function Deps.parse_version(s)
  -- Accepts "v0.10.0.5", "0.10.0.5", "0.10". Returns numeric component table.
  local t = {}
  for n in tostring(s or ""):gsub("^v", ""):gmatch("(%d+)") do
    t[#t + 1] = tonumber(n)
  end
  return t
end

function Deps.cmp_version(a, b)
  -- -1 if a < b, 0 if equal, 1 if a > b. Pads missing components with 0.
  local n = math.max(#a, #b)
  for i = 1, n do
    local ai, bi = a[i] or 0, b[i] or 0
    if ai < bi then return -1 end
    if ai > bi then return  1 end
  end
  return 0
end

function Deps.check_imgui_status()
  -- Returns "ok" | "missing" | "too_old" [, installed_version_string]
  if not reaper.ImGui_CreateContext then return "missing" end
  if not reaper.ImGui_GetVersion    then return "ok" end  -- pre-version-API; assume OK
  local ok, _, _, reaimgui_ver = pcall(reaper.ImGui_GetVersion)
  if not ok or not reaimgui_ver then return "ok" end
  local installed = Deps.parse_version(reaimgui_ver)
  if Deps.cmp_version(installed, Deps.REAIMGUI.min_version_num) < 0 then
    return "too_old", reaimgui_ver
  end
  return "ok"
end

function Deps.check_jsapi_status()
  -- Presence-only check (upstream is frozen at v1.310 since 2021).
  if SupportExtFlag("optoutjsapi") then return "ok" end
  return reaper.JS_ReaScriptAPI_Version and "ok" or "missing"
end

function Deps.check_sws_status()
  -- Returns "ok" | "missing" | "too_old" [, installed_version_string].
  if SupportExtFlag("optoutsws") then return "ok" end
  if not reaper.CF_GetSWSVersion then return "missing" end
  local ok, ver = pcall(reaper.CF_GetSWSVersion)
  if not ok or not ver or ver == "" then
    ok, ver = pcall(reaper.CF_GetSWSVersion, "")
  end
  if not ok or not ver or ver == "" then return "ok" end
  local installed = Deps.parse_version(ver)
  if Deps.cmp_version(installed, Deps.SWS.min_version_num) < 0 then
    return "too_old", ver
  end
  return "ok", ver
end

function Deps.prefer_screen_reader_enabled()
  return reaper.GetExtState
     and reaper.GetExtState("reaassist", "prefer_screen_reader") == "1"
end

function Deps.screen_reader_intent()
  if rawget(_G, "REAASSIST_SCREEN_READER_MODE") == true then return true end
  return Deps.prefer_screen_reader_enabled()
end

-- Build the install queue for the current platform. Order: ReaImGui
-- first (UI dependency, blocks anything from rendering), SWS second
-- when REQUIRE_SWS_EXTENSION is enabled (expanded script API surface),
-- JS_API last
-- (file dialogs, only blocks save/attach UX). Each queue item carries
-- everything the install pipeline needs: dep table, asset filename,
-- expected SHA, full destination path under UserPlugins/, and the
-- "kind" of install (missing vs. too_old) for messaging.
--
-- Skips deps whose platform has no upstream binary (e.g. js_ReaScriptAPI
-- on linux-arm64): the script still works on those platforms via the
-- existing fallback paths (GetUserInputs save, no-op attach), so we
-- silently drop the unsupported dep rather than block the install flow.
function Deps.build_queue(platform, screen_reader_intent)
  local queue = {}
  local user_plugins = reaper.GetResourcePath() .. "/UserPlugins/"

  if not screen_reader_intent then
    local imgui_status, imgui_ver = Deps.check_imgui_status()
    if imgui_status ~= "ok" then
      local entry = Deps.REAIMGUI.assets[platform]
      if entry then
        queue[#queue + 1] = {
          dep           = Deps.REAIMGUI,
          kind          = imgui_status,             -- "missing" or "too_old"
          installed_ver = imgui_ver,
          asset         = entry[1],
          expected_sha  = entry[2],
          dest_path     = user_plugins .. entry[1],
        }
      end
    end
  end

  if REQUIRE_SWS_EXTENSION and not SupportExtFlag("optoutsws") then
    local sws_status, sws_ver = Deps.check_sws_status()
    if sws_status ~= "ok" then
      local entry = Deps.SWS.assets[platform]
      if entry then
        queue[#queue + 1] = {
          dep           = Deps.SWS,
          kind          = sws_status,             -- "missing" or "too_old"
          installed_ver = sws_ver,
          asset         = entry[1],
          expected_sha  = entry[2],
          dest_path     = user_plugins .. entry[1],
        }
      end
    end
  end

  local jsapi_status = Deps.check_jsapi_status()
  if jsapi_status ~= "ok" then
    local entry = Deps.JSAPI.assets[platform]
    if entry then
      queue[#queue + 1] = {
        dep           = Deps.JSAPI,
        kind          = jsapi_status,             -- always "missing"
        installed_ver = nil,
        asset         = entry[1],
        expected_sha  = entry[2],
        dest_path     = user_plugins .. entry[1],
      }
    end
  end

  return queue
end

function Deps.cleanup_stale_backups(platform)
  if not platform then return end
  local user_plugins = reaper.GetResourcePath() .. "/UserPlugins/"
  local deps = { Deps.REAIMGUI, Deps.SWS, Deps.JSAPI }
  for _, dep in ipairs(deps) do
    local entry = dep.assets[platform]
    if entry then
      local dest = user_plugins .. entry[1]
      local f = io.open(dest, "rb")
      if f then
        f:close()
        -- Left by successful loaded-DLL replacement when the OS keeps the
        -- old mapped binary open until REAPER exits. Safe best-effort only:
        -- never delete the backup if the real dependency file is absent.
        os.remove(dest .. ".bak")
      end
    end
  end
end

