  -- progress bar in render_running.
  status            = "",
  error_msg         = nil,
  error_step        = nil,
  platform          = nil,
  -- Install queue: ordered list of items to install. Each item is the
  -- table built by Deps.build_queue (dep / kind / installed_ver / asset
