    track  = nil,   -- temp MediaTrack
    ident  = nil,   -- plugin identifier being rescanned
    fx_idx = -1,
    status = "",
    deep   = false, -- if true, use coroutine-based defer-paced scanner
  },
  -- Batch rescan state (Rescan All on the FX Cache page). Queues every
  -- cached plugin and feeds them through `rescan` one at a time so there
  -- is never more than one temp track / plugin load in flight.
  rescan_all = {
    active    = false,
    queue     = {},     -- list of remaining idents to scan (FIFO)
    total     = 0,      -- total queue size when started
    index     = 0,      -- 1-based count of plugins started so far
    current   = nil,    -- ident currently in flight (for display)
    failures  = {},     -- idents that failed to load (missing plugins)
  },
}

-- Deep FX scan state (coroutine-paced param probe for laggy VST3 plugins).
-- Resumed one step per frame from loop(); kicks its completion callback
-- when the coroutine finishes or is cancelled.
deep_scan = {
  active      = false,
  coro        = nil,          -- running coroutine
  tr          = nil,          -- temp MediaTrack holding the plugin
  fx_idx      = -1,
  identifier  = nil,
  search_names= nil,          -- for chat-status display
  started_at  = 0,            -- time_precise() at start (for elapsed display)
  probes_done = 0,
  origin      = nil,          -- "chat" | "fx_cache" (who to notify on completion)
  on_complete = nil,          -- function(params_list, max_group, total_count)
  on_cancel   = nil,          -- function() called if user cancels / errors
  cancel_req  = false,
}

-- =============================================================================
-- Auto-update state
-- =============================================================================
update = {
  -- State machine: idle -> checking -> verifying -> (available |
  -- repair_available | idle); user click -> downloading -> rename_retry?
  -- -> done; any error -> failed (with last_step / last_error stamped
  -- by Updater._set_failure for the Update Failed dialog to read).
  state           = "idle",
  remote_version  = nil,     -- version string from manifest (e.g. "0.9.1")
  manifest        = nil,     -- parsed manifest table
  download_queue  = {},      -- list of {filename, url, sha256} to download
  download_idx    = 0,       -- index into download_queue (current file)
  update_missing  = nil,     -- changed-file set from check-time SHA diff
  update_mismatched = nil,   -- for version updates (avoids post-click hash stall)
  applied_files   = {},      -- list of {path=dest, bak_existed=bool} for rollback;
                             -- bak_existed=false means "fresh-install add" so rollback
                             -- must delete dest (not try to restore a nonexistent .bak)
  send_time       = nil,     -- time_precise() when the current curl was launched
  applied         = false,   -- true once files have been written to disk
  show_dialog     = false,   -- drives the Update Available / Files Need Repair popup in UI.lua;
                             -- flipped true when the popup auto-show guard fires, false when
                             -- the user dismisses (Later, OK) or starts a new fetch (Retry)
  popup_opened    = false,   -- true once the "Update Available" popup has been shown
  force           = false,   -- true to bypass version comparison (integrity reinstall)
  rename_failures = 0,       -- consecutive os.rename failures for AV-locked retry (initial fail = 1; each defer retry increments; gives up at 15)
  rename_tmp      = nil,     -- tmp_path for pending rename retry
  rename_dest     = nil,     -- dest path for pending rename retry
  rename_bak      = nil,     -- bak path for pending rename retry
  rename_bak_existed = false,-- true if the .bak was actually created (file existed pre-rename);
                             -- false means "fresh install add" so rollback must not restore
  -- Structured diagnostics stamped on every failure path so a support
  -- dump (Bug Report -> Copy Diagnostics) can attribute which step of
  -- the update/repair pipeline failed and why. Surfaced to the user via
  -- the Bootstrap repair prompt when the previous attempt failed.
  last_error      = nil,     -- short human-readable reason (last failure only)
  last_step       = nil,     -- step identifier ("manifest_read", "download",
                             --   "sha_verify", "rename", "rollback", ...)
}

-- =============================================================================
-- ImGui context, fonts, and atexit cleanup
-- =============================================================================
if not S.screen_reader_startup_intent then
RA.ctx = ImGui.ImGui_CreateContext(CFG._PRODUCT .. " v" .. CFG.VERSION)

-- Freshly-installed-ReaImGui preflight. After the gfx installer drops a
-- new ReaImGui dylib into UserPlugins, REAPER occasionally hands us a
-- context whose runtime metatable does not pass ImGui's per-call
-- validation -- ImGui_CreateContext succeeds (returns a non-nil
-- pointer), but the first context-taking call inside the bootstrap
-- render fails with "expected a valid ImGui_Context*, got 0x...". One
-- extra full REAPER restart loads the extension correctly. Observed on
-- macOS Tahoe immediately after first install. Detect it here -- before
-- ImGui_Attach and the main loop -- so the user sees a friendly
-- "please restart REAPER" dialog instead of a raw Lua error from deep
-- inside the bootstrap render.
do
  local imgui_restart_msg = RA.early_t(
    "ReaImGui was just installed but is not yet fully loaded.\n\n" ..
    "Please quit REAPER and reopen it, then run ReaAssist again.\n\n" ..
    "If this dialog appears a second time, quit and reopen REAPER " ..
    "once more -- macOS sometimes loads new extensions over two " ..
    "restarts.",
    "ReaImGui se instaló, pero todavía no terminó de cargarse.\n\n" ..
    "Cierra REAPER, vuelve a abrirlo y ejecuta ReaAssist otra vez.\n\n" ..
    "Si este aviso aparece por segunda vez, cierra y reabre REAPER " ..
    "una vez más. A veces macOS carga extensiones nuevas después de " ..
    "dos reinicios.")
  local ok, err = pcall(ImGui.ImGui_SetNextWindowSize, RA.ctx, 0, 0,
                        ImGui.ImGui_Cond_Always())
  if not ok and tostring(err):match("[Ee]xpected.*ImGui_Context") then
    reaper.MB(imgui_restart_msg, "ReaAssist", 0)
    return
  end
end

-- In-frame variant of the ReaImGui context preflight above. The init-
-- time check runs OUTSIDE any defer/render frame; on macOS Tahoe,
-- ReaImGui's strict per-call context validation appears to fire only
-- INSIDE an active frame, so a freshly-installed dylib can pass the
-- init-time check yet still fail validation on the first in-frame
-- ImGui call (observed: SetNextWindowSize at the top of Bootstrap.loop).
-- The two main-loop bodies (Bootstrap.loop and the post-bootstrap main
-- loop) call this once on their first tick, before any other ImGui
-- call, so the user sees the same friendly "please restart REAPER"
-- dialog the init-time preflight uses instead of a raw Lua error.
--
-- Implementation: ImGui_ValidatePtr is a pure boolean check against
-- ReaImGui's pointer registry -- it does NOT raise the Lua error or
-- post to REAPER's "ReaScript error" popup. An earlier version probed
-- with pcall(ImGui_PushStyleVar): the pcall caught the Lua error fine
-- and the friendly dialog fired, but ReaImGui's C side ALSO posted
-- the raw "expected a valid ImGui_Context*" message to REAPER's
-- script error dialog before raising the Lua error, so the user got
-- both popups. ValidatePtr avoids that path entirely.
--
-- Returns true if the context is usable, false (after showing the
-- friendly dialog) if not.
--
-- Hung off RA (cross-file shared table) rather than declared as a
-- main-chunk local: the main file is at Lua 5.4's 200-local cap.
function RA.imgui_in_frame_context_ok()
  -- ValidatePtr was added in ReaImGui 0.3; if the running ReaImGui
  -- predates it (extremely unlikely on a fresh install, since the
  -- bootstrap ships current ReaImGui), assume the context is usable
  -- and let the original error path fire if it isn't.
  if not reaper.ImGui_ValidatePtr then return true end
  if reaper.ImGui_ValidatePtr(RA.ctx, "ImGui_Context*") then
    return true
  end
  reaper.MB(
    RA.early_t(
      "ReaImGui was just installed but is not yet fully loaded.\n\n" ..
      "Please quit REAPER and reopen it, then run ReaAssist again.\n\n" ..
      "If this dialog appears a second time, quit and reopen REAPER " ..
      "once more -- macOS sometimes loads new extensions over two " ..
      "restarts.",
      "ReaImGui se instaló, pero todavía no terminó de cargarse.\n\n" ..
      "Cierra REAPER, vuelve a abrirlo y ejecuta ReaAssist otra vez.\n\n" ..
      "Si este aviso aparece por segunda vez, cierra y reabre REAPER " ..
      "una vez más. A veces macOS carga extensiones nuevas después de " ..
      "dos reinicios."),
    "ReaAssist", 0)
  return false
end

-- EEL callback for InputTextMultiline: tracks selection start/end each
-- frame. Lives on RA so UI.selectable_text (in the UI chunk) can reach
-- it across the dofile boundary.
RA.sel_cb = ImGui.ImGui_CreateFunctionFromEEL([[
  sel_start = SelectionStart;
  sel_end   = SelectionEnd;
]])
ImGui.ImGui_Attach(RA.ctx, RA.sel_cb)

-- CharFilter callback for the chat prompt InputTextMultiline. ImGui
-- inserts \n into the widget's internal edit buffer the moment Enter
-- is pressed in a multiline widget; that insertion renders for one
-- frame -- a visible 1-line -> 2-line jump -- before the post-widget
-- handler in the UI chunk strips the \n and triggers send. Filtering
-- the \n at the source prevents the insert and the flicker. Lua sets
-- `discard_newline = 1` only on frames where Enter is pressed WITHOUT
-- Shift; multi-line paste still works because the same frame won't
-- have a fresh Enter keypress, so discard_newline stays 0 and pasted
-- newlines pass through. Keypath: UI.lua's prompt render.
RA.prompt_charfilter = ImGui.ImGui_CreateFunctionFromEEL([[
  EventChar == 10 && discard_newline ? EventChar = 0;
]])
ImGui.ImGui_Attach(RA.ctx, RA.prompt_charfilter)
else
  function RA.imgui_in_frame_context_ok()
    return false
  end
end

-- V5 font atlas declared below, after RA.SC() is defined (sizes are scaled
-- by the user's UI Scale preference).
-- FONT is a plain global (assigned as `FONT = {}` in the atlas block
-- below). bold_font and code_font are cross-file and live on RA
-- (RA.bold_font, RA.code_font). No forward declaration is needed.

-- Tmp file paths for curl/update/screenshot I/O. Files live under ReaAssist's
-- own Data/Temp directory so the REAPER resource root never accumulates
-- visible ReaAssist scratch artifacts.
-- CMD_ID + INSTANCE_ID suffix makes filenames unique across REAPER processes
-- that share one script install.
local tmp = {}
do
  local tmp_dir    = RA.TEMP_DIR
  local tmp_suffix = tostring(CMD_ID or 0) .. "_" .. RA.instance_file_suffix()
  tmp.out    = tmp_dir .. "reaassist_resp_"       .. tmp_suffix .. ".json"
  tmp.body   = tmp_dir .. "reaassist_body_"       .. tmp_suffix .. ".json"
  tmp.log    = tmp_dir .. "reaassist_last_error_" .. tmp_suffix .. ".json"
  tmp.auth   = tmp_dir .. "reaassist_auth_"       .. tmp_suffix .. ".txt"
  tmp.err    = tmp_dir .. "reaassist_stderr_"     .. tmp_suffix .. ".txt"
  -- Exit code file. curl writes its exit code here so the poll loop can detect
  -- network errors on both platforms. Windows: written by the PowerShell
  -- command. macOS/Linux: written by the shell pipeline via "echo $?".
  tmp.exit   = tmp_dir .. "reaassist_exit_"       .. tmp_suffix .. ".txt"
  -- Gemini cache-create I/O. Separate from the main pipeline so cache creation
  -- can run concurrently with a user send without trampling response files.
  tmp.cache_body = tmp_dir .. "reaassist_cbody_" .. tmp_suffix .. ".json"
  tmp.cache_out  = tmp_dir .. "reaassist_cresp_" .. tmp_suffix .. ".json"
  tmp.cache_err  = tmp_dir .. "reaassist_cerr_"  .. tmp_suffix .. ".txt"
  tmp.cache_exit = tmp_dir .. "reaassist_cexit_" .. tmp_suffix .. ".txt"
  -- Pid file: holds the OS PID of the in-flight curl process so Cancel can
  -- kill it via taskkill/kill rather than just orphaning it.
  tmp.pid    = tmp_dir .. "reaassist_pid_"        .. tmp_suffix .. ".txt"
  -- Gemini side-path auth file. Separate from tmp.auth so cache-create can run
  -- concurrently with a main API request without trampling the auth header file.
  tmp.gemini_auth = tmp_dir .. "reaassist_gauth_" .. tmp_suffix .. ".txt"
  tmp.cache_auth = tmp_dir .. "reaassist_cauth_" .. tmp_suffix .. ".txt"
  tmp.cache_delete_auth = tmp_dir .. "reaassist_cdelauth_" .. tmp_suffix .. ".txt"
  tmp.cache_renew_auth = tmp_dir .. "reaassist_crenewauth_" .. tmp_suffix .. ".txt"
  tmp.cache_renew_body = tmp_dir .. "reaassist_crenewbody_" .. tmp_suffix .. ".json"
  -- Auto-update I/O. Separate from the main pipeline so the update check
  -- runs independently without trampling API request/response files.
  tmp.update_out  = tmp_dir .. "reaassist_update_"     .. tmp_suffix .. ".txt"
  tmp.update_exit = tmp_dir .. "reaassist_uexit_"      .. tmp_suffix .. ".txt"
  -- Native SHA-256 verification I/O. Separate from tmp.update_out / _exit
  -- so a verify can run while the next manifest fetch is being prepared,
  -- and so polling reads never race the manifest pipeline. _in is the
  -- newline-delimited list of absolute paths to hash; _out receives one
  -- "<hex>\t<path>" line per file; _exit is the inner-process exit code;
  -- _ps is the .ps1 script body on Windows (avoids nested-quote escape
  -- hell when the inner PowerShell is invoked from cmd from PowerShell).
  tmp.update_sha_in   = tmp_dir .. "reaassist_shain_"   .. tmp_suffix .. ".txt"
  tmp.update_sha_out  = tmp_dir .. "reaassist_shaout_"  .. tmp_suffix .. ".txt"
  tmp.update_sha_exit = tmp_dir .. "reaassist_shaexit_" .. tmp_suffix .. ".txt"
  tmp.update_sha_ps   = tmp_dir .. "reaassist_sha_"     .. tmp_suffix .. ".ps1"
  -- Optional CJK font hash I/O. Separate from the updater native SHA files
  -- so an on-demand font verify can never trample an update/repair verify.
  tmp.font_sha_out  = tmp_dir .. "reaassist_font_shaout_"  .. tmp_suffix .. ".txt"
  tmp.font_sha_exit = tmp_dir .. "reaassist_font_shaexit_" .. tmp_suffix .. ".txt"
  tmp.font_sha_ps   = tmp_dir .. "reaassist_font_sha_"     .. tmp_suffix .. ".ps1"
  tmp.screenshot  = tmp_dir .. "reaassist_screenshot_" .. tmp_suffix .. ".png"
  tmp.clipboard   = tmp_dir .. "reaassist_clipboard_"  .. tmp_suffix .. ".png"
  tmp.live        = RA.temp_live_marker_path()
end
RA.write_temp_live_marker()

-- Startup cleanup: wipe any temp files left behind by a prior hard crash (BSOD,
-- power loss, OOM kill). atexit handles graceful shutdown but cannot run on
-- crash, so temp files (including plaintext auth headers) could otherwise
-- persist on disk. The broad sweep below respects other live process markers.
os.remove(tmp.auth)
os.remove(tmp.gemini_auth)
os.remove(tmp.cache_auth)
os.remove(tmp.cache_delete_auth)
os.remove(tmp.cache_renew_auth)
os.remove(tmp.pid)
os.remove(tmp.out)
os.remove(tmp.body)
os.remove(tmp.log)
os.remove(tmp.err)
os.remove(tmp.exit)
os.remove(tmp.cache_body)
os.remove(tmp.cache_out)
os.remove(tmp.cache_err)
os.remove(tmp.cache_exit)
os.remove(tmp.cache_renew_body)
os.remove(tmp.update_out)
os.remove(tmp.update_exit)
os.remove(tmp.update_sha_in)
os.remove(tmp.update_sha_out)
os.remove(tmp.update_sha_exit)
os.remove(tmp.update_sha_ps)
os.remove(tmp.font_sha_out)
os.remove(tmp.font_sha_exit)
os.remove(tmp.font_sha_ps)
os.remove(tmp.screenshot)
os.remove(tmp.clipboard)

-- Stranded temp sweep: remove crash leftovers from prior instance-suffixed
-- launches, but keep files whose live marker is still fresh. Legacy
-- CMD_ID-only non-auth files cannot be safely attributed across REAPER
-- processes, so leave them rather than risking deletion of another live
-- process's request. Auth-header files are the exception: older builds used
-- CMD_ID-only plaintext auth temp names, and a post-update crash should not
-- leave API-key headers sitting on disk forever.
-- Pattern is anchored to known temp extensions so we never touch user-authored
-- files that happen to start with "reaassist_".
do
  local sweep_dir = RA.TEMP_DIR
  local sweep_sep = (sweep_dir:sub(-1) == "/" or sweep_dir:sub(-1) == "\\")
    and "" or RA.SEP
  local now = time_precise()
  -- Collect first, remove second: EnumerateFiles is index-based, so
  -- os.remove mid-iteration would shift later entries down by one and
  -- we would skip every other match.
  local victims = {}
  local idx     = 0
  while true do
    local fn = reaper.EnumerateFiles(sweep_dir, idx)
    if not fn then break end
    local tracked = fn:match("^reaassist_.+%.txt$")
        or fn:match("^reaassist_.+%.json$")
        or fn:match("^reaassist_.+%.ps1$")
        or fn:match("^reaassist_.+%.png$")
        or fn:match("^font_.+%.download$")
        or fn:match("^font_.+%.exit$")
    local legacy_auth = fn:match("^reaassist_auth_%-?%d+%.txt$")
        or fn:match("^reaassist_gauth_%-?%d+%.txt$")
        or fn:match("^reaassist_cauth_%-?%d+%.txt$")
        or fn:match("^reaassist_cdelauth_%-?%d+%.txt$")
        or fn:match("^reaassist_crenewauth_%-?%d+%.txt$")
        or fn:match("^reaassist_auth%.txt$")
        or fn:match("^reaassist_gauth%.txt$")
        or fn:match("^reaassist_cauth%.txt$")
        or fn:match("^reaassist_cdelauth%.txt$")
        or fn:match("^reaassist_crenewauth%.txt$")
    local inst_suffix = tracked and RA.temp_instance_suffix_from_name(fn) or nil
    if legacy_auth then
      victims[#victims + 1] = fn
    elseif tracked and inst_suffix
        and not RA.temp_instance_is_live(inst_suffix, now) then
      victims[#victims + 1] = fn
    end
    idx = idx + 1
  end
  for _, fn in ipairs(victims) do
    os.remove(sweep_dir .. sweep_sep .. fn)
  end
end

-- Stranded atomic store sweep: Config/State/Providers writes use
-- `<file>.tmp.inst_*` + `<file>.bak.inst_*` so two REAPER processes sharing one
-- install no longer collide. If a process crashes mid-write, its orphaned temp
-- or backup file is safe to remove after its live marker goes stale.
do
  local store_bases = {
    ["Config.json"]            = true,
    ["Providers.json"]         = true,
    ["State.json"]             = true,
    ["Custom_Instructions.md"] = true,
  }
  local victims = {}
  local idx = 0
  local now = time_precise()
  while true do
    local fn = reaper.EnumerateFiles(RA.DATA_DIR, idx)
    if not fn then break end
    local base = fn:match("^(.+)%.tmp%.inst_[%w%-_]+$")
        or fn:match("^(.+)%.bak%.inst_[%w%-_]+$")
    local inst_suffix = base and store_bases[base]
      and RA.temp_instance_suffix_from_name(fn) or nil
    if inst_suffix and not RA.temp_instance_is_live(inst_suffix, now) then
      victims[#victims + 1] = fn
    end
    idx = idx + 1
  end
  for _, fn in ipairs(victims) do
    os.remove(RA.DATA_DIR .. fn)
  end
end

-- Stranded .bak sweep: the auto-update's atomic per-file swap renames
-- each existing dest -> dest.bak before moving the new file in, then
-- removes the .bak in a post-batch cleanup pass at the bottom of
-- download_poll. When ReaAssist.lua itself is one of the updated
-- files, the script auto-restarts shortly after the swap; if the
-- restart races the cleanup pass for ReaAssist.lua's .bak, the .bak
-- gets stranded in the install dir and sits there forever (cosmetic
-- clutter, not a functional bug -- the script reads ReaAssist.lua
-- and ignores .bak). Sweep here at startup.
--
-- Guards:
--   1. Only delete a .bak when its un-suffixed counterpart exists in
--      the same dir, so we never touch a user-saved hand-rolled .bak
--      that lives here without a matching live file.
--   2. Skip .bak files whose stem is in BAK_SWEEP_EXEMPT below: user
--      overrides (System_Prompt_Custom.md is documented; some users
--      keep a hand-saved .bak beside it before edits) and legacy runtime
--      state (FX_Cache.json, Debug.log -- users sometimes back these up
--      before clearing). Data/ is not swept here; its .bak files are
--      store-helper recovery files, not updater leftovers.
do
  local exempt = {
    ["System_Prompt_Custom.md"] = true,
    ["FX_Cache.json"]           = true,
    ["Debug.log"]               = true,
  }
  local sweep_dirs = { RA.script_path, RA.RESOURCES_DIR }
  for _, dir in ipairs(sweep_dirs) do
    local victims = {}
    local idx     = 0
    while true do
      local fn = reaper.EnumerateFiles(dir, idx)
      if not fn then break end
      local stem = fn:match("^(.+)%.bak$")
      if stem and not exempt[stem]
          and reaper.file_exists(dir .. stem) then
        victims[#victims + 1] = fn
      end
      idx = idx + 1
    end
    for _, fn in ipairs(victims) do
      os.remove(dir .. fn)
    end
  end
end

reaper.atexit(function()
  set_toolbar(false)
  -- Only clear the "running" lock if it still belongs to this instance.
  -- During auto-restart (Updater.try_auto_restart -> Main_OnCommand) the
  -- new instance has already claimed the lock by the time this atexit
  -- fires, and wiping it here would leave the new instance unlocked for
  -- up to a heartbeat interval.
  local current = reaper.GetExtState(CFG.EXT_NS, "running")
  if current:match("^([^|]+)") == S.INSTANCE_ID then
    reaper.DeleteExtState(CFG.EXT_NS, "running", false)
  end
  reaper.DeleteExtState(CFG.EXT_NS, "request_close", false)
  -- Remove any hidden temp tracks owned by an in-flight scan. Without this,
  -- closing mid-scan (or being displaced by a second instance) would leave
  -- the user's project with a stray hidden track in the TCP/mixer-invisible
  -- state - surprising if they later look at the track list directly.
  local _inflight = {}
  if pref_plugins.scan  and pref_plugins.scan.track  then _inflight[#_inflight+1] = pref_plugins.scan.track  end
  if fx_cache_ui.rescan and fx_cache_ui.rescan.track then _inflight[#_inflight+1] = fx_cache_ui.rescan.track end
  if S._fx_inspect_tmp  and S._fx_inspect_tmp.tr     then _inflight[#_inflight+1] = S._fx_inspect_tmp.tr     end
  if deep_scan.tr                                    then _inflight[#_inflight+1] = deep_scan.tr             end
  for _, _tr in ipairs(_inflight) do
    if reaper.ValidatePtr2(0, _tr, "MediaTrack*") then
      pcall(reaper.DeleteTrack, _tr)
    end
  end
  -- Release scan cleanup scopes without assuming every temp-track owner still
  -- has an Undo block open. Refresh suppression can span the deferred read, but
  -- Undo blocks are closed before returning to REAPER and tracked explicitly.
  local _refresh_owners = 0
  if pref_plugins.scan  and pref_plugins.scan.track  then _refresh_owners = _refresh_owners + 1 end
  if fx_cache_ui.rescan and fx_cache_ui.rescan.track then _refresh_owners = _refresh_owners + 1 end
  if S._fx_inspect_tmp                               then _refresh_owners = _refresh_owners + 1 end
  local _undo_owners = 0
  if pref_plugins.scan and pref_plugins.scan.undo_open then
    _undo_owners = _undo_owners + 1
    pref_plugins.scan.undo_open = false
  end
  if fx_cache_ui.rescan and fx_cache_ui.rescan.undo_open then
    _undo_owners = _undo_owners + 1
    fx_cache_ui.rescan.undo_open = false
  end
  if S._fx_inspect_tmp and S._fx_inspect_tmp.undo_open then
    _undo_owners = _undo_owners + 1
    S._fx_inspect_tmp.undo_open = false
  end
  local _refreshes = _refresh_owners
  if deep_scan._ui_refresh_released then _refreshes = _refreshes - 1 end
  if _refreshes < 0 then _refreshes = 0 end
  for _ = 1, _refreshes do pcall(reaper.PreventUIRefresh, -1) end
  for _ = 1, _undo_owners do
    pcall(reaper.Undo_EndBlock, "ReaAssist: scan (closed at exit)", 0)
  end
  if reaper.ImGui_DestroyContext and RA.ctx then
    pcall(reaper.ImGui_DestroyContext, RA.ctx)
  end
  -- Remove all temp files so nothing persists on disk after exit. Every
  -- tmp.* field is unconditionally assigned in the do-block above, so
  -- the previous `if tmp.X then` guards on each line were dead. The
  -- auth file should already be removed after each curl call, but
  -- os.remove silently no-ops on missing files so cleaning up
  -- defensively here is harmless.
  os.remove(tmp.out)
  os.remove(tmp.body)
  os.remove(tmp.log)
  os.remove(tmp.err)
  os.remove(tmp.auth)
  os.remove(tmp.gemini_auth)
  os.remove(tmp.cache_auth)
  os.remove(tmp.cache_delete_auth)
  os.remove(tmp.cache_renew_auth)
  os.remove(tmp.exit)
  os.remove(tmp.cache_body)
  os.remove(tmp.cache_out)
  os.remove(tmp.cache_err)
  os.remove(tmp.cache_exit)
  os.remove(tmp.cache_renew_body)
  os.remove(tmp.pid)
  os.remove(tmp.update_out)
  os.remove(tmp.update_exit)
  -- Native SHA verify temp files; symmetric with the startup wipe so
  -- the .ps1 in particular (which embeds tmp paths) doesn't linger
  -- on disk after a graceful close.
  os.remove(tmp.update_sha_in)
  os.remove(tmp.update_sha_out)
  os.remove(tmp.update_sha_exit)
  os.remove(tmp.update_sha_ps)
  os.remove(tmp.font_sha_out)
  os.remove(tmp.font_sha_exit)
  os.remove(tmp.font_sha_ps)
  os.remove(tmp.screenshot)
  os.remove(tmp.clipboard)
  os.remove(tmp.live)
end)

-- =============================================================================
-- Persisted UI preferences. Start with legacy ExtState defaults, then
-- Store.apply_config_preferences overlays Config.json and Store.save_config
-- removes migrated legacy keys after the file write succeeds.
-- =============================================================================
-- ~= "0" pattern: default ON for a fresh install (empty ExtState returns "")
-- == "1" pattern: default OFF for a fresh install
prefs = {
  auto_run         = reaper.GetExtState(CFG.EXT_NS, "auto_run")         == "1",  -- default off
  auto_backup      = reaper.GetExtState(CFG.EXT_NS, "auto_backup")      ~= "0",  -- default on
  show_details     = reaper.GetExtState(CFG.EXT_NS, "show_details")     == "1",  -- default off
  custom_instructions_enabled = reaper.GetExtState(CFG.EXT_NS, "custom_instructions_enabled") == "1", -- default off
  debug_logging    = reaper.GetExtState(CFG.EXT_NS, "debug_logging")    == "1",  -- default off; verbose request/response logging is opt-in
  include_api_ref  = reaper.GetExtState(CFG.EXT_NS, "include_api_ref")  == "1",  -- default off (prompt-bundle era; request docs on-demand)
  include_snapshot = reaper.GetExtState(CFG.EXT_NS, "include_snapshot") ~= "0", -- default on
  update_check     = reaper.GetExtState(CFG.EXT_NS, "update_check")    ~= "0", -- default on
  screen_reader_concise_hints = reaper.GetExtState(CFG.EXT_NS, "screen_reader_concise_hints") == "1", -- default off
  screen_reader_text_size_idx = 1, -- Screen Reader Mode visual size; separate from main UI scale/chat font
  screen_reader_contrast = "auto", -- "auto", "dark", or "light" for ReaGirl SR windows
  typed_actions_opt_in = true, -- built in; exact-fit structured track edits
  diag_auto_tier   = reaper.GetExtState(CFG.EXT_NS, "diag_auto_tier"),
  provider_idx     = 1,  -- set below from ExtState (1=Claude, 2=ChatGPT, 3=Gemini)
  model_idx        = 2,  -- set below by MODELS.refresh() per active provider
  thinking_idx     = 0,  -- 0 = provider has no thinking; set by MODELS.refresh()
  ui_scale_idx     = 3,  -- index into CFG.UI_SCALE_OPTIONS (default 3 = 1.0)
  theme            = "auto",  -- "auto", "dark", or "light"
  chat_font_idx    = 2,  -- index into CHAT_FONT_SIZES: 1=Small, 2=Medium, 3=Large
  reply_language_idx = 1, -- 1=English; visible assistant prose language only
  language_code    = "en", -- stable BCP-47-style language code; migrated from reply_language_idx
  cloud_request_timeout = 180,  -- seconds; user-facing watchdog timeout for cloud providers (Claude/ChatGPT/Gemini). Set below from ExtState. Custom providers use their own per-provider timeout instead.
  turn_cost_limit_usd = 5.00, -- projected prior actual cost + worst-case next call
  turn_token_limit = 1000000, -- projected prior actual tokens + worst-case next call
  -- Testing-only: when true, a per-send timestamp is appended to the
  -- system prompt as a hidden comment so every request hashes to a new
  -- cache prefix across all three providers. Consumed as a one-shot startup
  -- flag so an accidentally persisted test toggle cannot silently defeat
  -- cache behavior across future sessions.
  test_force_cold_cache = (function()
    local enabled = reaper.GetExtState(CFG.EXT_NS, "test_force_cold_cache") == "1"
    if enabled and type(reaper.DeleteExtState) == "function" then
      reaper.DeleteExtState(CFG.EXT_NS, "test_force_cold_cache", false)
      reaper.DeleteExtState(CFG.EXT_NS, "test_force_cold_cache", true)
    end
    return enabled
  end)(),
  -- Dev-only: the FabFilter-hide flag (used to test resolve/not-found
  -- popups without physically uninstalling anything) lives in ExtState
  -- under "dev_hide_fabfilter" and is read directly at every consumer.
  -- The Debug Helper's "Hide FabFilter" toggle writes ExtState and fires
  -- the "refresh_fx_filter" dev_signal to invalidate the installed-FX
  -- caches. No prefs field is mirrored here because nothing reads it
  -- (the flag's read sites all hit ExtState fresh, so a mirror would be
  -- dead state that could go stale if the signal ever missed a delivery).
}
if prefs.diag_auto_tier == "" then
  prefs.diag_auto_tier = "basic" -- default on; explicit "off" persists opt-out
elseif prefs.diag_auto_tier ~= "basic" and prefs.diag_auto_tier ~= "extended" then
  prefs.diag_auto_tier = "off"
end

-- Forward-declare JSON so the Log module (defined below) can reference it;
-- JSON is main-file-local and later assigned without `local` so it
-- reassigns this upvalue rather than shadowing it.
local JSON
-- PROVIDERS, MODELS, FXCache, and Net are cross-file shared state and
-- live as plain globals so ReaAssist.lua and Resources/*.lua sidecars
-- can read and write them. Their `= {}` initializers appear later in
-- this file; before those run the names are nil, so any code that touches
-- them at load time must appear after the initializers.

-- =============================================================================
-- Log: verbose debug logger (gated by prefs.debug_logging)
-- =============================================================================
-- When enabled via the "Debug log" checkbox in settings, appends tagged entries
-- to a log file including every outgoing API request body, every incoming
-- response body, every FX scan event, and every cache hit/miss. Includes
-- auto-follow-up requests (hidden from the chat UI) so the full exchange is
-- visible. Users can send this file to the developer for bug reports.
-- No-op when disabled so there's zero perf cost in normal use.
Log = {}
-- Single-writer log, shared across launches. Safe because the lock mechanism
-- above (S.INSTANCE_ID + ExtState "running" key) guarantees only one
-- ReaAssist can be writing to ExtState/log at a time on a given machine:
-- second-launch instances detect the fresh lock, send request_close, and
-- exit BEFORE the Log module loads. Each session writes a clear "session
-- start" header so multiple sessions in one file remain easy to navigate.
--
-- Cross-machine edge case (script directory synced via Dropbox/OneDrive,
-- both machines running ReaAssist simultaneously) is NOT covered -- ExtState
-- is per-machine so neither sees the other's lock, and the synced log file
-- could see interleaved appends. If you hit that scenario, the workaround
-- is to disable debug logging on all but one machine.
Log.path = RA.DEBUG_LOG_PATH
Log.enabled = function() return prefs.debug_logging end

-- Simple append-at-bottom log (standard chronological order). On first request
-- per session we write a header with system info at the top of the file; each
-- subsequent event is appended.
local function _log_write(text)
  if S and S._factory_reset_clean_boot then return end
  local f = io.open(Log.path, "a")
  if not f then return end
  f:write(text)
  f:close()
end

-- Indent every line of a multi-line string by `pad`.
local function _indent(s, pad)
  if s == nil or s == "" then return pad .. "(empty)" end
  pad = pad or "    "
  local out = {}
  for line in (tostring(s) .. "\n"):gmatch("([^\n]*)\n") do
    out[#out+1] = pad .. line
  end
  if out[#out] == pad then table.remove(out) end
  return table.concat(out, "\n")
end

-- Known static reference-doc prefixes. Their content is versioned with the
-- script and available in the repo; the log only needs to show that they were
-- injected, not their bodies.
--
-- Order matters: longer / more-specific variants must come first so the
-- substring search matches "REAPER LUA API REFERENCE (EXTENDED):" before
-- the shorter "REAPER LUA API REFERENCE:" prefix would, which would otherwise
-- swallow the "(EXTENDED)" tag into the elided body.
local _STATIC_REF_PREFIXES = {
  "REAPER LUA API REFERENCE (",
  "REAPER LUA API REFERENCE:",
  "REAPER MIDI WORKFLOW REFERENCE:",
  "REAPER THEME COLOR REFERENCE:",
  "PLUGIN PARAMETER REFERENCE (",
  "PROMPT BUNDLE (",
}

-- Explicit list of known top-level context section markers. The elision
-- function stops a section at the next \n\n followed by any of these prefixes
-- (exact match, not regex) so that "NOTE:" or "IMPORTANT:" lines INSIDE a
-- reference doc don't falsely terminate the elision.
local _SECTION_MARKERS = {
  "REAPER LUA API REFERENCE (",
  "REAPER LUA API REFERENCE:",
  "REAPER MIDI WORKFLOW REFERENCE:",
  "REAPER THEME COLOR REFERENCE:",
  "PLUGIN PARAMETER REFERENCE (",
  "PROMPT BUNDLE (",
  "PINNED REFERENCES ",
  "INSTALLED FX MATCHING ",
  "PREFERRED PLUGINS:",
  "SESSION CONTEXT:",
  "FX INSPECT ",
  "FX INSPECT:",
  "FX INSPECT ERROR:",
  "FX PARAMETER VALUES",
  "Track flags:",
  "PREVIOUS_RUN_ERROR",
  "USER REQUEST:",
}

local function _line_starts_new_section(s, line_start)
  for _, marker in ipairs(_SECTION_MARKERS) do
    if s:sub(line_start, line_start + #marker - 1) == marker then
      return true
    end
  end
  return false
end

-- Walk a message-content string and replace each static reference section with
-- a size placeholder. A section ends at the next \n\n that is followed by a
-- line starting with one of _SECTION_MARKERS, or at end of string.
local function _elide_static_refs(s)
  if type(s) ~= "string" then return s end
  for _, hdr in ipairs(_STATIC_REF_PREFIXES) do
    local pos = 1
    while true do
      local hs = s:find(hdr, pos, true)
      if not hs then break end
      -- Some prefixes are partial (e.g. "PROMPT BUNDLE (" -- the bucket name
      -- and trailing colon vary). Scan to the end of the header LINE so the
      -- full header ("PROMPT BUNDLE (PLUGIN):") stays visible in the log;
      -- the placeholder lands inline on the same line as the header.
      local he = s:find("\n", hs + #hdr, true) or (#s + 1)
      local section_end = #s + 1
      local scan = he
      while true do
        local blank = s:find("\n\n", scan, true)
        if not blank then break end
        local line_start = blank + 2
        if _line_starts_new_section(s, line_start) then
          section_end = blank
          break
        end
        scan = blank + 2
      end
      local body_len = section_end - he
      if body_len > 200 then
        s = s:sub(1, he - 1)
          .. "  [" .. body_len .. " chars omitted -- static reference doc]"
          .. s:sub(section_end)
        pos = hs + #hdr
      else
        pos = he
      end
    end
  end
  -- Also elide the static FX INSPECT guidance block (same text every time
  -- fx_inspect is injected). Match from "IMPORTANT: Use the EXACT parameter
  -- indices" through the "Apply the DECIDE FIRST flowchart..." line; replace
  -- with a single placeholder.
  local g_start = s:find("IMPORTANT: Use the EXACT parameter indices", 1, true)
  if g_start then
    local g_anchor = "Apply the DECIDE FIRST flowchart"
    local g_a = s:find(g_anchor, g_start, true)
    if g_a then
      local g_end = s:find("\n", g_a, true) or #s
      s = s:sub(1, g_start - 1)
        .. "[fx_inspect guidance omitted -- static]"
        .. s:sub(g_end)
    end
  end

  -- Cross-request dedupe pass. SESSION CONTEXT, PINNED REFERENCES, and
  -- INSTALLED FX MATCHING blocks get re-injected into every request body
  -- but rarely change within a 20-turn window (track count, tempo, pin
  -- list, FX list are usually stable). First occurrence is kept verbatim;
  -- byte-identical re-occurrences in later requests collapse to a back-
  -- reference placeholder. State lives in Log._seen_sections, keyed by
  -- "<label>\0<body>", reset on session header / clear / prune so
  -- references never point outside the current log window.
  local _DEDUP_HEADERS = {
    { hdr = "SESSION CONTEXT:",     label = "SESSION CONTEXT" },
    { hdr = "SESSION CONTEXT ",     label = "SESSION CONTEXT" },
    { hdr = "PINNED REFERENCES ",   label = "PINNED REFERENCES" },
    { hdr = "INSTALLED FX MATCHING ", label = "INSTALLED FX MATCHING" },
  }
  for _, ent in ipairs(_DEDUP_HEADERS) do
    local hdr   = ent.hdr
    local label = ent.label
    local pos = 1
    while true do
      local hs = s:find(hdr, pos, true)
      if not hs then break end
      local he = s:find("\n", hs + #hdr, true) or (#s + 1)
      local section_end = #s + 1
      local scan = he
      while true do
        local blank = s:find("\n\n", scan, true)
        if not blank then break end
        local line_start = blank + 2
        if _line_starts_new_section(s, line_start) then
          section_end = blank
          break
        end
        scan = blank + 2
      end
      -- Body = content after header line, before section terminator.
      local body = s:sub(he + 1, section_end - 1)
      if #body > 200 then
        local turn_num = Log._current_turn_num or 1
        local key = label .. "\0" .. body
        local seen = Log._seen_sections[key]
        if seen and seen ~= turn_num then
          s = s:sub(1, he)
            .. "  [" .. label .. " same as request #" .. seen
            .. " -- " .. #body .. " chars omitted]"
            .. s:sub(section_end)
          pos = hs + #hdr
        else
          if not seen then Log._seen_sections[key] = turn_num end
          pos = section_end
        end
      else
        pos = he
      end
    end
  end

  return s
end

-- Replace big base64-looking strings with a size placeholder so the log stays
-- readable when the user pastes in screenshots or images; also elide static
-- reference docs that bloat the request without adding debug value.
local function _trim_base64(s)
  if type(s) ~= "string" then return s end
  if #s > 1000 and s:match("^[A-Za-z0-9+/=\r\n]+$") then
    return "[base64 data omitted, " .. #s .. " bytes]"
  end
  return _elide_static_refs(s)
end

-- Render a single Anthropic-style content block (also handles OpenAI parts).
local function _render_block(block, pad)
  pad = pad or "    "
  if type(block) == "string" then
    return _indent(_trim_base64(block), pad)
  end
  if type(block) ~= "table" then return pad .. tostring(block) end
  local bt = block.type or (block.text and "text") or "?"
  if bt == "text" then
    return pad .. "[text]\n" .. _indent(_trim_base64(block.text or ""), pad .. "  ")
  elseif bt == "image" or bt == "image_url" then
    local sz = 0
    if block.source and block.source.data then sz = #block.source.data end
    if block.image_url and block.image_url.url then sz = #block.image_url.url end
    local mt = (block.source and block.source.media_type) or "image"
    return pad .. "[image] " .. mt .. " (" .. sz .. " bytes)"
  elseif bt == "tool_use" then
    local head = pad .. "[tool_use] name=" .. tostring(block.name)
      .. " id=" .. tostring(block.id)
    local body = block.input and _indent(JSON.encode(block.input), pad .. "  ") or ""
    return head .. (body ~= "" and ("\n" .. body) or "")
  elseif bt == "tool_result" then
    local head = pad .. "[tool_result] tool_use_id=" .. tostring(block.tool_use_id)
    local body = block.content and _indent(_trim_base64(tostring(block.content)), pad .. "  ") or ""
    return head .. (body ~= "" and ("\n" .. body) or "")
  else
    return pad .. "[" .. bt .. "]\n" .. _indent(JSON.encode(block), pad .. "  ")
  end
end

-- Sum the byte length of every text-bearing block in a message's content.
-- Handles Anthropic's `[{type="text", text="..."}, ...]` shape, OpenAI's
-- string-or-parts shape, and Gemini's `[{text="..."}, ...]` shape. Non-text
-- blocks (images, tool_use) contribute 0 by design -- they're already short
-- and the elision is targeted at long replayed prose / code.
local function _assistant_text_len(content)
  if content == nil then return 0 end
  if type(content) == "string" then return #content end
  if type(content) ~= "table" then return 0 end
  local n = 0
  for _, b in ipairs(content) do
    if type(b) == "string" then
      n = n + #b
    elseif type(b) == "table" then
      if type(b.text) == "string" then
        n = n + #b.text
      end
    end
  end
  return n
end

-- Threshold for replacing a replayed assistant turn with a one-line placeholder
-- in the request rendering. Short acks ("Understood.", "OK", brief confirmations)
-- stay visible; long replays (code blocks, multi-paragraph explanations) are
-- elided since the canonical full text lives in an earlier RESPONSE block in
-- the same log file.
local _ASST_HISTORY_TRIM_THRESHOLD = 500

-- Render the `content` or `parts` field of a message (string or array).
local function _render_content(content, pad)
  pad = pad or "    "
  if content == nil then return pad .. "(no content)" end
  if type(content) == "string" then
    return _indent(_trim_base64(content), pad)
  end
  if type(content) == "table" then
    local out = {}
    for _, b in ipairs(content) do out[#out+1] = _render_block(b, pad) end
    return table.concat(out, "\n")
  end
  return pad .. tostring(content)
end

-- Decode the request body JSON and produce a readable view. The system prompt
-- content is deliberately omitted (it lives in System_Prompt.md and
-- is versioned with the script) -- only its length is reported.
local function _render_request(body)
  local ok, req = pcall(JSON.decode, body)
  if not ok or type(req) ~= "table" then
    return "(unparseable JSON)\n" .. body
  end
  local out = {}
  if req.model then out[#out+1] = "Model: " .. tostring(req.model) end
  if req.max_tokens then out[#out+1] = "Max tokens: " .. tostring(req.max_tokens) end
  if req.temperature ~= nil then out[#out+1] = "Temperature: " .. tostring(req.temperature) end

  -- System prompt length. Three shapes:
  --   Anthropic: top-level `system` (string or array of text blocks)
  --   Gemini:    top-level `systemInstruction.parts`
  --   OpenAI:    first `messages` entry with role=="system"
  local sys = req.system or (req.systemInstruction and req.systemInstruction.parts)
  local messages = req.messages or req.contents
  local openai_sys_idx = nil
  if not sys and type(messages) == "table" and type(messages[1]) == "table"
     and messages[1].role == "system" then
    sys = messages[1].content
    openai_sys_idx = 1
  end
  if sys then
    local sys_len = 0
    if type(sys) == "string" then sys_len = #sys
    elseif type(sys) == "table" then
      for _, s in ipairs(sys) do
        if type(s) == "table" and s.text then sys_len = sys_len + #s.text
        elseif type(s) == "string" then sys_len = sys_len + #s
        end
      end
    end
    out[#out+1] = "System prompt: " .. sys_len
      .. " chars (omitted -- content is in System_Prompt.md)"
  end

  if type(req.tools) == "table" and #req.tools > 0 then
    local names = {}
    for _, t in ipairs(req.tools) do names[#names+1] = t.name or "?" end
    out[#out+1] = "Tools: " .. table.concat(names, ", ")
  end

  -- Any other top-level keys: dump as a compact JSON line so the log reveals
  -- vendor-specific extras (custom-provider extra_body merges, reasoning
  -- configs, Anthropic cache controls, Gemini generationConfig, etc.) that
  -- would otherwise be invisible in the rendered request. Keys already
  -- rendered above are skipped so the line stays focused on the "extras".
  do
    local shown = {
      model = true, max_tokens = true, max_completion_tokens = true,
      temperature = true, system = true, systemInstruction = true,
      messages = true, contents = true, tools = true,
      prompt_cache_key = true,  -- fixed routing id; noise in the log
      safety_identifier = true, -- opaque per-install safety id; never log it
    }
    local extras = {}
    local extra_keys = {}
    for k, v in pairs(req) do
      if not shown[k] then
        extras[k] = v
        extra_keys[#extra_keys+1] = k
      end
    end
    if #extra_keys > 0 then
      table.sort(extra_keys)
      local rendered, err = JSON.encode(extras)
      if rendered then
        out[#out+1] = "Extra fields: " .. rendered
      else
        out[#out+1] = "Extra fields: (encode failed: " .. tostring(err) .. ")"
      end
    end
  end

  -- Messages: Anthropic/OpenAI use `messages`; Gemini uses `contents`.
  if type(messages) == "table" then
    -- Count excluding an OpenAI system message we already summarized above.
    local shown = #messages - (openai_sys_idx and 1 or 0)
    out[#out+1] = "Messages (" .. shown .. "):"
    for i, m in ipairs(messages) do
      if i ~= openai_sys_idx then
        out[#out+1] = ""
        out[#out+1] = "  [" .. i .. "] role=" .. tostring(m.role or "?")
        local content = m.content or m.parts
        -- Replayed assistant turns are duplicates of the corresponding earlier
        -- RESPONSE block in the same log file. Elide long ones so a 6-turn
        -- conversation's request log doesn't grow quadratically with prior
        -- code-gen output. Short acks ("Understood.") fall through and render
        -- normally.
        if m.role == "assistant" or m.role == "model" then
          local len = _assistant_text_len(content)
          if len > _ASST_HISTORY_TRIM_THRESHOLD then
            out[#out+1] = "      [" .. tostring(m.role)
              .. " turn replay -- " .. len
              .. " chars; full text in earlier RESPONSE block]"
          else
            out[#out+1] = _render_content(content, "      ")
          end
        else
          out[#out+1] = _render_content(content, "      ")
        end
      end
    end
  end

  return table.concat(out, "\n")
end

-- Decode and render the response body.
local function _render_response(body)
  local ok, resp = pcall(JSON.decode, body)
  if not ok or type(resp) ~= "table" then
    return "(unparseable JSON)\n" .. body
  end
  local out = {}

  if resp.error then
    out[#out+1] = "ERROR: " .. JSON.encode(resp.error)
    return table.concat(out, "\n")
  end

  -- Anthropic shape.
  if resp.content or resp.stop_reason then
    if resp.stop_reason then out[#out+1] = "Stop reason: " .. tostring(resp.stop_reason) end
    if type(resp.usage) == "table" then
      local u, parts = resp.usage, {}
      if u.input_tokens              then parts[#parts+1] = "input="       .. u.input_tokens end
      if u.output_tokens             then parts[#parts+1] = "output="      .. u.output_tokens end
      if u.cache_read_input_tokens   then parts[#parts+1] = "cache_read="  .. u.cache_read_input_tokens end
      if u.cache_creation_input_tokens then parts[#parts+1] = "cache_write=" .. u.cache_creation_input_tokens end
      out[#out+1] = "Usage: " .. table.concat(parts, ", ")
    end
    if resp.content then
      out[#out+1] = "Content:"
      out[#out+1] = _render_content(resp.content, "    ")
    end
    return table.concat(out, "\n")
  end

  -- OpenAI shape.
  if type(resp.choices) == "table" then
    for i, c in ipairs(resp.choices) do
      out[#out+1] = "Choice " .. i .. ": finish_reason=" .. tostring(c.finish_reason)
      local msg = c.message or {}
      out[#out+1] = _indent(_trim_base64(tostring(msg.content or "")), "    ")
    end
    if type(resp.usage) == "table" then
      local u = resp.usage
      out[#out+1] = "Usage: prompt=" .. tostring(u.prompt_tokens)
        .. " completion=" .. tostring(u.completion_tokens)
        .. " total=" .. tostring(u.total_tokens)
    end
    return table.concat(out, "\n")
  end

  -- Gemini shape.
  if type(resp.candidates) == "table" then
    for i, c in ipairs(resp.candidates) do
      out[#out+1] = "Candidate " .. i .. ": finish_reason=" .. tostring(c.finishReason)
      if c.content and c.content.parts then
        for _, p in ipairs(c.content.parts) do
          if p.text then out[#out+1] = _indent(_trim_base64(p.text), "    ") end
        end
      end
    end
    if type(resp.usageMetadata) == "table" then
      local u = resp.usageMetadata
      out[#out+1] = "Usage: prompt=" .. tostring(u.promptTokenCount)
        .. " candidates=" .. tostring(u.candidatesTokenCount)
        .. " total=" .. tostring(u.totalTokenCount)
    end
    return table.concat(out, "\n")
  end

  return "(unknown response shape)\n" .. body
end

-- Rolling prune: cap the debug log at MAX_LOG_TURNS newest REQUEST /
-- RESPONSE pairs so a user who forgets to disable logging does not end
-- up with a multi-MB file. Runs at the top of Log.request so the cap
-- holds after the new turn is appended. Session header + system info
-- above the first kept REQUEST delimiter are preserved.
local MAX_LOG_TURNS = 40
local LOG_PRUNE_KEEP_TURNS = 32
local _REQ_DELIM = "\n======= REQUEST #"

-- Monotonic turn counter, shared by REQUEST / RESPONSE pairs so it's obvious
-- which response belongs to which request. Lazily initialized on first use by
-- scanning the existing log file for the highest existing #N so numbers never
-- repeat across script reloads.
Log._turn_counter = nil
Log._window_turn_count = nil

-- Cross-request dedupe state for repeated almost-static section blocks
-- (SESSION CONTEXT / PINNED REFERENCES / INSTALLED FX MATCHING). Maps
-- "<label>\0<verbatim body>" -> first-seen turn number. Only used by
-- _elide_static_refs's dedup pass; reset on session header / log clear /
-- prune so back-references never point outside the current log window.
Log._seen_sections = {}

-- Last [CHAIN] tagged-line message seen in this session. Consecutive
-- identical [CHAIN] events (which happen many times per session because
-- the chain-types list is fixed) are collapsed to a short marker.
Log._last_chain_msg = nil

local function _init_turn_counter()
  if Log._turn_counter then return end
  Log._turn_counter = 0
  Log._window_turn_count = 0
  local f = io.open(Log.path, "r")
  if not f then return end
  local content = f:read("*a")
  f:close()
  if not content then return end
  -- Find the largest "#N" immediately after a REQUEST delimiter.
  for n in content:gmatch("======= REQUEST #(%d+)") do
    Log._window_turn_count = Log._window_turn_count + 1
    local num = tonumber(n)
    if num and num > Log._turn_counter then Log._turn_counter = num end
  end
end

local function _prune_log()
  if (Log._window_turn_count or 0) < MAX_LOG_TURNS then return end
  local f = io.open(Log.path, "r")
  if not f then return end
  local content = f:read("*a")
  f:close()
  local positions, pos = {}, 1
  while true do
    local p = content:find(_REQ_DELIM, pos, true)
    if not p then break end
    positions[#positions+1] = p
    pos = p + #_REQ_DELIM
  end
  if #positions < MAX_LOG_TURNS then
    Log._window_turn_count = #positions
    return
  end
  -- We're about to drop the oldest turns. Any back-references in the
  -- kept turns to "[X same as request #N]" where N is in the dropped
  -- range now point outside the file. Reset the dedupe state so the
  -- next incoming request emits its sections verbatim again -- subsequent
  -- requests then dedupe against that fresh baseline. The dangling
  -- references in the already-written kept content are accepted as a
  -- known limitation; the verbose-baseline-then-elide pattern resumes
  -- cleanly from the next request forward.
  --
  -- Same logic for the [CHAIN] tag: if the verbatim baseline line was
  -- in a dropped turn, the kept content is left with only "(chains
  -- unchanged)" markers and no in-file reference for what they're
  -- unchanged FROM. Clearing _last_chain_msg here forces the next
  -- chain event to log the type list in full again, restoring a
  -- visible baseline.
  Log._seen_sections  = {}
  Log._last_chain_msg = nil
  -- Preserve the prefix (session header / system info) above positions[1],
  -- then keep a hysteresis window so the append does not force another full
  -- prune/rewrite on the very next request once the log reaches MAX.
  local prefix_end = positions[1] - 1
  local prefix     = content:sub(1, prefix_end)
  local keep_count = math.min(LOG_PRUNE_KEEP_TURNS, #positions)
  local keep_from  = positions[#positions - keep_count + 1]
  if not keep_from then return end
  local trimmed = content:sub(keep_from)
  local fw = io.open(Log.path, "w")
  if not fw then return end
  fw:write(prefix)
  fw:write("\n[earlier entries pruned -- auto-pruning to newest "
    .. MAX_LOG_TURNS .. " turns]\n")
  fw:write(trimmed)
  fw:close()
  Log._window_turn_count = keep_count
end

Log.request = function(provider_label, body)
  if not prefs.debug_logging or (S and S._factory_reset_clean_boot) then return end
  -- If the log file is missing or empty (user manually deleted it mid-session),
  -- re-arm the session header so it gets rewritten at the top of the new file.
  do
    local f = io.open(Log.path, "r")
    if not f then
      Log._session_header_written = false
      Log._window_turn_count = 0
    else
      local first = f:read(1)
      f:close()
      if not first then
        Log._session_header_written = false
        Log._window_turn_count = 0
      end
    end
  end
  -- First request since script load (or file was externally deleted): drop a
  -- session header (with system info) at the top so the log always has current
  -- environment info, even if the user didn't just toggle the checkbox.
  if not Log._session_header_written then
    Log._session_header_written = true
    Log.session_header()
  end
  _init_turn_counter()
  _prune_log()
  Log._turn_counter = Log._turn_counter + 1
  Log._window_turn_count = (Log._window_turn_count or 0) + 1
  Log._current_turn_num = Log._turn_counter
  local ts = os.date("%Y-%m-%d %H:%M:%S")
  _log_write(_REQ_DELIM .. Log._current_turn_num .. " ======= " .. ts
    .. " (" .. tostring(provider_label) .. ", " .. #body .. " bytes) =======\n"
    .. _render_request(body) .. "\n")
end

Log.response = function(body, elapsed)
  if not prefs.debug_logging or (S and S._factory_reset_clean_boot) then return end
  local ts = os.date("%Y-%m-%d %H:%M:%S")
  local elapsed_str = elapsed and string.format(", %.2fs", elapsed) or ""
  local num = Log._current_turn_num or "?"
  _log_write("\n======= RESPONSE #" .. tostring(num) .. " ====== " .. ts
    .. " (" .. #body .. " bytes" .. elapsed_str .. ") ===============================\n"
    .. _render_response(body) .. "\n")
end

-- Short tagged line (used for scan events, cache hit/miss, etc.).
-- [CHAIN] events fire many times per session with identical "loaded chains
-- for types: ..." messages because the chain-types list is fixed. After
-- the first occurrence in the current log window, byte-identical [CHAIN]
-- messages collapse to "[CHAIN] (chains unchanged)" -- timestamps still
-- log so the timeline is preserved, but we don't pay for the type list
-- on every event. State (Log._last_chain_msg) lives until session_header
-- / clear / prune resets it, at which point the next chain event re-emits
-- the full type list as a fresh baseline. Other tags log normally.
Log.line = function(tag, msg)
  if not prefs.debug_logging or (S and S._factory_reset_clean_boot) then return end
  msg = tostring(msg)
  local ts = os.date("%H:%M:%S")
  if tag == "CHAIN" then
    if Log._last_chain_msg == msg then
      _log_write("[" .. ts .. "] [CHAIN] (chains unchanged)\n")
      return
    end
    Log._last_chain_msg = msg
  end
  _log_write("[" .. ts .. "] [" .. tag .. "] " .. msg .. "\n")
end

if RA._MIGRATE_MESSAGES then
  for _, msg in ipairs(RA._MIGRATE_MESSAGES) do
    Log.line("MIGRATE", msg)
  end
  RA._MIGRATE_MESSAGES = nil
end

if S.screen_reader_missing_action_fallback then
  Log.line("SCREEN-READER",
    "Preferred startup fell back to the standard UI because the Screen Reader action was unavailable.")
end

if RA.update_override_status then
  if RA.update_override_status.active then
    Log.line("UPDATE-OVERRIDE", string.format(
      "active mode=%s base=%s manifest=%s reason=%s",
      tostring(RA.update_override_status.mode or ""),
      tostring(RA.update_override_status.base_url or ""),
      tostring(RA.update_override_status.manifest or ""),
      tostring(RA.update_override_status.reason or "")))
  elseif RA.update_override_status.ignored then
    Log.line("UPDATE-OVERRIDE", string.format(
      "ignored mode=%s reason=%s base=%s",
      tostring(RA.update_override_status.mode or ""),
      tostring(RA.update_override_status.reason or ""),
      tostring(RA.update_override_status.base_url or "")))
  end
end

-- Exchange-summary block: mirrors the details bubble (Model, Context, Tokens,
-- Cache, Estimated cost, Response time, FX Cache) so the log captures the same
-- info the user sees on hover. Written after each completed turn.
Log.exchange_summary = function(dmsg)
  if not prefs.debug_logging or (S and S._factory_reset_clean_boot) or not dmsg then return end
  local ts = os.date("%Y-%m-%d %H:%M:%S")
  local num = Log._current_turn_num or "?"
  local L = {}
  L[#L+1] = "\n------- EXCHANGE SUMMARY #" .. tostring(num) .. " ----- " .. ts
    .. " -------------------------"
  if dmsg.model_label then
    L[#L+1] = "Model: " .. dmsg.model_label:gsub(" %b()", "")
  end
  if dmsg.thinking_label then
    L[#L+1] = "Thinking: " .. dmsg.thinking_label
  end
  if dmsg.ctx_label then
    L[#L+1] = "Context: " .. dmsg.ctx_label
  end
  if dmsg.tok_in then
    L[#L+1] = string.format("Tokens: %d in / %d out",
      dmsg.tok_in, dmsg.tok_out or 0)
    local cr = dmsg.tok_cache_read   or 0
    local cc = dmsg.tok_cache_create or 0
    if cr > 0 or cc > 0 then
      L[#L+1] = string.format("Cache: %d read, %d created", cr, cc)
    end
    if dmsg.cost and MODELS and MODELS.format_cost then
      if dmsg.free_tier then
        L[#L+1] = "Estimated cost: Free Tier (would have been ~"
          .. MODELS.format_cost(dmsg.cost) .. ")"
      else
        L[#L+1] = "Estimated cost: " .. MODELS.format_cost(dmsg.cost)
      end
    end
  end
  -- Mirror the UI Details tile's API Calls row so the log records when
  -- a turn fired more than one round-trip (silent retries: docs-gate,
  -- beta-header fallback, cache-expired refresh, intra-turn fetch).
  if dmsg.api_calls then
    L[#L+1] = "API calls: " .. tostring(dmsg.api_calls)
  end
  if dmsg.model_calls then
    L[#L+1] = "Model calls: " .. tostring(dmsg.model_calls)
  end
  if (dmsg.transport_retries or 0) > 0 then
    L[#L+1] = "Transport retries: " .. tostring(dmsg.transport_retries)
  end
  if dmsg.response_time then
    L[#L+1] = string.format("Response time: %.1fs", dmsg.response_time)
  end
  if dmsg.fx_cache_label then
    L[#L+1] = "FX Cache: " .. dmsg.fx_cache_label
  end
  _log_write(table.concat(L, "\n") .. "\n")
end

Log.clear = function()
  Log._session_header_written = false
  Log._turn_counter = 0  -- reset numbering when log is cleared
  Log._current_turn_num = nil
  Log._seen_sections = {}
  Log._last_chain_msg = nil
  local f = io.open(Log.path, "w")
  if f then f:close() end
end

-- Build a privacy-safe system info block for the session header. Uses pcall
-- around every extension probe so a missing extension never errors.
local function _build_sysinfo()
  local L = {}
  local function try(fn) local ok, v = pcall(fn); if ok then return v end end

  L[#L+1] = "--- System ---"
  L[#L+1] = "ReaAssist:       " .. tostring(CFG.VERSION)
  L[#L+1] = "REAPER:          " .. tostring(reaper.GetAppVersion())
  L[#L+1] = "OS:              " .. tostring(reaper.GetOS())
  L[#L+1] = "Lua:             " .. tostring(_VERSION)

  -- Extensions (install status + version when available).
  local js_ver = try(function() return reaper.JS_ReaScriptAPI_Version and reaper.JS_ReaScriptAPI_Version() end)
  L[#L+1] = "js_ReaScriptAPI: " .. (js_ver and tostring(js_ver) or "not installed")
  local sws_ok = (reaper.CF_GetSWSVersion ~= nil)
  local sws_ver = sws_ok and try(function() return reaper.CF_GetSWSVersion("") end) or nil
  L[#L+1] = "SWS extension:   " .. (sws_ok and (sws_ver and tostring(sws_ver) or "installed") or "not installed")
  -- ReaImGui version: try a few possible probes (signature varies across
  -- ReaImGui releases; some take no args, some take ctx, some expose a constant).
  local imgui_ver = try(function()
    if not ImGui then return nil end
    if ImGui.ImGui_GetVersion then
      local v = select(1, ImGui.ImGui_GetVersion())
      if v then return v end
    end
    if ImGui.ReaImGui_Version then return ImGui.ReaImGui_Version end
    return nil
  end)
  L[#L+1] = "ReaImGui:        " .. (imgui_ver and tostring(imgui_ver) or "unknown")

  L[#L+1] = ""
  L[#L+1] = "--- Provider / Model ---"
  local p = try(function() return PROVIDERS and PROVIDERS.active and PROVIDERS.active() end)
  L[#L+1] = "Provider:        " .. (p and p.label or "?")
  local model_id = try(function() return MODELS and MODELS.active_id and MODELS.active_id() end)
  L[#L+1] = "Model:           " .. (model_id or "?")
  if p and p.thinking_levels and prefs and p.thinking_levels[prefs.thinking_idx] then
    L[#L+1] = "Thinking:        " .. p.thinking_levels[prefs.thinking_idx].label
  end

  L[#L+1] = ""
  L[#L+1] = "--- Preferences ---"
  if prefs then
    L[#L+1] = "Auto-run:        " .. tostring(prefs.auto_run)
    L[#L+1] = "Auto-backup:     " .. tostring(prefs.auto_backup)
    L[#L+1] = "Snapshot ctx:    " .. tostring(prefs.include_snapshot)
    L[#L+1] = "API ref:         " .. tostring(prefs.include_api_ref)
  end
  L[#L+1] = "Max history:     " .. tostring(CFG and CFG.MAX_HISTORY_TURNS or "?")
  -- Coerce to a strict bool so the display reads "true"/"false" instead of
  -- "nil" when the API-ref file hasn't been read yet (Lua `and` chains
  -- short-circuit to nil rather than false when an early operand is nil,
  -- and tostring(nil) prints "nil" -- visible in the debug log header).
  local _api_ref_loaded =
    (S and S.api_ref_section_cache and S.api_ref_section_cache.core ~= nil)
      and true or false
  L[#L+1] = "API ref loaded:  " .. tostring(_api_ref_loaded)

  -- FX cache size (plugin-count only; names can be identifying so we omit them).
  local cache_count = try(function()
    if FXCache and FXCache.load then
      local c = FXCache.load()
      if c and c.plugins then
        local n = 0
        for _ in pairs(c.plugins) do n = n + 1 end
        return n
      end
    end
  end)
  if cache_count then
    L[#L+1] = "FX cache size:   " .. tostring(cache_count) .. " plugins"
  end

  -- Excluded on purpose (PII / not debug-relevant):
  --   script path (contains username), API keys, project/track names,
  --   cached plugin identifiers.

  return tbl_concat(L, "\n") .. "\n"
end

Log.session_header = function()
  if not prefs.debug_logging or (S and S._factory_reset_clean_boot) then return end
  Log._session_header_written = true
  -- Fresh log file (or first write since module load) means no prior
  -- requests for back-references to point at -- start the dedupe windows
  -- empty so the next request's repeated sections are emitted in full.
  Log._seen_sections = {}
  Log._last_chain_msg = nil
  local ts = os.date("%Y-%m-%d %H:%M:%S")
  _log_write("\n================================================================\n"
    .. "ReaAssist debug log session start: " .. ts .. "\n"
    .. "================================================================\n\n"
    .. _build_sysinfo() .. "\n")
end

-- =============================================================================
-- MODEL NAMES & PRICING  (easy to update -- edit this table when models change)
-- =============================================================================
-- Each entry: { label, id, price_in, price_out, price_cache_r [, price_cache_w] [, flags] }
-- Prices are USD per 1 million tokens.
-- Sources: anthropic.com/pricing, openai.com/api/pricing, ai.google.dev/gemini-api/docs/pricing
-- Last pricing re-check: Jul 2026. Sonnet 5 uses Anthropic promotional
-- pricing through 2026-08-31; re-check before any release on/after 2026-09-01.
-- =============================================================================
-- Provider definitions
-- =============================================================================
-- Each provider entry holds its API endpoint, authentication style, model list,
-- key format rules, and console/billing URLs. The active provider is selected
-- by prefs.provider_idx (1-based). Adding a new provider is a single table entry.
--
-- auth_style:  "header"      = key sent as an HTTP header (all providers)
-- endpoint:    static URL (Claude, OpenAI) or nil when endpoint_tpl is used.
-- endpoint_tpl: format string with %s for model id (Gemini).
-- key_prefixes: optional list of accepted key prefixes; falls back to key_prefix.
-- key_prefix_warning_only: prefix mismatch is advisory; live API test decides.
-- key_exclude: reject keys that match this prefix (prevents cross-provider confusion).
-- has_caching: true enables prompt-cache token display/accounting.
-- cache_write applies to Claude and GPT-5.6+. OpenAI reports GPT-5.6 cache
-- writes in usage.prompt_tokens_details.cache_write_tokens and bills them at
-- 1.25x uncached input; Gemini's separate per-hour storage fee is not modeled.
PROVIDERS = {
  {
    id            = "anthropic",
    label         = "Claude",
    endpoint      = "https://api.anthropic.com/v1/messages",
    auth_style    = "header",
    auth_header   = "x-api-key",
    auth_prefix   = "",
    extra_headers = {
      "anthropic-version: 2023-06-01",
    },
    key_prefix    = "sk-ant-",
    key_min_len   = 40,
    key_extstate  = "api_key",
    has_caching   = true,
    console_url   = "https://console.anthropic.com/settings/keys",
    console_label = "console.anthropic.com/settings/keys",
    billing_url   = "https://console.anthropic.com/settings/billing",
    billing_label = "console.anthropic.com/settings/billing",
    default_model_idx = 2,
    -- Anthropic thinking levels carry BOTH a budget_tokens (for the
    -- legacy manual-thinking shape, {"thinking":{"type":"enabled",
    -- "budget_tokens":N}}) AND an effort string (for the adaptive shape,
    -- {"thinking":{"type":"adaptive"},"output_config":{"effort":"..."}}).
    -- Which shape lands on the wire is decided per-MODEL via
    -- thinking_style on the model entry, because Anthropic split the
    -- thinking API across the current Claude lineup:
    --   * Haiku 4.5 (and other "Claude 4" models without adaptive
    --     support): manual budget_tokens only.
    --   * Sonnet 5 / Opus 4.8: adaptive + effort. Sending the manual
    --     shape to either model returns a 400.
    -- "None" is the explicit off switch: ReaAssist sends
    -- {"thinking":{"type":"disabled"}} so Claude cannot inherit a future
    -- adaptive-thinking default. (Mythos Preview rejects disabled thinking,
    -- but we don't ship it.)
    -- Default idx is None to match pre-existing ReaAssist behavior. The
    -- budget_tokens stay under each model's max_output. This limit is
    -- separate from the request-level max_tokens below: max_tokens is the
    -- output ceiling sent to Anthropic, while budget_tokens is only the
    -- thinking allowance for manual-thinking models.
    thinking_levels = {
      { label = "None",   value = "none"   },
      { label = "Low",    value = "low",    budget_tokens = 2048,  effort = "low"    },
      { label = "Medium", value = "medium", budget_tokens = 8192,  effort = "medium" },
      { label = "High",   value = "high",   budget_tokens = 16384, effort = "high"   },
    },
    default_thinking_idx = 1,  -- None (matches pre-thinking-support behavior)
    -- price_cache_w reflects the 5-minute cache write rate (1.25x input).
    -- build_body_anthropic emits ttl="5m" on every breakpoint (see the
    -- "Plan A" comment block in that function for why the 1h escalation
    -- was dropped). 1h writes would be 2x but we never use them.
    -- max_output: per-model output-token ceiling (Anthropic Messages API
    -- enforces server-side; we send this as max_tokens). Sourced from
    -- Anthropic's published model docs as of Jun 2026. Update when
    -- ceilings change.
    -- context_window: per-model context size used by the preflight token
    -- gate. Haiku 4.5 stays at the 200K default (no field); Sonnet 5
    -- and Opus 4.8 advertise 1M-token windows.
    -- thinking_style: which wire-format shape this model accepts.
    --   "claude_manual"   = {"thinking":{"type":"enabled","budget_tokens":N}}
    --   "claude_adaptive" = {"thinking":{"type":"adaptive"},
    --                        "output_config":{"effort":"<level>"}}
    -- Haiku 4.5 accepts manual; Sonnet 5 / Opus 4.8 use adaptive
    -- and reject manual budget_tokens.
    --
    -- default_thinking_idx (per-model override): Haiku at None/Low
    -- struggles on multi-step REAPER scripting and Medium needs a
    -- retry on complex prompts, so Haiku defaults to High (4, 16K
    -- budget) -- the only Haiku combo that handles complex routing/
    -- FX work reliably at moderate latency. Sonnet and Opus inherit
    -- the provider default of None: explicit disabled thinking on the wire,
    -- no extended thinking, lowest latency, and on this workflow no
    -- measured quality gain from raising thinking. Users can still
    -- pick a higher level via the chip if a particular prompt needs
    -- it.
    models = {
      { label = "Haiku 4.5",  chip_label = "HAIKU",  id = "claude-haiku-4-5",
