-- Provider lookup helpers. No new top-level locals; everything hangs off PROVIDERS.
PROVIDERS._by_id = {}
for i, p in ipairs(PROVIDERS) do PROVIDERS._by_id[p.id] = i end
function PROVIDERS.get(id)    return PROVIDERS[PROVIDERS._by_id[id] or 0] end
function PROVIDERS.active()   return PROVIDERS[prefs.provider_idx] end

-- Per-model thinking_idx persistence. Stored as
-- "thinking_idx_<provider_id>_<model_id>". An earlier rev of this helper
-- read the legacy "thinking_idx_<provider_id>" key as a fallback to soften
-- the upgrade, but that bled a single per-provider setting onto every
-- model in the provider (e.g. picking High on Sonnet then restarting made
-- Haiku and Opus also load High as their default until the user touched
-- each one). Cleaner: per-model keys only, with the cascade falling
-- through model.default_thinking_idx -> provider.default_thinking_idx ->
-- 1. Legacy keys still in ExtState are inert orphans; the save helper
-- writes only the per-model slot. Used by MODELS.refresh, the chip
-- dropdown's provider-switch and model-switch handlers, and the thinking-
-- pick handler.
function PROVIDERS.load_thinking_idx(p, m)
  if not p or not p.thinking_levels then return 0 end
  local saved
  if m and m.id then
    saved = (Store and Store.config_thinking_idx
              and Store.config_thinking_idx(p, m))
      or tonumber(reaper.GetExtState(
        CFG.EXT_NS, "thinking_idx_" .. p.id .. "_" .. m.id))
  end
  local tdefault = (m and m.default_thinking_idx)
                    or p.default_thinking_idx or 1
  local idx = saved or tdefault
  if idx < 1 or idx > #p.thinking_levels then idx = tdefault end
  return idx
end

function PROVIDERS.save_thinking_idx(p, m, idx)
  if not p or not p.thinking_levels then return end
  if Store and Store.remember_thinking_idx then
    Store.remember_thinking_idx(p, m, idx)
    if Store.save_config then Store.save_config() end
  end
end

-- =============================================================================
-- Custom LLM / custom-endpoint provider support
-- =============================================================================
-- Registers OpenAI-compatible chat-completions endpoints as additional
-- providers. Works with truly local servers (Ollama, LM Studio, llama.cpp,
-- vLLM, text-generation-webui) and online services that speak the OpenAI wire
-- format (OpenRouter, Groq, Together AI, Mistral, Fireworks, etc.).
-- Configured via the Custom Providers list page, persisted to Data/Providers.json.
JSON = { NULL = {}, EMPTY_ARRAY = {} }

Store = {}

function Store._log(tag, msg)
  if Log and Log.line then Log.line(tag, msg) end
end

function Store._notify_user_once(key, text, kind, sticky)
  if not key or key == "" then return end
  Store._notified = Store._notified or {}
  if Store._notified[key] then return end
  Store._notified[key] = true
  if UI and UI.show_float_toast then
    UI.show_float_toast(text, kind or "err", sticky == true)
  else
    Store._pending_toast = {
      text = text,
      kind = kind or "err",
      sticky = sticky == true,
    }
  end
end

function Store.flush_user_notice()
  local tip = Store._pending_toast
  if not tip or not (UI and UI.show_float_toast) then return end
  Store._pending_toast = nil
  UI.show_float_toast(tip.text, tip.kind, tip.sticky)
end

function Store._notify_write_failure(label, err)
  Store._log("STORE", tostring(label or "data") .. " save failed: "
    .. tostring(err or "unknown error"))
  Store._notify_user_once("write_failure",
    "Could not save ReaAssist data. Check Data folder permissions.",
    "err", true)
end

function Store._atomic_write_suffix()
  if RA and RA.instance_file_suffix then
    return "." .. RA.instance_file_suffix()
  end
  local raw = tostring(CMD_ID or "session"):gsub("[^%w%-_]", "_")
  if raw == "" then raw = "session" end
  return ".inst_" .. raw
end

-- ===== atomic file IO (sliced by Dev/Tests/test_atomic_write.lua) =====
Store._read_failed_paths = Store._read_failed_paths or {}

function Store._mark_read_failed(path)
  if path and path ~= "" then Store._read_failed_paths[path] = true end
end

function Store._clear_read_failed(path)
  if path and path ~= "" and Store._read_failed_paths then
    Store._read_failed_paths[path] = nil
  end
end

function Store._path_read_failed(path)
  return path and path ~= "" and Store._read_failed_paths
    and Store._read_failed_paths[path] == true
end

function Store._should_quarantine_json_read_error(err)
  return err and err ~= "missing" and err ~= "empty" and err ~= "read_failed"
end

function Store._open_error_is_missing(err, code)
  if code == 2 then return true end
  local msg = tostring(err or ""):lower()
  return msg:find("no such file", 1, true) ~= nil
    or msg:find("not found", 1, true) ~= nil
    or msg:find("cannot find", 1, true) ~= nil
end

function Store._read_text_file(path)
  if not path or path == "" then return nil, "missing" end
  local ok_f, f, ferr, fcode = pcall(io.open, path, "r")
  if not ok_f then return nil, "read_failed", f end
  if not f then
    if Store._open_error_is_missing(ferr, fcode) then
      return nil, "missing", ferr
    end
    return nil, "read_failed", ferr or "open failed"
  end

  local ok_r, raw, rerr = pcall(f.read, f, "*a")
  local ok_c, c_ok, c_err = pcall(f.close, f)
  if not ok_r then return nil, "read_failed", raw end
  if raw == nil then return nil, "read_failed", rerr or "read failed" end
  if not ok_c or not c_ok then
    return nil, "read_failed",
      ((not ok_c) and c_ok) or c_err or "close failed"
  end
  return raw, nil
end

function Store.atomic_write_file(path, data, opts)
  if not path or path == "" then return "Missing file path." end
  opts = opts or {}
  local suffix = tostring(opts.suffix or "")
  local tmp_path = path .. ".tmp" .. suffix
  local bak_path = path .. ".bak" .. suffix
  local mode = opts.binary and "wb" or "w"
  local ok_f, f = pcall(io.open, tmp_path, mode)
  if not ok_f or not f then
    return "Failed to open " .. tmp_path .. ": " .. tostring(f or "open failed")
  end

  local p_w, w_ok, w_err = pcall(f.write, f, tostring(data or ""))
  local p_c, c_ok, c_err = pcall(f.close, f)
  if not p_w or not w_ok or not p_c or not c_ok then
    os.remove(tmp_path)
    local write_err = (not p_w) and w_ok or w_err
    local close_err = (not p_c) and c_ok or c_err
    return "Failed writing " .. tmp_path .. ": "
      .. tostring(write_err or close_err or "write/close failed")
  end

  os.remove(bak_path)
  local had_existing = os.rename(path, bak_path)
  local ok_r, ren_err = os.rename(tmp_path, path)
  if not ok_r then
    os.remove(tmp_path)
    if had_existing then os.rename(bak_path, path) end
    return "Failed renaming temp file: " .. tostring(ren_err)
  end
  if had_existing then os.remove(bak_path) end
  return nil
end

function Store.read_json(path, default_value, schema_version)
  local raw, read_err, read_detail = Store._read_text_file(path)
  if raw == nil and read_err == "read_failed" then
    raw, read_err, read_detail = Store._read_text_file(path)
  end
  if raw == nil then
    if read_err == "read_failed" then
      Store._mark_read_failed(path)
      Store._log("STORE", "read failed for " .. tostring(path)
        .. ": " .. tostring(read_detail or "unknown error"))
      return default_value, "read_failed"
    end
    return default_value, "missing"
  end
  Store._clear_read_failed(path)
  if raw == "" then return default_value, "empty" end
  local data, err = JSON.decode(raw)
  if not data then
    Store._log("STORE", "JSON decode failed for " .. tostring(path)
      .. ": " .. tostring(err))
    return default_value, err or "decode failed"
  end
  if type(data) ~= "table" then return default_value, "not an object" end
  if schema_version and data.schema_version ~= schema_version then
    Store._log("STORE", "schema mismatch for " .. tostring(path)
      .. " (file=" .. tostring(data.schema_version)
      .. ", expected=" .. tostring(schema_version) .. ")")
    return default_value, "schema mismatch"
  end
  return data, nil
end

function Store.write_json_atomic(path, value, skip_unchanged)
  if not path or path == "" then return "Missing JSON path." end
  local json_str, err = JSON.encode(value, "  ")
  if not json_str then return "JSON encode failed: " .. tostring(err) end
  local payload = json_str .. "\n"
  if Store._path_read_failed(path) then
    return "Refusing to overwrite " .. tostring(path) .. ": last read failed"
  end
  if skip_unchanged then
    local existing, read_err, read_detail = Store._read_text_file(path)
    if read_err == "read_failed" then
      Store._mark_read_failed(path)
      return "Refusing to overwrite " .. tostring(path)
        .. ": existing file could not be read (" .. tostring(read_detail) .. ")"
    end
    if existing == payload then return nil, true end
  end

  local write_err = Store.atomic_write_file(path, payload,
    { suffix = Store._atomic_write_suffix() })
  if write_err then return write_err end
  return nil, false
end
-- close atomic-write scope

function Store.json_array(list)
  if type(list) ~= "table" or #list == 0 then return JSON.EMPTY_ARRAY end
  return list
end

function Store._json_string(value)
  if value == nil or value == JSON.NULL then return "" end
  return tostring(value):match("^%s*(.-)%s*$") or ""
end

function Store._extra_body_object(raw, label)
  if raw == nil or raw == JSON.NULL then return {} end
  if type(raw) == "table" and raw ~= JSON.NULL then return raw end
  raw = Store._json_string(raw)
  if raw == "" then return {} end
  local obj, err = JSON.decode(raw)
  if err or type(obj) ~= "table" or obj == JSON.NULL then
    Store._log("PROVIDERS", "dropping invalid extra_body for "
      .. tostring(label or "custom provider") .. ": " .. tostring(err))
    return {}
  end
  local n = 0
  local is_array = true
  for k in pairs(obj) do
    n = n + 1
    if type(k) ~= "number" then is_array = false end
  end
  if n > 0 and is_array then
    Store._log("PROVIDERS", "dropping array extra_body for "
      .. tostring(label or "custom provider"))
    return {}
  end
  return obj
end

function Store._extra_body_string(value, label)
  if value == nil or value == JSON.NULL then return "" end
  if type(value) == "string" then
    value = Store._extra_body_object(value, label)
  end
  if type(value) ~= "table" then
    Store._log("PROVIDERS", "dropping non-object extra_body for "
      .. tostring(label or "custom provider"))
    return ""
  end

  local n = 0
  local is_array = true
  for k in pairs(value) do
    n = n + 1
    if type(k) ~= "number" then is_array = false end
  end
  if n == 0 then return "" end
  if is_array then
    Store._log("PROVIDERS", "dropping array extra_body for "
      .. tostring(label or "custom provider"))
    return ""
  end

  local encoded, err = JSON.encode(value)
  if not encoded or encoded == "{}" then
    if err then
      Store._log("PROVIDERS", "failed to encode extra_body for "
        .. tostring(label or "custom provider") .. ": " .. tostring(err))
    end
    return ""
  end
  return encoded
end

function Store._provider_record_to_json(record)
  local headers = {}
  for _, h in ipairs(record.extra_headers or {}) do
    headers[#headers+1] = h
  end

  local models = {}
  for _, m in ipairs(record.models or {}) do
    local notes = Store._json_string(m.notes)
    local clean_notes, note_err = Custom.validate_notes(notes)
    if not clean_notes then
      Store._log("PROVIDERS", "stripping invalid notes for "
        .. tostring(record.id or "") .. "/" .. tostring(m.id or "")
        .. ": " .. tostring(note_err))
      clean_notes = ""
    end
    local model_out = {
      id             = m.id or "",
      price_in       = tonumber(m.price_in) or 0,
      price_out      = tonumber(m.price_out) or 0,
      price_cache_r  = tonumber(m.price_cache_r) or 0,
      context_window = tonumber(m.context_window) or CUSTOM_DEFAULT_CTX,
      notes          = clean_notes,
    }
    local model_body = Store._extra_body_object(m.extra_body,
      tostring(record.id or "") .. "/" .. tostring(m.id or ""))
    if next(model_body) then model_out.extra_body = model_body end
    models[#models+1] = model_out
  end

  local out = {
    id                   = record.id or "",
    label                = record.label or "",
    endpoint             = Custom.normalize_chat_endpoint(record.endpoint or ""),
    timeout_secs         = tonumber(record.timeout_secs) or CUSTOM_DEFAULT_TIMEOUT,
    connect_timeout_secs = tonumber(record.connect_timeout_secs)
                              or Custom.DEFAULT_CONNECT,
    allow_insecure       = record.allow_insecure and true or false,
    model_prefix         = record.model_prefix or "",
    extra_headers        = Store.json_array(headers),
    models               = Store.json_array(models),
  }
  local provider_body = Store._extra_body_object(record.extra_body, record.id)
  if next(provider_body) then out.extra_body = provider_body end
  return out
end

function Store._provider_record_from_json(src, index)
  if type(src) ~= "table" then return nil end
  local id = Store._json_string(src.id)
  if id == "" then
    Store._log("PROVIDERS", "skipping Providers.json record "
      .. tostring(index or "?") .. ": missing id")
    return nil
  end

  local endpoint = Custom.normalize_chat_endpoint(Store._json_string(src.endpoint))
  if not Custom.endpoint_is_safe(endpoint) then
    Store._log("PROVIDERS", "skipping Providers.json record "
      .. tostring(id) .. ": invalid endpoint")
    return nil
  end

  local models = {}
  if type(src.models) == "table" then
    for _, m in ipairs(src.models) do
      if type(m) == "table" then
        local model_id = Store._json_string(m.id)
        if model_id ~= "" then
          local ctx = tonumber(m.context_window) or CUSTOM_DEFAULT_CTX
          if ctx < CUSTOM_MIN_CTX then ctx = CUSTOM_MIN_CTX end
          local notes = Store._json_string(m.notes)
          local clean_notes, note_err = Custom.validate_notes(notes)
          if not clean_notes then
            Store._log("PROVIDERS", "stripping invalid notes for "
              .. id .. "/" .. model_id .. ": " .. tostring(note_err))
            clean_notes = ""
          end
          models[#models+1] = {
            id             = model_id,
            price_in       = tonumber(m.price_in) or 0,
            price_out      = tonumber(m.price_out) or 0,
            price_cache_r  = tonumber(m.price_cache_r) or 0,
            context_window = ctx,
            notes          = clean_notes,
            extra_body     = Store._extra_body_string(m.extra_body,
                               id .. "/" .. model_id),
          }
        end
      end
    end
  end
  if #models == 0 then
    Store._log("PROVIDERS", "skipping Providers.json record "
      .. tostring(id) .. ": no valid models")
    return nil
  end

  local timeout = tonumber(src.timeout_secs) or CUSTOM_DEFAULT_TIMEOUT
  if timeout < CUSTOM_MIN_TIMEOUT then timeout = CUSTOM_MIN_TIMEOUT end
  if timeout > CUSTOM_MAX_TIMEOUT then timeout = CUSTOM_MAX_TIMEOUT end

  local connect_t = tonumber(src.connect_timeout_secs) or Custom.DEFAULT_CONNECT
  if connect_t < Custom.MIN_CONNECT then connect_t = Custom.MIN_CONNECT end
  if connect_t > Custom.MAX_CONNECT then connect_t = Custom.MAX_CONNECT end

  local headers = {}
  if type(src.extra_headers) == "table" then
    for _, h in ipairs(src.extra_headers) do
      h = Store._json_string(h)
      if h ~= "" and Custom.header_is_safe(h) and h:find(":", 1, true) then
        headers[#headers+1] = h
      end
    end
  end

  local label = Store._json_string(src.label)
  return {
    id                   = id,
    label                = (label ~= "" and label) or "Custom",
    endpoint             = endpoint,
    timeout_secs         = timeout,
    connect_timeout_secs = connect_t,
    allow_insecure       = (src.allow_insecure == true or src.allow_insecure == "1"),
    model_prefix         = Store._json_string(src.model_prefix),
    extra_headers        = headers,
    extra_body           = Store._extra_body_string(src.extra_body, id),
    models               = models,
  }
end

function Store.load_providers()
  local doc, err = Store.read_json(RA.PROVIDERS_PATH, nil, 1)
  if not doc then
    if Store._should_quarantine_json_read_error(err) then
      Store._quarantine_json(RA.PROVIDERS_PATH, err)
    end
    return nil, err or "missing"
  end
  if type(doc.records) ~= "table" then
    Store._quarantine_json(RA.PROVIDERS_PATH, "records missing")
    return nil, "records missing"
  end

  -- A valid empty records array is authoritative: it means the file says
  -- "there are no custom providers", so we do not fall through to ExtState.
  local records = {}
  local saw_record = false
  for i, src in ipairs(doc.records) do
    saw_record = true
    local rec = Store._provider_record_from_json(src, i)
    if rec then records[#records+1] = rec end
  end
  if saw_record and #records == 0 then return nil, "no valid provider records" end
  return records, nil
end

function Store._quarantine_json(path, reason)
  if not path or path == "" then return nil end
  if reason == "read_failed" then
    Store._log("STORE", "not quarantining " .. tostring(path)
      .. " after transient read failure")
    return nil
  end
  if RA._file_exists and not RA._file_exists(path) then return nil end
  local stamp = tostring(os.time())
  local bak_paths = {
    path .. ".bak", -- legacy pre-instance-suffix backup
    path .. ".bak" .. Store._atomic_write_suffix(),
  }
  for _, bak_path in ipairs(bak_paths) do
    if RA._file_exists and RA._file_exists(bak_path) then
      local bak_dst = bak_path .. ".corrupt." .. stamp
      local bak_ok, bak_err = os.rename(bak_path, bak_dst)
      if bak_ok then
        Store._log("STORE", "preserved JSON backup as " .. tostring(bak_dst))
      else
        Store._log("STORE", "could not preserve JSON backup " .. tostring(bak_path)
          .. ": " .. tostring(bak_err))
      end
    end
  end
  local dst = path .. ".corrupt." .. stamp
  local ok, err = os.rename(path, dst)
  if ok then
    Store._log("STORE", "moved corrupt JSON to " .. tostring(dst)
      .. " (" .. tostring(reason or "invalid") .. ")")
    Store._notify_user_once("json_quarantine",
      "A damaged ReaAssist data file was quarantined in Data.", "err", false)
  else
    Store._log("STORE", "could not move corrupt JSON " .. tostring(path)
      .. ": " .. tostring(err))
    Store._notify_user_once("json_quarantine_failed",
      "A ReaAssist data file looks damaged. Check the Data folder.", "err", true)
  end
  return ok
end

function Store.delete_extstate_keys(keys)
  for _, key in ipairs(keys or {}) do
    if key and key ~= "" then
      reaper.DeleteExtState(CFG.EXT_NS, key, true)
    end
  end
end

function Store.cleanup_config_extstate(doc)
  local keys = {
    "auto_run",
    "auto_backup",
    "show_details",
    "custom_instructions_enabled",
    "debug_logging",
    "include_api_ref",
    "include_snapshot",
    "update_check",
    "screen_reader_concise_hints",
    "screen_reader_text_size_idx",
    "screen_reader_contrast",
    "typed_actions_opt_in",
    "diag_auto_tier",
    "ui_scale_idx",
    "theme",
    "chat_font_idx",
    "reply_language_idx",
    "language_code",
    "cloud_request_timeout",
    "turn_cost_limit_usd",
    "turn_token_limit",
    "provider_id",
    "provider_idx",
    "win_x",
    "win_y",
    "win_w",
    "win_h",
    "tos_accepted_version",
    "first_launch_complete",
    "reaper_version_notice_dismissed",
    "thinking_idx_reset_v1",
    "model_picker_reset_v2",
    "anthropic_opus_48_model_v1",
    "google_flash_35_model_v1",
    "google_flash_35_minimal_default_v1",
    "update_check_default_on_v1",
  }
  if PROVIDERS then
    for _, p in ipairs(PROVIDERS) do
      if p and p.id then
        keys[#keys+1] = "model_idx_" .. p.id
        keys[#keys+1] = "thinking_idx_" .. p.id
        if p.models then
          for _, m in ipairs(p.models) do
            if m and m.id then
              keys[#keys+1] = "thinking_idx_" .. p.id .. "_" .. m.id
            end
          end
        end
      end
    end
  end
  local sel = type(doc) == "table" and doc.selection or nil
  local think_map = type(sel) == "table"
    and sel.thinking_idx_by_provider_model or nil
  if type(think_map) == "table" then
    for key in pairs(think_map) do
      local provider_id, model_id = tostring(key):match("^(.-)/(.*)$")
      if provider_id and model_id then
        keys[#keys+1] = "thinking_idx_" .. provider_id .. "_" .. model_id
      end
    end
  end
  Store.delete_extstate_keys(keys)
end

function Store.cleanup_state_extstate()
  Store.delete_extstate_keys({
    "update_last_check",
    "update_snooze",
    "os_theme_cache",
    "os_theme_cache_ts",
    "gemini_paid_tier",
    "gemini_cache_name",
    "gemini_cache_model",
    "gemini_cache_signature",
    "gemini_cache_expires",
    "openai_prompt_cache_key",
    "ceiling_next_base",
    "ceiling_slots",
    "diag_auto_last_ping_at",
    "diag_auto_last_sent_at",
  })
end

function Store.cleanup_providers_extstate(records)
  local ids = {}
  local seen = {}
  local function add_id(id)
    if type(id) == "string" and id ~= "" and not seen[id] then
      seen[id] = true
      ids[#ids+1] = id
    end
  end
  for _, record in ipairs(records or {}) do add_id(record.id) end
  if Custom and Custom.load_ids then
    for _, id in ipairs(Custom.load_ids()) do add_id(id) end
  end
  reaper.DeleteExtState(CFG.EXT_NS, "custom_provider_ids", true)
  for _, id in ipairs(ids) do
    if Custom and Custom.delete_record_extstate then
      Custom.delete_record_extstate(id, false)
    else
      Store.delete_extstate_keys({
        "custom_" .. id .. "_endpoint",
        "custom_" .. id .. "_label",
        "custom_" .. id .. "_timeout_secs",
        "custom_" .. id .. "_connect_timeout",
        "custom_" .. id .. "_allow_insecure",
        "custom_" .. id .. "_model_prefix",
        "custom_" .. id .. "_extra_headers",
        "custom_" .. id .. "_extra_body",
        "custom_" .. id .. "_models",
      })
    end
  end
end

function Store.seed_config_from_extstate(doc)
  doc = type(doc) == "table" and doc or {}
  doc.notices = type(doc.notices) == "table" and doc.notices or {}
  local tos = reaper.GetExtState(CFG.EXT_NS, "tos_accepted_version")
  if tos ~= "" and doc.notices.tos_accepted_version == nil then
    doc.notices.tos_accepted_version = tos
  end
  if reaper.GetExtState(CFG.EXT_NS, "first_launch_complete") == "1" then
    doc.notices.first_launch_complete = true
  end
  if reaper.GetExtState(CFG.EXT_NS, "reaper_version_notice_dismissed") == "true" then
    doc.notices.reaper_version_notice_dismissed = true
  end

  doc.migrations = type(doc.migrations) == "table" and doc.migrations or {}
  if reaper.GetExtState(CFG.EXT_NS, "thinking_idx_reset_v1") == "1" then
    doc.migrations.thinking_idx_reset_v1 = true
  end
  if reaper.GetExtState(CFG.EXT_NS, "model_picker_reset_v2") == "1" then
    doc.migrations.model_picker_reset_v2 = true
  end
  if reaper.GetExtState(CFG.EXT_NS, "update_check_default_on_v1") == "1" then
    doc.migrations.update_check_default_on_v1 = true
  end

  if type(doc.window) ~= "table" then
    local x = tonumber(reaper.GetExtState(CFG.EXT_NS, "win_x"))
    local y = tonumber(reaper.GetExtState(CFG.EXT_NS, "win_y"))
    local w = tonumber(reaper.GetExtState(CFG.EXT_NS, "win_w"))
    local h = tonumber(reaper.GetExtState(CFG.EXT_NS, "win_h"))
    if x and y and w and h then
      doc.window = { x = math_floor(x), y = math_floor(y),
        w = math_floor(w), h = math_floor(h) }
    end
  end

  return doc
end

function Store.config_doc()
  if Store._config_doc then return Store._config_doc end
  local doc, err = Store.read_json(RA.CONFIG_PATH, nil, 1)
  if doc then
    Store._config_doc = Store.seed_config_from_extstate(doc)
    return Store._config_doc
  end
  if Store._should_quarantine_json_read_error(err) then
    Store._quarantine_json(RA.CONFIG_PATH, err)
  end
  Store._config_doc = Store.seed_config_from_extstate({ schema_version = 1 })
  return Store._config_doc
end

function Store.config_pref_value(key)
  local doc = Store.config_doc()
  local p = doc and doc.preferences
  if type(p) ~= "table" then return nil end
  return p[key]
end

function Store.tos_is_accepted(version)
  local doc = Store.config_doc()
  doc.notices = type(doc.notices) == "table" and doc.notices or {}
  local accepted = doc.notices.tos_accepted_version == version
    or reaper.GetExtState(CFG.EXT_NS, "tos_accepted_version") == version
  if accepted then
    doc.notices.tos_accepted_version = version
  end
  return accepted
end

function Store.mark_tos_accepted(version)
  local doc = Store.config_doc()
  doc.notices = type(doc.notices) == "table" and doc.notices or {}
  doc.notices.tos_accepted_version = version
  doc.notices.first_launch_complete = true
  return Store.save_config()
end

function Store.first_launch_complete()
  local doc = Store.config_doc()
  doc.notices = type(doc.notices) == "table" and doc.notices or {}
  local complete = doc.notices.first_launch_complete == true
    or reaper.GetExtState(CFG.EXT_NS, "first_launch_complete") == "1"
  if complete then
    doc.notices.first_launch_complete = true
  end
  return complete
end

function Store.mark_first_launch_complete()
  local doc = Store.config_doc()
  doc.notices = type(doc.notices) == "table" and doc.notices or {}
  doc.notices.first_launch_complete = true
  return Store.save_config()
end

function Store.reaper_version_notice_dismissed()
  local doc = Store.config_doc()
  doc.notices = type(doc.notices) == "table" and doc.notices or {}
  local dismissed = doc.notices.reaper_version_notice_dismissed == true
    or reaper.GetExtState(CFG.EXT_NS, "reaper_version_notice_dismissed") == "true"
  if dismissed then
    doc.notices.reaper_version_notice_dismissed = true
  end
  return dismissed
end

function Store.dismiss_reaper_version_notice()
  local doc = Store.config_doc()
  doc.notices = type(doc.notices) == "table" and doc.notices or {}
  doc.notices.reaper_version_notice_dismissed = true
  return Store.save_config()
end

function Store._pref_bool(key, fallback)
  local v = Store.config_pref_value(key)
  if type(v) == "boolean" then return v end
  return fallback
end

function Store._pref_number(key, fallback, min_v, max_v)
  local v = tonumber(Store.config_pref_value(key))
  if not v then return fallback end
  if min_v and v < min_v then return fallback end
  if max_v and v > max_v then return fallback end
  return v
end

function Store._pref_index(key, fallback, list)
  local v = tonumber(Store.config_pref_value(key))
  if not v then return fallback end
  if v < 1 or v > #list then return fallback end
  return math_floor(v)
end

function Store.current_preferences()
  return {
    auto_run              = prefs.auto_run and true or false,
    auto_backup           = prefs.auto_backup and true or false,
    show_details          = prefs.show_details and true or false,
    custom_instructions_enabled =
      prefs.custom_instructions_enabled and true or false,
    debug_logging         = prefs.debug_logging and true or false,
    include_api_ref       = prefs.include_api_ref and true or false,
    include_snapshot      = prefs.include_snapshot and true or false,
    update_check          = prefs.update_check and true or false,
    screen_reader_concise_hints =
      prefs.screen_reader_concise_hints and true or false,
    screen_reader_text_size_idx = prefs.screen_reader_text_size_idx or 1,
    screen_reader_contrast = prefs.screen_reader_contrast or "auto",
    diag_auto_tier        = prefs.diag_auto_tier or "off",
    ui_scale_idx          = prefs.ui_scale_idx or 3,
    theme                 = prefs.theme or "auto",
    chat_font_idx         = prefs.chat_font_idx or 2,
    reply_language_idx    = prefs.reply_language_idx or 1,
    language_code         = CFG.current_language_code
                              and CFG.current_language_code() or "en",
    cloud_request_timeout = prefs.cloud_request_timeout
                              or CFG.CLOUD_TIMEOUT_DEFAULT,
    turn_cost_limit_usd   = prefs.turn_cost_limit_usd
                              or CFG.TURN_COST_LIMIT_DEFAULT,
    turn_token_limit      = prefs.turn_token_limit
                              or CFG.TURN_TOKEN_LIMIT_DEFAULT,
  }
end

function Store.sync_config_prefs_to_extstate()
  Store.cleanup_config_extstate_if_persisted(Store.config_doc())
end

function Store.apply_config_preferences()
  local doc = Store.config_doc()
  local p = doc and doc.preferences
  if type(p) ~= "table" then return nil end

  prefs.auto_run         = Store._pref_bool("auto_run", prefs.auto_run)
  prefs.auto_backup      = Store._pref_bool("auto_backup", prefs.auto_backup)
  prefs.show_details     = Store._pref_bool("show_details", prefs.show_details)
  prefs.custom_instructions_enabled =
    Store._pref_bool("custom_instructions_enabled",
      prefs.custom_instructions_enabled)
  prefs.debug_logging    = Store._pref_bool("debug_logging", prefs.debug_logging)
  prefs.include_api_ref  = Store._pref_bool("include_api_ref", prefs.include_api_ref)
  prefs.include_snapshot = Store._pref_bool("include_snapshot", prefs.include_snapshot)
  prefs.update_check     = Store._pref_bool("update_check", prefs.update_check)
  prefs.screen_reader_concise_hints =
    Store._pref_bool("screen_reader_concise_hints",
      prefs.screen_reader_concise_hints)
  prefs.screen_reader_text_size_idx = Store._pref_index(
    "screen_reader_text_size_idx", prefs.screen_reader_text_size_idx,
    CFG.SCREEN_READER_TEXT_SIZE_LABELS)
  local sr_contrast = Store.config_pref_value("screen_reader_contrast")
  if sr_contrast == "auto" or sr_contrast == "dark"
      or sr_contrast == "light" then
    prefs.screen_reader_contrast = sr_contrast
  end

  local tier = Store.config_pref_value("diag_auto_tier")
  if tier == "basic" or tier == "extended" or tier == "off" then
    prefs.diag_auto_tier = tier
  end

  prefs.ui_scale_idx = Store._pref_index(
    "ui_scale_idx", prefs.ui_scale_idx, CFG.UI_SCALE_OPTIONS)
  local theme = Store.config_pref_value("theme")
  if theme == "auto" or theme == "dark" or theme == "light" then
    prefs.theme = theme
  end
  prefs.chat_font_idx = Store._pref_index(
    "chat_font_idx", prefs.chat_font_idx, CFG.CHAT_FONT_SIZES)
  local reply_idx = Store._pref_index(
    "reply_language_idx", prefs.reply_language_idx, CFG.REPLY_LANGUAGE_LABELS)
  local lang_code = Store.config_pref_value("language_code")
  if CFG.is_valid_language_code and CFG.is_valid_language_code(lang_code) then
    prefs.language_code = lang_code
    prefs.reply_language_idx =
      CFG.legacy_idx_for_language_code(lang_code) or reply_idx
  else
    prefs.reply_language_idx = reply_idx
    prefs.language_code = (CFG.language_code_for_legacy_idx
      and CFG.language_code_for_legacy_idx(prefs.reply_language_idx)) or "en"
  end
  prefs.cloud_request_timeout = math_floor(Store._pref_number(
    "cloud_request_timeout",
    prefs.cloud_request_timeout or CFG.CLOUD_TIMEOUT_DEFAULT,
    CFG.CLOUD_TIMEOUT_MIN, CFG.CLOUD_TIMEOUT_MAX))
  prefs.turn_cost_limit_usd = Store._pref_number(
    "turn_cost_limit_usd",
    prefs.turn_cost_limit_usd or CFG.TURN_COST_LIMIT_DEFAULT,
    CFG.TURN_COST_LIMIT_MIN, CFG.TURN_COST_LIMIT_MAX)
  prefs.turn_token_limit = math_floor(Store._pref_number(
    "turn_token_limit",
    prefs.turn_token_limit or CFG.TURN_TOKEN_LIMIT_DEFAULT,
    CFG.TURN_TOKEN_LIMIT_MIN, CFG.TURN_TOKEN_LIMIT_MAX))
  return true
end

function Store._model_index_by_id(list, model_id)
  if not list or not model_id or model_id == "" then return nil end
  for i, m in ipairs(list) do
    if m.id == model_id then return i end
  end
  return nil
end

function Store.config_provider_idx(fallback)
  local doc = Store.config_doc()
  local sel = doc and doc.selection
  local provider_id = type(sel) == "table" and sel.provider_id or nil
  local idx = provider_id and PROVIDERS and PROVIDERS._by_id
    and PROVIDERS._by_id[provider_id] or nil
  return idx or fallback
end

function Store.config_model_idx(provider, models, fallback)
  local doc = Store.config_doc()
  local sel = doc and doc.selection
  local map = type(sel) == "table" and sel.model_id_by_provider or nil
  local model_id = type(map) == "table" and provider and map[provider.id] or nil
  return Store._model_index_by_id(models, model_id) or fallback
end

function Store.config_thinking_idx(provider, model)
  if not provider or not model or not model.id then return nil end
  local doc = Store.config_doc()
  local sel = doc and doc.selection
  local map = type(sel) == "table" and sel.thinking_idx_by_provider_model or nil
  local key = provider.id .. "/" .. model.id
  return type(map) == "table" and tonumber(map[key]) or nil
end

function Store._selection_doc()
  local doc = Store.config_doc()
  doc.selection = type(doc.selection) == "table" and doc.selection or {}
  doc.selection.model_id_by_provider =
    type(doc.selection.model_id_by_provider) == "table"
    and doc.selection.model_id_by_provider or {}
  doc.selection.thinking_idx_by_provider_model =
    type(doc.selection.thinking_idx_by_provider_model) == "table"
    and doc.selection.thinking_idx_by_provider_model or {}
  return doc.selection
end

function Store.remember_model_idx(provider, models, idx)
  if not provider or not provider.id then return end
  idx = tonumber(idx)
  local model = models and idx and models[idx] or nil
  if not (model and model.id) then return end
  local sel = Store._selection_doc()
  sel.model_id_by_provider[provider.id] = model.id
end

function Store.remember_thinking_idx(provider, model, idx)
  if not (provider and provider.id and model and model.id) then return end
  idx = tonumber(idx)
  if not idx then return end
  local sel = Store._selection_doc()
  sel.thinking_idx_by_provider_model[provider.id .. "/" .. model.id] = idx
end

function Store.current_selection()
  local doc = Store.config_doc()
  local previous = type(doc.selection) == "table" and doc.selection or {}
  local prev_model_map = type(previous.model_id_by_provider) == "table"
    and previous.model_id_by_provider or {}
  local prev_think_map = type(previous.thinking_idx_by_provider_model) == "table"
    and previous.thinking_idx_by_provider_model or {}
  local selection = {
    provider_id                    = nil,
    model_id_by_provider           = {},
    thinking_idx_by_provider_model = {},
  }
  local function provider_known(id)
    return not (PROVIDERS and PROVIDERS._by_id) or PROVIDERS._by_id[id]
  end
  for k, v in pairs(prev_model_map) do
    if provider_known(k) then selection.model_id_by_provider[k] = v end
  end
  for k, v in pairs(prev_think_map) do
    local provider_id = tostring(k):match("^(.-)/")
    if provider_known(provider_id) then
      selection.thinking_idx_by_provider_model[k] = v
    end
  end
  local active_provider = PROVIDERS and PROVIDERS.active and PROVIDERS.active()
  if active_provider then selection.provider_id = active_provider.id end

  if PROVIDERS then
    for _, p in ipairs(PROVIDERS) do
      local models = (active_provider and p.id == active_provider.id)
        and MODELS or p.models
      local idx
      if active_provider and p.id == active_provider.id then
        idx = prefs.model_idx
      else
        idx = Store._model_index_by_id(models, selection.model_id_by_provider[p.id])
          or tonumber(reaper.GetExtState(CFG.EXT_NS, "model_idx_" .. p.id))
      end
      local m = models and idx and models[idx] or nil
      if m and m.id then selection.model_id_by_provider[p.id] = m.id end

      if p.thinking_levels and p.models then
        for _, tm in ipairs(p.models) do
          if tm.id then
            local key = p.id .. "/" .. tm.id
            local saved = tonumber(selection.thinking_idx_by_provider_model[key])
              or tonumber(reaper.GetExtState(
                CFG.EXT_NS, "thinking_idx_" .. p.id .. "_" .. tm.id))
            if active_provider and p.id == active_provider.id
               and models and models[prefs.model_idx]
               and models[prefs.model_idx].id == tm.id
               and prefs.thinking_idx and prefs.thinking_idx > 0 then
              saved = prefs.thinking_idx
            end
            if saved then selection.thinking_idx_by_provider_model[key] = saved end
          end
        end
      end
    end
  end
  return selection
end

function Store.has_usable_provider()
  if not PROVIDERS then return false end
  for _, p in ipairs(PROVIDERS) do
    if Store.provider_has_usable_credentials(p) then
      return true
    end
  end
  return false
end

function Store.provider_has_usable_credentials(p)
  if not p then return false end
  if p.is_custom then return true end
  local key = S.api_key_map and S.api_key_map[p.id] or nil
  return type(key) == "string" and key ~= ""
end

function Store.first_usable_provider_idx()
  if not PROVIDERS then return nil end
  for i, p in ipairs(PROVIDERS) do
    if Store.provider_has_usable_credentials(p) then
      return i, p
    end
  end
  return nil
end

function Store.ensure_usable_provider_selection(reason)
  if not PROVIDERS then return false end
  local active = PROVIDERS.active and PROVIDERS.active() or nil
  if Store.provider_has_usable_credentials(active) then
    S.api_key = S.api_key_map and S.api_key_map[active.id] or nil
    return false
  end

  local fallback_idx, fallback = Store.first_usable_provider_idx()
  if not fallback_idx then
    S.api_key = nil
    return false
  end

  local previous_id = active and active.id or "none"
  prefs.provider_idx = fallback_idx
  if MODELS and MODELS.refresh then MODELS.refresh() end
  S.api_key = S.api_key_map and S.api_key_map[fallback.id] or nil
  Store._log("Provider", string.format(
    "Switched active provider from %s to %s because %s.",
    previous_id, fallback.id,
    reason or "the saved provider has no usable credentials"))
  return true
end

function Store.sync_config_selection_to_extstate(selection)
  Store.cleanup_config_extstate_if_persisted(Store.config_doc())
end

function Store.migration_fired(key)
  local doc = Store.config_doc()
  doc.migrations = type(doc.migrations) == "table" and doc.migrations or {}
  local fired = (doc.migrations[key] == true)
    or (reaper.GetExtState(CFG.EXT_NS, key) == "1")
  if fired then
    doc.migrations[key] = true
  end
  return fired
end

function Store.set_migration_fired(key)
  local doc = Store.config_doc()
  doc.migrations = type(doc.migrations) == "table" and doc.migrations or {}
  doc.migrations[key] = true
  return Store.save_config()
end

function Store.clear_thinking_selections()
  local doc = Store.config_doc()
  doc.selection = type(doc.selection) == "table" and doc.selection or {}
  doc.selection.thinking_idx_by_provider_model = {}
end

function Store.clear_model_picker_selections()
  local doc = Store.config_doc()
  doc.selection = type(doc.selection) == "table" and doc.selection or {}
  doc.selection.model_id_by_provider = {}
  doc.selection.thinking_idx_by_provider_model = {}
end

function Store.window_geometry()
  local doc = Store.config_doc()
  local w = doc and doc.window
  if type(w) ~= "table" then return nil end
  local x, y = tonumber(w.x), tonumber(w.y)
  local ww, wh = tonumber(w.w), tonumber(w.h)
  if x and y and ww and wh then
    return { x = x, y = y, w = ww, h = wh }
  end
  return nil
end

function Store.save_window_geometry(x, y, w, h)
  local doc = Store.config_doc()
  local nx = math_floor(x)
  local ny = math_floor(y)
  local nw = math_floor(w)
  local nh = math_floor(h)
  local old = type(doc.window) == "table" and doc.window or nil
  local same_config = old
    and tonumber(old.x) == nx
    and tonumber(old.y) == ny
    and tonumber(old.w) == nw
    and tonumber(old.h) == nh
  if same_config then
    Store.cleanup_config_extstate_if_persisted(doc)
    return nil
  end

  doc.window = {
    x = nx,
    y = ny,
    w = nw,
    h = nh,
  }
  return Store.save_config()
end

function Store.clear_window_geometry()
  local doc = Store.config_doc()
  doc.window = {}
  return Store.save_config()
end

function Store.sync_config_notices_to_extstate(doc)
  Store.cleanup_config_extstate_if_persisted(doc or Store.config_doc())
end

function Store.cleanup_config_extstate_if_persisted(doc)
  if RA._file_exists and RA._file_exists(RA.CONFIG_PATH) then
    Store.cleanup_config_extstate(doc or Store.config_doc())
  end
end

function Store.save_config()
  local doc = Store.config_doc()
  doc.schema_version = 1
  doc.preferences = Store.current_preferences()
  doc.selection = Store.current_selection()
  local err = Store.write_json_atomic(RA.CONFIG_PATH, doc, true)
  if err then Store._notify_write_failure("Config.json", err) end
  if not err then Store.cleanup_config_extstate(doc) end
  return err
end

function Store.write_text_atomic(path, text, skip_unchanged)
  if not path or path == "" then return "Missing text path." end
  text = tostring(text or "")
  if skip_unchanged then
    local existing, read_err, read_detail = Store._read_text_file(path)
    if read_err == "read_failed" then
      return "Refusing to overwrite " .. tostring(path)
        .. ": existing file could not be read (" .. tostring(read_detail) .. ")"
    end
    if existing == text then return nil, true end
  end

  local write_err = Store.atomic_write_file(path, text,
    { suffix = Store._atomic_write_suffix() })
  if write_err then return write_err end
  return nil, false
end

function Store.custom_instructions_text()
  if not RA.CUSTOM_INSTRUCTIONS_PATH then return "" end
  local raw = Store._read_text_file(RA.CUSTOM_INSTRUCTIONS_PATH)
  if type(raw) ~= "string" then return "" end
  local limit = CFG.CUSTOM_INSTRUCTIONS_READ_LIMIT or 100000
  if #raw > limit then
    return str_sub(raw, 1, limit)
  end
  return raw
end

function Store.custom_instructions_write(text)
  if type(reaper.RecursiveCreateDirectory) == "function" then
    pcall(reaper.RecursiveCreateDirectory, RA.DATA_DIR, 0)
  end
  local err, unchanged = Store.write_text_atomic(
    RA.CUSTOM_INSTRUCTIONS_PATH, tostring(text or ""), true)
  if S then
    S._custom_instr_prompt_key = nil
    S._custom_instr_prompt_block = nil
  end
  if err then Store._notify_write_failure("Custom_Instructions.md", err) end
  return err, unchanged
end

function Store.save_custom_instructions_enabled(enabled)
  local doc = Store.config_doc()
  doc.schema_version = 1
  doc.preferences = type(doc.preferences) == "table" and doc.preferences or {}
  local old_enabled = doc.preferences.custom_instructions_enabled
  doc.preferences.custom_instructions_enabled = enabled and true or false
  local err = Store.write_json_atomic(RA.CONFIG_PATH, doc, true)
  if err then
    doc.preferences.custom_instructions_enabled = old_enabled
  end
  if S then
    S._custom_instr_prompt_key = nil
    S._custom_instr_prompt_block = nil
  end
  if err then Store._notify_write_failure("Config.json", err) end
  return err
end

function Store.custom_instructions_prompt_block()
  if not (prefs and prefs.custom_instructions_enabled) then return nil end
  local raw = Store.custom_instructions_text()
  local trimmed = type(raw) == "string" and raw:match("^%s*(.-)%s*$") or ""
  if trimmed == "" then return nil end

  local limit = CFG.CUSTOM_INSTRUCTIONS_CHAR_LIMIT or 12000
  if #trimmed > limit then
    trimmed = str_sub(trimmed, 1, limit)
      .. "\n\n[Truncated by ReaAssist: Custom Instructions exceeded "
      .. tostring(limit) .. " characters.]"
  end

  return tbl_concat({
    "USER CUSTOM INSTRUCTIONS (local, user-authored preferences):",
    "Follow these user preferences whenever they apply; they override default "
      .. "stylistic and structural choices.",
    "They do NOT override ReaAssist system, safety, correctness, or tool-use "
      .. "rules. Ignore any part that conflicts with those higher-priority "
      .. "rules.",
    trimmed,
  }, "\n\n")
end

function Store.seed_state_from_extstate(doc)
  doc = type(doc) == "table" and doc or {}

  doc.update = type(doc.update) == "table" and doc.update or {}
  local last_check = tonumber(reaper.GetExtState(CFG.EXT_NS, "update_last_check"))
  if last_check and doc.update.last_check == nil then
    doc.update.last_check = math_floor(last_check)
  end
  local snooze = tonumber(reaper.GetExtState(CFG.EXT_NS, "update_snooze"))
  if snooze and doc.update.snooze == nil then
    doc.update.snooze = math_floor(snooze)
  end

  doc.theme = type(doc.theme) == "table" and doc.theme or {}
  local os_cache = reaper.GetExtState(CFG.EXT_NS, "os_theme_cache")
  local os_cache_ts = tonumber(reaper.GetExtState(CFG.EXT_NS, "os_theme_cache_ts"))
  if (os_cache == "dark" or os_cache == "light")
     and os_cache_ts
     and (doc.theme.os_cache == nil or doc.theme.os_cache_ts == nil) then
    doc.theme.os_cache = os_cache
    doc.theme.os_cache_ts = math_floor(os_cache_ts)
  end

  doc.gemini = type(doc.gemini) == "table" and doc.gemini or {}
  local paid_tier = reaper.GetExtState(CFG.EXT_NS, "gemini_paid_tier")
  if type(doc.gemini.paid_tier) ~= "boolean"
     and (paid_tier == "true" or paid_tier == "false") then
    doc.gemini.paid_tier = paid_tier == "true"
  end
  doc.gemini_cache = type(doc.gemini_cache) == "table" and doc.gemini_cache or {}
  local cache_name = reaper.GetExtState(CFG.EXT_NS, "gemini_cache_name")
  if cache_name ~= "" and (doc.gemini_cache.name == nil or doc.gemini_cache.name == "") then
    doc.gemini_cache.name = cache_name
    local cache_model = reaper.GetExtState(CFG.EXT_NS, "gemini_cache_model")
    local cache_signature = reaper.GetExtState(CFG.EXT_NS, "gemini_cache_signature")
    local cache_expires = tonumber(
      reaper.GetExtState(CFG.EXT_NS, "gemini_cache_expires"))
    if cache_model ~= "" then doc.gemini_cache.model = cache_model end
    if cache_signature ~= "" then doc.gemini_cache.signature = cache_signature end
    if cache_expires then doc.gemini_cache.expires = math_floor(cache_expires) end
  end

  doc.openai = type(doc.openai) == "table" and doc.openai or {}
  local prompt_cache_key = reaper.GetExtState(CFG.EXT_NS, "openai_prompt_cache_key")
  if prompt_cache_key ~= "" and doc.openai.prompt_cache_key == nil then
    doc.openai.prompt_cache_key = prompt_cache_key
  end

  doc.output_ceiling = type(doc.output_ceiling) == "table"
    and doc.output_ceiling or {}
  local next_base = tonumber(reaper.GetExtState(CFG.EXT_NS, "ceiling_next_base"))
  if next_base and doc.output_ceiling.next_base == nil then
    doc.output_ceiling.next_base = math_floor(next_base)
  end
  if type(doc.output_ceiling.slots) ~= "table" then
    local raw_slots = reaper.GetExtState(CFG.EXT_NS, "ceiling_slots")
    if raw_slots ~= "" then
      local ok, slots = pcall(JSON.decode, raw_slots)
      if ok and type(slots) == "table" then
        doc.output_ceiling.slots = slots
      end
    end
  end

  doc.diagnostics = type(doc.diagnostics) == "table" and doc.diagnostics or {}
  local ping = tonumber(reaper.GetExtState(CFG.EXT_NS, "diag_auto_last_ping_at"))
  if ping and doc.diagnostics.auto_last_ping_at == nil then
    doc.diagnostics.auto_last_ping_at = math_floor(ping)
  end
  local sent = tonumber(reaper.GetExtState(CFG.EXT_NS, "diag_auto_last_sent_at"))
  if sent and doc.diagnostics.auto_last_sent_at == nil then
    doc.diagnostics.auto_last_sent_at = math_floor(sent)
  end

  return doc
end

function Store.legacy_state_extstate_exists()
  local keys = {
    "update_last_check",
    "update_snooze",
    "os_theme_cache",
    "os_theme_cache_ts",
    "gemini_paid_tier",
    "gemini_cache_name",
    "gemini_cache_model",
    "gemini_cache_signature",
    "gemini_cache_expires",
    "openai_prompt_cache_key",
    "ceiling_next_base",
    "ceiling_slots",
    "diag_auto_last_ping_at",
    "diag_auto_last_sent_at",
  }
  for _, key in ipairs(keys) do
    if reaper.GetExtState(CFG.EXT_NS, key) ~= "" then return true end
  end
  return false
end

function Store.migrate_state_if_needed()
  if not Store.legacy_state_extstate_exists() then return nil end
  Store.state_doc()
  return Store.save_state()
end

function Store.state_doc()
  if Store._state_doc then return Store._state_doc end
  local doc, err = Store.read_json(RA.STATE_PATH, nil, 1)
  if doc then
    Store._state_doc = Store.seed_state_from_extstate(doc)
    return Store._state_doc
  end
  if Store._should_quarantine_json_read_error(err) then
    Store._quarantine_json(RA.STATE_PATH, err)
  end
  Store._state_doc = Store.seed_state_from_extstate({ schema_version = 1 })
  return Store._state_doc
end

function Store.save_state()
  local doc = Store.state_doc()
  doc.schema_version = 1
  local err = Store.write_json_atomic(RA.STATE_PATH, doc)
  if err then Store._notify_write_failure("State.json", err) end
  if not err then Store.cleanup_state_extstate() end
  return err
end

function Store.set_update_last_check(ts)
  local doc = Store.state_doc()
  doc.update = type(doc.update) == "table" and doc.update or {}
  doc.update.last_check = math_floor(tonumber(ts) or os.time())
  return Store.save_state()
end

function Store.update_snooze()
  local doc = Store.state_doc()
  local update_state = doc and doc.update
  local value = type(update_state) == "table"
    and tonumber(update_state.snooze) or nil
  if value then return value end
  value = tonumber(reaper.GetExtState(CFG.EXT_NS, "update_snooze") or "")
  if value then
    doc.update = type(doc.update) == "table" and doc.update or {}
    doc.update.snooze = math_floor(value)
    Store.save_state()
  end
  return value
end

function Store.set_update_snooze(ts)
  local doc = Store.state_doc()
  doc.update = type(doc.update) == "table" and doc.update or {}
  ts = tonumber(ts)
  if ts then
    doc.update.snooze = math_floor(ts)
  else
    doc.update.snooze = nil
  end
  return Store.save_state()
end

function Store.os_theme_cache()
  local doc = Store.state_doc()
  local theme_state = doc and doc.theme
  local cached = type(theme_state) == "table" and theme_state.os_cache or nil
  local cached_ts = type(theme_state) == "table"
    and tonumber(theme_state.os_cache_ts) or nil
  if (cached == "dark" or cached == "light") and cached_ts then
    return cached, cached_ts
  end
  cached = reaper.GetExtState(CFG.EXT_NS, "os_theme_cache")
  cached_ts = tonumber(reaper.GetExtState(CFG.EXT_NS, "os_theme_cache_ts") or "")
  if (cached == "dark" or cached == "light") and cached_ts then
    doc.theme = type(doc.theme) == "table" and doc.theme or {}
    doc.theme.os_cache = cached
    doc.theme.os_cache_ts = math_floor(cached_ts)
    Store.save_state()
    return cached, cached_ts
  end
  return nil, nil
end

function Store.set_os_theme_cache(theme, ts)
  if theme ~= "dark" and theme ~= "light" then return nil end
  local doc = Store.state_doc()
  doc.theme = type(doc.theme) == "table" and doc.theme or {}
  doc.theme.os_cache = theme
  doc.theme.os_cache_ts = math_floor(tonumber(ts) or os.time())
  return Store.save_state()
end

function Store.gemini_paid_tier()
  local doc = Store.state_doc()
  local gemini = doc and doc.gemini
  if type(gemini) == "table" and type(gemini.paid_tier) == "boolean" then
    return gemini.paid_tier
  end
  local tier_str = reaper.GetExtState(CFG.EXT_NS, "gemini_paid_tier")
  if tier_str == "true" or tier_str == "false" then
    doc.gemini = type(doc.gemini) == "table" and doc.gemini or {}
    doc.gemini.paid_tier = tier_str == "true"
    Store.save_state()
    return doc.gemini.paid_tier
  end
  return nil
end

function Store.set_gemini_paid_tier(value)
  local doc = Store.state_doc()
  doc.gemini = type(doc.gemini) == "table" and doc.gemini or {}
  if value == true or value == false then
    doc.gemini.paid_tier = value
  else
    doc.gemini.paid_tier = nil
  end
  if S then S.gemini_paid_tier = doc.gemini.paid_tier end
  return Store.save_state()
end

function Store.gemini_cache_state()
  local doc = Store.state_doc()
  local cache = doc and doc.gemini_cache
  if type(cache) == "table" and type(cache.name) == "string"
     and cache.name ~= "" then
    return cache.name,
      type(cache.model) == "string" and cache.model or "",
      type(cache.signature) == "string" and cache.signature or "",
      tonumber(cache.expires) or 0
  end
  return nil
end

function Store.set_gemini_cache_state(name, model, signature, expires)
  if not name or name == "" then return Store.clear_gemini_cache_state() end
  local doc = Store.state_doc()
  doc.gemini_cache = type(doc.gemini_cache) == "table"
    and doc.gemini_cache or {}
  doc.gemini_cache.name = name
  doc.gemini_cache.model = model or ""
  doc.gemini_cache.signature = signature or ""
  doc.gemini_cache.expires = math_floor(tonumber(expires) or 0)
  return Store.save_state()
end

function Store.clear_gemini_cache_state()
  local doc = Store.state_doc()
  doc.gemini_cache = {}
  return Store.save_state()
end

function Store.openai_prompt_cache_key()
  local doc = Store.state_doc()
  doc.openai = type(doc.openai) == "table" and doc.openai or {}
  local key = type(doc.openai.prompt_cache_key) == "string"
    and doc.openai.prompt_cache_key or ""
  if key ~= "" then return key end
  key = reaper.GetExtState(CFG.EXT_NS, "openai_prompt_cache_key")
  if key == "" then
    key = string.format("ra_%s_%06d",
      tostring(time_precise()):gsub("[^%w]", ""),
      math.random(100000, 999999))
  end
  key = key:gsub("[^%w%-_]", "_")
  if #key > 96 then key = key:sub(1, 96) end
  if key == "" then key = "ra_prompt_cache" end
  doc.openai.prompt_cache_key = key
  local err = Store.save_state()
  if err then
    reaper.SetExtState(CFG.EXT_NS, "openai_prompt_cache_key", key, true)
  end
  return key
end

function Store.ceiling_output_doc()
  local doc = Store.state_doc()
  doc.output_ceiling = type(doc.output_ceiling) == "table"
    and doc.output_ceiling or {}
  return doc.output_ceiling
end

function Store.reserve_ceiling_base(start_base, stride, limit)
  local out = Store.ceiling_output_doc()
  local cur = tonumber(out.next_base)
    or tonumber(reaper.GetExtState(CFG.EXT_NS, "ceiling_next_base"))
    or start_base
  if cur < start_base then cur = start_base end
  if cur >= limit then return nil, "State slot allocator exhausted" end
  out.next_base = math_floor(cur + stride)
  local err = Store.save_state()
  if err then
    reaper.SetExtState(CFG.EXT_NS, "ceiling_next_base",
      tostring(out.next_base), true)
  end
  return math_floor(cur)
end

function Store.ceiling_slots()
  local out = Store.ceiling_output_doc()
  if type(out.slots) == "table" then return out.slots end
  local raw = reaper.GetExtState(CFG.EXT_NS, "ceiling_slots")
  if raw ~= "" then
    local ok, decoded = pcall(JSON.decode, raw)
    if ok and type(decoded) == "table" then
      out.slots = decoded
      Store.save_state()
      return out.slots
    end
  end
  out.slots = {}
  return out.slots
end

function Store.save_ceiling_slots(list)
  local out = Store.ceiling_output_doc()
  out.slots = type(list) == "table" and list or {}
  local err = Store.save_state()
  if err then
    local enc = JSON.encode(out.slots)
    if enc then reaper.SetExtState(CFG.EXT_NS, "ceiling_slots", enc, true) end
  end
  return err
end

function Store.set_diag_auto_last_ping_at(ts)
  local doc = Store.state_doc()
  doc.diagnostics = type(doc.diagnostics) == "table" and doc.diagnostics or {}
  doc.diagnostics.auto_last_ping_at = math_floor(tonumber(ts) or os.time())
  return Store.save_state()
end

function Store.set_diag_auto_last_sent_at(ts)
  local doc = Store.state_doc()
  doc.diagnostics = type(doc.diagnostics) == "table" and doc.diagnostics or {}
  doc.diagnostics.auto_last_sent_at = math_floor(tonumber(ts) or os.time())
  return Store.save_state()
end

function Store.providers_document(records)
  local out = {}
  for _, record in ipairs(records or {}) do
    out[#out+1] = Store._provider_record_to_json(record)
  end
  return {
    schema_version = 1,
    records        = Store.json_array(out),
  }
end

function Store.save_providers(records)
  records = records
    or (Custom and Custom.load_all_extstate and Custom.load_all_extstate())
    or {}
  local err = Store.write_json_atomic(RA.PROVIDERS_PATH,
    Store.providers_document(records))
  if err then Store._notify_write_failure("Providers.json", err) end
  if not err then Store.cleanup_providers_extstate(records) end
  return err
end

function Store.mirror_providers_if_missing()
  if not RA.PROVIDERS_PATH or RA.PROVIDERS_PATH == "" then return nil end
  if RA._file_exists and RA._file_exists(RA.PROVIDERS_PATH) then return nil end
  local records = (Custom and Custom.load_all_extstate
                    and Custom.load_all_extstate()) or {}
  if #records == 0 then return nil end
  return Store.save_providers(records)
end

-- =============================================================================
-- JSON helpers
-- =============================================================================
-- Sanitises a Lua byte string into valid UTF-8 by replacing any invalid byte
-- sequences with '?'. REAPER allows raw 8-bit bytes in track names, item
-- notes, and marker labels (often a result of dragged-in corrupt audio files
-- or weird VST presets), and the AI provider APIs reject any payload that
-- isn't strict UTF-8 with a 400 Bad Request.
--
-- Validates the four legal multi-byte forms (per RFC 3629):
--   1-byte: 0xxxxxxx
--   2-byte: 110xxxxx 10xxxxxx              (U+0080..U+07FF)
--   3-byte: 1110xxxx 10xxxxxx 10xxxxxx     (U+0800..U+FFFF, excluding surrogates)
--   4-byte: 11110xxx 10xxxxxx 10xxxxxx 10xxxxxx (U+10000..U+10FFFF)
-- Single-pass byte scan, no allocations on the happy path (string is returned
-- unchanged when it is already valid UTF-8).
local function sanitize_utf8(s)
  local len = #s
  local i = 1
  local out = nil  -- lazily allocated only if we hit invalid bytes
  while i <= len do
    local b1 = str_byte(s, i)
    local size, ok = 1, true
    if b1 < 0x80 then
      -- ASCII
      size = 1
    elseif b1 < 0xC2 then
      -- Continuation byte or overlong 2-byte form: invalid as a leading byte
      ok = false
    elseif b1 < 0xE0 then
      -- 2-byte sequence
      size = 2
      if i + 1 > len then ok = false
      else
        local b2 = str_byte(s, i + 1)
        if b2 < 0x80 or b2 > 0xBF then ok = false end
      end
    elseif b1 < 0xF0 then
      -- 3-byte sequence
      size = 3
      if i + 2 > len then ok = false
      else
        local b2 = str_byte(s, i + 1)
        local b3 = str_byte(s, i + 2)
        if b2 < 0x80 or b2 > 0xBF or b3 < 0x80 or b3 > 0xBF then
          ok = false
        elseif b1 == 0xE0 and b2 < 0xA0 then
          ok = false  -- overlong
        elseif b1 == 0xED and b2 > 0x9F then
          ok = false  -- UTF-16 surrogate half
        end
      end
    elseif b1 < 0xF5 then
      -- 4-byte sequence
      size = 4
      if i + 3 > len then ok = false
      else
        local b2 = str_byte(s, i + 1)
        local b3 = str_byte(s, i + 2)
        local b4 = str_byte(s, i + 3)
        if b2 < 0x80 or b2 > 0xBF
           or b3 < 0x80 or b3 > 0xBF
           or b4 < 0x80 or b4 > 0xBF then
          ok = false
        elseif b1 == 0xF0 and b2 < 0x90 then
          ok = false  -- overlong
        elseif b1 == 0xF4 and b2 > 0x8F then
          ok = false  -- > U+10FFFF
        end
      end
    else
      ok = false  -- 0xF5..0xFF: never valid
    end

    if ok then
      if out then out[#out+1] = str_sub(s, i, i + size - 1) end
      i = i + size
    else
      if not out then
        out = {}
        if i > 1 then out[1] = str_sub(s, 1, i - 1) end
      end
      out[#out+1] = "?"
      i = i + 1
    end
  end
  if out then return tbl_concat(out) end
  return s
end
JSON.sanitize_utf8 = sanitize_utf8

JSON._ESCAPE_MAP = JSON._ESCAPE_MAP or {
  ['\\'] = '\\\\',
  ['"'] = '\\"',
  ['\n'] = '\\n',
  ['\r'] = '\\r',
  ['\t'] = '\\t',
}

-- Escapes a Lua string for safe embedding inside a JSON string value.
-- Also escapes control characters below 0x20 (backspace, form feed,
-- null bytes, etc.) that can appear in track names or user input and would
-- produce invalid JSON, causing silent API call failures. Invalid UTF-8 byte
-- sequences are replaced with '?' so the API never sees malformed payloads.
function JSON.escape(s)
  return sanitize_utf8(s):gsub('[\\"\n\r\t\x00-\x08\x0b\x0c\x0e-\x1f]',
    function(c)
      return JSON._ESCAPE_MAP[c] or str_format('\\u%04x', str_byte(c))
    end)
end

-- =============================================================================
-- Minimal recursive-descent JSON decoder
-- =============================================================================
-- Proper parser that handles the full JSON spec: objects, arrays, strings
-- (with all escape sequences including \uXXXX), numbers, booleans, and null.
--
-- The decoder returns a native Lua table/value on success, or nil + error
-- string on malformed input. It never throws.
--
-- JSON null is represented by the sentinel table JSON.NULL rather than Lua nil.
-- This prevents silent key loss when a JSON object contains {"key": null},
-- since obj[key] = nil is a no-op in Lua. Callers should compare values
-- against JSON.NULL when null-awareness matters.
--
-- Performance: single-pass, no string copying for non-string values, avoids
-- gsub inside the hot path. Fast enough for the response sizes we handle
-- (typically 1-20 KB).
do
  -- Forward declarations for mutual recursion.
  local decode_value, decode_string, decode_number, decode_object, decode_array

  -- Skip whitespace and return the next non-whitespace position.
  local function skip_ws(s, pos)
    return str_match(s, "^%s*()", pos)
  end

  -- Decode a JSON string starting at the opening quote.
  -- Returns (lua_string, next_position) or (nil, error_string).
  decode_string = function(s, pos)
    -- pos points to the opening '"'
    pos = pos + 1  -- skip opening quote
    local start = pos
    local len = #s
    local buf
    while pos <= len do
      local hit = str_find(s, '[\\"]', pos)
      if not hit then return nil, "unterminated string" end
      local ch = str_sub(s, hit, hit)
      if ch == '"' then
        if not buf then return str_sub(s, start, hit - 1), hit + 1 end
        if hit > pos then buf[#buf+1] = str_sub(s, pos, hit - 1) end
        return tbl_concat(buf), hit + 1
      else
        if not buf then
          buf = {}
          if hit > start then buf[1] = str_sub(s, start, hit - 1) end
        elseif hit > pos then
          buf[#buf+1] = str_sub(s, pos, hit - 1)
        end
        pos = hit + 1
        if pos > len then return nil, "unterminated string escape" end
        local esc = str_sub(s, pos, pos)
        if     esc == 'n'  then buf[#buf+1] = '\n'
        elseif esc == 't'  then buf[#buf+1] = '\t'
        elseif esc == 'r'  then buf[#buf+1] = '\r'
        elseif esc == '"'  then buf[#buf+1] = '"'
        elseif esc == '\\' then buf[#buf+1] = '\\'
        elseif esc == '/'  then buf[#buf+1] = '/'
        elseif esc == 'b'  then buf[#buf+1] = '\b'
        elseif esc == 'f'  then buf[#buf+1] = '\f'
        elseif esc == 'u'  then
          -- \uXXXX unicode escape. Decode to UTF-8 bytes.
          -- Handles surrogate pairs (\uD800-\uDFFF) for emoji/CJK.
          local hex = str_sub(s, pos + 1, pos + 4)
          local cp  = tonumber(hex, 16)
          if not cp then
            buf[#buf+1] = '\\u' .. hex
          else
            -- Surrogate pair: high surrogate followed by \uXXXX low surrogate.
            if cp >= 0xD800 and cp <= 0xDBFF then
              local lo_hex = str_sub(s, pos + 5, pos + 10)
              if str_sub(lo_hex, 1, 2) == "\\u" then
                local lo_cp = tonumber(str_sub(lo_hex, 3, 6), 16)
                if lo_cp and lo_cp >= 0xDC00 and lo_cp <= 0xDFFF then
                  cp = 0x10000 + (cp - 0xD800) * 0x400 + (lo_cp - 0xDC00)
                  pos = pos + 6  -- skip the low surrogate
                end
              end
            end
            -- Encode codepoint as UTF-8.
            if cp < 0x80 then
              buf[#buf+1] = str_char(cp)
            elseif cp < 0x800 then
              buf[#buf+1] = str_char(0xC0 + math_floor(cp / 64),
                                     0x80 + cp % 64)
            elseif cp < 0x10000 then
              buf[#buf+1] = str_char(0xE0 + math_floor(cp / 4096),
                                     0x80 + math_floor(cp / 64) % 64,
                                     0x80 + cp % 64)
            else
              buf[#buf+1] = str_char(0xF0 + math_floor(cp / 262144),
                                     0x80 + math_floor(cp / 4096) % 64,
                                     0x80 + math_floor(cp / 64) % 64,
                                     0x80 + cp % 64)
            end
          end
          pos = pos + 4
        else
          -- Unknown escape: preserve as-is for debugging.
          buf[#buf+1] = '\\' .. esc
        end
      end
      pos = pos + 1
    end
    return nil, "unterminated string"
  end

  -- Decode a JSON number. Returns (number, next_position).
  decode_number = function(s, pos)
    local num_str = str_match(s, "^-?%d+%.?%d*[eE]?[+-]?%d*()", pos)
    if not num_str then return nil, "invalid number" end
    local val = tonumber(str_sub(s, pos, num_str - 1))
    if not val then return nil, "invalid number" end
    return val, num_str
  end

  -- Decode a JSON object. Returns (table, next_position).
  decode_object = function(s, pos)
    pos = pos + 1  -- skip '{'
    local obj = {}
    pos = skip_ws(s, pos)
    if str_sub(s, pos, pos) == '}' then return obj, pos + 1 end
    while true do
      pos = skip_ws(s, pos)
      if str_sub(s, pos, pos) ~= '"' then return nil, "expected string key" end
      local key, next_pos = decode_string(s, pos)
      if not key then return nil, next_pos end
      pos = skip_ws(s, next_pos)
      if str_sub(s, pos, pos) ~= ':' then return nil, "expected ':'" end
      pos = skip_ws(s, pos + 1)
      local val
      val, pos = decode_value(s, pos)
      if val == nil and type(pos) == "string" then return nil, pos end
      obj[key] = val
      pos = skip_ws(s, pos)
      local sep = str_sub(s, pos, pos)
      if sep == '}' then return obj, pos + 1 end
      if sep ~= ',' then return nil, "expected ',' or '}'" end
      pos = pos + 1
    end
  end

  -- Decode a JSON array. Returns (table, next_position).
  decode_array = function(s, pos)
    pos = pos + 1  -- skip '['
    local arr = {}
    pos = skip_ws(s, pos)
    if str_sub(s, pos, pos) == ']' then return arr, pos + 1 end
    while true do
      pos = skip_ws(s, pos)
      local val
      val, pos = decode_value(s, pos)
      if val == nil and type(pos) == "string" then return nil, pos end
      arr[#arr+1] = val
      pos = skip_ws(s, pos)
      local sep = str_sub(s, pos, pos)
      if sep == ']' then return arr, pos + 1 end
      if sep ~= ',' then return nil, "expected ',' or ']'" end
      pos = pos + 1
    end
  end

  -- Decode any JSON value. Top-level dispatch.
  decode_value = function(s, pos)
    pos = skip_ws(s, pos)
    local ch = str_sub(s, pos, pos)
    if ch == '"' then return decode_string(s, pos)
    elseif ch == '{' then return decode_object(s, pos)
    elseif ch == '[' then return decode_array(s, pos)
    elseif ch == 't' then
      if str_sub(s, pos, pos + 3) == "true" then return true, pos + 4 end
      return nil, "invalid value"
    elseif ch == 'f' then
      if str_sub(s, pos, pos + 4) == "false" then return false, pos + 5 end
      return nil, "invalid value"
    elseif ch == 'n' then
      if str_sub(s, pos, pos + 3) == "null" then return JSON.NULL, pos + 4 end
      return nil, "invalid value"
    elseif ch == '-' or (ch >= '0' and ch <= '9') then
      return decode_number(s, pos)
    else
      return nil, "unexpected character: " .. ch
    end
  end

  -- Public API: decode a JSON string into a Lua value.
  -- Returns (value, nil) on success, or (nil, error_string) on failure.
  -- Wrapped in pcall as a final safety net against any unforeseen edge case.
  JSON.decode = function(s)
    if type(s) ~= "string" or #s == 0 then
      return nil, "empty or non-string input"
    end
    local ok, result, next_pos = pcall(decode_value, s, 1)
    if not ok then return nil, tostring(result) end
    if result == nil and type(next_pos) == "string" then
      return nil, next_pos
    end
    return result, nil
  end
end

-- =============================================================================
-- Minimal recursive JSON encoder
-- =============================================================================
-- Encodes Lua values into compact or pretty-printed JSON strings.
-- Handles strings, numbers, booleans, nil, JSON.NULL, and tables
-- (auto-detects array vs object by checking sequential integer keys).
do
  local function is_array(t)
    local n = #t
    if n == 0 then
      -- Empty table: always encode as {} (object), never [].
      -- In this codebase empty tables are dictionaries, not empty arrays.
      return false
    end
    local count = 0
    for _ in pairs(t) do count = count + 1 end
    return count == n
  end

  local encode_value  -- forward declaration

  local function encode_string(s)
    return '"' .. JSON.escape(s) .. '"'
  end

  local function encode_number(n)
    if n ~= n then return '"NaN"' end             -- NaN safety
    if n == math.huge then return '"Infinity"' end
    if n == -math.huge then return '"-Infinity"' end
    if math.floor(n) == n and math.abs(n) < 2^53 then
      return str_format("%d", n)
    end
    return str_format("%.14g", n)
  end

  local function encode_array(t, indent, depth)
    if #t == 0 then return "[]" end
    local parts = {}
    for i = 1, #t do
      parts[i] = encode_value(t[i], indent, depth)
    end
    if indent then
      local pad = string.rep(indent, depth)
      local inner_pad = string.rep(indent, depth + 1)
      return "[\n" .. inner_pad .. tbl_concat(parts, ",\n" .. inner_pad) .. "\n" .. pad .. "]"
    end
    return "[" .. tbl_concat(parts, ",") .. "]"
  end

  local function encode_object(t, indent, depth)
    local parts = {}
    -- Collect and sort keys for deterministic output.
    local keys = {}
    for k in pairs(t) do keys[#keys+1] = k end
    table.sort(keys, function(a, b)
      local ta, tb = type(a), type(b)
      if ta ~= tb then return ta < tb end
      return a < b
    end)
    for _, k in ipairs(keys) do
      local ks = type(k) == "string" and encode_string(k) or ('"' .. tostring(k) .. '"')
      local vs = encode_value(t[k], indent, depth)
      if indent then
        parts[#parts+1] = ks .. ": " .. vs
      else
        parts[#parts+1] = ks .. ":" .. vs
      end
    end
    if #parts == 0 then return "{}" end
    if indent then
      local pad = string.rep(indent, depth)
      local inner_pad = string.rep(indent, depth + 1)
      return "{\n" .. inner_pad .. tbl_concat(parts, ",\n" .. inner_pad) .. "\n" .. pad .. "}"
    end
    return "{" .. tbl_concat(parts, ",") .. "}"
  end

  encode_value = function(v, indent, depth)
    depth = depth or 0
    if v == nil or v == JSON.NULL then return "null" end
    if v == JSON.EMPTY_ARRAY then return "[]" end
    local tv = type(v)
    if tv == "string"  then return encode_string(v) end
    if tv == "number"  then return encode_number(v) end
    if tv == "boolean" then return v and "true" or "false" end
    if tv == "table"   then
      if is_array(v) then
        return encode_array(v, indent, depth + 1)
      else
        return encode_object(v, indent, depth + 1)
      end
    end
    return '"' .. tostring(v) .. '"'
  end

  -- Public API: encode a Lua value into a JSON string.
  -- Pass indent string (e.g. "  ") for pretty-printing, or nil for compact.
  JSON.encode = function(value, indent)
    local ok, result = pcall(encode_value, value, indent, 0)
    if not ok then return nil, tostring(result) end
    return result, nil
  end
end

-- Expose JSON to sidecars that parse request/response bodies or diagnostics.
-- JSON is local to this chunk, so dofile/loadfile sidecars cannot see it unless
-- it is attached to RA after the encoder/decoder table is fully populated.
RA.JSON = JSON

--
-- The user can register any number of custom providers. Each record is a
-- self-contained endpoint with its own label, URL, timeout, API key, and
-- model list. Each model row is id + per-million-token input/output prices
-- + context window. Prices are displayed in the Show Details bubble;
-- ReaAssist is NOT optimized for these endpoints and the cost number is an
-- estimate only.
--
-- Storage (Data/Providers.json primary with one-time ExtState fallback).
-- Legacy keys are read during upgrade, then removed after Providers.json is
-- written successfully. The legacy shape was one index key plus per-record
-- keys, keyed by a stable record id of the form "custom_<8 hex chars>":
--
--   custom_provider_ids                 -- comma-separated ordered id list
--   custom_<id>_label                   -- friendly name shown in combo
--   custom_<id>_endpoint                -- full URL
--   custom_<id>_timeout_secs            -- request timeout in seconds (curl --max-time)
--   custom_<id>_connect_timeout         -- TCP/TLS handshake timeout in seconds
--                                          (curl --connect-timeout)
--   custom_<id>_allow_insecure          -- "1" to pass curl --insecure (skip TLS
--                                          verification; for self-signed local servers)
--   custom_<id>_model_prefix            -- optional string prepended to each model
--                                          id sent in the request body (e.g. "openrouter/")
--   custom_<id>_extra_headers           -- newline-delimited HTTP headers, each
--                                          "Name: value". Values are validated on
--                                          save to reject triple-quotes / newlines
--                                          that would break Windows curl argv.
--   custom_<id>_extra_body              -- optional provider-wide JSON object
--                                          merged into every chat-completions
--                                          body. Validated as a JSON object at
--                                          save time and stored in canonical
--                                          (JSON.encode) form. Per-model
--                                          extra_body (stored inside the models
--                                          blob) overrides these keys on a
--                                          per-request basis.
--   custom_<id>_models                  -- newline-delimited rows, pipe-delimited
--                                          fields with optional tab-prefixed
--                                          extra_body suffix. Row format:
--                                            id|price_in|price_out|context|price_cache_r|notes[\t<extra_body_json>]
--   api_key_<id>                        -- optional Bearer token, encoded via Key.encode
--
-- The record id doubles as the provider id in the PROVIDERS table, so every
-- existing lookup that goes through PROVIDERS.get(id) / PROVIDERS._by_id[id]
-- continues to work. Providers.json stores the same records as objects, with
-- extra_body fields as JSON objects; runtime converts them back to canonical
-- JSON strings for the existing request-building path.
Custom = {}

function Custom.t(key, values, fallback)
  return RA.t(key, values, fallback)
end

CUSTOM_DEFAULT_CTX          = 65536  -- per-model fallback if everything is missing
CUSTOM_DEFAULT_TIMEOUT      = 600    -- 10 minutes
CUSTOM_MIN_TIMEOUT          = 10
CUSTOM_MAX_TIMEOUT          = 3600   -- 1 hour cap
CUSTOM_MIN_CTX              = 256
CUSTOM_DEFAULT_TEST_TIMEOUT = 30     -- Test Connection curl --max-time (hard-coded;
                                           -- 30s accommodates remote/cloud-compatible
                                           -- endpoints while staying responsive locally)
-- Connect-timeout bounds live on the Custom namespace (not as file-scope
-- locals) because ReaAssist's main chunk is at the 200-locals ceiling --
-- adding three more would overflow. Referenced anywhere we currently use
-- the CUSTOM_DEFAULT_* constants.
Custom.DEFAULT_CONNECT = 10
Custom.MIN_CONNECT     = 1
Custom.MAX_CONNECT     = 60
Custom.REASON_INVALID_ENDPOINT = "invalid endpoint"
-- Per-model free-text label shown in the main-screen model dropdown next to
-- the id (e.g. "kimi-k2.6 . fast" vs "kimi-k2.6 . thinking"). Capped so the
-- dropdown stays readable and rejected at save time if it contains delimiters
-- ("|" or "\t") that would break the models blob parser.
Custom.MAX_NOTES_LEN   = 20

function Custom.endpoint_is_safe(endpoint)
  return type(endpoint) == "string"
    and endpoint:match("^https?://") ~= nil
    and endpoint:find("[\"'`%c]") == nil
end

function Custom.normalize_chat_endpoint(endpoint)
  if type(endpoint) ~= "string" then return endpoint end
  local url = endpoint:match("^%s*(.-)%s*$") or ""
  if url == "" then return "" end
  local suffix = url:match("([?#].*)$") or ""
  local path = suffix ~= "" and url:sub(1, #url - #suffix) or url
  path = path:gsub("/+$", "")
  local host = path:match("^(https?://[^/]+)$")
  if host then return host .. "/v1/chat/completions" .. suffix end
  local v1 = path:match("^(.-)/v1$")
  if v1 then return v1 .. "/v1/chat/completions" .. suffix end
  local models = path:match("^(.-)/models$")
  if models then return models .. "/chat/completions" .. suffix end
  return path .. suffix
end

function Custom.endpoint_is_chat_completions(endpoint)
  if type(endpoint) ~= "string" then return false end
  local url = endpoint:match("^%s*(.-)%s*$") or ""
  if url == "" then return false end
  local suffix = url:match("([?#].*)$") or ""
  local path = suffix ~= "" and url:sub(1, #url - #suffix) or url
  path = path:gsub("/+$", "")
  return path:match("/chat/completions$") ~= nil
end

-- Return true if s is safe to drop into an HTTP-header slot on the curl
-- command line across both shells we target. Rejects newlines (which would
-- split the argument), null bytes, and the triple-quote boundary that our
-- Windows PowerShell launcher uses to terminate each -H argument. Everything
-- else (Unicode, spaces, dollar signs, backticks, single/double quotes) is
-- fine because the POSIX branch wraps each header in sq() (POSIX single-
-- quote escape) and the Windows branch wraps each header in triple double
-- quotes for cmd.exe; neither shell interpolates inside those contexts.
function Custom.header_is_safe(s)
  if type(s) ~= "string" then return false end
  if s:find("[%z\n\r]") then return false end
  if s:find('"""', 1, true) then return false end
  return true
end

-- Parse a multi-line "Name: value" buffer into an array of header strings.
-- Returns (array, err). err is non-nil if any non-blank line fails
-- validation -- we return on the FIRST bad line so the user gets one
-- specific error to fix rather than a pile. Blank lines are skipped.
function Custom.parse_headers_text(text)
  local out = {}
  local lineno = 0
  for line in (text .. "\n"):gmatch("([^\n]*)\n") do
    lineno = lineno + 1
    local trimmed = line:match("^%s*(.-)%s*$") or ""
    if trimmed ~= "" then
      if not Custom.header_is_safe(trimmed) then
        return nil, Custom.t("settings.custom.error.header_unsafe",
          { line = lineno },
          str_format(
            "Line %d contains a newline, null byte, or triple-quote that "
            .. "can't be sent safely. Remove those characters.", lineno))
      end
      local name, rest = trimmed:match("^([^:]+):%s*(.*)$")
      if not name or name:match("^%s*$") then
        return nil, Custom.t("settings.custom.error.header_format",
          { line = lineno },
          str_format(
            "Line %d is not in \"Name: value\" format. Each header must "
            .. "have a name, a colon, and a value.", lineno))
      end
      -- Reject Authorization collision: users should use the API Key
      -- field for bearer tokens, not here. Also blocks accidental
      -- duplicate Authorization headers overriding the auth file.
      if name:lower():match("^%s*authorization%s*$") then
        return nil, Custom.t("settings.custom.error.header_auth",
          { line = lineno },
          str_format(
            "Line %d: use the API Key field for Authorization; don't "
            .. "set it here.", lineno))
      end
      out[#out+1] = trimmed
    end
  end
  return out, nil
end

-- Validate a user-typed Extra Body JSON buffer. Trims whitespace. Empty input
-- is considered valid (returns "" with nil err). Non-empty input must parse
-- as a JSON OBJECT (not an array, not a scalar) via JSON.decode, and re-encode
-- cleanly; the re-encoded canonical form is what gets stored. Called from the
-- UI save handlers for both the provider-level field and the per-model popup.
--
-- JSON.decode is already populated by the time custom providers load or save.
function Custom.validate_extra_body(text)
  if not text then return "", nil end
  local trimmed = text:match("^%s*(.-)%s*$") or ""
  if trimmed == "" then return "", nil end
  local obj, err = JSON.decode(trimmed)
  if err or obj == nil then
    return nil, Custom.t("settings.custom.error.extra_body_json",
      { error = err or "unknown parse error" },
      "Not valid JSON: " .. (err or "unknown parse error"))
  end
  if type(obj) ~= "table" then
    return nil, Custom.t("settings.custom.error.extra_body_object", nil,
      "Must be a JSON object like {\"thinking\":{\"type\":\"disabled\"}}")
  end
  -- Reject arrays and the null sentinel: valid JSON but not an object.
  if obj == JSON.NULL then
    return nil, Custom.t("settings.custom.error.extra_body_null", nil,
      "Must be a JSON object, got null")
  end
  local n = 0
  local is_array = true
  for k in pairs(obj) do
    n = n + 1
    if type(k) ~= "number" then is_array = false end
  end
  if n > 0 and is_array then
    return nil, Custom.t("settings.custom.error.extra_body_array", nil,
      "Must be a JSON object, got an array")
  end
  -- Canonicalize by re-encoding so storage is normalized (no trailing whitespace,
  -- no comments, stable key order as emitted by JSON.encode). An empty object
  -- still canonicalizes to "{}", which is semantically a no-op at build time.
  local encoded, eerr = JSON.encode(obj)
  if not encoded then
    return nil, Custom.t("settings.custom.error.extra_body_canonicalize",
      { error = tostring(eerr) },
      "Failed to canonicalize: " .. tostring(eerr))
  end
  return encoded, nil
end

-- Validate a per-model short notes string. Trims whitespace, enforces the
-- length cap, and rejects the two delimiter characters (pipe, tab) that the
-- models blob format uses between fields. Newlines are also rejected because
-- the blob uses "\n" as the row separator. Returns (clean_string, nil) on
-- success or (nil, error_string) on failure.
function Custom.validate_notes(text)
  if not text then return "", nil end
  local trimmed = text:match("^%s*(.-)%s*$") or ""
  if trimmed == "" then return "", nil end
  if #trimmed > Custom.MAX_NOTES_LEN then
    return nil, Custom.t("settings.custom.error.notes_max",
      { count = Custom.MAX_NOTES_LEN },
      str_format("Notes must be %d characters or fewer.",
        Custom.MAX_NOTES_LEN))
  end
  if trimmed:find("[|\t\n\r]") then
    return nil, Custom.t("settings.custom.error.notes_chars", nil,
      "Notes cannot contain pipe (|), tab, or newline characters.")
  end
  return trimmed, nil
end

-- Seed math.random once per script load from REAPER's high-resolution clock so
-- consecutive Custom.gen_id calls across rapid reloads do not reuse the same
-- short random sequence.
math.randomseed(math.floor((reaper.time_precise() or 0) * 1e6) % 2147483647)
-- Generate a new stable record id. Prefixed "custom_" so logs and ExtState
-- dumps are self-describing; 8 random hex chars for 4-billion-wide namespace
-- (collision-resistant for any realistic record count).
function Custom.gen_id()
  local chars = {}
  for i = 1, 8 do chars[i] = str_format("%x", math.random(0, 15)) end
  return "custom_" .. tbl_concat(chars)
end

-- Read the ordered id list. Returns {} when unset. IDs are re-validated by
-- the caller against the per-record keys before being trusted.
function Custom.load_ids()
  local raw = reaper.GetExtState(CFG.EXT_NS, "custom_provider_ids")
  if raw == "" then return {} end
  local ids = {}
  for id in (raw .. ","):gmatch("([^,]*),") do
    id = id:match("^%s*(.-)%s*$") or ""
    if id ~= "" then ids[#ids+1] = id end
  end
  return ids
end

function Custom.save_ids(ids)
  reaper.SetExtState(CFG.EXT_NS, "custom_provider_ids",
    tbl_concat(ids or {}, ","), true)
end

-- REAPER's ExtState writer round-trips literal newlines fine *within* a
-- session (SetExtState/GetExtState see the full multi-line string), but it
-- truncates each value at the first newline when serializing to
-- reaper-extstate.ini on shutdown. A user who saves a 4-row models blob
-- (rows joined by "\n") sees the right thing in-session, then closes
-- REAPER and on re-open finds only the first row survived.
--
-- Fix: percent-encode \n / \r before SetExtState, decode after GetExtState,
-- for any field that legitimately holds multiple lines (custom-provider
-- _models and _extra_headers right now). Encoding `%` first is what makes
-- the round-trip lossless when user content already contains a literal `%`
-- or `%25` sequence -- decode reverses the order to undo the guarding.
--
-- Backward compatibility: the decode is a no-op on legacy single-line
-- content (no `%0A`/`%0D`/`%25` sequences appear in any pre-existing
-- _models or _extra_headers value the encoder could have produced).
--
-- Hung off the Custom table rather than declared as `local function`s so
-- the main chunk doesn't blow past Lua's 200-local-variable limit (hard
-- parse error, not a style nit).
function Custom._mline_encode(s)
  if not s or s == "" then return s or "" end
  s = s:gsub("%%", "%%25")
  s = s:gsub("\n", "%%0A")
  s = s:gsub("\r", "%%0D")
  return s
end
function Custom._mline_decode(s)
  if not s or s == "" then return s or "" end
  s = s:gsub("%%0A", "\n")
  s = s:gsub("%%0D", "\r")
  s = s:gsub("%%25", "%%")
  return s
end

-- Parse a per-record "models" ExtState blob. Pipe-delimited fields, one line
-- per model. The extra_body field (optional JSON object) is appended after a
-- tab separator to avoid pipe-in-JSON collisions; single-line JSON.encode
-- output never contains a literal tab, so tab is a safe sentinel. The notes
-- field (short free-text label shown in the main-screen model dropdown) is
-- rejected at save time if it contains "|" or "\t", so it's safe inside the
-- pipe-delimited main part.
--
-- Row format:
--   id|price_in|price_out|context|price_cache_r|notes[\t<extra_body_json>]
-- Legacy rows may omit the cache-hit price and/or notes fields. Keep them
-- loadable so an upgrade does not silently drop a user's custom models.
--
-- Empty / malformed rows are dropped.
local function parse_models_blob(raw)
  local out = {}
  if not raw or raw == "" then return out end
  for line in (raw .. "\n"):gmatch("([^\n]*)\n") do
    if line ~= "" then
      -- Peel off optional extra_body after the tab sentinel.
      local main, extra = line:match("^(.-)\t(.*)$")
      if not main then main = line end
      local fields = {}
      for part in (main .. "|"):gmatch("([^|]*)|") do
        fields[#fields+1] = part
      end
      local id, pin, pout, ctx = fields[1], fields[2], fields[3], fields[4]
      local pcache, notes = fields[5] or "0", fields[6] or ""
      if #fields == 5 and pcache ~= "" and not tonumber(pcache) then
        notes, pcache = pcache, "0"
      end
      if id and id ~= "" and #fields >= 4 and #fields <= 6 then
        local ctx_n = tonumber(ctx) or CUSTOM_DEFAULT_CTX
        if ctx_n < CUSTOM_MIN_CTX then ctx_n = CUSTOM_MIN_CTX end
        out[#out+1] = {
          id             = id,
          price_in       = tonumber(pin)    or 0,
          price_out      = tonumber(pout)   or 0,
          price_cache_r  = tonumber(pcache) or 0,
          context_window = ctx_n,
          notes          = notes or "",
          extra_body     = extra or "",
        }
      end
    end
  end
  return out
end

local function encode_models_blob(models)
  local lines = {}
  for _, m in ipairs(models or {}) do
    local ctx    = tonumber(m.context_window) or CUSTOM_DEFAULT_CTX
    local pcache = tonumber(m.price_cache_r)  or 0
    local base = (m.id or "") .. "|"
              .. tostring(m.price_in  or 0) .. "|"
              .. tostring(m.price_out or 0) .. "|"
              .. tostring(ctx) .. "|"
              .. tostring(pcache) .. "|"
              .. (m.notes or "")
    local extra = m.extra_body or ""
    if extra ~= "" then
      lines[#lines+1] = base .. "\t" .. extra
    else
      lines[#lines+1] = base
    end
  end
  return tbl_concat(lines, "\n")
end

-- Read one record by id. Returns nil if the record has no endpoint or
-- no valid models (either field missing = record is effectively empty,
-- same treatment as a record that was never saved).
function Custom.load_record(id)
  if not id or id == "" then return nil end
  local endpoint = Custom.normalize_chat_endpoint(
    reaper.GetExtState(CFG.EXT_NS, "custom_" .. id .. "_endpoint"))
  if endpoint == "" then return nil, "missing endpoint" end
  if not Custom.endpoint_is_safe(endpoint) then
    if Store and Store._log then
      Store._log("PROVIDERS", "skipping ExtState provider "
        .. tostring(id) .. ": invalid endpoint")
    end
    return nil, Custom.REASON_INVALID_ENDPOINT
  end
  local label      = reaper.GetExtState(CFG.EXT_NS, "custom_" .. id .. "_label")
  -- _models is multi-line content stored encoded; see Custom._mline_*
  -- helpers above for why. Decode is a no-op on legacy single-line blobs.
  local models_raw = Custom._mline_decode(
    reaper.GetExtState(CFG.EXT_NS, "custom_" .. id .. "_models"))
  local timeout    = tonumber(
    reaper.GetExtState(CFG.EXT_NS, "custom_" .. id .. "_timeout_secs"))
    or CUSTOM_DEFAULT_TIMEOUT
  if timeout < CUSTOM_MIN_TIMEOUT then timeout = CUSTOM_MIN_TIMEOUT end
  if timeout > CUSTOM_MAX_TIMEOUT then timeout = CUSTOM_MAX_TIMEOUT end
  local connect_t = tonumber(
    reaper.GetExtState(CFG.EXT_NS, "custom_" .. id .. "_connect_timeout"))
    or Custom.DEFAULT_CONNECT
  if connect_t < Custom.MIN_CONNECT then connect_t = Custom.MIN_CONNECT end
  if connect_t > Custom.MAX_CONNECT then connect_t = Custom.MAX_CONNECT end
  local allow_insecure =
    reaper.GetExtState(CFG.EXT_NS, "custom_" .. id .. "_allow_insecure") == "1"
  local model_prefix   =
    reaper.GetExtState(CFG.EXT_NS, "custom_" .. id .. "_model_prefix")
  -- Parse extra headers. One "Name: value" per line; drop empty and unsafe
  -- lines silently (they were either blanks the user left between edits or
  -- characters that slipped past UI validation -- better to drop than to
  -- try to render a command line with them).
  -- _extra_headers is the other multi-line ExtState field; see encode/decode
  -- comment above. Decode is a no-op on legacy / single-header blobs.
  local headers_raw = Custom._mline_decode(
    reaper.GetExtState(CFG.EXT_NS, "custom_" .. id .. "_extra_headers"))
  local extra_headers = {}
  if headers_raw and headers_raw ~= "" then
    for line in (headers_raw .. "\n"):gmatch("([^\n]*)\n") do
      line = line:match("^%s*(.-)%s*$") or ""
      if line ~= "" and Custom.header_is_safe(line) and line:find(":", 1, true) then
        extra_headers[#extra_headers+1] = line
      end
    end
  end
  local models = parse_models_blob(models_raw)
  if #models == 0 then return nil, "missing models" end
  -- Provider-level extra_body: raw JSON string (canonicalized at save time).
  -- Trusted as-is at load; the save validator is the only gate that checks
  -- syntax, so a hand-edited ExtState with garbage JSON would flow through
  -- until the first send and be rejected by the remote API. That's an
  -- acceptable tradeoff for not re-parsing on every script load.
  local extra_body = reaper.GetExtState(
    CFG.EXT_NS, "custom_" .. id .. "_extra_body") or ""
  return {
    id                  = id,
    label               = (label ~= "" and label) or "Custom",
    endpoint            = endpoint,
    timeout_secs        = timeout,
    connect_timeout_secs = connect_t,
    allow_insecure      = allow_insecure,
    model_prefix        = model_prefix or "",
    extra_headers       = extra_headers,
    extra_body          = extra_body,
    models              = models,
  }
end

-- Read every valid ExtState record in the order the id list specifies. Records
-- whose per-key data is missing/empty are silently skipped AND pruned from the
-- stored id list, so the list is self-healing against manual ini edits (or
-- partial factory-reset states) that leave a dangling id with no backing data.
function Custom.load_all_extstate()
  local ids = Custom.load_ids()
  local records = {}
  local valid_ids = {}
  local pruned_ids = {}
  local pruned = false
  for _, id in ipairs(ids) do
    local rec, reason = Custom.load_record(id)
    if rec then
      records[#records+1]     = rec
      valid_ids[#valid_ids+1] = id
    elseif reason == Custom.REASON_INVALID_ENDPOINT then
      valid_ids[#valid_ids+1] = id
    else
      pruned = true
      pruned_ids[#pruned_ids+1] = id
    end
  end
  if pruned then
    Custom.save_ids(valid_ids)
    for _, id in ipairs(pruned_ids) do
      Custom.delete_record_extstate(id, true)
    end
  end
  return records
end

function Custom.load_all()
  if Store and Store.load_providers then
    local records, err = Store.load_providers()
    if records then return records end
    if err and err ~= "missing" and err ~= "empty" then
      Store._log("PROVIDERS", "falling back to ExtState providers: "
        .. tostring(err))
    end
  end
  return Custom.load_all_extstate()
end

function Custom._mirror_providers_file()
  if Store and Store.save_providers then
    return Store.save_providers(Custom.load_all_extstate())
  end
  return nil
end

-- Persist one record's per-key data. Does NOT touch the id list -- that's
-- managed by upsert_record / remove_record so save_record stays idempotent
-- for in-place edits.
function Custom.save_record(record)
  local id = record.id
  reaper.SetExtState(CFG.EXT_NS, "custom_" .. id .. "_endpoint",
    Custom.normalize_chat_endpoint(record.endpoint or ""), true)
  reaper.SetExtState(CFG.EXT_NS, "custom_" .. id .. "_label",
    record.label or "", true)
  reaper.SetExtState(CFG.EXT_NS, "custom_" .. id .. "_timeout_secs",
    tostring(record.timeout_secs or CUSTOM_DEFAULT_TIMEOUT), true)
  reaper.SetExtState(CFG.EXT_NS, "custom_" .. id .. "_connect_timeout",
    tostring(record.connect_timeout_secs or Custom.DEFAULT_CONNECT), true)
  reaper.SetExtState(CFG.EXT_NS, "custom_" .. id .. "_allow_insecure",
    record.allow_insecure and "1" or "0", true)
  reaper.SetExtState(CFG.EXT_NS, "custom_" .. id .. "_model_prefix",
    record.model_prefix or "", true)
  -- Extra headers: filter unsafe entries here too, so a record can't carry
  -- a malformed header even if save_record is called from a code path that
  -- skipped the UI validator.
  local safe_headers = {}
  for _, h in ipairs(record.extra_headers or {}) do
    if Custom.header_is_safe(h) and h:find(":", 1, true) then
      safe_headers[#safe_headers+1] = h
    end
  end
  -- Multi-line value: encode \n so REAPER's ExtState INI writer doesn't
  -- truncate every header after the first one when saving to disk on
  -- shutdown. See Custom._mline_encode for the round-trip rationale.
  reaper.SetExtState(CFG.EXT_NS, "custom_" .. id .. "_extra_headers",
    Custom._mline_encode(tbl_concat(safe_headers, "\n")), true)
  -- Provider-level extra_body: stored as-is. Save handlers are expected to
  -- have already canonicalized it via Custom.validate_extra_body before
  -- reaching here, so this write is a straight pass-through.
  reaper.SetExtState(CFG.EXT_NS, "custom_" .. id .. "_extra_body",
    record.extra_body or "", true)
  -- Same multi-line encoding rationale as _extra_headers above: this blob
  -- joins rows with "\n", which REAPER's INI writer would truncate at the
  -- first newline on shutdown without the encode hop.
  reaper.SetExtState(CFG.EXT_NS, "custom_" .. id .. "_models",
    Custom._mline_encode(encode_models_blob(record.models or {})), true)
end

function Custom.delete_record_extstate(id, include_api_key)
  reaper.DeleteExtState(CFG.EXT_NS, "custom_" .. id .. "_endpoint",        true)
  reaper.DeleteExtState(CFG.EXT_NS, "custom_" .. id .. "_label",           true)
  reaper.DeleteExtState(CFG.EXT_NS, "custom_" .. id .. "_timeout_secs",    true)
  reaper.DeleteExtState(CFG.EXT_NS, "custom_" .. id .. "_connect_timeout", true)
  reaper.DeleteExtState(CFG.EXT_NS, "custom_" .. id .. "_allow_insecure",  true)
  reaper.DeleteExtState(CFG.EXT_NS, "custom_" .. id .. "_model_prefix",    true)
  reaper.DeleteExtState(CFG.EXT_NS, "custom_" .. id .. "_extra_headers",   true)
  reaper.DeleteExtState(CFG.EXT_NS, "custom_" .. id .. "_extra_body",      true)
  reaper.DeleteExtState(CFG.EXT_NS, "custom_" .. id .. "_models",          true)
  if include_api_key then
    reaper.DeleteExtState(CFG.EXT_NS, "api_key_" .. id, true)
  end
end

-- Save + ensure the record's id appears in the ordered id list. If the id
-- is already present, only the per-key data is rewritten (the list order
-- is preserved so the provider dropdown doesn't reshuffle on every edit).
function Custom.upsert_record(record)
  if not Store or not Store.save_providers then
    Custom.save_record(record)
    local ids = Custom.load_ids()
    local found = false
    for _, existing in ipairs(ids) do
      if existing == record.id then found = true; break end
    end
    if not found then
      ids[#ids+1] = record.id
      Custom.save_ids(ids)
    end
    return
  end
  local records = Custom.load_all()
  local found = false
  for i, existing in ipairs(records) do
    if existing.id == record.id then
      records[i] = record
      found = true
      break
    end
  end
  if not found then
    records[#records+1] = record
  end
  Store.save_providers(records)
end

-- Delete one record: update Providers.json and clear its API key. The caller is
-- responsible for calling unregister_id if the record is currently registered
-- in PROVIDERS.
function Custom.remove_record(id)
  if not Store or not Store.save_providers then
    Custom.delete_record_extstate(id, true)
    local ids = Custom.load_ids()
    for i = #ids, 1, -1 do
      if ids[i] == id then table.remove(ids, i) end
    end
    Custom.save_ids(ids)
    return
  end
  local records = Custom.load_all()
  for i = #records, 1, -1 do
    if records[i].id == id then table.remove(records, i) end
  end
  local err = Store.save_providers(records)
  if not err then Custom.delete_record_extstate(id, true) end
  return err
end

function Custom.build_provider(record)
  -- Build one entry per configured model so the main UI's model dropdown
  -- shows them all and per-message cost uses the correct prices. Each model
  -- carries its own context_window so the preflight check can warn against
  -- requests that would overflow the specific model the user has loaded.
  --
  -- Display label: the raw model id, with an optional short notes tag
  -- appended (" . <notes>") so rows that share a model id but differ in
  -- tuning (thinking on/off, temperature preset, etc.) are distinguishable
  -- in the main-screen dropdown. The on-wire id stays unmodified.
  local prov_models = {}
  for _, m in ipairs(record.models or {}) do
    local label = m.id or ""
    if m.notes and m.notes ~= "" then
      label = label .. " \xc2\xb7 " .. m.notes  -- utf-8 middle dot
    end
    prov_models[#prov_models+1] = {
      label          = label,
      id             = m.id,
      price_in       = m.price_in       or 0,
      price_out      = m.price_out      or 0,
      price_cache_r  = m.price_cache_r  or 0,
      context_window = m.context_window or CUSTOM_DEFAULT_CTX,
      extra_body     = m.extra_body     or "",
      notes          = m.notes          or "",
    }
  end
  if #prov_models == 0 then
    -- Defensive: build_provider should never be called with an empty list,
    -- but if it is, give the dropdown a single placeholder so the main UI
    -- doesn't crash on MODELS[1] indexing.
    prov_models[1] = { label = "Custom", id = "custom", price_in = 0,
                       price_out = 0, price_cache_r = 0,
                       context_window = CUSTOM_DEFAULT_CTX,
                       extra_body = "", notes = "" }
  end
  -- Pass-through the saved extra headers (already sanitized at save time).
  -- A defensive second pass here catches any record that was hand-written
  -- directly into ExtState, bypassing the UI's validator.
  local headers_pass = {}
  for _, h in ipairs(record.extra_headers or {}) do
    if Custom.header_is_safe(h) and h:find(":", 1, true) then
      headers_pass[#headers_pass+1] = h
    end
  end
  -- has_caching: true when any model on this provider has a non-zero cache-hit
  -- price. Gates the cost-accounting display so custom providers that surface
  -- usage.prompt_tokens_details.cached_tokens (Kimi, OpenRouter, some vLLM
  -- builds) get their cached portion billed at the discounted rate instead
  -- of being silently dropped from the cost estimate.
  local has_caching = false
  for _, m in ipairs(prov_models) do
    if (m.price_cache_r or 0) > 0 then has_caching = true; break end
  end

  return {
    id                = record.id,
    label             = record.label or "Custom",
    endpoint          = Custom.normalize_chat_endpoint(record.endpoint),
    auth_style        = "header",
    auth_header       = "Authorization",
    auth_prefix       = "Bearer ",
    extra_headers     = headers_pass,
    key_prefix        = "",
    key_min_len       = 0,
    key_extstate      = "api_key_" .. record.id,
    has_caching       = has_caching,
    console_url       = nil,
    console_label     = nil,
    billing_url       = nil,
    billing_label     = nil,
    default_model_idx = 1,
    thinking_levels   = nil,
    is_custom         = true,
    -- Request timeout is provider-wide (one curl --max-time value applies
    -- regardless of which model is currently selected from the dropdown).
    request_timeout   = record.timeout_secs or CUSTOM_DEFAULT_TIMEOUT,
    connect_timeout   = record.connect_timeout_secs or Custom.DEFAULT_CONNECT,
    allow_insecure    = record.allow_insecure and true or false,
    -- Prepended to MODELS.active_id() when building the OpenAI-compatible
    -- request body. Empty string is the no-op default.
    model_prefix      = record.model_prefix or "",
    -- Provider-wide JSON object merged into every chat-completions request
    -- body. Stored in canonical JSON.encode form (validated at save time).
    -- Per-model extra_body overrides keys set here on a per-request basis;
    -- see Net.build_body_openai for the merge.
    extra_body        = record.extra_body or "",
    models            = prov_models,
  }
end

-- Append one provider entry to PROVIDERS and refresh lookup tables. Returns
-- the 1-based index of the new entry. Does NOT remove existing customs --
-- that's register_all's job; register_one is primarily for the in-flight
-- connection-test path that registers a single temporary provider.
-- Bumped whenever the custom-provider list mutates (register_one /
-- unregister_all / unregister_id). Render-side code can key cached
-- "list custom records" walks on this cookie and only rebuild on
-- change rather than rebuilding every frame on the screens that show
-- them.
Custom._records_version = 0

function Custom.register_one(record)
  local prov = Custom.build_provider(record)
  PROVIDERS[#PROVIDERS+1]    = prov
  PROVIDERS._by_id[prov.id]  = #PROVIDERS
  Custom._records_version    = Custom._records_version + 1
  return #PROVIDERS
end

-- Remove every entry flagged is_custom. Caller is responsible for clamping
-- prefs.provider_idx after -- indices shift when entries disappear.
function Custom.unregister_all()
  for i = #PROVIDERS, 1, -1 do
    if PROVIDERS[i].is_custom then table.remove(PROVIDERS, i) end
  end
  PROVIDERS._by_id = {}
  for i, p in ipairs(PROVIDERS) do PROVIDERS._by_id[p.id] = i end
  Custom._records_version = Custom._records_version + 1
end

-- Remove one specific custom entry by id. Used by the connection-test path
-- to pull the temporary test provider without disturbing saved records.
function Custom.unregister_id(id)
  for i = #PROVIDERS, 1, -1 do
    if PROVIDERS[i].id == id then table.remove(PROVIDERS, i) end
  end
  PROVIDERS._by_id = {}
  for i, p in ipairs(PROVIDERS) do PROVIDERS._by_id[p.id] = i end
  Custom._records_version = Custom._records_version + 1
end

-- Full refresh: clear every custom entry, then re-register each persisted
-- record in the saved order. Safe to call multiple times.
function Custom.register_all()
  Custom.unregister_all()
  for _, rec in ipairs(Custom.load_all()) do
    Custom.register_one(rec)
  end
end

-- Register every persisted record at startup so prefs.provider_idx clamping
-- below sees every custom entry as a valid index.
Custom.register_all()
Store.mirror_providers_if_missing()

-- One-time thinking-level reset, sentinel-gated to fire exactly once per
-- install on first launch of any release that contains this block. Wipes
-- every saved thinking_idx -- both the legacy per-provider key
-- ("thinking_idx_<provider>") and the new per-model keys
-- ("thinking_idx_<provider>_<model>") -- so everyone lands on the
-- freshly-tuned defaults instead of carrying forward a level that was
-- set under different rules. Without this, users who had picked, say,
-- High on GPT-5.4 in 1.1.1 would silently keep High on every GPT-5.4
-- model after upgrade because the legacy key bleeds across models.
--
-- Defaults users land on after the reset:
--   Claude:   Haiku=High (per-model override), Sonnet/Opus=None
--   ChatGPT:  Medium (provider default)
--   Gemini:   Medium (provider default)
--   DeepSeek: Non-Thinking (provider default)
--
-- Subsequent user picks via the chip dropdown persist normally. The
-- sentinel lives in the user's ExtState, so this block needs to remain
-- in future releases too -- a user who skips from 1.1.1 straight to a
-- later release should still get the reset on their first launch of
-- that release. Once the sentinel is "1" the block is a single
-- GetExtState no-op, so the cost of keeping it is negligible. A future
-- release that needs another reset should add a new block with a fresh
-- sentinel name (thinking_idx_reset_v2, etc.) rather than editing
-- this one.
do
  if not (S and S._factory_reset_clean_boot)
     and not Store.migration_fired("thinking_idx_reset_v1") then
    Store.clear_thinking_selections()
    for _, p in ipairs(PROVIDERS) do
      reaper.DeleteExtState(CFG.EXT_NS, "thinking_idx_" .. p.id, true)
      if p.models then
        for _, m in ipairs(p.models) do
          if m.id then
            reaper.DeleteExtState(
              CFG.EXT_NS, "thinking_idx_" .. p.id .. "_" .. m.id, true)
          end
        end
      end
    end
    Store.set_migration_fired("thinking_idx_reset_v1")
  end
end

-- Second one-time reset (v1.1.4), gated by a fresh sentinel. Wipes both
-- saved model_idx_<provider> (per-provider model picks) AND the
-- thinking_idx_<provider>_<model> per-model thinking picks so users
-- land on the new bench-driven defaults shipped this release:
--   anthropic.default_model_idx unchanged (Sonnet still recommended);
--   claude-haiku-4-5 default thinking: Low -> High;
--   openai.default_model_idx: mini (2) -> full GPT-5.4 (3);
--   gpt-5.4-nano default thinking: Low -> None;
--   gemini-3.1-flash-lite default thinking: Minimal -> Low;
--   retired Gemini Flash preview default thinking: Low -> Minimal.
-- Without this, users who'd already picked a model/thinking combo
-- before v1.1.4 would silently keep it and never see the new
-- recommendations -- the picker badge would still mark the recommended
-- row, but the user's saved selection would still load on launch.
--
-- Same sentinel pattern as v1 above: fires exactly once per install
-- on first launch of any release containing this block, then becomes
-- a single GetExtState no-op forever. Future resets add a fresh
-- sentinel name (model_picker_reset_v3, etc.) rather than editing
-- this one. The legacy thinking_idx_<provider> + the per-model keys
-- get wiped again here too -- harmless if v1 already cleared them,
-- and it covers users who installed fresh post-v1 (so v1's reset
-- ran on empty state) and then accumulated picks before v1.1.4.
do
  if not (S and S._factory_reset_clean_boot)
     and not Store.migration_fired("model_picker_reset_v2") then
    Store.clear_model_picker_selections()
    for _, p in ipairs(PROVIDERS) do
      reaper.DeleteExtState(CFG.EXT_NS, "model_idx_" .. p.id, true)
      reaper.DeleteExtState(CFG.EXT_NS, "thinking_idx_" .. p.id, true)
      if p.models then
        for _, m in ipairs(p.models) do
          if m.id then
            reaper.DeleteExtState(
              CFG.EXT_NS, "thinking_idx_" .. p.id .. "_" .. m.id, true)
          end
        end
      end
    end
    Store.set_migration_fired("model_picker_reset_v2")
  end
end

-- One-time Anthropic model-id migration. Opus 4.8 replaces Opus 4.7 at the
-- same price tier and context window, so users who explicitly saved Opus 4.7
-- should stay on the Opus row instead of falling back to the Claude default.
-- Preserve any per-model thinking preference because the wire shape and
-- practical recommendation remain the same.
do
  if not (S and S._factory_reset_clean_boot)
     and not Store.migration_fired("anthropic_opus_48_model_v1") then
    local doc = Store.config_doc()
    doc.selection = type(doc.selection) == "table" and doc.selection or {}
    doc.selection.model_id_by_provider =
      type(doc.selection.model_id_by_provider) == "table"
      and doc.selection.model_id_by_provider or {}
    doc.selection.thinking_idx_by_provider_model =
      type(doc.selection.thinking_idx_by_provider_model) == "table"
      and doc.selection.thinking_idx_by_provider_model or {}
    if doc.selection.model_id_by_provider.anthropic == "claude-opus-4-7" then
      doc.selection.model_id_by_provider.anthropic = "claude-opus-4-8"
    end
    local old_key = "anthropic/claude-opus-4-7"
    local new_key = "anthropic/claude-opus-4-8"
    if doc.selection.thinking_idx_by_provider_model[new_key] == nil then
      doc.selection.thinking_idx_by_provider_model[new_key] =
        doc.selection.thinking_idx_by_provider_model[old_key]
        or tonumber(reaper.GetExtState(CFG.EXT_NS,
          "thinking_idx_anthropic_claude-opus-4-7"))
    end
    doc.selection.thinking_idx_by_provider_model[old_key] = nil
    local old_ext = reaper.GetExtState(
      CFG.EXT_NS, "thinking_idx_anthropic_claude-opus-4-7")
    if old_ext ~= ""
       and reaper.GetExtState(
         CFG.EXT_NS, "thinking_idx_anthropic_claude-opus-4-8") == "" then
      reaper.SetExtState(
        CFG.EXT_NS, "thinking_idx_anthropic_claude-opus-4-8", old_ext, true)
    end
    reaper.DeleteExtState(
      CFG.EXT_NS, "thinking_idx_anthropic_claude-opus-4-7", true)
    doc.migrations = type(doc.migrations) == "table" and doc.migrations or {}
    doc.migrations.anthropic_opus_48_model_v1 = true
    local err = Store.write_json_atomic(RA.CONFIG_PATH, doc, true)
    if err then
      Store._notify_write_failure("Config.json", err)
    end
  end
end

