function OptionalFonts.entry_for_language_code(code)
  return OptionalFonts.entries[tostring(code or "")]
end

function OptionalFonts.entry_for_language_idx(idx)
  if type(idx) == "string" then
    return OptionalFonts.entry_for_language_code(idx)
  end
  if not (CFG and CFG.language_code_for_legacy_idx) then return nil end
  return OptionalFonts.entry_for_language_code(CFG.language_code_for_legacy_idx(idx))
end

function OptionalFonts.ordered_entry_indices()
  local entries = OptionalFonts.entries or {}
  local order, seen, extras = {}, {}, {}
  for _, code in ipairs(OptionalFonts.fallback_order or {}) do
    if entries[code] then
      order[#order + 1] = code
      seen[code] = true
    end
  end
  for code in pairs(entries) do
    if not seen[code] then extras[#extras + 1] = code end
  end
  table.sort(extras, function(a, b)
    return tostring(a) < tostring(b)
  end)
  for _, code in ipairs(extras) do order[#order + 1] = code end
  return order
end

function OptionalFonts.path_for(entry)
  if not entry then return nil end
  return OptionalFonts.DIR .. entry.filename
end

function OptionalFonts._file_exists(path)
  if not path or path == "" then return false end
  if reaper.file_exists then return reaper.file_exists(path) end
  local f = io.open(path, "rb")
  if f then f:close(); return true end
  return false
end

function OptionalFonts._load_font_path(entry, path, source)
  if not entry then return false, "Missing optional font metadata." end
  if not path or path == "" then return false, "Font path is missing." end
  if not (RA and RA.ctx) then
    return false, "ImGui context is not available."
  end
  if reaper.ImGui_ValidatePtr
      and not reaper.ImGui_ValidatePtr(RA.ctx, "ImGui_Context*") then
    return false, "ImGui context is not available."
  end
  local f = io.open(path, "rb")
  if not f then return false, "Font file is missing." end
  f:close()
  local font = ImGui.ImGui_CreateFontFromFile(path, 0, 0)
  if not font then return false, "Font file could not be loaded." end
  local ok_attach, attach_err = pcall(ImGui.ImGui_Attach, RA.ctx, font)
  if not ok_attach then
    return false, tostring(attach_err or "Font file could not be attached.")
  end
  entry.font = font
  entry.font_path = path
  entry.font_source = source or "download"
  if source == "system" then
    entry.system_font_path = path
  else
    entry._file_present = true
  end
  return true
end

function OptionalFonts._fontconfig_match(pattern)
  if not (io and io.popen and Shell and Shell.sh_quote) then return nil end
  pattern = tostring(pattern or "")
  if pattern == "" then return nil end
  local cmd = "fc-match -f '%{file}\\n' " .. Shell.sh_quote(pattern)
    .. " 2>/dev/null"
  local pipe = io.popen(cmd, "r")
  if not pipe then return nil end
  local raw = pipe:read("*a") or ""
  pipe:close()
  local path = raw:gsub("\r", ""):match("([^\n]+)")
  if path and path ~= "" then return path end
  return nil
end

function OptionalFonts._system_font_paths(entry)
  local out, seen = {}, {}
  local function add(path)
    path = tostring(path or "")
    if path ~= "" and not seen[path] then
      out[#out + 1] = path
      seen[path] = true
    end
  end

  if RA and RA.IS_WINDOWS then
    local root = os.getenv("WINDIR") or os.getenv("SystemRoot")
      or "C:\\Windows"
    local fonts_dir = root .. "\\Fonts\\"
    for _, name in ipairs(entry.system_windows or {}) do
      add(fonts_dir .. tostring(name or ""))
    end
  elseif RA and RA.IS_MACOS then
    for _, path in ipairs(entry.system_macos or {}) do add(path) end
  else
    for _, pattern in ipairs(entry.system_fontconfig or {}) do
      add(OptionalFonts._fontconfig_match(pattern))
    end
    for _, path in ipairs(entry.system_linux_paths or {}) do add(path) end
  end
  return out
end

function OptionalFonts.load_system_entry(entry)
  if not entry then return false, "Missing optional font metadata." end
  if entry.font then return true end
  if entry._system_probe_done then
    return false, entry._system_probe_error or "No compatible system font found."
  end
  entry._system_probe_done = true
  local last_err = nil
  for _, path in ipairs(OptionalFonts._system_font_paths(entry)) do
    if OptionalFonts._file_exists(path) then
      local ok, err = OptionalFonts._load_font_path(entry, path, "system")
      if ok then
        if Log and Log.line then
          Log.line("FONT", "using system font for " .. tostring(entry.code)
            .. ": " .. tostring(path))
        end
        entry._system_probe_error = nil
        return true
      end
      last_err = err
    end
  end
  entry._system_probe_error = last_err or "No compatible system font found."
  return false, entry._system_probe_error
end

function OptionalFonts.ensure_dir()
  if I18N and I18N.ensure_cache_dir then
    return I18N.ensure_cache_dir("fonts")
  end
  reaper.RecursiveCreateDirectory(OptionalFonts.DIR, 0)
end

function OptionalFonts.file_exists(entry)
  local exists = OptionalFonts._file_exists(OptionalFonts.path_for(entry))
  if entry then entry._file_present = exists end
  return exists
end

function OptionalFonts.load_entry(entry)
  if not entry then return false, "Missing optional font metadata." end
  if entry.font then return true end
  local path = OptionalFonts.path_for(entry)
  if not OptionalFonts._file_exists(path) then
    entry.font = nil
    entry._file_present = false
    return false, "Font file is missing."
  end
  local ok, err = OptionalFonts._load_font_path(entry, path, "download")
  if not ok then
    entry.font = nil
    return false, err
  end
  return true
end

function OptionalFonts.load_available_entry(entry)
  if not entry then return false, "Missing optional font metadata." end
  if entry.font then return true end
  if OptionalFonts.file_exists(entry) then
    local ok = OptionalFonts.load_entry(entry)
    if ok then return true end
  end
  return false, "Font file is missing."
end

function OptionalFonts.is_ready_for_language_idx(idx)
  local entry = OptionalFonts.entry_for_language_idx(idx)
  if not entry then return true end
  local ok = OptionalFonts.load_available_entry(entry)
  return ok == true
end

function OptionalFonts.is_ready_for_language_code(code)
  if not (CFG and CFG.legacy_idx_for_language_code) then return true end
  return OptionalFonts.is_ready_for_language_idx(
    CFG.legacy_idx_for_language_code(code))
end

function OptionalFonts.active_font()
  local entry = OptionalFonts.entry_for_language_idx(prefs.reply_language_idx or 1)
  if entry and entry.font then return entry.font end
  if entry then
    local ok = OptionalFonts.load_available_entry(entry)
    if ok and entry.font then return entry.font end
  end
  return FONT.inter_reg
end

function OptionalFonts.active_font_key()
  local entry = OptionalFonts.entry_for_language_idx(prefs.reply_language_idx or 1)
  if entry and entry.font then return entry.key end
  if entry then
    local ok = OptionalFonts.load_available_entry(entry)
    if ok and entry.font then return entry.key end
  end
  return "inter"
end

function OptionalFonts._remember_base_fonts()
  if OptionalFonts._base_fonts or not FONT then return end
  OptionalFonts._base_fonts = {
    inter_reg = FONT.inter_reg,
    inter_light = FONT.inter_light,
    inter_semi = FONT.inter_semi,
    inter_bold = FONT.inter_bold,
    mono_reg = FONT.mono_reg,
    mono_med = FONT.mono_med,
    bold_font = RA and RA.bold_font,
  }
end

function OptionalFonts.apply_current_ui_font()
  if not (FONT and RA) then return end
  OptionalFonts._remember_base_fonts()
  local base = OptionalFonts._base_fonts
  if not base then return end
  local entry = OptionalFonts.entry_for_language_idx(
    prefs and prefs.reply_language_idx or 1)
  local font = nil
  if entry then
    if entry.font then
      font = entry.font
    elseif OptionalFonts._ui_font_missing_key ~= entry.key then
      local ok = OptionalFonts.load_available_entry(entry)
      if ok and entry.font then font = entry.font end
    end
  end
  if font then
    if OptionalFonts._ui_font_override_key == entry.key then return end
    FONT.inter_reg = font
    FONT.inter_light = font
    FONT.inter_semi = font
    FONT.inter_bold = font
    FONT.mono_reg = font
    FONT.mono_med = font
    RA.bold_font = font
    OptionalFonts._ui_font_missing_key = nil
    OptionalFonts._ui_font_override_key = entry.key
    return
  end
  if entry then OptionalFonts._ui_font_missing_key = entry.key end
  if OptionalFonts._ui_font_override_key then
    FONT.inter_reg = base.inter_reg
    FONT.inter_light = base.inter_light
    FONT.inter_semi = base.inter_semi
    FONT.inter_bold = base.inter_bold
    FONT.mono_reg = base.mono_reg
    FONT.mono_med = base.mono_med
    RA.bold_font = base.bold_font
    OptionalFonts._ui_font_override_key = nil
  end
end

function OptionalFonts.is_busy()
  local d = OptionalFonts.download or {}
  return d.state == "downloading"
      or d.state == "verifying"
      or d.state == "installing"
      or d.state == "rename_retry"
end

function OptionalFonts._t(key, values, fallback)
  return (RA and RA.t and RA.t(key, values, fallback)) or fallback or key
end

function OptionalFonts._cleanup_tmp_paths(d)
  d = type(d) == "table" and d or {}
  if d.out_path then pcall(os.remove, d.out_path) end
  if d.exit_path then pcall(os.remove, d.exit_path) end
  pcall(os.remove, tmp.font_sha_out)
  pcall(os.remove, tmp.font_sha_exit)
  pcall(os.remove, tmp.font_sha_ps)
end

function OptionalFonts._set_failure(step, err)
  local d = OptionalFonts.download or {}
  d.state = "failed"
  d.last_step = step
  d.last_error = tostring(err or OptionalFonts._t(
    "settings.font.error.unknown", nil, "Unknown font download error."))
  d.done = 0
  d.last_detail = {
    code = d.entry and d.entry.code or "",
    step = tostring(step or ""),
    error = d.last_error,
    url = tostring(d.request_url or d.url or (d.entry and d.entry.url) or ""),
    url_cache_bust = tostring(d.request_url_with_cache_bust or ""),
    curl_exit = d.curl_exit_code,
    expected_bytes = d.entry and d.entry.bytes or nil,
    actual_bytes = d.actual_bytes or OptionalFonts._file_size(d.out_path),
    sha256 = d.entry and d.entry.sha256 or nil,
    sha_mode = d.sha_mode,
  }
  OptionalFonts.download = d
  if Log and Log.line then
    Log.line("FONT", string.format("fail [%s]: %s",
      tostring(step), tostring(d.last_error)))
  end
  OptionalFonts._cleanup_tmp_paths(d)
end

function OptionalFonts._use_system_fallback_after_failure(step, err)
  local d = OptionalFonts.download or {}
  local entry = d.entry
  if not entry then return false end
  local ok, system_err = OptionalFonts.load_system_entry(entry)
  if not ok then
    d.system_fallback_error = system_err
    return false
  end
  d.state = "done"
  d.done = 1
  d.last_step = step
  d.last_error = tostring(err or "")
  d.system_fallback_used = true
  d.system_font_path = entry.system_font_path
  d.status_text = OptionalFonts._t("settings.font.system_fallback", nil,
    "Using system font.")
  d.last_detail = {
    code = entry.code or "",
    step = tostring(step or ""),
    error = d.last_error,
    url = tostring(d.request_url or d.url or entry.url or ""),
    url_cache_bust = tostring(d.request_url_with_cache_bust or ""),
    curl_exit = d.curl_exit_code,
    expected_bytes = entry.bytes,
    actual_bytes = d.actual_bytes or OptionalFonts._file_size(d.out_path),
    sha256 = entry.sha256,
    sha_mode = d.sha_mode,
    system_fallback_used = true,
    system_font_path = entry.system_font_path,
  }
  OptionalFonts.download = d
  if Log and Log.line then
    Log.line("FONT", "preferred font failed; using system font for "
      .. tostring(entry.code) .. ": " .. tostring(entry.system_font_path)
      .. " after " .. tostring(step))
  end
  OptionalFonts._cleanup_tmp_paths(d)
  return true
end

function OptionalFonts._fail_or_use_system_fallback(step, err)
  if OptionalFonts._use_system_fallback_after_failure(step, err) then
    return true
  end
  OptionalFonts._set_failure(step, err)
  return false
end

function OptionalFonts.diagnostic_text(d)
  d = type(d) == "table" and d or OptionalFonts.download or {}
  local detail = type(d.last_detail) == "table" and d.last_detail or {}
  local lines = {
    "ReaAssist font download diagnostic",
    "version=" .. tostring(CFG and CFG.VERSION or ""),
    "os=" .. tostring(reaper and reaper.GetOS and reaper.GetOS() or ""),
    "utc=" .. tostring(os.date and os.date("!%Y-%m-%dT%H:%M:%SZ") or ""),
    "code=" .. tostring(detail.code or (d.entry and d.entry.code) or ""),
    "step=" .. tostring(detail.step or d.last_step or ""),
    "error=" .. tostring(detail.error or d.last_error or ""),
    "url=" .. tostring(detail.url or d.request_url or ""),
    "url_cache_bust=" .. tostring(detail.url_cache_bust
      or d.request_url_with_cache_bust or ""),
    "curl_exit=" .. tostring(detail.curl_exit or d.curl_exit_code or ""),
    "expected_bytes=" .. tostring(detail.expected_bytes or ""),
    "actual_bytes=" .. tostring(detail.actual_bytes or ""),
    "sha256=" .. tostring(detail.sha256 or ""),
    "sha_mode=" .. tostring(detail.sha_mode or d.sha_mode or ""),
    "system_fallback_used=" .. tostring(detail.system_fallback_used
      or d.system_fallback_used or ""),
    "system_font_path=" .. tostring(detail.system_font_path
      or d.system_font_path or ""),
  }
  return table.concat(lines, "\n")
end

function OptionalFonts._read_file(path)
  local f = io.open(path, "rb")
  if not f then return nil end
  local data = f:read("*a")
  f:close()
  return data
end

function OptionalFonts._file_size(path)
  local f = io.open(path, "rb")
  if not f then return nil end
  local size = f:seek("end")
  f:close()
  return size
end

function OptionalFonts._copy_file(src, dest)
  local rf, rerr = io.open(src, "rb")
  if not rf then return false, rerr end
  local wf, werr = io.open(dest, "wb")
  if not wf then rf:close(); return false, werr end
  while true do
    local chunk = rf:read(65536)
    if not chunk then break end
    local ok, err = wf:write(chunk)
    if not ok then
      rf:close(); wf:close()
      os.remove(dest)
      return false, err
    end
  end
  rf:close()
  wf:close()
  return true
end

function OptionalFonts._native_sha_to_lua_fallback(reason)
  local d = OptionalFonts.download
  if not d then return end
  d.sha_mode = "lua"
  d.sha_send_time = nil
  d.lua_sha_state = nil
  if Log and Log.line then
    Log.line("FONT", "native checksum unavailable; falling back to Lua SHA"
      .. (reason and (": " .. tostring(reason)) or ""))
  end
end

function OptionalFonts.fire_native_sha(path)
  os.remove(tmp.font_sha_out)
  os.remove(tmp.font_sha_exit)
  os.remove(tmp.font_sha_ps)
  if not path or path == "" then return false end

  if RA.IS_WINDOWS then
    for _, c in ipairs({'"', '<', '>', '|'}) do
      if path:find(c, 1, true)
          or tmp.font_sha_out:find(c, 1, true)
          or tmp.font_sha_exit:find(c, 1, true)
          or tmp.font_sha_ps:find(c, 1, true) then
        Log.line("FONT", string.format(
          "fire_native_sha: refusing to launch with cmd-unsafe character '%s'",
          c))
        return false
      end
    end
    local ps_script = string.format(
[[$ErrorActionPreference = 'Stop'
$exitPath = '%s'
$utf8 = New-Object System.Text.UTF8Encoding($false)
try {
  function Get-Sha256Hex([string]$Path) {
    $sha = [System.Security.Cryptography.SHA256]::Create()
    $stream = [System.IO.File]::Open($Path,
      [System.IO.FileMode]::Open,
      [System.IO.FileAccess]::Read,
      [System.IO.FileShare]::ReadWrite)
    try {
      $hash = $sha.ComputeHash($stream)
      return ([System.BitConverter]::ToString($hash)).Replace('-', '').ToLowerInvariant()
    } finally {
      $stream.Dispose()
      $sha.Dispose()
    }
  }
  $h = $null
  for ($i = 0; $i -lt 60; $i++) {
    try {
      $h = Get-Sha256Hex -Path '%s'
      break
    } catch {
      if ($i -eq 59) { throw }
      Start-Sleep -Milliseconds 200
    }
  }
  $writer = New-Object System.IO.StreamWriter('%s', $false, $utf8)
  try {
    $writer.Write($h)
  } finally {
    $writer.Close()
  }
  [System.IO.File]::WriteAllText($exitPath, '0', $utf8)
  exit 0
} catch {
  try {
    [System.IO.File]::WriteAllText($exitPath, '1', $utf8)
  } catch {
  }
  exit 1
}
]],
      Shell.ps_escape(tmp.font_sha_exit), Shell.ps_escape(path),
      Shell.ps_escape(tmp.font_sha_out))
    local sf, sf_err = io.open(tmp.font_sha_ps, "wb")
    if not sf then
      Log.line("FONT", "fire_native_sha: PS-script open failed: "
                       .. tostring(sf_err))
      return false
    end
    sf:write("\239\187\191")
    sf:write(ps_script)
    sf:close()
    local cmd_line = string.format(
      'powershell -NoProfile -ExecutionPolicy Bypass'
      .. ' -File """%s"""',
      tmp.font_sha_ps)
    local ps_cmd = string.format(
      'powershell -NoProfile -WindowStyle Hidden'
      .. ' -Command "Start-Process cmd -ArgumentList \'/c %s\''
      .. ' -WindowStyle Hidden"',
      Shell.ps_escape(cmd_line))
    reaper.ExecProcess(ps_cmd, 5000)
  else
    local cmd = string.format(
      "(if command -v sha256sum >/dev/null 2>&1; then "
      .. "sha256sum %s | awk '{print $1}' > %s; rc=$?; "
      .. "elif command -v shasum >/dev/null 2>&1; then "
      .. "shasum -a 256 %s | awk '{print $1}' > %s; rc=$?; "
      .. "else rc=127; fi; echo $rc > %s) &",
      Shell.sh_quote(path), Shell.sh_quote(tmp.font_sha_out),
      Shell.sh_quote(path), Shell.sh_quote(tmp.font_sha_out),
      Shell.sh_quote(tmp.font_sha_exit))
    os.execute(cmd)
  end
  return true
end

function OptionalFonts.start_download(language_idx)
  local entry = OptionalFonts.entry_for_language_idx(language_idx)
  if not entry then
    return false, OptionalFonts._t("settings.font.error.no_font_needed", nil,
      "No optional font is needed for this language.")
  end
  if OptionalFonts.is_ready_for_language_idx(language_idx) then
    return true, "ready"
  end
  if OptionalFonts.is_busy() then
    return false, OptionalFonts._t("settings.font.error.already_running", nil,
      "A language font download is already running.")
  end
  if Updater and Updater.is_busy and Updater.is_busy() then
    return false, OptionalFonts._t("settings.font.error.update_busy", nil,
      "Finish the current update check before downloading a font.")
  end
  if LangPacks and LangPacks.is_busy and LangPacks.is_busy() then
    return false, OptionalFonts._t("settings.lang.finish_download_first", nil,
      "Finish the language pack download first.")
  end
  if LangPacks and LangPacks.ensure_dir then
    LangPacks.ensure_dir("tmp")
  elseif I18N and I18N.ensure_cache_dir then
    I18N.ensure_cache_dir("tmp")
  else
    reaper.RecursiveCreateDirectory(RA.LANG_TMP_DIR, 0)
  end
  local font_suffix = (RA and RA.instance_file_suffix and RA.instance_file_suffix())
    or tostring(S and S.INSTANCE_ID or "session")
  local base = RA.LANG_TMP_DIR .. "font_" .. entry.key .. "_" .. font_suffix
  local out_path = base .. ".download"
  local exit_path = base .. ".exit"
  os.remove(out_path)
  os.remove(exit_path)
  OptionalFonts.download = {
    state = "downloading",
    language_idx = language_idx,
    entry = entry,
    url = entry.url,
    out_path = out_path,
    exit_path = exit_path,
    done = 0,
    total = 1,
    status_text = OptionalFonts._t("settings.font.downloading", nil,
      "Downloading font..."),
  }
  local ok = RA.fire_get_to(entry.url, out_path, exit_path,
    CFG.FONT_DOWNLOAD_TIMEOUT, OptionalFonts.download, "FONT",
    { cache_bust = false })
  if not ok then
    if OptionalFonts._fail_or_use_system_fallback("launch", OptionalFonts._t(
        "settings.font.error.launch", nil, "Font download could not start.")) then
      return true, "ready"
    end
    return false, OptionalFonts.download.last_error
  end
  return true
end

function OptionalFonts._install_verified_download()
  local d = OptionalFonts.download
  local entry = d and d.entry
  if not entry then
    OptionalFonts._set_failure("install", OptionalFonts._t(
      "settings.font.error.no_metadata", nil,
      "Missing downloaded font metadata."))
    return
  end
  OptionalFonts.ensure_dir()
  local dest = OptionalFonts.path_for(entry)
  local tmp_path = dest .. ".tmp"
  os.remove(tmp_path)
  local ok_stage, stage_err = os.rename(d.out_path, tmp_path)
  if not ok_stage then
    local ok_copy, copy_err = OptionalFonts._copy_file(d.out_path, tmp_path)
    if not ok_copy then
      OptionalFonts._fail_or_use_system_fallback("stage", OptionalFonts._t(
        "settings.font.error.stage",
        { error = tostring(copy_err or stage_err) },
        string.format("Could not stage downloaded font: %s",
          tostring(copy_err or stage_err))))
      return
    end
    os.remove(d.out_path)
  end
  os.remove(dest)
  local ok_mv = os.rename(tmp_path, dest)
  if not ok_mv then
    d.state = "rename_retry"
    d.rename_started_at = time_precise()
    d.rename_tmp = tmp_path
    d.rename_dest = dest
    d.status_text = OptionalFonts._t("settings.font.installing", nil,
      "Installing font...")
    return
  end
  entry.font = nil
  local ok_load, load_err = OptionalFonts.load_entry(entry)
  if not ok_load then
    OptionalFonts._fail_or_use_system_fallback("load", load_err)
    return
  end
  d.state = "done"
  d.done = 1
  d.status_text = OptionalFonts._t("settings.font.installed", nil,
    "Font installed.")
  OptionalFonts._cleanup_tmp_paths(d)
end

function OptionalFonts.poll()
  local d = OptionalFonts.download
  if not d or d.state == "idle" or d.state == "done" or d.state == "failed" then
    return
  end
  if d.state == "downloading" then
    if not d.send_time then
      OptionalFonts._fail_or_use_system_fallback("download", OptionalFonts._t(
        "settings.font.error.download_missing", nil, "Download did not launch."))
      return
    end
    if (time_precise() - d.send_time) > (CFG.FONT_DOWNLOAD_TIMEOUT + 10) then
      OptionalFonts._fail_or_use_system_fallback("download", OptionalFonts._t(
        "settings.font.error.download_timeout", nil, "Font download timed out."))
      return
    end
    local ef = io.open(d.exit_path, "r")
    if not ef then return end
    local exit_str = ef:read("*a"); ef:close()
    local exit_code = tonumber(exit_str:match("(%d+)"))
    if not exit_code then return end
    d.curl_exit_code = exit_code
    if exit_code ~= 0 then
      OptionalFonts._fail_or_use_system_fallback("download", OptionalFonts._t(
        "settings.font.error.download_failed", nil, "Font download failed."))
      return
    end
    d.state = "verifying"
    d.sha_send_time = nil
    d.status_text = OptionalFonts._t("settings.font.verifying", nil,
      "Verifying font...")
    local size = OptionalFonts._file_size(d.out_path)
    d.actual_bytes = size
    local entry = d.entry
    if not size or size == 0 then
      OptionalFonts._fail_or_use_system_fallback("verify", OptionalFonts._t(
        "settings.font.error.empty", nil, "Downloaded font file is empty."))
      return
    end
    if entry.bytes and size ~= entry.bytes then
      OptionalFonts._fail_or_use_system_fallback("verify", OptionalFonts._t(
        "settings.font.error.size_mismatch",
        { actual = size, expected = entry.bytes },
        string.format("Downloaded font size was %d bytes, expected %d.",
          size, entry.bytes)))
      return
    end
    d.sha_send_time = time_precise()
    d.sha_mode = OptionalFonts.fire_native_sha(d.out_path) and "native" or "lua"
    return
  end
  if d.state == "verifying" then
    if d.sha_send_time
        and (time_precise() - d.sha_send_time)
            > (CFG.UPDATE_NATIVE_SHA_TIMEOUT + 5) then
      OptionalFonts._native_sha_to_lua_fallback("watchdog timeout")
      return
    end
    local entry = d.entry
    local actual = nil
    if d.sha_mode == "native" then
      local ef = io.open(tmp.font_sha_exit, "r")
      if not ef then return end
      local exit_str = ef:read("*a"); ef:close()
      local exit_code = tonumber(exit_str:match("(%d+)"))
      if not exit_code then return end
      if exit_code ~= 0 then
        OptionalFonts._native_sha_to_lua_fallback(
          "native hasher exited " .. tostring(exit_code))
        return
      end
      local raw_hash = OptionalFonts._read_file(tmp.font_sha_out)
      actual = raw_hash and raw_hash:match("([0-9a-fA-F]+)") or nil
      if not actual then
        OptionalFonts._native_sha_to_lua_fallback("native output missing hash")
        return
      end
    else
      if not d.lua_sha_state then
        local raw = OptionalFonts._read_file(d.out_path)
        if not raw then return end
        if RA and RA.sha256_create and RA.sha256_step
            and RA.sha256_finalize then
          d.lua_sha_state = RA.sha256_create(raw)
        else
          actual = RA and RA.sha256_hex and RA.sha256_hex(raw)
        end
      end
      if d.lua_sha_state then
        local tick_start = time_precise()
        local budget = CFG.UPDATE_SHA_TIME_BUDGET_MANUAL
          or CFG.UPDATE_SHA_TIME_BUDGET
          or 0.005
        local done
        repeat
          done = RA.sha256_step(d.lua_sha_state, 16)
          if done then break end
        until (time_precise() - tick_start) >= budget
        if not done then return end
        actual = RA.sha256_finalize(d.lua_sha_state)
        d.lua_sha_state = nil
      end
    end
    actual = actual and actual:lower() or nil
    if not actual then
      OptionalFonts._fail_or_use_system_fallback("verify", OptionalFonts._t(
        "settings.font.error.checksum_start", nil,
        "Font checksum could not start."))
      return
    end
    if actual ~= entry.sha256 then
      OptionalFonts._fail_or_use_system_fallback("verify", OptionalFonts._t(
        "settings.font.error.checksum_mismatch", nil,
        "Downloaded font checksum did not match."))
      return
    end
    d.state = "installing"
    d.status_text = OptionalFonts._t("settings.font.installing", nil,
      "Installing font...")
    OptionalFonts._install_verified_download()
    return
  end
  if d.state == "rename_retry" then
    os.remove(d.rename_dest)
    local ok_mv = os.rename(d.rename_tmp, d.rename_dest)
    if ok_mv then
      local entry = d.entry
      if entry then entry.font = nil end
      local ok_load, load_err = OptionalFonts.load_entry(entry)
      if not ok_load then
        OptionalFonts._fail_or_use_system_fallback("load", load_err)
        return
      end
      d.state = "done"
      d.done = 1
      d.status_text = OptionalFonts._t("settings.font.installed", nil,
        "Font installed.")
      OptionalFonts._cleanup_tmp_paths(d)
      return
    end
    if d.rename_started_at
        and (time_precise() - d.rename_started_at) > 5 then
      OptionalFonts._fail_or_use_system_fallback("install", OptionalFonts._t(
        "settings.font.error.install_move", nil,
        "Could not move the downloaded font into Data/Lang/fonts."))
    end
  end
end

function OptionalFonts.warm_up_installed()
  for _, code in ipairs(OptionalFonts.ordered_entry_indices()) do
    local entry = OptionalFonts.entries[code]
    if OptionalFonts.file_exists(entry) then
      OptionalFonts.load_entry(entry)
    end
  end
end

OptionalFonts.warm_up_installed()

-- Build a UTF-8 string for a Unicode codepoint in the U+0800..U+FFFF range.
-- Lucide glyphs live in PUA (U+E000..U+F8FF), which always encodes to 3-byte
-- UTF-8. The ICON table precomputes these so source stays ASCII.
local function _utf8(cp)
  return string.char(
    0xE0 | (cp >> 12),
    0x80 | ((cp >> 6) & 0x3F),
    0x80 | (cp & 0x3F))
end
-- Codepoints extracted from lucide-static's font/info.json (encodedCode field).
ICON = {
  PAPERCLIP        = _utf8(0xE12D),
  SEND             = _utf8(0xE152),
  SETTINGS         = _utf8(0xE154),
  HEART            = _utf8(0xE0F2),
  CHEVRON_DOWN     = _utf8(0xE06D),
  X                = _utf8(0xE1B2),
  PLUS             = _utf8(0xE13D),
  COPY             = _utf8(0xE09E),
  COPY_PLUS        = _utf8(0xE3FD),  -- Lucide copy-plus glyph; reads as "duplicate this row"
  TRASH            = _utf8(0xE18E),  -- Lucide trash-2 glyph; row-delete affordance
  INFO             = _utf8(0xE0F9),
  CHECK            = _utf8(0xE06C),
  BADGE_CHECK      = _utf8(0xE241),  -- Lucide badge-check glyph; model-picker recommended badge
  TRIANGLE_ALERT   = _utf8(0xE193),  -- Lucide triangle-alert / alert-triangle glyph; model-picker warning badge
  PLAY             = _utf8(0xE13C),
  ZAP              = _utf8(0xE1B4),
  CORNER_DOWN_LEFT = _utf8(0xE0A1),
  FILE             = _utf8(0xE0C0),
  SUN              = _utf8(0xE178),
  MOON             = _utf8(0xE11E),
  -- Credits-screen link-row glyphs (verified against lucide.ttf's
  -- Unicode cmap). Prefer these over hand-drawn arrows so the icon
  -- weight matches the rest of the V5 Lucide icons (gear, plus, sun,
  -- etc.) rather than standing out as a one-off line-draw.
  LINK             = _utf8(0xE102),
  MAIL             = _utf8(0xE10F),
  PHONE            = _utf8(0xE133),
  SAVE             = _utf8(0xE14D),  -- floppy-disk glyph, for Save buttons
  REDO_2           = _utf8(0xE2A0),  -- Lucide redo-2 glyph; used as Rescan affordance
  THUMBS_UP        = _utf8(0xE18A),  -- Helpful sentiment in feedback modal
  THUMBS_DOWN      = _utf8(0xE189),  -- Not-helpful sentiment in feedback modal
}

-- Load chat_font_idx (default 2 = Medium/14px).
prefs.chat_font_idx = _prefs_load_idx("chat_font_idx", 2, CFG.CHAT_FONT_SIZES)

-- Load reply_language_idx (default 1 = English) and migrate it to the stable
-- language_code preference. The visible row still renders as Chat Language
-- until baseline UI coverage exists for every public language.
prefs.reply_language_idx = _prefs_load_idx(
  "reply_language_idx", 1, CFG.REPLY_LANGUAGE_LABELS)
prefs.language_code = reaper.GetExtState(CFG.EXT_NS, "language_code")
if not (CFG.is_valid_language_code and CFG.is_valid_language_code(prefs.language_code)) then
  prefs.language_code = (CFG.language_code_for_legacy_idx
    and CFG.language_code_for_legacy_idx(prefs.reply_language_idx)) or "en"
end
prefs.reply_language_idx =
  (CFG.legacy_idx_for_language_code
    and CFG.legacy_idx_for_language_code(prefs.language_code))
  or prefs.reply_language_idx

-- MODELS.refresh: syncs the MODELS array with the active provider's model list,
-- loads the per-provider model_idx from ExtState, and invalidates the combo cache.
function MODELS.refresh()
  local p = PROVIDERS.active()
  -- Build the visible model list. For Gemini, hide paid-only models when the
  -- tier is known-free OR untested. Untested-as-free is the safer default:
  -- showing Pro on a free-tier account that just hasn't tier-tested yet
  -- means the user picks Pro, sends, and gets a confusing API error. The
  -- tier-test fires automatically right after a Google key save (see
  -- post_save_settle), so the nil window is short -- once it resolves,
  -- MODELS.refresh fires again and a paid user immediately sees the full
  -- list.
  local src = p.models
  if p.id == "google" and S.gemini_paid_tier ~= true then
    src = {}
    for _, m in ipairs(p.models) do
      if not m.paid_only then src[#src+1] = m end
    end
  end
  -- Copy into MODELS array slots; clear any stale extras. Use clear-then-
  -- fill instead of a single mixed loop, because writing nil to slots past
  -- #src leaves nil holes -- safe for direct index access but breaks any
  -- future `for i=1,#MODELS do` iterator (which stops at the first hole).
  for i = #MODELS, 1, -1 do MODELS[i] = nil end
  for i, m in ipairs(src) do MODELS[i] = m end
  -- Load per-provider model_idx.
  local key = "model_idx_" .. p.id
  local default_idx
  if p.id == "google" and S.gemini_paid_tier ~= true then
    default_idx = math_min(2, #src)  -- Flash (mid) to match paid-tier default
  else
    default_idx = p.default_model_idx or #src
  end
  prefs.model_idx = Store.config_model_idx(
    p, src, _prefs_load_idx(key, default_idx, src))
  -- Load per-(provider,model) thinking_idx via the shared helper so all
  -- the cascade rules (per-model -> model default -> provider default
  -- -> 1) live in one place.
  if p.thinking_levels then
    local active_m = MODELS[prefs.model_idx] or MODELS[1]
    prefs.thinking_idx = PROVIDERS.load_thinking_idx(p, active_m)
  else
    prefs.thinking_idx = 0  -- 0 = provider does not expose thinking
  end
end

function MODELS.active_id()
  local m = MODELS[prefs.model_idx] or MODELS[1]
  return m and m.id or PROVIDERS.active().models[1].id
end

function PROVIDERS.switch_to_model(provider_id, model_id)
  local prov_idx = PROVIDERS._by_id[provider_id or ""]
  local p_new = prov_idx and PROVIDERS[prov_idx] or nil
  if not p_new then return false, "Provider is not available." end

  local old_provider_idx = prefs.provider_idx
  local p_old = PROVIDERS.active()
  if p_old then
    if Store and Store.remember_model_idx then
      Store.remember_model_idx(p_old, MODELS, prefs.model_idx)
    end
    if p_old.thinking_levels and prefs.thinking_idx > 0 then
      local old_m = MODELS[prefs.model_idx] or MODELS[1]
      PROVIDERS.save_thinking_idx(p_old, old_m, prefs.thinking_idx)
    end
    if p_old.id == "google" then Net.gemini_cache_invalidate() end
  end

  prefs.provider_idx = prov_idx
  MODELS.refresh()

  local target_idx, target_model
  for i, m in ipairs(MODELS) do
    if m.id == model_id then
      target_idx, target_model = i, m
      break
    end
  end
  if not target_idx then
    prefs.provider_idx = old_provider_idx
    MODELS.refresh()
    S.api_key = S.api_key_map[PROVIDERS.active().id]
    if Store and Store.cleanup_config_extstate then
      Store.cleanup_config_extstate(Store.config_doc())
    end
    return false, "That model is not available for the current account tier."
  end

  prefs.model_idx = target_idx
  if p_new.thinking_levels then
    prefs.thinking_idx = PROVIDERS.load_thinking_idx(p_new, target_model)
  else
    prefs.thinking_idx = 0
  end
  if p_new.id == "google" then Net.gemini_cache_invalidate() end
  S.api_key = S.api_key_map[p_new.id]
  S.api_ref_message = nil
  for _, att in ipairs(S.attachments or {}) do
    att.cost = att.tokens * (target_model.price_in or 0) / 1000000
  end
  if Store and Store.save_config then Store.save_config() end
  return true
end

-- =============================================================================
-- API key loading
-- =============================================================================
-- The API key is stored in REAPER's ExtState (persisted in reaper-extstate.ini)
-- as an XOR-obfuscated hex string locked to this machine's install path.
-- On first launch with no key, a welcome message prompts the user to paste
-- their key directly into the chat. The key can be changed later via the
-- Settings button.
--
-- Install-moved detection: if the stored value decodes to something that
-- doesn't look like an API key, the install path has changed. Set a flag
-- so the UI can show a re-entry prompt with an explanation.
-- Load API keys for all providers from ExtState. Each provider's key is stored
-- under its own ExtState key (key_extstate field). The decoded key is validated
-- against provider format rules that are safe to enforce locally.
do
  for _, p in ipairs(PROVIDERS) do
    local stored = reaper.GetExtState(CFG.EXT_NS, p.key_extstate)
    if stored ~= "" then
      local decoded = Key.decode(stored)
      if decoded and #decoded >= p.key_min_len and not decoded:match("%s")
          and not Key.matches_excluded_prefix(decoded, p)
          and (p.key_prefix_warning_only
            or Key.matches_known_prefix(decoded, p)) then
        S.api_key_map[p.id] = decoded
      else
        -- Decode failed (magic prefix mismatch): install path has changed.
        -- Do NOT clear the stored blob -- restoring the original path will
        -- recover the key because the XOR anchor will match again.
        S.key_install_moved = true
      end
    end
  end
  -- Convenience alias: active provider's key.
  S.api_key = S.api_key_map[PROVIDERS.active().id]
  -- Load persisted Gemini tier (nil if never tested).
  S.gemini_paid_tier = Store.gemini_paid_tier()
  Store.ensure_usable_provider_selection(
    "the saved provider has no usable credentials")
  -- If tier is unknown but a Google key is configured, schedule an auto
  -- retest on the first loop tick. Net isn't defined yet at this point in
  -- script init, so we set a flag and let the main loop dispatch it once
  -- everything is wired up. Handles the common case where a previous test
  -- got an ambiguous response (503 UNAVAILABLE on Pro, transient network
  -- blip) -- restart picks up the retry without manual Test-API-Keys.
  if S.gemini_paid_tier == nil and S.api_key_map.google then
    S.gemini_auto_retest_pending = true
  end
  -- If force-cold-cache is persisted on from a prior session, mint a fresh
  -- stamp for this session. The stamp lives per script lifetime, so
  -- reloading = new cold start even if the pref stayed on.
  if prefs.test_force_cold_cache then
    S.cold_cache_stamp = tostring(reaper.time_precise())
  end
end

-- Must run AFTER the ExtState tier/key load above: refresh()'s free-
-- tier filter reads S.gemini_paid_tier, so calling it earlier would
-- leave paid_only models (Gemini Pro) visible to free-tier users.
MODELS.refresh()

-- Determine the initial first-run screen. Order: TOS first, then API key,
-- then main UI. Show the first-run API key screen only if no usable provider
-- exists: a built-in with a saved key OR a registered custom provider.
--
-- The visibility scan lives inside a do-block so its locals don't count
-- against the main chunk's 200-local limit (already very near the cap).
do
  local has_usable = Store.has_usable_provider()
  if not api_keys.tos_is_accepted() then
    api_keys.screen = "tos"
  elseif not has_usable then
    api_keys.screen = "first_run"
  else
    api_keys.screen = nil
  end
end

-- =============================================================================
-- Script state
-- =============================================================================
-- S.history: API conversation pairs {role, content}.
--   Content stores the user's prompt text (prefixed with "USER REQUEST:\n") and
--   optionally the API reference, but NEVER the session snapshot. The snapshot is
--   injected at send time by Net.build_body() so only the current turn gets fresh
--   project state. Only the most recent CFG.MAX_HISTORY_TURNS entries are sent to the
--   API (via Net.trimmed_history); older entries are kept for display only.
--
-- S.display_messages: UI-only list for rendering the chat. Each entry:
--   role             (string)  "user" or "assistant"
--   content          (string)  text shown in the chat (bare prompt for user, response for assistant)
--   hidden           (bool)    keep turn bookkeeping but skip visible chat rendering
--   code_block       (string)  extracted Lua code from ```lua fences, or nil
--   ctx_label        (string)  context info for Show Details: "snapshot", "snapshot + api_ref",
--                              "snapshot + docs", "error", "timeout"
--   tok_in           (number)  total input tokens for this exchange (set on response)
--   tok_out          (number)  output tokens for this exchange (set on response)
--   tok_cache_read   (number)  input tokens served from cache (subset of tok_in)
--   tok_cache_create (number)  input tokens written to cache this call (subset of tok_in)
--   cost             (number)  estimated USD cost for this exchange (set on response)
--   model_label      (string)  model label captured at send time
--   link_url         (string)  optional clickable URL rendered after content
--   link_label       (string)  display text for the link (defaults to link_url if omitted)
--   storage_note     (string)  optional dim secondary line shown after the link (used on key-entry messages)

-- If the REAPER install path changed since the key was last saved, the
-- key can't be decoded and the user must re-enter it. Surface as an
-- inline error on the API key screen.
if S.key_install_moved then
  api_keys.key_error = RA.t("settings.api_key.error.install_moved_v2", nil,
    "Your REAPER install location changed. Because the reversible key "
    .. "obfuscation uses that path, the saved value cannot be decoded here. "
    .. "Paste the key again to continue. This path binding prevents casual "
    .. "copying; it is not encryption.")
end


-- =============================================================================
-- Utility: MODELS.calc_cost
-- =============================================================================
-- Returns the estimated USD cost for one API exchange given token counts and
-- a model entry from the MODELS table. Prices are per million tokens.
-- tok_in_base: non-cached input tokens; tok_cache_r: cache-hit read tokens;
-- tok_cache_w: cache-write tokens; tok_out: output tokens.
function MODELS.calc_cost(model_entry, tok_in_base, tok_cache_r, tok_cache_w, tok_out)
  if not model_entry then return 0 end
  local M = 1000000
  local base = tonumber(tok_in_base) or 0
  local read = tonumber(tok_cache_r) or 0
  local write = tonumber(tok_cache_w) or 0
  local output = tonumber(tok_out) or 0
  local input_mult, output_mult = 1, 1
  local long_threshold = tonumber(model_entry.long_context_threshold)
  if long_threshold and (base + read + write) > long_threshold then
    input_mult = tonumber(model_entry.long_context_input_multiplier) or 1
    output_mult = tonumber(model_entry.long_context_output_multiplier) or 1
  end
  return ((base  * (model_entry.price_in      or 0)
         + read  * (model_entry.price_cache_r or 0)
         + write * (model_entry.price_cache_w or 0)) * input_mult
         + output * (model_entry.price_out or 0) * output_mult) / M
end

-- MODELS.format_cost(usd) -> string like "$0.000123" or "$1.23"
-- Uses 6 significant digits for sub-cent amounts, 4 for larger values.
function MODELS.format_cost(usd)
  if usd == 0 then return "$0.000000" end
  if usd < 0.01 then
    return str_format("$%.6f", usd)
  elseif usd < 1 then
    return str_format("$%.4f", usd)
  else
    return str_format("$%.2f", usd)
  end
end

