-- Severity badges for the most discouraging provider/model/thinking combos.
-- Keep this list intentionally short: the warning icon should mean "think hard
-- before choosing this", not merely "not the default". These keys mirror
-- UI.COMBO_HINTS so the row tooltip and the active-combo hint remain the
-- source of the explanatory copy.
UI.COMBO_TONES = {
  anthropic = {
    ["claude-sonnet-5"] = {
      high = "warn",
    },
  },
  google = {
    ["gemini-3.1-flash-lite"] = {
      HIGH = "warn",
    },
    ["gemini-3.1-pro-preview"] = {
      LOW = "warn",
      MEDIUM = "warn",
      HIGH = "warn",
    },
  },
  deepseek = {},
}

-- Look up the explainer line for the current (provider, model, thinking) pick.
-- Returns the string from UI.COMBO_HINTS or nil if any layer is absent (custom
-- provider, missing thinking_level, uncovered combo). Callers render nothing
-- when nil.
function UI.combo_hint(provider, model, thinking_level)
  if not (provider and model) then return nil end
  if provider.is_custom then return nil end
  local p_tbl = UI.COMBO_HINTS[provider.id];  if not p_tbl then return nil end
  local m_tbl = p_tbl[model.id];              if not m_tbl then return nil end
  local key = thinking_level and thinking_level.value
  if not key then return nil end
  local fallback = m_tbl[key]
  if not fallback then return nil end
  if I18N and I18N.t then
    local i18n_key = "mode.combo_hint." .. tostring(provider.id)
      .. "." .. tostring(model.id) .. "." .. tostring(key)
    local text = I18N.t(i18n_key)
    if type(text) == "string" and text ~= "" and text ~= i18n_key then
      return text
    end
  end
  return fallback
end

-- Look up the visual tone for the current (provider, model, thinking) pick.
-- Returns "warn" for combos that should carry the triangle-alert badge, or nil
-- for normal rows. Custom providers are skipped because their model/tuning
-- semantics are user-defined.
function UI.combo_tone(provider, model, thinking_level)
  if not (provider and model) then return nil end
  if provider.is_custom then return nil end
  local p_tbl = UI.COMBO_TONES[provider.id]; if not p_tbl then return nil end
  local m_tbl = p_tbl[model.id];             if not m_tbl then return nil end
  local key = thinking_level and thinking_level.value
  if not key then return nil end
  return m_tbl[key]
end


-- Floating toast: a top-level rounded bubble near the bottom-center of the
-- ReaAssist window. Draws its OWN window on top of whatever's below, so it's
-- visible regardless of scroll position or which settings page is current.
-- Animation: 180ms fade-in, 1.6s hold, 500ms fade-out (2.3s total).
-- Sticky=true skips the hold/fade-out and keeps the toast visible until the
-- caller replaces it (by firing another show_float_toast) or clears it
-- (S.float_toast = nil). Used by the Settings "Check for Updates" button
-- to show "Checking for updates..." throughout the async manifest fetch.
function UI.show_float_toast(text, kind, sticky)
  local now = reaper.time_precise()
  local FADE_IN, HOLD, FADE_OUT = 0.18, 1.6, 0.5
  S.float_toast = {
    text            = text,
    kind            = kind or "ok",  -- "ok" (green accent) | "err" (red accent)
    sticky          = sticky == true,
    start_at        = now,
    fade_in_end_at  = now + FADE_IN,
    hold_end_at     = now + FADE_IN + HOLD,
    fade_out_end_at = now + FADE_IN + HOLD + FADE_OUT,
    fade_in_s       = FADE_IN,
    fade_out_s      = FADE_OUT,
  }
end
if Store and Store.flush_user_notice then Store.flush_user_notice() end

-- =============================================================================
-- Utility: UI.open_url
-- =============================================================================
-- Opens a URL in the user's default browser. Tries SWS CF_ShellExecute first
-- (available when the SWS extension is installed), then falls back to
-- platform-native commands.
function UI._safe_shell_url(url)
  local safe = tostring(url or ""):gsub("[^%w%-%.%_%~%:%/%?%#%[%]%@%!%&%*%+%,%;%=%{%}%%]", "")
  -- Keep real percent-encoded octets (%20, %7B, etc.) but drop stray percent
  -- signs so Windows cmd fallback cannot expand %ENV_VAR% after sanitization.
  safe = safe:gsub("%%(%x%x)", "\31%1")
  safe = safe:gsub("%%", "")
  safe = safe:gsub("\31(%x%x)", "%%%1")
  return safe
end

function UI.open_url(url)
  url = tostring(url or "")
  -- Only allow http(s) / mailto: / tel: URLs. Reject file://, javascript:,
  -- data:, and other schemes that could execute local code or inject
  -- content. mailto: + tel: are safe schemes handled by the OS shell
  -- (mail client / dialer) and are used by the Credits screen's contact
  -- links.
  if not (url:match("^https?://")
       or url:match("^mailto:")
       or url:match("^tel:")) then
    return false
  end
  if reaper.CF_ShellExecute then
    local ok, result = pcall(reaper.CF_ShellExecute, url)
    return ok and result ~= false
  else
    -- Sanitise: strip any characters that could enable shell injection.
    -- Excluded: $, (, ), `, ", \, ', non-printable chars, and stray percent.
    -- $() = command substitution on Unix; %VAR% = expansion on Windows;
    -- backtick/backslash/quotes could break quoting boundaries.
    local safe = UI._safe_shell_url(url)
    if safe == "" then return false end
    local result, _, code
    if RA.IS_WINDOWS then
      result, _, code = os.execute('start "" "' .. safe .. '"')
    elseif RA.IS_MACOS then
      -- Single quotes disable all shell interpretation (no $(), no \, no `).
      result, _, code = os.execute(
        "open '" .. safe .. "' >/dev/null 2>&1 &")
    else
      -- Single quotes disable all shell interpretation (no $(), no \, no `).
      result, _, code = os.execute(
        "xdg-open '" .. safe .. "' >/dev/null 2>&1 &")
    end
    return result == true or result == 0 or code == 0
  end
end

function UI.open_path(path)
  path = tostring(path or "")
  if path == "" or path:find("[%z\r\n]") then return false end
  if reaper.CF_ShellExecute then
    local ok, result = pcall(reaper.CF_ShellExecute, path)
    return ok and result ~= false
  end

  local result, _, code
  if RA.IS_WINDOWS then
    -- cmd.exe expands %VAR% even inside double quotes, and quotes cannot be
    -- escaped portably in the `start "" "<path>"` form. A path containing % or "
    -- would silently open the wrong location, so refuse it rather than mangle it;
    -- CF_ShellExecute (checked above) handles such paths safely when present.
    if path:find('[%"%%]') then return false end
    result, _, code = os.execute('start "" "' .. path .. '"')
  elseif RA.IS_MACOS then
    result, _, code = os.execute(
      "open " .. Shell.sh_quote(path) .. " >/dev/null 2>&1 &")
  else
    result, _, code = os.execute(
      "xdg-open " .. Shell.sh_quote(path) .. " >/dev/null 2>&1 &")
  end
  return result == true or result == 0 or code == 0
end

-- =============================================================================
-- Attachment system (base64, file I/O, screenshot, clipboard, attach helpers)
-- =============================================================================
-- Wrapped in do...end to keep internal helpers out of the main-chunk local
-- count (Lua 5.x limit: 200 locals per function/chunk).
Attach = {}
do -- attachment system scope

local b64_chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/"
Attach.base64_encode = function(data, start_pos, end_pos)
  if not data or #data == 0 then return "" end
  start_pos = start_pos or 1
  end_pos   = end_pos   or #data
  local out = {}
  local i = start_pos
  while i <= end_pos - 2 do
    local a, b, c = str_byte(data, i, i + 2)
    local n = a * 65536 + b * 256 + c
    out[#out+1] = str_sub(b64_chars, math_floor(n / 262144) + 1, math_floor(n / 262144) + 1)
    out[#out+1] = str_sub(b64_chars, math_floor(n / 4096) % 64 + 1, math_floor(n / 4096) % 64 + 1)
    out[#out+1] = str_sub(b64_chars, math_floor(n / 64) % 64 + 1, math_floor(n / 64) % 64 + 1)
    out[#out+1] = str_sub(b64_chars, n % 64 + 1, n % 64 + 1)
    i = i + 3
  end
  local remain = end_pos - i + 1
  if remain == 2 then
    local a, b = str_byte(data, i, i + 1)
    local n = a * 65536 + b * 256
    out[#out+1] = str_sub(b64_chars, math_floor(n / 262144) + 1, math_floor(n / 262144) + 1)
    out[#out+1] = str_sub(b64_chars, math_floor(n / 4096) % 64 + 1, math_floor(n / 4096) % 64 + 1)
    out[#out+1] = str_sub(b64_chars, math_floor(n / 64) % 64 + 1, math_floor(n / 64) % 64 + 1)
    out[#out+1] = "="
  elseif remain == 1 then
    local a = str_byte(data, i)
    local n = a * 65536
    out[#out+1] = str_sub(b64_chars, math_floor(n / 262144) + 1, math_floor(n / 262144) + 1)
    out[#out+1] = str_sub(b64_chars, math_floor(n / 4096) % 64 + 1, math_floor(n / 4096) % 64 + 1)
    out[#out+1] = "=="
  end
  return tbl_concat(out)
end

-- Chunked base64 encoder for large attachments. Pure Lua base64 over a 10MB
-- file is ~13M operations and freezes the UI thread for hundreds of ms in a
-- single synchronous pass -- catastrophic for low-latency audio. Instead we
-- pre-encode at attach time, processing one ~256KB chunk per main-loop frame
-- via Attach.pump_encoding(). The Send button stays disabled until every
-- binary attachment has finished encoding.
--
-- Chunk size is 3-byte aligned (every base64 group is 3 input bytes -> 4
-- output chars) so each chunk produces padding-free output that can be
-- concatenated directly. The very last chunk may include 1-2 leftover bytes
-- and gets the standard '='/'==' padding from base64_encode.
local B64_CHUNK_BYTES = math_floor(256 * 1024 / 3) * 3  -- ~256KB, 3-aligned

-- Attach.pump_encoding() -- called once per main-loop frame.
-- Encodes one chunk for the first attachment that still needs encoding.
-- Returns true while any work remains, false when all attachments are done.
Attach.pump_encoding = function()
  for _, att in ipairs(S.attachments) do
    if att.kind ~= "text" and not att.b64 then
      if not att.b64_pos then
        att.b64_pos   = 1
        att.b64_parts = {}
      end
      local len       = #att.data
      local remaining = len - att.b64_pos + 1
      local take      = (remaining <= B64_CHUNK_BYTES) and remaining or B64_CHUNK_BYTES
      att.b64_parts[#att.b64_parts+1] = Attach.base64_encode(att.data, att.b64_pos, att.b64_pos + take - 1)
      att.b64_pos = att.b64_pos + take
      if att.b64_pos > len then
        -- Encoding complete: flatten to a single string and free the source
        -- bytes so we don't carry around two copies of a 10MB file in memory.
        att.b64       = tbl_concat(att.b64_parts)
        att.b64_parts = nil
        att.b64_pos   = nil
        att.data      = nil
      end
      return true  -- one chunk per frame is enough
    end
  end
  return false
end

-- Attach.all_encoded() -- true when every binary attachment has finished
-- base64 encoding. Used by the Send button can_send check to block sending
-- until pre-encoding completes.
Attach.all_encoded = function()
  for _, att in ipairs(S.attachments) do
    if att.kind ~= "text" and not att.b64 then return false end
  end
  return true
end

-- Attach.encoding_progress() -> {bytes_done, bytes_total} or nil if no work
-- pending. Used by the attachment strip to draw a progress indicator.
Attach.encoding_progress = function()
  local done, total = 0, 0
  local any_pending = false
  for _, att in ipairs(S.attachments) do
    if att.kind ~= "text" then
      if att.b64 then
        -- Already encoded -- we no longer have att.data, but we tracked the
        -- byte count by counting base64 chars * 3 / 4 (close enough for the
        -- progress display).
        local approx_bytes = math_floor(#att.b64 * 3 / 4)
        done  = done  + approx_bytes
        total = total + approx_bytes
      else
        any_pending = true
        local len = #att.data
        total = total + len
        done  = done  + (att.b64_pos or 1) - 1
      end
    end
  end
  if not any_pending then return nil end
  return done, total
end

-- =============================================================================
-- Attachment utilities
-- =============================================================================
-- Supported image MIME types for the AI provider vision endpoints.
local IMAGE_EXTENSIONS = {
  jpg = "image/jpeg", jpeg = "image/jpeg", png = "image/png",
  gif = "image/gif", webp = "image/webp",
}
-- Text file extensions that are read as UTF-8 text and sent as text blocks.
local TEXT_EXTENSIONS = {
  lua = true, txt = true, csv = true, py = true, js = true, ts = true,
  json = true, xml = true, html = true, css = true, md = true, yaml = true,
  yml = true, ini = true, cfg = true, conf = true, sh = true, bat = true,
  log = true, rpp = true, reascript = true, c = true, cpp = true, h = true,
  jsfx = true, ["jsfx-inc"] = true, eel = true,
}

-- get_file_extension(path) -> lowercase extension without dot, or ""
local function get_file_extension(path)
  local ext = path:match("%.([^%.]+)$")
  return ext and ext:lower() or ""
end

-- get_filename(path) -> filename with extension
local function get_filename(path)
  return path:match("[^\\/]+$") or path
end

-- Maximum size (bytes) for text attachments. Files larger than this are
-- rejected to avoid blowing up token budgets and provider context windows.
local TEXT_ATTACH_MAX_BYTES = 200 * 1024  -- 200 KB

-- is_likely_binary(path) -> true if the file appears to be binary.
-- Reads the first 512 bytes and checks for null bytes, which are absent
-- in well-formed UTF-8 / ASCII text but common in binary formats.
local function is_likely_binary(path)
  local f = io.open(path, "rb")
  if not f then return false end
  local head = f:read(512)
  f:close()
  if not head then return false end
  return head:find("\0") ~= nil
end

-- classify_file(path) -> "image", "pdf", "text", or "unsupported" + media_type
-- Files with a recognised text extension, unknown extension, or no extension
-- are treated as text only when the binary sniff passes. Binary-looking files
-- stay unsupported so they are not shoved into the prompt as garbage.
local function classify_file(path)
  local ext = get_file_extension(path)
  if IMAGE_EXTENSIONS[ext] then return "image", IMAGE_EXTENSIONS[ext] end
  if ext == "pdf" then return "pdf", "application/pdf" end
  if TEXT_EXTENSIONS[ext] then return "text", nil end
  -- Unknown/extensionless: attempt a binary sniff. If the file looks like text,
  -- allow it; otherwise reject it as unsupported.
  if not is_likely_binary(path) then return "text", nil end
  return "unsupported", nil
end

-- read_file_binary(path) -> data string or nil, error
local function read_file_binary(path)
  local f, err = io.open(path, "rb")
  if not f then return nil, err end
  local data = f:read("*a")
  f:close()
  return data
end

-- read_file_text(path) -> text string or nil, error
local function read_file_text(path)
  local f, err = io.open(path, "r")
  if not f then return nil, err end
  local text = f:read("*a")
  f:close()
  return text
end

-- read_image_dimensions(data, media_type) -> width, height or nil, nil
-- Reads pixel dimensions from PNG/JPEG/GIF/WebP file headers without
-- decoding the full image. Returns nil if the format is unrecognized.
local function read_image_dimensions(data, media_type)
  if not data or #data < 24 then return nil, nil end

  -- PNG: bytes 1-8 are signature, IHDR chunk starts at byte 9.
  -- Width at bytes 17-20, height at bytes 21-24 (big-endian uint32).
  if media_type == "image/png" then
    if str_sub(data, 1, 4) == "\137PNG" then
      local w = str_byte(data,17)*16777216 + str_byte(data,18)*65536
             + str_byte(data,19)*256 + str_byte(data,20)
      local h = str_byte(data,21)*16777216 + str_byte(data,22)*65536
             + str_byte(data,23)*256 + str_byte(data,24)
      if w > 0 and h > 0 then return w, h end
    end
  end

  -- JPEG: scan for SOF0/SOF2 marker (0xFF 0xC0 or 0xFF 0xC2).
  -- Height at marker+5 (2 bytes), width at marker+7 (2 bytes), big-endian.
  if media_type == "image/jpeg" then
    local pos = 1
    local len = #data
    while pos < len - 10 do
      if str_byte(data, pos) == 0xFF then
        local marker = str_byte(data, pos + 1)
        if marker == 0xC0 or marker == 0xC2 then
          local h = str_byte(data, pos+5)*256 + str_byte(data, pos+6)
          local w = str_byte(data, pos+7)*256 + str_byte(data, pos+8)
          if w > 0 and h > 0 then return w, h end
        end
        -- Skip to next marker using segment length
        if marker ~= 0x00 and marker ~= 0xFF and marker ~= 0xD8 and marker ~= 0xD9 then
          if pos + 3 <= len then
            local seg_len = str_byte(data, pos+2)*256 + str_byte(data, pos+3)
            -- A valid JPEG segment includes the 2-byte length field
            -- itself; seg_len < 2 is malformed and would either loop
            -- forever (seg_len = 0) or rewind into the marker we just
            -- read. Bail rather than risk the loop on hostile input.
            if seg_len < 2 then break end
            pos = pos + 2 + seg_len
          else
            break
          end
        else
          pos = pos + 1
        end
      else
        pos = pos + 1
      end
    end
  end

  -- GIF: width at bytes 7-8, height at bytes 9-10 (little-endian uint16).
  if media_type == "image/gif" then
    if str_sub(data, 1, 3) == "GIF" then
      local w = str_byte(data,7) + str_byte(data,8)*256
      local h = str_byte(data,9) + str_byte(data,10)*256
      if w > 0 and h > 0 then return w, h end
    end
  end

  -- WebP: "RIFF" at 1-4, "WEBP" at 9-12. VP8 chunk has dimensions.
  if media_type == "image/webp" then
    if str_sub(data, 1, 4) == "RIFF" and str_sub(data, 9, 12) == "WEBP" then
      local chunk = str_sub(data, 13, 16)
      if chunk == "VP8 " and #data >= 30 then
        -- Lossy VP8: width at 27-28, height at 29-30 (little-endian, masked)
        local w = (str_byte(data,27) + str_byte(data,28)*256) % 16384
        local h = (str_byte(data,29) + str_byte(data,30)*256) % 16384
        if w > 0 and h > 0 then return w, h end
      elseif chunk == "VP8L" and #data >= 26 then
        -- Lossless VP8L: packed bits at byte 22-25
        local b1,b2,b3,b4 = str_byte(data,22,25)
        local w = (b1 + (b2 % 64) * 256) + 1
        local h = (math_floor(b2/64) + b3*4 + (b4 % 16)*1024) + 1
        if w > 0 and h > 0 then return w, h end
      end
    end
  end

  return nil, nil
end

-- Estimate token cost for an attachment. Returns estimated tokens (number).
-- Images: based on pixel dimensions (tokens ~ width*height/750).
-- PDFs: ~1500 tokens per page; estimated from file size (~50KB per page).
-- Text: ~4 chars per token.
local function estimate_attachment_tokens(attachment)
  if attachment.kind == "image" then
    -- Try to read actual dimensions from the image header.
    -- Claude resizes images so the longest side is at most 1568px before
    -- calculating tokens. Apply the same scaling here for accuracy.
    local w, h = read_image_dimensions(attachment.data, attachment.media_type)
    if w and h then
      local MAX_SIDE = 1568
      if w > MAX_SIDE or h > MAX_SIDE then
        local scale = MAX_SIDE / math_max(w, h)
        w = math_floor(w * scale)
        h = math_floor(h * scale)
      end
      return math_max(85, math_floor(w * h / 750))
    end
    -- Fallback: rough estimate from file size (conservative 2 bytes/pixel
    -- for PNG screenshots which compress heavily).
    local pixels = #attachment.data / 2
    return math_max(85, math_floor(pixels / 750))
  elseif attachment.kind == "pdf" then
    local pages = math_max(1, math_floor(#attachment.data / 50000))
    return pages * 1500
  elseif attachment.kind == "text" then
    return math_floor(#attachment.data / 4)
  end
  return 0
end

-- Estimate USD cost for attachment tokens given the current model.
local function estimate_attachment_cost(tokens)
  local model = MODELS[prefs.model_idx]
  if not model then return 0 end
  return tokens * (model.price_in or 0) / 1000000
end

-- Max attachment size (bytes) -- warn above 5MB, reject above 10MB.
-- Claude resizes images internally, so >10MB rarely adds value.
local ATTACH_WARN_BYTES  = 5 * 1024 * 1024
local ATTACH_MAX_BYTES   = 10 * 1024 * 1024
local ATTACH_MAX_COUNT   = 10  -- max attachments per message

-- =============================================================================
-- Screenshot capture
-- =============================================================================
-- Captures the screen to a temporary PNG file for use as an attachment.
-- Windows: uses PowerShell + .NET GDI to capture the REAPER main window
--   region specifically (requires js_ReaScriptAPI for JS_Window_GetRect;
--   falls back to full primary screen if the extension is not installed).
-- macOS: uses the built-in screencapture utility (silent, no shutter sound).
--   This captures all screens, not just the REAPER window -- macOS does not
--   expose a simple per-window capture via shell without extra dependencies.
-- Linux: tries common desktop capture tools (grim, gnome-screenshot,
--   spectacle, scrot, ImageMagick import), capturing the full screen.
-- Returns the PNG file path on success, or nil + error string.
local function capture_screenshot()
  local png_path = tmp.screenshot

  if RA.IS_WINDOWS then
    local hwnd = reaper.GetMainHwnd()
    if not hwnd then return nil, "Could not find REAPER main window." end

    local ps_script
    if reaper.JS_Window_GetRect then
      local _, left, top, right, bottom = reaper.JS_Window_GetRect(hwnd)
      local w = right - left
      local h = bottom - top
      if w <= 0 or h <= 0 then return nil, "Invalid window dimensions." end
      -- Minimized REAPER on Windows reports rect coords near (-32000,
      -- -32000) -- the standard ShowWindow(SW_MINIMIZE) sentinel. The
      -- positive w/h above passes the previous guard, but CopyFromScreen
      -- from those coordinates produces a uniformly black bitmap that
      -- attaches as a useless screenshot. Treat any far-off-screen
      -- origin as minimized/hidden and refuse the capture so the user
      -- gets a clear error instead of a black image.
      if left < -10000 or top < -10000 then
        return nil, "REAPER window is minimized or off-screen. "
          .. "Restore it before taking a screenshot."
      end
      ps_script = str_format(
        "Add-Type -AssemblyName System.Drawing; "
        .. "$bmp = New-Object System.Drawing.Bitmap(%d, %d); "
        .. "$g = [System.Drawing.Graphics]::FromImage($bmp); "
        .. "$g.CopyFromScreen(%d, %d, 0, 0, $bmp.Size); "
        .. "$g.Dispose(); "
        .. "$bmp.Save('%s', [System.Drawing.Imaging.ImageFormat]::Png); "
        .. "$bmp.Dispose(); "
        .. "Write-Output 'OK'",
        w, h, left, top, png_path:gsub("'", "''"))
    else
      ps_script =
        "Add-Type -AssemblyName System.Drawing; "
        .. "Add-Type -AssemblyName System.Windows.Forms; "
        .. "$bounds = [System.Windows.Forms.Screen]::PrimaryScreen.Bounds; "
        .. "$bmp = New-Object System.Drawing.Bitmap($bounds.Width, $bounds.Height); "
        .. "$g = [System.Drawing.Graphics]::FromImage($bmp); "
        .. "$g.CopyFromScreen($bounds.Location, [System.Drawing.Point]::Empty, $bounds.Size); "
        .. "$g.Dispose(); "
        .. "$bmp.Save('" .. png_path:gsub("'", "''") .. "', "
        .. "[System.Drawing.Imaging.ImageFormat]::Png); "
        .. "$bmp.Dispose(); "
        .. "Write-Output 'OK'"
    end

    local ps_cmd = 'powershell -NoProfile -WindowStyle Hidden -Command "' .. ps_script .. '"'
    local result = reaper.ExecProcess(ps_cmd, 10000)
    if not result or not result:match("OK") then
      os.remove(png_path)
      return nil, "Screenshot capture failed. PowerShell returned: "
        .. tostring(result and result:sub(1, 200) or "nil")
    end

    local f = io.open(png_path, "rb")
    if f then
      local size = f:seek("end")
      f:close()
      if size and size > 0 then
        return png_path
      end
    end
    os.remove(png_path)
    return nil, "Screenshot produced an empty file."

  elseif RA.IS_MACOS then
    -- screencapture -x: silent (no shutter sound). Captures all screens.
    -- Absolute path because REAPER's os.execute / ExecProcess on some
    -- macOS configs (notably Tahoe) doesn't reliably resolve PATH-based
    -- binaries; mirrors the /usr/bin/curl pattern in the installer.
    local sq_path = "'" .. png_path:gsub("'", "'\\''") .. "'"
    local ok, _, code = os.execute("/usr/sbin/screencapture -x " .. sq_path)
    if ok then
      local f = io.open(png_path, "rb")
      if f then
        local size = f:seek("end")
        f:close()
        if size and size > 0 then return png_path end
      end
    end
    os.remove(png_path)
    -- Surface the actionable cause via a modal popup. Since macOS 10.15,
    -- screencapture from a child process is denied when the parent app
    -- (REAPER) lacks Screen Recording permission -- with no Lua-level
    -- error, the file just never appears or comes back empty. The
    -- transient inline error in the attachment row is too short to fit
    -- the recovery steps, so use reaper.MB to deliver them.
    reaper.MB(
      RA.t("attach.screenshot.macos_permission_popup", {
        code = tostring(code or "?"),
      }, "Screenshot capture failed (exit " .. tostring(code or "?") .. ").\n\n"
        .. "On macOS this usually means REAPER does not have Screen Recording "
        .. "permission. To grant it:\n\n"
        .. "1. Open System Settings > Privacy & Security > Screen Recording.\n"
        .. "2. Enable REAPER in the list.\n"
        .. "3. Quit and reopen REAPER (macOS requires this before the new "
        .. "permission takes effect).\n"
        .. "4. Try the screenshot attachment again.\n\n"
        .. "On macOS Sequoia / Tahoe you may also see a one-time \"bypass "
        .. "the system private window picker\" prompt the first time the "
        .. "capture runs -- click Allow."),
      "ReaAssist", 0)
    return nil, RA.t("attach.error.screenshot_failed_popup", nil,
      "Screenshot capture failed (see popup for details).")
  elseif RA.IS_LINUX then
    local q_path = Shell.sh_quote(png_path)
    local cmds = {
      "command -v grim >/dev/null 2>&1 && grim " .. q_path,
      "command -v gnome-screenshot >/dev/null 2>&1 && gnome-screenshot -f " .. q_path,
      "command -v spectacle >/dev/null 2>&1 && spectacle -b -n -o " .. q_path,
      "command -v scrot >/dev/null 2>&1 && scrot " .. q_path,
      "command -v import >/dev/null 2>&1 && import -window root " .. q_path,
    }
    for _, cmd in ipairs(cmds) do
      os.remove(png_path)
      local ok = os.execute(cmd)
      if ok then
        local f = io.open(png_path, "rb")
        if f then
          local size = f:seek("end")
          f:close()
          if size and size > 0 then return png_path end
        end
      end
    end
    os.remove(png_path)
    return nil, RA.t("attach.error.screenshot_linux_unsupported", nil,
      "Screenshot capture on Linux needs grim, gnome-screenshot, spectacle, "
      .. "scrot, or ImageMagick import.")
  end

  return nil, RA.t("attach.error.screenshot_linux_unsupported", nil,
    "Screenshot capture is not available on this platform.")
end

-- =============================================================================
-- Clipboard image paste
-- =============================================================================
-- Checks if the clipboard contains an image and returns it as a PNG file path.
-- Windows: uses PowerShell with .NET to read the clipboard.
-- macOS: uses osascript to read clipboard image data and write it as PNG.
-- Linux: tries image/png clipboard targets via wl-paste (Wayland) or xclip.
local function get_clipboard_image()
  local png_path = tmp.clipboard

  if RA.IS_WINDOWS then
    local ps_cmd = 'powershell -NoProfile -WindowStyle Hidden -Command "'
      .. "Add-Type -AssemblyName System.Windows.Forms; "
      .. "Add-Type -AssemblyName System.Drawing; "
      .. "$img = [System.Windows.Forms.Clipboard]::GetImage(); "
      .. "if ($img -ne $null) { "
      .. "$img.Save('" .. png_path:gsub("'", "''") .. "', "
      .. "[System.Drawing.Imaging.ImageFormat]::Png); "
      .. "Write-Output 'OK' "
      .. '} else { Write-Output \'EMPTY\' }"'

    local result = reaper.ExecProcess(ps_cmd, 5000)
    if result and result:match("OK") then
      local f = io.open(png_path, "rb")
      if f then
        local size = f:seek("end")
        f:close()
        if size and size > 0 then return png_path end
      end
    end
    os.remove(png_path)
    return nil

  elseif RA.IS_MACOS then
    -- Use osascript to grab clipboard image data as PNG and write to file.
    local sq_path = png_path:gsub("'", "'\\''")
    local cmd = "osascript -e '"
      .. 'try\n'
      .. '  set imgData to the clipboard as «class PNGf»\n'
      .. '  set fp to open for access POSIX file "' .. sq_path .. '" with write permission\n'
      .. '  set eof fp to 0\n'
      .. '  write imgData to fp\n'
      .. '  close access fp\n'
      .. '  return "OK"\n'
      .. 'on error\n'
      .. '  return "EMPTY"\n'
      .. "end try'"
    local handle = io.popen(cmd)
    if handle then
      local result = handle:read("*a")
      handle:close()
      if result and result:match("OK") then
        local f = io.open(png_path, "rb")
        if f then
          local size = f:seek("end")
          f:close()
          if size and size > 0 then return png_path end
        end
      end
    end
    os.remove(png_path)
    return nil
  elseif RA.IS_LINUX then
    local q_path = Shell.sh_quote(png_path)
    local cmds = {
      "command -v wl-paste >/dev/null 2>&1 && wl-paste --type image/png > " .. q_path,
      "command -v xclip >/dev/null 2>&1 && xclip -selection clipboard -t image/png -o > " .. q_path,
    }
    for _, cmd in ipairs(cmds) do
      os.remove(png_path)
      local ok = os.execute(cmd)
      if ok then
        local f = io.open(png_path, "rb")
        if f then
          local size = f:seek("end")
          f:close()
          if size and size > 0 then return png_path end
        end
      end
    end
    os.remove(png_path)
    return nil
  end

  return nil
end

-- Attach.file(path) -> true on success, false + sets S.attach_error on failure.
-- Reads the file, classifies it, estimates cost, and adds to the queue.
Attach.file = function(path)
  if #S.attachments >= ATTACH_MAX_COUNT then
    S.attach_error = (RA and RA.t and RA.t("attach.error.max_count",
      { count = ATTACH_MAX_COUNT },
      str_format("Maximum %d attachments per message.", ATTACH_MAX_COUNT)))
      or str_format("Maximum %d attachments per message.", ATTACH_MAX_COUNT)
    S.attach_error_time = time_precise()
    return false
  end

  local kind, media_type = classify_file(path)

  if kind == "unsupported" then
    local ext = get_file_extension(path)
    local ext_text = ext ~= "" and (" (." .. ext .. ")") or ""
    S.attach_error = (RA and RA.t and RA.t("attach.error.unsupported_type",
      { ext = ext_text },
      str_format("Unsupported file type%s. Supported: images, PDFs, and common text formats.",
        ext ~= "" and (" (." .. ext .. ")") or "")))
      or str_format("Unsupported file type%s. Supported: images, PDFs, and common text formats.",
        ext ~= "" and (" (." .. ext .. ")") or "")
    S.attach_error_time = time_precise()
    return false
  end

  local data, err
  if kind == "text" then
    data, err = read_file_text(path)
  else
    data, err = read_file_binary(path)
  end

  if not data then
    S.attach_error = (RA and RA.t and RA.t("attach.error.read_failed",
      { error = tostring(err) }, "Could not read file: " .. tostring(err)))
      or ("Could not read file: " .. tostring(err))
    S.attach_error_time = time_precise()
    return false
  end

  -- Text-specific size cap: prevents token budget blow-ups from large logs,
  -- data files, etc. Binary attachments (images, PDFs) use the general cap.
  if kind == "text" and #data > TEXT_ATTACH_MAX_BYTES then
    local size_kb = str_format("%.0f", #data / 1024)
    local max_kb = str_format("%d", TEXT_ATTACH_MAX_BYTES / 1024)
    S.attach_error = (RA and RA.t and RA.t("attach.error.text_too_large",
      { size = size_kb, max = max_kb },
      str_format("Text file too large (%.0f KB, max %d KB).",
        #data / 1024, TEXT_ATTACH_MAX_BYTES / 1024)))
      or str_format("Text file too large (%.0f KB, max %d KB).",
        #data / 1024, TEXT_ATTACH_MAX_BYTES / 1024)
    S.attach_error_time = time_precise()
    return false
  end

  if #data > ATTACH_MAX_BYTES then
    local size_mb = str_format("%.1f", #data / 1048576)
    local max_mb = str_format("%d", ATTACH_MAX_BYTES / 1048576)
    S.attach_error = (RA and RA.t and RA.t("attach.error.file_too_large",
      { size = size_mb, max = max_mb },
      str_format("File too large (%.1f MB, max %d MB).",
        #data / 1048576, ATTACH_MAX_BYTES / 1048576)))
      or str_format("File too large (%.1f MB, max %d MB).",
        #data / 1048576, ATTACH_MAX_BYTES / 1048576)
    S.attach_error_time = time_precise()
    return false
  end

  if #data == 0 then
    S.attach_error = (RA and RA.t and RA.t("attach.error.empty_file", nil,
      "File is empty.")) or "File is empty."
    S.attach_error_time = time_precise()
    return false
  end

  local entry = {
    kind       = kind,
    name       = get_filename(path),
    data       = data,
    media_type = media_type,
    path       = path,
  }
  entry.tokens = estimate_attachment_tokens(entry)
  entry.cost   = estimate_attachment_cost(entry.tokens)

  S.attachments[#S.attachments+1] = entry

  if #data > ATTACH_WARN_BYTES then
    local size_mb = str_format("%.1f", #data / 1048576)
    local cost = MODELS.format_cost(entry.cost)
    S.attach_error = (RA and RA.t and RA.t("attach.warning.large_file",
      { size = size_mb, cost = cost },
      str_format("Large file (%.1f MB), estimated cost: %s",
        #data / 1048576, cost)))
      or str_format("Large file (%.1f MB), estimated cost: %s",
        #data / 1048576, cost)
    S.attach_error_time = time_precise()
  end

  return true
end

-- Attach.screenshot() -> true on success, false on failure (sets S.attach_error)
Attach.screenshot = function()
  if #S.attachments >= ATTACH_MAX_COUNT then
    S.attach_error = (RA and RA.t and RA.t("attach.error.max_count",
      { count = ATTACH_MAX_COUNT },
      str_format("Maximum %d attachments per message.", ATTACH_MAX_COUNT)))
      or str_format("Maximum %d attachments per message.", ATTACH_MAX_COUNT)
    S.attach_error_time = time_precise()
    return false
  end

  local png_path, err = capture_screenshot()
  if not png_path then
    S.attach_error = (err and tostring(err) ~= "" and tostring(err))
      or ((RA and RA.t and RA.t("attach.error.screenshot_failed", nil,
        "Screenshot failed.")) or "Screenshot failed.")
    S.attach_error_time = time_precise()
    return false
  end

  local data = read_file_binary(png_path)
  os.remove(png_path)  -- clean up temp file

  if not data or #data == 0 then
    S.attach_error = (RA and RA.t and RA.t(
      "attach.error.screenshot_empty", nil,
      "Screenshot produced an empty file."))
      or "Screenshot produced an empty file."
    S.attach_error_time = time_precise()
    return false
  end

  if #data > ATTACH_MAX_BYTES then
    local size_mb = str_format("%.1f", #data / 1048576)
    local max_mb = str_format("%d", ATTACH_MAX_BYTES / 1048576)
    S.attach_error = (RA and RA.t and RA.t("attach.error.screenshot_too_large",
      { size = size_mb, max = max_mb },
      str_format("Screenshot too large (%.1f MB, max %d MB).",
        #data / 1048576, ATTACH_MAX_BYTES / 1048576)))
      or str_format("Screenshot too large (%.1f MB, max %d MB).",
        #data / 1048576, ATTACH_MAX_BYTES / 1048576)
    S.attach_error_time = time_precise()
    return false
  end

  local entry = {
    kind       = "image",
    name       = (RA and RA.t and RA.t("attach.name.screenshot", nil,
      "Screenshot")) or "Screenshot",
    data       = data,
    media_type = "image/png",
    path       = nil,
  }
  entry.tokens = estimate_attachment_tokens(entry)
  entry.cost   = estimate_attachment_cost(entry.tokens)

  S.attachments[#S.attachments+1] = entry
  return true
end

-- Attach.clipboard() -> true if an image was found and attached, false otherwise
Attach.clipboard = function()
  if #S.attachments >= ATTACH_MAX_COUNT then
    S.attach_error = (RA and RA.t and RA.t("attach.error.max_count",
      { count = ATTACH_MAX_COUNT },
      str_format("Maximum %d attachments per message.", ATTACH_MAX_COUNT)))
      or str_format("Maximum %d attachments per message.", ATTACH_MAX_COUNT)
    S.attach_error_time = time_precise()
    return false
  end

  local png_path = get_clipboard_image()
  if not png_path then
    S.attach_error = (RA and RA.t and RA.t(
      "attach.error.clipboard_no_image", nil,
      "No image found in clipboard."))
      or "No image found in clipboard."
    S.attach_error_time = time_precise()
    return false
  end

  local data = read_file_binary(png_path)
  os.remove(png_path)  -- clean up temp file

  if not data or #data == 0 then
    S.attach_error = (RA and RA.t and RA.t(
      "attach.error.clipboard_empty", nil,
      "Clipboard image is empty."))
      or "Clipboard image is empty."
    S.attach_error_time = time_precise()
    return false
  end

  if #data > ATTACH_MAX_BYTES then
    local size_mb = str_format("%.1f", #data / 1048576)
    local max_mb = str_format("%d", ATTACH_MAX_BYTES / 1048576)
    S.attach_error = (RA and RA.t and RA.t("attach.error.clipboard_too_large",
      { size = size_mb, max = max_mb },
      str_format("Clipboard image too large (%.1f MB, max %d MB).",
        #data / 1048576, ATTACH_MAX_BYTES / 1048576)))
      or str_format("Clipboard image too large (%.1f MB, max %d MB).",
        #data / 1048576, ATTACH_MAX_BYTES / 1048576)
    S.attach_error_time = time_precise()
    return false
  end

  local entry = {
    kind       = "image",
    name       = "Clipboard image",
    data       = data,
    media_type = "image/png",
    path       = nil,
  }
  entry.tokens = estimate_attachment_tokens(entry)
  entry.cost   = estimate_attachment_cost(entry.tokens)

  S.attachments[#S.attachments+1] = entry
  return true
end

end -- attachment system scope

-- =============================================================================
-- System prompt
-- =============================================================================
-- Loaded from System_Prompt.md at startup. {VERSION} is replaced
-- with CFG.VERSION.
--
-- Power-user override: if System_Prompt_Custom.md exists in the
-- same Resources/ folder, it is loaded INSTEAD of the stock prompt. The
-- custom file is not in the update manifest, so it survives updates and
-- is never touched by repair. The stock file may still change across
-- updates; advance_after_rename detects that and queues a one-time toast
-- on next launch reminding the user to review the new stock prompt.
local SYSTEM_PROMPT
local SYSTEM_PROMPT_IS_CUSTOM = false
-- Loads the system prompt at the kick-off block (after the bootstrap
-- critical-files check has run) so a missing or token-gutted stock prompt
-- can route into bootstrap recovery instead of returning from the main
-- chunk before recovery has a chance to render. Returns true on success;
-- on failure either sets S.bootstrap_active (stock missing/corrupt, repair
-- can fix it) or shows a message box (custom override is the user's file
-- and bootstrap cannot restore it).
local function load_system_prompt()
  local stock_path  = RA.RESOURCES_DIR .. "System_Prompt.md"
  local custom_path = RA.RESOURCES_DIR .. "System_Prompt_Custom.md"
  local prompt_path = stock_path
  if reaper.file_exists(custom_path) then
    prompt_path = custom_path
    SYSTEM_PROMPT_IS_CUSTOM = true
  end
  local f = io.open(prompt_path, "r")
  if not f then
    if SYSTEM_PROMPT_IS_CUSTOM then
      reaper.ShowMessageBox(
        RA.early_t(
          "Could not load system prompt file:\n" .. prompt_path
          .. "\n\nPlease make sure System_Prompt.md is in the "
          .. "Resources/ subfolder next to ReaAssist.lua.",
          "No se pudo cargar el archivo de prompt del sistema:\n" .. prompt_path
          .. "\n\nComprueba que System_Prompt.md esté en la subcarpeta "
          .. "Resources/ junto a ReaAssist.lua."),
        "ReaAssist", 0)
      return false
    end
    S.bootstrap_active = true
    S.bootstrap_missing[#S.bootstrap_missing + 1] =
      "Resources/System_Prompt.md"
    -- Log only; do NOT call Updater._set_failure here. _set_failure
    -- populates update.last_error, which Bootstrap.loop's view selector
    -- reads as "the last repair attempt failed" and routes straight to
    -- render_failed -- skipping the normal recovery prompt that lets
    -- the user click Repair. This is a load-time detection of a
    -- recoverable file (downloading it again will fix it), not a
    -- failed repair, so we leave last_error alone and let the
    -- bootstrap_active + bootstrap_missing entries drive render_prompt.
    Log.line("BOOTSTRAP",
      "system_prompt_load: System_Prompt.md missing; "
      .. "routing to recovery prompt.")
    return false
  end
  local raw = f:read("*a"); f:close()
  -- Strip the HTML comment header (<!-- ... -->) lines so they don't leak
  -- into the prompt sent to the API.
  raw = raw:gsub("<!%-%-.-%-%->\n?", "")
  local sws_required_prompt =
    REQUIRE_SWS_EXTENSION and not SupportExtFlag("optoutsws")
  if sws_required_prompt then
    local sws_rewrite_pattern =
      "%- Extension APIs: avoid SWS %(CF_%*%), js_ReaScriptAPI %(JS_%*%), and other non%-core extension functions unless the user explicitly requests them or the script first checks the function exists %(e%.g%. if reaper%.CF_GetClipboard then %.%.%. end%) and shows a clear error if missing%."
    local sws_rewrite_replacement =
      "- Extension APIs: SWS Extension is available and required in this build. Treat documented SWS APIs (`CF_*`, `BR_*`, `NF_*`, `FNG_*`) as available after requesting `docs:sws` when needed. js_ReaScriptAPI (`JS_*`) and other non-core extension functions remain optional unless the user explicitly requests them or the script first checks the function exists and shows a clear error if missing."
    local sws_rewrite_n
    raw, sws_rewrite_n = raw:gsub(sws_rewrite_pattern,
      sws_rewrite_replacement, 1)
    if sws_rewrite_n == 0 then
      Log.line("PROMPT",
        "system_prompt_load: SWS prompt rewrite anchor not found")
      if not SYSTEM_PROMPT_IS_CUSTOM then
        S.bootstrap_active = true
        S.bootstrap_missing[#S.bootstrap_missing + 1] =
          "Resources/System_Prompt.md (corrupt)"
        Log.line("BOOTSTRAP",
          "system_prompt_load: System_Prompt.md corrupt "
          .. "(missing SWS rewrite anchor); routing to recovery prompt.")
        return false
      end
    end
  end
  SYSTEM_PROMPT = raw:gsub("{VERSION}", CFG.VERSION)
  if sws_required_prompt then
    SYSTEM_PROMPT = SYSTEM_PROMPT .. [[

SWS DOCS ROUTING:
- Before using SWS-only calls, SWS/S&M startup actions, or SWS/S&M menu/action workflows, request <context_needed>docs:sws</context_needed> unless that section is already present in context.
- Prefer native REAPER APIs when they are equally direct; use SWS for clipboard, mouse cursor context, GUID helpers, loudness analysis, SWS notes, FX-chain window helpers, SWS/S&M startup actions, and other APIs/workflows documented in docs:sws.
]]
  end
  -- Tamper guard for the SHIPPED prompt only: if the stock file has been
  -- gutted, partially truncated, or replaced with junk, route into bootstrap
  -- recovery so repair can restore it. Custom overrides bypass this check;
  -- power users may legitimately rewrite the branding in their own copy.
  --
  -- We require multiple structural anchors (not just the product token) so
  -- a partial corruption that still contains "ReaAssist" somewhere in the
  -- file passes through and produces one bad chat session before the SHA
  -- repair check catches it on the next launch. The anchors below are the
  -- prompt's load-bearing section headers; if any one is missing, the file
  -- is structurally broken and unsafe to feed to a model.
  if not SYSTEM_PROMPT_IS_CUSTOM then
    local required_anchors = {
      CFG._PRODUCT,
      "CORE BEHAVIOR:",
      "CONTEXT BUCKETS",
      "API REF REQUIREMENT",
      "PROMPT BUNDLES",
    }
    for _, anchor in ipairs(required_anchors) do
      if not SYSTEM_PROMPT:find(anchor, 1, true) then
        S.bootstrap_active = true
        S.bootstrap_missing[#S.bootstrap_missing + 1] =
          "Resources/System_Prompt.md (corrupt)"
        -- Log only; see the parallel comment on the missing-file branch
        -- above for why we do NOT call Updater._set_failure here. The
        -- specific anchor is preserved in the debug log for triage.
        Log.line("BOOTSTRAP", string.format(
          "system_prompt_load: System_Prompt.md corrupt "
          .. "(missing anchor %q); routing to recovery prompt.",
          anchor))
        return false
      end
    end
  end
  -- Log custom-prompt usage so support can rule it in/out when triaging
  -- "weird model output" reports. No-op if debug logging is disabled.
  if SYSTEM_PROMPT_IS_CUSTOM then
    Log.line("PROMPT",
      "Using System_Prompt_Custom.md (override active)")
  end
  return true
end

-- CTX is a plain global (cross-file shared state; its `= {}` initializer
-- runs later in this file). Code.auto_save_jsfx invalidates the installed-FX
-- cache after saving a new plugin by touching CTX, which is harmless before
-- the initializer because the touch happens inside a function body, not at
-- load time.

Code = {}

-- Forward declaration so Code.ensure_preferred_from_chains can call
-- _is_fabfilter_ident after RA.load_context pulls the Context.lua binding back
-- into this chunk-local slot. Without this forward decl, Lua's parser treats
-- the call site as a global lookup and the call resolves to nil at runtime.
local _is_fabfilter_ident

-- =============================================================================
-- Utility: Code.safe_write
-- =============================================================================
-- Writes content to a file path with crash- and failure-safe semantics:
--   1. Write to <path>.tmp.<instance>, checking both f:write and f:close
--      for nil+err
--      returns (not just thrown errors -- short writes/disk full/permission
--      failures come back that way in Lua, not as exceptions).
--   2. Rename any existing <path> to <path>.bak.<instance> so the original
--      is preserved.
--   3. Rename <path>.tmp.<instance> -> <path>. If that fails, restore from .bak.
--   4. On success, remove the instance-scoped .bak.
-- The original file is never destroyed unless the replacement is in place.
-- Returns true on success, shows a message box and returns false on failure.
function Code.safe_write(path, content)
  local atomic_suffix = (RA and RA.instance_file_suffix)
    and ("." .. RA.instance_file_suffix()) or ""
  local tmp_path = path .. ".tmp" .. atomic_suffix
  local bak_path = path .. ".bak" .. atomic_suffix
  local f, err = io.open(tmp_path, "wb")
  if not f then
    reaper.ShowMessageBox(
      RA.t("file_error.write", {
        path = tmp_path,
        error = tostring(err),
      }, "Could not write file:\n" .. tmp_path .. "\n\n" .. tostring(err)),
      RA.t("file_error.title", nil, "ReaAssist - File Error"), 0)
    return false
  end
  local w_ok, w_err = pcall(function()
    local ok, perr = f:write(content)
    if not ok then error(perr or "write returned nil", 0) end
  end)
  local c_ok, c_err = pcall(function()
    local ok, perr = f:close()
    if not ok then error(perr or "close returned nil", 0) end
  end)
  if not w_ok or not c_ok then
    os.remove(tmp_path)
    reaper.ShowMessageBox(
      RA.t("file_error.write_temp_failed", {
        path = tmp_path,
        error = tostring(w_err or c_err),
      }, "Failed writing temp file:\n" .. tmp_path .. "\n\n"
        .. tostring(w_err or c_err)),
      RA.t("file_error.title", nil, "ReaAssist - File Error"), 0)
    return false
  end
  -- Preserve the original until the new file is definitely in place. Windows
  -- os.rename fails when the destination exists, so move the original out of
  -- the way first. os.rename returns nil when the source does not exist (a
  -- fresh write); had_original tracks that so restoration is only attempted
  -- when there was actually something to restore.
  os.remove(bak_path)
  local had_original = os.rename(path, bak_path)
  local ok_r, ren_err = os.rename(tmp_path, path)
  if not ok_r then
    if had_original then os.rename(bak_path, path) end
    os.remove(tmp_path)
    reaper.ShowMessageBox(
      RA.t("file_error.finalize", {
        path = path,
        error = tostring(ren_err),
      }, "Could not finalize file:\n" .. path .. "\n\n" .. tostring(ren_err)),
      RA.t("file_error.title", nil, "ReaAssist - File Error"), 0)
    return false
  end
  os.remove(bak_path)
  return true
end

-- =============================================================================
-- Utility: Code.derive_filename
-- =============================================================================
-- Suggests a .lua filename from code content without an API call.
-- Strategy (in priority order):
--   1. Undo_EndBlock label: "ReaAssist: Create 20 tracks" -> "Create 20 tracks.lua"
--   2. First useful comment: "-- My Script" -> "My Script.lua"
--   3. First function name: "local function do_thing()" -> "do_thing.lua"
--   4. Fallback: "reaassist_script.lua"
-- Result is safe for all OSes: filesystem-unsafe chars stripped,
-- spaces preserved, length capped at 60 chars.
-- Shared filename sanitizer: strip filesystem-unsafe chars, collapse whitespace,
-- cap at 60 chars. Returns cleaned string (caller appends extension).
local function sanitize_filename(s, fallback)
  s = s:gsub('[<>:"/\\|%?%*]', ""):gsub("%s+", " "):gsub("^ +", ""):gsub(" +$", "")
  -- Strip trailing dots/spaces (Windows truncates them silently, breaking
  -- subsequent open-by-name lookups).
  s = s:gsub("[%. ]+$", "")
  if #s > 60 then s = s:sub(1, 60):gsub("[%. ]+$", "") end
  if s == "" then s = fallback end
  -- Reject Windows reserved device names. Match the stem before any extension
  -- the caller will append, so "CON" alone is enough to trigger.
  if RA.is_windows_reserved_name(s) then s = s .. "_" end
  return s
end

function Code.derive_filename(code)
  -- 1. Undo_EndBlock label: e.g. Undo_EndBlock("ReaAssist: Create 20 tracks", -1)
  --    Strip a leading "ReaAssist: " prefix if present so the filename is clean.
  local undo_label = code:match("Undo_EndBlock%s*%(%s*\"(.-)\"%s*,")
                  or code:match("Undo_EndBlock%s*%(%s*'(.-)'%s*,")
  if undo_label and undo_label ~= "" then
    undo_label = undo_label:gsub("^ReaAssist:%s*", "")
    return sanitize_filename(undo_label, "reaassist_script") .. ".lua"
  end

  -- 2. First useful comment.
  local function internal_comment(text)
    local lower = tostring(text or ""):lower()
    lower = lower:gsub("^%s+", ""):gsub("%s+$", "")
    return lower:match("^helper:") ~= nil
      or lower:find("plugin_ref", 1, true) ~= nil
      or lower:find("binary search", 1, true) ~= nil
      or lower:match("^band%s*%d") ~= nil
  end
  for raw in (tostring(code or ""):gsub("\r\n", "\n"):gsub("\r", "\n")
      .. "\n"):gmatch("([^\n]*)\n") do
    local comment = raw:match("^%s*%-%-+%s*(.-)%s*$")
    if comment and comment ~= "" and not comment:match("^!")
        and not internal_comment(comment) then
      return sanitize_filename(comment, "reaassist_script") .. ".lua"
    end
  end

  -- 3. First function name (covers local function and bare function forms).
  local fn_name = code:match("local%s+function%s+([%w_]+)%s*%(")
               or code:match("^function%s+([%w_]+)%s*%(")
  if fn_name then return sanitize_filename(fn_name, "reaassist_script") .. ".lua" end

  -- 4. Fallback.
  return "reaassist_script.lua"
end

-- =============================================================================
-- Utility: Code.derive_filename_jsfx
-- =============================================================================
-- Suggests a filename from JSFX code content.
-- Uses the desc: line if present, otherwise falls back to a generic name.
function Code.derive_filename_jsfx(code)
  local desc = code:match("^%s*desc:%s*(.-)%s*[\r\n]")
  if desc and desc ~= "" then return sanitize_filename(desc, "reaassist_effect") .. ".jsfx" end
  return "reaassist_effect.jsfx"
end

-- =============================================================================
-- Code.inject_output_ceiling -- runaway-feedback containment layer
-- =============================================================================
-- Defense-in-depth on top of the JSFX validator. The validator catches every
-- known runaway pattern at static-analysis time; this injection adds a hard
-- post-DSP cap on spl0..spl7 in case a future evasion slips through. Cap is
-- user-disableable via the injected slider (drag to 40 = bypass).
--
-- See implementation contract in this conversation's design v2.1-final
-- (gitignored notes). Key points enforced here:
--
--   * JSFX side uses `options:gmem=ReaAssist_Ceiling` (header directive),
--     NOT `gmem_attach()` (which is Lua-side only). Host script calls
--     `reaper.gmem_attach("ReaAssist_Ceiling")` to read the same namespace.
--
--   * Section-aware injection only. Append-only, no rewrites.
--     - Header: insert slider declaration; merge `gmem=ReaAssist_Ceiling`
--       into existing options: line OR insert a new options: line.
--     - @init: append init block (or create section if absent).
--     - @slider: append recompute block (or create section if absent).
--     - @sample: append clamp+engagement block.
--
--   * Bail conditions skip injection (ship original, log warning):
--       - 0 or 2+ @sample sections
--       - source contains `import` directive
--       - source uses `_ra_` identifier prefix already
--       - source already has `options:gmem=...` (any value)
--       - source uses `gmem[...]` anywhere (would silently rebind to our
--         private namespace and break intentional cross-plugin gmem)
--       - all slider slots 1..256 are used
--       - ExtState slot allocator wedged or exhausted
--
--   * Per-FILE alert/mute identity (not per-instance). Multiple track
--     instances of the same saved JSFX file share one gmem block. Documented
--     v1 trade-off; per-instance identity is v2 work.
--
--   * gmem layout (per-file block at base B, stride 8):
--       B+0: engagement flag (set by JSFX, cleared by host on poll)
--       B+1: cumulative engagement-sample count (lifetime)
--       B+2: time_precise() of most recent engagement
--       B+3: running consecutive-engagement count (for sustained-trip mute)
--       B+4: muted latch (set by JSFX after sustained trip; cleared by host
--            on user reset, or by JSFX when slider goes to 40 = off)
--       B+5..B+7: reserved
--     Global: gmem[0] = schema version, gmem[1] = "any engagement" sentinel.
--
--   * Allocation is monotonic via State.json (`ceiling_next_base`). Starts at
--     8, increments by 8 per save. Slot 0..7 reserved for global metadata.
--     No reuse in v1 (heartbeat/lease scheme deferred). Re-saving the same
--     LLM-generated source ultimately writes a NEW file with a numeric
--     suffix (slot differs => content differs => existing dedup misses).
--     Acceptable v1 trade-off; can add original-content dedup later.
do

local CEILING_NS          = "ReaAssist_Ceiling"
local CEILING_NEXT_BASE   = "ceiling_next_base"
local CEILING_SLOTS_KEY   = "ceiling_slots"
local CEILING_BASE_START  = 8
local CEILING_STRIDE      = 8
local CEILING_BASE_LIMIT  = 8000000  -- well under gmem's 8M cap; defensive
local CEILING_DB_DEFAULT  = 20       -- dBFS, slider default
local CEILING_DB_OFF      = 40       -- slider value at which clamp/mute bypass
local SLIDER_SLOT_MAX     = 256

-- gmem layout offsets (within a slot's 8-deep block; matches the JSFX
-- injection's writes -- keep these in lockstep with render_injection_blocks).
local CEILING_GMEM_ENGFLAG  = 0   -- per-slot engagement flag (set by JSFX)
local CEILING_GMEM_ENGCOUNT = 1   -- per-slot lifetime engagement-sample count
local CEILING_GMEM_MUTE     = 4   -- per-slot mute latch (0/1)
local CEILING_GMEM_GLOBAL_ENG = 1 -- gmem[1] -- global "any-instance engagement"
                                  -- sentinel; cheap-poll fast path. Slot 1 is
                                  -- inside the 0..7 reserved global block, NOT
                                  -- inside a per-slot allocation (allocations
                                  -- start at slot 8).

-- Public so host poll can reference symbolic names.
Code.CEILING_NS              = CEILING_NS
Code.CEILING_GMEM_MUTE       = CEILING_GMEM_MUTE
Code.CEILING_GMEM_ENGFLAG    = CEILING_GMEM_ENGFLAG
Code.CEILING_GMEM_ENGCOUNT   = CEILING_GMEM_ENGCOUNT
Code.CEILING_GMEM_GLOBAL_ENG = CEILING_GMEM_GLOBAL_ENG

-- Replace comment bodies and string literal contents with spaces so token
-- scans (`gmem[`, `import`, `_ra_`, `options:gmem=`) don't match inside
-- strings or comments. Approximate but conservative -- false positives
-- on bail-condition checks just make us bail more often, which is safe.
local function scrub_jsfx(src)
  local out = src:gsub("/%*(.-)%*/", function(body)
    return "/*" .. body:gsub("[^\n\r]", " ") .. "*/"
  end)
  out = out:gsub("//[^\r\n]*", function(s) return string.rep(" ", #s) end)
  out = out:gsub('"([^"\r\n]*)"', function(body)
    return '"' .. string.rep(" ", #body) .. '"'
  end)
  out = out:gsub("'([^'\r\n]*)'", function(body)
    return "'" .. string.rep(" ", #body) .. "'"
  end)
  return out
end

-- Split a string into lines without terminators. Trailing newline produces
-- no empty final element.
local function split_lines(s)
  local out = {}
  for line in (s .. "\n"):gmatch("([^\r\n]*)\r?\n") do
    out[#out + 1] = line
  end
  if out[#out] == "" then out[#out] = nil end
  return out
end

-- Allocate a gmem base for this save. State-backed, monotonic. Returns
-- the base (>=8, multiple of 8) or nil + reason on failure.
local function allocate_ceiling_slot()
  if Store and Store.reserve_ceiling_base then
    return Store.reserve_ceiling_base(
      CEILING_BASE_START, CEILING_STRIDE, CEILING_BASE_LIMIT)
  end
  local cur_str = reaper.GetExtState(CFG.EXT_NS, CEILING_NEXT_BASE)
  local cur = tonumber(cur_str)
  if not cur or cur < CEILING_BASE_START then cur = CEILING_BASE_START end
  if cur >= CEILING_BASE_LIMIT then
    return nil, "ExtState slot allocator exhausted"
  end
  -- Persist next base BEFORE returning so a crash mid-save still consumes
  -- the slot rather than handing the same slot to the next call.
  reaper.SetExtState(CFG.EXT_NS, CEILING_NEXT_BASE,
                     tostring(cur + CEILING_STRIDE), true)
  return cur
end

-- ============================================================================
-- Slot metadata tracking
-- ============================================================================
-- Each successful injection records the slot it allocated alongside the
-- saved file path, the JSFX `desc:` name, and the allocation timestamp.
-- The host's defer poll loop iterates this list to know which gmem slots
-- to read when checking for engaged/muted JSFX.
--
-- Storage: State.json `output_ceiling.slots` value, with legacy ExtState
-- fallback for older installs. Allocation is monotonic so the array grows
-- but never reuses slots.

-- Pull the recorded slot list. Empty array if not yet written.
function Code.ceiling_get_slots()
  if Store and Store.ceiling_slots then return Store.ceiling_slots() end
  local raw = reaper.GetExtState(CFG.EXT_NS, CEILING_SLOTS_KEY)
  if not raw or raw == "" then return {} end
  local ok, decoded = pcall(JSON.decode, raw)
  if not ok or type(decoded) ~= "table" then return {} end
  return decoded
end

-- Append a new slot entry to the list. info comes from
-- Code.inject_output_ceiling; saved_path is the path Code.auto_save_jsfx
-- wrote (may be nil if the JSFX was not saved -- e.g. JSFX-only response
-- without a Lua companion -- in which case we skip the record entirely
-- since there's no on-disk file to diagnose later).
function Code.ceiling_record_slot(info, saved_path, desc)
  if not info or not info.slot_base or not saved_path then return end
  local list = Code.ceiling_get_slots()
  list[#list + 1] = {
    slot      = info.slot_base,
    file      = saved_path,
    desc      = desc or "",
    alloc_ts  = os.time(),
  }
  if Store and Store.save_ceiling_slots then
    Store.save_ceiling_slots(list)
  else
    local enc = JSON.encode(list)
    if enc then reaper.SetExtState(CFG.EXT_NS, CEILING_SLOTS_KEY, enc, true) end
  end
end

-- Forget the slot whose recorded file is `path`. Called when the user
-- Reset-All-then-clears or when a saved file is detected missing during a
-- poll (orphaned slot). Allocation never reuses the slot index, so this
-- only prunes the metadata; gmem state for the slot stays whatever the
-- last write left it as.
function Code.ceiling_forget_slot_for_path(path)
  if not path or path == "" then return end
  local list = Code.ceiling_get_slots()
  local kept = {}
  for _, e in ipairs(list) do
    if e.file ~= path then kept[#kept + 1] = e end
  end
  if #kept ~= #list then
    if Store and Store.save_ceiling_slots then
      Store.save_ceiling_slots(kept)
    else
      reaper.SetExtState(CFG.EXT_NS, CEILING_SLOTS_KEY, JSON.encode(kept), true)
    end
  end
end

-- Bulk garbage-collect slots in ExtState. Drops any entry whose:
--   (a) recorded file is missing from disk, OR
--   (b) file exists but no longer contains `_ra_slot = <N>;` matching
--       the recorded slot (file was overwritten or re-injected with
--       a different slot allocation).
--
-- Caller MUST have already called `reaper.gmem_attach(CEILING_NS)`
-- so the per-slot mute mirror clears land on the right region. In
-- practice the only caller is the poll loop, which attaches before
-- doing anything else.
--
-- Scans each file in chunks for the `_ra_slot` marker. The injector may
-- append @init after a long JSFX header, so a fixed header read can falsely
-- prune live slots. Allocation is monotonic so pruned slot indices are
-- never reused; this just trims the metadata + gmem cruft.
--
-- Returns the number of slots pruned (0 if everything still valid).
function Code.ceiling_gc_slots()
  local list = Code.ceiling_get_slots()
  if #list == 0 then return 0 end
  local kept = {}
  local pruned = 0
  for _, e in ipairs(list) do
    local keep = false
    if e.file and e.file ~= "" and e.slot then
      local f = io.open(e.file, "rb")
      if f then
        -- Match `_ra_slot = N;` (whitespace tolerant). The injector
        -- emits exactly this in the injected @init block.
        local pat = "_ra_slot%s*=%s*" .. tostring(e.slot) .. "%s*;"
        local scan = ""
        while true do
          local chunk = f:read(32768)
          if not chunk or chunk == "" then break end
          scan = scan .. chunk
          if scan:find(pat) then
            keep = true
            break
          end
          if #scan > 128 then scan = scan:sub(-128) end
        end
        f:close()
      end
    end
    if keep then
      kept[#kept + 1] = e
    else
      pruned = pruned + 1
      -- Zero the mute mirror so an orphaned `1` doesn't pollute any
      -- future allocation that happens to land on a neighbour slot.
      -- Best-effort: if gmem_write isn't available, the metadata
      -- prune still happens.
      if reaper.gmem_write then
        reaper.gmem_write(e.slot + CEILING_GMEM_MUTE, 0)
      end
    end
  end
  if pruned > 0 then
    if Store and Store.save_ceiling_slots then
      Store.save_ceiling_slots(kept)
    else
      reaper.SetExtState(CFG.EXT_NS, CEILING_SLOTS_KEY,
        JSON.encode(kept), true)
    end
    if Log and Log.line then
      Log.line("CEILING-GC",
        ("pruned %d stale slot(s); kept %d"):format(pruned, #kept))
    end
  end
  return pruned
end

-- Host-side mute clear: write gmem[slot+4] = 0. Caller must have
-- previously called `reaper.gmem_attach(CEILING_NS)`.
function Code.ceiling_clear_mute(slot)
  if not slot or slot < CEILING_BASE_START then return end
  reaper.gmem_write(slot + CEILING_GMEM_MUTE, 0)
end

-- Render the three injection blocks parameterised on slot base + slider id.
--
-- Slider semantics (UX simplification, 2026-04-29 follow-up):
-- The slider value is ALWAYS the ceiling level in dBFS. There is no magic
-- "off" position. At the slider's max (40 dBFS = 100x linear), the ceiling
-- is so permissive that real audio in normal use never reaches it -- so
-- 40 is "effectively off" without needing a special bypass code path.
-- This avoids the earlier "is 40 really off, or just at +40 dBFS?" UX
-- confusion: now it's unambiguously "the ceiling is at this dBFS value,
-- always."
--
-- The mute latch is cleared on ANY slider change. Touching the control =
-- explicit user acknowledgement that they've seen something happened and
-- want to continue. Simpler than a dedicated reset position on the slider.
--
-- We avoid a `1e30`-style "infinity" literal here because REAPER's JSFX
-- parser rejected it in some contexts (observed: bare `1e30` inside a
-- ternary RHS produced `@init: syntax error`). Always-compute via pow()
-- is defensible regardless of the literal-parsing rules.
local function render_injection_blocks(slot, slider_n)
  -- @init resets local mute state AND clears the gmem mirror slots for
  -- this allocation. Without the gmem clear, gmem state from a previous
  -- session (gmem persists in REAPER project files) could lie to the
  -- host's poll loop on reopen -- the JSFX's _ra_muted is fresh-zero but
  -- gmem[slot+4] could still carry an old `1` from a prior run.
  local INIT_INJ = ([[
// --- ReaAssist output ceiling (auto-injected; do not edit) ---
_ra_slot = %d;
_ra_mute_samples = srate * 0.05;
_ra_sus = 0;
_ra_muted = 0;
_ra_prev_slider = slider%d;
_ra_ceil_lin = pow(10, slider%d/20);
gmem[_ra_slot+0] = 0;
gmem[_ra_slot+1] = 0;
gmem[_ra_slot+4] = 0;
// ----------------------------------------------------------]])
    :format(slot, slider_n, slider_n)

  -- @slider recompute. Mute state cleared via local _ra_muted on any
  -- slider change. gmem[slot+4] is mirrored so a slider-driven reset
  -- stays consistent with the host's view (host poll reads gmem).
  local SLIDER_INJ = ([[
// --- ReaAssist output ceiling recompute (auto-injected) ---
_ra_ceil_lin = pow(10, slider%d/20);
_ra_changed = slider%d != _ra_prev_slider ? 1 : 0;
_ra_muted = _ra_changed ? 0 : _ra_muted;
_ra_sus = _ra_changed ? 0 : _ra_sus;
_ra_prev_slider = slider%d;
gmem[_ra_slot+4] = _ra_muted;
// ----------------------------------------------------------]])
    :format(slider_n, slider_n, slider_n)

  -- NOTE: a previous version injected an @block section to clear the mute
  -- latch on any transport stop edge. Both the && form and a nested-ternary
  -- form caused the per-sample mute logic to stop working entirely, even
  -- though the inner clear should never have fired during sustained
  -- playback. The mechanism remains unidentified -- possibly a section-
  -- ordering quirk specific to this user's REAPER build.
  --
  -- Stop-edge auto-clear is therefore deferred to the host-side path: once
  -- the gmem poll loop lands (next §9 step), the host can write
  -- gmem[B+4] = 0 from Lua when it observes a transport stop, achieving
  -- the same UX without injecting @block code into the JSFX.
  --
  -- Until then, the user can clear a latched mute by moving the ceiling
  -- slider (the @slider injection clears on any slider change). Returning
  -- nil here makes the create-or-append logic in inject_output_ceiling
  -- below skip @block entirely.
  local BLOCK_INJ = nil

  -- @sample: per-channel ceiling clamp + sustained-trip mute.
  --
  -- This block is structurally identical to a standalone test JSFX that
  -- the user verified WORKS (the same logic, in plain globals, not gmem,
  -- with single-line OR-chains). The mute decision uses local _ra_muted
  -- as the source of truth; gmem writes are pure host-visibility mirrors
  -- (the `@slider` inj also writes through to gmem on user reset).
  -- Slot layout matches the host-side poll constants in
  -- `Net.ceiling_*` -- keep in lockstep.
  --   gmem[_ra_slot+0]: engagement flag (set on any engaged sample;
  --                     host clears after consuming the alert)
  --   gmem[_ra_slot+1]: cumulative engagement-sample count (lifetime)
  --   gmem[_ra_slot+4]: mute mirror (latches when _ra_muted goes 1)
  --   gmem[1]:          global "any-instance engagement" sentinel,
  --                     allows host's defer poll to skip the per-slot
  --                     scan when nothing has fired anywhere
  --
  -- The host-side reset (Reset Mute button in the popup) writes
  -- gmem[slot+4] = 0 directly. The injection's @slider section also
  -- mirrors _ra_muted -> gmem[slot+4] every slider change so a slider
  -- nudge from the JSFX side stays consistent with gmem.
  local SAMPLE_INJ = [[
// --- ReaAssist output ceiling (auto-injected; do not edit) ---
_ra_muted ? (
  spl0 = 0; spl1 = 0; spl2 = 0; spl3 = 0;
  spl4 = 0; spl5 = 0; spl6 = 0; spl7 = 0;
) : (
  _ra_eng = (abs(spl0) > _ra_ceil_lin) || (abs(spl1) > _ra_ceil_lin) || (abs(spl2) > _ra_ceil_lin) || (abs(spl3) > _ra_ceil_lin) || (abs(spl4) > _ra_ceil_lin) || (abs(spl5) > _ra_ceil_lin) || (abs(spl6) > _ra_ceil_lin) || (abs(spl7) > _ra_ceil_lin);
  spl0 = abs(spl0) > _ra_ceil_lin ? max(-_ra_ceil_lin, min(_ra_ceil_lin, spl0)) : spl0;
  spl1 = abs(spl1) > _ra_ceil_lin ? max(-_ra_ceil_lin, min(_ra_ceil_lin, spl1)) : spl1;
  spl2 = abs(spl2) > _ra_ceil_lin ? max(-_ra_ceil_lin, min(_ra_ceil_lin, spl2)) : spl2;
  spl3 = abs(spl3) > _ra_ceil_lin ? max(-_ra_ceil_lin, min(_ra_ceil_lin, spl3)) : spl3;
  spl4 = abs(spl4) > _ra_ceil_lin ? max(-_ra_ceil_lin, min(_ra_ceil_lin, spl4)) : spl4;
  spl5 = abs(spl5) > _ra_ceil_lin ? max(-_ra_ceil_lin, min(_ra_ceil_lin, spl5)) : spl5;
  spl6 = abs(spl6) > _ra_ceil_lin ? max(-_ra_ceil_lin, min(_ra_ceil_lin, spl6)) : spl6;
  spl7 = abs(spl7) > _ra_ceil_lin ? max(-_ra_ceil_lin, min(_ra_ceil_lin, spl7)) : spl7;
  _ra_sus = _ra_eng ? _ra_sus + 1 : max(0, _ra_sus - 1);
  _ra_muted = _ra_sus >= _ra_mute_samples ? 1 : _ra_muted;
  // Host-visibility mirrors. Mute logic above already used the local
  // _ra_muted for the per-sample decision; these writes just expose the
  // state to the Lua-side host poll loop.
  gmem[_ra_slot+0] = _ra_eng ? 1 : gmem[_ra_slot+0];
  gmem[_ra_slot+1] = _ra_eng ? gmem[_ra_slot+1] + 1 : gmem[_ra_slot+1];
  gmem[_ra_slot+4] = _ra_muted;
  gmem[1] = _ra_eng ? 1 : gmem[1];
);
// ----------------------------------------------------------]]

  return INIT_INJ, SLIDER_INJ, BLOCK_INJ, SAMPLE_INJ
end

-- Main entry point. Returns (injected_src, info_table) on success, or
-- (nil, skip_reason_string) on bail. Caller is responsible for shipping
-- the original source on bail.
function Code.inject_output_ceiling(src)
  if type(src) ~= "string" or src == "" then
    return nil, "empty source"
  end

  -- Idempotency: if the source already has our injection markers, ship it
  -- back unmodified. Lets the response-handler path inject for the chat
  -- display AND lets auto_save_jsfx call inject again (as a defense) without
  -- double-injecting or burning a second slot allocation.
  if src:find("// --- ReaAssist output ceiling", 1, true) then
    return nil, "already injected"
  end

  -- Split into lines (preserve content; we'll rejoin with \n on output).
  local lines = split_lines(src)
  if #lines == 0 then return nil, "empty source" end

  -- Locate section markers (`@<word>` at column 0).
  local sections = {}        -- ordered list: { name, marker_line }
  local sections_by_name = {}
  for i, line in ipairs(lines) do
    local kw = line:match("^@(%w+)")
    if kw then
      local entry = { name = kw, marker_line = i }
      sections[#sections + 1] = entry
      sections_by_name[kw] = sections_by_name[kw] or {}
      table.insert(sections_by_name[kw], entry)
    end
  end

  -- Compute body ranges: section i's body is lines [marker_line+1 .. next_marker_line-1].
  for i, sec in ipairs(sections) do
    sec.body_start = sec.marker_line + 1
    sec.body_end = (i < #sections) and (sections[i + 1].marker_line - 1) or #lines
  end
  local header_end = (#sections > 0) and (sections[1].marker_line - 1) or #lines

  -- Bail: must have exactly one @sample.
  local sample_entries = sections_by_name.sample
  if not sample_entries then return nil, "no @sample section" end
  if #sample_entries > 1 then return nil, "multiple @sample sections" end

  -- Bail: forbidden tokens in scrubbed source.
  local scrubbed = scrub_jsfx(src)
  if scrubbed:match("[^%w_]import%s") or scrubbed:match("^import%s") then
    return nil, "import directive present"
  end
  if scrubbed:match("[^%w_]_ra_") or scrubbed:match("^_ra_") then
    return nil, "source uses _ra_ identifier prefix"
  end
  if scrubbed:match("options:[^\r\n]*gmem%s*=") then
    return nil, "existing options:gmem= directive"
  end
  if scrubbed:match("gmem%s*%[") then
    return nil, "source already uses gmem[]"
  end

  -- Pick a free slider slot. Also bail if the LLM emitted any slider whose
  -- name suggests it's already trying to be an output ceiling/limit/cap --
  -- shipping a duplicate would put two same-purpose sliders in the UI.
  -- The Prompts.md OUTPUT STAGE rule forbids the LLM from doing this; this
  -- bail is the runtime defense if the rule is violated.
  local used_sliders = {}
  for _, line in ipairs(lines) do
    local n, name = line:match("^slider(%d+):[^>]*>(.*)$")
    if n then
      used_sliders[tonumber(n)] = true
      -- Match patterns like "Safety Output Ceiling", "Output Ceiling",
      -- "Output Limiter", "Master Out", "Final Gain". Lowercased for
      -- case-insensitive comparison. Conservative -- false positives just
      -- skip the injection, which is safer than colliding with a real
      -- output-control slider the LLM legitimately added on user request.
      local lname = (name or ""):lower()
      if lname:find("output ceiling", 1, true)
         or lname:find("output limit", 1, true)
         or lname:find("output cap", 1, true)
         or lname:find("safety ceiling", 1, true)
         or (lname:find("safety", 1, true) and lname:find("output", 1, true)) then
        return nil, "source already declares an output-ceiling slider: \""
          .. (name or "") .. "\""
      end
    end
  end
  local slider_n
  for i = 1, SLIDER_SLOT_MAX do
    if not used_sliders[i] then slider_n = i; break end
  end
  if not slider_n then
    return nil, "all slider slots 1.." .. SLIDER_SLOT_MAX .. " used"
  end

  -- Allocate gmem slot. Persists ExtState before any source mutation; safe
  -- to reach this point only after ALL bail conditions cleared.
  local slot, alloc_err = allocate_ceiling_slot()
  if not slot then return nil, alloc_err end

  -- Locate or merge the header `options:` line.
  local options_line_idx
  for i = 1, header_end do
    if lines[i]:match("^options:") then options_line_idx = i; break end
  end
  if options_line_idx then
    -- In-place edit: append " gmem=ReaAssist_Ceiling" (space-separated per
    -- JSFX options syntax; not comma).
    lines[options_line_idx] = lines[options_line_idx] .. " gmem=" .. CEILING_NS
  end

  -- Build the injection plan. Each entry: { after_line = N, lines = {...} }.
  -- Apply by walking the original line array once and inserting AFTER each
  -- target line. Multiple entries with the same after_line are concatenated
  -- in plan order.
  local plan = {}
  local function add_after(line_no, content_lines)
    plan[line_no] = plan[line_no] or {}
    for _, l in ipairs(content_lines) do
      plan[line_no][#plan[line_no] + 1] = l
    end
  end

  -- Header: options line (if not merged) + slider declaration. The slider
  -- value is unconditionally the ceiling level in dBFS -- no magic "off"
  -- position. Max value (CEILING_DB_OFF dBFS = high linear gain) is
  -- effectively off because real audio in normal use never reaches it.
  --
  -- Collision protection lives in the bail conditions above (specifically
  -- the "safety/output/ceiling slider already present" check). The bundle
  -- forbids the LLM from emitting any output-control slider; the bail is
  -- the runtime defense if it slips through anyway.
  local slider_line = ("slider%d:%d<0,%d,1>Safety Output Ceiling (dBFS)")
    :format(slider_n, CEILING_DB_DEFAULT, CEILING_DB_OFF)
  local header_block = {}
  if not options_line_idx then
    header_block[#header_block + 1] = "options:gmem=" .. CEILING_NS
  end
  header_block[#header_block + 1] = slider_line
  add_after(header_end, header_block)

  -- Render section blocks.
  local INIT_INJ, SLIDER_INJ, BLOCK_INJ, SAMPLE_INJ =
    render_injection_blocks(slot, slider_n)

  local function find_sec(name)
    return sections_by_name[name] and sections_by_name[name][1] or nil
  end

  -- @init injection.
  local init_sec = find_sec("init")
  local created_init = false
  if init_sec then
    add_after(init_sec.body_end, split_lines(INIT_INJ))
  else
    -- No @init -- create one immediately after our header insertions
    -- (which go after `header_end`). Both go through add_after(header_end).
    -- Plan-order ensures: [options/slider header_block] [@init] [INIT_INJ].
    add_after(header_end, { "@init" })
    add_after(header_end, split_lines(INIT_INJ))
    created_init = true
  end

  -- @slider injection.
  local slider_sec = find_sec("slider")
  local created_slider = false
  if slider_sec then
    add_after(slider_sec.body_end, split_lines(SLIDER_INJ))
  else
    -- Create @slider just before @sample's marker line.
    local sample_sec = find_sec("sample")
    add_after(sample_sec.marker_line - 1, { "@slider" })
    add_after(sample_sec.marker_line - 1, split_lines(SLIDER_INJ))
    created_slider = true
  end

  -- @block injection (transport-edge mute clear). v1: skipped entirely;
  -- BLOCK_INJ is nil. See render_injection_blocks for rationale.
  local created_block = false
  if BLOCK_INJ then
    local block_sec = find_sec("block")
    if block_sec then
      add_after(block_sec.body_end, split_lines(BLOCK_INJ))
    else
      local sample_sec = find_sec("sample")
      add_after(sample_sec.marker_line - 1, { "@block" })
      add_after(sample_sec.marker_line - 1, split_lines(BLOCK_INJ))
      created_block = true
    end
  end

  -- @sample injection (always present per bail check above).
  local sample_sec = find_sec("sample")
  add_after(sample_sec.body_end, split_lines(SAMPLE_INJ))

  -- Walk original lines and apply insertions.
  local out = {}
  -- Insert any `after_line = 0` content first (before line 1).
  if plan[0] then
    for _, l in ipairs(plan[0]) do out[#out + 1] = l end
  end
  for i = 1, #lines do
    out[#out + 1] = lines[i]
    if plan[i] then
      for _, l in ipairs(plan[i]) do out[#out + 1] = l end
    end
  end

  -- desc: line lookup -- caller (host poll, popup, diagnose path) wants
  -- the user-facing name without re-parsing.
  local desc = src:match("^%s*desc:%s*(.-)%s*[\r\n]") or ""

  return table.concat(out, "\n"), {
    slot_base       = slot,
    slider_num      = slider_n,
    merged_options  = options_line_idx ~= nil,
    created_init    = created_init,
    created_slider  = created_slider,
    created_block   = created_block,
    desc            = desc,
  }
end

end  -- close ceiling-injection scope

-- =============================================================================
-- Utility: Code.auto_save_jsfx
-- =============================================================================
-- Silently saves JSFX code to Effects/ReaAssist/<derived_name>.jsfx.
-- Returns the saved path on success, nil on failure.
--
-- Filename is derived from `code` directly. The output-ceiling injection
-- step now runs at chat-display time in Net.process_response_content, BEFORE
-- this function is called -- so by the time auto_save_jsfx sees `code`, it
-- already contains the injected ceiling slider, options:gmem= line, and
-- @init/@slider/@block/@sample blocks. The desc: line is untouched by
-- injection, so filename derivation produces the same name either way.
--
-- Dedup compares full content. Two saves of the same LLM source allocate
-- different gmem slots at injection time, so re-saving produces a new
-- numeric-suffixed file rather than reusing the existing one. v1 trade-off.
function Code.auto_save_jsfx(code)
  local base_name = Code.derive_filename_jsfx(code)

  local name = base_name
  local stem = base_name:match("^(.+)%.jsfx$") or base_name
  local dest = JSFX_DIR .. RA.SEP .. name
  -- Check existing files: if one has identical content, return it (no duplicate).
  -- If content differs, skip past it and try the next numeric suffix.
  local n = 1
  local f = io.open(dest, "r")
  while f do
    local existing = f:read("*a")
    f:close()
    if existing == code then
      -- Exact same content already on disk -- reuse it.
      return dest, "ReaAssist/" .. name
    end
    n = n + 1
    name = stem .. "_" .. n .. ".jsfx"
    dest = JSFX_DIR .. RA.SEP .. name
    f = io.open(dest, "r")
  end
  local ok = Code.safe_write(dest, code)
  if ok then
    -- Refresh JSFX list so TrackFX_AddByName can find it immediately.
    if reaper.EnumInstalledFX then
      reaper.EnumInstalledFX(-1)
    end
    -- Invalidate our cached installed-FX list so a follow-up
    -- <context_needed>fx_list:...</context_needed> for the newly saved
    -- plugin actually sees it instead of reporting "not installed".
    CTX._installed_fx_list = nil
    return dest, "ReaAssist/" .. name
  end
  return nil
end

function Code.auto_save_lua(code)
  code = tostring(code or "")
  if code == "" then return nil end

  local base_name = Code.derive_filename(code)
  if not base_name:lower():match("%.lua$") then base_name = base_name .. ".lua" end
  reaper.RecursiveCreateDirectory(RA.SCRIPT_SAVE_DIR, 0)

  local name = base_name
  local stem = base_name:match("^(.+)%.lua$") or base_name
  local dest = RA.SCRIPT_SAVE_DIR .. RA.SEP .. name
  local n = 1
  local f = io.open(dest, "r")
  while f do
    f:close()
    n = n + 1
    local suffix = " " .. tostring(n)
    local numbered_stem = stem
    if #numbered_stem + #suffix > 60 then
      numbered_stem = numbered_stem:sub(1, 60 - #suffix)
        :gsub("[%. ]+$", "")
      if numbered_stem == "" then numbered_stem = "reaassist_script" end
    end
    name = numbered_stem .. suffix .. ".lua"
    dest = RA.SCRIPT_SAVE_DIR .. RA.SEP .. name
    f = io.open(dest, "r")
  end

  if Code.safe_write(dest, code) then
    return dest, "Script: ReaAssist/" .. name, name
  end
  return nil
end

-- =============================================================================
-- ReEQ bundled-install support
-- =============================================================================
-- ReEQ (by Justin Johnson, MIT) is bundled with ReaAssist and installed on
-- demand at the standard ReaPack location so sessions remain portable: anyone
-- with ReEQ from ReaPack will resolve the same `ReJJ/ReEQ/ReEQ.jsfx` path.
--
-- The bundled source lives in <script>/Resources/ReEQ/ and contains:
--   ReEQ.jsfx, LICENSE.txt, Dependencies/{firhalfband,spectrum,svf_filter}.jsfx-inc
-- LICENSE keeps a .txt extension because gen_manifest.py only ships files
-- on a safe-extension whitelist (no-extension files are excluded). The
-- .txt suffix lets the file flow through both ReaPack's index.xml source
-- list and the internal updater's manifest.
--
-- After install we call EnumInstalledFX(-1) so TrackFX_AddByName finds the
-- new JSFX immediately (the FX Browser does not visually refresh until REAPER
-- restarts, but plugin lookup by path works right away).

local REEQ_SRC_DIR  = RA.RESOURCES_DIR .. "ReEQ"
local REEQ_DEST_DIR = reaper.GetResourcePath() .. RA.SEP .. "Effects" .. RA.SEP .. "ReJJ" .. RA.SEP .. "ReEQ"
local REEQ_DEPS     = { "firhalfband.jsfx-inc", "spectrum.jsfx-inc", "svf_filter.jsfx-inc" }

-- Returns true iff the canonical ReEQ.jsfx file is present at the ReaPack path.
function Code.is_reeq_installed()
  local f = io.open(REEQ_DEST_DIR .. RA.SEP .. "ReEQ.jsfx", "r")
  if f then f:close(); return true end
  return false
end

-- Internal: copies a single file if the destination doesn't already exist.
-- Returns true on success (including "already present" no-op), false + err on failure.
local function reeq_copy_file(src, dest)
  local existing = io.open(dest, "r")
  if existing then existing:close(); return true end  -- idempotent: don't overwrite
  local sf, err = io.open(src, "rb")
  if not sf then return false, "Cannot read " .. src .. ": " .. tostring(err) end
  local data = sf:read("*a"); sf:close()
  local df, derr = io.open(dest, "wb")
  if not df then return false, "Cannot write " .. dest .. ": " .. tostring(derr) end
  -- Check write/close return values. A short write (disk full mid-copy)
  -- or a close failure (filesystem flush error) used to leave a corrupt
  -- destination but return true; Code.is_reeq_installed() then sees the
  -- file exists and short-circuits any reinstall, so the user is stuck
  -- with a broken JSFX until they manually delete it. Remove the partial
  -- file on failure so a reinstall can recover.
  local wok, werr = df:write(data)
  local cok, cerr = df:close()
  if not wok or not cok then
    os.remove(dest)
    return false, "Write failed for " .. dest .. ": "
      .. tostring(werr or cerr or "unknown")
  end
  return true
end

-- Installs the bundled ReEQ to {resource_path}/Effects/ReJJ/ReEQ/.
-- Idempotent: skips files that already exist at the destination.
-- Returns (true, nil) on success or (false, error_message) on failure.
function Code.install_reeq()
  -- Sanity check that the bundled source is present.
  local probe = io.open(REEQ_SRC_DIR .. RA.SEP .. "ReEQ.jsfx", "r")
  if not probe then
    return false, "Bundled ReEQ source not found at " .. REEQ_SRC_DIR
  end
  probe:close()

  -- Create destination tree.
  reaper.RecursiveCreateDirectory(REEQ_DEST_DIR .. RA.SEP .. "Dependencies", 0)

  -- Copy main JSFX + LICENSE.txt.
  local ok, err = reeq_copy_file(REEQ_SRC_DIR .. RA.SEP .. "ReEQ.jsfx",
                                 REEQ_DEST_DIR .. RA.SEP .. "ReEQ.jsfx")
  if not ok then return false, err end
  ok, err = reeq_copy_file(REEQ_SRC_DIR .. RA.SEP .. "LICENSE.txt",
                           REEQ_DEST_DIR .. RA.SEP .. "LICENSE.txt")
  if not ok then return false, err end

  -- Copy dependencies.
  for _, dep in ipairs(REEQ_DEPS) do
    ok, err = reeq_copy_file(REEQ_SRC_DIR  .. RA.SEP .. "Dependencies" .. RA.SEP .. dep,
                             REEQ_DEST_DIR .. RA.SEP .. "Dependencies" .. RA.SEP .. dep)
    if not ok then return false, err end
  end

  -- Force REAPER to rescan installed FX so AddByName finds ReEQ immediately.
  -- Same trick used by Code.auto_save_jsfx; the FX Browser doesn't visually
  -- refresh, but lookup-by-path works right away.
  if reaper.EnumInstalledFX then reaper.EnumInstalledFX(-1) end
  CTX._installed_fx_list = nil

  -- Re-run fallback chains now that ReEQ is on disk. Fills pref_types.eq
  -- with the first chain candidate that's installed (ReEQ if the user has
  -- no FabFilter EQ) so the Preferred Plugins page reflects it and preempt
  -- injection fires for "eq" keywords from now on. No-op if the user
  -- already has an EQ preference set.
  Code.ensure_preferred_from_chains()

  return true, nil
end

-- =============================================================================
-- Fallback chains: auto-assign preferred plugins from Plugin_Ref.md
-- =============================================================================
-- PLUGIN AUTO-ASSIGN / POPUP FLOW
-- -------------------------------
-- Single source of truth: the ```chains block in Resources/Plugin_Ref.md.
-- Line format:
--   type: chain1 | chain2 | ... || stock-fallback [optional alias]
--
-- AUTO-ASSIGN CHAIN (left of `||`):
--   Walked at startup by Code.ensure_preferred_from_chains (and again after
--   install_reeq invalidates the FX list cache). First installed entry wins
--   and is written to pref_types[type]. Appears on the Preferred Plugins
--   page. Only high-quality third-party picks belong here -- they commit
--   users silently. Stock REAPER plugins are NEVER in chains.
--
-- STOCK FALLBACK (right of `||`):
--   Offered by the resolve popup as a one-click "Use <name> instead" button
--   when no chain entry is installed and the model emits resolve:<type>.
--   Used for THIS TURN ONLY -- never saved to pref_types, never shown on
--   the Preferred Plugins page. The popup fires again next time the type
--   comes up. Users who want a stock plugin permanent must type it into the
--   Preferred Plugins page themselves.
--
-- DISPLAY ALIAS (in brackets after any entry):
--   Optional. Overrides the button label for stock fallbacks. Example:
--     JS: Liteon/deesser [JSFX De-esser]
--   Shows as "Use JSFX De-esser instead" on the popup button.
--
-- LINE FORMAT EXAMPLES:
--   eq: Pro-Q 4 | ReJJ/ReEQ/ReEQ.jsfx || ReaEQ      -- 2-entry chain + stock
--   chorus:  || JS: SStillwell/chorus_stereo [JSFX Chorus]
--                                                    -- stock-only type
--   custom_thing: MyPlugin                           -- chain-only (rare)
--
-- TO ADD A NEW AUTO-ASSIGN CANDIDATE: add to the matching chain line in
-- Plugin_Ref.md. Entries are format-agnostic (just the plugin name); the
-- resolver tries VST3 > VSTi > VST > AU > CLAP. JSFX entries use the full
-- relative path (e.g. ReJJ/ReEQ/ReEQ.jsfx, or JS: vendor/file for stock).
--
-- TO ADD A NEW PLUGIN TYPE: add to PREF_PLUGIN_DEFAULTS, PREF_PLUGIN_ALIASES,
-- VALID_RESOLVE_TYPES, and add a chain line in Plugin_Ref.md. The popup
-- picks up the stock fallback automatically via Code.get_stock_fallback.
-- See Dev/Plugin Scanner Script/README.md for the full integration recipe.
-- -----------------------------------------------------------------------------

-- Reads the ```chains code block from Resources/Plugin_Ref.md.
-- Line format:
--   type: chain1 | chain2 | ... || stock-fallback
-- Any entry (chain or stock) may have an optional display alias in brackets:
--   JS: Liteon/deesser [JSFX De-esser]
-- Types with no auto-chain are written as:
--   type: || stock-fallback
--
-- Returns { type_key = { chain = {name1, ...}, stock = {add=..., alias=...} } }.
-- Parsed once per session; the file is authoritative.
local _fallback_chains

-- Parse a single entry string like "Pro-Q 4" or "JS: Liteon/deesser [JSFX De-esser]"
-- into { name = "...", alias = "..." or nil }.
local function _parse_chain_entry(s)
  s = s:match("^%s*(.-)%s*$") or ""
  if s == "" then return nil end
  local name, alias = s:match("^(.-)%s*%[(.-)%]%s*$")
  if name and alias and name ~= "" then
    return { name = name:match("^%s*(.-)%s*$"),
             alias = alias:match("^%s*(.-)%s*$") }
  end
  return { name = s, alias = nil }
end

function Code.get_fallback_chains()
  if _fallback_chains then return _fallback_chains end
  _fallback_chains = {}
  local ref_path = RA.RESOURCES_DIR .. "Plugin_Ref.md"
  local f = io.open(ref_path, "r")
  if not f then
    Log.line("CHAIN", "Plugin_Ref.md not found; no fallback chains loaded")
    return _fallback_chains
  end
  local content = f:read("*a")
  f:close()
  local block = content:match("```chains%s*\n(.-)\n```")
  if not block then
    Log.line("CHAIN", "no ```chains block found in Plugin_Ref.md")
    return _fallback_chains
  end
  local loaded = {}
  for line in block:gmatch("[^\n]+") do
    -- Skip comment lines and blank lines.
    local stripped = line:match("^%s*(.-)%s*$") or ""
    if stripped ~= "" and stripped:sub(1, 1) ~= "#" then
      local type_key, rest = line:match("^%s*([%w_]+)%s*:%s*(.*)$")
      if type_key and rest then
        -- Split on "||" to separate auto-chain from stock fallback.
        local chain_str, stock_str = rest:match("^(.-)%s*||%s*(.+)$")
        if not chain_str then
          -- No "||" found -- treat whole line as chain (no stock fallback).
          chain_str, stock_str = rest, nil
        end
        local chain_entries = {}
        for entry in chain_str:gmatch("[^|]+") do
          local parsed = _parse_chain_entry(entry)
          if parsed then chain_entries[#chain_entries+1] = parsed.name end
        end
        local stock = nil
        if stock_str then
          local parsed_stock = _parse_chain_entry(stock_str)
          if parsed_stock then
            stock = { add = parsed_stock.name, alias = parsed_stock.alias }
          end
        end
        if #chain_entries > 0 or stock then
          _fallback_chains[type_key] = {
            chain = chain_entries,
            stock = stock,
          }
          loaded[#loaded+1] = type_key
        end
      end
    end
  end
  Log.line("CHAIN", "loaded chains for types: " .. tbl_concat(loaded, ", "))
  return _fallback_chains
end

-- Code.get_stock_fallback and Code.is_curated_plugin are installed by
-- Resources/Context.lua because they read plugin-reference aliases loaded there.

-- Format preference for format-agnostic chain entries. Plugins installed in
-- multiple formats are resolved in this order so VST3 wins over CLAP, etc.
local CHAIN_FORMAT_PREFIXES = {
  "VST3:", "VST3i:", "VSTi:", "VST:", "AU:", "AUi:", "CLAP:", "CLAPi:",
}

-- Test whether a chain entry (plugin name or JSFX path) is installed on the
-- system by searching the enumerated FX list. Returns the full enumerated
-- name on match, or nil. JSFX paths match exactly; plugin names use a
-- case-insensitive substring match plus format-prefix preference.
function Code.resolve_chain_entry(entry, installed_list)
  -- Bundled-ReEQ fallback: check the filesystem regardless of what
  -- installed_list contains. EnumInstalledFX on macOS has been observed
  -- to omit our installed ReEQ.jsfx even after a REAPER restart while
  -- the file is unambiguously present at the canonical install path.
  -- Same coverage gap that the resolve handler already works around
  -- via Code.is_reeq_installed (mid-session filesystem check); we
  -- apply it to the chain walk too so the auto-pref slot populates
  -- without requiring a chat round-trip. Runs before the empty-list
  -- guard so it works even on a fresh launch where EnumInstalledFX
  -- hasn't returned any rows yet.
  if entry == "ReJJ/ReEQ/ReEQ.jsfx" and Code.is_reeq_installed() then
    return entry
  end
  if not installed_list or #installed_list == 0 then return nil end
  if entry:find("/", 1, true) then
    for _, inst in ipairs(installed_list) do
      if inst == entry or inst == "JS: " .. entry then return inst end
    end
    return nil
  end
  local entry_lower = entry:lower()
  local best, best_rank = nil, math.huge
  for _, inst in ipairs(installed_list) do
    if inst:lower():find(entry_lower, 1, true) then
      local rank = math.huge
      for i, p in ipairs(CHAIN_FORMAT_PREFIXES) do
        if inst:sub(1, #p) == p then rank = i; break end
      end
      if rank < best_rank then best, best_rank = inst, rank end
    end
  end
  return best
end

-- Walk every fallback chain and auto-assign pref_types[type] to the first
-- installed entry, ONLY when no existing preference is set. Never overwrites
-- user choices. Called at script load and after installing bundled plugins.
-- Idempotent; returns count of types newly assigned this call.
function Code.ensure_preferred_from_chains()
  local chains = Code.get_fallback_chains()
  if not next(chains) then return 0 end
  CTX.populate_installed_fx()
  local installed = CTX._installed_fx_list or {}
  local cache = FXCache.load()
  cache.preferred_types = cache.preferred_types or {}
  local hide_ff = reaper.GetExtState(CFG.EXT_NS, "dev_hide_fabfilter") == "1"
  -- Dev-only HideFabFilter override: when the flag is on AND the cached
  -- pref for a type is a FabFilter ident (Pro-Q 4 / Pro-C 3 / ...), treat
  -- the cached value as empty so the chain walk falls through to the next
  -- resolvable alternative (ReEQ for eq, etc.). This makes "Hide FabFilter"
  -- actually simulate a no-FabFilter install instead of just hiding the
  -- value at display time. The override is SESSION-ONLY: ephemeral_originals
  -- captures the pre-override values so we can restore them before
  -- persisting to disk -- toggling HideFabFilter back off must restore the
  -- user's real preferred plugin (e.g. Pro-Q 4) cleanly.
  local ephemeral_originals = {}
  local assigned = 0
  local sorted_types = {}
  for k in pairs(chains) do sorted_types[#sorted_types+1] = k end
  table.sort(sorted_types)
  for _, type_key in ipairs(sorted_types) do
    local original = cache.preferred_types[type_key]
    local existing = original
    local overridden = false
    if hide_ff and existing and existing ~= ""
        and _is_fabfilter_ident(existing) then
      existing = ""
      overridden = true
    end
    if not existing or existing == "" then
      local chain_list = chains[type_key].chain or {}
      for _, entry in ipairs(chain_list) do
        if Code.resolve_chain_entry(entry, installed) then
          -- Canonicalize the chain-entry form to AddByName-ready prefixed
          -- form before storing. Chain entries are intentionally format-
          -- agnostic ("Twin 3"), but the model + TrackFX_AddByName work
          -- more reliably with the prefixed form ("VST3i: Twin 3").
          local canonical = FXCache.canonicalize_identifier(type_key, entry)
          cache.preferred_types[type_key] = canonical
          Log.line("PREF", str_format(
            "auto-assigned preferred_types.%s = %s%s%s",
            type_key, canonical,
            (canonical ~= entry) and " (canonicalized from " .. entry .. ")" or "",
            overridden and " (ephemeral; hide_fabfilter override of "
              .. tostring(original) .. ")" or " (from chain)"))
          assigned = assigned + 1
          if overridden then ephemeral_originals[type_key] = original end
          break
        end
      end
    end
  end
  -- One-time-per-session migration of any legacy bare-name entries that
  -- this run didn't touch (entries that already had a value when this
  -- function was called, so the chain-walk above skipped them). Runs
  -- after the chain assignment so newly-assigned entries are already
  -- canonical and the migration finds nothing to do for them.
  FXCache.canonicalize_all_preferred_types()
  if assigned > 0 then
    if next(ephemeral_originals) then
      -- Snapshot-and-restore: write the rolled-back values to disk, then
      -- re-apply the in-memory overrides so the rest of the session keeps
      -- using the simulated alternatives. Both `cache` and the table held
      -- in FXCache._fx_cache_mem are the same Lua table, so restoring
      -- `cache.preferred_types[k]` also updates the module-level cache
      -- that FXCache.load returns to other callers.
      --
      -- Save is wrapped in pcall and the in-memory restore runs
      -- unconditionally: if FXCache.save errors mid-write (disk full /
      -- permission failure surfaces a message-box from Code.safe_write),
      -- we still want the session to keep simulating "no FabFilter".
      -- Without unconditional restore, an error here would leave
      -- cache.preferred_types[k] at the original FabFilter ident (the
      -- value we just swapped in for the save), silently breaking the
      -- HideFabFilter override until the next ReaAssist relaunch.
      local in_memory_values = {}
      for k in pairs(ephemeral_originals) do
        in_memory_values[k] = cache.preferred_types[k]
      end
      for k, original_v in pairs(ephemeral_originals) do
        cache.preferred_types[k] = original_v
      end
      -- FXCache.save returns nil on success or an error STRING on failure
      -- (it does not raise). pcall therefore returns (true, err_string) on
      -- the failure path, so the previous `if not ok` guard alone never
      -- caught a normal save error. Capture the function's return value
      -- too and log when it's non-nil, otherwise the operator triaging a
      -- "HideFabFilter override didn't persist" report would see no log
      -- breadcrumb at all.
      local ok, save_ret = pcall(FXCache.save, cache)
      for k, mem_v in pairs(in_memory_values) do
        cache.preferred_types[k] = mem_v
      end
      if not ok then
        Log.line("PREF", "FXCache.save raised during HideFabFilter "
                       .. "rollback; in-memory override preserved: "
                       .. tostring(save_ret))
      elseif save_ret then
        Log.line("PREF", "FXCache.save failed during HideFabFilter "
                       .. "rollback; in-memory override preserved: "
                       .. tostring(save_ret))
      end
    else
      local save_err = FXCache.save(cache)
      if save_err then
        Log.line("PREF", "FXCache.save failed (HideFabFilter assign): "
                       .. tostring(save_err))
      end
    end
  end
  return assigned
end

-- =============================================================================
-- Utility: Code._save_generated (internal)
-- =============================================================================
-- Shared save-dialog + write flow used by Code.save_file and
-- Code.save_file_jsfx. Opens a native save dialog when js_ReaScriptAPI is
-- present; otherwise falls back to a GetUserInputs prompt and strips path
-- separators from the input so the user cannot escape opts.base_dir.
-- Returns the saved path on success, or nil plus a reason on cancellation/error.
function Code._save_generated(code, suggested_name, opts)
  local dest_path
  local save_dialog = reaper.ReaAssist_Native_JS_Dialog_BrowseForSaveFile
    or reaper.JS_Dialog_BrowseForSaveFile
  if S and S.screen_reader_mode then
    save_dialog = nil
  end
  if save_dialog then
    local ok, ret, path = pcall(save_dialog,
      opts.dialog_title, opts.base_dir, suggested_name, opts.filter)
    if not ok then
      local first_err = ret
      ok, ret, path = pcall(save_dialog, opts.dialog_title, opts.base_dir,
        suggested_name, opts.filter, false)
      if not ok and Log and Log.line then
        Log.line("SAVE", "save dialog failed: " .. tostring(first_err)
          .. "; retry failed: " .. tostring(ret))
      end
    end
    if not ok then
      return nil, "dialog_failed"
    end
    if ret ~= 1 or not path or path == "" then return nil, "cancelled" end
    -- Lower-case the path before matching ext_pattern. Filesystems on
    -- Windows / macOS preserve the typed case, so a user who picks
    -- "MyScript.LUA" in the dialog used to fall through the case-
    -- sensitive `%.lua$` pattern and we'd append .lua, producing the
    -- ugly double-extension MyScript.LUA.lua.
    if not path:lower():match(opts.ext_pattern) then path = path .. opts.ext end
    dest_path = path
  else
    local ret, name = reaper.GetUserInputs(
      opts.fallback_title, 1, opts.fallback_label, suggested_name)
    if not ret or name == "" then return nil, "cancelled" end
    if not name:lower():match(opts.ext_pattern) then name = name .. opts.ext end
    name = name:match("[^\\/]+$") or name
    dest_path = opts.base_dir .. RA.SEP .. name
  end
  if Code.safe_write(dest_path, code) then return dest_path end
  return nil, "write_failed"
end

-- Save JSFX code to REAPER's Effects folder (thin wrapper over _save_generated).
function Code.save_file_jsfx(code, suggested_name)
  return Code._save_generated(code, suggested_name, {
    dialog_title   = (RA and RA.t and RA.t(
      "code.save_jsfx.dialog_title", nil, "Save JSFX Effect"))
      or "Save JSFX Effect",
    base_dir       = reaper.GetResourcePath() .. RA.SEP .. "Effects",
    filter         = (RA and RA.t and RA.t("code.save_jsfx.filter", nil,
      "JSFX files (.jsfx)\0*.jsfx\0All files\0*.*\0"))
      or "JSFX files (.jsfx)\0*.jsfx\0All files\0*.*\0",
    ext            = ".jsfx",
    ext_pattern    = "%.jsfx$",
    fallback_title = (RA and RA.t and RA.t(
      "code.save_jsfx.fallback_title", nil, "Save JSFX")) or "Save JSFX",
    fallback_label = (RA and RA.t and RA.t("code.save_jsfx.fallback_label",
      nil, "Filename (saved to REAPER Effects folder):,extrawidth=260"))
      or "Filename (saved to REAPER Effects folder):,extrawidth=260",
  })
end

-- Save Lua script to REAPER's Scripts folder (thin wrapper over _save_generated).
function Code.save_file(code, suggested_name)
  return Code._save_generated(code, suggested_name, {
    dialog_title   = (RA and RA.t and RA.t(
      "code.save_lua.dialog_title", nil, "Save Lua Script"))
      or "Save Lua Script",
    base_dir       = reaper.GetResourcePath() .. RA.SEP .. "Scripts",
    filter         = (RA and RA.t and RA.t("code.save_lua.filter", nil,
      "Lua files (.lua)\0*.lua\0All files\0*.*\0"))
      or "Lua files (.lua)\0*.lua\0All files\0*.*\0",
    ext            = ".lua",
    ext_pattern    = "%.lua$",
    fallback_title = (RA and RA.t and RA.t(
      "code.save_lua.fallback_title", nil, "Save Script")) or "Save Script",
    fallback_label = (RA and RA.t and RA.t("code.save_lua.fallback_label",
      nil, "Filename (saved to REAPER Scripts folder):,extrawidth=260"))
      or "Filename (saved to REAPER Scripts folder):,extrawidth=260",
  })
end

-- Strips API keys and secrets from URLs/error strings before they reach the
-- UI. Covers ?key= / &key= style query params (case-insensitive) and Bearer
-- tokens in headers. Lua patterns do not support alternation, so each secret
-- name is scrubbed with its own gsub; an earlier "one-pattern" attempt used a
-- pipe character that matches literally, so it never fired.
local SCRUB_KEYS = {
  "[Kk][Ee][Yy]",
  "[Tt][Oo][Kk][Ee][Nn]",
  "[Ss][Ee][Cc][Rr][Ee][Tt]",
  "[Aa][Pp][Ii][_]?[Kk][Ee][Yy]",
  "[Aa][Cc][Cc][Ee][Ss][Ss][_][Tt][Oo][Kk][Ee][Nn]",
  "[Pp][Aa][Ss][Ss][Ww][Oo][Rr][Dd]",
}
-- Shared scrubber: both Log.add_error and Diag.add_error route error
-- strings through this before display / storage. SCRUB_KEYS stays a
-- local because nothing else references it.
function Log.scrub_url_secrets(s)
  if not s then return s end
  for _, name in ipairs(SCRUB_KEYS) do
    s = s:gsub("([?&]" .. name .. "=)[^&%s\"']+", "%1***")
  end
  s = s:gsub("([Bb]earer%s+)[^%s\"']+", "%1***")
  return s
end

-- Queue an error message into S.display_messages as an assistant turn,
-- flip S.status to "error", clear in-flight timers, and scroll to bottom.
-- Optional link_url/link_label render a clickable URL beneath the text.
-- Optional `recovery` renders inline recovery buttons scoped by provider/model
-- metadata on the message. `extra` can stamp recovery-specific payload such as
-- a saved prompt or fallback model id.
function Log.add_error(msg, link_url, link_label, recovery, extra)
  S.status             = "error"
  S.send_time          = nil
  S.request_start_time = nil
  local entry = {
    role       = "assistant",
    content    = Log.scrub_url_secrets(msg),
    link_url   = link_url,
    link_label = link_label,
    recovery   = recovery,
  }
  if recovery == "token_limit" or recovery == "google_model_capacity" then
    local p = PROVIDERS.active()
    entry.provider_id = p and p.id or nil
  end
  if type(extra) == "table" then
    for k, v in pairs(extra) do entry[k] = v end
  end
  if entry.recovery_kind == nil and recovery ~= nil then
    entry.recovery_kind = recovery
  end
  if entry.assistant_response_status == nil then
    entry.assistant_response_status = (recovery == "token_limit")
      and "empty" or "error"
  end
  if entry.code_block_present == nil then entry.code_block_present = false end
  if entry.validation_status == nil then entry.validation_status = "not_applicable" end
  if entry.error_kind == nil and recovery == "token_limit" then
    entry.error_kind = "model_no_usable_answer"
    entry.error_debug = entry.error_debug or {
      failure_kind = "model_empty_response",
      recovery_kind = recovery,
    }
  end
  if entry.run_status == nil then
    if entry.assistant_response_status == "empty" then
      entry.run_status = "no_usable_answer"
    elseif entry.error_kind ~= nil or entry.error_debug ~= nil then
      entry.run_status = "provider_failed"
    else
      entry.run_status = "request_error"
    end
  end
  S.display_messages[#S.display_messages+1] = entry
  S.scroll_to_bottom = true
end

-- =============================================================================
-- Diag -- Diagnostic report builder for bug reports
-- =============================================================================
-- Captures recent code-execution errors and assembles a plain-text diagnostic
-- report the user can copy to their clipboard and paste into a bug report.

-- Schema version stamped into every saved FX cache file. Bump when the
-- on-disk structure changes in a way old code can't safely read. Files
-- with a missing or mismatched version are discarded cleanly on load
-- (fresh scan rebuilds the cache rather than silently misreading it).
-- Declared here (above Diag) because Diag.build_report reads it for the
-- diagnostic report's Plugin System section.
local FXCACHE_VERSION = 1

Diag = { errors = {}, MAX_ERRORS = 20 }

function Diag.add_error(msg, traceback, code)
  local entry = {
    time = os.date("%Y-%m-%d %H:%M:%S"),
    msg  = Log.scrub_url_secrets(tostring(msg)),
    traceback = traceback and Log.scrub_url_secrets(tostring(traceback)) or nil,
    code = code and (code:sub(1, 500) .. (#code > 500 and "..." or "")) or nil,
  }
  Diag.errors[#Diag.errors + 1] = entry
  if #Diag.errors > Diag.MAX_ERRORS then
    table.remove(Diag.errors, 1)
  end
end

-- opts (optional table):
--   skip_followup_note = true  -- omit the trailing "For detailed bugs..."
--                                 guidance paragraph. Used when the report
--                                 is embedded in a pre-filled email body
--                                 that already surfaces its own log-attach
--                                 instruction, so the two don't repeat.
function Diag.build_report(opts)
  local parts = {}
  -- Small pcall wrapper so a broken / missing extension probe can't
  -- crash the report build mid-stream.
  local function _try(fn) local ok, v = pcall(fn); if ok then return v end end
  -- On / Off formatter -- normalises booleans (and nil) to the
  -- ON / OFF convention the rest of the header already uses for
  -- "Auto model" / "Debug logging".
  local function _onoff(v) return v and "ON" or "OFF" end

  parts[#parts + 1] = "=== ReaAssist Diagnostic Report ==="
  parts[#parts + 1] = ""
  parts[#parts + 1] = "ReaAssist version: " .. CFG.VERSION
  parts[#parts + 1] = "REAPER version:    " .. tostring(reaper.GetAppVersion())
  parts[#parts + 1] = "OS:                " .. tostring(reaper.GetOS())
  -- ReaImGui version -- UI / rendering bugs hinge on this. Probe
  -- covers a few possible shapes across ReaImGui releases.
  local imgui_ver = _try(function()
    if not ImGui then return nil end
    if ImGui.ImGui_GetVersion then
      return select(1, ImGui.ImGui_GetVersion())
    end
    if ImGui.ReaImGui_Version then return ImGui.ReaImGui_Version end
  end)
  parts[#parts + 1] = "ReaImGui version:  " .. (imgui_ver and tostring(imgui_ver) or "unknown")
  parts[#parts + 1] = "Provider:          " .. (PROVIDERS.active().label or "unknown")
  parts[#parts + 1] = "Model:             " .. (MODELS.active_id() or "unknown")
  local p = PROVIDERS.active()
  if p.thinking_levels and p.thinking_levels[prefs.thinking_idx] then
    parts[#parts + 1] = "Thinking:          " .. p.thinking_levels[prefs.thinking_idx].label
  end
  -- Gemini paid-tier flag -- only meaningful when the active provider
  -- is Google, since it gates which models are visible and controls
  -- the "free tier data may be used for training" advisory.
  if p and p.id == "google" then
    parts[#parts + 1] = "Gemini paid tier:  " .. _onoff(S.gemini_paid_tier)
  end
  parts[#parts + 1] = "Debug logging:     " .. _onoff(prefs.debug_logging)
  if prefs.debug_logging then
    parts[#parts + 1] = "Log file:          " .. Log.path
    local f = io.open(Log.path, "r")
    if f then
      local size = f:seek("end") or 0
      f:close()
      parts[#parts + 1] = "Log file size:     " .. size .. " bytes"
    end
  end
  -- Current page / screen (which UI view the user was on when they copied
  -- the report). Useful for UI-specific bug reports.
  local screen = "chat"
  if api_keys.screen then
    screen = api_keys.screen
  elseif S.show_bug_report then screen = "bug_report"
  elseif S.show_help       then screen = "help"
  elseif S.show_credits    then screen = "credits"
  end
  parts[#parts + 1] = "Current screen:    " .. screen
  -- Session uptime -- seconds -> human-readable. Helps triage "UI
  -- froze after 6h" / "memory balloon" / long-session issues.
  local uptime_s = math_floor((reaper.time_precise() - (S.session_start_ts or reaper.time_precise())) + 0.5)
  local function _fmt_uptime(sec)
    if sec < 60 then return sec .. "s" end
    if sec < 3600 then
      return string.format("%dm %02ds", math_floor(sec / 60), sec % 60)
    end
    local h = math_floor(sec / 3600)
    local m = math_floor((sec % 3600) / 60)
    return string.format("%dh %02dm", h, m)
  end
  parts[#parts + 1] = "Session uptime:    " .. _fmt_uptime(uptime_s)
  parts[#parts + 1] = ""

  -- Required + optional REAPER extensions. Missing / old extensions
  -- cause a long tail of "button did nothing" / "file dialog didn't
  -- open" bugs that are otherwise a pain to diagnose.
  parts[#parts + 1] = "--- Extensions ---"
  local sws_ok  = reaper.CF_GetSWSVersion ~= nil
  local sws_ver = sws_ok and _try(function() return reaper.CF_GetSWSVersion("") end) or nil
  parts[#parts + 1] = "SWS:               " ..
    (sws_ok and (sws_ver and tostring(sws_ver) or "installed") or "not installed")
  local js_ver = _try(function() return reaper.JS_ReaScriptAPI_Version and reaper.JS_ReaScriptAPI_Version() end)
  parts[#parts + 1] = "js_ReaScriptAPI:   " ..
    (js_ver and tostring(js_ver) or "not installed")
  -- Probe the specific calls ReaAssist uses, so a partially-working
  -- extension (e.g. old SWS / JS build missing a newer symbol) shows
  -- up here too rather than reading as "fully installed."
  parts[#parts + 1] = "CF_ShellExecute:   " ..
    _onoff(reaper.CF_ShellExecute ~= nil)
  parts[#parts + 1] = "CF_LocateInExplorer: " ..
    _onoff(reaper.CF_LocateInExplorer ~= nil)
  parts[#parts + 1] = "JS_Dialog_BrowseForSaveFile: " ..
    _onoff(reaper.JS_Dialog_BrowseForSaveFile ~= nil)
  parts[#parts + 1] = ""

  -- User preferences
  parts[#parts + 1] = "--- Preferences ---"
  parts[#parts + 1] = "Auto-run:          " .. _onoff(prefs.auto_run)
  parts[#parts + 1] = "Auto-backup:       " .. _onoff(prefs.auto_backup)
  parts[#parts + 1] = "Include snapshot:  " .. _onoff(prefs.include_snapshot)
  parts[#parts + 1] = "Include API ref:   " .. _onoff(prefs.include_api_ref)
  parts[#parts + 1] = "Max history turns: " .. CFG.MAX_HISTORY_TURNS
  -- Cloud request timeout (seconds) -- affects "request hung" /
  -- "503 / timeout" bug reports directly.
  if prefs.cloud_request_timeout then
    parts[#parts + 1] = "Cloud timeout:     " .. tostring(prefs.cloud_request_timeout) .. "s"
  end
  parts[#parts + 1] = "API ref loaded:    " .. _onoff(
    S.api_ref_section_cache and S.api_ref_section_cache.core ~= nil)
  parts[#parts + 1] = "UI theme:          " .. tostring(prefs.theme or "default")
  local scale_val = CFG.UI_SCALE_OPTIONS[prefs.ui_scale_idx or 3] or 1.0
  parts[#parts + 1] = str_format("UI scale:          %.2fx", scale_val)
  -- API keys configured per provider (without revealing the keys). Helps
  -- diagnose "Test API Keys fails" or wrong-provider-selected reports.
  local configured = {}
  for _, pk in ipairs(PROVIDERS) do
    if S.api_key_map and S.api_key_map[pk.id] and S.api_key_map[pk.id] ~= "" then
      configured[#configured+1] = pk.label or pk.id
    end
  end
  parts[#parts + 1] = "API keys set:      " ..
    (#configured > 0 and tbl_concat(configured, ", ") or "(none)")
  parts[#parts + 1] = ""

  -- Plugin system state (chains, preferences, FX cache). Critical for
  -- diagnosing plugin-resolve / popup / auto-assign bugs.
  parts[#parts + 1] = "--- Plugin System ---"
  local ok_chains, chains = pcall(Code.get_fallback_chains)
  if ok_chains and chains then
    local chain_types = {}
    for k in pairs(chains) do chain_types[#chain_types+1] = k end
    table.sort(chain_types)
    parts[#parts + 1] = "Fallback chains loaded: " .. #chain_types
      .. (#chain_types > 0 and " (" .. tbl_concat(chain_types, ", ") .. ")" or "; check Plugin_Ref.md")
  else
    parts[#parts + 1] = "Fallback chains:        ERROR loading"
  end
  local ok_cache, fx_cache = pcall(FXCache.load)
  if ok_cache and fx_cache then
    local pref_types = fx_cache.preferred_types or {}
    local pref_keys = {}
    for k in pairs(pref_types) do pref_keys[#pref_keys+1] = k end
    table.sort(pref_keys)
    if #pref_keys == 0 then
      parts[#parts + 1] = "Preferred plugins:      (none set)"
    else
      parts[#parts + 1] = "Preferred plugins:"
      for _, k in ipairs(pref_keys) do
        parts[#parts + 1] = "  " .. k .. " = " .. tostring(pref_types[k])
      end
    end
    local plugin_count = 0
    for _ in pairs(fx_cache.plugins or {}) do
      plugin_count = plugin_count + 1
    end
    parts[#parts + 1] = "FX cache size:          " .. plugin_count .. " plugins scanned"
  end
  if CTX._installed_fx_list then
    parts[#parts + 1] = "Installed FX enumerated: " .. #CTX._installed_fx_list
  else
    parts[#parts + 1] = "Installed FX enumerated: (not populated yet this session)"
  end
  if ok_cache and fx_cache then
    parts[#parts + 1] = "FX cache schema:        v" .. tostring(fx_cache._version or "?")
      .. " (expected v" .. FXCACHE_VERSION .. ")"
  end
  -- Plugin_Ref.md status. Missing / unreadable file breaks chains + curated
  -- injection; size signals whether it looks truncated.
  local ref_path = RA.RESOURCES_DIR .. "Plugin_Ref.md"
  local rf = io.open(ref_path, "r")
  if rf then
    local sz = rf:seek("end") or 0
    rf:close()
    parts[#parts + 1] = "Plugin_Ref.md:          present (" .. sz .. " bytes)"
  else
    parts[#parts + 1] = "Plugin_Ref.md:          MISSING at " .. ref_path
  end
  parts[#parts + 1] = ""

  -- Recent Lua/runtime errors. Provider/request errors are stored on chat
  -- messages and appear in the Recent Chat section below.
  if #Diag.errors > 0 then
    parts[#parts + 1] = "--- Recent Lua/Runtime Errors (" .. #Diag.errors .. ") ---"
    for i, e in ipairs(Diag.errors) do
      parts[#parts + 1] = ""
      parts[#parts + 1] = "[" .. i .. "] " .. e.time
      parts[#parts + 1] = "  Error: " .. e.msg
      if e.traceback then
        parts[#parts + 1] = "  Traceback: " .. e.traceback
      end
      if e.code then
        parts[#parts + 1] = "  Code snippet: " .. e.code
      end
    end
  else
    parts[#parts + 1] = "--- No recent Lua/runtime errors ---"
    if S.status == "error" then
      parts[#parts + 1] =
        "Current chat status is error; see Recent Chat below for provider/request details."
    end
  end
  parts[#parts + 1] = ""

  -- Recent chat (last 5 exchanges, truncated) with details metadata.
  -- Trailing blank moved INSIDE the `if` so an empty chat doesn't
  -- leave a stray double-blank between "No recent errors" above and
  -- "Session State" below.
  if #S.display_messages > 0 then
    parts[#parts + 1] = "--- Recent Chat (last 5 exchanges, truncated) ---"
    local start = math.max(1, #S.display_messages - 9)
    for i = start, #S.display_messages do
      local m = S.display_messages[i]
      local content = m.content or ""
      if #content > 300 then content = content:sub(1, 300) .. "..." end
      parts[#parts + 1] = ""
      parts[#parts + 1] = "[" .. (m.role or "?") .. "] " .. content
      -- Include exchange details when available (context sent, tokens, cost).
      local details = {}
      if m.ctx_label   then details[#details + 1] = "context: " .. m.ctx_label end
      if m.model_label then details[#details + 1] = "model: " .. m.model_label end
      if m.error_kind  then details[#details + 1] = "error: " .. m.error_kind end
      if m.tok_in      then details[#details + 1] = "in: " .. m.tok_in end
      if m.tok_out     then details[#details + 1] = "out: " .. m.tok_out end
      if m.tok_cache_read and m.tok_cache_read > 0 then
        details[#details + 1] = "cache_read: " .. m.tok_cache_read
      end
      if m.tok_cache_create and m.tok_cache_create > 0 then
        details[#details + 1] = "cache_create: " .. m.tok_cache_create
      end
      if m.cost and m.cost > 0 then
        if m.free_tier and MODELS and MODELS.format_cost then
          details[#details + 1] = "cost: Free Tier (would have been ~"
            .. MODELS.format_cost(m.cost) .. ")"
        elseif MODELS and MODELS.format_cost then
          details[#details + 1] = "cost: " .. MODELS.format_cost(m.cost)
        else
          details[#details + 1] = str_format("cost: $%.4f", m.cost)
        end
      end
      if m.fx_cache_label then
        details[#details + 1] = "fx_cache: " .. m.fx_cache_label
      end
      if #details > 0 then
        parts[#parts + 1] = "  [" .. tbl_concat(details, " | ") .. "]"
      end
      -- Include generated code block if present (truncated).
      if m.code_block then
        local code = m.code_block
        if #code > 800 then code = code:sub(1, 800) .. "\n  ...(truncated)" end
        parts[#parts + 1] = "  Code block:"
        for cline in code:gmatch("[^\n]+") do
          parts[#parts + 1] = "    " .. cline
        end
      end
    end
    parts[#parts + 1] = ""
  end

  -- Status
  parts[#parts + 1] = "--- Session State ---"
  parts[#parts + 1] = "Status: " .. tostring(S.status)
  parts[#parts + 1] = "Messages: " .. #S.display_messages
  parts[#parts + 1] = "History turns: " .. #S.history
  -- In-flight request state. Only meaningful while a request is
  -- actually pending -- `S.send_time` is non-nil for the duration of
  -- the curl call and cleared on completion. Catches "my send is
  -- stuck" reports where the watchdog hasn't tripped yet.
  if S.send_time then
    local elapsed = reaper.time_precise() - S.send_time
    parts[#parts + 1] = str_format("In-flight request: started %.1fs ago", elapsed)
  end

  -- Resolve popup state: useful for diagnosing "popup didn't fire" reports.
  if S.resolve_popup then
    parts[#parts + 1] = "Resolve popup: ACTIVE (type=" ..
      tostring(S.resolve_popup.type) .. ")"
  elseif S.open_resolve_popup then
    parts[#parts + 1] = "Resolve popup: pending open"
  else
    parts[#parts + 1] = "Resolve popup: inactive"
  end

  -- Pending request state: captures an in-flight or stuck turn.
  local pending_bits = {}
  if S.pending_orig_prompt then pending_bits[#pending_bits+1] = "orig_prompt" end
  if S.pending_snapshot    then pending_bits[#pending_bits+1] = "snapshot"    end
  if S.pending_code        then pending_bits[#pending_bits+1] = "code"        end
  if S.pending_resolves and #S.pending_resolves > 0 then
    pending_bits[#pending_bits+1] = "queued_resolves=" ..
      tbl_concat(S.pending_resolves, ",")
  end
  if #pending_bits > 0 then
    parts[#parts + 1] = "Pending turn state: " .. tbl_concat(pending_bits, ", ")
  end

  -- Sticky context keys pinned this session (e.g. plugin_ref:Pro-Q 4). Shows
  -- what the preempt / resolve flow injected so "model got wrong params"
  -- reports can be traced.
  if S.sticky_context and next(S.sticky_context) then
    local sticky_keys = {}
    for k in pairs(S.sticky_context) do sticky_keys[#sticky_keys+1] = k end
    table.sort(sticky_keys)
    parts[#parts + 1] = "Sticky context pinned: " ..
      tbl_concat(sticky_keys, ", ")
  end

  -- Last script execution result (from the most recent generated-code run).
  -- Captures compile + runtime errors from user-run code. Errors get cleared
  -- on next send, so a non-nil here means "the last thing the user saw".
  if S.last_run_error and S.last_run_error ~= "" then
    parts[#parts + 1] = "Last script error: " .. tostring(S.last_run_error)
  end

  -- FX scan state: catches stuck/in-flight rescans.
  if fx_cache_ui and fx_cache_ui.rescan and fx_cache_ui.rescan.active then
    parts[#parts + 1] = "FX scan in progress: " ..
      tostring(fx_cache_ui.rescan.ident or "?")
  end
  if pref_plugins and pref_plugins.scan and pref_plugins.scan.active then
    parts[#parts + 1] = "Preferred-plugins scan in progress: " ..
      tostring(pref_plugins.scan.phase or "?")
  end

  -- Update-check state: "why isn't my update showing" reports.
  if update and update.state and update.state ~= "idle" then
    parts[#parts + 1] = "Update check state: " .. tostring(update.state)
      .. (update.remote_version and (" (remote v" .. update.remote_version .. ")") or "")
  end

  -- Follow-up note block. Skipped when the caller (the Feedback page's
  -- email flow) embeds this report inside an email body that already
  -- surfaces a tailored log-attach instruction of its own -- printing
  -- both creates redundant back-to-back "please attach the log" text.
  -- Default behaviour (used by the standalone Copy button) keeps the
  -- note in so a hand-pasted report carries the instruction with it.
  if not (opts and opts.skip_followup_note) then
    parts[#parts + 1] = ""
    parts[#parts + 1] = "For detailed bugs (wrong model output, multi-turn issues, API errors),"
    parts[#parts + 1] = "also attach the debug log: " .. Log.path
    parts[#parts + 1] = "Enable \"Enable Advanced Log\" on the Report a Bug page if it's off, reproduce, then send."
  end
  parts[#parts + 1] = ""
  parts[#parts + 1] = "=== End Report ==="
  return tbl_concat(parts, "\n")
end

-- =============================================================================
-- Context bucket functions
-- =============================================================================
-- Each takes a project pointer (proj) captured at send time and returns a
-- plain-text string describing a slice of that project's state. Track indices
-- are reported as 1-based for the assistant's benefit (REAPER API is 0-based).
-- =============================================================================
-- Unified FX parameter cache (JSON)
-- =============================================================================
-- Persists plugin parameter metadata (names, indices, defaults, enum values)
-- to FX_Cache.json. Two top-level maps:
--
--   preferred_types  -- user preferences (one plugin per type). Values are
--                       the chain-entry form (format-agnostic), e.g.
--                       "Pro-Q 4" or "ReJJ/ReEQ/ReEQ.jsfx". Populated either
--                       by Code.ensure_preferred_from_chains at startup or
--                       by user edits on the Preferred Plugins page.
--   plugins          -- live-scanned param data keyed by full enumerated FX
--                       name (e.g. "VST3: Pro-Q 4"). Only populated by
--                       user-triggered scans for non-curated plugins.
--
-- Structure:
--   {
--     "preferred_types": { "eq": "Pro-Q 4", ... },
--     "plugins": {
--       "VST3: Some Plugin": {
--         "param_count": 234,
--         "max_group": 24,
--         "params": [
--           { "idx": 0, "name": "1 Frequency", "default": 0.3040,
--             "display": "100.0 Hz" },
--           { "idx": 5, "name": "1 Shape", "default": 0.0,
--             "display": "Bell", "enum": ["Bell","Low Cut",...] }
--         ]
--       }
--     }
--   }


FXCache = {}

-- In-memory cache. Loaded lazily on first access, invalidated on save.
local _fx_cache_mem = nil

function FXCache.load()
  if _fx_cache_mem then return _fx_cache_mem end
  local ok_f, f = pcall(io.open, RA.FX_CACHE_PATH, "r")
  if not ok_f or not f then
    -- Stamp _version on every fresh-table return so the schema invariant
    -- doesn't depend on a save round-trip to land. Earlier shape varied
    -- per branch (no-file / empty / corrupt / schema-mismatch) which left
    -- a brief window where _fx_cache_mem._version was nil.
    _fx_cache_mem = { _version = FXCACHE_VERSION, preferred_types = {}, plugins = {} }
    return _fx_cache_mem
  end
  local content = f:read("*a")
  f:close()
  if not content or content == "" then
    _fx_cache_mem = { _version = FXCACHE_VERSION, preferred_types = {}, plugins = {} }
    return _fx_cache_mem
  end
  local data, err = JSON.decode(content)
  if not data then
    -- Surface the parse error to the debug log. Without this, the user
    -- silently loses their cache on a truncated or corrupted file with
    -- no breadcrumb to triage from -- only the schema-mismatch branch
    -- below logged.
    Log.line("FX_CACHE", "JSON decode failed (" .. tostring(err)
      .. "); discarding cache")
    _fx_cache_mem = { _version = FXCACHE_VERSION, preferred_types = {}, plugins = {} }
    return _fx_cache_mem
  end
  -- Reject files from a different schema version. Missing _version means
  -- the file was written before this field was added; treat it the same
  -- way -- start fresh rather than silently misread. User's only real
  -- loss is re-scanning plugins on next use.
  if data._version ~= FXCACHE_VERSION then
    Log.line("FX_CACHE", "schema version mismatch (file="
      .. tostring(data._version) .. ", expected=" .. FXCACHE_VERSION
      .. ") -- discarding cache")
    _fx_cache_mem = { _version = FXCACHE_VERSION, preferred_types = {}, plugins = {} }
    return _fx_cache_mem
  end
  -- Ensure required top-level keys exist.
  data.preferred_types = data.preferred_types or {}
  data.plugins = data.plugins or {}
  _fx_cache_mem = data
  return _fx_cache_mem
end

function FXCache.save(cache)
  cache = cache or _fx_cache_mem
  if not cache then return "No cache data to save." end
  -- Stamp the schema version so future builds can reject old files cleanly.
  cache._version = FXCACHE_VERSION
  local json_str, err = JSON.encode(cache, "  ")
  if not json_str then return "JSON encode failed: " .. tostring(err) end
  -- Atomic write: instance-scoped temp file + rename. AV scanners and abrupt
  -- exits can otherwise leave the 60+ KB cache JSON half-written, breaking
  -- parse on the next session.
  local write_err = Store.atomic_write_file(RA.FX_CACHE_PATH, json_str .. "\n",
    { suffix = Store._atomic_write_suffix() })
  if write_err then return write_err end
  _fx_cache_mem = cache
  return nil  -- success
end

function FXCache.get_plugin(identifier)
  local cache = FXCache.load()
  return cache.plugins[identifier]
end

-- Look up a plugin by fuzzy-matching the identifier against cache keys.
-- Uses bidirectional case-insensitive substring match (each direction catches
-- both "Pro-Q 4" in "VST3: Pro-Q 4 (FabFilter)" and vice versa).
function FXCache.find_plugin(name)
  local cache = FXCache.load()
  -- Exact match first.
  if cache.plugins[name] then return name, cache.plugins[name] end
  -- Fuzzy match against all cached identifiers. Pick the longest
  -- matching key (most specific) instead of `pairs`-first match: when
  -- two cached plugins share a common substring (e.g. "Pro-Q" and
  -- "Pro-Q 4 (FabFilter)") `pairs` order is hash-bucket-dependent, so
  -- the same lookup could pick either across saves/reloads. CTX.fx_params
  -- attaches the cached plugin's enum/range data via this lookup, so
  -- non-deterministic resolution corrupts the [enum: ...] annotation
  -- sent to the model.
  local name_lower = name:lower()
  local best_ident, best_data, best_len = nil, nil, -1
  for ident, data in pairs(cache.plugins) do
    local ident_lower = ident:lower()
    if ident_lower:find(name_lower, 1, true)
       or name_lower:find(ident_lower, 1, true) then
      if #ident > best_len then
        best_ident, best_data, best_len = ident, data, #ident
      end
    end
  end
  return best_ident, best_data
end

-- Mutation counter bumped whenever cache.plugins or cache.preferred_types
-- changes. Lets render-side code cheaply cache lists derived from these
-- (FX cache settings page, preempt scans) and invalidate on change
-- without having to thread invalidation calls through every mutator.
FXCache._mutation_count = 0

function FXCache.put_plugin(identifier, params_list, param_count, max_group, needs_deep_scan)
  local cache = FXCache.load()
  cache.plugins[identifier] = {
    param_count      = param_count or 0,
    max_group        = max_group or 0,
    params           = params_list,
    needs_deep_scan  = needs_deep_scan or nil,
  }
  FXCache._mutation_count = FXCache._mutation_count + 1
  return FXCache.save(cache)
end

function FXCache.remove_plugin(identifier)
  local cache = FXCache.load()
  cache.plugins[identifier] = nil
  FXCache._mutation_count = FXCache._mutation_count + 1
  return FXCache.save(cache)
end

function FXCache.clear_plugins()
  local cache = FXCache.load()
  cache.plugins = {}
  FXCache._mutation_count = FXCache._mutation_count + 1
  return FXCache.save(cache)
end

-- Wipe all type->plugin mappings. Used by the "Clear All" button on the
-- Preferred Plugins page. Does NOT touch cache.plugins (scanned param data
-- stays intact so we don't have to re-scan everything when the user reconfigures).
function FXCache.clear_preferred_types()
  local cache = FXCache.load()
  cache.preferred_types = {}
  FXCache._mutation_count = FXCache._mutation_count + 1
  return FXCache.save(cache)
end

-- Canonicalize an identifier to AddByName-ready form by resolving against
-- the installed-FX list (REAPER 7.42+'s EnumInstalledFX). Chain-entry form
-- ("Twin 3", "Pro-Q 4") is portable across plugin-format namespaces and is
-- what shows up in .RfxChain files, but TrackFX_AddByName works most
-- reliably with the prefixed form ("VST3i: Twin 3"). The model also picks
-- the right plugin format when it sees the prefix instead of guessing.
--
-- Returns (canonical, was_upgraded) where was_upgraded is true if the
-- input was normalized. Bare chain-entry forms resolve to prefixed forms,
-- and prefixed identifiers drop REAPER's trailing vendor suffix because
-- TrackFX_AddByName expects "VST3: Pro-Q 4", not
-- "VST3: Pro-Q 4 (FabFilter)".
-- If no match in installed-FX, or the FX list isn't available (REAPER < 7.42),
-- returns the identifier unchanged apart from safe prefixed-form cleanup.
--
-- type_key is used as a tie-breaker when multiple format variants of the
-- same plugin are installed (e.g., Twin 3 as both VST3i and AUi on Mac):
-- "synth" prefers instrument-variant prefixes (*i:); other types prefer
-- effect-variant prefixes. Without type_key, picks the first match.
local _ADDBYNAME_PREFIXES = {
  "VST3i", "VST3", "VSTi", "VST",
  "AUi", "AU",
  "CLAPi", "CLAP",
  "LV2i", "LV2",
  "DXi", "DX",
  "JS",
}
local _INSTRUMENT_PREFIXES = {
  VST3i = true, VSTi = true, AUi = true, CLAPi = true,
  LV2i = true, DXi = true,
}
local _INSTRUMENT_TYPES = { synth = true }

local function _split_addbyname_identifier(identifier)
  local prefix = identifier:match("^([A-Za-z][A-Za-z0-9]*):")
  if not prefix then return nil, nil end
  for _, p in ipairs(_ADDBYNAME_PREFIXES) do
    if prefix == p then
      local rest = identifier:match("^[A-Za-z][A-Za-z0-9]*:%s*(.+)$")
      return prefix, rest
    end
  end
  return nil, nil
end

local function _strip_vendor_suffix(name)
  -- "VST3: Pro-Q 4 (FabFilter)" -> "VST3: Pro-Q 4". Chain-entry form
  -- doesn't include the vendor, so the canonical form drops it too.
  return (name:gsub("%s*%(.-%)%s*$", ""))
end

function FXCache.canonicalize_identifier(type_key, identifier)
  if not identifier or identifier == "" then return identifier, false end
  local prefixed_prefix, prefixed_rest = _split_addbyname_identifier(identifier)
  if prefixed_prefix and prefixed_rest then
    local stripped = _strip_vendor_suffix(prefixed_rest)
    stripped = stripped:match("^%s*(.-)%s*$") or stripped
    if stripped ~= "" then
      local canonical = prefixed_prefix .. ": " .. stripped
      return canonical, canonical ~= identifier
    end
    return identifier, false
  end
  if not CTX or not CTX.populate_installed_fx then return identifier, false end
  CTX.populate_installed_fx()
  local installed = CTX._installed_fx_list
  if not installed or #installed == 0 then return identifier, false end

  local target = _strip_vendor_suffix(identifier)
  target = (target:match("^%s*(.-)%s*$") or target):lower()
  local prefer_instrument = type_key and _INSTRUMENT_TYPES[type_key:lower()] or false
  -- Match against the bare base name (after stripping the AddByName prefix
  -- and a trailing " (Vendor)" suffix), then return the cleaned prefixed
  -- form. The installed list is still the source of truth for the format
  -- prefix, but vendor text is display metadata that breaks AddByName on
  -- some VST3 plugins.
  local best, best_rank = nil, -1
  for _, full in ipairs(installed) do
    local prefix, rest = full:match("^([A-Za-z][A-Za-z0-9]*):%s*(.+)$")
    if prefix and rest then
      local base = _strip_vendor_suffix(rest):lower()
      if base == target then
        local is_instr = _INSTRUMENT_PREFIXES[prefix] == true
        -- Rank prefers (instrument-match for synth-type), then prefers
        -- earlier-in-list (which is roughly REAPER's preferred load order
        -- via _ADDBYNAME_PREFIXES).
        local rank = (prefer_instrument == is_instr) and 1000 or 0
        for i, p in ipairs(_ADDBYNAME_PREFIXES) do
          if prefix == p then rank = rank + (#_ADDBYNAME_PREFIXES - i); break end
        end
        if rank > best_rank then
          best, best_rank = full, rank
        end
      end
    end
  end
  if best then
    local canonical = FXCache.canonicalize_identifier(type_key, best)
    return canonical, canonical ~= identifier
  end
  return identifier, false
end

function FXCache.set_preferred_type(type_key, identifier)
  -- Canonicalize before storing so the on-disk form is AddByName-ready.
  -- Logs the upgrade once (per write) so the operator sees that the legacy
  -- bare-name input was upgraded.
  local canonical, upgraded = FXCache.canonicalize_identifier(type_key, identifier)
  if upgraded then
    Log.line("PREF", str_format(
      "preferred_types.%s = %s -> %s (canonicalized on save)",
      type_key, identifier, canonical))
  end
  local cache = FXCache.load()
  cache.preferred_types[type_key] = canonical
  FXCache._mutation_count = FXCache._mutation_count + 1
  return FXCache.save(cache)
end

-- One-time-per-session migration. Walks cache.preferred_types and upgrades
-- any bare chain-entry forms ("Twin 3") to AddByName-ready prefixed form
-- ("VST3i: Twin 3") via FXCache.canonicalize_identifier. Logs each upgrade
-- as `preferred_types.<type> = old -> new` so legacy data drift is visible
-- once. Saves the cache only if any entry was actually upgraded.
--
-- Idempotent: a second call after the first does nothing because every
-- entry is already prefixed. Safe to call from multiple entry points
-- (Code.ensure_preferred_from_chains startup, render-side first paint).
function FXCache.canonicalize_all_preferred_types()
  if FXCache._canonicalized_session then return 0 end
  if not CTX or not CTX.populate_installed_fx then return 0 end
  CTX.populate_installed_fx()
  if not CTX._installed_fx_list or #CTX._installed_fx_list == 0 then
    -- REAPER < 7.42 or empty FX library. Defer; another call may succeed
    -- once the list is populated. Don't mark as done.
    return 0
  end
  local cache = FXCache.load()
  local upgraded_count = 0
  for type_key, identifier in pairs(cache.preferred_types or {}) do
    local canonical, upgraded = FXCache.canonicalize_identifier(type_key, identifier)
    if upgraded then
      Log.line("PREF", str_format(
        "preferred_types.%s = %s -> %s (canonicalized on load)",
        type_key, identifier, canonical))
      cache.preferred_types[type_key] = canonical
      upgraded_count = upgraded_count + 1
    end
  end
  FXCache._canonicalized_session = true
  if upgraded_count > 0 then
    FXCache._mutation_count = FXCache._mutation_count + 1
    local save_err = FXCache.save(cache)
    if save_err then Store._notify_write_failure("FX cache", save_err) end
  end
  return upgraded_count
end

function FXCache.get_preferred_types()
  local cache = FXCache.load()
  return cache.preferred_types
end

function FXCache.invalidate()
  _fx_cache_mem = nil
  FXCache._mutation_count = (FXCache._mutation_count or 0) + 1
  -- Clear the session migration flag too so a fresh load (e.g., after a
  -- corrupt-cache reset, an external edit, or a manual reload) will
  -- re-run canonicalization on whatever's now on disk.
  FXCache._canonicalized_session = nil
end

-- =============================================================================
-- Context bucket builders (CTX)
-- =============================================================================
-- Stored in a table to conserve top-level local variable slots
-- (Lua 5.x 200-local limit). Each function takes (proj) and returns a string.
-- =============================================================================
-- Context sidecar load (eager, fail-closed)
-- =============================================================================
-- Loads the request-context runtime into a narrow environment. If it cannot load,
-- fallbacks keep startup/recovery usable while guarded send paths fail closed
-- before they depend on missing context helpers.
RA.Context = RA.Context or { loaded = false, error = nil }

function RA.context_unavailable_message(action)
  local suffix = action and tostring(action) or "before building context"
  return "Context runtime unavailable; repair or update ReaAssist " .. suffix .. "."
end

function RA.context_loaded()
  return RA.Context and RA.Context.loaded == true
end

function RA.fail_context_unavailable(action, status)
  local msg = RA.context_unavailable_message(action)
  if Log and Log.add_error then Log.add_error(msg) end
  if S then
    S.status = status or "idle"
    S.scroll_to_bottom = true
  end
  return false
end

function RA.install_context_fallbacks(reason)
  RA.Context = RA.Context or {}
  RA.Context.loaded = false
  RA.Context.error = tostring(reason or "unknown error")
  if Log and Log.line then
    Log.line("CONTEXT", "Context.lua unavailable: " .. RA.Context.error)
  end

  -- Keep every main-file call site callable in degraded mode. Public send paths
  -- still block on RA.context_loaded(), so these stubs are for recovery and
  -- defensive cleanup rather than a partial context runtime.
  CTX = CTX or {}
  CTX._installed_fx_list = CTX._installed_fx_list or {}
  CTX._installed_fx_list_deduped = CTX._installed_fx_list_deduped or {}
  _is_fabfilter_ident = _is_fabfilter_ident or function() return false end

  local function unavailable(action)
    return RA.context_unavailable_message(action)
  end
  local function unavailable_err(action)
    return nil, unavailable(action)
  end
  local function false_unavailable(action)
    return false, unavailable(action)
  end

  function CTX.reaper_version()
    return "REAPER version: " .. tostring(reaper.GetAppVersion and reaper.GetAppVersion() or "unknown")
  end
  function CTX.reaassist_version()
    return "ReaAssist version: " .. tostring(CFG.VERSION or "unknown")
  end
  function CTX.extension_status()
    return unavailable("before reading extension status")
  end
  function CTX.ai_selection_status()
    return unavailable("before reading AI selection")
  end
  function CTX.reaassist_settings_status()
    return unavailable("before reading ReaAssist settings")
  end
  function CTX.diagnostics_status()
    return unavailable("before reading diagnostics settings")
  end
  function CTX.local_read_answer()
    return nil
  end
  function CTX.preempt_buckets_for_prompt()
    return nil
  end
  function CTX.build_snapshot()
    return unavailable("before building project context")
  end
  CTX.PLUGIN_REF_ALIASES = CTX.PLUGIN_REF_ALIASES or {}
  CTX.CHAIN_PHRASE_HINTS = CTX.CHAIN_PHRASE_HINTS or {}
  function CTX.resolve_pending_project()
    return reaper.EnumProjects and reaper.EnumProjects(-1) or 0
  end
  function CTX.docs_section_list() return "" end
  function CTX.curated_for_ident() return nil end

  function CTX.docs() return unavailable_err("before loading REAPER docs") end
  function CTX.docs_section_canonical() return nil end
  function CTX.docs_extended() return unavailable_err("before loading extended docs") end
  function CTX.docs_section() return unavailable_err("before loading docs sections") end
  function CTX.recent_reaper_changes() return unavailable_err("before loading recent changes") end
  function CTX.prompt_bundle() return unavailable_err("before loading prompt bundles") end
  function CTX.midi() return unavailable_err("before loading MIDI reference") end
  function CTX.theme() return unavailable_err("before loading theme reference") end
  function CTX.plugin_ref() return unavailable_err("before loading plugin reference") end
  function CTX.installed_fx() return unavailable_err("before reading installed FX") end
  function CTX.preferred_plugins() return unavailable_err("before reading preferred plugins") end
  function CTX.fx_params() return unavailable_err("before scanning FX parameters") end
  function CTX.fx_inspect_load() return nil, nil, nil, unavailable("before inspecting FX") end
  function CTX.format_fx_params() return unavailable("before formatting FX parameters") end
  function CTX.scan_fx_params() return {}, 0, 0, false end
  function CTX.scan_fx_params_deep_body() return false_unavailable("before deep-scanning FX parameters") end

  function CTX.fx_filter_parse(payload)
    return { name = tostring(payload or "") }
  end
  function CTX.fx_filter_key(filters)
    local parts = {}
    if type(filters) == "table" then
      for i, entry in ipairs(filters) do
        parts[i] = type(entry) == "table" and tostring(entry.name or "") or tostring(entry or "")
      end
    end
    return table.concat(parts, "/")
  end
  function CTX.fx_filter_names_only(filters)
    local names = {}
    if type(filters) == "table" then
      for _, entry in ipairs(filters) do
        names[#names + 1] = type(entry) == "table" and tostring(entry.name or "") or tostring(entry or "")
      end
    end
    return names
  end
  function CTX.fx_name_matches() return false end
  function CTX.populate_installed_fx()
    CTX._installed_fx_list = {}
    CTX._installed_fx_list_deduped = {}
    return false
  end
  function CTX.ensure_plugin_ref_cache() return false end

  function CTX.load_pref_plugins() return false end
  function CTX.save_pref_plugins() return unavailable("before saving preferred plugins") end
  function CTX.pref_plugins_scan_start()
    if pref_plugins and pref_plugins.scan then
      pref_plugins.scan.active = false
      pref_plugins.scan.status = unavailable("before scanning preferred plugins")
    end
    return false
  end
  function CTX.pref_plugins_scan_read()
    if pref_plugins and pref_plugins.scan then pref_plugins.scan.active = false end
    return false
  end
  function CTX.start_deep_scan(opts)
    if type(opts) == "table" and type(opts.on_cancel) == "function" then
      opts.on_cancel("context_runtime_unavailable")
    end
    return false
  end
  function CTX.pump_deep_scan()
    if deep_scan then deep_scan.active = false end
    return false
  end
  function CTX.cancel_deep_scan()
    if deep_scan then deep_scan.active = false end
    return false
  end

  Theme = Theme or {}
  Theme.restore_backups = Theme.restore_backups or function() end
  Theme.save_to_file = Theme.save_to_file or function()
    return false, unavailable("before saving theme changes")
  end

  label_to_type_key = label_to_type_key or function(label)
    local canonical = tostring(label or "")
    canonical = (canonical:match("^%s*(.-)%s*$") or ""):lower()
    canonical = canonical:gsub("[%s%-]+", "_")
    return (PREF_PLUGIN_ALIASES and PREF_PLUGIN_ALIASES[canonical]) or canonical
  end
  pref_plugins_best_match = pref_plugins_best_match or function() return nil, 0 end
  pref_plugins_rank_matches = pref_plugins_rank_matches or function() return {} end

  Code = Code or {}
  Code.is_curated_plugin = Code.is_curated_plugin or function() return false end
  Code.get_stock_fallback = Code.get_stock_fallback or function() return nil end
end

function RA.load_context()
  RA.Context = RA.Context or {}
  local path = RA.RESOURCES_DIR .. "Context.lua"
  local env = setmetatable({
    CTX = CTX or {},
    str_format = str_format,
    tbl_concat = tbl_concat,
    read_file_text = read_file_text,
    math_floor = math_floor,
    math_min = math_min,
    math_max = math_max,
    time_precise = time_precise,
    R_CountTracks = R_CountTracks,
    R_GetTrack = R_GetTrack,
    R_GetTrackName = R_GetTrackName,
    R_CountTrackMediaItems = R_CountTrackMediaItems,
    R_GetMediaTrackInfo_Value = R_GetMediaTrackInfo_Value,
    R_IsTrackSelected = R_IsTrackSelected,
    R_TrackFX_GetCount = R_TrackFX_GetCount,
    R_TrackFX_GetFXName = R_TrackFX_GetFXName,
    R_TrackFX_GetNumParams = R_TrackFX_GetNumParams,
    R_TrackFX_GetParamName = R_TrackFX_GetParamName,
    R_TrackFX_GetParam = R_TrackFX_GetParam,
    R_TrackFX_GetFormattedParamValue = R_TrackFX_GetFormattedParamValue,
    R_CountSelectedMediaItems = R_CountSelectedMediaItems,
    R_GetSelectedMediaItem = R_GetSelectedMediaItem,
    R_GetMediaItemInfo_Value = R_GetMediaItemInfo_Value,
    R_GetMediaItem_Track = R_GetMediaItem_Track,
    R_EnumProjectMarkers3 = R_EnumProjectMarkers3,
    R_CountProjectMarkers = R_CountProjectMarkers,
    PREF_PLUGIN_ALIASES = PREF_PLUGIN_ALIASES,
  }, { __index = _G })
  local chunk, load_err = loadfile(path, "t", env)
  if not chunk then
    RA.install_context_fallbacks(load_err)
    return false
  end
  local ok, err = pcall(chunk)
  if not ok then
    RA.install_context_fallbacks(err)
    return false
  end

  CTX = env.CTX or CTX
  _is_fabfilter_ident = env._is_fabfilter_ident or _is_fabfilter_ident
  Theme = env.Theme or Theme
  label_to_type_key = env.label_to_type_key or label_to_type_key
  pref_plugins_best_match = env.pref_plugins_best_match or pref_plugins_best_match
  pref_plugins_rank_matches = env.pref_plugins_rank_matches or pref_plugins_rank_matches

  local required = {
    { "CTX.docs", CTX and CTX.docs },
    { "CTX.docs_section_canonical", CTX and CTX.docs_section_canonical },
    { "CTX.docs_section_list", CTX and CTX.docs_section_list },
    { "CTX.preempt_buckets_for_prompt", CTX and CTX.preempt_buckets_for_prompt },
    { "CTX.build_snapshot", CTX and CTX.build_snapshot },
    { "CTX.resolve_pending_project", CTX and CTX.resolve_pending_project },
    { "CTX.curated_for_ident", CTX and CTX.curated_for_ident },
    { "CTX.CHAIN_PHRASE_HINTS", CTX and CTX.CHAIN_PHRASE_HINTS, "table" },
    { "_is_fabfilter_ident", _is_fabfilter_ident },
    { "Theme.restore_backups", Theme and Theme.restore_backups },
    { "Theme.save_to_file", Theme and Theme.save_to_file },
    { "label_to_type_key", label_to_type_key },
    { "pref_plugins_best_match", pref_plugins_best_match },
    { "pref_plugins_rank_matches", pref_plugins_rank_matches },
    { "Code.is_curated_plugin", Code and Code.is_curated_plugin },
    { "Code.get_stock_fallback", Code and Code.get_stock_fallback },
  }
  for _, item in ipairs(required) do
    if type(item[2]) ~= (item[3] or "function") then
      RA.install_context_fallbacks("missing required context symbol: " .. item[1])
      return false
    end
  end

  RA.Context.loaded = true
  RA.Context.error = nil
  return true
end

RA.load_context()

-- =============================================================================
-- Auto-update module
-- =============================================================================
-- Non-blocking update checker. On startup (when prefs.update_check is on
-- and UPDATE_BASE_URL is configured) fires an async curl for manifest.json;
-- if a newer version exists the UI offers "Update Available". Each file
-- is fetched, SHA-256 verified against the manifest, and written to the
-- script directory (any hash mismatch rolls back the whole update). An
-- organic check failure stays silent (update.state = "idle"); only a
-- user-forced Repair surfaces errors via Updater._set_failure.
-- Manifest schema: see .tools/gen_manifest.py.

-- =============================================================================
-- SHA-256 (pure Lua, no external dependencies)
-- =============================================================================
-- Minimal implementation for update integrity verification. Operates on
-- 8-bit byte strings via string.byte. Lua 5.3+ bitwise operators; loaded
-- via load() so this whole block parses cleanly on older linters too.
--
-- Two interfaces:
--   sha256_hash(msg)              -- single-shot. Used by download_poll
--                                    where each file is small and gets
--                                    hashed once after a successful write.
--   _SHA.create(content)          -- chunked: returns state ready for step().
--   _SHA.step(state, max_blocks)  -- process up to N 64-byte blocks; returns
--                                    true when state is exhausted.
--   _SHA.finalize(state)          -- return hex digest of completed state.
--
-- Pure-Lua SHA-256 throughput on commodity hardware sits around ~1 MB/s
-- on Lua 5.4. The two largest manifest files (ReaAssist.lua and
-- UI.lua, ~700 KB each) take 600+ ms each in single-shot mode
-- which is a visible REAPER hitch. The chunked interface lets
-- Updater.tick_sha_diff process work for a per-frame time budget
-- (CFG.UPDATE_SHA_TIME_BUDGET), spreading the same total work across
-- many frames so each frame stays inside the budget regardless of CPU.
local sha256_hash
local _SHA = {}
do
  local band   = load("return function(a,b) return a & b end")()
  local bor    = load("return function(a,b) return a | b end")()
  local bxor   = load("return function(a,b) return a ~ b end")()
  local bnot   = load("return function(a) return ~a & 0xFFFFFFFF end")()
  local rshift = load("return function(a,n) return (a >> n) & 0xFFFFFFFF end")()
  local lshift = load("return function(a,n) return (a << n) & 0xFFFFFFFF end")()

  local function rrotate(x, n) return bor(rshift(x, n), lshift(x, 32 - n)) end

  local K = {
    0x428a2f98, 0x71374491, 0xb5c0fbcf, 0xe9b5dba5,
    0x3956c25b, 0x59f111f1, 0x923f82a4, 0xab1c5ed5,
    0xd807aa98, 0x12835b01, 0x243185be, 0x550c7dc3,
    0x72be5d74, 0x80deb1fe, 0x9bdc06a7, 0xc19bf174,
    0xe49b69c1, 0xefbe4786, 0x0fc19dc6, 0x240ca1cc,
    0x2de92c6f, 0x4a7484aa, 0x5cb0a9dc, 0x76f988da,
    0x983e5152, 0xa831c66d, 0xb00327c8, 0xbf597fc7,
    0xc6e00bf3, 0xd5a79147, 0x06ca6351, 0x14292967,
    0x27b70a85, 0x2e1b2138, 0x4d2c6dfc, 0x53380d13,
    0x650a7354, 0x766a0abb, 0x81c2c92e, 0x92722c85,
    0xa2bfe8a1, 0xa81a664b, 0xc24b8b70, 0xc76c51a3,
    0xd192e819, 0xd6990624, 0xf40e3585, 0x106aa070,
    0x19a4c116, 0x1e376c08, 0x2748774c, 0x34b0bcb5,
    0x391c0cb3, 0x4ed8aa4a, 0x5b9cca4f, 0x682e6ff3,
    0x748f82ee, 0x78a5636f, 0x84c87814, 0x8cc70208,
    0x90befffa, 0xa4506ceb, 0xbef9a3f7, 0xc67178f2,
  }

  -- Build incremental state from a plain content string. Pre-pads the
  -- message to a 64-byte boundary so subsequent step() calls only need
  -- to compress complete 64-byte blocks (no partial-block bookkeeping
  -- across calls). Pre-padding cost is O(n) memcpy, negligible vs the
  -- compression work that follows.
  function _SHA.create(content)
    local len = #content
    local extra = 64 - ((len + 9) % 64)
    if extra == 64 then extra = 0 end
    local msg = content .. "\128" .. ("\0"):rep(extra + 4)
       .. string.char(
            band(rshift(len * 8, 24), 0xFF),
            band(rshift(len * 8, 16), 0xFF),
            band(rshift(len * 8, 8), 0xFF),
            band(len * 8, 0xFF))
    return {
      msg = msg,
      pos = 1,                        -- next byte (1-indexed) to compress
      h0  = 0x6a09e667, h1 = 0xbb67ae85,
      h2  = 0x3c6ef372, h3 = 0xa54ff53a,
      h4  = 0x510e527f, h5 = 0x9b05688c,
      h6  = 0x1f83d9ab, h7 = 0x5be0cd19,
    }
  end

  -- Process up to max_blocks complete 64-byte chunks starting at
  -- state.pos. Updates state.h0..h7 and advances state.pos. Returns
  -- true when all blocks have been compressed (state ready for
  -- finalize), false when more remain. Pass math.huge to drain all
  -- remaining blocks in one call (single-shot mode).
  function _SHA.step(state, max_blocks)
    local msg = state.msg
    local total = #msg
    local h0, h1, h2, h3 = state.h0, state.h1, state.h2, state.h3
    local h4, h5, h6, h7 = state.h4, state.h5, state.h6, state.h7
    local pos = state.pos
    local processed = 0
    while pos <= total and processed < max_blocks do
      local W = {}
      for t = 1, 16 do
        local b = pos + (t - 1) * 4
        W[t] = lshift(string.byte(msg, b), 24)
             + lshift(string.byte(msg, b + 1), 16)
             + lshift(string.byte(msg, b + 2), 8)
             + string.byte(msg, b + 3)
      end
      for t = 17, 64 do
        local s0 = bxor(rrotate(W[t-15], 7),
                        bxor(rrotate(W[t-15], 18), rshift(W[t-15], 3)))
        local s1 = bxor(rrotate(W[t-2], 17),
                        bxor(rrotate(W[t-2], 19), rshift(W[t-2], 10)))
        W[t] = (W[t-16] + s0 + W[t-7] + s1) % 0x100000000
      end
      local a, b, c, d, e, f, g, h = h0, h1, h2, h3, h4, h5, h6, h7
      for t = 1, 64 do
        local S1 = bxor(rrotate(e, 6),
                        bxor(rrotate(e, 11), rrotate(e, 25)))
        local ch = bxor(band(e, f), band(bnot(e), g))
        local temp1 = (h + S1 + ch + K[t] + W[t]) % 0x100000000
        local S0 = bxor(rrotate(a, 2),
                        bxor(rrotate(a, 13), rrotate(a, 22)))
        local maj = bxor(band(a, b), bxor(band(a, c), band(b, c)))
        local temp2 = (S0 + maj) % 0x100000000
        h = g; g = f; f = e; e = (d + temp1) % 0x100000000
        d = c; c = b; b = a; a = (temp1 + temp2) % 0x100000000
      end
      h0 = (h0 + a) % 0x100000000; h1 = (h1 + b) % 0x100000000
      h2 = (h2 + c) % 0x100000000; h3 = (h3 + d) % 0x100000000
      h4 = (h4 + e) % 0x100000000; h5 = (h5 + f) % 0x100000000
      h6 = (h6 + g) % 0x100000000; h7 = (h7 + h) % 0x100000000
      pos = pos + 64
      processed = processed + 1
    end
    state.h0, state.h1, state.h2, state.h3 = h0, h1, h2, h3
    state.h4, state.h5, state.h6, state.h7 = h4, h5, h6, h7
    state.pos = pos
    return pos > total
  end

  function _SHA.finalize(state)
    return string.format("%08x%08x%08x%08x%08x%08x%08x%08x",
      state.h0, state.h1, state.h2, state.h3,
      state.h4, state.h5, state.h6, state.h7)
  end

  sha256_hash = function(msg)
    local s = _SHA.create(msg)
    _SHA.step(s, math.huge)
    return _SHA.finalize(s)
  end
end

-- Expose the updater's SHA helpers to sidecars. Diag.lua uses them when
-- available for feedback-upload integrity, and falls back internally if absent.
RA.sha256_hex = sha256_hash
RA.sha256_create = function(content) return _SHA.create(content) end
RA.sha256_step = function(state, max_blocks) return _SHA.step(state, max_blocks) end
RA.sha256_finalize = function(state) return _SHA.finalize(state) end

-- =============================================================================
-- Local deterministic action modules
-- =============================================================================
-- These sidecars hold focused, non-LLM feature implementations that are too
-- substantial to keep in ReaAssist.lua. They are non-critical at startup:
-- a missing/corrupt module disables that local action but must not prevent the
-- chat UI, updater, or recovery flow from loading.
RA.Local = RA.Local or {}
do
  local path = RA.RESOURCES_DIR .. "Local" .. RA.SEP .. "init.lua"
  if RA._file_exists(path) then
    local ok, modules = pcall(dofile, path)
    if ok and type(modules) == "table" then
      for name, module in pairs(modules) do
        RA.Local[name] = module
      end
    elseif type(Log) == "table" and type(Log.line) == "function" then
      Log.line("LOCAL",
        "Optional local module loader failed; local-only features disabled.")
    end
  end
end

-- Cross-chunk namespace. The UI file's Update-Available and File-
-- Integrity dialogs call Updater.download_start / Updater.force_reinstall,
-- so this table must be a plain global (chunk-local `local` would make
-- it invisible to the dofile'd UI chunk). The state table next to it is
-- lowercase `update`.
Updater = {}

function Updater.url_encode_path(path)
  return tostring(path or ""):gsub("([^%w%-%._~/])", function(ch)
    return string.format("%%%02X", string.byte(ch))
  end)
end

function Updater.url_for(filename)
  local base = tostring(CFG.UPDATE_BASE_URL or ""):gsub("/+$", "")
  return base .. "/" .. Updater.url_encode_path(filename)
end

-- Stamp a structured failure reason onto the update state so the
-- Bootstrap repair prompt can show the user *why* the last attempt
-- failed instead of silently re-rendering the Repair button. Also
-- emits a Log.line so the active debug log records the same
-- detail for post-mortem.
function Updater._set_failure(step, err)
  update.last_step  = step
  update.last_error = err
  Log.line("UPDATE", string.format("fail [%s]: %s",
                                   tostring(step), tostring(err)))
end

-- True when the updater is mid-flight on a fetch, verification, download,
-- or rename. Centralises the four-state predicate that gates re-entry on
-- force_reinstall, manual_check, the chat-piggyback check_start, and the
-- UI's ver_busy / busy disabled-button flags. A single helper means a
-- future state addition only needs to land in one place rather than five
-- separate condition lists.
function Updater.is_busy()
  return update.state == "checking"
      or update.state == "verifying"
      or update.state == "downloading"
      or update.state == "rename_retry"
end

function Updater.font_download_busy()
  return OptionalFonts and OptionalFonts.is_busy and OptionalFonts.is_busy()
end

function Updater.language_download_busy()
  return LangPacks and LangPacks.is_busy and LangPacks.is_busy()
end

-- Compare two semver strings numerically. Returns true if remote > local.
function Updater.is_newer(remote_ver, local_ver)
  local function parse(v)
    local parts = {}
    for n in v:gmatch("(%d+)") do parts[#parts+1] = tonumber(n) end
    return parts
  end
  local r, l = parse(remote_ver), parse(local_ver)
  for i = 1, math_max(#r, #l) do
    local rv, lv = r[i] or 0, l[i] or 0
    if rv > lv then return true end
    if rv < lv then return false end
  end
  return false
end

-- Fire an async curl GET. Writes response to out_path, exit code to exit_path.
-- Returns true if launched, false if URL is empty or launch fails.
function RA.fire_get_to(url, out_path, exit_path, timeout, send_state, log_tag, opts)
  if not url or url == "" then return false end
  if send_state then send_state.request_url = tostring(url or "") end
  os.remove(out_path)
  os.remove(exit_path)
  opts = type(opts) == "table" and opts or {}
  -- Cache-busting: append a unix-time query parameter to the URL.
  -- GitHub's raw CDN keys on URL, so a unique timestamp guarantees a
  -- cache miss on every check. This eliminates the propagation race we
  -- have hit during rapid test-branch iteration where a new manifest
  -- and its updated file SHAs can be cached separately, leading to
  -- false repair popups on first launch after an update push.
  --
  -- We previously also sent Cache-Control / Pragma no-cache headers,
  -- but on Windows the literal double quotes around those header
  -- values broke the outer PowerShell -Command argument parse: the
  -- inner `"` terminated PowerShell's -Command string early, curl
  -- never ran, and the manual update check toasted "Could not reach
  -- update server" on every press. The timestamp query alone is
  -- sufficient (a CDN cannot serve a cached response for a URL it has
  -- never seen before), so the headers were dropped.
  -- Content-addressed payload downloads can opt out because their SHA-256
  -- verification already rejects stale or corrupted bytes, and keeping the
  -- URL stable lets CDNs serve large fonts/lang packs/update files from cache.
  if opts.cache_bust == false then
    if send_state then send_state.request_url_with_cache_bust = nil end
  else
    local sep = url:find("?", 1, true) and "&" or "?"
    -- Cache-bust query: combine os.time() seconds with time_precise()
    -- millisecond fraction so two fetches inside the same second still
    -- produce distinct URLs. Pure os.time() collides on rapid Retry
    -- clicks (the v0.9.8.22 CDN-propagation fix encourages users to
    -- click Retry repeatedly), and a duplicate URL re-hits whatever
    -- the CDN has cached for that key, defeating the whole point.
    local ms = math.floor((time_precise() % 1) * 1000)
    url = url .. sep .. "_=" .. tostring(os.time())
                    .. string.format("%03d", ms)
    if send_state then send_state.request_url_with_cache_bust = url end
  end
  timeout = timeout or CFG.UPDATE_CURL_TIMEOUT
  log_tag = log_tag or "NET"
  if RA.IS_WINDOWS then
    -- Defensive guard limited to characters that cannot legitimately
    -- appear in a valid Windows path OR a valid URL: " < > | are all
    -- reserved by Windows filenames and are also invalid in URLs (or,
    -- for ", a quote-terminator that would break the inner cmd arg
    -- parse). Other cmd-significant chars (& ^ ( ) %) ARE valid in
    -- Windows paths ("Program Files (x86)", user dirs like "R&D")
    -- and in URL query strings; the triple-quoted argument passing
    -- protects them, so we must NOT reject them or update / repair
    -- would silently fail for users on those paths.
    for _, c in ipairs({'"', '<', '>', '|'}) do
      if url:find(c, 1, true)
          or out_path:find(c, 1, true)
          or exit_path:find(c, 1, true) then
        Log.line(log_tag, string.format(
          "fire_get: refusing to launch with cmd-unsafe character '%s' "
          .. "in URL or path", c))
        return false
      end
    end
    local cmd_line = str_format(
      'curl -s --connect-timeout 10 --max-time %d'
      .. ' "%s" -o """%s"""'
      .. ' & call echo %%%%errorlevel%%%% > """%s"""',
      timeout, url, out_path, exit_path)
    local ps_cmd = str_format(
      'powershell -NoProfile -WindowStyle Hidden'
      .. ' -Command "Start-Process cmd -ArgumentList \'/c %s\''
      .. ' -WindowStyle Hidden"',
      Shell.ps_escape(cmd_line))
    reaper.ExecProcess(ps_cmd, 5000)
  else
    -- Single-quote the URL on POSIX shells. Double quotes still allow
    -- $(...) and `...` command substitution, so a malicious or malformed
    -- manifest filename baked into the URL could execute. is_safe_filename
    -- already blocks shell-sensitive characters, but quoting cleanly here
    -- closes the gap as defense-in-depth.
    local cmd = str_format(
      '(curl -s --connect-timeout 10 --max-time %d'
      .. ' %s -o %s ; echo $? > %s) &',
      timeout, Shell.sh_quote(url), Shell.sh_quote(out_path),
      Shell.sh_quote(exit_path))
    os.execute(cmd)
  end
  -- NOTE: Neither ExecProcess nor os.execute reliably indicate launch failure,
  -- so send_time is set unconditionally. If the process never started, the
  -- watchdog in Updater.poll() will time out after UPDATE_CURL_TIMEOUT + 10s.
  if send_state then send_state.send_time = time_precise() end
  return true
end

function Updater.fire_get(url, out_path, exit_path, opts)
  return RA.fire_get_to(url, out_path, exit_path,
    CFG.UPDATE_CURL_TIMEOUT, update, "UPDATE", opts)
end

LangPacks = LangPacks or { download = { state = "idle" } }

function LangPacks._t(key, values, fallback)
  return (RA and RA.t and RA.t(key, values, fallback)) or fallback or key
end

function LangPacks._display_language(code)
  local idx = CFG and CFG.legacy_idx_for_language_code
    and CFG.legacy_idx_for_language_code(code)
  return (idx and CFG and CFG.prompt_language_name_for_idx
      and CFG.prompt_language_name_for_idx(idx))
    or tostring(code or "")
end

function LangPacks.is_busy()
  local d = LangPacks.download or {}
  return d.state == "index_downloading"
      or d.state == "ui_downloading"
end

function LangPacks.ensure_dirs()
  if I18N and I18N.ensure_cache_dirs then return I18N.ensure_cache_dirs() end
  if not (reaper and reaper.RecursiveCreateDirectory) then return false end
  if not (RA and RA.LANG_DIR and RA.LANG_UI_DIR
      and RA.LANG_FONT_DIR and RA.LANG_TMP_DIR) then return false end
  reaper.RecursiveCreateDirectory(RA.LANG_DIR, 0)
  reaper.RecursiveCreateDirectory(RA.LANG_UI_DIR, 0)
  reaper.RecursiveCreateDirectory(RA.LANG_FONT_DIR, 0)
  reaper.RecursiveCreateDirectory(RA.LANG_TMP_DIR, 0)
  return true
end

function LangPacks.ensure_dir(kind)
  if I18N and I18N.ensure_cache_dir then return I18N.ensure_cache_dir(kind) end
  if not (reaper and reaper.RecursiveCreateDirectory) then return false end
  kind = tostring(kind or "root")
  local dir
  if kind == "root" then
    dir = RA and RA.LANG_DIR
  elseif kind == "ui" then
    dir = RA and RA.LANG_UI_DIR
  elseif kind == "fonts" then
    dir = RA and RA.LANG_FONT_DIR
  elseif kind == "tmp" then
    dir = RA and RA.LANG_TMP_DIR
  end
  if not dir then return false end
  reaper.RecursiveCreateDirectory(dir, 0)
  return true
end

function LangPacks._tmp_path(name, ext)
  LangPacks.ensure_dir("tmp")
  local dir = (I18N and I18N.tmp_pack_dir and I18N.tmp_pack_dir())
    or (RA and RA.LANG_TMP_DIR)
    or (RA and RA.TEMP_DIR)
    or ""
  local suffix = (RA and RA.instance_file_suffix and RA.instance_file_suffix())
    or tostring(S and S.INSTANCE_ID or "session")
  return dir .. "lang_" .. tostring(name or "pack") .. "_"
    .. suffix .. tostring(ext or ".tmp")
end

function LangPacks._cleanup_tmp_paths(d)
  d = type(d) == "table" and d or {}
  if d.out_path then pcall(os.remove, d.out_path) end
  if d.exit_path then pcall(os.remove, d.exit_path) end
end

function LangPacks.cleanup_stale_tmp()
  local dir = (I18N and I18N.tmp_pack_dir and I18N.tmp_pack_dir())
    or (RA and RA.LANG_TMP_DIR)
  if not (dir and reaper and reaper.EnumerateFiles) then return end
  local sep = dir:sub(-1) == "/" or dir:sub(-1) == "\\"
  sep = sep and "" or (RA and RA.SEP or package.config:sub(1, 1))
  local now = time_precise()
  local idx = 0
  while true do
    local name = reaper.EnumerateFiles(dir, idx)
    if not name then break end
    local tracked = tostring(name):match("^lang_")
      or tostring(name):match("^font_")
    local inst_suffix = tracked and RA.temp_instance_suffix_from_name(name)
      or nil
    if tracked and inst_suffix
        and not RA.temp_instance_is_live(inst_suffix, now) then
      pcall(os.remove, dir .. sep .. name)
    else
      idx = idx + 1
    end
  end
end

function LangPacks.cleanup_legacy_help_dir_once()
  local key = "lang_help_cache_removed_v1"
  if Store and Store.migration_fired and Store.migration_fired(key) then
    return false, "done"
  end
  local root = RA and RA.LANG_DIR
  if not (root and root ~= "") then return false, "missing_root" end
  local sep = RA and RA.SEP or package.config:sub(1, 1)
  local dir = root .. "help" .. sep
  local path = dir:gsub("[/\\]+$", "")
  local root_clean = root:gsub("[/\\]+$", "")
  if root_clean == "" or path:sub(1, #root_clean + 1) ~= root_clean .. sep then
    return false, "unsafe_path"
  end
  local function remove_tree_contents(target_dir)
    if not (reaper and type(reaper.EnumerateFiles) == "function") then return end
    local target_sep = target_dir:sub(-1) == "/" or target_dir:sub(-1) == "\\"
    target_sep = target_sep and "" or sep
    local files = {}
    local idx = 0
    while true do
      local name = reaper.EnumerateFiles(target_dir, idx)
      if not name then break end
      files[#files + 1] = name
      idx = idx + 1
    end
    for _, name in ipairs(files) do
      pcall(os.remove, target_dir .. target_sep .. name)
    end
    if type(reaper.EnumerateSubdirectories) ~= "function" then return end
    local dirs = {}
    idx = 0
    while true do
      local name = reaper.EnumerateSubdirectories(target_dir, idx)
      if not name then break end
      dirs[#dirs + 1] = name
      idx = idx + 1
    end
    for _, name in ipairs(dirs) do
      local child = target_dir .. target_sep .. name
      remove_tree_contents(child)
      pcall(os.remove, child:gsub("[/\\]+$", ""))
    end
  end
  remove_tree_contents(dir)
  if os.remove(path) ~= true then
    if RA and RA.IS_WINDOWS and reaper and type(reaper.ExecProcess) == "function" then
      local ps_path = path:gsub("'", "''")
      local cmd = "powershell -NoProfile -WindowStyle Hidden"
        .. " -Command \"Remove-Item -LiteralPath '"
        .. ps_path
        .. "' -Recurse -Force -ErrorAction SilentlyContinue\""
      pcall(reaper.ExecProcess, cmd, 5000)
    else
      local sq = "'" .. path:gsub("'", "'\\''") .. "'"
      os.execute("rmdir " .. sq .. " >/dev/null 2>&1")
    end
  end
  if Store and Store.set_migration_fired then Store.set_migration_fired(key) end
  return true
end

if LangPacks and LangPacks.cleanup_stale_tmp then
  LangPacks.cleanup_stale_tmp()
end
if LangPacks and LangPacks.cleanup_legacy_help_dir_once then
  LangPacks.cleanup_legacy_help_dir_once()
end

function LangPacks._read_file(path)
  local f = io.open(path, "rb")
  if not f then return nil end
  local raw = f:read("*a")
  f:close()
  return raw
end

function LangPacks._copy_file(src, dest)
  local rf, rerr = io.open(src, "rb")
  if not rf then return false, rerr end
  local wf, werr = io.open(dest, "wb")
  if not wf then rf:close(); return false, werr end
  while true do
    local chunk = rf:read(65536)
    if not chunk then break end
    local ok, err = wf:write(chunk)
    if not ok then
      rf:close(); wf:close()
      os.remove(dest)
      return false, err
    end
  end
  rf:close()
  wf:close()
  return true
end

function LangPacks._write_file(path, raw)
  local f, err = io.open(path, "wb")
  if not f then return false, err end
  local ok, werr = f:write(raw or "")
  f:close()
  if not ok then os.remove(path); return false, werr end
  return true
end

function LangPacks._install_file(src, dest)
  local tmp_path = dest .. ".tmp"
  os.remove(tmp_path)
  local ok_stage, stage_err = os.rename(src, tmp_path)
  if not ok_stage then
    local ok_copy, copy_err = LangPacks._copy_file(src, tmp_path)
    if not ok_copy then return false, copy_err or stage_err end
    os.remove(src)
  end
  os.remove(dest)
  local ok_mv, mv_err = os.rename(tmp_path, dest)
  if not ok_mv then
    os.remove(tmp_path)
    return false, mv_err or "move_failed"
  end
  return true
end

function LangPacks._safe_url(url)
  url = tostring(url or "")
  if not url:match("^https://") then return nil end
  if url:find('"', 1, true) or url:find("<", 1, true)
      or url:find(">", 1, true) or url:find("|", 1, true) then
    return nil
  end
  return url
end

function LangPacks._file_size(path)
  local f = path and io.open(path, "rb") or nil
  if not f then return nil end
  local size = f:seek("end")
  f:close()
  return size
end

function LangPacks._kind_label(d, step)
  d = type(d) == "table" and d or {}
  local kind = tostring(d.kind or d.pending_kind or "")
  local state = tostring(d.last_state or d.state or "")
  step = tostring(step or "")
  if kind == "index" or state == "index_downloading"
      or step == "index" or step == "index_launch" then
    return "language index"
  end
  return "language pack"
end

function LangPacks._cap(text)
  return (tostring(text or ""):gsub("^%l", string.upper))
end

function LangPacks._friendly_failure(step, err, d)
  step = tostring(step or "")
  err = tostring(err or "Language pack download failed.")
  local kind = LangPacks._kind_label(d, step)
  local exit_code = d and d.curl_exit_code
  if step == "download" then
    if exit_code then
      return string.format("%s download failed (curl exit %s).",
        LangPacks._cap(kind), tostring(exit_code))
    end
    if err:find("timed out", 1, true) then
      return string.format("%s download timed out after %d seconds.",
        LangPacks._cap(kind),
        (CFG and CFG.LANG_DOWNLOAD_TIMEOUT or 30))
    end
    return string.format("%s download failed.", LangPacks._cap(kind))
  elseif step == "index" then
    return "Language index downloaded but could not be read: " .. err
  elseif step == "metadata" then
    return "Language pack metadata is unavailable or incompatible: " .. err
  elseif step == "verify" then
    return "Downloaded " .. kind .. " failed verification: " .. err
  elseif step == "validate" then
    return "Downloaded " .. kind .. " could not be parsed: " .. err
  elseif step == "install" then
    return "Downloaded " .. kind .. " could not be installed: " .. err
  elseif step:find("launch", 1, true) then
    return LangPacks._cap(kind) .. " download could not start."
  end
  return err
end

function LangPacks._failure_detail(d, step, err, extra)
  d = type(d) == "table" and d or {}
  local detail = {
    code = tostring(d.last_code or d.code or d.pending_code or ""),
    state = tostring(d.last_state or d.state or ""),
    kind = LangPacks._kind_label(d, step),
    step = tostring(step or ""),
    error = tostring(err or ""),
    url = tostring(d.request_url or d.url or ""),
    url_cache_bust = tostring(d.request_url_with_cache_bust or ""),
    curl_exit = d.curl_exit_code,
    expected_bytes = d.entry and d.entry.bytes or nil,
    actual_bytes = d.actual_bytes or LangPacks._file_size(d.out_path),
    sha256 = d.entry and d.entry.sha256 or nil,
  }
  if type(extra) == "table" then
    for k, v in pairs(extra) do detail[k] = v end
  end
  return detail
end

function LangPacks.diagnostic_text(d)
  d = type(d) == "table" and d or LangPacks.download or {}
  local detail = type(d.last_detail) == "table" and d.last_detail or {}
  local lines = {
    "ReaAssist language download diagnostic",
    "version=" .. tostring(CFG and CFG.VERSION or ""),
    "os=" .. tostring(reaper and reaper.GetOS and reaper.GetOS() or ""),
    "utc=" .. tostring(os.date and os.date("!%Y-%m-%dT%H:%M:%SZ") or ""),
    "code=" .. tostring(detail.code or d.last_code or d.code or d.pending_code or ""),
    "kind=" .. tostring(detail.kind or ""),
    "state=" .. tostring(detail.state or d.state or ""),
    "step=" .. tostring(detail.step or d.last_step or ""),
    "error=" .. tostring(detail.error or d.last_raw_error or d.last_error or ""),
    "display_error=" .. tostring(d.last_error or ""),
    "url=" .. tostring(detail.url or d.request_url or ""),
    "url_cache_bust=" .. tostring(detail.url_cache_bust
      or d.request_url_with_cache_bust or ""),
    "curl_exit=" .. tostring(detail.curl_exit or d.curl_exit_code or ""),
    "expected_bytes=" .. tostring(detail.expected_bytes or ""),
    "actual_bytes=" .. tostring(detail.actual_bytes or ""),
    "sha256=" .. tostring(detail.sha256 or ""),
  }
  return table.concat(lines, "\n")
end

function LangPacks._sha_ok(raw, expected)
  expected = tostring(expected or ""):lower()
  if not expected:match("^[0-9a-f]+$") or #expected ~= 64 then return false end
  if not (RA and RA.sha256_hex) then return false end
  return tostring(RA.sha256_hex(raw or "")):lower() == expected
end

function LangPacks._parse_version(v)
  local parts = {}
  for n in tostring(v or ""):gmatch("(%d+)") do
    parts[#parts + 1] = tonumber(n) or 0
  end
  return parts
end

function LangPacks._version_cmp(a, b)
  local av = LangPacks._parse_version(a)
  local bv = LangPacks._parse_version(b)
  for i = 1, math_max(#av, #bv) do
    local ai, bi = av[i] or 0, bv[i] or 0
    if ai < bi then return -1 end
    if ai > bi then return 1 end
  end
  return 0
end

function LangPacks._app_compatible(entry)
  if type(entry) ~= "table" then return false end
  local current = tostring(CFG and CFG.VERSION or "0")
  if entry.app_min and LangPacks._version_cmp(current, entry.app_min) < 0 then
    return false
  end
  local app_max = tostring(entry.app_max or "")
  if app_max ~= "" then
    if app_max:match("^%d+%.x$") then
      local major = tonumber(current:match("^(%d+)")) or 0
      local wanted = tonumber(app_max:match("^(%d+)")) or -1
      if major ~= wanted then return false end
    elseif LangPacks._version_cmp(current, app_max) > 0 then
      return false
    end
  end
  return true
end

function LangPacks.remote_ui_entry(code)
  if not (I18N and I18N.remote_index) then return nil, "missing_index" end
  code = tostring(code or "")
  local lang = I18N.remote_index.languages
    and I18N.remote_index.languages[code]
  local ui = type(lang) == "table" and lang.ui or nil
  if type(ui) ~= "table" then return nil, "missing_ui" end
  if lang.status and lang.status ~= "complete" then return nil, "incomplete" end
  if ui.schema ~= (I18N.PACK_SCHEMA or 1) then return nil, "schema" end
  if not LangPacks._safe_url(ui.url) then return nil, "url" end
  if not tonumber(ui.bytes) or tonumber(ui.bytes) <= 0
      or tonumber(ui.bytes) > (I18N.MAX_UI_PACK_BYTES or (512 * 1024)) then
    return nil, "size"
  end
  if not tostring(ui.sha256 or ""):lower():match("^[0-9a-f]+$")
      or #tostring(ui.sha256 or "") ~= 64 then
    return nil, "sha"
  end
  if not LangPacks._app_compatible(ui) then return nil, "app" end
  return ui
end

function LangPacks.status_for_code(code)
  code = tostring(code or "")
  local d = LangPacks.download or {}
  if d.code == code and d.state == "ui_downloading" then return "downloading" end
  if d.pending_code == code and d.state == "index_downloading" then
    return "downloading"
  end
  local has_catalog = I18N and I18N.catalog_available
    and I18N.catalog_available(code)
  if has_catalog then
    return "installed"
  end
  if d.last_code == code and d.state == "failed" then return "failed" end
  if code ~= "" and code ~= "en" and code ~= "qps-ploc"
      and I18N and not I18N.remote_index
      and CFG and CFG.is_valid_language_code
      and CFG.is_valid_language_code(code) then
    return "download"
  end
  local entry = LangPacks.remote_ui_entry(code)
  if entry then return "download" end
  return "unavailable"
end

function LangPacks.label_for_code(code, base_label)
  local status = LangPacks.status_for_code(code)
  local lang = I18N and I18N.remote_index and I18N.remote_index.languages
    and I18N.remote_index.languages[tostring(code or "")]
  local cfg_lang = CFG and CFG.language_for_code
    and CFG.language_for_code(code)
  local label = tostring((type(lang) == "table" and lang.english_label)
    or (type(cfg_lang) == "table" and (cfg_lang.label_en
      or cfg_lang.prompt_name))
    or base_label or code or "")
  if status == "download" then
    return label
  elseif status == "downloading" then
    return label .. " (" .. LangPacks._t("settings.lang.downloading_suffix", nil,
      "Downloading...") .. ")"
  elseif status == "failed" then
    return label .. " (" .. LangPacks._t("settings.lang.retry_suffix", nil,
      "Retry") .. ")"
  end
  return label
end

function LangPacks._failure_is_quiet_refresh(code)
  local d = LangPacks.download or {}
  if not (d.is_refresh or d.pending_refresh) then return false end
  code = tostring(code or d.code or d.pending_code or "")
  if code == "" then return false end
  return I18N and I18N.catalog_available and I18N.catalog_available(code)
end

function LangPacks._set_failure(code, step, err, detail)
  local d = LangPacks.download or {}
  local previous_state = d.state
  d.last_state = previous_state
  d.state = "failed"
  d.last_code = code or d.code or d.pending_code
  d.last_step = step
  d.last_raw_error = tostring(err or "Language pack download failed.")
  d.last_detail = LangPacks._failure_detail(d, step, d.last_raw_error, detail)
  d.last_error = LangPacks._friendly_failure(step, d.last_raw_error, d)
  d.quiet_refresh = LangPacks._failure_is_quiet_refresh(d.last_code) or nil
  if d.last_code then
    d.status_text = LangPacks._t("settings.lang.failed_detail", {
      language = LangPacks._display_language(d.last_code),
      current = LangPacks._display_language(I18N and I18N.lang_code
        and I18N.lang_code() or "en"),
      detail = d.last_error,
    }, "Language pack download failed. " .. d.last_error)
  else
    d.status_text = LangPacks._t("settings.lang.index_failed_detail", {
      detail = d.last_error,
    }, "Could not check language packs. " .. d.last_error)
  end
  LangPacks.download = d
  if d.last_code and UI and UI.show_float_toast and not d.quiet_refresh then
    UI.show_float_toast(d.status_text)
  end
  if Log and Log.line then
    local det = d.last_detail or {}
    Log.line("LANG", string.format(
      "fail [%s/%s/%s]: %s url=%s curl=%s bytes=%s/%s",
      tostring(d.last_code), tostring(previous_state), tostring(step),
      tostring(d.last_error), tostring(det.url or ""),
      tostring(det.curl_exit or ""), tostring(det.actual_bytes or ""),
      tostring(det.expected_bytes or "")))
  end
  LangPacks._cleanup_tmp_paths(d)
end

function LangPacks._store_index(raw)
  if type(raw) ~= "string" or raw == "" then return false, "empty" end
  if #raw > (I18N.MAX_INDEX_BYTES or (128 * 1024)) then
    return false, "oversize"
  end
  local doc, err = I18N._json_decode(raw)
  if type(doc) ~= "table" or doc.schema ~= (I18N.PACK_SCHEMA or 1)
      or type(doc.languages) ~= "table" then
    return false, err or "invalid_index"
  end
  local path = I18N.index_path and I18N.index_path()
  if not path then return false, "missing_index_path" end
  LangPacks.ensure_dir("root")
  local ok, werr = LangPacks._write_file(path, raw)
  if not ok then return false, werr or "write_failed" end
  I18N.remote_index = doc
  return true
end

function LangPacks.start_index_download(pending_code, force, pending_refresh)
  if not (I18N and I18N._json_decode and I18N.index_path) then
    return false, "i18n_unavailable"
  end
  if I18N.remote_index and not force then return true end
  if LangPacks.is_busy() then return false, "busy" end
  local out_path = LangPacks._tmp_path("index", ".json")
  local exit_path = LangPacks._tmp_path("index", ".exit")
  LangPacks.download = {
    state = "index_downloading",
    kind = "index",
    pending_code = pending_code,
    pending_refresh = pending_refresh and true or nil,
    out_path = out_path,
    exit_path = exit_path,
    status_text = LangPacks._t("settings.lang.checking", nil,
      "Checking languages..."),
  }
  local url = (I18N and I18N.INDEX_URL)
    or "https://reaassist.app/lang/v1/index.json"
  LangPacks.download.url = url
  local ok = RA.fire_get_to(url, out_path, exit_path,
    CFG.LANG_DOWNLOAD_TIMEOUT, LangPacks.download, "LANG")
  if not ok then
    LangPacks._set_failure(pending_code, "index_launch",
      "Language index download could not start.")
    return false, LangPacks.download.last_error
  end
  return true
end

function LangPacks.ensure_index()
  if I18N and I18N.remote_index then return true end
  local d = LangPacks.download or {}
  if d.state == "failed" and not d.last_code then return false end
  if LangPacks.is_busy() then return false end
  return LangPacks.start_index_download(nil, false)
end

function LangPacks.cached_ui_matches_entry(code, entry)
  if not (I18N and I18N.cached_ui_pack_path) then return false, "i18n" end
  entry = type(entry) == "table" and entry or nil
  if not entry then return false, "entry" end
  local cache = LangPacks._ui_match_cache and LangPacks._ui_match_cache[code]
  if cache and cache.sha256 == entry.sha256 and cache.bytes == entry.bytes then
    return cache.ok, cache.reason
  end
  local path = I18N.cached_ui_pack_path(code)
  local raw = path and LangPacks._read_file(path) or nil
  local ok, reason = true, nil
  if not raw or raw == "" then
    ok, reason = false, "missing"
  elseif entry.bytes and #raw ~= tonumber(entry.bytes) then
    ok, reason = false, "bytes"
  elseif entry.sha256 and not LangPacks._sha_ok(raw, entry.sha256) then
    ok, reason = false, "sha"
  end
  LangPacks._ui_match_cache = LangPacks._ui_match_cache or {}
  LangPacks._ui_match_cache[code] = {
    sha256 = entry.sha256,
    bytes = entry.bytes,
    ok = ok,
    reason = reason,
  }
  return ok, reason
end

function LangPacks.refresh_language_if_stale(code)
  code = tostring(code or "")
  if code == "" or code == "en" or code == "qps-ploc" then
    return true, "bundled"
  end
  local entry, entry_err = LangPacks.remote_ui_entry(code)
  if not entry then return false, entry_err or "unavailable" end
  local fresh = LangPacks.cached_ui_matches_entry(code, entry)
  if fresh then return true, "current" end
  return LangPacks.start_language_download(code, true)
end

function LangPacks.ensure_active_language_current()
  if LangPacks._active_refresh_started then return false, "done" end
  if LangPacks.is_busy() then return false, "busy" end
  local code = prefs and tostring(prefs.language_code or "") or ""
  if code == "" or code == "en" or code == "qps-ploc" then
    LangPacks._active_refresh_started = true
    return true, "bundled"
  end
  if CFG and CFG.is_valid_language_code and not CFG.is_valid_language_code(code) then
    LangPacks._active_refresh_started = true
    return false, "invalid"
  end
  LangPacks._active_refresh_started = true
  return LangPacks.start_index_download(code, true, true)
end

function LangPacks.start_language_download(code, force)
  code = tostring(code or "")
  if not force and I18N and I18N.catalog_available
      and I18N.catalog_available(code) then
    return true, "installed"
  end
  if LangPacks.is_busy() then return false, "busy" end
  if not (I18N and I18N.remote_index) then
    local ok, err = LangPacks.start_index_download(code, true, false)
    return false, err or (ok and "index_downloading" or "index_failed")
  end
  local entry, entry_err = LangPacks.remote_ui_entry(code)
  if not entry then
    LangPacks._set_failure(code, "metadata", entry_err or "unavailable")
    return false, entry_err or "unavailable"
  end
  local out_path = LangPacks._tmp_path("ui_" .. code, ".json")
  local exit_path = LangPacks._tmp_path("ui_" .. code, ".exit")
  local language = LangPacks._display_language(code)
  LangPacks.download = {
    state = "ui_downloading",
    kind = "ui",
    code = code,
    entry = entry,
    is_refresh = force and true or nil,
    out_path = out_path,
    exit_path = exit_path,
    status_text = LangPacks._t("settings.lang.downloading", {
      language = language,
    }, "Downloading language pack..."),
  }
  LangPacks.download.url = entry.url
  if UI and UI.show_float_toast then
    UI.show_float_toast(LangPacks.download.status_text)
  end
  local ok = RA.fire_get_to(entry.url, out_path, exit_path,
    CFG.LANG_DOWNLOAD_TIMEOUT, LangPacks.download, "LANG",
    { cache_bust = false })
  if not ok then
    LangPacks._set_failure(code, "launch",
      "Language pack download could not start.")
    return false, LangPacks.download.last_error
  end
  return true
end

function LangPacks._activate_language(code)
  local idx = CFG and CFG.legacy_idx_for_language_code
    and CFG.legacy_idx_for_language_code(code)
  if idx then prefs.reply_language_idx = idx end
  prefs.language_code = code
  if S and S.wrap_cache then S.wrap_cache = {} end
end

function LangPacks._finish_ui_download()
  local d = LangPacks.download or {}
  local entry = d.entry or {}
  local raw = LangPacks._read_file(d.out_path)
  d.actual_bytes = raw and #raw or LangPacks._file_size(d.out_path)
  if not raw or raw == "" then
    LangPacks._set_failure(d.code, "verify", "Downloaded pack was empty.",
      { actual_bytes = d.actual_bytes or 0 })
    return
  end
  if #raw > (I18N.MAX_UI_PACK_BYTES or (512 * 1024)) then
    LangPacks._set_failure(d.code, "verify", "Downloaded pack was too large.",
      { actual_bytes = #raw })
    return
  end
  if entry.bytes and #raw ~= tonumber(entry.bytes) then
    LangPacks._set_failure(d.code, "verify",
      string.format("Downloaded pack size was %d bytes, expected %d.",
        #raw, tonumber(entry.bytes) or 0),
      { actual_bytes = #raw, expected_bytes = tonumber(entry.bytes) or 0 })
    return
  end
  if not LangPacks._sha_ok(raw, entry.sha256) then
    LangPacks._set_failure(d.code, "verify",
      "Downloaded pack checksum did not match.",
      { actual_bytes = #raw })
    return
  end
  local catalog, parse_err = I18N.parse_ui_pack_json(raw, d.code)
  if not catalog then
    LangPacks._set_failure(d.code, "validate", parse_err or "invalid_pack")
    return
  end
  local dest = I18N.cached_ui_pack_path and I18N.cached_ui_pack_path(d.code)
  if not dest then
    LangPacks._set_failure(d.code, "install", "Missing pack cache path.")
    return
  end
  LangPacks.ensure_dir("ui")
  local ok_install, install_err = LangPacks._install_file(d.out_path, dest)
  if not ok_install then
    LangPacks._set_failure(d.code, "install", install_err or "move_failed")
    return
  end
  I18N.catalogs[d.code] = catalog
  if I18N._cached_pack_miss then I18N._cached_pack_miss[d.code] = nil end
  if LangPacks._ui_match_cache then LangPacks._ui_match_cache[d.code] = nil end
  LangPacks._activate_language(d.code)
  d.state = "done"
  d.last_code = d.code
  d.status_text = LangPacks._t(d.is_refresh and "settings.lang.updated_toast"
      or "settings.lang.installed_toast", {
    language = LangPacks._display_language(d.code),
  }, d.is_refresh and "Language pack updated." or "Language pack installed.")
  if UI and UI.show_float_toast then UI.show_float_toast(d.status_text) end
  LangPacks._cleanup_tmp_paths(d)
end

function LangPacks.poll()
  local d = LangPacks.download
  if not d or d.state == "idle" or d.state == "done" or d.state == "failed" then
    return
  end
  if not d.send_time then
    LangPacks._set_failure(d.code or d.pending_code, "download",
      "Language pack download did not launch.")
    return
  end
  if (time_precise() - d.send_time) > (CFG.LANG_DOWNLOAD_TIMEOUT + 10) then
    LangPacks._set_failure(d.code or d.pending_code, "download",
      "Language pack download timed out.",
      { timeout_seconds = CFG.LANG_DOWNLOAD_TIMEOUT })
    return
  end
  local ef = io.open(d.exit_path, "r")
  if not ef then return end
  local exit_str = ef:read("*a"); ef:close()
  local exit_code = tonumber(exit_str:match("(%d+)"))
  if not exit_code then return end
  d.curl_exit_code = exit_code
  if exit_code ~= 0 then
    LangPacks._set_failure(d.code or d.pending_code, "download",
      "Language pack download failed.", { curl_exit = exit_code })
    return
  end
  if d.state == "index_downloading" then
    local raw = LangPacks._read_file(d.out_path)
    d.actual_bytes = raw and #raw or LangPacks._file_size(d.out_path)
    local ok, err = LangPacks._store_index(raw)
    if not ok then
      LangPacks._set_failure(d.pending_code, "index", err or "invalid_index",
        { actual_bytes = d.actual_bytes or 0 })
      return
    end
    local pending_code = d.pending_code
    LangPacks._cleanup_tmp_paths(d)
    LangPacks.download = { state = "idle" }
    if pending_code then
      if d.pending_refresh then
        LangPacks.refresh_language_if_stale(pending_code)
      else
        LangPacks.start_language_download(pending_code)
      end
    end
    return
  end
  if d.state == "ui_downloading" then LangPacks._finish_ui_download() end
end

-- Poll for completion of the current async curl. Returns "done", "waiting", or "error".
function Updater.poll()
  if not update.send_time then return "error" end
  -- Watchdog: give up after timeout + generous slack.
  if (time_precise() - update.send_time) > (CFG.UPDATE_CURL_TIMEOUT + 10) then
    return "error"
  end
  -- io.open returns nil + err on failure; never throws. Direct call
  -- keeps the control flow flat.
  local ef = io.open(tmp.update_exit, "r")
  if not ef then return "waiting" end
  local exit_str = ef:read("*a"); ef:close()
  local exit_code = tonumber(exit_str:match("(%d+)"))
  if not exit_code then return "waiting" end
  if exit_code ~= 0 then return "error" end
  return "done"
end

-- Read and parse the response file. Returns parsed table or nil.
function Updater.read_response()
  local f = io.open(tmp.update_out, "r")
  if not f then return nil end
  local raw = f:read("*a"); f:close()
  if not raw or #raw < 2 then return nil end
  local data, err = JSON.decode(raw)
  if not data or type(data) ~= "table" then return nil end
  return data
end

-- Force a reinstall: bypass version check, daily cap, and snooze.
-- Re-entry guard: bail when a curl is already in flight. Without it, a
-- double-click on Bootstrap's Repair button (which stays rendered during
-- "checking" because Bootstrap's state dispatcher falls through to
-- render_prompt on unknown states) would double-fire the curl while the
-- first one is still writing to tmp.update_out / tmp.update_exit,
-- corrupting the read.
function Updater.force_reinstall()
  if CFG.UPDATE_BASE_URL == "" then return false end
  if Updater.is_busy() then return false end
  if Updater.font_download_busy() then return false end
  if Updater.language_download_busy() then return false end
  update.force = true
  update.popup_opened = false
  -- Clear stale failure metadata from a previous attempt. Without this,
  -- a Retry-after-failed click inherits the prior failure's last_step /
  -- last_error / repair_missing / repair_mismatched / action_was_repair
  -- values until the new check_poll result lands. The Update Failed
  -- dialog branches its copy on update.last_step (sha_verify gets the
  -- CDN-propagation message; everything else gets the generic copy), so
  -- a brief frame with a stale last_step could flash the wrong message.
  -- Mirror download_start's clean-slate pattern (download_queue,
  -- applied_files, skipped_count) for the failure-display fields too.
  update.last_step         = nil
  update.last_error        = nil
  update.repair_missing    = nil
  update.repair_mismatched = nil
  update.action_was_repair = nil
  local url = Updater.url_for(CFG.UPDATE_MANIFEST)
  if Updater.fire_get(url, tmp.update_out, tmp.update_exit) then
    update.state = "checking"
    return true
  end
  return false
end

-- Start the manifest check. Called from loop() on the first idle->waiting
-- chat-send edge in the session, so PowerShell is already warm from the
-- chat's curl and this check's ExecProcess cost is ~200ms instead of
-- 1-3s cold. No 24h throttle: the session flag
-- `update._session_check_fired` already prevents multiple fires per
-- session, and gating the fetch itself would prevent repair detection
-- too; we NEED a fresh manifest every session to compute the local-
-- vs-remote SHA diff. The update-nag snooze is honored lower in the
-- pipeline (check_poll's available branch) so it only suppresses the
-- "Update Available" popup, never the repair flow. Stamp
-- update_last_check here so any future consumer that wants a "time of
-- most recent successful fetch" reading has one.
function Updater.check_start()
  if CFG.UPDATE_BASE_URL == "" then return end
  if not prefs.update_check then return end
  -- Busy guard: the chat-piggyback fires on the first idle->waiting
  -- transition of the session, but a user could already have launched
  -- a manual Check / Repair in the same window. Without this guard the
  -- piggyback would fire a second curl that shares tmp.update_out /
  -- tmp.update_exit with the in-flight one, racing the manifest check
  -- against a download and corrupting the read.
  if Updater.is_busy() then return end
  if Updater.font_download_busy() then return end
  if Updater.language_download_busy() then return end
  Store.set_update_last_check(os.time())
  local url = Updater.url_for(CFG.UPDATE_MANIFEST)
  if Updater.fire_get(url, tmp.update_out, tmp.update_exit) then
    update.state = "checking"
  end
end

-- User-initiated check, wired to the "Check for Updates" button in
-- Settings. Bypasses the 24h throttle and the snooze (user is explicitly
-- asking), but unlike force_reinstall does NOT set update.force = true:
-- if the server is on the same version and SHAs match, we want to show
-- a friendly "You're up to date" toast instead of misleadingly offering
-- a reinstall. Bumps the throttle timestamp so the chat-piggyback does
-- not immediately re-fire the check on the user's next send.
function Updater.manual_check()
  if CFG.UPDATE_BASE_URL == "" then
    UI.show_float_toast(RA.t("update.toast.url_missing", nil,
      "Update URL not configured"), "err")
    return false
  end
  if Updater.is_busy() then return false end
  if Updater.font_download_busy() then
    UI.show_float_toast(RA.t("settings.font.finish_download_first", nil,
      "Finish the font download first"), "err")
    return false
  end
  if Updater.language_download_busy() then
    UI.show_float_toast(RA.t("settings.lang.finish_download_first", nil,
      "Finish the language pack download first"), "err")
    return false
  end
  Store.set_update_last_check(os.time())
  update._manual = true
  -- Reset popup_opened so the "Update Available" dialog re-fires when
  -- this manual check finds an update. Without this, a sequence of
  -- (auto-fire piggyback shows popup -> Later -> manual check) would
  -- silently re-set state = "available" but the auto-show guard
  -- (`not update.popup_opened`) would suppress the popup the user
  -- explicitly asked to re-trigger. Same pattern as force_reinstall.
  update.popup_opened = false
  -- Sticky "Checking..." toast appears instantly so the user's click
  -- has immediate visual feedback during the PowerShell + curl round
  -- trip. check_poll replaces or clears this toast on every non-
  -- waiting result (up-to-date -> "up to date" toast; update or repair
  -- available -> cleared so the popup carries the feedback alone;
  -- error -> replaced with a specific error toast).
  UI.show_float_toast(RA.t("update.toast.checking", nil,
    "Checking for updates..."), "ok", true)
  local url = Updater.url_for(CFG.UPDATE_MANIFEST)
  if Updater.fire_get(url, tmp.update_out, tmp.update_exit) then
    update.state = "checking"
    return true
  end
  update._manual = false
  UI.show_float_toast(RA.t("update.toast.start_failed", nil,
    "Update check failed to start"), "err")
  return false
end

-- =============================================================================
-- SHA-256 verification pipeline (native subprocess + pure-Lua fallback)
-- =============================================================================
-- start_sha_diff preflights the manifest in pure Lua (classifying each entry
-- as missing / locked-skip / readable) and then prefers a native SHA-256
-- subprocess (PowerShell Get-FileHash on Windows; sha256sum / shasum -a 256
-- on POSIX) over the pure-Lua incremental hasher. Native is hundreds of MB/s
-- vs ~1 MB/s pure-Lua, so on a ~3.6 MB manifest the verify tail drops from
-- 5-12 s to well under 1 s.
--
-- The pure-Lua path remains as the reliability floor. It runs when:
--   * The native launcher couldn't start (PowerShell missing, AV block,
--     no sha256sum / shasum on POSIX, paths-file write error)
--   * tick_native_sha hits a non-zero exit, watchdog timeout, or
--     suspicious output (preflighted file readable but missing from
--     native output)
-- Each tick_sha_diff call compresses up to s.budget seconds of SHA work
-- (CFG.UPDATE_SHA_TIME_BUDGET for background piggyback,
-- CFG.UPDATE_SHA_TIME_BUDGET_MANUAL for manual / forced) at the 64-byte SHA
-- block level, so REAPER stays responsive even if every file has to be
-- hashed in-Lua. The main loop pumps either tick_native_sha or
-- tick_sha_diff once per frame while update.state == "verifying", same
-- shape as "checking" / "downloading" / "rename_retry".
--
-- download_start (the post-Update-Now path) consumes the precomputed diff and
-- never hashes the whole manifest synchronously on the UI thread.

-- Begin SHA verification. Caller passes the parsed manifest plus the
-- snapshotted manual / forced flags (so tick_*_sha -> _complete can branch
-- on the same intent that check_poll captured). Two-phase pipeline:
--
--   1) Preflight (in this function, in pure Lua): walk manifest, classify
--      each entry as missing / locked-skip / readable. Missing entries are
--      recorded directly in s.diff.missing; locked ones are logged and
--      skipped (preserving today's "AV / editor lock = treat as intact"
--      semantics so transient locks don't produce false Repair-Available
--      popups). Readable entries are collected into s.to_hash[].
--
--   2) Hash (deferred across frames): prefer native SHA-256 via PowerShell
--      Get-FileHash on Windows or sha256sum / shasum -a 256 on POSIX;
--      native is hundreds of MB/s vs ~1 MB/s pure-Lua, so on a ~3.6 MB
--      manifest the verify tail drops from 5-12 s to well under 1 s. Pure-
--      Lua remains the reliability floor: if the native subprocess fails
--      to launch, exits non-zero, watchdog-times-out, or produces output
--      that doesn't match preflight, _native_to_lua_fallback flips
--      s.mode = "lua_fallback" and tick_sha_diff walks s.to_hash from
--      idx 1 to recompute from a known-good code path.
--
-- Sets state = "verifying" so the main loop knows to pump the right tick
-- function each frame (tick_native_sha when s.mode == "native";
-- tick_sha_diff when s.mode == "lua" or "lua_fallback").
function Updater.start_sha_diff(manifest, manual, forced, purpose)
  local diff = { missing = {}, mismatched = {} }
  local to_hash = {}            -- list of { path, entry }
  local path_to_entry = {}      -- absolute path -> entry, for native parse

  for _, entry in ipairs(manifest.files or {}) do
    if type(entry) == "table" and type(entry.name) == "string"
        and type(entry.sha256) == "string"
        and Updater.is_safe_filename(entry.name) then
      local path = Updater.local_path_for(entry.name)
      local f, open_err = io.open(path, "rb")
      if not f then
        if reaper.file_exists and reaper.file_exists(path) then
          -- Locked: skip from diff entirely (treat as intact). See
          -- tick_sha_diff's note about Repair-Available false positives.
          Log.line("UPDATE", string.format(
            "start_sha_diff preflight: %s exists but open failed: %s "
            .. "(likely AV / editor lock; skipping from diff)",
            path, tostring(open_err)))
        else
          diff.missing[#diff.missing+1] = entry.name
        end
      else
        f:close()
        to_hash[#to_hash+1] = { path = path, entry = entry }
        path_to_entry[path] = entry
      end
    end
    -- Malformed manifest entry: skip silently here; download_start still
    -- rejects malformed entries before queueing any download.
  end

  update._sha_diff = {
    manifest      = manifest,
    files         = manifest.files,
    to_hash       = to_hash,
    path_to_entry = path_to_entry,
    lua_idx       = 1,             -- pure-Lua walker pointer into to_hash
    cur           = nil,           -- in-flight per-file SHA state (lua mode)
    diff          = diff,
    manual        = manual,
    forced        = forced,
    purpose       = purpose or "repair",
    -- Higher per-frame budget when the user is actively waiting (manual
    -- check or forced repair). Background piggyback checks
    -- (manual = forced = nil/false) keep the conservative default because
    -- they run while the user reads the chat response and any visible
    -- stutter is undesirable. Only consulted by tick_sha_diff -- the
    -- native path runs out-of-process and has no per-frame budget concern.
    budget        = (manual or forced) and CFG.UPDATE_SHA_TIME_BUDGET_MANUAL
                                       or  CFG.UPDATE_SHA_TIME_BUDGET,
    started_at    = time_precise(),
    mode          = "lua",         -- overridden to "native" if subprocess launches
  }

  -- All entries were missing / locked / unsafe: nothing to hash, finalize.
  if #to_hash == 0 then
    Updater._sha_diff_complete()
    return
  end

  -- Try native first. If launch fails (no PowerShell, AV block, file write
  -- error, missing POSIX tool), stay in "lua" mode and the main loop's
  -- verifying branch will pump tick_sha_diff() from lua_idx 1.
  if Updater.fire_native_sha(to_hash) then
    update._sha_diff.mode             = "native"
    update._sha_diff.native_send_time = time_precise()
  end

  update.state = "verifying"
end

-- Launch a native SHA-256 hasher subprocess for every path in to_hash.
-- Writes one "<hex>\t<input path>" line per file to tmp.update_sha_out
-- and the inner-process exit code to tmp.update_sha_exit. Returns true if
-- the launch was attempted, false on prerequisite failure (paths-file
-- write error, defensive quote rejection, PS-script write error).
--
-- Detached via the same Start-Process cmd pattern as fire_get on Windows
-- and a backgrounded subshell on POSIX, so the main thread only pays
-- launcher startup (~200 ms warm PowerShell) -- not the hash duration --
-- and tick_native_sha polls tmp.update_sha_exit each frame for completion.
--
-- The Windows path emits the verbatim INPUT path (not Get-FileHash's
-- $_.Path) so tick_native_sha's exact-match lookup in path_to_entry can't
-- be defeated by provider-side casing or normalization. Output is written
-- via .NET StreamWriter with UTF-8(no-BOM) for predictable encoding
-- across PowerShell 5 / 7 / redirection differences.
function Updater.fire_native_sha(to_hash)
  os.remove(tmp.update_sha_in)
  os.remove(tmp.update_sha_out)
  os.remove(tmp.update_sha_exit)
  os.remove(tmp.update_sha_ps)

  -- Write absolute paths, one per line, UTF-8.
  local pf, pf_err = io.open(tmp.update_sha_in, "wb")
  if not pf then
    Log.line("UPDATE", "fire_native_sha: paths-file open failed: "
                       .. tostring(pf_err))
    return false
  end
  for _, item in ipairs(to_hash) do
    pf:write(item.path)
    pf:write("\n")
  end
  pf:close()

  if RA.IS_WINDOWS then
    -- Defensive guard limited to characters that cannot legitimately
    -- appear in a valid Windows path: " < > | are all reserved by
    -- Windows filenames. Other cmd-significant chars (& ^ ( ) %) ARE
    -- valid in Windows paths ("Program Files (x86)", "R&D", etc.) and
    -- the triple-quoted argument passing protects them; rejecting
    -- them would silently break update / repair for valid users. See
    -- fire_get for the same guard on the manifest-fetch path.
    for _, c in ipairs({'"', '<', '>', '|'}) do
      if tmp.update_sha_in:find(c, 1, true)
          or tmp.update_sha_out:find(c, 1, true)
          or tmp.update_sha_exit:find(c, 1, true)
          or tmp.update_sha_ps:find(c, 1, true) then
        Log.line("UPDATE", string.format(
          "fire_native_sha: refusing to launch with cmd-unsafe "
          .. "character '%s' in tmp paths", c))
        return false
      end
    end

    -- The PS script: read paths, hash each via Get-FileHash, write
    -- "<hex>\t<input path>" to the output file. Per-file try/catch so a
    -- single bad file (locked / deleted between preflight and hash)
    -- doesn't lose the rest -- tick_native_sha's missing-from-output
    -- triage handles those cases.
    local ps_script = string.format(
[[$ErrorActionPreference = 'Continue'
$exitPath = '%s'
$utf8 = New-Object System.Text.UTF8Encoding($false)
try {
  function Get-Sha256Hex([string]$Path) {
    $sha = [System.Security.Cryptography.SHA256]::Create()
    $stream = [System.IO.File]::Open($Path,
      [System.IO.FileMode]::Open,
      [System.IO.FileAccess]::Read,
      [System.IO.FileShare]::ReadWrite)
    try {
      $hash = $sha.ComputeHash($stream)
      return ([System.BitConverter]::ToString($hash)).Replace('-', '').ToLowerInvariant()
    } finally {
      $stream.Dispose()
      $sha.Dispose()
    }
  }
  $paths = Get-Content -LiteralPath '%s' -Encoding UTF8
  $writer = New-Object System.IO.StreamWriter('%s', $false, $utf8)
  try {
    foreach ($p in $paths) {
      $hex = $null
      for ($i = 0; $i -lt 10; $i++) {
        try {
          $hex = Get-Sha256Hex -Path $p
          break
        } catch {
          if ($i -eq 9) { $hex = $null } else { Start-Sleep -Milliseconds 100 }
        }
      }
      if ($hex) {
        $writer.WriteLine($hex + "`t" + $p)
      }
    }
  } finally {
    $writer.Close()
  }
  [System.IO.File]::WriteAllText($exitPath, '0', $utf8)
  exit 0
} catch {
  try {
    [System.IO.File]::WriteAllText($exitPath, '1', $utf8)
  } catch {
  }
  exit 1
}
]],
      Shell.ps_escape(tmp.update_sha_exit), Shell.ps_escape(tmp.update_sha_in),
      Shell.ps_escape(tmp.update_sha_out))

    -- Write the .ps1 with a UTF-8 BOM so PowerShell 5 reads it as UTF-8
    -- unambiguously (PS5 default file encoding is the system codepage;
    -- PS7 defaults to UTF-8). Matters when paths contain non-ASCII (e.g.
    -- a user dir with Unicode characters).
    local sf, sf_err = io.open(tmp.update_sha_ps, "wb")
    if not sf then
      Log.line("UPDATE", "fire_native_sha: PS-script open failed: "
                         .. tostring(sf_err))
      return false
    end
    sf:write("\239\187\191")
    sf:write(ps_script)
    sf:close()

    -- Inner cmd: run the PS script via -File (no script-content quoting
    -- needed -- avoids the inner-PS / cmd / outer-PS triple escape) and
    -- capture the inner PS's exit code via cmd's %errorlevel%.
    local cmd_line = string.format(
      'powershell -NoProfile -ExecutionPolicy Bypass'
      .. ' -File """%s"""',
      tmp.update_sha_ps)

    -- Outer PS: detach via Start-Process so ExecProcess's positive
    -- timeout only waits for PS to spawn cmd (~200 ms warm), not for
    -- the actual hashing. Same pattern as fire_get.
    local ps_cmd = string.format(
      'powershell -NoProfile -WindowStyle Hidden'
      .. ' -Command "Start-Process cmd -ArgumentList \'/c %s\''
      .. ' -WindowStyle Hidden"',
      Shell.ps_escape(cmd_line))
    reaper.ExecProcess(ps_cmd, 5000)
  else
    -- POSIX: prefer sha256sum (GNU; standard on Linux), fall back to
    -- shasum -a 256 (Perl; standard on macOS). exit 127 if neither is
    -- installed -- tick_native_sha falls back to pure-Lua. tr '\n' '\0'
    -- piped to xargs -0 so paths with spaces survive the shell split.
    local cmd = string.format(
      "(if command -v sha256sum >/dev/null 2>&1; then "
      .. "tr '\\n' '\\0' < %s | xargs -0 sha256sum > %s; rc=$?; "
      .. "elif command -v shasum >/dev/null 2>&1; then "
      .. "tr '\\n' '\\0' < %s | xargs -0 shasum -a 256 > %s; rc=$?; "
      .. "else rc=127; fi; echo $rc > %s) &",
      Shell.sh_quote(tmp.update_sha_in), Shell.sh_quote(tmp.update_sha_out),
      Shell.sh_quote(tmp.update_sha_in), Shell.sh_quote(tmp.update_sha_out),
      Shell.sh_quote(tmp.update_sha_exit))
    os.execute(cmd)
  end

  return true
end

-- One tick of the native-hash poll path. Called by the main loop each
-- frame while update.state == "verifying" and s.mode == "native". Reads
-- tmp.update_sha_exit; on completion (exit 0) parses tmp.update_sha_out,
-- triages each preflighted file against the parsed output, and either
-- commits results to s.diff or falls back to lua. On non-zero exit /
-- watchdog timeout / read failure / suspicious output (preflighted file
-- readable but missing from native output), transitions to lua_fallback
-- and lets tick_sha_diff take over from a known-good code path.
function Updater.tick_native_sha()
  local s = update._sha_diff
  if not s then return end

  -- Watchdog: native hashing of ~3.6 MB completes in well under a second;
  -- 15 s + 5 s slack covers cold spawn, slow disks, AV scanning. Beyond
  -- that, fall back rather than wait further.
  if s.native_send_time
      and (time_precise() - s.native_send_time)
          > (CFG.UPDATE_NATIVE_SHA_TIMEOUT + 5) then
    Log.line("UPDATE", "tick_native_sha: watchdog timeout, "
                       .. "falling back to pure-Lua verify")
    Updater._native_to_lua_fallback()
    return
  end

  -- Read exit file. While the inner process is still running, the file
  -- doesn't exist (cmd's `& echo %errorlevel% > exit` only runs after
  -- powershell returns). The race window where it exists but isn't
  -- fully written is small; tonumber(nil) -> nil makes us wait one more
  -- frame on partial reads.
  local ef = io.open(tmp.update_sha_exit, "r")
  if not ef then return end
  local exit_str = ef:read("*a"); ef:close()
  local exit_code = tonumber(exit_str:match("(%d+)"))
  if not exit_code then return end

  if exit_code ~= 0 then
    Log.line("UPDATE", string.format(
      "tick_native_sha: native hasher exited %d, "
      .. "falling back to pure-Lua verify", exit_code))
    Updater._native_to_lua_fallback()
    return
  end

  local of, of_err = io.open(tmp.update_sha_out, "rb")
  if not of then
    Log.line("UPDATE", "tick_native_sha: output read failed: "
                       .. tostring(of_err) .. ", falling back")
    Updater._native_to_lua_fallback()
    return
  end
  local raw = of:read("*a"); of:close()
  -- Defensive UTF-8 BOM strip. The PS script writes via UTF-8(no-BOM)
  -- StreamWriter so this should never trigger, but POSIX redirection
  -- behaves differently across platforms and stripping is harmless.
  if raw:sub(1, 3) == "\239\187\191" then raw = raw:sub(4) end

  -- Parse: "<64 hex>(whitespace)<path>". Both PS-pinned tab-separated
  -- output and POSIX two-space-separated output match this pattern.
  local hash_by_path = {}
  for line in raw:gmatch("[^\r\n]+") do
    local hex, rest = line:match("^([0-9a-fA-F]+)[ \t]+(.+)$")
    if hex and #hex == 64 and rest then
      hash_by_path[rest] = hex:lower()
    end
  end

  -- Triage each preflighted file. Hold mismatched / additional_missing
  -- in local tables so a fallback decision can discard them cleanly --
  -- the lua fallback redoes the comparison from scratch and we don't
  -- want partial native results leaking into its diff.
  local mismatched = {}
  local additional_missing = {}
  local suspicious = false
  for _, item in ipairs(s.to_hash) do
    local local_hash = hash_by_path[item.path]
    if local_hash then
      if local_hash ~= item.entry.sha256:lower() then
        mismatched[#mismatched+1] = item.entry.name
      end
    else
      -- Native produced no hash for this preflight-readable file. Triage:
      --   * file gone now: native saw a delete race -> record as missing
      --   * file present but locked now: AV / lock race -> log + skip
      --   * file present and readable now: native should have hashed it
      --     but didn't -- output is suspicious, fall back to lua so the
      --     whole result set gets recomputed from a known-good path.
      local exists = (reaper.file_exists and reaper.file_exists(item.path))
      if not exists then
        additional_missing[#additional_missing+1] = item.entry.name
      else
        local f = io.open(item.path, "rb")
        if not f then
          Log.line("UPDATE", string.format(
            "tick_native_sha: %s preflight readable but locked now "
            .. "(skipping from diff)", item.path))
        else
          f:close()
          Log.line("UPDATE", string.format(
            "tick_native_sha: %s readable but missing from native output "
            .. "(suspicious, falling back to pure-Lua verify)",
            item.path))
          suspicious = true
          break
        end
      end
    end
  end

  if suspicious then
    Updater._native_to_lua_fallback()
    return
  end

  -- Commit results to s.diff and finalize.
  for _, name in ipairs(mismatched) do
    s.diff.mismatched[#s.diff.mismatched+1] = name
  end
  for _, name in ipairs(additional_missing) do
    s.diff.missing[#s.diff.missing+1] = name
  end
  Updater._sha_diff_complete()
end

-- Switch from native mode to pure-Lua fallback. Reset the lua walker
-- pointer so tick_sha_diff re-walks s.to_hash from the start. Intentionally
-- does NOT clear s.diff -- preflight-derived missing entries remain valid
-- (they're filesystem facts, not native-tool output) and s.diff.mismatched
-- is empty at this point because tick_native_sha only mutates it after a
-- successful triage commit.
function Updater._native_to_lua_fallback()
  local s = update._sha_diff
  if not s then return end
  s.mode    = "lua_fallback"
  s.lua_idx = 1
  s.cur     = nil
end

-- One tick of incremental pure-Lua SHA verification. Called by the main
-- loop each frame while update.state == "verifying" and s.mode == "lua"
-- or "lua_fallback". Walks s.to_hash[] (preflighted readable files) so
-- classification work is not duplicated -- start_sha_diff already filed
-- missing / unsafe / locked entries.
--
-- State machine:
--   * No current file (s.cur == nil): pop the next entry from to_hash.
--     Race-handle the rare case where preflight saw the file readable
--     but it's locked now (log + skip, mirroring start_sha_diff's
--     locked-skip behavior) and the rare nil-read race (treat as locked).
--   * Current file in flight: compress one tick's worth of blocks. When
--     the state is exhausted, finalize, compare to manifest hash, append
--     to s.diff.mismatched on miss, advance lua_idx.
-- When lua_idx walks past #to_hash with no s.cur set, hand off to _complete.
function Updater.tick_sha_diff()
  local s = update._sha_diff
  if not s then return end
  local to_hash = s.to_hash

  if not s.cur then
    while s.lua_idx <= #to_hash do
      local item = to_hash[s.lua_idx]
      local f, open_err = io.open(item.path, "rb")
      if not f then
        Log.line("UPDATE", string.format(
          "tick_sha_diff: %s preflight readable but open failed: %s "
          .. "(likely AV / editor lock; skipping from diff)",
          item.path, tostring(open_err)))
        s.lua_idx = s.lua_idx + 1
      else
        local content = f:read("*a")
        f:close()
        if content then
          s.cur = { entry = item.entry, state = _SHA.create(content) }
          break
        else
          Log.line("UPDATE", string.format(
            "tick_sha_diff: %s opened but read returned nil "
            .. "(treating as locked; skipping from diff)", item.path))
          s.lua_idx = s.lua_idx + 1
        end
      end
    end
    if not s.cur then
      Updater._sha_diff_complete()
      return
    end
  end

  -- File in flight: compress as many 16-block chunks as fit inside the
  -- per-tick time budget. The chunk size is small enough that the budget
  -- check stays meaningful on slow hardware (one chunk ~= 1 ms on a
  -- commodity CPU; would-be 5+ ms on a very old CPU still stops after a
  -- single chunk, which is still better than the previous 192-block
  -- fixed budget would have been on the same hardware).
  local tick_start = time_precise()
  local budget = s.budget or CFG.UPDATE_SHA_TIME_BUDGET
  local done
  repeat
    done = _SHA.step(s.cur.state, 16)
    if done then break end
  until (time_precise() - tick_start) >= budget
  if done then
    local local_hash = _SHA.finalize(s.cur.state)
    if local_hash ~= s.cur.entry.sha256:lower() then
      s.diff.mismatched[#s.diff.mismatched+1] = s.cur.entry.name
    end
    s.cur     = nil
    s.lua_idx = s.lua_idx + 1
  end
end

-- Apply the result of a completed incremental SHA diff. Same branch logic as
-- the inline block that lived in check_poll before the refactor: a non-empty
-- diff transitions to "repair_available" with the popup, an empty diff
-- transitions to "idle" with the manual-check toast (or silence for the
-- piggyback). Clears update._sha_diff so a stale snapshot can never leak
-- into a later check.
function Updater._sha_diff_complete()
  local s = update._sha_diff
  if not s then return end
  local diff     = s.diff
  local manifest = s.manifest
  local manual   = s.manual
  local forced   = s.forced
  local purpose  = s.purpose or "repair"
  local elapsed  = time_precise() - (s.started_at or time_precise())
  update._sha_diff = nil

  if purpose == "update" then
    update.state             = "available"
    update.remote_version    = manifest.version
    update.manifest          = manifest
    update.update_missing    = diff.missing
    update.update_mismatched = diff.mismatched
    Log.line("UPDATE", string.format(
      "sha_diff complete in %.2fs: remote v%s newer than installed v%s; "
      .. "%d file(s) differ (%d missing, %d mismatched).",
      elapsed, tostring(manifest.version), tostring(CFG.VERSION),
      #diff.missing + #diff.mismatched, #diff.missing, #diff.mismatched))
    if manual then S.float_toast = nil end
    if not forced and not manual then
      local snooze = Store.update_snooze()
      if snooze and os.time() < snooze then
        update.popup_opened = true
      end
    end
    return
  end

  local repair_count = #diff.missing + #diff.mismatched
  if repair_count > 0 then
    update.state          = "repair_available"
    update.remote_version = manifest.version  -- same as CFG.VERSION; kept
                                              -- for consistent popup format
    update.manifest       = manifest
    update.repair_missing    = diff.missing
    update.repair_mismatched = diff.mismatched
    Log.line("UPDATE", string.format(
      "sha_diff complete in %.2fs: version matches (%s) but %d files "
      .. "need repair (%d missing, %d mismatched).",
      elapsed, manifest.version, repair_count,
      #diff.missing, #diff.mismatched))
    -- Match the "available" branch: clear the sticky "Checking..."
    -- toast so the repair popup is the sole visual feedback.
    if manual then S.float_toast = nil end
  else
    update.state = "idle"  -- already up to date and all files intact
    Log.line("UPDATE", string.format(
      "sha_diff complete in %.2fs: version matches (%s) and all files "
      .. "intact.", elapsed, manifest.version))
    -- Stamp the last-successful-check time so the footer's version-
    -- number tooltip can show "Up to date (checked X ago)" instead
    -- of the generic "Click to check for updates" copy. Applies to
    -- both manual checks (Settings button / footer link) and the
    -- auto-fired piggyback check after the first chat response.
    update._last_ok_at = os.time()
    -- Manual check (Settings button / version-number link) with no
    -- action needed -> give the user explicit feedback that their
    -- click did something. Auto-fired checks stay silent.
    if manual then
      UI.show_float_toast(
        "ReaAssist is up to date (v" .. CFG.VERSION .. ")", "ok")
    end
  end
end

function Updater.check_poll()
  local result = Updater.poll()
  if result == "waiting" then return end
  -- Snapshot-and-clear both one-shot flags before any return path so a
  -- single force_reinstall / manual_check call cannot leak into a
  -- later organic check. Without this, update.force stayed true after
  -- consumption, and subsequent startup checks were misclassified as
  -- "available" even when the user was already on the current version,
  -- feeding the wrong action_was_repair bool into download_start's
  -- completion copy. _manual follows the same snapshot pattern so the
  -- "You're up to date" toast only fires for the check the user just
  -- clicked, not any later one.
  local forced = update.force
  update.force = false
  local manual = update._manual
  update._manual = false
  if result == "error" then
    -- Network / curl failure. Only surface as a failure when the user
    -- explicitly forced this check (Repair button): organic startup
    -- checks fail silently so offline launches do not nag the user.
    if forced then
      Updater._set_failure("manifest_fetch",
        "Could not reach update server (network error or timeout).\n\n"
        .. "Please enable your network connection if it is disabled.")
    end
    -- Manual Settings button: replace the sticky "Checking..." toast
    -- with a transient error message so the user sees explicit failure
    -- feedback on their explicit action.
    if manual then
      UI.show_float_toast(
        "Could not reach update server\nCheck your network connection",
        "err")
    end
    update.state = "idle"
    return
  end
  -- Parse manifest.
  local manifest = Updater.read_response()
  if not manifest
    or type(manifest.version) ~= "string"
    or type(manifest.files) ~= "table" then
    -- Distinguish empty / near-empty response (connection dropped
    -- silently, typical of offline on Windows where DNS cache may let
    -- curl exit with status 0 even though no bytes were received) from
    -- a body that actually contained something but wasn't valid JSON.
    -- Empty body is surfaced as a connection error so the user's toast
    -- / Bootstrap error message points at the likely cause instead of
    -- blaming the server for "malformed" output.
    local body_size = 0
    local bf = io.open(tmp.update_out, "rb")
    if bf then
      bf:seek("end")
      body_size = bf:seek("cur")
      bf:close()
    end
    local empty = (body_size < 2)
    if forced then
      if empty then
        Updater._set_failure("manifest_fetch",
          "Could not reach update server (no response received).\n\n"
          .. "Please enable your network connection if it is disabled.")
      else
        Updater._set_failure("manifest_parse",
          "Update server returned a malformed manifest "
          .. "(missing version or files field).")
      end
    end
    if manual then
      if empty then
        UI.show_float_toast(
          "Could not reach update server\nCheck your network connection",
          "err")
      else
        UI.show_float_toast(
          "Update server returned a malformed response", "err")
      end
    end
    update.state = "idle"
    return
  end
  -- Three-way version compare so we never repair against an older manifest
  -- (which would effectively downgrade the install). Equality via the
  -- "neither newer" rule because is_newer parses numerically (so "1.0.0"
  -- and "1.0.0.0" compare equal even though string == would say false).
  update.update_missing = nil
  update.update_mismatched = nil
  local remote_newer = Updater.is_newer(manifest.version, CFG.VERSION)
  local remote_older = Updater.is_newer(CFG.VERSION, manifest.version)
  if remote_newer then
    -- A newer version is on the server. The update flow handles this case --
    -- first compute the changed-file set asynchronously, then show
    -- "Update Available". That moves the SHA work before the prompt so
    -- clicking Update Now can immediately enter the download UI.
    Updater.start_sha_diff(manifest, manual, forced, "update")
  elseif not remote_older then
    -- Versions match. But the local install may still have missing or
    -- corrupted files (user deleted something, disk error, partial copy).
    -- Normally we run the per-file SHA diff to find them, deferred across
    -- frames so REAPER stays responsive (synchronous diff would freeze
    -- the UI for ~100-500 ms hashing ~5-6 MB of fonts and large .lua
    -- files). See Updater.start_sha_diff / tick_sha_diff for the
    -- incremental machine.
    --
    -- Bootstrap fast-path: when this check fired from the Bootstrap
    -- repair button (`update._bootstrap_repair == true`), we already
    -- know which files are missing/broken from the critical-files probe
    -- at startup -- skip the SHA verify entirely and route directly to
    -- repair_available with the known list. The trade-off: SHA-level
    -- corruption in non-critical files won't be caught by THIS repair,
    -- but the next non-bootstrap launch's normal SHA verify will.
    if update._bootstrap_repair then
      update._bootstrap_repair = nil
      update.manifest          = manifest
      update.remote_version    = manifest.version
      -- S.bootstrap_missing entries can carry a " (load error)" suffix
      -- (added by the font-load probe) that is presentation-only and
      -- not part of the manifest filename; strip before queueing.
      local missing = {}
      for _, name in ipairs(S.bootstrap_missing or {}) do
        local clean = name:gsub("%s*%(load error%)$", "")
        missing[#missing + 1] = clean
      end
      update.repair_missing    = missing
      update.repair_mismatched = {}
      update.state             = "repair_available"
      Log.line("UPDATE", string.format(
        "check_poll: bootstrap fast-path armed; queueing %d known-broken "
        .. "file(s) without SHA verify.", #missing))
      if manual then S.float_toast = nil end
    else
      Updater.start_sha_diff(manifest, manual, forced)
    end
  elseif forced then
    -- Remote manifest is older than installed AND user explicitly asked to
    -- reinstall. Repairing against an older manifest would effectively
    -- downgrade the install; refuse with a specific failure so the
    -- "Update Failed" dialog can surface the cause.
    Updater._set_failure("manifest_version", string.format(
      "Update server returned manifest v%s, older than installed v%s. "
      .. "Refusing to repair against an older manifest.",
      tostring(manifest.version), tostring(CFG.VERSION)))
    update.state = "failed"
  else
    -- Remote manifest is older than installed and the user didn't force a
    -- reinstall. Most likely a CDN propagation race or a stale branch.
    -- Skip silently for auto-fire piggyback checks; surface a brief toast
    -- for explicit manual checks so the user knows the click was processed.
    update.state = "idle"
    Log.line("UPDATE", string.format(
      "Remote manifest is older (v%s) than installed (v%s); "
      .. "skipping repair check.",
      tostring(manifest.version), tostring(CFG.VERSION)))
    if manual then
      UI.show_float_toast(
        "Update server returned an older manifest; try again later.",
        "err", true)
    end
  end
end

-- Validate a manifest filename: no path traversal, no absolute paths, safe extension.
-- Forward-slash subpaths are allowed (e.g. "Resources/UI.lua",
-- "Resources/ReEQ/Dependencies/svf_filter.jsfx-inc") so the manifest can mirror
-- the on-disk layout. Backslashes, leading slashes, drive letters, and any
-- ".." or hidden ("."-prefixed) path segments are rejected.
function Updater.is_safe_filename(name)
  if type(name) ~= "string" or name == "" then return false end
  -- Strict allowlist: only ASCII alphanumerics, spaces, underscore,
  -- hyphen, dot, and forward slash. Blocks shell-sensitive characters
  -- ($, `, &, ?, #, ;, parens, quotes, etc.) before they ever reach a
  -- curl command line or a local path. The remaining checks below run
  -- after the allowlist as defense-in-depth.
  if not name:match("^[A-Za-z0-9_./ %-]+$") then return false end
  -- Reject backslashes, leading /, drive letters (absolute paths).
  if name:match("^/") or name:match("^%a:") then return false end
  if name:find("\\", 1, true) then return false end
  -- Validate each forward-slash-separated path segment.
  for segment in (name .. "/"):gmatch("([^/]*)/") do
    if segment == "" or segment == "." or segment == ".." then return false end
    if segment:sub(1, 1) == "." then return false end  -- hidden dotfiles/dirs
    if segment:sub(1, 1) == " " or segment:sub(-1) == " " then return false end
  end
  -- The final segment is the filename itself.
  local base_name = name:match("([^/]+)$") or name
  -- Reject Windows reserved device names (CON, PRN, AUX, NUL, COM1-9, LPT1-9).
  local base = base_name:match("^([^%.]+)") or ""
  if RA.is_windows_reserved_name(base) then return false end
  -- Allow only known safe extensions.
  local ext = base_name:match("%.([^%.]+)$")
  if not ext then return false end
  local safe = {
    lua=true, md=true, txt=true, jsfx=true, ["jsfx-inc"]=true,
    json=true, png=true, csv=true, pdf=true,
    -- .ttf added in Stage 3.4: Resources/fonts/*.ttf are part of the
    -- distributable install (the bootstrap critical-files check verifies
    -- them at launch), so the download pipeline has to accept them.
    ttf=true,
  }
  if not safe[ext:lower()] then return false end
  return true
end

-- Resolve a manifest filename ("Resources/X.md") to an absolute local path
-- using the host OS separator. Centralized so the SHA-diff verifier and
-- download_poll (the write target) agree on the layout.
function Updater.local_path_for(filename)
  local rel = filename
  if RA.SEP ~= "/" then rel = rel:gsub("/", RA.SEP) end
  return RA.script_path .. rel
end

-- Paths the orphan-cleanup pass must never delete, even if a manifest
-- listed them in removed_files. System_Prompt_Custom.md is the documented
-- power-user override -- the loader prefers it over the stock prompt and
-- it's intentionally untracked so updates don't touch it. The Data/ entries
-- are structurally outside the updater-owned zone, but keeping them here makes
-- that user-state contract explicit; the legacy Resources/ entries protect
-- users during the migration window.
local PROTECTED_FROM_REMOVAL = {
  ["Resources/System_Prompt_Custom.md"] = true,
  ["Resources/Debug.log"]                = true,
  ["Resources/FX_Cache.json"]            = true,
  ["Data/Config.json"]                   = true,
  ["Data/Providers.json"]                = true,
  ["Data/State.json"]                    = true,
  ["Data/Debug.log"]                     = true,
  ["Data/FX_Cache.json"]                 = true,
}

local REMOVABLE_TOP_LEVEL_COMPANIONS = {
  ["ReaAssist - Screen Reader Mode.lua"] = true,
  ["ReaAssist_ScreenReaderMode.lua"]     = true,
}

-- Predicate gating per-path orphan deletes. All four checks must hold:
--   1. is_safe_filename: path-traversal, absolute paths, backslashes,
--      hidden segments, and non-allowlisted extensions all rejected here.
--   2. Inside ReaAssist's install zone: ReaAssist.lua, known retired
--      top-level companion scripts, the three top-level docs, or anything
--      under Resources/. Anything else is out of scope for the package and
--      never something we shipped.
--   3. Not in PROTECTED_FROM_REMOVAL: user-override + runtime artifacts.
--   4. Not also in the current manifest's files list: defensive double-
--      lock against an inconsistent manifest where a path appears in both
--      `files` and `removed_files`. gen_manifest.py guards against this
--      at authoring time; this is belt-and-suspenders.
function Updater.should_remove_orphan(name, current_files)
  if type(name) ~= "string" then return false end
  if not Updater.is_safe_filename(name) then return false end
  if current_files and current_files[name] then return false end
  local owned =
       name == "ReaAssist.lua"
    or REMOVABLE_TOP_LEVEL_COMPANIONS[name] == true
    or name == "CHANGELOG.md"
    or name == "LICENSE.txt"
    or name == "README.md"
    or name:sub(1, 10) == "Resources/"
  if not owned then return false end
  if PROTECTED_FROM_REMOVAL[name] then return false end
  return true
end

function Updater.download_start()
  -- Accept both triggers: "available" (new version on server) and
  -- "repair_available" (version matches but some files are missing or
  -- corrupted locally). The download pipeline and SHA-diff logic are
  -- identical for both; only the popup messaging differs.
  if (update.state ~= "available" and update.state ~= "repair_available")
      or not update.manifest then return end
  if Updater.font_download_busy() then
    if UI and UI.show_float_toast then
      UI.show_float_toast(RA.t("settings.font.finish_download_first", nil,
        "Finish the font download first"), "err")
    end
    return
  end
  if Updater.language_download_busy() then
    if UI and UI.show_float_toast then
      UI.show_float_toast(RA.t("settings.lang.finish_download_first", nil,
        "Finish the language pack download first"), "err")
    end
    return
  end
  -- Remember which trigger started the session so the "done" view can
  -- say "Updated to vX" vs "Restored N files" accurately.
  update.action_was_repair = (update.state == "repair_available")
  update.download_queue = {}
  update.applied_files = {}  -- track successfully written files for rollback
  update.skipped_count  = 0  -- files whose local SHA already matches manifest
  -- When entering from repair_available OR an update prompt produced by
  -- the check-time SHA diff, we already know which files are missing or
  -- mismatched. Reuse those lists instead of re-hashing the entire
  -- manifest synchronously after the user clicks the button. Trade-off:
  -- corruption introduced in the few seconds between the diff completing
  -- and the click would not be caught here, but the next launch's SHA
  -- check would catch it.
  local repair_fileset = nil
  if update.action_was_repair
      and update.repair_missing
      and update.repair_mismatched then
    repair_fileset = {}
    for _, n in ipairs(update.repair_missing)    do repair_fileset[n] = true end
    for _, n in ipairs(update.repair_mismatched) do repair_fileset[n] = true end
  end
  local update_fileset = nil
  if not update.action_was_repair
      and update.update_missing
      and update.update_mismatched then
    update_fileset = {}
    for _, n in ipairs(update.update_missing)    do update_fileset[n] = true end
    for _, n in ipairs(update.update_mismatched) do update_fileset[n] = true end
  end
  for _, entry in ipairs(update.manifest.files) do
    local filename, expected_hash
    if type(entry) == "table" and entry.name and entry.sha256 then
      filename      = entry.name
      expected_hash = entry.sha256
    else
      -- Reject manifests without per-file SHA-256 hashes. All production
      -- manifests must use the {name, sha256} format for integrity
      -- verification. Route through _set_failure so the Update Failed
      -- dialog has a real reason to display instead of the generic
      -- "(unknown)" the empty fields would produce.
      Updater._set_failure("manifest_file",
        "Manifest entry missing required SHA-256 hash")
      update.state = "failed"
      return
    end
    if not Updater.is_safe_filename(filename) then
      Updater._set_failure("manifest_file",
        "Unsafe filename in manifest: " .. tostring(filename))
      update.state = "failed"
      return
    end
    if repair_fileset then
      -- Repair path: queue only files the SHA diff flagged. Everything else
      -- already matched per the diff and is safe to skip without re-hashing.
      if repair_fileset[filename] then
        update.download_queue[#update.download_queue+1] = {
          filename = filename,
          url      = Updater.url_for(filename),
          sha256   = expected_hash,
        }
      else
        update.skipped_count = update.skipped_count + 1
      end
    elseif update_fileset then
      -- Version-bump path after check-time SHA diff: queue only files
      -- already proven different so the Update Now click can jump
      -- straight into the download UI instead of synchronously hashing
      -- every manifest entry.
      if update_fileset[filename] then
        update.download_queue[#update.download_queue+1] = {
          filename = filename,
          url      = Updater.url_for(filename),
          sha256   = expected_hash,
        }
      else
        update.skipped_count = update.skipped_count + 1
      end
    else
      -- Legacy/impossible state: modern check paths compute repair_fileset or
      -- update_fileset before the button is shown. If a stale state reaches
      -- here without that diff, do not synchronously hash the whole manifest on
      -- the UI thread; queue the file and rely on post-download SHA verify.
      update.download_queue[#update.download_queue+1] = {
        filename = filename,
        url      = Updater.url_for(filename),
        sha256   = expected_hash,
      }
    end
  end
  -- If every file already matches (user manually swapped files, or re-invoked
  -- an update that already ran), close the popup and stay idle -- the
  -- manifest version stamp is handled by the next startup check. Surface a
  -- short toast so the click on "Update Now" doesn't silently appear to do
  -- nothing; without it the popup just disappears and the user has no
  -- confirmation that the action completed.
  if #update.download_queue == 0 then
    Log.line("UPDATE", string.format(
      "download_start: all %d manifest files already match local SHA; "
      .. "nothing to download.", update.skipped_count))
    update.show_dialog = false
    update.state       = "idle"
    if UI and UI.show_float_toast then
      UI.show_float_toast(RA.t("update.toast.up_to_date", nil,
        "Already up to date"), "ok")
    end
    return
  end
  Log.line("UPDATE", string.format(
    "download_start: %d files to download, %d already up to date.",
    #update.download_queue, update.skipped_count))
  update.download_idx = 1
  update.state = "downloading"
  local entry = update.download_queue[1]
  if not Updater.fire_get(entry.url, tmp.update_out, tmp.update_exit,
      { cache_bust = false }) then
    Updater._set_failure("download_start", string.format(
      "Could not start download for %s.", tostring(entry.filename)))
    update.state = "failed"
    return
  end
end

-- Rollback all successfully written files. For files that existed before
-- the update (bak_existed=true), restore the .bak. For fresh-install adds
-- (bak_existed=false), just delete the dest -- there is no prior version
-- to restore, and renaming a nonexistent .bak over dest silently deletes
-- it, leaving the user with neither a working file nor a recoverable
-- backup if the next update file fails.
function Updater.rollback()
  if not update.applied_files then return end
  -- Track restore failures so we can surface them via update.last_error.
  -- Rollback runs because some EARLIER step already failed, so last_step
  -- and last_error are typically already set at this point. We only
  -- overwrite them if a restore failure produces a worse situation than
  -- the original failure (i.e. a file the user had before the update is
  -- now gone with no .bak to recover from), which is the one rollback
  -- failure mode that genuinely requires manual attention.
  local restore_failures = {}
  for i = #update.applied_files, 1, -1 do
    local applied = update.applied_files[i]
    local dest = applied.path
    os.remove(dest)
    if applied.bak_existed then
      local bak_path = dest .. ".bak"
      local ok, err = os.rename(bak_path, dest)
      if not ok then
        Log.line("UPDATE", string.format(
          "rollback restore failed for %s: %s "
          .. "(.bak still on disk; manual recovery may be needed)",
          dest, tostring(err)))
        restore_failures[#restore_failures + 1] = dest
      end
    end
  end
  update.applied_files = {}
  if #restore_failures > 0 then
    -- Append a manual-attention note to the existing failure message so
    -- the Update Failed dialog surfaces both the original cause and the
    -- restore problem. Don't replace last_error/last_step -- the original
    -- failure step is the right pointer for the user; the restore note
    -- just adds urgency.
    local note = string.format(
      "\n\nNote: rollback could not restore %d previous file%s "
      .. "(.bak file%s left on disk for manual recovery): %s",
      #restore_failures,
      #restore_failures == 1 and "" or "s",
      #restore_failures == 1 and "" or "s",
      table.concat(restore_failures, ", "))
    update.last_error = (update.last_error or "(no prior error)") .. note
  end
end

-- Poll the current file download. Advances to next file or applies update.
function Updater.download_poll()
  local entry = update.download_queue[update.download_idx]
  local fname = entry and entry.filename or "?"
  local result = Updater.poll()
  if result == "waiting" then return end
  if result == "error" then
    Updater._set_failure("download",
      string.format("curl failed or timed out while fetching %s", fname))
    Updater.rollback()
    update.state = "failed"
    return
  end
  -- Read the downloaded file and save it.
  local f, f_err = io.open(tmp.update_out, "rb")
  if not f then
    Updater._set_failure("download_read",
      string.format("Could not open downloaded %s: %s",
                    fname, tostring(f_err)))
    Updater.rollback()
    update.state = "failed"
    return
  end
  local content = f:read("*a"); f:close()
  if not content or #content == 0 then
    Updater._set_failure("download_read",
      string.format("Downloaded %s is empty.", fname))
    Updater.rollback()
    update.state = "failed"
    return
  end
  -- Integrity checks.
  -- SHA-256 hash verification: if the manifest provided a hash, verify it.
  -- This is the primary integrity gate. A mismatch means the download was
  -- corrupted or tampered with; reject the entire update.
  if entry.sha256 then
    local actual_hash = sha256_hash(content)
    if actual_hash ~= entry.sha256:lower() then
      Updater._set_failure("sha_verify", string.format(
        "SHA-256 mismatch for %s: expected %s, got %s",
        fname, entry.sha256:lower(), actual_hash))
      Updater.rollback()
      update.state = "failed"
      return
    end
  end
  -- Secondary sanity check: every shipped .lua file contains a
  -- CFG.VERSION literal. Sidecars that do not otherwise need the runtime
  -- version include a marker comment for exactly this reason. A
  -- download that passes SHA but doesn't contain the marker has either
  -- been intercepted (proxy injecting an HTML error page) or is some
  -- other file entirely. Distinct step name from sha_verify so the
  -- Update-Failed dialog can show a content-specific message instead
  -- of the CDN-propagation copy that fits sha_verify cases.
  if entry.filename:match("%.lua$") then
    if not content:find("CFG.VERSION", 1, true) then
      Updater._set_failure("content_verify", string.format(
        "Downloaded %s is missing the CFG.VERSION marker "
        .. "(rejected as likely-corrupt or non-ReaAssist content).",
        fname))
      Updater.rollback()
      update.state = "failed"
      return
    end
  end
  -- Write to a .tmp file first, then rename. Manifest entries may include
  -- forward-slash subpaths (e.g. "Resources/UI.lua"); the path
  -- helper normalizes them to the platform separator. Ensure the parent
  -- directory exists so fresh installs can create the Resources/ tree on
  -- first update.
  local dest = Updater.local_path_for(entry.filename)
  local parent = dest:match("^(.*)[\\/][^\\/]+$")
  if parent and parent ~= "" then
    reaper.RecursiveCreateDirectory(parent, 0)
  end
  local tmp_path = dest .. ".tmp"
  local bak_path = dest .. ".bak"
  -- Write temp file. pcall-wrap the write/close so short writes, disk-
  -- full, and permission errors propagate as failure instead of silently
  -- shipping a truncated file.
  local wf, open_err = io.open(tmp_path, "wb")
  if not wf then
    Updater._set_failure("write_open", string.format(
      "Could not open temp file %s for write: %s",
      tmp_path, tostring(open_err)))
    Updater.rollback()
    update.state = "failed"
    return
  end
  local w_ok, w_err = pcall(function()
    local ok, perr = wf:write(content)
    if not ok then error(perr or "write returned nil", 0) end
  end)
  local c_ok, c_err = pcall(function()
    local ok, perr = wf:close()
    if not ok then error(perr or "close returned nil", 0) end
  end)
  if not w_ok or not c_ok then
    Updater._set_failure("write", string.format(
      "Write to %s failed: %s",
      tmp_path, tostring(w_err or c_err)))
    os.remove(tmp_path)
    Updater.rollback()
    update.state = "failed"
    return
  end
  -- Back up current file. We must distinguish "dest does not exist
  -- (fresh-install add)" from "dest exists but rename failed (lock,
  -- permissions, AV scan, cloud sync, editor handle)". `os.rename`
  -- returns nil for both, so probing existence first is the only way
  -- to disambiguate. Misclassifying an existing-but-locked file as
  -- fresh-install is dangerous: rollback's fresh-install branch deletes
  -- dest, which would destroy the only intact copy when no .bak was
  -- ever created. rename_bak_existed carries the truth into
  -- rename_retry_poll and rollback.
  os.remove(bak_path)
  local dest_existed = reaper.file_exists and reaper.file_exists(dest)
  if dest_existed then
    local ok_bak, bak_err = os.rename(dest, bak_path)
    if not ok_bak then
      os.remove(tmp_path)
      Updater._set_failure("backup", string.format(
        "Could not back up existing file %s: %s",
        dest, tostring(bak_err)))
      Updater.rollback()
      update.state = "failed"
      return
    end
    update.rename_bak_existed = true
  else
    update.rename_bak_existed = false
  end
  -- Move temp to final. On Windows, Defender / AV may hold a short-lived lock
  -- on the .tmp file immediately after close, causing rename to fail during
  -- the scan window (~20-50ms). Instead of busy-waiting, we attempt the rename
  -- once and defer to "rename_retry" state if it fails. The main loop will
  -- call Updater.rename_retry_poll() on subsequent frames (~30ms apart), which
  -- is a natural non-blocking delay that avoids stalling the UI thread.
  local ok_mv = os.rename(tmp_path, dest)
  if not ok_mv then
    -- Stash rename context and defer. The next frame will retry.
    update.rename_failures = 1
    update.rename_tmp      = tmp_path
    update.rename_dest     = dest
    update.rename_bak      = bak_path
    update.state           = "rename_retry"
    return
  end
  Updater.advance_after_rename(dest)
end

-- Fire auto-restart if the download pipeline is in "done" state, the
-- restart delay has elapsed, and we have not already fired. Called from
-- both the main loop and Bootstrap.loop so either flow auto-restarts
-- after a successful apply. Single-fire via update.restart_fired so we
-- only invoke Main_OnCommand once.
--
-- Fires the external relauncher action (registered at startup) and
-- closes ourselves. Firing Main_OnCommand on ReaAssist's own CMD_ID
-- from inside our still-running defer chain triggers REAPER's
-- re-entrance handling -- the action "is already running" -- and the
-- single-instance handshake interprets that as a toggle-off, exiting
-- the new instance immediately. The relauncher is a separate script
-- with its own action id, so invoking it from here does NOT hit that
-- re-entrance path. It waits for our "running" ExtState to clear,
-- re-registers ReaAssist via AddRemoveReaScript, and fires a fresh
-- Main_OnCommand on ReaAssist from its own context.
--
-- advance_after_rename only sets update.restart_after when the
-- relauncher file is present on disk, so by the time we reach this
-- function the on-demand AddRemoveReaScript call should succeed.
function Updater.try_auto_restart()
  if update.state ~= "done" then return end
  if not update.restart_after or update.restart_fired then return end
  if time_precise() < update.restart_after then return end
  update.restart_fired = true
  local ok = Updater.fire_relauncher_now()
  if not ok then update.restart_after = nil end
  return ok
end

-- Shared helper: fires the relauncher script in its own Lua state, then
-- closes the current ReaAssist instance. Used by:
--   * try_auto_restart (post-update success)
--   * Render._factory_reset_execute (UI file -- relauncher path is
--     local to this file, so the UI can't fire it directly)
-- Returns true on success, false if the relauncher couldn't be
-- registered (caller can fall back to a "close and reopen" prompt).
function Updater.fire_relauncher_now()
  if not RA._file_exists(RELAUNCHER_PATH) then return false end
  -- Lazy-register the relauncher action right before firing it. Keeps
  -- the Actions list uncluttered for sessions where no auto-restart
  -- ever happens. AddRemoveReaScript is synchronous and the returned
  -- cmd_id is immediately usable from Main_OnCommand. commit=false so
  -- the registration is session-only (vanishes when REAPER closes).
  local cmd_id = reaper.AddRemoveReaScript(true, 0, RELAUNCHER_PATH, false)
  if cmd_id and cmd_id ~= 0 then
    reaper.Main_OnCommand(cmd_id, 0)
    S.script_open = false
    return true
  end
  return false
end

-- Advance to the next file (or finish) after a successful rename.
function Updater.advance_after_rename(dest)
  -- Capture whether dest had a .bak before this apply. rollback uses the
  -- flag to skip restore for fresh-install adds (no prior .bak to restore;
  -- rolling back means simply deleting the newly-written dest, not renaming
  -- a nonexistent .bak over it which would silently delete the new file).
  update.applied_files[#update.applied_files+1] = {
    path = dest,
    bak_existed = (update.rename_bak_existed == true),
  }
  update.rename_failures = 0
  update.rename_tmp      = nil
  update.rename_dest     = nil
  update.rename_bak      = nil
  update.rename_bak_existed = false
  if update.download_idx < #update.download_queue then
    update.download_idx = update.download_idx + 1
    local next_entry = update.download_queue[update.download_idx]
    if not Updater.fire_get(next_entry.url, tmp.update_out, tmp.update_exit,
        { cache_bust = false }) then
      Updater._set_failure("download_start", string.format(
        "Could not start download for %s.", tostring(next_entry.filename)))
      Updater.rollback()
      update.state = "failed"
      return
    end
    update.state = "downloading"
  else
    for _, applied in ipairs(update.applied_files) do
      os.remove(applied.path .. ".bak")
    end
    -- Per-version stale-file cleanup. The new manifest's removed_files
    -- list (auto-populated by gen_manifest.py from the diff between this
    -- release and the prior, plus carry-forward of older deletions for
    -- users skipping versions) names files we previously shipped and no
    -- longer do. Without this step a renamed file's old name would
    -- linger on disk forever -- the rest of the updater only writes new
    -- files and overwrites existing ones, never deletes. Three layers
    -- of safety make removing user-facing files here safe:
    --   1. Authoring layer: gen_manifest.py only ever populates this
    --      list from prior manifests we ourselves shipped. A user-
    --      dropped file in the install dir cannot end up there.
    --   2. is_safe_filename: rejects path-traversal, absolute paths,
    --      backslashes, hidden segments, and unknown extensions.
    --   3. should_remove_orphan: enforces the "owned path" zone and the
    --      PROTECTED_FROM_REMOVAL set (custom system prompt override,
    --      runtime debug log, FX cache).
    -- os.remove failures are logged but do not fail the update; the
    -- new files are already in place, lingering orphans are cosmetic.
    do
      local removed = update.manifest and update.manifest.removed_files
      if type(removed) == "table" then
        local current_files = {}
        for _, entry in ipairs(update.manifest.files or {}) do
          if type(entry) == "table" and type(entry.name) == "string" then
            current_files[entry.name] = true
          end
        end
        for _, name in ipairs(removed) do
          if Updater.should_remove_orphan(name, current_files) then
            local path = Updater.local_path_for(name)
            if reaper.file_exists and reaper.file_exists(path) then
              local ok = os.remove(path)
              Log.line("UPDATE", string.format(
                "removed orphan %s: %s",
                name, ok and "ok" or "failed"))
            end
          elseif type(name) == "string" then
            -- Loud about rejected entries so a malformed manifest doesn't
            -- silently get past the predicate. Only log the first ~20
            -- chars of the name to keep the log line short on
            -- pathological inputs.
            Log.line("UPDATE", string.format(
              "removed_files: refused %s (outside owned zone or "
              .. "protected)", tostring(name):sub(1, 80)))
          end
        end
      end
    end
    update.state   = "done"
    update.applied = true
    -- Active stale-stock nudge for power-user prompt overrides. If this
    -- update modified the stock system prompt AND the user has a custom
    -- override file in place (which the loader prefers over the stock),
    -- set a persistent ExtState flag. The next-launch path reads it,
    -- clears it, and shows a one-time sticky toast inviting the user to
    -- diff the new stock prompt against their custom copy and merge any
    -- improvements worth keeping. Persistent (3rd arg true) so it
    -- survives the auto-restart that follows.
    do
      local stock_pp  = RA.RESOURCES_DIR .. "System_Prompt.md"
      local custom_pp = RA.RESOURCES_DIR .. "System_Prompt_Custom.md"
      local prompt_changed = false
      for _, applied in ipairs(update.applied_files) do
        if applied.path == stock_pp then prompt_changed = true; break end
      end
      if prompt_changed and reaper.file_exists(custom_pp) then
        reaper.SetExtState(CFG.EXT_NS, "prompt_review_pending", "1", true)
      end
    end
    -- Stage 3.4 auto-restart: schedule a short delay (so the user sees
    -- the "Applied" confirmation), then re-launch the script via the
    -- sidecar relauncher (Relaunch.lua). The relauncher re-
    -- registers ReaAssist via AddRemoveReaScript and fires it from its
    -- own script context, so auto-restart works regardless of how this
    -- instance was launched. File-existence check (cheap, no action-
    -- registry side effects) gates the restart scheduling so the done-
    -- view message stays honest: falls back to "Close and reopen" if
    -- the relauncher file is missing, which only happens on a broken
    -- install. try_auto_restart does the actual AddRemoveReaScript
    -- registration on-demand when it fires.
    if reaper.file_exists(RELAUNCHER_PATH) then
      update.restart_after = time_precise() + 1.5
      update.restart_fired = false
    else
      update.restart_after = nil
    end
  end
end

-- Called from the main loop when state == "rename_retry". Each call is one
-- frame (~30ms apart), providing a natural non-blocking delay between
-- attempts without busy-waiting. Ceiling is 15 attempts (~450ms): the
-- previous 5-attempt limit (~150ms total) tripped false-fails on cold
-- Windows Defender scans, which can hold a just-closed file exclusively
-- for 300-500ms. 15 covers the tail of that distribution without
-- noticeably delaying success cases (a single retry is the median).
function Updater.rename_retry_poll()
  if not update.rename_tmp or not update.rename_dest then
    Updater._set_failure("rename",
      "rename_retry_poll entered with no pending paths.")
    update.state = "failed"
    return
  end
  local ok_mv = os.rename(update.rename_tmp, update.rename_dest)
  if ok_mv then
    Updater.advance_after_rename(update.rename_dest)
    return
  end
  update.rename_failures = update.rename_failures + 1
  if update.rename_failures >= 15 then
    -- Give up. Restore the backup only if one was actually created --
    -- otherwise the destination is a fresh-install add and there is
    -- nothing to restore. Skipping the restore in that case prevents
    -- an empty-rename clobber that leaves neither dest nor bak.
    if update.rename_bak_existed then
      local ok_restore, restore_err = os.rename(update.rename_bak,
                                                update.rename_dest)
      if not ok_restore then
        Log.line("UPDATE", string.format(
          "rollback restore failed for %s: %s",
          update.rename_dest, tostring(restore_err)))
      end
    else
      -- Fresh-install add: no bak exists. Remove any leftover dest.
      os.remove(update.rename_dest)
    end
    os.remove(update.rename_tmp)
    Updater._set_failure("rename", string.format(
      "Could not rename downloaded file into place after %d attempts "
      .. "(%s -> %s). Antivirus or file lock?",
      update.rename_failures, update.rename_tmp, update.rename_dest))
    update.rename_tmp  = nil
    update.rename_dest = nil
    update.rename_bak  = nil
    update.rename_bak_existed = false
    Updater.rollback()
    update.state = "failed"
  end
  -- Otherwise stay in "rename_retry" state; next frame will try again.
end

Net = {}

function Net.custom_instructions_prompt_block_for_request()
  local request_key = S and S.probe_turn or nil
  if request_key and S._custom_instr_prompt_key == request_key then
    return S._custom_instr_prompt_block
  end
  local blob = Store and Store.custom_instructions_prompt_block
    and Store.custom_instructions_prompt_block() or nil
  if request_key then
    S._custom_instr_prompt_key = request_key
    S._custom_instr_prompt_block = blob
  end
  return blob
end

-- =============================================================================
-- Custom-LLM connection test helpers
-- =============================================================================
-- Supports the Test Connection button on the custom_llm page. Fires a single
-- GET /v1/models request against the currently entered endpoint (without
-- requiring Save) and stores pass/fail in api_keys.custom_conn_test.result.
--
-- The test is model-agnostic -- /v1/models is a server directory listing, so
-- it only verifies the server is reachable + auth works. This is the most
-- information we can extract without running inference (which would invoke
-- reasoning on models like deepseek-r1 and block the test).
--
-- Implementation temporarily registers a minimal custom provider, fires
-- Net.fire_key_test (which dispatches custom providers to GET /v1/models),
-- then restores the originally-saved config on finish.
-- Placed after `local Net = {}` so the closures capture Net as an upvalue
-- instead of resolving it as a (nil) global.

-- Synthetic id used exclusively for the in-flight connection-test provider.
-- Double-underscore prefix makes it impossible to collide with any id that
-- Custom.gen_id() produces ("custom_" + 8 hex). Never persisted: the test
-- flow only touches in-memory PROVIDERS + S.api_key_map, never Key.save.
CUSTOM_CONN_TEST_ID = "__cllm_conn_test__"

-- Build a throwaway record from cfg_base, append it to PROVIDERS under the
-- conn-test sentinel id, and select it as the active provider. The model id
-- is a placeholder -- the GET /v1/models test doesn't reference it. Returns
-- the new provider index, or nil on failure. cfg_base carries the advanced
-- fields (connect_timeout, allow_insecure, extra_headers, model_prefix) so
-- the test exercises the same curl options the real request will use.
local function custom_conn_test_register(cfg_base)
  -- Default model id: a placeholder safe for the GET /v1/models path
  -- (which doesn't reference it). When the caller opts into the real-
  -- inference path, swap in the user's first model id from the form so
  -- the chat/completions POST hits the right model -- the placeholder
  -- would just earn an "unknown model" rejection from the server.
  local model_id_for_test = "conn-test"
  if cfg_base.use_inference_test and type(cfg_base.test_model_id) == "string"
     and cfg_base.test_model_id ~= "" then
    model_id_for_test = cfg_base.test_model_id
  end
  -- Provider-wide and per-model extra_body get plumbed through ONLY for
  -- the inference test path (GET /v1/models doesn't send a body, so the
  -- extras are irrelevant there). Net.merge_custom_extra_body reads
  -- p.extra_body and p.models[1].extra_body to assemble the merged
  -- vendor-toggle suffix that real chat would send.
  local record = {
    id                   = CUSTOM_CONN_TEST_ID,
    endpoint             = cfg_base.endpoint,
    timeout_secs         = cfg_base.timeout_secs,
    connect_timeout_secs = cfg_base.connect_timeout_secs,
    allow_insecure       = cfg_base.allow_insecure,
    model_prefix         = cfg_base.model_prefix,
    extra_headers        = cfg_base.extra_headers,
    label                = cfg_base.label,
    extra_body           = (cfg_base.use_inference_test
                              and cfg_base.extra_body) or "",
    models               = { {
      id             = model_id_for_test,
      price_in       = 0,
      price_out      = 0,
      context_window = CUSTOM_DEFAULT_CTX,
      extra_body     = (cfg_base.use_inference_test
                          and cfg_base.test_model_extra_body) or "",
    } },
  }
  -- Defensive: if a prior test left the sentinel registered, drop it first.
  Custom.unregister_id(CUSTOM_CONN_TEST_ID)
  local cust_idx = Custom.register_one(record)
  if cust_idx then
    -- Stamp the runtime-only flag on the registered provider entry so
    -- Net.fire_key_test / Net.handle_key_test can dispatch on it. Lives
    -- on the throwaway PROVIDERS slot only -- gets dropped with the
    -- sentinel in custom_conn_test_finish.
    if cfg_base.use_inference_test then
      PROVIDERS[cust_idx].use_inference_test = true
    end
    prefs.provider_idx = cust_idx
    MODELS.refresh()
  end
  return cust_idx
end

-- Validate current form values on the custom_llm edit screen and fire a
-- single connection test. Called by the "Test Connection" button. Writes
-- per-field errors on failure. Returns true if the test was fired, false
-- otherwise. Reads from api_keys.custom_edit, which is populated when the
-- user navigates into the edit screen (new record or existing record).
function CTX.custom_llm_start_conn_test()
  local edit = api_keys.custom_edit
  if not edit then return false end
  edit.errors = {}
  local has_format_error = false

  local endpoint_t  = (edit.endpoint        or ""):match("^%s*(.-)%s*$") or ""
  endpoint_t = Custom.normalize_chat_endpoint(endpoint_t)
  if edit.endpoint ~= endpoint_t then edit.endpoint = endpoint_t end
  local timeout_t   = (edit.timeout         or ""):match("^%s*(.-)%s*$") or ""
  local ctimeout_t  = (edit.connect_timeout or ""):match("^%s*(.-)%s*$") or ""
  local label_t     = (edit.label           or ""):match("^%s*(.-)%s*$") or ""
  local key_t       = (edit.key             or ""):match("^%s*(.-)%s*$") or ""
  local prefix_t    = (edit.model_prefix    or ""):match("^%s*(.-)%s*$") or ""

  if label_t == "" then
    edit.errors.label = Custom.t("settings.custom.error.name_required", nil,
      "Name is required.")
    has_format_error = true
  end

  if not endpoint_t:match("^https?://") then
    edit.errors.endpoint = Custom.t("settings.custom.error.endpoint_scheme", nil,
      "Endpoint must start with http:// or https://.")
    has_format_error = true
  elseif endpoint_t:find("[\"'`%c]") then
    -- Reject characters that would break (or escape out of) the
    -- powershell + cmd quoting in Net.fire_curl.
    edit.errors.endpoint = Custom.t("settings.custom.error.endpoint_chars", nil,
      "Endpoint may not contain quotes, backticks, or control characters.")
    has_format_error = true
  elseif not Custom.endpoint_is_chat_completions(endpoint_t) then
    edit.errors.endpoint = Custom.t(
      "settings.custom.error.endpoint_chat_completions", nil,
      "Use the full chat-completions URL, for example http://localhost:1234/v1/chat/completions.")
    has_format_error = true
  end

  local timeout_n = tonumber(timeout_t == "" and tostring(CUSTOM_DEFAULT_TIMEOUT) or timeout_t)
  if not timeout_n or timeout_n < CUSTOM_MIN_TIMEOUT then
    edit.errors.timeout = Custom.t("settings.custom.error.timeout_min",
      { min = CUSTOM_MIN_TIMEOUT },
      str_format("Timeout must be a number >= %d seconds.",
        CUSTOM_MIN_TIMEOUT))
    has_format_error = true
  elseif timeout_n > CUSTOM_MAX_TIMEOUT then
    edit.errors.timeout = Custom.t("settings.custom.error.timeout_max",
      { max = CUSTOM_MAX_TIMEOUT },
      str_format("Timeout must be <= %d seconds (1 hour).",
        CUSTOM_MAX_TIMEOUT))
    has_format_error = true
  end

  local ctimeout_n = tonumber(ctimeout_t == "" and tostring(Custom.DEFAULT_CONNECT) or ctimeout_t)
  if not ctimeout_n or ctimeout_n < Custom.MIN_CONNECT or ctimeout_n > Custom.MAX_CONNECT then
    edit.errors.connect_timeout =
      Custom.t("settings.custom.error.connect_timeout_range",
        { min = Custom.MIN_CONNECT, max = Custom.MAX_CONNECT },
        str_format(
          "Connect timeout must be a number between %d and %d seconds.",
          Custom.MIN_CONNECT, Custom.MAX_CONNECT))
    has_format_error = true
  end

  local headers_arr, headers_err = Custom.parse_headers_text(edit.headers_text or "")
  if headers_err then
    edit.errors.headers = headers_err
    has_format_error = true
  end

  if key_t ~= "" then
    local lk_valid, lk_reason = Key.validate_format(key_t,
      { is_custom = true, key_prefix = "", key_min_len = 0 })
    if not lk_valid then
      edit.errors.key = lk_reason
      has_format_error = true
    end
  end

  -- Opt-in real-inference test: only fires if the user ticked the
  -- checkbox AND filled in at least one model id. Without a model id we
  -- have nothing to send in the chat/completions body, so block the
  -- attempt with a clear per-field error rather than firing a malformed
  -- request and getting a confusing server-side error back.
  local use_inference = edit.test_with_inference and true or false
  local first_model_id = ""
  if type(edit.models) == "table" and edit.models[1] then
    first_model_id = (edit.models[1].id or ""):match("^%s*(.-)%s*$") or ""
  end
  if use_inference and first_model_id == "" then
    -- Surface via the test-result panel since edit.errors.models has no
    -- inline renderer. This puts the message right where the user is
    -- looking after they click Test Connection.
    if api_keys.custom_conn_test then
      api_keys.custom_conn_test.result = {
        ok    = false,
        error = Custom.t("settings.custom.error.inference_model_required", nil,
          "Add at least one model id before running an inference test."),
      }
    end
    return false
  end

  if has_format_error then return false end

  local cfg_base = {
    endpoint             = endpoint_t,
    timeout_secs         = timeout_n or CUSTOM_DEFAULT_TIMEOUT,
    connect_timeout_secs = ctimeout_n or Custom.DEFAULT_CONNECT,
    allow_insecure       = edit.allow_insecure and true or false,
    model_prefix         = prefix_t,
    extra_headers        = headers_arr,
    label                = label_t,
    use_inference_test   = use_inference,
    test_model_id        = first_model_id,
    -- Provider-wide and per-model extra_body. Only consumed by the
    -- inference test path; the GET /v1/models path sends no body so it
    -- ignores them. Pass the form values raw -- merge_custom_extra_body
    -- silently discards malformed JSON, so we don't need to re-run the
    -- save-time canonicalizer here.
    extra_body              = edit.extra_body or "",
    test_model_extra_body   = (edit.models and edit.models[1]
                                and edit.models[1].extra_body) or "",
  }
  CTX.custom_conn_test_start(cfg_base, key_t)
  return true
end

-- Start the connection test. cfg_base carries shared config (endpoint,
-- timeout, label); api_key is the auth key (or "" for none). The test
-- registers a throwaway provider under CUSTOM_CONN_TEST_ID and stashes
-- the active provider's index so finish() can restore it.
function CTX.custom_conn_test_start(cfg_base, api_key)
  local state = api_keys.custom_conn_test
  state.active            = true
  state.started           = reaper.time_precise()
  state.timeout           = CUSTOM_DEFAULT_TEST_TIMEOUT
  state.result            = nil   -- cleared; filled by advance()
  state.orig_provider_idx = prefs.provider_idx
  S.api_key_map[CUSTOM_CONN_TEST_ID] = (api_key ~= "" and api_key) or nil

  local cust_idx = custom_conn_test_register(cfg_base)
  local cust_prov = cust_idx and PROVIDERS[cust_idx] or nil
  if not cust_prov then
    CTX.custom_conn_test_advance(false,
      Custom.t("settings.custom.error.register_failed", nil,
        "Could not register custom provider."))
    return
  end
  S.api_key = S.api_key_map[CUSTOM_CONN_TEST_ID]
  api_keys.key_validating     = true
  api_keys.key_validating_idx = cust_idx
  -- Publish the test timeout for Net.fire_curl to pick up.
  S.key_test_custom_timeout = state.timeout
  Net.fire_key_test(cust_prov)
end

-- Record the test's pass/fail result and finish. Called by Net.handle_key_test
-- and by the various error paths in Net.fire_curl / Net.try_finish_curl.
function CTX.custom_conn_test_advance(ok, err_msg)
  local state = api_keys.custom_conn_test
  state.result = { ok = ok, error = err_msg }
  S.key_test_pending  = false
  S.key_test_provider = nil
  S.curl_pid          = nil
  CTX.custom_conn_test_finish()
end

-- Cancel an in-flight connection test. Kills any active curl request, marks
-- the result as cancelled, and restores the original custom config via finish().
function CTX.custom_conn_test_cancel()
  local state = api_keys.custom_conn_test
  if not state or not state.active then return end
  if Net.kill_curl then pcall(Net.kill_curl) end
  state.result        = {
    ok    = false,
    error = Custom.t("settings.custom.status.cancelled", nil,
      "Test cancelled."),
  }
  S.key_test_pending  = false
  S.key_test_provider = nil
  S.curl_pid          = nil
  CTX.custom_conn_test_finish()
end

-- Drop the throwaway conn-test provider, restore the previous active
-- provider, and clear transient state. Leaves state.result in place so
-- the UI can render the pass/fail message until the user clicks Test
-- Connection again or leaves the page. Persisted records are never
-- touched -- register_all was called at startup and stays in effect.
-- Idempotent: if the test was already finished (watchdog + advance racing,
-- or Cancel double-click), the second call is a no-op.
function CTX.custom_conn_test_finish()
  local state = api_keys.custom_conn_test
  if not state or not state.active then return end
  state.active                = false
  state.started               = nil
  -- Remove the throwaway provider and its in-memory key. The sentinel id is
  -- reserved, so wiping the key unconditionally is safe -- nothing else
  -- ever writes to S.api_key_map[CUSTOM_CONN_TEST_ID].
  Custom.unregister_id(CUSTOM_CONN_TEST_ID)
  S.api_key_map[CUSTOM_CONN_TEST_ID] = nil
  -- Restore active provider index (clamp if out of range).
  local orig_idx = state.orig_provider_idx or 1
  if orig_idx < 1 or orig_idx > #PROVIDERS then orig_idx = 1 end
  prefs.provider_idx = orig_idx
  MODELS.refresh()
  S.api_key = S.api_key_map[PROVIDERS.active().id]
  -- Clear transient flags.
  api_keys.key_validating     = false
  api_keys.key_validating_idx = nil
  S.status                    = "idle"
  S.key_test_custom_timeout   = nil
end

-- =============================================================================
-- Net.system_prompt_text
-- =============================================================================
-- General model guidance is separate from typed-action profiles. Typed-action
-- profiles change a structured contract; these notes are small hidden nudges
-- for a specific provider/model's everyday response habits.
Code.MODEL_GUIDANCE_BY_MODEL = Code.MODEL_GUIDANCE_BY_MODEL or {
  openai = {
    ["*"] = {
      key = "openai_explicit_sidechain_route",
      prompt = [[
- For explicit sidechain wording like "create a send from Voiceover to Music Bed", follow those named endpoints exactly: put the compressor on the destination/ducked track and create one direct source-to-destination send feeding sidechain channels. If the prompt also names a Sidechain Comp track, create/name that track only; do not route through it, send the destination into it, disable master send, or invent a separate sidechain/helper bus unless the user explicitly says that track is the bus.
- For named routing lists, create only the requested sends from the named sources to the named destination bus, return, or print track. Do not also route return/parallel/print/bus tracks to each other unless the user explicitly asks for those extra sends.
- If the user gives exact marker, region, item, loop, or time-selection positions in seconds, use those exact seconds. BPM, bar count, or phrase-length wording must not shorten or replace explicit second-based positions.
- If the prompt includes `at N BPM`, `N BPM`, or asks to set tempo, include `reaper.SetCurrentBPM(0, N, true)` near the top before creating MIDI, markers, or regions. Do this even when the session snapshot already shows that BPM or all requested positions are exact seconds; a local `bpm` variable is not enough.
- If the user says to create or append a new track after the existing tracks, insert it after the current last track. Do not insert after a similarly named existing track unless that exact existing-track insertion point is named.
- Do not delete, clear, or replace existing tracks before building a setup unless the user explicitly asks to delete/clear/replace tracks or start from scratch.
- For MIDI items, `reaper.TakeIsMIDI` only accepts a take handle. Never call `reaper.TakeIsMIDI(item)` on a MediaItem variable; first use `local take = reaper.GetActiveTake(item)` and then check `reaper.TakeIsMIDI(take)`.
- For nested folders, an inner folder and an outer folder may need separate negative `I_FOLDERDEPTH` closes on different tracks. Do not remove the outer close when the inner folder is already closed.
- Track names like Pad Synth, Arp Synth, Lead Synth, Piano, Bass, or Keys are names only unless the user explicitly asks to load a virtual instrument, synth plugin, sampler, VSTi, or sound source. Do not add instrument plugins for those names.
- For JSFX memory, use explicit base variables and direct reads/writes such as `bufferL[i]` and `bufferR[i]`. Never use a generic `buf[base + i]` pattern, and never leave the requested words allpass, buffer, grain, freeze, or width only implicit in abbreviated variable names.
]],
      validators = {
        sidechain_ducking_requires_send = true,
      },
    },
    ["gpt-5.6-luna"] = {
      key = "luna_practical_track_routing",
      prompt = [[
- For simple track/routing setup, create only the requested or named tracks. Do not add helper, folder, parent, or container tracks unless the user explicitly asks for them.
- If the user asks to "select only" a track while doing another action, the selection change is required project state. Do not skip it as "touching less"; clear existing track selection and select only the target.
- `TrackFX_AddByName` returns exactly one integer FX index. Use `local fx = reaper.TrackFX_AddByName(...)`, then check `if fx < 0 then ... return end`; never use `local ok, fx = ...`.
- `CreateTrackSend(src, dst)` creates one send from that source to that destination. Do not call it twice for the same source/destination pair unless the user explicitly asks for duplicate sends.
- `GetSetMediaTrackInfo_String(track, "P_NAME", name, true)` always takes 4 arguments. For track names, never omit the final `true`.
- When you create a new track for an instrument, part, or MIDI idea, name that track for the part. For a drum MIDI idea, use a name containing "Drum".
- For ordinary action requests like create, add, make, put, set up, route, or select in REAPER, return a runnable fenced ```lua script. Do not answer with only a prose summary of what the script would do.
- For simple folder/template setup requests, treat plural category words like "guitars", "vocals", "keys", or "drums" as one category track named by that word unless the user gives a count or names separate parts. Do not ask how many tracks to create for those ordinary categories.
- For cue/routing setup requests that name source parts like vocal, guitar, or keys, ensure those named source tracks exist before creating sends. If the current session does not already contain a named source track, create it; do not silently skip a requested source because it is missing.
- For cue/headphones/monitor buses that should stay out of the master, set the bus track's `B_MAINSEND` to `0` with `SetMediaTrackInfo_Value`. Do not leave that bus feeding the master.
- Avoid plugin helper functions unless helper definitions are pinned and truly needed for a requested display-unit value. For simple/basic EQ/compressor/limiter tasks, add the resolved preferred plugin and use direct verified normalized values only when configuring is clearly requested; never invent or rewrite bundled helper bodies.
- For JSFX delay, reverb, and grain/freezer effects, keep memory base names literal and stable across sections. If `@init` assigns `bufferL = 0`, `@sample` must read/write `bufferL[i]` exactly; do not rename it to `bufferL_base`, `bufL`, or pass it through `buf[base + i]`. If the user says allpass, name buffers or comments with the full word `allpass`, not only `ap`.
- For JSFX with several delay/comb/allpass buffers, allocate fixed unique base regions in `@init`. Do not initialize every buffer to `0` as placeholders, and do not compute buffer base offsets in `@slider`; slider changes can adjust tap lengths, not memory layout.
- For JSFX reverb code, do not abbreviate allpass as `ap`, `ap1`, `ap2`, or `ap_fb`; use identifiers such as `allpass1L`, `allpass2R`, and `allpass_fb`.
]],
      validators = {
        exclusive_track_selection = true,
        created_track_inferred_name = true,
        action_requires_lua = true,
      },
    },
    ["gpt-5.4-mini"] = {
      key = "mini_practical_action_defaults",
      prompt = [[
- Prefer a runnable script for ordinary safe ReaScript action requests. Do not ask for setup details when the request has a practical default.
- For "select only X" track requests, clear existing track selection first, then select only the target track.
- For "ready to record" track creation, create the track, arm it, enable monitoring if appropriate, leave it selected, and use the current/default input unless the user asks for a specific hardware input.
- For short MIDI idea or pattern requests, create a new appropriately named MIDI track and item by default. Do not ask which track to use unless the user explicitly says to use an existing or selected track.
- `reaper.MIDI_InsertNote` start/end arguments are PPQ positions, not seconds or beats. For musical/project-time note placement, convert each absolute project time with `reaper.MIDI_GetPPQPosFromProjTime(take, seconds)` before inserting notes.
- For any prompt that says `at N BPM` or names a BPM for MIDI, marker, region, or arrangement setup, call `reaper.SetCurrentBPM(0, N, true)` before creating content. Do not satisfy this with only `local bpm = N`.
- When the user names exact stock Cockos plugins such as ReaEQ, ReaComp, ReaDelay, ReaVerbate, ReaGate, or ReaLimit, add those exact plugins. Do not substitute preferred/FabFilter plugins or try those alternatives first.
- Avoid plugin helper functions unless helper definitions are pinned and truly needed for a requested display-unit value. For simple/basic EQ/compressor/limiter tasks, add the resolved preferred plugin and use direct verified normalized values only when configuring is clearly requested; never invent or rewrite bundled helper bodies.
]],
      validators = {
        action_requires_lua = true,
      },
    },
  },
  anthropic = {
    ["*"] = {
      key = "anthropic_practical_reascript_defaults",
      prompt = [[
- For ordinary safe ReaScript action/setup requests, return a runnable fenced ```lua script using practical defaults. Do not answer with only a prose setup question when the user names the tracks, sources, bus, return, MIDI idea, tempo, or setup goal.
- In an empty project, when the user names instrument/source parts for a setup, create those named tracks instead of asking whether they already exist.
- When the user asks for tracks going into a bus or return, create explicit sends with `reaper.CreateTrackSend(source_track, bus_or_return_track)` from every named non-destination source to the bus/return unless the user explicitly excludes a source. Folder depth alone is not bus routing.
- For cue/headphone/monitor buses that should be separate from or away from the main mix, set the cue bus track's own `B_MAINSEND` to `0` with `reaper.SetMediaTrackInfo_Value(cue_bus_track, "B_MAINSEND", 0)`.
- For named effect returns such as plate/reverb/delay returns, name the destination track with the requested effect word, for example "Plate Verb" for a plate reverb return, add the requested/resolved effect there, and route each named source to that return.
- For setup wording like "host, guest, music, and a bus", create the bus and route every named non-bus source track to it unless the user explicitly says a source should remain direct. Do not reinterpret that as a dialogue-only bus when Music is named; Music is a named source.
- For short MIDI ideas, beats, patterns, chords, or pads, create one appropriately named MIDI track and one MIDI item unless the user asks for separate tracks or separate items. Put multiple drums or chords into that one item; for a drum idea, name the track with "Drum" and include common GM kick/snare notes.
- For explicit sidechain wording like "create a send from Voiceover to Music Bed", follow those named endpoints exactly: put the compressor on the destination/ducked track and create one direct source-to-destination send feeding sidechain channels. If the prompt also names a Sidechain Comp track, create/name that track only; do not route through it, send the destination into it, disable master send, or invent a separate sidechain/helper bus unless the user explicitly says that track is the bus. For generic kick/bass ducking with no endpoints named, use Kick as source and Bass as destination.
- Keep plugin scripts direct and small. For simple/basic/add-only plugin chains, add the requested/resolved plugins and avoid display-unit helper functions unless helper definitions are pinned and must be copied exactly.
- Plain requests such as "add EQ and compression" are add-only when the user gives no settings, tonal goal, recipe, or starter/generic-treatment request. Insert the resolved plugins in the requested order at their defaults, check every AddByName result, and stop; do not invent settings, request fx_inspect, or use plugin helpers.
- Track/item custom colors written through I_CUSTOMCOLOR and ColorToNative are object colors, not application-theme edits. Do not request theme or prompt_bundle:theme unless actually calling SetThemeColor.
- For JSFX requests, return the requested ```jsfx block, not Lua/ReaScript. Preserve user-named DSP terms like allpass, buffer, grain, freeze, and width as readable identifiers or comments.
]],
      validators = {
        action_requires_lua = true,
        bus_routing_requires_sends = true,
        podcast_bus_routes_all_sources = true,
        sidechain_ducking_requires_send = true,
      },
    },
    ["claude-haiku-4-5"] = {
      key = "haiku_practical_track_templates",
      prompt = [[
- Prefer a runnable script for ordinary safe ReaScript action requests like create, add, make, set up, route, select, or organize. Do not answer with only a prose question or summary when a practical default exists.
- For simple folder/template setup requests, treat plural category words like "guitars", "vocals", "keys", or "drums" as one category track named by that word unless the user gives a count or names separate parts. Do not ask how many tracks to create for those ordinary categories.
- For folder setup, create only the requested folder/category tracks. Do not add extra lead/rhythm/helper tracks unless the user explicitly asks for them.
- Treat aliases like "comp" or "compression" as compressor requests. If `pref:` or `plugin_ref:` context is already pinned for the needed plugin type, use it and write the script; do not emit another `resolve:` request for that same type.
- For simple vocal chain requests, add the EQ and compressor in order and stop there unless the user asks for exact settings. Do not define `set_param_display`, use parameter helper functions, or defer parameter-setting code for a simple chain.
- For kick/bass ducking, the Kick-to-Bass send is mandatory. Create the send before any deferred compressor parameter setup, even if you also add/configure Pro-C or ReaComp.
- Keep plugin code direct and small. Avoid helper functions unless helper definitions are pinned and the user requested a display-unit value that cannot be set from verified normalized reference values.
]],
      validators = {
        action_requires_lua = true,
      },
    },
    ["claude-sonnet-5"] = {
      key = "sonnet5_explicit_bus_sends",
      prompt = [[
- When the user asks for tracks going into a bus or return, create explicit sends with `reaper.CreateTrackSend(source_track, bus_or_return_track)`. Folder depth alone is not bus routing and should not be used as a substitute unless the user explicitly asks for folders.
- Treat "basic EQ" by itself as add-only. Add the resolved EQ plugin to the requested/selected track(s), check each AddByName result, and stop there unless the user gives a tonal goal, explicit settings, or asks for starter/generic EQ settings. Do not use track-type starter EQ recipes, call `TrackFX_SetParam*`, or call/rewrite plugin helper functions for add-only/basic EQ tasks.
- For podcast setup wording like "host, guest, music, and a bus", Music is also a source. Route Host, Guest, and Music to the bus unless the user explicitly says Music should stay direct.
]],
      validators = {
        bus_routing_requires_sends = true,
      },
    },
    ["claude-opus-4-8"] = {
      key = "opus_practical_setup_defaults",
      prompt = [[
- For folder setup such as "put drums, bass, and guitar inside a band folder", create the folder/category track plus the named child tracks. Close the folder on the last child track, not on the following outside track.
]],
      validators = {
        action_requires_lua = true,
        bus_routing_requires_sends = true,
      },
    },
  },
  google = {
    ["*"] = {
      key = "google_explicit_sidechain_route",
      prompt = [[
- For explicit sidechain wording like "create a send from Voiceover to Music Bed", follow those named endpoints exactly: put the compressor on the destination/ducked track and create one direct source-to-destination send feeding sidechain channels. If the prompt also names a Sidechain Comp track, create/name that track only; do not route through it, send the destination into it, disable master send, or invent a separate sidechain/helper bus unless the user explicitly says that track is the bus.
- For cue/headphone/monitor setups that name tracks in a simple list, create those tracks in the user's order unless the user explicitly asks for a different order. Route named source tracks to the named cue bus and set the cue bus track's own `B_MAINSEND` to `0` when it should stay out of the master/main mix.
- When the user asks for tracks going into a bus or return, create explicit sends with `reaper.CreateTrackSend(source_track, bus_or_return_track)`. Folder depth alone is not bus routing.
- For podcast layouts with Dialog Bus, Music Bus, FX Bus, and Print Mix, create explicit sends from Host/Guest to Dialog Bus, Music Bed/Music to Music Bus, SFX to FX Bus, and then each bus to Print Mix.
- For JSFX requests, return the requested ```jsfx block, not Lua/ReaScript. Preserve user-named DSP terms like allpass, buffer, grain, freeze, and width as readable identifiers or comments.
]],
      validators = {
        bus_routing_requires_sends = true,
        sidechain_ducking_requires_send = true,
      },
    },
    ["gemini-3.1-flash-lite"] = {
      key = "flash_lite_practical_free_tier_actions",
      prompt = [[
- For ordinary action requests like create, add, make, put, set up, route, or select in REAPER, return a runnable fenced ```lua script. Do not answer with only a prose question, summary, or `<context_needed>` when a practical default exists.
- For short MIDI idea, beat, pattern, chord, or pad requests, create a new appropriately named MIDI track and item by default. Do not ask which track, instrument, or sample library to use unless the user explicitly says to use existing media or selected items.
- When the user asks for a drum beat or drum MIDI idea, create a track with a name containing "Drum" and add a small MIDI item using common GM pitches such as kick 36 and snare 38.
- When the user asks for intro, verse, chorus, bridge, or other song sections in time chunks, create timeline regions or markers. Do not create empty tracks or media items for sections unless the user explicitly asks for section tracks or items.
- For cue/routing setup requests that name source parts like vocal, guitar, or keys, ensure those named source tracks exist before creating sends. If the current session does not already contain a named source track, create it; do not silently skip a requested source because it is missing.
- For cue/headphone/monitor buses that should be separate from the main mix, set the cue bus track's own `B_MAINSEND` to `0` with `reaper.SetMediaTrackInfo_Value(cue_bus_track, "B_MAINSEND", 0)`. Disabling master send only on the source tracks is incomplete; the cue bus itself must not feed the master.
- When the user asks for tracks going into a bus or return, create explicit sends with `reaper.CreateTrackSend(source_track, bus_or_return_track)`. Folder depth alone is not bus routing.
- Avoid plugin helper functions unless helper definitions are pinned and truly needed for a requested display-unit value. For simple/basic EQ/compressor/limiter tasks, add the resolved preferred plugin and use direct verified normalized values only when configuring is clearly requested; never invent or rewrite bundled helper bodies.
]],
      validators = {
        action_requires_lua = true,
        bus_routing_requires_sends = true,
      },
    },
  },
  deepseek = {
    ["deepseek-v4-flash"] = {
      key = "deepseek_exact_reaper_global",
      prompt = [[
- When writing REAPER Lua, every REAPER API call must use the exact global `reaper`. Never write `rearga`, `repaer`, `reaperl`, or any other variant.
- If you need context, output the literal `<context_needed>...</context_needed>` tag as the entire reply. Do not wrap it in backticks, code fences, quotes, or prose.
- Always include the closing `</context_needed>` tag. If PINNED REFERENCES already lists the bucket you need, especially `midi`, do not request it again; use the pinned data and write the Lua script.
- For runnable Lua, use one fenced ```lua code block. The opening fence must be exactly three backticks immediately followed by lua on the same line: ```lua. Never write ``` on one line and lua on the next line.
- For JSFX, use one fenced ```jsfx code block. The opening fence must be exactly three backticks immediately followed by jsfx on the same line, and the closing fence must be on its own line after the final JSFX statement.
- For pure track, folder, marker, region, MIDI, and routing setup requests with docs/session already pinned, write the runnable Lua immediately. Do not request `prompt_bundle:plugin` unless your script will actually call TrackFX_* or plugin parameter APIs.
- When a request says to make, create, add, or set up a track, insert the new track first. Do not replace requested track creation with `reaper.GetTrack(0, 0)` unless the user explicitly asked to modify an existing or selected track.
- For ordered track layouts, especially folder outlines, append tracks in forward user order: get `idx = reaper.CountTracks(0)`, insert at `idx`, fetch `reaper.GetTrack(0, idx)`, then name/store that handle. Do not repeatedly insert at index 0 or reverse the name list.
- If the user says to create or append a new track after the existing tracks, insert it after the current last track. Do not insert after a similarly named existing track unless that exact existing-track insertion point is named.
- Do not delete, clear, or replace existing tracks before building a setup unless the user explicitly asks to delete/clear/replace tracks or start from scratch.
- For folder setup such as "Band folder with Drums, Bass, Guitars, and Keys inside, then Mix Print outside", create Band, Drums, Bass, Guitars, Keys, and Mix Print only. Set Band `I_FOLDERDEPTH = 1`, set the last child Keys `I_FOLDERDEPTH = -1`, and leave Mix Print at `0`. Never create a separate "(folder end)" track.
- When the user asks for tracks going into a bus or return, create explicit sends with `reaper.CreateTrackSend(source_track, bus_or_return_track)`. Folder depth alone is not bus routing.
- For named routing lists, create only the requested sends from the named sources to the named destination bus, return, or print track. Do not also route return/parallel/print/bus tracks to each other unless the user explicitly asks for those extra sends.
- For explicit sidechain wording like "create a send from Voiceover to Music Bed", follow those named endpoints exactly: put the compressor on the destination/ducked track and create one direct source-to-destination send feeding sidechain channels. If the prompt also names a Sidechain Comp track, create/name that track only; do not route through it, send the destination into it, disable master send, or invent a separate sidechain/helper bus unless the user explicitly says that track is the bus.
- When the user asks for a region, create a region, not a marker: use `reaper.AddProjectMarker(0, true, start_time, end_time, name, -1)` or the equivalent region API with the region boolean set to `true`.
- If the user gives exact marker, region, item, loop, or time-selection positions in seconds, use those exact seconds. BPM, bar count, or phrase-length wording must not shorten or replace explicit second-based positions.
- For short MIDI idea or pattern requests, create a new appropriately named MIDI track and pass that track handle to `reaper.CreateNewMIDIItemInProj(track, start_seconds, end_seconds, false)`. Never pass `0`, `nil`, or a project id as the first argument.
- For chord/arpeggio MIDI scripts, keep pitch tables scalar: `local chords = { {48, 51, 55}, {53, 56, 60} }`. Do not wrap all chord rows in one extra table, because `chord[i]` must be a numeric MIDI pitch before `MIDI_InsertNote`.
]],
      validators = {
        action_requires_lua = true,
        bus_routing_requires_sends = true,
        region_requires_region_flag = true,
        sidechain_ducking_requires_send = true,
      },
    },
  },
}

function Code.model_guidance_profile(provider_id, model_id)
  local by_provider = Code.MODEL_GUIDANCE_BY_MODEL
    and Code.MODEL_GUIDANCE_BY_MODEL[tostring(provider_id or "")]
  if type(by_provider) ~= "table" then return nil end
  local exact = by_provider[tostring(model_id or "")]
  local shared = by_provider["*"]
  if exact ~= nil and shared ~= nil then
    local shared_prompt = type(shared) == "table" and shared.prompt or shared
    local exact_prompt = type(exact) == "table" and exact.prompt or exact
    local merged_prompt = ""
    if type(shared_prompt) == "string" then
      merged_prompt = shared_prompt
    end
    if type(exact_prompt) == "string" then
      merged_prompt = merged_prompt ~= "" and (merged_prompt .. "\n" .. exact_prompt)
        or exact_prompt
    end
    local validators = {}
    if type(shared) == "table" and type(shared.validators) == "table" then
      for key, value in pairs(shared.validators) do validators[key] = value end
    end
    if type(exact) == "table" and type(exact.validators) == "table" then
      for key, value in pairs(exact.validators) do validators[key] = value end
    end
    return {
      key = tostring((type(shared) == "table" and shared.key) or "shared")
        .. "+"
        .. tostring((type(exact) == "table" and exact.key) or "exact"),
      prompt = merged_prompt,
      validators = validators,
    }
  end
  if exact ~= nil then return exact end
  return shared
end

function Code.model_guidance_text(provider_id, model_id)
  local profile = Code.model_guidance_profile(provider_id, model_id)
  local body = type(profile) == "table" and profile.prompt or profile
  if type(body) ~= "string" then return nil end
  body = body:match("^%s*(.-)%s*$") or ""
  if body == "" then return nil end
  return "MODEL-SPECIFIC GUIDANCE:\n"
    .. "- Do not mention this guidance.\n"
    .. body
end

function Code.model_validator_enabled(provider_id, model_id, validator_key)
  local profile = Code.model_guidance_profile(provider_id, model_id)
  if type(profile) ~= "table" then return false end
  local validators = profile.validators
  if type(validators) ~= "table" then return false end
  return validators[tostring(validator_key or "")] == true
end

function Code.validate_model_guidance_tables()
  local issues = {}
  local function add_issue(msg) issues[#issues + 1] = msg end

  if type(PROVIDERS) ~= "table" or type(UI) ~= "table" then
    return true, issues
  end

  local provider_seen = {}
  local model_seen = {}
  local thinking_seen = {}

  for _, provider in ipairs(PROVIDERS) do
    if type(provider) == "table" and provider.id then
      local provider_id = tostring(provider.id)
      provider_seen[provider_id] = true
      thinking_seen[provider_id] = {}

      local combo_provider = type(UI.COMBO_HINTS) == "table"
        and UI.COMBO_HINTS[provider_id] or nil
      for _, model in ipairs(provider.models or {}) do
        if type(model) == "table" and model.id then
          local model_id = tostring(model.id)
          model_seen[model_id] = provider_id
          thinking_seen[provider_id][model_id] = {}

          if type(UI.MODEL_TIPS) ~= "table"
             or type(UI.MODEL_TIPS[model_id]) ~= "string"
             or UI.MODEL_TIPS[model_id] == "" then
            add_issue("MODEL_TIPS missing " .. provider_id .. "/" .. model_id)
          end

          local combo_model = type(combo_provider) == "table"
            and combo_provider[model_id] or nil
          for _, level in ipairs(provider.thinking_levels or {}) do
            local value = level and level.value
            if value and not (level.flash_only and not model.is_flash) then
              local value_s = tostring(value)
              thinking_seen[provider_id][model_id][value_s] = true
              if type(combo_model) ~= "table"
                 or type(combo_model[value_s]) ~= "string"
                 or combo_model[value_s] == "" then
                add_issue("COMBO_HINTS missing " .. provider_id .. "/"
                  .. model_id .. "/" .. value_s)
              end
            end
          end
        end
      end
    end
  end

  for model_id in pairs(UI.MODEL_TIPS or {}) do
    if not model_seen[tostring(model_id)] then
      add_issue("MODEL_TIPS stale " .. tostring(model_id))
    end
  end

  for provider_id, provider_tbl in pairs(UI.COMBO_HINTS or {}) do
    provider_id = tostring(provider_id)
    if not provider_seen[provider_id] then
      add_issue("COMBO_HINTS stale provider " .. provider_id)
    elseif type(provider_tbl) == "table" then
      for model_id, model_tbl in pairs(provider_tbl) do
        model_id = tostring(model_id)
        if model_seen[model_id] ~= provider_id then
          add_issue("COMBO_HINTS stale model " .. provider_id .. "/"
            .. model_id)
        elseif type(model_tbl) == "table" then
          for value in pairs(model_tbl) do
            value = tostring(value)
            if not (thinking_seen[provider_id]
                    and thinking_seen[provider_id][model_id]
                    and thinking_seen[provider_id][model_id][value]) then
              add_issue("COMBO_HINTS stale thinking " .. provider_id .. "/"
                .. model_id .. "/" .. value)
            end
          end
        end
      end
    end
  end

  for provider_id, provider_tbl in pairs(UI.COMBO_TONES or {}) do
    provider_id = tostring(provider_id)
    if not provider_seen[provider_id] then
      add_issue("COMBO_TONES stale provider " .. provider_id)
    elseif type(provider_tbl) == "table" then
      for model_id, tone_tbl in pairs(provider_tbl) do
        model_id = tostring(model_id)
        if model_seen[model_id] ~= provider_id then
          add_issue("COMBO_TONES stale model " .. provider_id .. "/"
            .. model_id)
        elseif type(tone_tbl) == "table" then
          for value in pairs(tone_tbl) do
            value = tostring(value)
            if not (UI.COMBO_HINTS
                    and UI.COMBO_HINTS[provider_id]
                    and UI.COMBO_HINTS[provider_id][model_id]
                    and UI.COMBO_HINTS[provider_id][model_id][value]) then
              add_issue("COMBO_TONES without COMBO_HINTS " .. provider_id
                .. "/" .. model_id .. "/" .. value)
            end
          end
        end
      end
    end
  end

  for provider_id, provider_tbl in pairs(Code.MODEL_GUIDANCE_BY_MODEL or {}) do
    provider_id = tostring(provider_id)
    if not provider_seen[provider_id] then
      add_issue("MODEL_GUIDANCE stale provider " .. provider_id)
    elseif type(provider_tbl) == "table" then
      for model_id in pairs(provider_tbl) do
        model_id = tostring(model_id)
        if model_id ~= "*" and model_seen[model_id] ~= provider_id then
          add_issue("MODEL_GUIDANCE stale model " .. provider_id .. "/"
            .. model_id)
        end
      end
    end
  end

  return #issues == 0, issues
end

function Code.compact_system_prompt_text()
  local version = (type(CFG) == "table" and CFG.VERSION) or ""
  local text = [[-- ReaAssist v]] .. version .. "\n" .. [[
You are a REAPER DAW assistant. This is the compact prompt for local/custom models: be practical, obey the context protocol exactly, and generate safe standalone REAPER Lua/JSFX.

CONTEXT PROTOCOL:
- Check the PINNED REFERENCES manifest before asking for context. If a key is listed, use the already-pinned data and do not request it again.
- When context is needed, the whole reply must be one tag only: <context_needed>bucket, bucket</context_needed>. No prose, no fence, no explanation.
- Required buckets: `docs` before any reaper.* code unless docs is pinned or the request is covered only by pinned `midi`; `session` for project state/track selection; `tracks` only when capped session rows omit needed tracks; `recent_reaper_changes` for current/latest REAPER behavior.
- Plugin buckets: `resolve:Type` for generic FX types; `plugin_ref:Name` for curated plugins; `fx_list:Name` for add-only unknown plugins; `fx_inspect:Name` for add+configure unknown plugins; `fx_params:Name@TrackIndex` for current values on loaded plugins. Use full prefixes for multiple tokens.
- Prompt bundles are mandatory before their domains: `prompt_bundle:plugin` before TrackFX_*/param code, `prompt_bundle:plugin_helpers` before using helper functions, `prompt_bundle:drums` for drum edit/quantize code, `prompt_bundle:jsfx` before JSFX, and `prompt_bundle:theme` before SetThemeColor.

OUTPUT CONTRACT:
- For action requests, prefer one complete runnable ```lua block after required context is pinned. For JSFX requests, output one ```jsfx block with `desc:` first.
- Do not claim code ran unless runtime output says so. Keep visible prose short and user-facing; never expose param indices, normalized values, helper internals, or cache annotations.
- Ask one concise question only for genuine ambiguity that context cannot resolve. Negative constraints such as no FX, no sends, no new tracks, or no delete are hard requirements.

SANDBOX / SAFETY:
- FORBIDDEN in code: os, io, ffi, debug, coroutine, package, require, dofile, loadfile, loadstring, load, _G, getfenv, setfenv, rawget, rawset.
- Use only reaper.*, gfx.* when a persistent UI is explicitly requested, and safe Lua builtins (math, string, table, pairs, ipairs, tonumber, tostring, type, pcall, xpcall, select, error, assert, next, unpack).
- Do not use SWS/js_ReaScriptAPI/extension APIs unless requested or docs says they exist and the script checks availability with a clear user error.

REAPER LUA PITFALLS:
- Void APIs return nil: InsertTrackAtIndex, SetEditCurPos, Main_OnCommand, Undo_BeginBlock, Undo_EndBlock, PreventUIRefresh, UpdateArrange, ThemeLayout_RefreshAll. Call them separately, then fetch handles.
- Track indices shown to users are 1-based; API indices are 0-based. Never invent track indices. Nil-check tracks/items/takes before use.
- Create tracks with InsertTrackAtIndex(index, true), then GetTrack(0, index), then name with GetSetMediaTrackInfo_String(track, "P_NAME", name, true).
- Wrap project changes in one Undo_BeginBlock/Undo_EndBlock. Balance PreventUIRefresh with pcall and always call UpdateArrange after changes.
- D_VOL is linear amplitude. Do not use DB2SLIDER/SLIDER2DB for track/item/take/send volume.
- CreateTrackSend returns one integer send index; 0 is valid and -1 is failure. Master send is B_MAINSEND, not RemoveTrackSend category 1.
- For folders, parent track gets I_FOLDERDEPTH=1 and the final child closes with a negative depth. Do not create a fake "(folder end)" track.
- For MIDI notes, use MIDI PPQ positions, CreateNewMIDIItemInProj(track,...), GM drums kick 36/snare 38/closed hat 42, and REAPER note numbering C4=60.
- For exact seconds, use exact seconds. For bars/beats/tempo math, request docs:tempo; for MIDI note work, request midi.
- Use Main_OnCommand only for verified action IDs from provided docs/context or when the user explicitly names a known action.
- Never Save the project, start Record, Undo, or Redo unless the current user request explicitly asks for that exact action. Creating or arming a record-ready track is not permission to start recording.

PLUGIN RULES:
- Every TrackFX_AddByName result must be checked immediately: if fx < 0 then ShowMessageBox and return.
- Add-only FX means leave defaults; no param writes unless the user requests settings, a preset/recipe, or a tonal setup.
- For generic FX type requests, request resolve:Type so user preferences can win. For exact stock names like ReaEQ/ReaComp, use that exact plugin.
- For existing loaded plugin edits, request fx_params scoped to the target track when possible. For adding/configuring unknown third-party plugins, request fx_inspect.
- Helper functions such as find_param/set_param_display are not built-ins. If used, paste their definitions from prompt_bundle:plugin_helpers into the script.
- Plugin param writes that need defer must keep shared state in an outer local visible to the deferred function.

JSFX RULES:
- JSFX is opt-in only. EEL2 has no `reaper`, no Lua syntax, no `if/end`, and no `math.` prefix. Use sections such as @init, @slider, @sample.
- Do not declare or touch gmem; ReaAssist injects its own safety layer. Initialize every memory base before using `name[index]`, and keep feedback clamped/DC-blocked.

STYLE:
- One logical user action per answer, concise summary, then code. No repeated caveats. If a TrackFX_SetParam* write is used, include only the standard UI-verification tip after the code.
]]
  if REQUIRE_SWS_EXTENSION
     and (not SupportExtFlag or not SupportExtFlag("optoutsws")) then
    text = text .. [[

SWS DOCS ROUTING:
- SWS is available in this build. Before SWS-only calls or SWS actions, request <context_needed>docs:sws</context_needed> unless already pinned.
]]
  end
  return text
end

function Code.model_id_looks_local(model_id)
  local mid = tostring(model_id or ""):lower()
  return mid:find("local", 1, true) ~= nil
    or mid:find("ollama", 1, true) ~= nil
    or mid:find("llama", 1, true) ~= nil
    or mid:find("qwen", 1, true) ~= nil
    or mid:find("mistral", 1, true) ~= nil
    or mid:find("mixtral", 1, true) ~= nil
    or mid:find("codestral", 1, true) ~= nil
    or mid:find("gemma", 1, true) ~= nil
    or mid:find("phi", 1, true) ~= nil
    or mid:find("gguf", 1, true) ~= nil
end

function Code.custom_endpoint_looks_hosted(endpoint)
  local ep = tostring(endpoint or ""):lower()
  return ep:find("openrouter%.ai") ~= nil
    or ep:find("api%.openai%.com") ~= nil
    or ep:find("anthropic%.com") ~= nil
    or ep:find("generativelanguage%.googleapis%.com") ~= nil
    or ep:find("api%.together%.xyz") ~= nil
    or ep:find("api%.fireworks%.ai") ~= nil
    or ep:find("api%.groq%.com") ~= nil
    or ep:find("api%.deepseek%.com") ~= nil
    or ep:find("openai%.azure%.com") ~= nil
end

function Code.custom_endpoint_looks_local(endpoint)
  local ep = tostring(endpoint or ""):lower()
  if ep:find("localhost", 1, true)
     or ep:find("127.", 1, true)
     or ep:find("0.0.0.0", 1, true)
     or ep:find("[::1]", 1, true) then
    return true
  end
  if ep:find("://10%.") then return true end
  if ep:find("://192%.168%.") then return true end
  if ep:find("://172%.1[6-9]%.")
     or ep:find("://172%.2%d%.")
     or ep:find("://172%.3[01]%.") then
    return true
  end
  return false
end

function Code.use_compact_system_prompt(provider, model_id)
  if SYSTEM_PROMPT_IS_CUSTOM then return false end
  if type(provider) == "table" and provider.is_custom then
    if Code.custom_endpoint_looks_hosted(provider.endpoint) then
      return false
    end
    return Code.custom_endpoint_looks_local(provider.endpoint)
      or Code.model_id_looks_local(model_id)
  end
  return Code.model_id_looks_local(model_id)
end

-- Return the SYSTEM_PROMPT string plus request-stable system-level additions,
-- optionally with a per-TEST-SESSION stamp appended as a hidden comment when
-- prefs.test_force_cold_cache is on.
--
-- The stamp is minted ONCE when the toggle transitions off -> on (held in
-- S.cold_cache_stamp) and reused on every subsequent send until the toggle
-- flips off or is re-minted. That way the FIRST send after toggling on
-- misses cache across all three providers (fresh prefix the server has
-- never seen), but subsequent sends within the same test run hit cache
-- normally -- so you can still observe caching behavior turn-over-turn
-- while starting from a guaranteed cold state.
--
-- Starting a fresh cold test: toggle off, then toggle on again -- that
-- mints a new stamp.
do
  local ok, issues = Code.validate_model_guidance_tables()
  if not ok and Log and Log.line then
    Log.line("MODEL-GUIDANCE", table.concat(issues, "; "))
  end
end

function Net.system_prompt_text()
  local active_provider = PROVIDERS and PROVIDERS.active and PROVIDERS.active()
    or nil
  local active_model_id = MODELS and MODELS.active_id
    and MODELS.active_id() or nil
  local text = Code.use_compact_system_prompt(active_provider, active_model_id)
    and Code.compact_system_prompt_text()
    or SYSTEM_PROMPT
  local custom_blob = Net.custom_instructions_prompt_block_for_request()
  if custom_blob then
    text = text .. "\n\n" .. custom_blob
  end
  local lang = (I18N and I18N.prompt_language_name and I18N.prompt_language_name())
    or (CFG.prompt_language_name_for_idx
      and CFG.prompt_language_name_for_idx(prefs.reply_language_idx or 1))
    or (CFG.REPLY_LANGUAGE_CODES and CFG.REPLY_LANGUAGE_CODES[prefs.reply_language_idx or 1])
  if lang and lang ~= "English" then
    text = text .. "\n\nVISIBLE REPLY LANGUAGE:\n"
      .. "- When visible natural-language prose is allowed, write it in "
      .. lang .. ".\n"
      .. "- Generated script comments, script title comments, "
      .. "Undo_EndBlock labels, ShowMessageBox text, console/debug text, "
      .. "and other user-visible string literals are visible prose: write "
      .. "those in " .. lang .. " too. Keep the `ReaAssist:` prefix in "
      .. "undo labels unchanged, but localize the action description after "
      .. "the prefix.\n"
      .. "- Structured-edit JSON is not Lua code. Keep JSON syntax, schema "
      .. "keys, op names, REAPER API identifiers, FX/plugin names, and "
      .. "existing user/project names unchanged, but write generated "
      .. "user-visible string values such as track.create.name, "
      .. "track.ensure.name, track.set.name, and generic object labels in "
      .. lang .. ".\n"
      .. "- Do not translate code syntax, code fence labels, REAPER API "
      .. "names, variable/function identifiers, plugin names/identifiers, "
      .. "JSON schema/syntax, XML-like tags such as <context_needed>, paths, filenames "
      .. "supplied by the user, model/provider names, "
      .. "diagnostic labels, or quoted project/user text. For generated "
      .. "script title comments and generated undo descriptions, use "
      .. lang .. " so ReaAssist can derive a localized suggested filename.\n"
      .. "- If a contract requires raw code, JSON, or a bare "
      .. "<context_needed> tag only, obey that contract exactly."
  end
  local model_guidance = Code.model_guidance_text(
    active_provider and active_provider.id or nil,
    active_model_id)
  if model_guidance then
    text = text .. "\n\n" .. model_guidance
  end
  if prefs.test_force_cold_cache and S.cold_cache_stamp then
    return text
      .. "\n\n<!-- test_force_cold_cache: "
      .. S.cold_cache_stamp
      .. " -->"
  end
  return text
end

-- =============================================================================
-- Net.bundled_static_refs
-- =============================================================================
-- Concatenates the long-lived static references (api_ref, midi_ref, theme_ref)
-- into one blob so each provider can emit them as ONE pinned exchange instead
-- of three. Saves the per-ref "Understood." ack overhead and reduces the
-- number of message turns the providers' caches have to align on (matters
-- most for Gemini's cachedContents structure). Returns nil when no refs
-- are present. Order is stable: api_ref first (largest, most stable), then
-- midi_ref, then theme_ref, then a small manifest line so static-only turns
-- do not need a separate manifest-only sticky message.
function Net.bundled_static_refs()
  local parts = {}
  local keys = {}
  if S.api_ref_message   then parts[#parts+1] = S.api_ref_message;   keys[#keys+1] = "docs"  end
  if S.midi_ref_message  then parts[#parts+1] = S.midi_ref_message;  keys[#keys+1] = "midi"  end
  if S.theme_ref_message then parts[#parts+1] = S.theme_ref_message; keys[#keys+1] = "theme" end
  if #parts == 0 then return nil end
  parts[#parts+1] =
    "PINNED REFERENCES (already provided above; do NOT re-request via "
    .. "<context_needed>): " .. tbl_concat(keys, ", ")
  return tbl_concat(parts, "\n\n")
end

function Net.answer_only_context_enabled()
  -- Intentional cache trade-off: answer-only follow-ups drop static refs,
  -- sticky context, and snapshot for one turn. Alternating answer-only and
  -- code-generation phrasing can rebuild a cache rung, but the answer-only
  -- request becomes much smaller and avoids carrying code/plugin context into
  -- pure "why did you choose that?" follow-ups.
  return S.pending_answer_only_followup == true
end

function Net.bundled_static_refs_for_request()
  if Net.answer_only_context_enabled() then return nil end
  return Net.bundled_static_refs()
end

-- =============================================================================
-- Net.sticky_text
-- =============================================================================
-- Net.sticky_set / Net.sticky_unset: wrappers that maintain both
-- S.sticky_context (the key -> content map) AND S.sticky_context_order (the
-- insertion-order key list). Use these instead of assigning to
-- S.sticky_context[k] directly -- the order list drives sticky_parts() emit
-- order, which is critical for prefix-cache stability.
--
-- Why insertion order matters: providers (Anthropic, OpenAI, Gemini) cache on
-- exact byte-prefix match. The earlier alphabetical sort shuffled new refs
-- into the middle of the sticky blob (e.g. adding Pro-C 3 pushed it before
-- Pro-Q 4), invalidating the entire cached prefix on every plugin addition.
-- Observed cost: ~15-20K tokens of cache_write on every ref-addition turn,
-- ~50% of total chat cost in a plugin-heavy session. Insertion order keeps
-- appends truly appended -- the prefix through existing refs stays
-- byte-identical and remains cached. See Net.sticky_parts() for the
-- two-block split that also preserves Anthropic block-level caching.
-- Dedup helper: for a fresh plugin_ref:/pref: write, check whether an
-- existing bundled key (same prefix, slash-joined names) already covers
-- this name. If yes, the standalone write is redundant -- skip it and let
-- the caller's "injected" log entry still fire at the bucket-dispatch site.
-- Returns true when the write should be skipped.
local function _sticky_would_duplicate(key)
  local prefix, name = key:match("^([%a_]+:)(.+)$")
  if not prefix or not name then return false end
  if prefix ~= "plugin_ref:" and prefix ~= "pref:" then return false end
  if name:find("/", 1, true) then return false end  -- the new key IS a bundle
  for existing_key in pairs(S.sticky_context or {}) do
    if existing_key ~= key then
      local ex_prefix, ex_names = existing_key:match("^([%a_]+:)(.+)$")
      if ex_prefix == prefix and ex_names and ex_names:find("/", 1, true) then
        for chunk in ex_names:gmatch("[^/]+") do
          if chunk == name then return true end
        end
      end
    end
  end
  return false
end

-- Symmetrical dedup: when a FRESH bundle is added, any standalone entries
-- with the same prefix that name a member of the bundle are now redundant
-- and should be removed. Returns the list of keys that were cleared (caller
-- uses this for logging if it cares).
local function _sticky_evict_standalones_for_bundle(bundle_key)
  local prefix, names = bundle_key:match("^([%a_]+:)(.+)$")
  if not prefix or not names then return {} end
  if prefix ~= "plugin_ref:" and prefix ~= "pref:" then return {} end
  if not names:find("/", 1, true) then return {} end
  local covered = {}
  for chunk in names:gmatch("[^/]+") do covered[chunk] = true end
  local to_evict = {}
  for existing_key in pairs(S.sticky_context or {}) do
    if existing_key ~= bundle_key then
      local ex_prefix, ex_name = existing_key:match("^([%a_]+:)(.+)$")
      if ex_prefix == prefix and ex_name
         and not ex_name:find("/", 1, true)
         and covered[ex_name] then
        to_evict[#to_evict+1] = existing_key
      end
    end
  end
  for _, k in ipairs(to_evict) do Net.sticky_unset(k) end
  return to_evict
end

function Net.sticky_set(key, content, source)
  if not S.sticky_context_order then S.sticky_context_order = {} end
  local is_fresh = S.sticky_context[key] == nil
  -- First-time add of a singleton that's already covered by an existing
  -- bundle: skip. Every turn before this was paying to send the same
  -- plugin_ref/pref content twice (once inside the bundle, once standalone),
  -- which bloated the sticky blob and invalidated prefix caching further
  -- downstream every time a new standalone landed.
  if is_fresh and _sticky_would_duplicate(key) then
    Log.line("STICKY", "skip redundant " .. key
      .. " (already covered by existing bundle)")
    return
  end
  if is_fresh then
    S.sticky_context_order[#S.sticky_context_order+1] = key
    -- First-time add of a bundle: evict any singletons it now subsumes.
    -- One-time cache-miss cost on the immediate next turn (the blob's
    -- suffix bytes shift), then permanent savings from not resending the
    -- singleton content on every subsequent turn.
    local evicted = _sticky_evict_standalones_for_bundle(key)
    if #evicted > 0 then
      Log.line("STICKY", "evicted " .. tbl_concat(evicted, ", ")
        .. " (subsumed by new bundle " .. key .. ")")
    end
    -- Record the source on first add only. Later same-key calls (idempotent
    -- re-pins) keep the original source -- a "copin" mid-session call
    -- shouldn't downgrade an already-"preempt" entry.
    S.sticky_pin_source = S.sticky_pin_source or {}
    S.sticky_pin_source[key] = source or "copin"
  end
  S.sticky_context[key] = content
end

function Net.sticky_unset(key)
  S.sticky_context[key] = nil
  if S.sticky_pin_source then S.sticky_pin_source[key] = nil end
  if not S.sticky_context_order then return end
  for i, k in ipairs(S.sticky_context_order) do
    if k == key then
      table.remove(S.sticky_context_order, i)
      return
    end
  end
end

function Net.sticky_key_mentioned_in_prompt(key, lower_prompt)
  local ident = key and key:match("^[^:]+:(.+)$")
  if not ident or lower_prompt == "" then return false end
  local ident_lower = ident:lower()
  if lower_prompt:find(ident_lower, 1, true) then return true end
  for part in ident:gmatch("[^/]+") do
    part = part:match("^%s*(.-)%s*$")
    if part ~= "" and lower_prompt:find(part:lower(), 1, true) then
      return true
    end
  end
  return false
end

-- Pin prompt_bundle:plugin into sticky if it's not already there. Called from
-- every site that pins a plugin_ref / pref_plugin / preferred_plugins entry,
-- so that any plugin ADD/CONFIGURE task arrives at the model already holding
-- the plugin workflow rules (find_param / set_param_display etc) -- saves
-- the first-plugin-turn round-trip where the model would otherwise emit
-- <context_needed>prompt_bundle:plugin</context_needed> and wait a full
-- turn before writing the script. The optional out_list parameter, when
-- provided, gets the pb_key appended so the caller can surface the bundle
-- in ctx_label / fetched_to_sticky logs.
function Net.copin_plugin_bundle(out_list)
  local pb_key = "prompt_bundle:plugin"
  if S.sticky_context[pb_key] then
    if S.prompt_bundle_sent then S.prompt_bundle_sent["plugin"] = true end
    return
  end
  local pb_content, _ = CTX.prompt_bundle("plugin")
  if not pb_content then return end
  Net.sticky_set(pb_key, pb_content)
  if S.prompt_bundle_sent then S.prompt_bundle_sent["plugin"] = true end
  if out_list then out_list[#out_list+1] = pb_key end
end

-- Pin prompt_bundle:theme next to the theme color reference. The theme bucket
-- lists the color keys; this bundle carries the backup/restore safety rule
-- required before any SetThemeColor code.
function Net.copin_theme_bundle(out_list)
  local pb_key = "prompt_bundle:theme"
  if S.sticky_context[pb_key] then
    if S.prompt_bundle_sent then S.prompt_bundle_sent["theme"] = true end
    return
  end
  local pb_content, _ = CTX.prompt_bundle("theme")
  if not pb_content then return end
  Net.sticky_set(pb_key, pb_content)
  if S.prompt_bundle_sent then S.prompt_bundle_sent["theme"] = true end
  if out_list then out_list[#out_list+1] = pb_key end
end

-- Pre-pin prompt_bundle:plugin_helpers (DECIDE FIRST flowchart, helper
-- function source, API DISPLAY RANGE MISMATCH guidance) into sticky_context.
-- Called when the dispatcher resolves a path that's about to write plugin
-- params with non-anchor values: fx_inspect (ADD + CONFIGURE), and fx_params
-- / preferred_plugins under a write-intent prompt. Most curated-plugin tasks
-- with verified-anchor values never need helpers and skip this co-pin.
--
-- No-op when:
--   - prompt_bundle:plugin_helpers is already in sticky_context (loaded
--     earlier this session; eviction is exempted same as docs sections).
--   - prompt_bundle_sent[plugin_helpers] is already true (defensive guard
--     against rapid double-co-pin within the same dispatch).
--   - The bundle file fails to load (logged via CTX.prompt_bundle error
--     path; the helper-definition validator is the safety net at gen time).
function Net.copin_plugin_helpers(out_list, source)
  local ph_key = "prompt_bundle:plugin_helpers"
  if S.sticky_context[ph_key] then
    if S.prompt_bundle_sent then S.prompt_bundle_sent["plugin_helpers"] = true end
    return
  end
  local ph_content, _ = CTX.prompt_bundle("plugin_helpers")
  if not ph_content then return end
  -- source defaults to "copin" inside Net.sticky_set. Pass "preempt"
  -- explicitly when called from CTX.preempt_buckets_for_prompt so the
  -- helpers bundle rides the same stable rung that's being initialized
  -- alongside prompt_bundle:plugin -- no extra rung-invalidation cost
  -- because the stable rung is being rebuilt this turn anyway.
  Net.sticky_set(ph_key, ph_content, source)
  if S.prompt_bundle_sent then S.prompt_bundle_sent["plugin_helpers"] = true end
  if out_list then out_list[#out_list+1] = ph_key end
end

-- Pre-pin an on-demand prompt bundle into sticky_context. Called from the
-- preempt path when the user prompt matches a narrow bundle-specific intent
-- (JSFX pitch recipes, drum-edit workflow rules, etc.).
-- No-op when the bundle is already pinned this session, when the bundle
-- file is missing, or when the bundle name isn't registered in
-- PROMPT_BUNDLE_NAMES.
function Net.copin_jsfx_family(family, out_list)
  if not family or family == "" then return end
  local pb_key = "prompt_bundle:" .. family
  if S.sticky_context[pb_key] then
    if S.prompt_bundle_sent then S.prompt_bundle_sent[family] = true end
    return
  end
  local pb_content, _ = CTX.prompt_bundle(family)
  if not pb_content then return end
  Net.sticky_set(pb_key, pb_content)
  if S.prompt_bundle_sent then S.prompt_bundle_sent[family] = true end
  if out_list then out_list[#out_list+1] = pb_key end
end

-- Pre-pin docs (core API ref) into S.api_ref_message. Called alongside
-- copin_plugin_bundle from every preempt / resolve site that signals plugin
-- work. Without this, the chain-phrase / resolve preempts pre-pin a rich
-- plugin context (plugin_ref + pref + bundle) but NO docs -- the model then
-- bypasses the API-REF-REQUIREMENT rule, writes reaper.* code anyway, and
-- the docs-gate inside Net.try_finish_curl silently force-fetches +
-- retries. Net: 2 round-trips instead of 1, +30K cache_write on the retry,
-- and the user-visible cost/time display only shows the FIRST request,
-- understating the true cost. Co-pinning docs alongside the plugin context
-- adds ~5K cache_write on the first turn but eliminates the retry's ~30K
-- and the wasted assistant turn. Net: smaller AND faster on every plugin
-- session that goes through preempt / resolve.
--
-- No-ops when:
--   - api_ref_message is already set (user has "Always include API ref" on,
--     or docs was force-fetched / requested earlier this session)
--   - docs file fails to load (logged via CTX.docs error path; docs-gate
--     still acts as the safety net on response)
--
-- Sets S.docs_already_sent so a same-turn <context_needed>docs</context_needed>
-- (e.g. from a model that's belt-and-suspenders) hits the dispatcher's
-- dedup branch instead of re-fetching. Also sets S.docs_fetched_session
-- so the docs-gate sees docs as available and doesn't trigger.
function Net.copin_docs_core(out_list)
  if S.api_ref_message then return end
  local content, _err = CTX.docs()
  if not content then return end
  S.api_ref_message      = content
  S.docs_already_sent    = true
  S.docs_fetched_session = true
  if out_list then out_list[#out_list+1] = "docs" end
end

-- Returns two text blobs, stable + growing, emitted in sticky_context_order.
--   stable : prompt_bundle:* payloads and request-scoped Custom Instructions.
--            These effectively never change once pinned during a request.
--            Placed in a dedicated Anthropic cache block so this rung stays
--            hot across ref-addition turns.
--   growing: everything else (plugin_ref, pref, preferred_plugins,
--            fx_params, fx_inspect, docs_extended). Grows as new plugins
--            are referenced; its cache rung invalidates when a new ref is
--            appended, but that only costs the new ref's tokens -- the
--            stable rung stays cached. A leading manifest line lists ALL
--            pinned keys (stable + growing) so weak models can string-scan
--            before emitting a redundant <context_needed>.
--
-- Both may be nil when their respective bucket set is empty. When only one
-- side has content, the other returns nil. sticky_text() concatenates both
-- for providers without multi-breakpoint caching.
function Net.sticky_parts()
  -- Static refs (docs / midi / theme) live in their own message slots, not in
  -- S.sticky_context, but they're equally "pinned above" from the model's POV.
  -- Include them in the manifest so the model's quick-scan sees them and
  -- doesn't emit a redundant <context_needed>docs</context_needed> (observed
  -- failure mode on weaker models).
  local static_keys = {}
  if S.api_ref_message   then static_keys[#static_keys+1] = "docs"  end
  if S.midi_ref_message  then static_keys[#static_keys+1] = "midi"  end
  if S.theme_ref_message then static_keys[#static_keys+1] = "theme" end
  local suppress_fx_sticky =
    type(Code) == "table"
    and type(Code.prompt_forbids_fx_addition) == "function"
    and Code.prompt_forbids_fx_addition(S.pending_orig_prompt or "")
  local function skip_sticky_key(k)
    -- Intentional cache trade-off: prompts that explicitly forbid adding FX
    -- drop plugin/Fx sticky refs for this one turn. That can invalidate a
    -- mid-prefix cache rung when the user alternates FX/no-FX wording, but
    -- the suppressed turn is much smaller and the prior 5-minute rungs
    -- usually survive for the next normal turn. Keep this local to the
    -- skip predicate; do not "fix" it by always retaining plugin context.
    if not suppress_fx_sticky then return false end
    return k == "prompt_bundle:plugin"
      or k == "prompt_bundle:plugin_helpers"
      or k:find("^plugin_ref:") ~= nil
      or k:find("^pref:") ~= nil
      or k:find("^preferred_plugins:") ~= nil
      or k:find("^fx:") ~= nil
      or k == "fx_list"
      or k:find("^fx_list:") ~= nil
      or k:find("^fx_inspect:") ~= nil
      or k == "fx_chains"
  end

  local stable_keys, growing_keys = {}, {}
  if S.sticky_context_order then
    for _, k in ipairs(S.sticky_context_order) do
      if S.sticky_context[k] and not skip_sticky_key(k) then
        -- Most prompt_bundle:* entries are stable (pinned once at the start
        -- of a plugin/jsfx/theme task and don't change). prompt_bundle:
        -- plugin_helpers is the exception: it can be pinned via three
        -- different paths and only one of them is safe to route to stable:
        --
        --   "preempt"        -- co-pinned in CTX.preempt_buckets_for_prompt
        --                       alongside prompt_bundle:plugin. The stable
        --                       rung is already being initialized this turn,
        --                       so adding helpers to it costs no extra
        --                       cache miss. Route to STABLE.
        --   "copin"          -- co-pinned mid-flow by a dispatcher write-
        --                       intent path (fx_params / fx_inspect /
        --                       preferred_plugins) or the helper-validator
        --                       retry. The stable rung was cached on an
        --                       earlier turn; adding helpers there would
        --                       invalidate it on a turn we didn't plan to.
        --                       Route to GROWING.
        --   "context_needed" -- pulled in response to a model
        --                       <context_needed>prompt_bundle:plugin_helpers
        --                       tag. Same reasoning as "copin". Route to
        --                       GROWING.
        --
        -- Default to "copin" (growing) for any helpers entry without a
        -- recorded source -- the safe choice that matches pre-source-tag
        -- behavior. Other prompt_bundle:* keys always go to stable; those
        -- bundles are session-defining and don't suffer the late-add
        -- problem helpers does.
        local is_helpers = (k == "prompt_bundle:plugin_helpers")
        local helpers_source = is_helpers and S.sticky_pin_source
          and S.sticky_pin_source[k] or nil
        if k:find("^prompt_bundle:") and not is_helpers then
          stable_keys[#stable_keys+1] = k
        elseif is_helpers and helpers_source == "preempt" then
          stable_keys[#stable_keys+1] = k
        else
          growing_keys[#growing_keys+1] = k
        end
      end
    end
  end

  -- Nothing pinned anywhere: no sticky output.
  if #static_keys == 0 and #stable_keys == 0 and #growing_keys == 0 then
    return nil, nil
  end
  -- Static-only pinned refs already carry their manifest inside
  -- Net.bundled_static_refs(). Avoid emitting a separate manifest-only sticky
  -- message plus acknowledgement when no actual sticky keys are present.
  if #stable_keys == 0 and #growing_keys == 0 then
    return nil, nil
  end

  local stable_text
  if #stable_keys > 0 then
    local parts = {}
    for _, k in ipairs(stable_keys) do parts[#parts+1] = S.sticky_context[k] end
    stable_text = tbl_concat(parts, "\n\n")
  end

  -- Always emit the sticky manifest when any sticky bucket exists. Static-only
  -- turns carry their manifest inside Net.bundled_static_refs() instead. The
  -- manifest lists every pinned key so the model can short-circuit re-requests.
  -- Order: static refs first (stable slot), then stable sticky
  -- (prompt_bundle:*), then growing sticky (plugin_ref/pref/fx_*).
  --
  -- LAYOUT WITHIN growing_text (cache-stability-driven):
  --   1. Byte-stable preamble (fixed text -- never changes).
  --   2. Plugin content in insertion order (sticky_context_order). This
  --      block's prefix bytes are stable across additions because content
  --      only ever appends to the end.
  --   3. Manifest at the END.
  -- Why manifest-at-end: the manifest line gains a key every time a plugin
  -- is added. Putting it at the TOP made byte 0 of growing_text differ on
  -- every addition, invalidating the entire growing cache rung. With the
  -- manifest at the end, the plugin-content prefix stays byte-identical
  -- across additions, so Anthropic's cache hits up through the previous
  -- turn's content -- only the new plugin's content + new manifest +
  -- last_asst need fresh cache_write. ~10-15K cache_write savings per
  -- ref-addition turn.
  local all_keys = {}
  for _, k in ipairs(static_keys)  do all_keys[#all_keys+1] = k end
  -- Keep the manifest shape stable on normal snapshot-enabled turns. The
  -- snapshot itself rides the latest user message, not sticky_context, but
  -- changing this manifest line every time a retry/follow-up rebuild toggles
  -- S.pending_snapshot would invalidate the sticky cache rung.
  if prefs.include_snapshot ~= false then all_keys[#all_keys+1] = "session" end
  for _, k in ipairs(stable_keys)  do all_keys[#all_keys+1] = k end
  for _, k in ipairs(growing_keys) do all_keys[#all_keys+1] = k end
  local growing_parts = {}
  if #growing_keys > 0 then
    -- Byte-stable preamble (no key list -- fixed text). Cues the model that
    -- a manifest exists at the bottom of this section without changing the
    -- byte content turn-to-turn.
    growing_parts[#growing_parts+1] =
      "PINNED REFERENCES section follows. Full manifest at the END of this section."
    -- Plugin content in insertion order. Append-only is critical for cache
    -- stability -- see Net.sticky_set / sticky_context_order.
    for _, k in ipairs(growing_keys) do
      growing_parts[#growing_parts+1] = S.sticky_context[k]
    end
  end
  growing_parts[#growing_parts+1] =
    "PINNED REFERENCES (already provided above; do NOT re-request via "
    .. "<context_needed>): " .. tbl_concat(all_keys, ", ")
  local growing_text = tbl_concat(growing_parts, "\n\n")

  return stable_text, growing_text
end

function Net.sticky_parts_for_request()
  if Net.answer_only_context_enabled() then return nil, nil end
  return Net.sticky_parts()
end

-- Single-blob accessor for providers without Anthropic-style multi-breakpoint
-- caching (OpenAI / Gemini paths use this; Anthropic uses sticky_parts()
-- directly to keep the stable rung in its own cache breakpoint). Concatenates
-- stable + growing preserving insertion order. Returns nil when both sides
-- are empty.
function Net.sticky_text()
  local s, g = Net.sticky_parts_for_request()
  if not s and not g then return nil end
  if s and g then return s .. "\n\n" .. g end
  return s or g
end

-- =============================================================================
-- Net.sticky_evict
-- =============================================================================
-- Keeps S.sticky_context bounded over long sessions. Without this, every
-- plugin_ref / pref_plugins / fx_params bucket ever pinned in the session
-- stays in sticky forever, growing the prefix linearly and re-sending
-- 50-100K of irrelevant data on every turn for cinematic / 30+ turn sessions.
--
-- Strategy: each key has a "last touched" turn (sticky_context_age[k]).
--   - Unknown keys (just added) are treated as touched on the current turn.
--   - Keys whose payload identifier (the part after the colon) appears in
--     the current user prompt are refreshed to the current turn.
--   - Keys older than STICKY_MAX_AGE turns are evicted.
-- Conservative -- a re-mentioned plugin survives indefinitely; only truly
-- abandoned context gets pruned.
local STICKY_MAX_AGE = 10  -- turns

function Net.sticky_evict(user_text)
  if not S.sticky_context then return end
  S.turn_counter = (S.turn_counter or 0) + 1
  local now = S.turn_counter
  local age = S.sticky_context_age
  if not age then S.sticky_context_age = {}; age = S.sticky_context_age end
  local lower = (user_text or ""):lower()
  -- Initialize new keys, refresh keys whose identifier hits in the prompt.
  for k in pairs(S.sticky_context) do
    if not age[k] then age[k] = now end
    if Net.sticky_key_mentioned_in_prompt(k, lower) then
      age[k] = now
    end
  end
  -- Drop stale keys + clean up orphaned age entries.
  -- Exemption: docs:* / docs_extended and prompt_bundle:* are stable
  -- session-wide reference material, not per-task context that should churn.
  -- The doc payloads are cheaper to keep than to re-fetch on a follow-up
  -- keyword mention. Prompt bundles are treated as system-prompt content
  -- (`prompt_bundle_sent` is session-scoped), so evicting them would make the
  -- manifest/sent flags claim a bundle is pinned when it no longer is.
  -- Trade-off: a misfired pre-pin stays alive forever (bounded ~850-1800
  -- tokens × cache rolls; if this becomes a problem, a softer "evict at
  -- 25 turns of no-keyword-mention" rule could be added).
  local evicted
  for k, t in pairs(age) do
    if not S.sticky_context[k] then
      age[k] = nil
    elseif k == "docs_extended" or k:find("^docs:")
        or k:find("^prompt_bundle:") then
      -- exempt; see comment above.
    elseif k == "recent_reaper_changes"
        and (now - t) > 2 then
      Net.sticky_unset(k)
      age[k] = nil
      evicted = (evicted or {})
      evicted[#evicted+1] = k
    elseif (now - t) > STICKY_MAX_AGE then
      Net.sticky_unset(k)   -- also removes k from sticky_context_order
      age[k] = nil
      evicted = (evicted or {})
      evicted[#evicted+1] = k
    end
  end
  if evicted then
    Log.line("STICKY", "evicted stale sticky context: "
      .. tbl_concat(evicted, ", "))
  end
end

function Net.sticky_prune_after_plugin_success(user_text, code_text)
  if not (CTX and CTX.prompt_indicates_chain_context
      and CTX.prompt_indicates_chain_context(user_text)) then
    return
  end
  if not S.sticky_context then return end

  local code = tostring(code_text or "")
  local helper_used =
       code:find("%f[%w]find_param%s*%(") ~= nil
    or code:find("%f[%w]set_param_display%s*%(") ~= nil
    or code:find("%f[%w]set_param_enum%s*%(") ~= nil
    or code:find("%f[%w]set_param_enum_paced%s*%(") ~= nil
  local evict = {}
  for k in pairs(S.sticky_context) do
    if k == "fx_chains"
       or k:find("^plugin_ref:")
       or k:find("^pref:")
       or (k == "prompt_bundle:plugin_helpers" and not helper_used) then
      evict[#evict+1] = k
    end
  end
  table.sort(evict)
  for _, k in ipairs(evict) do
    if k == "fx_chains" then
      S.fx_chains_already_sent = false
    elseif k == "prompt_bundle:plugin_helpers" then
      if S.prompt_bundle_sent then S.prompt_bundle_sent["plugin_helpers"] = nil end
    else
      local refs = k:match("^plugin_ref:(.+)$")
      if refs and S.plugin_ref_sent then
        for name in refs:gmatch("[^/]+") do S.plugin_ref_sent[name] = nil end
      end
      local prefs = k:match("^pref:(.+)$")
      if prefs and S.pref_plugins_sent then
        for name in prefs:gmatch("[^/]+") do S.pref_plugins_sent[name] = nil end
      end
    end
    Net.sticky_unset(k)
    if S.sticky_context_age then S.sticky_context_age[k] = nil end
  end
  if #evict > 0 then
    Log.line("STICKY", "pruned after successful chain action: "
      .. tbl_concat(evict, ", "))
  end
end

-- =============================================================================
-- Net.build_body (provider dispatch)
-- =============================================================================
-- Constructs the complete API request JSON body. Dispatches to a provider-specific
-- builder based on the active provider. Each builder handles system prompt
-- packaging, message formatting, attachment encoding, and any provider-specific
-- features (e.g. Anthropic prompt caching).
function Net.build_body(msgs, snapshot, msg_attachments)
  -- Probe timing: time spent assembling the request body.
  -- Wraps the dispatcher rather than each provider variant so all
  -- callers (send_to_api initial build + retries / context-needed
  -- re-fires that call build_body inline) accumulate into the same
  -- turn's body_build phase total.
  Probe.mark_phase_start(S.probe_turn, "body_build")
  local p = PROVIDERS.active()
  local result
  if p.id == "anthropic" then
    result = Net.build_body_anthropic(msgs, snapshot, msg_attachments)
  elseif p.id == "openai" or p.id == "deepseek" or p.is_custom then
    -- Custom providers always speak the OpenAI Chat Completions schema (the
    -- de-facto standard for OSS servers like Ollama, LM Studio, vLLM).
    -- DeepSeek shares this branch -- it is OpenAI-compatible at the wire
    -- level, with thinking expressed via extra_body (see the
    -- deepseek_extra_body branch in build_body_openai itself).
    result = Net.build_body_openai(msgs, snapshot, msg_attachments)
  elseif p.id == "google" then
    result = Net.build_body_google(msgs, snapshot, msg_attachments)
  end
  Probe.mark_phase_end(S.probe_turn, "body_build")
  -- Local Bench builds expose a request-context recorder. Keep this hook inert
  -- in shipped ReaAssist, but let the Bench attribute exact included source
  -- bytes to individual sticky buckets before Log.request attaches the body to
  -- a cell. Matching against the assembled JSON avoids reporting stale sticky
  -- entries that the request-specific skip policy omitted.
  if result and BenchMode and BenchMode.record_request_context then
    local buckets = {}
    local function record_if_included(name, content)
      if type(content) ~= "string" or content == "" then return end
      if result:find(JSON.escape(content), 1, true) then
        buckets[name] = #content
      end
    end
    local sys = Net.system_prompt_text()
    if sys then
      local custom = Net.custom_instructions_prompt_block_for_request()
      local base_bytes = #sys - (custom and #custom or 0)
      if base_bytes > 0 then buckets.system_prompt = base_bytes end
      record_if_included("custom_instructions", custom)
    end
    if msgs and msgs[#msgs] then
      record_if_included("user_request", msgs[#msgs].content)
    end
    if not Net.answer_only_context_enabled() then
      record_if_included("docs", S.api_ref_message)
      record_if_included("midi", S.midi_ref_message)
      record_if_included("theme", S.theme_ref_message)
      for key, content in pairs(S.sticky_context or {}) do
        record_if_included(key, content)
      end
    end
    record_if_included("snapshot", snapshot)
    local attachment_bytes = 0
    for _, att in ipairs(msg_attachments or {}) do
      attachment_bytes = attachment_bytes
        + #(att.b64 or att.data or "")
    end
    if attachment_bytes > 0 then buckets.attachments = attachment_bytes end
    BenchMode.record_request_context({
      provider = p.id,
      body_bytes = #result,
      buckets = buckets,
    })
  end
  return result
end

-- =============================================================================
-- Net.build_body_anthropic
-- =============================================================================
-- Anthropic Messages API format. System prompt as top-level "system" field with
-- cache_control. Pinned API ref as first user message (stable cache position).
-- Snapshot injected as a separate content block in the last user message.
--
-- Cache breakpoints (max 4 allowed by Anthropic, we use up to 4):
--   1. System prompt                                 (always)
--   2. End of static_blob + sticky_stable rung       (when either present;
--      static_blob piggybacks on sticky_stable's mark when both are present)
--   3. sticky_growing rung                           (when present)
--   4. Last assistant message                        (moving breakpoint,
--      prefix grows one user/assistant pair per turn)
--
-- TTL strategy: every rung uses the 5-minute default (CACHE_5M). Two
-- constraints made anything fancier net-negative:
--
--   1. Anthropic forbids a 1h cache_control block from appearing AFTER any
--      5m block in the same request: "a ttl='1h' cache_control block must
--      not come after a ttl='5m' cache_control block" (invalid_request_error).
--      Since our breakpoints are positionally fixed (system first,
--      last_asst last), any per-rung mix of 5m+1h that puts 1h on
--      last_asst gets rejected.
--   2. Anthropic also treats the ttl field as part of the cache key, so
--      flipping a rung from 5m to 1h between turns busts that rung's
--      cached prefix. Earlier code stamped one TTL per request and
--      flipped 5m -> 1h on turn 2 to "warm" 1h coverage; the observed
--      effect was cache_read=0 on T2 (full prefix re-write) regardless
--      of whether the gap exceeded 5 min.
--
-- Plan A (this code): drop the 1h escalation entirely. Always 5m, on every
-- rung, every turn. Net effect: cache stays warm across normal read/run/
-- refine cadences (which are typically <5 min anyway), and the rare
-- >5-min idle gap costs one prefix re-write -- strictly cheaper than
-- the original "flip everyone to 1h on T2" approach which paid that cost
-- 100% of the time on multi-turn sessions.
local CACHE_5M = ',"cache_control":{"type":"ephemeral"}'

-- Cheap content fingerprint for cache-plan diagnostics. Not cryptographic --
-- just a stable 32-bit FNV-1a in hex so the debug log can show "did this
-- rung's bytes drift between turns" at a glance. Skipped when debug logging
-- is off (callers gate on prefs.debug_logging via Log.line).
local function _cache_plan_hash(s)
  local h = 2166136261
  for i = 1, #s do
    h = (h ~ s:byte(i)) * 16777619
    h = h & 0xFFFFFFFF
  end
  return string.format("%08x", h)
end

function Net.build_body_anthropic(msgs, snapshot, msg_attachments)
  -- Each rung emits CACHE_5M; the helpers below also record bytes/hash into
  -- cache_plan for the per-request CACHE-PLAN debug line. See the function
  -- header for the constraints that motivated the always-5m strategy.
  local cache_plan = {}
  local function rung_cache_mark(rung_name, content)
    cache_plan[#cache_plan+1] = {
      name = rung_name, ttl = "5m", bytes = content and #content or 0,
      hash = (content and prefs.debug_logging) and _cache_plan_hash(content) or "-",
    }
    return CACHE_5M
  end

  -- Diagnostic-only registration for content that lands ahead of an
  -- existing cache breakpoint without a marker of its own (e.g.,
  -- static_blob when sticky_stable absorbs it onto the same rung).
  -- Without this, the cache plan only hashes the rung-bearing block,
  -- so drift in the absorbed content (a new static ref appearing,
  -- reorder of api_ref / midi_ref / theme_ref) is invisible to the
  -- log even though it busts the rung's prefix in reality.
  local function rung_piggyback(rung_name, content)
    cache_plan[#cache_plan+1] = {
      name = rung_name .. "(piggyback)",
      ttl  = "-",
      bytes = content and #content or 0,
      hash = (content and prefs.debug_logging) and _cache_plan_hash(content) or "-",
    }
  end

  local system_text = Net.system_prompt_text()
  local system_json = str_format(
    '[{"type":"text","text":"%s"%s}]',
    JSON.escape(system_text), rung_cache_mark("system", system_text))

  local msg_parts = {}

  -- Bundle the long-lived static refs (api_ref + midi_ref + theme_ref) into
  -- ONE pinned user message with a single trailing ack, instead of three
  -- separate user/ack pairs. Saves ~16-24 tokens per turn in ack overhead
  -- and reduces alignment churn for downstream caches when refs come in.
  -- Anthropic 4-breakpoint allocation:
  --   slot 1: system + custom instructions             (always)
  --   slot 2: end of static_blob + sticky_stable       (when sticky_stable
  --                                                     present; static_blob
  --                                                     piggybacks on this rung)
  --           OR static_blob                           (when sticky_stable
  --                                                     absent but static_blob
  --                                                     present)
  --           OR sticky_stable                         (when static_blob absent)
  --   slot 3: sticky_growing                           (when present)
  --   slot 4: last_asst                                (moving, when history
  --                                                     has >= 1 complete turn)
  -- Why static_blob loses its dedicated cache mark when sticky_stable is
  -- present: a single-rung cache covering "system + static_blob + sticky_stable"
  -- is functionally identical to two separate rungs (any change to static_blob
  -- invalidates sticky_stable's prefix anyway), but it FREES a breakpoint slot
  -- so sticky_growing can have its own rung. The win: when sticky_growing
  -- changes (every fx_inspect / plugin_ref / pref addition), sticky_stable
  -- (~14K plugin bundle) keeps reading from cache instead of being rewritten
  -- alongside the growing block. Observed cost before this change: ~10-15K
  -- cache_write per ref-addition turn.
  local sticky_stable, sticky_growing = Net.sticky_parts_for_request()
  local static_blob = Net.bundled_static_refs_for_request()
  if static_blob then
    -- Drop static_blob's own cache_mark when sticky_stable will absorb it
    -- into the next rung. Keep it when sticky_stable is absent (otherwise
    -- static_blob would only cache via sticky_growing's rung, which gets
    -- invalidated frequently).
    local static_cache_mark
    if sticky_stable then
      -- Absorbed onto sticky_stable's rung. Register a piggyback entry
      -- in the cache plan so static-ref drift (a new midi_ref / theme_ref
      -- arriving, or api_ref reordering) shows up in the log even though
      -- this block carries no cache_control marker of its own.
      rung_piggyback("static", static_blob)
      static_cache_mark = ""
    else
      static_cache_mark = rung_cache_mark("static", static_blob)
    end
    msg_parts[#msg_parts+1] = str_format(
      '{"role":"user","content":[{"type":"text","text":"%s"%s}]}',
      JSON.escape(static_blob), static_cache_mark)
    msg_parts[#msg_parts+1] = '{"role":"assistant","content":[{"type":"text","text":"Understood."}]}'
  end
  -- Pinned sticky with up to TWO cache_control breakpoints:
  --   - sticky_stable  : prompt_bundle:* payloads (big, effectively frozen
  --                      for the rest of the session). Own cache rung so it
  --                      stays hot even when the growing block invalidates.
  --   - sticky_growing : plugin_ref / pref / fx_params / fx_inspect, plus
  --                      a manifest line listing all pinned keys. Its cache
  --                      rung re-writes on each ref addition but the stable
  --                      rung's ~15K tokens no longer get re-written with it.
  -- The 2-block split now fires whenever both halves are populated -- the
  -- breakpoint budget is free because static_blob piggybacks on sticky_stable.
  local has_sticky = sticky_stable or sticky_growing
  if has_sticky then
    local can_split = sticky_stable and sticky_growing
    if can_split then
      -- Two content blocks in ONE user message, each with its own
      -- cache_control. Anthropic caches each block as its own prefix rung:
      -- adding a new plugin_ref changes the growing block but NOT the
      -- stable block, so the stable rung keeps reading on subsequent
      -- turns. Saves ~15K tokens of cache_write per ref-addition turn.
      msg_parts[#msg_parts+1] = str_format(
        '{"role":"user","content":[{"type":"text","text":"%s"%s},{"type":"text","text":"%s"%s}]}',
        JSON.escape(sticky_stable), rung_cache_mark("sticky_stable", sticky_stable),
        JSON.escape(sticky_growing), rung_cache_mark("sticky_growing", sticky_growing))
    else
      -- Single-block fallback: only one of stable/growing is populated.
      -- Concatenate in stable-first order so byte-prefix caching still wins
      -- on OpenAI-style implicit cache if we're ever reused there.
      local blob = sticky_stable and sticky_growing
        and (sticky_stable .. "\n\n" .. sticky_growing)
        or  (sticky_stable or sticky_growing)
      -- Rung name reflects which half is present so per-rung TTL state
      -- doesn't conflate "sticky_stable alone" with "sticky_stable + growing
      -- collapsed into one rung". In practice only one of these branches
      -- exercises within a given session.
      local rung = sticky_stable and "sticky_stable" or "sticky_growing"
      msg_parts[#msg_parts+1] = str_format(
        '{"role":"user","content":[{"type":"text","text":"%s"%s}]}',
        JSON.escape(blob), rung_cache_mark(rung, blob))
    end
    msg_parts[#msg_parts+1] = '{"role":"assistant","content":[{"type":"text","text":"Understood."}]}'
  end

  local last_asst_idx = nil
  for idx = #msgs, 1, -1 do
    local m = msgs[idx]
    if m and m.role == "assistant" then
      last_asst_idx = idx
      break
    end
  end

  for idx, m in ipairs(msgs) do
    local is_last_user = (m.role == "user" and idx == #msgs)

    if is_last_user then
      -- Build content blocks for the last user message: text + snapshot + attachments.
      local blocks = {}
      blocks[#blocks+1] = str_format('{"type":"text","text":"%s"}',
        JSON.escape(m.content))

      if snapshot then
        blocks[#blocks+1] = str_format('{"type":"text","text":"%s"}',
          JSON.escape(snapshot))
      end

      -- Append attachment content blocks (images, PDFs, text files).
      if msg_attachments then
        for _, att in ipairs(msg_attachments) do
          if att.kind == "image" then
            blocks[#blocks+1] = str_format(
              '{"type":"image","source":{"type":"base64","media_type":"%s","data":"%s"}}',
              att.media_type, att.b64)
          elseif att.kind == "pdf" then
            blocks[#blocks+1] = str_format(
              '{"type":"document","source":{"type":"base64","media_type":"application/pdf","data":"%s"}}',
              att.b64)
          elseif att.kind == "text" then
            blocks[#blocks+1] = str_format(
              '{"type":"text","text":"[Attached file: %s]\\n%s"}',
              JSON.escape(att.name), JSON.escape(att.data))
          end
        end
      end

      msg_parts[#msg_parts+1] = str_format(
        '{"role":"user","content":[%s]}', tbl_concat(blocks, ","))
    else
      -- Non-final messages: single block. Mark the last assistant message as a
      -- moving cache breakpoint so the conversation prefix is cached for
      -- cheaper follow-up turns.
      local is_last_asst = (m.role == "assistant" and idx == last_asst_idx)
      local cache = is_last_asst and rung_cache_mark("last_asst", m.content) or ""
      msg_parts[#msg_parts+1] = str_format(
        '{"role":"%s","content":[{"type":"text","text":"%s"%s}]}',
        m.role, JSON.escape(m.content), cache)
    end
  end

  -- Per-rung cache plan (debug only): rung=bytes/ttl/hash, comma-separated.
  -- Lets the user diff request-to-request: if a rung's hash changes, its
  -- prefix bytes drifted (manifest reorder, ref insertion); if its ttl
  -- string changes, the freeze logic regressed. Either way, expect a miss.
  if prefs.debug_logging and #cache_plan > 0 then
    local parts = {}
    for _, p in ipairs(cache_plan) do
      parts[#parts+1] = str_format("%s=%dB/%s/%s", p.name, p.bytes, p.ttl, p.hash)
    end
    Log.line("CACHE-PLAN", tbl_concat(parts, ", "))
  end

  -- Anthropic Messages API REQUIRES max_tokens (omitting returns 400). Send
  -- the active model's published output ceiling so the model can write up to
  -- the maximum it supports. This is intentionally larger than any thinking
  -- budget above; thinking budget limits reasoning tokens, while max_tokens
  -- limits total response output. Non-streaming requests with very large
  -- ceilings rely on ReaAssist's watchdog/Extend UX to handle slow completions.
  -- Falls back to 64K if the model entry is missing max_output (older entries;
  -- defensive, all current entries have it).
  local active_m = MODELS[prefs.model_idx] or MODELS[1]
  local max_out  = (active_m and active_m.max_output) or 64000

  -- Extended thinking. Anthropic's API treats `thinking` as opt-in for
  -- every Claude model: when the field is absent, the model runs in
  -- non-thinking mode regardless of which 4.x variant is active. The
  -- "None" dropdown entry maps to an explicit disabled-thinking request.
  -- When a non-None level is picked, the wire shape depends on the active model's
  -- thinking_style: Haiku 4.5 takes manual budget_tokens; Sonnet 5 and
  -- Opus 4.8 use adaptive + an effort knob and reject manual budgets.
  -- S.thinking_override_idx (when
  -- set) wins over prefs.thinking_idx so the length-retry path can force
  -- "None" for one round-trip.
  local p_active = PROVIDERS.active()
  local effective_thinking_idx = S.thinking_override_idx or prefs.thinking_idx
  local thinking_field = ""
  if effective_thinking_idx and effective_thinking_idx > 0
     and p_active.thinking_levels then
    local tl = p_active.thinking_levels[effective_thinking_idx]
    local style = active_m and active_m.thinking_style
    if tl then
      if tl.value == "none" then
        thinking_field = ',"thinking":{"type":"disabled"}'
      elseif style == "claude_adaptive" and tl.effort then
        thinking_field = str_format(
          ',"thinking":{"type":"adaptive"},"output_config":{"effort":"%s"}',
          tl.effort)
      elseif tl.budget_tokens then
        -- claude_manual (Haiku 4.5) -- and a defensive fallback if a
        -- model entry omits thinking_style entirely.
        thinking_field = str_format(
          ',"thinking":{"type":"enabled","budget_tokens":%d}',
          tl.budget_tokens)
      end
    end
  end

  return str_format(
    '{"model":"%s","max_tokens":%d%s,"system":%s,"messages":[%s]}',
    MODELS.active_id(), max_out, thinking_field, system_json,
    tbl_concat(msg_parts, ","))
end

-- =============================================================================
-- Net.merge_custom_extra_body
-- =============================================================================
-- Merge provider-wide extra_body (p.extra_body) with per-model extra_body
-- (active_m.extra_body) and return the result as a comma-prefixed JSON
-- body suffix ("," + inner-JSON without surrounding braces) ready to splice
-- into the outer chat/completions body. Returns "" when both are empty or
-- decode fails -- callers can append it unconditionally.
--
-- Per-model keys win over provider-wide keys (in-order decode/merge/re-
-- encode pass). Runs through JSON.decode / JSON.encode so we don't brace-
-- splice raw user input.
--
-- Shared by Net.build_body_openai (real chat) and Net.fire_key_test's
-- opt-in inference probe so the test exercises the same vendor-specific
-- toggles as the real chat path. active_m may be nil; result is the same
-- as if its extra_body were empty.
function Net.merge_custom_extra_body(p, active_m)
  if not p or not p.is_custom then return "" end
  local prov_body  = p.extra_body or ""
  local model_body = (active_m and active_m.extra_body) or ""
  if prov_body == "" and model_body == "" then return "" end
  local merged = {}
  if prov_body ~= "" then
    local pobj = JSON.decode(prov_body)
    if type(pobj) == "table" then
      for k, v in pairs(pobj) do merged[k] = v end
    end
  end
  if model_body ~= "" then
    local mobj = JSON.decode(model_body)
    if type(mobj) == "table" then
      for k, v in pairs(mobj) do merged[k] = v end
    end
  end
  local encoded = JSON.encode(merged)
  if not encoded or encoded == "{}"
     or encoded:sub(1, 1) ~= "{" or encoded:sub(-1) ~= "}" then
    return ""
  end
  local inner = encoded:sub(2, -2)
  if inner == "" then return "" end
  return "," .. inner
end

-- =============================================================================
-- Net.build_body_openai
-- =============================================================================
-- OpenAI Chat Completions API format. System prompt as a "system" role message.
-- All messages are simple {role, content} objects. Attachments: images as
-- image_url content parts, text files inline, PDFs as text note (unsupported).
function Net.openai_prompt_cache_key()
  if type(S.openai_prompt_cache_key) == "string"
     and S.openai_prompt_cache_key ~= "" then
    return S.openai_prompt_cache_key
  end
  local key
  if Store and Store.openai_prompt_cache_key then
    local ok, result = pcall(Store.openai_prompt_cache_key)
    if ok and type(result) == "string" and result ~= "" then
      key = result
    elseif not ok then
      Log.line("CACHE", "openai prompt_cache_key restore failed: "
        .. tostring(result))
    end
  end
  key = key or S.INSTANCE_ID or "ra_prompt_cache"
  S.openai_prompt_cache_key = key
  return key
end

function Net.openai_safety_identifier()
  if type(S.openai_safety_identifier) == "string"
     and #S.openai_safety_identifier == 64
     and S.openai_safety_identifier:match("^[0-9a-f]+$") then
    return S.openai_safety_identifier
  end
  if not RA or type(RA.sha256_hex) ~= "function" then
    Log.line("SAFETY", "OpenAI safety identifier omitted: SHA-256 unavailable")
    return nil
  end
  local cache_key = Net.openai_prompt_cache_key()
  if type(cache_key) ~= "string" or cache_key == "" then return nil end
  local ok, identifier = pcall(RA.sha256_hex,
    "reaassist:openai:safety:v1:" .. cache_key)
  if not ok or type(identifier) ~= "string" then
    Log.line("SAFETY", "OpenAI safety identifier omitted: hash failed")
    return nil
  end
  identifier = identifier:lower()
  if #identifier ~= 64 or not identifier:match("^[0-9a-f]+$") then
    Log.line("SAFETY", "OpenAI safety identifier omitted: invalid hash")
    return nil
  end
  S.openai_safety_identifier = identifier
  return identifier
end

function Net.build_body_openai(msgs, snapshot, msg_attachments)
  local msg_parts = {}
  local p = PROVIDERS.active()
  local model_id = MODELS.active_id()
  if p.is_custom and p.model_prefix and p.model_prefix ~= "" then
    model_id = p.model_prefix .. model_id
  end
  local is_openai_56 = p.id == "openai"
    and type(model_id) == "string"
    and model_id:match("^gpt%-5%.6") ~= nil

  -- GPT-5.6 explicit caching: mark the stable core system prompt and disable
  -- the implicit latest-message breakpoint. This avoids paying a 1.25x write
  -- premium on the changing user prompt, snapshot, and attachments. Older
  -- models reject the new fields, so they retain automatic implicit caching.
  if is_openai_56 then
    msg_parts[#msg_parts+1] = str_format(
      '{"role":"system","content":[{"type":"text","text":"%s","prompt_cache_breakpoint":{"mode":"explicit"}}]}',
      JSON.escape(Net.system_prompt_text()))
  else
    msg_parts[#msg_parts+1] = str_format(
      '{"role":"system","content":"%s"}', JSON.escape(Net.system_prompt_text()))
  end

  -- Bundle the long-lived static refs (api_ref + midi_ref + theme_ref) into
  -- ONE pinned system message instead of three. OpenAI's implicit prefix
  -- caching aligns on byte-level prefix; fewer message boundaries mean a
  -- cleaner, more stable prefix. See Net.bundled_static_refs().
  local static_blob = Net.bundled_static_refs_for_request()
  if static_blob then
    if is_openai_56 then
      -- The bundled API/MIDI/theme references are the second reusable prefix.
      -- Prompt-specific sticky plugin/context material remains after this
      -- breakpoint so one-off context does not create avoidable cache writes.
      msg_parts[#msg_parts+1] = str_format(
        '{"role":"system","content":[{"type":"text","text":"%s","prompt_cache_breakpoint":{"mode":"explicit"}}]}',
        JSON.escape(static_blob))
    else
      msg_parts[#msg_parts+1] = str_format(
        '{"role":"system","content":"%s"}', JSON.escape(static_blob))
    end
  end

  -- Prepend pinned sticky context (plugin_ref / pref_plugins / fx_params /
  -- fx_inspect) as a system message so OpenAI's implicit prefix caching can
  -- discover the stable common prefix across turns. See Net.sticky_text().
  local sticky_blob = Net.sticky_text()
  if sticky_blob then
    msg_parts[#msg_parts+1] = str_format(
      '{"role":"system","content":"%s"}', JSON.escape(sticky_blob))
  end

  for idx, m in ipairs(msgs) do
    local is_last_user = (m.role == "user" and idx == #msgs)

    if is_last_user then
      -- Last user message: may include snapshot and attachments as content array.
      local has_extras = snapshot or msg_attachments
      if has_extras then
        local blocks = {}
        blocks[#blocks+1] = str_format('{"type":"text","text":"%s"}',
          JSON.escape(m.content))
        if snapshot then
          blocks[#blocks+1] = str_format('{"type":"text","text":"%s"}',
            JSON.escape(snapshot))
        end
        local _is_deepseek = (PROVIDERS.active().id == "deepseek")
        if msg_attachments then
          for _, att in ipairs(msg_attachments) do
            if att.kind == "image" then
              if _is_deepseek then
                -- DeepSeek's Chat Completion API is text-only (their own
                -- Anthropic-compat table marks image content unsupported),
                -- so an image_url block would 400 the request. Surface
                -- the attachment by name as a text note so the model can
                -- acknowledge it and the user understands why it isn't
                -- visually inspected -- mirrors the PDF handling below.
                blocks[#blocks+1] = str_format(
                  '{"type":"text","text":"[Attached image: %s] (DeepSeek does not support image input; this attachment was not sent.)"}',
                  JSON.escape(att.name))
              else
                blocks[#blocks+1] = str_format(
                  '{"type":"image_url","image_url":{"url":"data:%s;base64,%s"}}',
                  att.media_type, att.b64)
              end
            elseif att.kind == "text" then
              blocks[#blocks+1] = str_format(
                '{"type":"text","text":"[Attached file: %s]\\n%s"}',
                JSON.escape(att.name), JSON.escape(att.data))
            elseif att.kind == "pdf" then
              blocks[#blocks+1] = str_format(
                '{"type":"text","text":"[Attached PDF: %s] (PDF content attached as document)"}',
                JSON.escape(att.name))
            end
          end
        end
        msg_parts[#msg_parts+1] = str_format(
          '{"role":"user","content":[%s]}', tbl_concat(blocks, ","))
      else
        msg_parts[#msg_parts+1] = str_format(
          '{"role":"user","content":"%s"}', JSON.escape(m.content))
      end
    else
      msg_parts[#msg_parts+1] = str_format(
        '{"role":"%s","content":"%s"}', m.role, JSON.escape(m.content))
    end
  end

  local safety_identifier_field = ""
  if p.id == "openai" then
    local safety_identifier = Net.openai_safety_identifier()
    if safety_identifier then
      safety_identifier_field = str_format(
        ',"safety_identifier":"%s"', JSON.escape(safety_identifier))
    end
  end
  -- reasoning_effort: top-level string on the Chat Completions API.
  -- Hosted OpenAI accepts "none" | "low" | "medium" | "high" (and newer
  -- models also accept xhigh/max). Send "none" explicitly: GPT-5.6 defaults
  -- to Medium when the field is omitted, so omission is not an off switch.
  -- Custom-compatible providers keep the older omission behavior because
  -- many reject OpenAI-specific reasoning values.
  -- S.thinking_override_idx (when set) wins over prefs.thinking_idx -- the
  -- length auto-retry path uses this to force "none" for one round-trip
  -- when reasoning consumed the entire output budget on the first attempt.
  --
  -- DeepSeek (thinking_style == "deepseek_extra_body") expresses thinking
  -- via a top-level "thinking" object with type="disabled"|"enabled" instead
  -- of OpenAI's reasoning_effort scale. The "extra_body" name in DeepSeek's
  -- own docs is an OpenAI-SDK pass-through convention; on the wire the
  -- field sits at the top level next to where reasoning_effort would go.
  -- The field is MANDATORY for every DeepSeek request: omitting it falls
  -- through to DeepSeek's server-side default (currently enabled) which
  -- would silently ignore both the user's Non-Thinking selection and the
  -- length-retry fallback. Always emit an explicit "enabled"/"disabled";
  -- if the resolved idx is somehow out-of-range or carries an unexpected
  -- value, default to "disabled" (safer -- no surprise reasoning cost).
  local effective_thinking_idx = S.thinking_override_idx or prefs.thinking_idx
  local reasoning = ""
  if p.thinking_style == "deepseek_extra_body" then
    local tl = p.thinking_levels and p.thinking_levels[effective_thinking_idx]
    local val = (tl and tl.value) or "disabled"
    if val ~= "enabled" and val ~= "disabled" then val = "disabled" end
    reasoning = str_format(',"thinking":{"type":"%s"}', val)
  elseif effective_thinking_idx > 0
     and p.thinking_levels
     and p.thinking_levels[effective_thinking_idx] then
    local val = p.thinking_levels[effective_thinking_idx].value
    if val and (val ~= "none" or is_openai_56) then
      reasoning = str_format(',"reasoning_effort":"%s"', val)
    end
  end
  -- prompt_cache_key: stable per install identifier. OpenAI cache routing uses
  -- this together with the exact prefix, raising hit rates on long sessions
  -- and across REAPER restarts. GPT-5.6 requires it for improved implicit or
  -- explicit matching. The key is opaque to us and persisted in State.json.
  -- Custom-provider model prefix: OpenRouter/LiteLLM/Ollama routing gateways
  -- often require a prefix ("openrouter/anthropic/...", "ollama/...") on the
  -- model id. Stored per-provider so users don't have to type it into every
  -- model row. Empty string = no-op, matching hosted OpenAI's behaviour.
  local cache_options_field = is_openai_56
    and ',"prompt_cache_options":{"mode":"explicit","ttl":"30m"}' or ""
  local response_format = ""
  if p.id == "openai"
     and S.pending_typed_action_expected == true
     and S.pending_typed_action_response_format == true
     and type(Code.typed_actions_openai_response_format_field) == "function" then
    response_format =
      Code.typed_actions_openai_response_format_field(
        S.pending_orig_prompt or "") or ""
  end
  -- Custom-provider extra_body: merge provider-wide + per-model JSON objects
  -- into the outer request body. Net.merge_custom_extra_body is the shared
  -- helper -- used here for real chat AND from Net.fire_key_test's opt-in
  -- inference test path so the test exercises the same vendor toggles
  -- (Kimi thinking flag, Qwen enable_thinking, OpenRouter reasoning, etc.)
  -- that real chat sends.
  local extra_suffix = ""
  if p.is_custom then
    extra_suffix = Net.merge_custom_extra_body(p, MODELS[prefs.model_idx])
  end
  -- max_completion_tokens: optional on the OpenAI Chat Completions API. For
  -- normal cloud OpenAI chat, omit it so the server applies its own per-model
  -- ceiling -- avoids the GPT-5-thinking failure mode where a fixed cap got
  -- consumed by reasoning tokens and produced empty visible output. Typed-action
  -- response-format requests are different: the only valid answer is compact
  -- JSON, so cap them to prevent runaway structured-output completions. Keep
  -- enough room for GPT-5 mini Low thinking, which can spend several thousand
  -- hidden reasoning tokens before emitting the compact JSON object. Small
  -- typed-action profiles can opt into a lower cap; if they hit it, the
  -- validator fails closed and escalates instead of waiting on an 8K-token loop.
  -- For custom providers (Ollama / LM Studio / vLLM / OpenRouter etc.), keep
  -- the cap derived from the per-model context_window field on the API Keys
  -- page, since local servers commonly run with tight context windows that need
  -- a real bound on output.
  local max_tokens_field = ""
  if p.id == "openai" and response_format ~= "" then
    local typed_action_cap = 8192
    local active_model = MODELS[prefs.model_idx]
    local model_cap = active_model
      and tonumber(active_model.typed_action_max_completion)
    if model_cap and model_cap > 0 then
      typed_action_cap = math_floor(model_cap)
    end
    local tl = p.thinking_levels and p.thinking_levels[effective_thinking_idx]
    if S.typed_action_escalation_used == true
       and tl and tl.value == "none" then
      typed_action_cap = math_min(typed_action_cap, 2048)
    end
    max_tokens_field =
      str_format(',"max_completion_tokens":%d', typed_action_cap)
  elseif p.is_custom then
    local custom_active = MODELS[prefs.model_idx]
    local ctx_window    = (custom_active and tonumber(custom_active.context_window))
                          or CUSTOM_DEFAULT_CTX
    -- Reserve at most 10% of the local context for output, with a hard
    -- ceiling at 16K so a misconfigured huge context_window doesn't lead
    -- to absurd output budgets that don't match what local hardware can
    -- actually generate in a reasonable time.
    local custom_cap = math_min(16384, math_floor(ctx_window * 0.1))
    if custom_cap < 256 then custom_cap = 256 end
    max_tokens_field = str_format(',"max_completion_tokens":%d', custom_cap)
  end
  -- DeepSeek: skip prompt_cache_key (OpenAI-only routing hint; DeepSeek caches
  -- automatically on prefix and ignores the field, but emitting it makes the
  -- request log misleading) and skip max_completion_tokens (handled like
  -- cloud OpenAI -- let the server apply its own per-model ceiling).
  if p.id == "deepseek" then
    return str_format(
      '{"model":"%s","messages":[%s]%s%s}',
      model_id, tbl_concat(msg_parts, ","), reasoning, extra_suffix)
  end
  return str_format(
    '{"model":"%s"%s,"prompt_cache_key":"%s"%s%s,"messages":[%s]%s%s%s}',
    model_id, max_tokens_field, JSON.escape(Net.openai_prompt_cache_key()),
    cache_options_field, safety_identifier_field, tbl_concat(msg_parts, ","),
    reasoning, response_format, extra_suffix)
end

-- =============================================================================
-- Net.build_body_google
-- =============================================================================
-- Gemini generateContent API format. System prompt as systemInstruction.
-- Messages as contents[]. Role mapping: "assistant" -> "model".
-- Attachments: images and PDFs as inlineData parts, text files inline.
--
-- If a Gemini explicit context cache is active and valid for the current
-- model, the cached content (system_instruction including Custom Instructions
-- + api_ref priming) is referenced via cachedContent and omitted from the live
-- request body.
function Net.build_body_google(msgs, snapshot, msg_attachments)
  local msg_parts = {}
  local answer_only_context = Net.answer_only_context_enabled()
  local use_cache = (not answer_only_context) and Net.gemini_cache_is_usable()
  S.gemini_cache_last_used = use_cache == true
  S.gemini_cache_last_state =
    Net.gemini_cache_debug_state("body_build", use_cache)
  if answer_only_context and type(S.gemini_cache_last_state) == "table" then
    S.gemini_cache_last_state.status = "disabled"
    S.gemini_cache_last_state.reason = "answer_only_followup"
    S.gemini_cache_last_state.used = false
  end

  -- Bundle the long-lived static refs (api_ref + midi_ref + theme_ref) into
  -- ONE pinned user+model exchange instead of three. Fewer turns inside
  -- contents[] is cleaner for Gemini's implicit prefix caching to align on.
  -- When the explicit context cache is active, it already covers
  -- system_instruction (including Custom Instructions when enabled) + api_ref,
  -- so we omit api_ref from the bundle in that case to avoid double-sending it.
  local static_parts = {}
  if not answer_only_context and S.api_ref_message and not use_cache then
    static_parts[#static_parts+1] = S.api_ref_message
  end
  if not answer_only_context and S.midi_ref_message then
    static_parts[#static_parts+1] = S.midi_ref_message
  end
  if not answer_only_context and S.theme_ref_message then
    static_parts[#static_parts+1] = S.theme_ref_message
  end
  if #static_parts > 0 then
    local static_blob = tbl_concat(static_parts, "\n\n")
    msg_parts[#msg_parts+1] = str_format(
      '{"role":"user","parts":[{"text":"%s"}]}', JSON.escape(static_blob))
    msg_parts[#msg_parts+1] = '{"role":"model","parts":[{"text":"Understood."}]}'
  end

  -- Prepend pinned sticky context (plugin_ref / pref_plugins / fx_params /
  -- fx_inspect) as a user+model exchange. Sits in a stable prefix position
  -- so Gemini's implicit caching (and explicit cache if it covers here) can
  -- match it across turns. See Net.sticky_text(). Deliberately NOT included
  -- in the Gemini explicit cache (that stays scoped to api_ref only), so
  -- sticky growth doesn't force cache recreation.
  local sticky_blob = Net.sticky_text()
  if sticky_blob then
    msg_parts[#msg_parts+1] = str_format(
      '{"role":"user","parts":[{"text":"%s"}]}', JSON.escape(sticky_blob))
    msg_parts[#msg_parts+1] = '{"role":"model","parts":[{"text":"Understood."}]}'
  end

  for idx, m in ipairs(msgs) do
    local is_last_user = (m.role == "user" and idx == #msgs)
    -- Gemini uses "model" instead of "assistant".
    local role = (m.role == "assistant") and "model" or m.role

    if is_last_user then
      local parts = {}
      parts[#parts+1] = str_format('{"text":"%s"}', JSON.escape(m.content))
      if snapshot then
        parts[#parts+1] = str_format('{"text":"%s"}', JSON.escape(snapshot))
      end
      if msg_attachments then
        for _, att in ipairs(msg_attachments) do
          if att.kind == "image" then
            parts[#parts+1] = str_format(
              '{"inlineData":{"mimeType":"%s","data":"%s"}}',
              att.media_type, att.b64)
          elseif att.kind == "pdf" then
            parts[#parts+1] = str_format(
              '{"inlineData":{"mimeType":"application/pdf","data":"%s"}}',
              att.b64)
          elseif att.kind == "text" then
            parts[#parts+1] = str_format(
              '{"text":"[Attached file: %s]\\n%s"}',
              JSON.escape(att.name), JSON.escape(att.data))
          end
        end
      end
      msg_parts[#msg_parts+1] = str_format(
        '{"role":"user","parts":[%s]}', tbl_concat(parts, ","))
    else
      msg_parts[#msg_parts+1] = str_format(
        '{"role":"%s","parts":[{"text":"%s"}]}', role, JSON.escape(m.content))
    end
  end

  local thinking = ""
  -- S.thinking_override_idx (when set) wins over prefs.thinking_idx -- the
  -- length auto-retry path uses this to force "none" for one round-trip
  -- when reasoning consumed the entire output budget on the first attempt.
  local effective_thinking_idx = S.thinking_override_idx or prefs.thinking_idx
  if effective_thinking_idx > 0 then
    local p = PROVIDERS.active()
    local m = MODELS[prefs.model_idx] or MODELS[1]
    if p.thinking_levels then
      -- If Pro model and MINIMAL selected, bump to LOW (MINIMAL is flash-only)
      local tidx = effective_thinking_idx
      local tl = p.thinking_levels[tidx]
      if tl and tl.flash_only and not m.is_flash then
        tidx = math_min(tidx + 1, #p.thinking_levels)  -- next level (LOW)
        tl = p.thinking_levels[tidx]
      end
      if tl then
        thinking = str_format(',"thinkingConfig":{"thinkingLevel":"%s","includeThoughts":false}', tl.value)
      end
    end
  end
  -- maxOutputTokens: optional in Gemini's generationConfig. Omit it so the
  -- server applies its own per-model ceiling (~64K on Gemini 3.x). Same
  -- rationale as the OpenAI path: a fixed cap can be entirely consumed by
  -- thinking tokens, leaving zero visible output. Letting the server cap
  -- naturally avoids that failure mode.
  if use_cache then
    -- system_instruction lives inside the cache; omit it from the live body.
    return str_format(
      '{"contents":[%s],"cachedContent":"%s","generationConfig":{%s}}',
      tbl_concat(msg_parts, ","), S.gemini_cache_name,
      thinking:gsub("^,", ""))
  end
  return str_format(
    '{"contents":[%s],"systemInstruction":{"parts":[{"text":"%s"}]},"generationConfig":{%s}}',
    tbl_concat(msg_parts, ","), JSON.escape(Net.system_prompt_text()),
    thinking:gsub("^,", ""))
end

-- =============================================================================
-- Net.trimmed_history
-- =============================================================================
-- Returns the last CFG.MAX_HISTORY_TURNS entries from S.history for the API call.
-- The full S.history table is preserved for display; only the slice is sent.
-- If the first entry in the slice is an assistant message (possible if an
-- odd number of entries were removed mid-conversation), it is dropped so
-- the API always receives a conversation starting with a user turn.
function Net.trimmed_history()
  local hist
  if #S.history <= CFG.MAX_HISTORY_TURNS then
    S.history_trim_start = nil
    hist = S.history
  else
    hist = {}
    local start = tonumber(S.history_trim_start)
    if not start or start < 1 or start > #S.history
       or (#S.history - start + 1) > CFG.MAX_HISTORY_TURNS then
      local hysteresis = math_floor(
        tonumber(CFG.HISTORY_TRIM_HYSTERESIS) or 0)
      if hysteresis < 0 then hysteresis = 0 end
      if hysteresis >= CFG.MAX_HISTORY_TURNS then hysteresis = 0 end
      local keep = CFG.MAX_HISTORY_TURNS - hysteresis
      if keep < 1 then keep = CFG.MAX_HISTORY_TURNS end
      start = #S.history - keep + 1
      if start < 1 then start = 1 end
      if S.history[start]
         and S.history[start].role == "assistant"
         and start < #S.history then
        start = start + 1
      end
      S.history_trim_start = start
    end
    for i = start, #S.history do
      hist[#hist+1] = S.history[i]
    end
    if #hist > 0 and hist[1].role == "assistant" then
      tbl_remove(hist, 1)
    end
    if #hist == 0 then
      -- Slice was a single assistant entry that we just dropped. Return
      -- just the most recent message rather than falling back to the
      -- FULL untrimmed S.history (latent overshoot of the trim budget;
      -- only triggerable at very low MAX_HISTORY_TURNS, but the previous
      -- behaviour silently sent every prior turn, defeating the trim).
      hist = { S.history[#S.history] }
    end
  end
  return hist
end

-- =============================================================================
-- Net.fire_curl
-- =============================================================================
-- Writes the JSON body to a temp file and launches curl asynchronously.
-- Provider-aware: builds the endpoint URL, auth headers, and extra headers
-- dynamically from the active PROVIDERS entry.
--
-- Auth strategies:
--   header      (Claude, OpenAI, Gemini): key sent via -H @file so it never
--               appears on the command line. The auth file is cleaned up after
--               curl. Each provider specifies its own auth_header name.
--
-- Both platforms use an async pattern: curl runs in the background, writes
-- its response to tmp.out, stderr to tmp.err, and echoes its exit code to tmp.exit.
-- Net.try_finish_curl() polls both files each frame to detect completion.
--
-- Windows: the curl command is inlined directly into a PowerShell -Command
--   string launched via Start-Process -WindowStyle Hidden.
-- macOS/Linux: trailing "&" backgrounds the shell pipeline.
-- opts (optional table) lets the caller request a non-standard request shape:
--   opts.method            -- "GET" to send an empty GET instead of POST
--   opts.endpoint_override -- full URL to use instead of the provider's endpoint
-- Both are used by the custom-LLM connection test, which hits GET /v1/models
-- so no inference runs on the server. When method=="GET" we skip the body
-- write, the content-type header, and the -d flag; nil/POST behaves as before.
-- Restore the trailing user-history entry from S.pending_orig_prompt,
-- shedding any sticky-bucket / internal-retry-note content that was baked
-- in mid-turn. Mirrors the success-path cleanup in Net.process_response;
-- centralised so the per-turn-call-cap abort path can reuse the same
-- semantics without leaving an internal note as the user's last turn.
function Net._restore_pending_user_history()
  if not S.pending_orig_prompt or not S.history or #S.history == 0 then return end
  local restored = "USER REQUEST:\n" .. S.pending_orig_prompt
  local tail = S.history[#S.history]
  if tail and tail.role == "user" then
    tail.content = restored
    return
  end
  local prev = S.history[#S.history - 1]
  if tail and tail.role == "assistant"
     and prev and prev.role == "user" then
    prev.content = restored
  end
end

-- Retry prompts sometimes fire on terse follow-ups ("1", "yes", "use built
-- in", "snap them"), where S.pending_orig_prompt alone is not enough context.
-- Expand those into a compact task-context block so hidden validator retries
-- don't make the model reconstruct the user's real intent from luck.
function Net._retry_trim_text(text)
  return tostring(text or "")
    :gsub("\r\n", "\n")
    :gsub("^%s+", "")
    :gsub("%s+$", "")
end

function Net._retry_extract_user_request(content)
  local text = tostring(content or "")
  if text:find("INTERNAL NOTE TO THE MODEL", 1, true) then return "" end
  local marker, last = "USER REQUEST:", nil
  local pos = 1
  while true do
    local s, e = text:find(marker, pos, true)
    if not s then break end
    last = e + 1
    pos = e + 1
  end
  if last then text = text:sub(last) end
  return Net._retry_trim_text(text)
end

function Net._retry_prompt_needs_context(text)
  local t = Net._retry_trim_text(text)
  local lo = t:lower()
  if lo == "" then return false end
  if #lo <= 24 then return true end
  if lo:match("^%d+[%.)]?$") then return true end
  if lo:find("%f[%w]option%f[%W]") then return true end
  if lo:find("%f[%w]same%f[%W]") then return true end
  if lo:find("%f[%w]previous%f[%W]") then return true end
  if lo:find("%f[%w]last%f[%W]") then return true end
  if lo:find("%f[%w]that%f[%W]") then return true end
  if lo:find("%f[%w]this%f[%W]") then return true end
  if lo:find("%f[%w]them%f[%W]") then return true end
  if lo:find("%f[%w]those%f[%W]") then return true end
  if lo:find("built in", 1, true) or lo:find("built%-in") then return true end
  return false
end

function Net._retry_request_is_substantive(text, current)
  local t = Net._retry_trim_text(text)
  if t == "" or t == current then return false end
  if #t <= 12 then return false end
  if t:match("^[%d%p%s]+$") then return false end
  return true
end

function Net.retry_user_request_context()
  local current = Net._retry_trim_text(S.pending_orig_prompt or "")
  if not Net._retry_prompt_needs_context(current) then return current end
  local prior_rev = {}
  for i = #S.history, 1, -1 do
    local row = S.history[i]
    if row and row.role == "user" then
      local req = Net._retry_extract_user_request(row.content)
      if Net._retry_request_is_substantive(req, current) then
        prior_rev[#prior_rev + 1] = req
        if #prior_rev >= 2 then break end
      end
    end
  end
  if #prior_rev == 0 then return current end
  local prior = {}
  for i = #prior_rev, 1, -1 do
    local req = prior_rev[i]
    if #req > 700 then req = req:sub(1, 697) .. "..." end
    prior[#prior + 1] = req
  end
  return "Prior task context:\n" .. tbl_concat(prior, "\n\n")
    .. "\n\nLatest user reply / option selection:\n" .. current
end

-- Tier-aware copy for the per-turn-call-cap abort. Small / local models
-- loop the most, so the message nudges users toward the next tier up;
-- flagship models on the cap usually mean a genuinely confused turn,
-- so the suggestion is to start fresh and report it if it repeats.
function Net._call_cap_message()
  local p   = PROVIDERS.active() or {}
  local m   = MODELS[prefs.model_idx] or MODELS[1] or {}
  local mid = (m.id or m.name or ""):lower()
  local pid = p.id or ""
  -- Match a marker only at a word boundary so substrings inside larger
  -- names don't trigger -- e.g. "gemini-3.1-pro-preview" must NOT hit
  -- "mini", and "anthropic-flash-prototype" must hit "flash" cleanly.
  -- %f[%a] = position where prev char is non-letter and next is letter
  -- (start of a word); %f[%A] is the inverse (end of a word).
  local function tag(kw)
    return mid:find("%f[%a]" .. kw .. "%f[%A]") ~= nil
  end
  local hint
  if pid == "anthropic" and tag("haiku") then
    hint = "Try Sonnet 5 or Opus 4.8 for this request."
  elseif pid == "google" and (tag("flash") or tag("nano")) then
    hint = "Try Gemini 3.1 Pro for this request."
  elseif pid == "openai" and tag("mini") then
    hint = "Try a non-mini OpenAI model for this request."
  elseif p.is_custom
      or tag("haiku") or tag("flash") or tag("mini")
      or tag("nano")  or tag("gemma") or tag("llama")
      or tag("phi") then
    hint = "This often happens with smaller or local models -- try a "
        .. "higher-tier model."
  else
    hint = "Unusual on a flagship model. Try starting a new chat or "
        .. "rephrasing. If it repeats, please use Help -> Report an Issue."
  end
  return ("Stopped after %d API calls in one turn to avoid runaway cost. %s")
         :format(CFG.MAX_CALLS_PER_TURN, hint)
end

function Net._validator_retry_cap_message()
  return ("Stopped after %d automatic repair retries in one turn to avoid runaway cost. Try rephrasing the request or using a stronger model if it repeats.")
         :format(CFG.MAX_VALIDATOR_RETRIES_PER_TURN or 3)
end

function Net._call_cap_error_extra()
  local p   = PROVIDERS.active() or {}
  local m   = MODELS[prefs.model_idx] or MODELS[1] or {}
  local provider_id = p.is_custom and "custom" or (p.id or nil)
  local model_id = p.is_custom and "custom" or (m and (m.id or m.name) or nil)
  return {
    error_kind = "runaway_call_cap",
    error_debug = {
      failure_kind = "runaway_call_cap",
      source = "runaway_call_guardrail",
      matched_condition = "api_call_turn_cap",
      provider_id = provider_id,
      model_id = model_id,
      api_calls_this_turn = S.api_calls_this_turn or 0,
      max_api_calls_per_turn = CFG.MAX_CALLS_PER_TURN,
      session_status_before = S.status or nil,
      retry_count = S.retry_count,
      retry_max = S.retry_max,
      pending_display_idx = S.pending_display_idx,
      pending_turn_state = S.pending_orig_prompt and "orig_prompt" or nil,
    },
  }
end

function Net._validator_retry_cap_error_extra()
  local p   = PROVIDERS.active() or {}
  local m   = MODELS[prefs.model_idx] or MODELS[1] or {}
  local provider_id = p.is_custom and "custom" or (p.id or nil)
  local model_id = p.is_custom and "custom" or (m and (m.id or m.name) or nil)
  return {
    error_kind = "runaway_validator_retry_cap",
    error_debug = {
      failure_kind = "runaway_validator_retry_cap",
      source = "runaway_validator_retry_guardrail",
      matched_condition = "validator_retry_turn_cap",
      provider_id = provider_id,
      model_id = model_id,
      validator_retries_this_turn = S.validator_retries_this_turn or 0,
      max_validator_retries_per_turn = CFG.MAX_VALIDATOR_RETRIES_PER_TURN or 3,
      api_calls_this_turn = S.api_calls_this_turn or 0,
      max_api_calls_per_turn = CFG.MAX_CALLS_PER_TURN,
      session_status_before = S.status or nil,
      retry_count = S.retry_count,
      retry_max = S.retry_max,
      pending_display_idx = S.pending_display_idx,
      pending_turn_state = S.pending_orig_prompt and "orig_prompt" or nil,
    },
  }
end

function Net._ensure_request_start_time()
  -- Hidden same-turn retries fire curl directly instead of re-entering
  -- Net.send_to_api(), so they must preserve the original wall-clock anchor
  -- for the visible "Elapsed" timer. If an older path already lost it, fall
  -- back to the current request clock rather than showing a frozen 0:00.
  if not S.request_start_time then
    S.request_start_time = S.send_time or time_precise()
  end
end

function Net.try_local_read_answer(user_text, attachments, probe_turn)
  if attachments then return false end
  if not CTX or not CTX.local_read_answer then return false end
  local answer = CTX.local_read_answer(user_text, S.pending_project)
  if not answer then return false end
  return Net._emit_local_answer(user_text, answer, probe_turn, {
    ctx_label = "local_read",
  })
end

function Net.try_local_jsfx_capability_overview(user_text, attachments, probe_turn)
  if attachments then return false end
  if Code.history_has_prior_assistant(S.history) then return false end
  if not CTX or not CTX.local_jsfx_capability_overview_answer then return false end
  local answer = CTX.local_jsfx_capability_overview_answer(user_text)
  if not answer then return false end
  return Net._emit_local_answer(user_text, answer, probe_turn, {
    ctx_label = "local_jsfx_overview",
  })
end

function Net._prune_display_messages(max_count)
  local list = S and S.display_messages
  if type(list) ~= "table" then return 0 end
  local max = tonumber(max_count) or CFG.MAX_DISPLAY_MSGS
  local n = #list
  if n <= max then return 0 end
  local pruned_count = n - max
  for i = 1, max do
    list[i] = list[i + pruned_count]
  end
  for i = max + 1, n do
    list[i] = nil
  end
  return pruned_count
end

function Net._rebase_display_message_index(idx, pruned_count)
  local n = tonumber(idx)
  local pruned = tonumber(pruned_count) or 0
  if not n then return nil end
  n = n - pruned
  if n < 1 then return nil end
  return n
end

function Net._rebase_display_message_refs(pruned_count)
  pruned_count = tonumber(pruned_count) or 0
  if pruned_count <= 0 or type(S) ~= "table" then return end
  S.pending_display_idx = Net._rebase_display_message_index(
    S.pending_display_idx, pruned_count)
  S.backup_warn_idx = Net._rebase_display_message_index(
    S.backup_warn_idx, pruned_count)
  S.backup_warn_typed_idx = Net._rebase_display_message_index(
    S.backup_warn_typed_idx, pruned_count)
  S.risky_warn_idx = Net._rebase_display_message_index(
    S.risky_warn_idx, pruned_count)
  S.jsfx_save_warn_idx = Net._rebase_display_message_index(
    S.jsfx_save_warn_idx, pruned_count)
  S.scroll_to_msg = Net._rebase_display_message_index(
    S.scroll_to_msg, pruned_count)
  if not S.scroll_to_msg then S.scroll_to_msg_frames = nil end
  if type(S.lua_defer_run) == "table" then
    S.lua_defer_run.message_idx = Net._rebase_display_message_index(
      S.lua_defer_run.message_idx, pruned_count)
  end
  if type(S.backup_flash) == "table" then
    local shifted = {}
    for idx, flash in pairs(S.backup_flash) do
      local rebased = Net._rebase_display_message_index(idx, pruned_count)
      if rebased then shifted[rebased] = flash end
    end
    S.backup_flash = shifted
  end
end

function Net._emit_local_answer(user_text, answer, probe_turn, opts)
  opts = opts or {}
  S.history[#S.history + 1] = {
    role = "user",
    content = "USER REQUEST:\n" .. tostring(user_text or ""),
  }
  S.history[#S.history + 1] = {
    role = "assistant",
    content = answer,
  }

  S.display_messages[#S.display_messages + 1] = {
    role = "user",
    content = tostring(user_text or ""),
    ctx_label = opts.ctx_label or "local_answer",
    model_label = "ReaAssist Local",
    provider_id = "local",
    from_card = S.from_card or nil,
  }
  local local_answer_msg = {
    role = "assistant",
    content = answer,
    provider_id = "local",
    model_label = "ReaAssist Local",
    local_answer = true,
    local_answer_available = true,
    provider_call_avoided = true,
    code_block_present = false,
    assistant_response_status = "complete",
    -- Diagnostic-only run_status: local read answer finished without provider/code execution.
    run_status = "local_answer",
    validation_status = "not_applicable",
    local_retry_available = true,
    llm_retry_prompt = tostring(user_text or ""),
  }
  if opts.selected_count_guard then
    local_answer_msg.selected_count_guard = opts.selected_count_guard
    local_answer_msg.validation_status = "blocked"
    local_answer_msg.validation_block_kind = "selected_count_mismatch"
  end
  S.display_messages[#S.display_messages + 1] = local_answer_msg
  S.from_card = false
  if #S.display_messages > CFG.MAX_DISPLAY_MSGS then
    if Diag.uploader_enabled and Diag.capture_current_chat then
      Diag.capture_current_chat()
    end
    local pruned_count = Net._prune_display_messages(CFG.MAX_DISPLAY_MSGS)
    if pruned_count > 0 then
      Net._rebase_display_message_refs(pruned_count)
      S.wrap_cache = {}
    end
  end

  S.status = "idle"
  S.request_start_time = nil
  S.send_time = nil
  S.pending_code = nil
  S.pending_display_idx = nil
  S.pending_orig_prompt = nil
  S.pending_typed_action_expected = false
  S.pending_typed_action_response_format = false
  S.pending_typed_action_profile = nil
  S.pending_answer_only_followup = nil
  S.pending_project = nil
  S.pending_snapshot = nil
  S.pending_attachments = nil
  S._fx_cache_events = nil
  S.scroll_to_bottom = true
  Probe.end_turn(probe_turn, "success")
  S.probe_turn = nil
  return true
end

function Net.try_local_panner_lfo_clarification(user_text, attachments, probe_turn)
  if attachments then return false end
  local needs, hz = Code.prompt_needs_pan_lfo_rate_clarification(user_text)
  if not needs then return false end
  local rate = hz and string.format("%g Hz", hz) or "that Hz rate"
  local answer = "Quick clarification before I write or run this: do you mean "
    .. rate .. " as an audio-rate JSFX/autopan-style effect, or do you mean "
    .. "that many cycles spread across the bar span as normal pan envelope "
    .. "automation? I can do either, but I need that choice so I don't create "
    .. "a huge pan envelope that isn't what you meant."
  return Net._emit_local_answer(user_text, answer, probe_turn, {
    ctx_label = "local_clarification",
  })
end

function Net.try_local_selected_track_rename_count_guard(user_text, attachments,
    probe_turn)
  if attachments then return false end
  if type(Code.selected_track_rename_numbered_range) ~= "function" then
    return false
  end
  if type(reaper.CountSelectedTracks) ~= "function" then return false end
  local range = Code.selected_track_rename_numbered_range(user_text)
  if not range then return false end
  local actual = tonumber(reaper.CountSelectedTracks(0)) or 0
  local expected = tonumber(range.expected_count) or 0
  if expected <= 0 or actual == expected then return false end
  local range_text = tostring(range.start_index) .. " through "
    .. tostring(range.end_index)
  local selected_text = actual == 0 and "no tracks are"
    or (actual == 1 and "1 track is" or (tostring(actual) .. " tracks are"))
  local answer = str_format(
    "I didn't make any changes. This asks for %d sequential names (%s), but %s selected. Select %d tracks or change the range, then send it again.",
    expected, range_text, selected_text, expected)
  return Net._emit_local_answer(user_text, answer, probe_turn, {
    ctx_label = "local_selected_count_guard",
    selected_count_guard = {
      expected_selected_count = expected,
      actual_selected_count = actual,
      start_index = range.start_index,
      end_index = range.end_index,
    },
  })
end

function Net.ask_model_instead(user_text)
  S.skip_local_answer_once = true
  -- Escalation keeps request bookkeeping, but reuses the original visible turn.
  S.suppress_user_display_once = true
  return Net.send_to_api(user_text)
end

function Net._try_escalate_typed_actions(reason_code, detail)
  local profile =
    Code.typed_actions_model_profile_by_key(S.pending_typed_action_profile)
  local fallback = type(profile) == "table" and profile.fallback or nil
  if type(fallback) ~= "table" then return false end
  if S.typed_action_escalation_used then return false end

  local original_p = PROVIDERS.active() or {}
  local original_m = MODELS[prefs.model_idx] or MODELS[1] or {}
  local original_thinking_override_idx = S.thinking_override_idx
  local ok, switch_reason =
    PROVIDERS.switch_to_model(fallback.provider_id, fallback.model_id)
  if not ok then
    Log.line("TYPED-ACTION-ESCALATION",
      "fallback model unavailable: " .. tostring(switch_reason or "unknown"))
    return false
  end

  local p = PROVIDERS.active() or {}
  local m = MODELS[prefs.model_idx] or MODELS[1] or {}
  local response_format = p.id == "openai"
  local fallback_profile = Code.typed_actions_model_profile(p.id, m.id)
  local fallback_model_id = m.id or fallback.model_id or "?"
  if fallback.thinking_value and p.thinking_levels then
    local found_thinking_idx
    for i, tl in ipairs(p.thinking_levels) do
      if tostring(tl.value or "") == tostring(fallback.thinking_value) then
        found_thinking_idx = i
        break
      end
    end
    if found_thinking_idx then
      S.thinking_override_idx = found_thinking_idx
    else
      Log.line("TYPED-ACTION-ESCALATION",
        "fallback thinking level unavailable: "
        .. tostring(fallback.thinking_value))
    end
  end
  S.pending_typed_action_response_format = response_format
  S.pending_typed_action_profile =
    type(fallback_profile) == "table" and fallback_profile.key or nil
  S.typed_action_retry_offset =
    (S.typed_action_retry_offset or 0)
    + (S.typed_action_format_validator_retries or 0)
    + (S.typed_action_schema_validator_retries or 0)
    + (S.typed_action_semantic_validator_retries or 0)
  S.typed_action_format_validator_retries = 0
  S.typed_action_schema_validator_retries = 0
  S.typed_action_semantic_validator_retries = 0
  S.typed_action_escalation_used = true
  S.typed_action_escalation_count =
    (S.typed_action_escalation_count or 0) + 1
  S.typed_action_escalation_model =
    tostring(p.id or fallback.provider_id or "") .. "/"
    .. tostring(fallback_model_id)
  S.typed_action_escalation_restore = {
    provider_id = original_p.id,
    model_id = original_m.id,
    fallback_provider_id = p.id or fallback.provider_id,
    fallback_model_id = fallback_model_id,
    thinking_override_idx = original_thinking_override_idx,
  }
  Probe.add_validator_retry(S.probe_turn, "typed_action_escalation")

  Log.line("TYPED-ACTION-ESCALATION",
    "escalating typed-action turn to "
    .. tostring(S.typed_action_escalation_model)
    .. " after " .. tostring(reason_code or "typed_action_failure")
    .. " (" .. tostring(detail or "") .. ")")

  local retry_contract =
    Code.typed_actions_prompt_contract(S.pending_orig_prompt or "",
      {
        force_enabled = true,
        response_format = response_format,
        profile = fallback_profile,
      }) or ""
  local reemit_hint = response_format
    and "the raw JSON object required by the active response schema"
    or "a single ```reaassist-actions fenced JSON object"
  local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
    .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: A weaker model could "
    .. "not produce a safe typed-action plan for this request. Reason: "
    .. tostring(reason_code or "typed_action_failure")
    .. ". Details: " .. tostring(detail or "") .. ". Re-solve the original "
    .. "request from scratch using the active typed-action contract. Emit "
    .. "the complete plan as " .. reemit_hint .. ". Do not copy any prior "
    .. "bad JSON. Do not write Lua, ReaScript, JSFX, prose, apologies, or "
    .. "omit any actions.)\n\n"
    .. (retry_contract ~= "" and (retry_contract .. "\n\n") or "")
    .. "USER REQUEST:\n" .. (S.pending_orig_prompt or "")
  if #S.history > 0 and S.history[#S.history].role == "assistant" then
    S.history[#S.history] = nil
  end
  if #S.history > 0 and S.history[#S.history].role == "user" then
    S.history[#S.history] = nil
  end
  S.history[#S.history + 1] = { role = "user", content = history_content }

  if S.pending_display_idx
     and S.display_messages[S.pending_display_idx] then
    local dmsg = S.display_messages[S.pending_display_idx]
    local existing = dmsg.ctx_label or ""
    if not existing:find("typed_action_escalated", 1, true) then
      dmsg.ctx_label = existing ~= ""
        and (existing .. " + typed_action_escalated")
        or "typed_action_escalated"
    end
  end

  if prefs.include_snapshot and not S.pending_answer_only_followup then
    S.pending_project  = CTX.resolve_pending_project()
    S.pending_snapshot = CTX.build_snapshot(S.pending_project,
      S.pending_jsfx_intent and { minimal_tracks = true } or nil)
  end
  S.status = "waiting"
  Net._ensure_request_start_time()
  Code.safe_write(tmp.out, "")
  local fired, fire_reason = Net.fire_curl(Net.build_body(Net.trimmed_history(),
    S.pending_snapshot, S.pending_attachments))
  if not fired then
    Net._restore_typed_action_escalation_model()
    S.status = "idle"
    S.request_start_time = nil
    if fire_reason ~= "call_cap_exceeded" then
      local fallback = "Typed-action fallback model request did not go through. "
        .. "Please resend the last message."
      Log.add_error((RA and RA.t and RA.t(
        "typed_actions.error.fallback_request_failed", nil, fallback))
          or fallback)
    end
    return false
  end
  S.scroll_to_bottom = true
  return true
end

function Net._try_typed_action_lua_fallback(reason_code, detail)
  if S.typed_action_lua_fallback_used then return false end
  S.typed_action_lua_fallback_used = true
  S.pending_typed_action_expected = false
  S.pending_typed_action_response_format = false
  S.pending_typed_action_profile = nil
  Probe.add_validator_retry(S.probe_turn, "typed_action_lua_fallback")

  Log.line("TYPED-ACTION-LUA-FALLBACK",
    "structured edit exhausted; requesting Lua fallback after "
    .. tostring(reason_code or "typed_action_failure")
    .. " (" .. tostring(detail or "") .. ")")

  local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
    .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: The structured "
    .. "typed-action plan failed after retries and cannot be used safely. "
    .. "Reason: " .. tostring(reason_code or "typed_action_failure")
    .. ". Details: " .. tostring(detail or "") .. ". Do NOT emit "
    .. "typed-action JSON, raw JSON, markdown prose-only output, or "
    .. "`reaassist-actions`. Write one complete runnable REAPER Lua script "
    .. "inside one ```lua code fence. The script must directly implement the "
    .. "original request, including every requested track, stock FX, send, "
    .. "routing level, pan, volume, mute, master-send state, and ordering. "
    .. "Use normal ReaScript APIs, check created FX/send results, and do not "
    .. "copy any prior bad JSON. Respond as if this is your FIRST reply -- "
    .. "do NOT apologize, do NOT mention a retry.)\n\n"
    .. "USER REQUEST:\n" .. (S.pending_orig_prompt or "")

  if #S.history > 0 and S.history[#S.history].role == "assistant" then
    S.history[#S.history] = nil
  end
  if #S.history > 0 and S.history[#S.history].role == "user" then
    S.history[#S.history] = nil
  end
  S.history[#S.history + 1] = { role = "user", content = history_content }

  if S.pending_display_idx
     and S.display_messages[S.pending_display_idx] then
    local dmsg = S.display_messages[S.pending_display_idx]
    local existing = dmsg.ctx_label or ""
    if not existing:find("typed_action_lua_fallback", 1, true) then
      dmsg.ctx_label = existing ~= ""
        and (existing .. " + typed_action_lua_fallback")
        or "typed_action_lua_fallback"
    end
  end

  if prefs.include_snapshot and not S.pending_answer_only_followup then
    S.pending_project  = CTX.resolve_pending_project()
    S.pending_snapshot = CTX.build_snapshot(S.pending_project,
      S.pending_jsfx_intent and { minimal_tracks = true } or nil)
  end

  S.status = "waiting"
  Net._ensure_request_start_time()
  Code.safe_write(tmp.out, "")
  local fired, fire_reason = Net.fire_curl(Net.build_body(Net.trimmed_history(),
    S.pending_snapshot, S.pending_attachments))
  if not fired then
    S.status = "idle"
    S.request_start_time = nil
    if fire_reason ~= "call_cap_exceeded" then
      Log.add_error((RA and RA.retry_failed and RA.retry_failed(
        "retry.reason.for_typed_action_lua_fallback",
        "for typed-action Lua fallback"))
        or "Auto-retry for typed-action Lua fallback did not go through. Please resend the last message.")
    end
    return false
  end
  S.scroll_to_bottom = true
  return true
end

function Net._restore_typed_action_escalation_model()
  local restore = S.typed_action_escalation_restore
  if type(restore) ~= "table" then return false end
  S.typed_action_escalation_restore = nil
  S.thinking_override_idx = restore.thinking_override_idx

  if not restore.provider_id or not restore.model_id then return false end

  local p = PROVIDERS.active() or {}
  local m = MODELS[prefs.model_idx] or MODELS[1] or {}
  if tostring(p.id or "") ~= tostring(restore.fallback_provider_id or "")
     or tostring(m.id or "") ~= tostring(restore.fallback_model_id or "") then
    Log.line("TYPED-ACTION-ESCALATION",
      "not restoring original model because active model changed from "
      .. tostring(restore.fallback_provider_id or "") .. "/"
      .. tostring(restore.fallback_model_id or "") .. " to "
      .. tostring(p.id or "") .. "/" .. tostring(m.id or ""))
    return false
  end

  local ok, reason = PROVIDERS.switch_to_model(restore.provider_id,
    restore.model_id)
  if not ok then
    Log.line("TYPED-ACTION-ESCALATION",
      "could not restore original model "
      .. tostring(restore.provider_id) .. "/" .. tostring(restore.model_id)
      .. ": " .. tostring(reason or "unknown"))
    return false
  end

  Log.line("TYPED-ACTION-ESCALATION",
    "restored original model after hidden fallback rescue: "
    .. tostring(restore.provider_id) .. "/" .. tostring(restore.model_id))
  return true
end

function Net._drop_pending_display_rows()
  local idx = tonumber(S.pending_display_idx)
  if not (idx and S.display_messages and S.display_messages[idx]) then return end
  for i = #S.display_messages, idx, -1 do
    tbl_remove(S.display_messages, i)
  end
  S.wrap_cache = {}
end

function Net._drop_pending_history_rows()
  if not (S.pending_orig_prompt and S.history and #S.history > 0) then return end
  local tail = S.history[#S.history]
  if tail and tail.role == "assistant" then
    local prev = S.history[#S.history - 1]
    if prev and prev.role == "user" then
      tbl_remove(S.history, #S.history)
      tbl_remove(S.history, #S.history)
      return
    end
  end
  if tail and tail.role == "user" then
    tbl_remove(S.history, #S.history)
  end
end

function Net.cancel_active_request(probe_reason)
  if S.turn_budget_confirmation and Net.cancel_turn_budget_confirmation then
    return Net.cancel_turn_budget_confirmation()
  end
  local active = S.status == "waiting"
    or S.curl_pid ~= nil
    or S.retry_scheduled == true
    or S.gemini_tier_pending == true
    or (deep_scan and deep_scan.active == true)
  if not active then return false, "not_active" end

  if deep_scan and deep_scan.active and CTX and CTX.cancel_deep_scan then
    pcall(CTX.cancel_deep_scan)
  end
  if Net.kill_curl then pcall(Net.kill_curl) end

  Net._drop_pending_display_rows()
  Net._drop_pending_history_rows()
  Net._restore_typed_action_escalation_model()

  S.curl_pid            = nil
  S.curl_os_pid         = nil
  S.send_time           = nil
  S.request_start_time  = nil
  S.status              = "idle"
  S.pending_display_idx = nil
  S.pending_code        = nil
  S.pending_orig_prompt = nil
  S.pending_typed_action_expected = false
  S.pending_typed_action_response_format = false
  S.pending_typed_action_profile = nil
  S.pending_answer_only_followup = nil
  S.pending_project     = nil
  S.pending_snapshot    = nil
  S.pending_attachments = nil
  S._fx_cache_events    = nil
  S.retry_scheduled     = false
  S.retry_fire_time     = nil
  S.retry_count         = 0
  S.retry_max           = CFG.MAX_RETRIES
  S.retry_saved_body    = nil
  S.retry_saved_provider_idx = nil
  S.retry_saved_model_idx    = nil
  S.retry_saved_thinking_idx = nil
  if Net._clear_turn_budget_confirmation then
    Net._clear_turn_budget_confirmation()
  end
  S.reset_turn_retries()
  S.scroll_to_bottom    = true

  if S.probe_turn then
    Probe.end_turn(S.probe_turn, probe_reason or "cancelled")
    S.probe_turn = nil
  end
  if Code and Code.safe_write and tmp and tmp.out then
    Code.safe_write(tmp.out, "")
  end
  return true
end

function Net._abort_runaway_turn(probe_reason)
  Net._restore_pending_user_history()
  Net._restore_typed_action_escalation_model()
  if Net._clear_turn_budget_confirmation then
    Net._clear_turn_budget_confirmation()
  end
  S.status               = "idle"
  S.pending_display_idx  = nil
  S.pending_orig_prompt  = nil
  S.pending_typed_action_expected = false
  S.pending_typed_action_response_format = false
  S.pending_typed_action_profile = nil
  S.pending_answer_only_followup = nil
  S.request_start_time   = nil
  S.retry_count          = 0
  S.retry_max            = CFG.MAX_RETRIES
  S.retry_scheduled      = false
  S.retry_saved_body     = nil
  S.retry_saved_provider_idx = nil
  S.retry_saved_model_idx    = nil
  S.retry_saved_thinking_idx = nil
  if S.probe_turn then
    Probe.end_turn(S.probe_turn, probe_reason or "call_cap")
  end
  return false, "call_cap_exceeded"
end

function Net._read_file_limited(path, cap)
  if not path or path == "" then return "", 0, false end
  local f = io.open(path, "rb")
  if not f then return "", 0, false end
  cap = cap or 4096
  local data = f:read(cap + 1) or ""
  local size = f:seek("end") or #data
  f:close()
  local truncated = #data > cap
  if truncated then data = data:sub(1, cap) end
  return data, size, truncated
end

function Net._debug_scrub(s)
  if not s or s == "" then return s end
  if type(Diag) == "table" and type(Diag.redact_log) == "function" then
    local ok, redacted = pcall(Diag.redact_log, s)
    if ok and type(redacted) == "string" then return redacted end
  end
  return Log.scrub_url_secrets(s)
end

function Net._debug_endpoint(p, endpoint)
  if not endpoint or endpoint == "" then return nil end
  if p and p.is_custom then return "(custom endpoint redacted)" end
  return Net._debug_scrub(endpoint)
end

function Net._curl_exit_meaning(code)
  local meanings = {
    [5]  = "could not resolve proxy",
    [6]  = "could not resolve host",
    [7]  = "failed to connect",
    [18] = "partial file / transfer closed early",
    [23] = "local write error",
    [28] = "operation timed out",
    [35] = "TLS/SSL connect error",
    [52] = "empty reply from server",
    [56] = "receive failure",
    [60] = "certificate verification failed",
    [77] = "certificate file problem",
    [92] = "HTTP/2 stream error",
  }
  return meanings[tonumber(code)] or "unmapped curl error"
end

function Net._curl_failure_debug(exit_code, detail, failure_kind)
  local dbg = {}
  if type(S.curl_debug) == "table" then
    for k, v in pairs(S.curl_debug) do dbg[k] = v end
  end
  dbg.failure_kind = failure_kind or "curl_exit"
  if exit_code ~= nil then
    dbg.exit_code = exit_code
    dbg.exit_meaning = Net._curl_exit_meaning(exit_code)
  end
  dbg.user_message = detail
  dbg.failed_at_utc = os.date("!%Y-%m-%dT%H:%M:%SZ")
  dbg.api_calls_this_turn = S.api_calls_this_turn
  dbg.retry_count = S.retry_count
  dbg.retry_max = S.retry_max
  dbg.gemini_tier_pending = S.gemini_tier_pending or nil
  dbg.key_test_pending = S.key_test_pending or nil
  if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
    local dmsg = S.display_messages[S.pending_display_idx]
    dbg.display_context = dmsg.ctx_label
    dbg.display_model = dmsg.model_label
    dbg.display_thinking = dmsg.thinking_label
  end

  local stderr, stderr_size, stderr_truncated =
    Net._read_file_limited(tmp.err, 4096)
  if stderr and stderr ~= "" then
    dbg.stderr = Net._debug_scrub(stderr)
    dbg.stderr_bytes = stderr_size
    dbg.stderr_truncated = stderr_truncated or nil
  else
    dbg.stderr_bytes = stderr_size or 0
  end

  local body_head, body_size, body_truncated =
    Net._read_file_limited(tmp.out, 2048)
  dbg.response_bytes = body_size or 0
  if body_head and body_head ~= "" then
    dbg.response_head = Net._debug_scrub(body_head)
    dbg.response_head_truncated = body_truncated or nil
  end
  return dbg
end

function Net._turn_call_budget(body, provider_idx, model_idx)
  local p = PROVIDERS[provider_idx] or PROVIDERS.active() or {}
  local m = p.models and p.models[model_idx]
  if not m and p == PROVIDERS.active() then
    m = MODELS[prefs.model_idx] or MODELS[1]
  end
  m = m or {}

  local input_tokens = math_max(1,
    Net.estimate_request_tokens_from_body(body))
  local output_tokens = tonumber(tostring(body or ""):match(
    '"max_completion_tokens"%s*:%s*(%d+)'))
    or tonumber(tostring(body or ""):match(
      '"maxOutputTokens"%s*:%s*(%d+)'))
    or tonumber(tostring(body or ""):match(
      '"max_tokens"%s*:%s*(%d+)'))
    or tonumber(m.max_output)
    or 16384
  output_tokens = math_max(1, math_floor(output_tokens))

  local next_tokens = input_tokens + output_tokens
  local next_cost = MODELS.calc_cost(m, input_tokens, 0, 0, output_tokens)
  local free_tier = p.id == "google" and S.gemini_paid_tier == false
  local is_billable = not free_tier and next_cost > 0
  local actual_cost = tonumber(S.turn_billable_actual_cost_usd) or 0
  local actual_tokens = tonumber(S.turn_actual_tokens) or 0
  return {
    provider = p,
    model = m,
    input_tokens = input_tokens,
    output_tokens = output_tokens,
    next_tokens = next_tokens,
    next_cost = next_cost,
    is_billable = is_billable,
    projected_cost = actual_cost + (is_billable and next_cost or 0),
    projected_tokens = actual_tokens + next_tokens,
    actual_cost = actual_cost,
    actual_tokens = actual_tokens,
  }
end

-- Worst-case single-call floor for the currently selected provider/model.
-- The per-turn cost/token guardrails project this same worst case: a normal
-- cloud chat request omits max_completion_tokens, so the projected output
-- falls back to the model's max_output ceiling (128,000 on GPT-5.x, generic
-- 16,384). A per-turn limit set below this floor stops every send before the
-- first request can land. UI and Screen Reader read this to warn up front.
-- Resolves the model the same way Net._turn_call_budget does.
function Net._turn_call_floor()
  local p = PROVIDERS[prefs.provider_idx] or PROVIDERS.active() or {}
  local m = p.models and p.models[prefs.model_idx]
  if not m and p == PROVIDERS.active() then
    m = MODELS[prefs.model_idx] or MODELS[1]
  end
  m = m or {}
  local input_allowance = 2000
  local output_tokens = math_max(1, math_floor(tonumber(m.max_output) or 16384))
  local cost = MODELS.calc_cost(m, input_allowance, 0, 0, output_tokens)
  local free_tier = p.id == "google" and S.gemini_paid_tier == false
  return {
    tokens = input_allowance + output_tokens,
    cost = cost,
    cost_limit_applies = not free_tier and cost > 0,
  }
end

function Net._record_turn_budget_usage(p, raw_tok_in, raw_tok_out,
                                       tok_in_read, tok_in_create)
  local input = tonumber(raw_tok_in) or 0
  local output = tonumber(raw_tok_out) or 0
  if input <= 0 and output <= 0 then return end
  S.turn_actual_tokens = (S.turn_actual_tokens or 0) + input + output
  if p and p.id == "google" and S.gemini_paid_tier == false then return end
  local model_idx = S.pending_model_idx or prefs.model_idx
  local m = p and p.models and p.models[model_idx]
    or MODELS[model_idx] or MODELS[1]
  local cache_read = tonumber(tok_in_read) or 0
  local cache_create = tonumber(tok_in_create) or 0
  local base = math_max(0, input - cache_read - cache_create)
  S.turn_billable_actual_cost_usd =
    (S.turn_billable_actual_cost_usd or 0)
    + MODELS.calc_cost(m, base, cache_read, cache_create, output)
end

-- Record provider-reported usage as soon as a successful response is parsed.
-- This must run before context/repair dispatch: those intermediate responses
-- can return early and fire another model call, but their tokens and cost still
-- belong to the visible exchange and the session total.
function Net._record_display_usage(p, raw_tok_in, raw_tok_out,
                                   tok_in_read, tok_in_create, stage)
  local input = tonumber(raw_tok_in) or 0
  local output = tonumber(raw_tok_out) or 0
  if input <= 0 and output <= 0 then return nil end
  local cache_read = tonumber(tok_in_read) or 0
  local cache_create = tonumber(tok_in_create) or 0
  local dmsg = S.pending_display_idx
    and S.display_messages[S.pending_display_idx] or nil

  if dmsg then
    dmsg.tok_in = (dmsg.tok_in or 0) + input
    dmsg.tok_out = (dmsg.tok_out or 0) + output
    dmsg.tok_cache_read = (dmsg.tok_cache_read or 0) + cache_read
    dmsg.tok_cache_create = (dmsg.tok_cache_create or 0) + cache_create
  end

  local model_idx = S.pending_model_idx or prefs.model_idx
  local m = p and p.models and p.models[model_idx]
    or MODELS[model_idx] or MODELS[1]
  local base = math_max(0, input - cache_read - cache_create)
  local this_cost = MODELS.calc_cost(
    m, base, cache_read, cache_create, output)
  local free_tier = p and p.id == "google" and S.gemini_paid_tier == false

  S.session_tok_in = S.session_tok_in + input
  S.session_tok_out = S.session_tok_out + output
  if not free_tier then
    S.session_cost = S.session_cost + this_cost
  end

  if dmsg then
    dmsg.cost = (dmsg.cost or 0) + this_cost
    if free_tier then dmsg.free_tier = true end
    if p and p.id == "google" then
      local gc = Net.gemini_cache_debug_state(
        stage or "response", S.gemini_cache_last_used == true, cache_read)
      local req_gc = S.gemini_cache_last_state
      if type(req_gc) == "table" then
        gc.request_status = req_gc.status
        gc.request_reason = req_gc.reason
        gc.request_used = req_gc.used == true
        gc.request_create_reason = req_gc.create_reason
      end
      dmsg.gemini_cache = gc
    end
  end
  return this_cost
end

function Net._turn_budget_error_extra(budget, matched_condition)
  budget = budget or {}
  local p = budget.provider or {}
  local m = budget.model or {}
  return {
    error_kind = "turn_spend_budget",
    error_debug = {
      failure_kind = "turn_spend_budget",
      source = "turn_spend_guardrail",
      matched_condition = matched_condition,
      provider_id = p.is_custom and "custom" or p.id,
      model_id = p.is_custom and "custom" or (m.id or m.name),
      projected_cost_usd = budget.projected_cost,
      projected_tokens = budget.projected_tokens,
      next_call_worst_case_cost_usd = budget.next_cost,
      next_call_worst_case_tokens = budget.next_tokens,
      turn_cost_limit_usd = prefs.turn_cost_limit_usd,
      turn_token_limit = prefs.turn_token_limit,
      model_calls_this_turn = S.model_calls_this_turn or 0,
      billable_model_calls_this_turn = S.billable_model_calls_this_turn or 0,
      transport_retries_this_turn = S.transport_retries_this_turn or 0,
      api_calls_this_turn = S.api_calls_this_turn or 0,
    },
  }
end

function Net._clear_turn_budget_confirmation()
  S.turn_budget_confirmation = nil
  S.open_turn_budget_confirmation = false
  S.turn_budget_confirm_focus_cancel = false
  S.turn_budget_override_once = false
end

function Net._queue_turn_budget_confirmation(body, opts, budget,
                                              matched_condition)
  local saved_opts
  if type(opts) == "table" then
    saved_opts = {}
    for key, value in pairs(opts) do saved_opts[key] = value end
  end
  S.turn_budget_confirmation = {
    body = body,
    opts = saved_opts,
    budget = budget,
    matched_condition = matched_condition,
  }
  S.open_turn_budget_confirmation = true
  S.turn_budget_confirm_focus_cancel = true
  S.status = "awaiting_confirmation"
  S.scroll_to_bottom = true
  return true, "turn_budget_confirmation"
end

function Net.continue_turn_budget_confirmation()
  local pending = S.turn_budget_confirmation
  if type(pending) ~= "table" or type(pending.body) ~= "string" then
    Net._clear_turn_budget_confirmation()
    return false, "no_turn_budget_confirmation"
  end
  S.turn_budget_confirmation = nil
  S.open_turn_budget_confirmation = false
  S.turn_budget_confirm_focus_cancel = false
  S.turn_budget_override_once = true
  S.status = "waiting"
  local fired, reason = Net.fire_curl(pending.body, pending.opts)
  if not fired then
    S.turn_budget_override_once = false
    if reason ~= "call_cap_exceeded" then
      Log.add_error(RA.t("net.turn_budget.continue_failed", nil,
        "The approved model request could not be started. Please try again."))
      Net._abort_runaway_turn("turn_budget_continue_failed")
    end
  end
  return fired, reason
end

function Net.cancel_turn_budget_confirmation()
  local pending = S.turn_budget_confirmation
  if type(pending) ~= "table" then
    Net._clear_turn_budget_confirmation()
    return false, "no_turn_budget_confirmation"
  end
  local budget = pending.budget or {}
  local matched = pending.matched_condition or "projected_token_limit"
  -- Clear the deferred body before logging or aborting so no later UI or
  -- accessibility action can accidentally resume a cancelled request.
  Net._clear_turn_budget_confirmation()
  Net._turn_budget_stop(budget, matched)
  return true, "turn_budget_cancelled"
end

function Net._turn_budget_stop(budget, matched_condition)
  local cost_limit = tonumber(prefs.turn_cost_limit_usd)
    or CFG.TURN_COST_LIMIT_DEFAULT
  local token_limit = tonumber(prefs.turn_token_limit)
    or CFG.TURN_TOKEN_LIMIT_DEFAULT
  local message
  if matched_condition == "projected_token_limit" then
    local projected = UI and UI.format_number and UI.format_number(budget.projected_tokens)
      or tostring(math_floor(budget.projected_tokens or 0))
    local limit_str = UI and UI.format_number and UI.format_number(token_limit)
      or tostring(math_floor(token_limit))
    message = RA.t("net.turn_budget.token_stop",
      { projected = projected, limit = limit_str },
      str_format(
        "Stopped before another model request. Its worst-case token allowance would put this turn at about %s tokens, above your %s-token limit.\n\nRaise the per-turn token limit in Settings > Advanced, shorten the request, or start a new chat.",
        projected, limit_str))
  else
    local projected = MODELS.format_cost(budget.projected_cost or 0)
    local limit_str = MODELS.format_cost(cost_limit)
    message = RA.t("net.turn_budget.cost_stop",
      { projected = projected, limit = limit_str },
      str_format(
        "Stopped before another billable model request. Its estimated worst case would put this turn at about %s, above your %s per-turn limit.\n\nRaise the dollar limit in Settings > Advanced, choose a less expensive model, or start a new chat.",
        projected, limit_str))
  end
  Log.add_error(message, nil, nil, nil,
    Net._turn_budget_error_extra(budget, matched_condition))
  return Net._abort_runaway_turn("turn_budget")
end

function Net._preflight_turn_budget(body, provider_idx, model_idx,
                                    is_transport_retry)
  if is_transport_retry then return true, { transport_retry = true } end
  local budget = Net._turn_call_budget(body, provider_idx, model_idx)
  S.turn_estimated_next_cost_usd = budget.next_cost
  S.turn_estimated_next_tokens = budget.next_tokens
  if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
    local dmsg = S.display_messages[S.pending_display_idx]
    dmsg.next_call_worst_case_cost = budget.next_cost
    dmsg.next_call_worst_case_tokens = budget.next_tokens
  end
  if budget.projected_tokens > (tonumber(prefs.turn_token_limit)
      or CFG.TURN_TOKEN_LIMIT_DEFAULT) then
    return false, budget, "projected_token_limit"
  end
  if budget.is_billable
     and budget.projected_cost > (tonumber(prefs.turn_cost_limit_usd)
       or CFG.TURN_COST_LIMIT_DEFAULT) then
    return false, budget, "projected_cost_limit"
  end
  return true, budget
end

function Net.fire_curl(body, opts)
  -- TCP/TLS handshake timeout (seconds). Default 10 for cloud providers;
  -- per-record override for customs set below.
  local connect_timeout = 10
  -- Guard against double-send. Return a reason so callers can distinguish
  -- "another request in flight" (transient, deferrable) from genuine
  -- failures like disk/IO errors. Plain `if not fire_curl()` callers stay
  -- compatible -- the second return value is ignored unless inspected.
  if S.kill_pending then
    Net.try_finish_kill_pending()
    if S.kill_pending then return false, "kill_pending" end
  end
  if S.curl_pid then return false, "in_flight" end

  local method   = (opts and opts.method) or "POST"
  local is_get   = (method == "GET")
  local launch_provider_idx = (opts and opts.provider_idx) or prefs.provider_idx
  local launch_model_idx    = (opts and opts.model_idx) or prefs.model_idx
  local launch_thinking_idx = (opts and opts.thinking_idx) or prefs.thinking_idx
  local is_transport_retry  = opts and opts.transport_retry == true

  -- A "turn POST" is a POST tied to the user's currently-pending display
  -- message: the initial send and every silent retry / context fetch /
  -- beta-fallback that fires before the turn settles. NOT a turn POST:
  -- GETs (auth probes, /v1/models scans), and the Settings-page POSTs
  -- from Net.fire_key_test / Net.fire_gemini_tier_test, which don't have
  -- a pending display message attached. The per-turn cap and per-message
  -- counter both gate on this same predicate so they stay in sync.
  local is_turn_post = not is_get
                       and S.pending_orig_prompt ~= nil
                       and S.pending_display_idx
                       and S.display_messages[S.pending_display_idx] ~= nil

  -- Validator/repair retry sub-cap. Individual retry vectors still have
  -- their own small counters; this aggregate guard catches a turn that keeps
  -- tripping different validators before it reaches the broader POST cap.
  if is_turn_post
     and (S.validator_retries_this_turn or 0)
         > (CFG.MAX_VALIDATOR_RETRIES_PER_TURN or 3) then
    Log.add_error(Net._validator_retry_cap_message(), nil, nil, nil,
      Net._validator_retry_cap_error_extra())
    return Net._abort_runaway_turn("validator_retry_cap")
  end

  -- Per-turn call cap. Catches runaway loops (small / local model
  -- thrashing on context_needed or validator retries) before they rack
  -- up real cost. Aborts the turn cleanly: logs ONE user-visible error,
  -- restores the user's history entry from any internal retry note,
  -- ends the Probe turn, and returns a distinct reason so the 13 retry
  -- call sites can suppress their generic "did not go through" message.
  if is_turn_post
     and (S.api_calls_this_turn or 0) >= CFG.MAX_CALLS_PER_TURN then
    Log.add_error(Net._call_cap_message(), nil, nil, nil,
      Net._call_cap_error_extra())
    return Net._abort_runaway_turn("call_cap")
  end

  local budget
  if is_turn_post then
    local allowed, matched_condition
    allowed, budget, matched_condition = Net._preflight_turn_budget(body,
      launch_provider_idx, launch_model_idx, is_transport_retry)
    if S.turn_budget_override_once == true then
      -- Consent applies to this exact launch only. Consume it before any I/O
      -- so a failed start cannot silently carry approval into another call.
      S.turn_budget_override_once = false
    elseif not allowed then
      return Net._queue_turn_budget_confirmation(body, opts, budget,
        matched_condition)
    end
  end

  -- Per-message API-call counter. Incremented for every POST that's tied
  -- to the user's pending display message: the initial send AND any
  -- silent retries (docs-gate auto-fetch, beta-header fallback, cache-
  -- expired refresh, fx-inspect intra-turn fetches). Surfaced in the
  -- Details box so the user can see when an "invisible" retry added work.
  -- Tokens/cache/cost accumulate from every successful response that reports
  -- usage, while time spans the full turn. GET is a probe (auth check,
  -- /v1/models scan) and never a user-message API call, so it stays out of
  -- the count.
  if is_turn_post then
    local dmsg = S.display_messages[S.pending_display_idx]
    dmsg.api_calls = (dmsg.api_calls or 0) + 1
    S.api_calls_this_turn = (S.api_calls_this_turn or 0) + 1
    if is_transport_retry then
      dmsg.transport_retries = (dmsg.transport_retries or 0) + 1
      S.transport_retries_this_turn =
        (S.transport_retries_this_turn or 0) + 1
    else
      dmsg.model_calls = (dmsg.model_calls or 0) + 1
      S.model_calls_this_turn = (S.model_calls_this_turn or 0) + 1
      if budget and budget.is_billable then
        dmsg.billable_model_calls = (dmsg.billable_model_calls or 0) + 1
        S.billable_model_calls_this_turn =
          (S.billable_model_calls_this_turn or 0) + 1
      end
    end
    if S.probe_turn then
      S.probe_turn.posts_fired = (S.probe_turn.posts_fired or 0) + 1
    end
  end

  if not is_get then
    if not Code.safe_write(tmp.body, body) then return false, "io_error" end
  end

  local p = PROVIDERS[launch_provider_idx] or PROVIDERS.active()
  launch_provider_idx = PROVIDERS[launch_provider_idx] and launch_provider_idx
    or prefs.provider_idx
  if not (p and p.models and p.models[launch_model_idx]) then
    if p == PROVIDERS.active() and p and p.models and p.models[prefs.model_idx] then
      launch_model_idx = prefs.model_idx
    else
      launch_model_idx = 1
    end
  end
  local active_model = (p and p.models and p.models[launch_model_idx])
    or (p == PROVIDERS.active() and (MODELS[prefs.model_idx] or MODELS[1]))
    or {}

  Log.request(p.label, is_get and ("[GET " .. (opts.endpoint_override or "?") .. "]") or body)

  -- Local LLMs (custom OpenAI-compatible endpoints) need a much longer timeout
  -- than cloud providers: prompt processing alone for a 15K-token context can
  -- take 1-2 minutes on consumer hardware before any tokens stream back. Cloud
  -- providers use the high curl hard ceiling in CFG.CURL_TIMEOUT; the
  -- user-facing timeout is the watchdog driven by prefs.cloud_request_timeout
  -- and the Extend button.
  -- Custom providers expose a user-configurable per-provider timeout (set on
  -- the API Keys page); fall back to the 10-minute default if missing.
  local curl_timeout = (p.is_custom and (tonumber(p.request_timeout) or 600))
                       or CFG.CURL_TIMEOUT

  -- Custom-provider TCP/TLS handshake override. Cloud providers keep the
  -- fixed 10s default because every hosted endpoint is consistently reachable
  -- in under a second; customs can be behind slow CDNs or local servers that
  -- need more breathing room, so we expose a per-record knob.
  if p.is_custom and tonumber(p.connect_timeout) then
    connect_timeout = tonumber(p.connect_timeout)
  end

  -- Key-test override for custom providers. The curl --max-time is capped to
  -- the user-configured "Connection test timeout" (default 30s). Prevents a
  -- stalled/unresponsive model from blocking the row-test queue for the full
  -- request timeout (up to 1 hour). Also shortens the connect-timeout so a
  -- test against a dead port fails quickly instead of waiting the full
  -- per-provider handshake budget.
  if S.key_test_pending and p.is_custom then
    curl_timeout    = tonumber(S.key_test_custom_timeout)
                      or CUSTOM_DEFAULT_TEST_TIMEOUT
    connect_timeout = 3
  end

  -- --insecure: skip TLS verification when the custom provider has it set.
  -- Only ever applied to custom providers (cloud providers always validate).
  -- Emitted as a standalone flag in both Windows and POSIX branches below.
  local insecure_flag = (p.is_custom and p.allow_insecure) and " --insecure" or ""

  -- Build the endpoint URL.
  local endpoint
  if opts and opts.endpoint_override then
    endpoint = opts.endpoint_override
  elseif p.endpoint_tpl then
    endpoint = str_format(p.endpoint_tpl,
      active_model.id or MODELS.active_id())
  else
    endpoint = p.endpoint
  end
  S.curl_debug = {
    launched_at_utc = os.date("!%Y-%m-%dT%H:%M:%SZ"),
    method = method,
    provider_id = p.id,
    provider_label = p.label,
    model_id = active_model.id or MODELS.active_id(),
    model_label = active_model.label,
    endpoint = Net._debug_endpoint(p, endpoint),
    connect_timeout_s = connect_timeout,
    curl_timeout_s = curl_timeout,
    request_body_bytes = (not is_get and type(body) == "string") and #body or 0,
    is_turn_post = is_turn_post and true or false,
    provider_idx = launch_provider_idx,
    model_idx = launch_model_idx,
  }
  -- Write the auth header file (header-based auth only). Custom providers may
  -- have no key at all -- in that case skip the auth file so we don't send a
  -- bare "Authorization: Bearer " header that some servers reject.
  local api_key = (S.api_key_map and S.api_key_map[p.id])
    or (p == PROVIDERS.active() and S.api_key) or nil
  local use_auth_file = (p.auth_style == "header")
    and api_key ~= nil and api_key ~= ""
  if use_auth_file then
    local auth_value = (p.auth_prefix or "") .. api_key
    if not Code.safe_write(tmp.auth, p.auth_header .. ": " .. auth_value) then return false, "io_error" end
  end

  -- Clear any stale exit code / pid / response file from a previous request.
  -- The pid file is rewritten by the launched process; clearing first ensures
  -- Net.kill_curl never sees a stale PID from a finished request. tmp.out
  -- MUST also be cleared -- Net.try_finish_curl reads it every poll tick and
  -- only short-circuits on empty (<2 bytes); leaving the previous response's
  -- bytes in place makes the poller latch onto the prior response (which
  -- will even JSON-parse) before the new curl has had a chance to overwrite
  -- it, producing a stale instant "response".
  os.remove(tmp.exit)
  os.remove(tmp.err)
  os.remove(tmp.pid)
  Code.safe_write(tmp.out, "")
  Code.safe_write(tmp.err, "")

  -- Build the list of extra header flags.
  local extra_h_parts = {}
  for _, h in ipairs(p.extra_headers or {}) do
    extra_h_parts[#extra_h_parts+1] = h
  end

  if RA.IS_WINDOWS then
    -- Escape paths for embedding inside PowerShell single-quoted strings.
    local function ps_escape(path) return path:gsub("'", "''") end

    -- Build header flags for cmd.exe (triple-quoted for PowerShell).
    local h_flags = ""
    if use_auth_file then
      h_flags = h_flags .. ' -H @"""' .. tmp.auth .. '"""'
    end
    for _, h in ipairs(extra_h_parts) do
      h_flags = h_flags .. ' -H """' .. h .. '"""'
    end
    if not is_get then
      h_flags = h_flags .. ' -H """content-type: application/json"""'
    end

    -- Cleanup: delete auth file only if we wrote one.
    local cleanup = use_auth_file
      and (' & del """' .. tmp.auth .. '"""') or ""

    local body_flags = is_get and ""
      or (' -d @"""' .. tmp.body .. '"""')
    local cmd_line = str_format(
      'curl -sS%s --connect-timeout %d --max-time %d'
      .. ' -X %s """%s"""'
      .. '%s'
      .. '%s -o """%s""" 2> """%s"""'
      .. ' & call echo ^%%errorlevel^%% > """%s"""'
      .. '%s',
      insecure_flag,
      connect_timeout, curl_timeout,
      method, endpoint,
      h_flags,
      body_flags, tmp.out, tmp.err,
      tmp.exit,
      cleanup)

    -- Use Start-Process -PassThru so PowerShell hands us back the launched
    -- cmd.exe process object. We persist its PID to tmp.pid so Net.kill_curl
    -- can later run `taskkill /F /T /PID <pid>` to terminate the entire
    -- cmd+curl process tree on Cancel.
    local ps_cmd = str_format(
      'powershell -NoProfile -WindowStyle Hidden'
      .. ' -Command "$p = Start-Process cmd -ArgumentList \'/c %s\''
      .. ' -WindowStyle Hidden -PassThru;'
      .. ' $p.Id | Out-File -Encoding ASCII -FilePath \'%s\'"',
      ps_escape(cmd_line), ps_escape(tmp.pid))
    reaper.ExecProcess(ps_cmd, 5000)
  else
    -- macOS / Linux: launch curl in the background via shell.
    local function sq(path)
      return "'" .. path:gsub("'", "'\\''") .. "'"
    end

    -- Build header flags for shell. Each header is wrapped with sq() so
    -- $VAR, backticks, "\", and " in a custom provider header are treated
    -- as literal bytes by the shell rather than expanded or parsed. The
    -- header_is_safe() validator already rejects newlines and nulls; sq()
    -- handles every other shell-meaningful character.
    local h_flags = ""
    if use_auth_file then
      h_flags = h_flags .. ' -H @' .. sq(tmp.auth)
    end
    for _, h in ipairs(extra_h_parts) do
      h_flags = h_flags .. ' -H ' .. sq(h)
    end
    if not is_get then
      h_flags = h_flags .. ' -H ' .. sq("content-type: application/json")
    end

    local cleanup = use_auth_file
      and (' ; rm -f ' .. sq(tmp.auth)) or ""

    local body_flags = is_get and "" or (' -d @' .. sq(tmp.body))

    -- Wrap entire pipeline in a subshell so & backgrounds curl+echo together.
    -- Background curl inside the subshell so we can capture its PID via $!,
    -- write it to tmp.pid (so Net.kill_curl can `kill -9 <pid>` on Cancel),
    -- then `wait` for curl and record its real exit code in tmp.exit.
    local unix_curl = str_format(
      '(curl -sS%s --connect-timeout %d --max-time %d'
      .. ' -X %s %s'
      .. '%s'
      .. '%s -o %s 2> %s & CURL_PID=$! ; echo $CURL_PID > %s ; wait $CURL_PID ; echo $? > %s%s) &',
      insecure_flag,
      connect_timeout, curl_timeout,
      method, sq(endpoint),
      h_flags,
      body_flags, sq(tmp.out), sq(tmp.err),
      sq(tmp.pid),
      sq(tmp.exit),
      cleanup)
    os.execute(unix_curl)
  end

  S.curl_pid              = true
  S.curl_exited_clean     = false  -- reset partial-read guard for new request
  S.kill_pending          = false  -- a fresh request voids any stale Cancel watchdog
  S.send_time             = time_precise()
  S.timeout_extensions    = 0      -- watchdog clock just restarted; prior
                                   -- "Extend by Ns" clicks no longer apply
  S.retry_saved_body      = body  -- saved so a 529/overload retry can re-send
  S.retry_saved_provider_idx = launch_provider_idx
  S.retry_saved_model_idx    = launch_model_idx
  S.retry_saved_thinking_idx = launch_thinking_idx
  S.pending_provider_idx  = launch_provider_idx  -- snapshot for response parsing
  S.pending_model_idx     = launch_model_idx
  S.pending_thinking_idx  = launch_thinking_idx
  -- Probe timing: curl_wait phase begins here. The curl
  -- process is now running; we are waiting for its response. The
  -- corresponding mark_phase_end fires inside Net.try_finish_curl
  -- just before JSON.decode parses the response body. This wraps
  -- every fire_curl success path, so multi-request turns
  -- (context-needed re-fires, validator retries) accumulate
  -- correctly via mark_phase_end's additive timing.
  Probe.mark_phase_start(S.probe_turn, "curl_wait")
  return true
end

function Net.build_body_for_launch(msgs, snapshot, msg_attachments,
                                   provider_idx, model_idx, thinking_idx)
  local saved_provider_idx = prefs.provider_idx
  local saved_model_idx    = prefs.model_idx
  local saved_thinking_idx = prefs.thinking_idx
  local saved_api_key      = S.api_key
  local launch_provider = PROVIDERS[provider_idx]
  if not launch_provider then return nil, nil, "provider_unavailable" end

  local function restore_selection()
    prefs.provider_idx = saved_provider_idx
    MODELS.refresh()
    if MODELS[saved_model_idx] then prefs.model_idx = saved_model_idx end
    prefs.thinking_idx = saved_thinking_idx
    S.api_key = saved_api_key
  end

  prefs.provider_idx = provider_idx
  MODELS.refresh()
  if launch_provider.models and launch_provider.models[model_idx] then
    prefs.model_idx = model_idx
  else
    prefs.model_idx = 1
  end
  local launch_model = MODELS[prefs.model_idx] or launch_provider.models[1]
  if launch_provider.thinking_levels then
    prefs.thinking_idx = thinking_idx
      or PROVIDERS.load_thinking_idx(launch_provider, launch_model)
  else
    prefs.thinking_idx = 0
  end
  S.api_key = S.api_key_map[launch_provider.id]

  local ok, body = pcall(Net.build_body, msgs, snapshot, msg_attachments)
  local actual_model_idx = prefs.model_idx
  local actual_thinking_idx = prefs.thinking_idx
  restore_selection()
  if not ok then error(body) end
  return body, {
    provider_idx = provider_idx,
    model_idx = actual_model_idx,
    thinking_idx = actual_thinking_idx,
  }
end

function Net.fire_pending_retry(msgs, snapshot, msg_attachments)
  local provider_idx = S.pending_provider_idx or prefs.provider_idx
  local model_idx    = S.pending_model_idx or prefs.model_idx
  local thinking_idx = S.pending_thinking_idx or prefs.thinking_idx
  local body, opts, reason = Net.build_body_for_launch(msgs, snapshot,
    msg_attachments, provider_idx, model_idx, thinking_idx)
  if not body then return false, reason or "body_build_failed" end
  return Net.fire_curl(body, opts)
end

function Net.fire_validator_retry(opts)
  opts = type(opts) == "table" and opts or {}
  if opts.kind then Probe.add_validator_retry(S.probe_turn, opts.kind) end
  if opts.log_tag and opts.log_message then
    Log.line(opts.log_tag, opts.log_message)
  end
  if #S.history > 0 and S.history[#S.history].role == "assistant" then
    S.history[#S.history] = nil
  end
  if #S.history > 0 and S.history[#S.history].role == "user" then
    S.history[#S.history] = nil
  end
  S.history[#S.history + 1] = {
    role = "user",
    content = tostring(opts.history_content or ""),
  }
  local label = tostring(opts.ctx_label or "")
  if label ~= "" and S.pending_display_idx
     and S.display_messages[S.pending_display_idx] then
    local dmsg = S.display_messages[S.pending_display_idx]
    local existing = dmsg.ctx_label or ""
    if not existing:find(label, 1, true) then
      dmsg.ctx_label = existing ~= "" and (existing .. " + " .. label) or label
    end
  end
  if opts.rebuild_snapshot ~= false
     and prefs.include_snapshot
     and not S.pending_answer_only_followup then
    S.pending_project  = CTX.resolve_pending_project()
    S.pending_snapshot = CTX.build_snapshot(S.pending_project,
      S.pending_jsfx_intent and { minimal_tracks = true } or nil)
  end
  S.status = "waiting"
  Net._ensure_request_start_time()
  Code.safe_write(tmp.out, "")
  local ok, reason = Net.fire_pending_retry(Net.trimmed_history(),
    S.pending_snapshot, S.pending_attachments)
  if not ok and reason ~= "call_cap_exceeded" then
    local msg
    if opts.retry_failed_key and RA and RA.retry_failed then
      msg = RA.retry_failed(opts.retry_failed_key,
        opts.retry_failed_label or opts.ctx_label or opts.kind or "validator retry")
    end
    Log.add_error(msg or opts.failure_message
      or "Auto-retry did not go through. Please resend the last message.")
  end
  S.scroll_to_bottom = true
  return ok, reason
end

-- =============================================================================
-- Net.kill_curl
-- =============================================================================
-- Forcibly terminates the in-flight curl request launched by Net.fire_curl.
-- Reads the OS PID written to tmp.pid by the launcher and runs the platform's
-- kill command. Without this, pressing Cancel only resets ReaAssist's state --
-- the underlying curl process keeps running, holding bandwidth and possibly
-- writing a stale response into tmp.out that contaminates the next request.
--
-- Windows: PowerShell wrote cmd.exe's PID; taskkill /T tears down the entire
-- cmd+curl process tree.
-- Unix: the shell wrapper wrote curl's PID directly; kill -9 ends it, which
-- causes the parent subshell's `wait` to return non-zero into tmp.exit.
function Net.kill_curl()
  -- Tier-test path doesn't capture a PID (no Start-Process -PassThru / $!),
  -- so there is no process to kill. The tier-test curl runs to completion
  -- under its own --connect-timeout 10 / --max-time 30 budget. Bail early
  -- and clear the tier flag so the post-Cancel state stays consistent.
  if S.gemini_tier_pending then
    Log.line("CANCEL", "tier test in flight; nothing to kill (no PID captured)")
    S.gemini_tier_pending = false
    return
  end
  local f = io.open(tmp.pid, "r")
  if not f then
    -- The launcher (PowerShell on Windows, sh on Unix) hasn't written the pid
    -- file yet -- there is a several-hundred-ms gap between Start-Process and
    -- Out-File on Windows in particular. Arm the deferred-kill watchdog so
    -- the main loop keeps retrying until either the pid file shows up or the
    -- deadline elapses; without this, a rapid Send -> Cancel leaves the
    -- background curl alive holding bandwidth and writing into tmp.out.
    S.kill_pending       = true
    S.kill_pending_until = reaper.time_precise() + 2.0
    return
  end
  local pid_text = f:read("*a") or ""
  f:close()
  local pid = pid_text:match("(%d+)")
  if not pid then
    -- File exists but is still mid-write (very rare but possible). Same fix.
    S.kill_pending       = true
    S.kill_pending_until = reaper.time_precise() + 2.0
    return
  end
  if RA.IS_WINDOWS then
    -- /F = force, /T = include child process tree.
    reaper.ExecProcess('cmd /c taskkill /F /T /PID ' .. pid, 2000)
  else
    reaper.ExecProcess('/bin/sh -c "kill -9 ' .. pid .. ' 2>/dev/null"', 2000)
  end
  -- Remove the pid file so a stray Cancel after this call doesn't try to kill
  -- a now-finished or PID-recycled process.
  os.remove(tmp.pid)
  S.kill_pending = false
end

-- =============================================================================
-- Net.try_finish_kill_pending
-- =============================================================================
-- Polled from the main loop while S.kill_pending is true. Re-attempts kill_curl
-- once the pid file lands (or until the deadline elapses, after which we give
-- up to avoid burning CPU forever on a request whose launcher silently failed).
function Net.try_finish_kill_pending()
  if not S.kill_pending then return end
  if reaper.time_precise() > S.kill_pending_until then
    S.kill_pending = false
    return
  end
  local f = io.open(tmp.pid, "r")
  if not f then return end
  f:close()
  -- pid file now exists -- re-enter kill_curl which will read and act on it.
  Net.kill_curl()
end

-- =============================================================================
-- Net.custom_models_url
-- =============================================================================
-- Derive an OpenAI-compatible `GET /v1/models` URL from a chat/completions
-- endpoint. Covers the common shapes emitted by LM Studio, Ollama, llama.cpp,
-- vLLM, and OpenRouter. Falls back to appending /v1/models to the host if the
-- input URL is unrecognized.
function Net.custom_models_url(endpoint)
  if type(endpoint) ~= "string" or endpoint == "" then return nil end
  -- Require an http(s):// scheme. The form validator catches this at user-
  -- input time, but defending here too means a saved-but-corrupt config
  -- can't accidentally produce a curl-wrong URL.
  if not endpoint:match("^https?://") then return nil end
  -- Strip trailing slash.
  local url = endpoint:gsub("/+$", "")
  -- Most common: ".../v1/chat/completions" -> ".../v1/models"
  local base = url:match("^(.-)/chat/completions$")
  if base then return base .. "/models" end
  -- Already a models URL.
  if url:match("/models$") then return url end
  -- URL ends at /v1 (no suffix): append /models.
  if url:match("/v1$") then return url .. "/models" end
  -- Bare-host fallback: append /v1/models ONLY when the input has no path.
  -- Strict anchor (^scheme://host$) so that a deliberately-typed-but-wrong
  -- path like ".../v3fffs" is NOT silently rewritten to ".../v1/models" --
  -- the test would otherwise report success against the canonical path
  -- the user didn't ask for. The earlier permissive prefix match was too
  -- eager. Returning nil here causes Net.fire_key_test to surface
  -- "Could not derive a /v1/models URL from the endpoint." so the user
  -- knows their endpoint shape isn't recognised.
  local host_only = url:match("^(https?://[^/]+)$")
  if host_only then return host_only .. "/v1/models" end
  return nil
end

-- =============================================================================
-- Net.fire_key_test
-- =============================================================================
-- Sends a minimal API request to validate the key. Cloud providers get a
-- 1-token chat/completions POST (cost negligible). Custom OpenAI-compatible
-- providers instead get a GET /v1/models request so no inference runs on the
-- server -- critical for reasoning models where `max_completion_tokens=1`
-- only caps output tokens, not the full thinking pass.
-- On completion, Net.try_finish_curl detects S.key_test_pending and routes to
-- Net.handle_key_test instead of the normal response flow.
-- provider_override: optional provider table to test (for multi-key intro screen).
function Net.fire_key_test(provider_override)
  local p = provider_override or PROVIDERS.active()
  -- Build a minimal test request. Cloud providers use a 1-token chat POST;
  -- custom providers use a GET /v1/models call (no inference -> no reasoning
  -- cost, no model load, instant response).
  local body
  local curl_opts = nil
  if p.is_custom then
    if p.use_inference_test then
      -- Opt-in real-inference test (Test Connection checkbox). Sends a
      -- 1-token chat/completions POST against the user's first model id
      -- (with model_prefix applied) -- exercises the same code path real
      -- chat will, at the cost of one short inference call. Default-off
      -- per the custom-LLM page UX since reasoning models would still
      -- run a full thinking pass on max_completion_tokens=1.
      --
      -- Mirrors Net.build_body_openai's custom path on two load-bearing
      -- points: (1) max_completion_tokens (the field newer OpenAI-
      -- compatibles expect; max_tokens diverges and could fail on a
      -- working provider); (2) the merged provider-wide + per-model
      -- extra_body via Net.merge_custom_extra_body so vendor toggles
      -- (Kimi thinking flag, Qwen enable_thinking, OpenRouter reasoning)
      -- get tested too -- without it, a provider that requires a toggle
      -- could pass the probe and fail under real chat. System prompt /
      -- prompt_cache_key / reasoning_effort are deliberately NOT included
      -- to keep the probe cheap (input-token cost stays minimal).
      local model_id = (p.models and p.models[1] and p.models[1].id) or ""
      if p.model_prefix and p.model_prefix ~= "" then
        model_id = p.model_prefix .. model_id
      end
      local extra_suffix = Net.merge_custom_extra_body(p,
        p.models and p.models[1] or nil)
      body = str_format(
        '{"model":"%s","max_completion_tokens":1,"messages":[{"role":"user","content":"hi"}]%s}',
        model_id, extra_suffix)
      -- curl_opts stays nil -> default POST to p.endpoint.
    else
      -- Default safe path: GET /v1/models. No inference, no cost,
      -- instant response.
      local url = Net.custom_models_url(p.endpoint)
      if not url then
        S.key_test_pending  = false
        S.key_test_provider = nil
        S.status            = "error"
        if api_keys.custom_conn_test and api_keys.custom_conn_test.active
           and api_keys.screen == "custom_llm" then
          CTX.custom_conn_test_advance(false,
            "Could not derive a /v1/models URL from the endpoint.")
          return
        end
        return
      end
      body      = nil
      curl_opts = { method = "GET", endpoint_override = url }
    end
  elseif p.id == "anthropic" then
    body = str_format(
      '{"model":"%s","max_tokens":1,"messages":[{"role":"user","content":"hi"}]}',
      p.models[1].id)
  elseif p.id == "openai" then
    body = str_format(
      '{"model":"%s","max_completion_tokens":1,"messages":[{"role":"user","content":"hi"}]}',
      p.models[1].id)
  elseif p.id == "deepseek" then
    -- DeepSeek speaks the OpenAI Chat Completions wire format but uses
    -- the older `max_tokens` cap field; their reference does not document
    -- `max_completion_tokens`, and an unknown-field cap is silently
    -- ignored (so the probe burns ~100+ output tokens of real generation
    -- on every key test instead of stopping at 1).
    body = str_format(
      '{"model":"%s","max_tokens":1,"messages":[{"role":"user","content":"hi"}]}',
      p.models[1].id)
  elseif p.id == "google" then
    body = '{"contents":[{"role":"user","parts":[{"text":"hi"}]}],"generationConfig":{"maxOutputTokens":1}}'
  end
  -- Defer if another curl is in flight (typically the auto-retest Gemini
  -- tier test that fires on startup). Without this guard, fire_curl's
  -- in_flight return would cascade through the queue, marking every
  -- provider as "Could not reach the X API. Check your internet connection"
  -- in seconds even though the actual problem is just timing. The loop
  -- handler below polls and re-fires once curl_pid clears, with a 30s
  -- ceiling so a stuck pending state doesn't trap the queue indefinitely.
  if S.curl_pid then
    S.key_test_armed = {
      provider = p,
      armed_at = time_precise(),
    }
    S.status = "waiting"
    return
  end
  S.key_test_pending  = true
  S.key_test_provider = p.id
  S.status            = "waiting"
  Code.safe_write(tmp.out, "")
  local fired, reason = Net.fire_curl(body, curl_opts)
  if not fired then
    S.key_test_pending  = false
    S.key_test_provider = nil
    S.status            = "error"
    local label = p.label
    -- "in_flight" should have been caught by the pre-check above; this
    -- branch covers the I/O-error reasons (disk full, AV lock on tmp.body
    -- / tmp.auth, etc.) and any future failure modes added to fire_curl.
    local in_flight = (reason == "in_flight")
    local short_msg, detail_msg, hint
    if in_flight then
      short_msg  = RA.t("settings.api_key.error.in_flight_short", nil,
        "Another request is in progress. Try again in a moment.")
      detail_msg = RA.t("settings.api_key.error.in_flight_detail",
        { provider = label },
        "Couldn't start the " .. label .. " key test -- another request is already in flight.")
      hint       = RA.t("settings.api_key.error.in_flight_hint", nil,
        "Wait a few seconds and click Test API Keys again.")
    else
      short_msg  = RA.t("settings.api_key.error.local_start_short",
        { provider = label },
        "Couldn't start the " .. label .. " key test (local error writing temp files).")
      detail_msg = RA.t("settings.api_key.error.local_start_detail",
        { provider = label },
        "Couldn't start the " .. label .. " key test. ReaAssist failed to write its temporary request files.")
      hint       = RA.t("settings.api_key.error.local_start_hint", nil,
        "Check that your REAPER Resources directory is writable and that no antivirus is locking files in it.")
    end
    -- Custom-LLM row-test mode: record failure and advance the queue.
    if api_keys.custom_conn_test and api_keys.custom_conn_test.active
       and api_keys.screen == "custom_llm" and p.is_custom then
      CTX.custom_conn_test_advance(false, short_msg)
      return
    end
    -- Multi-key test mode: record failure and advance queue.
    if #api_keys.test_queue > 0 and (api_keys.screen == "first_run" or api_keys.screen == "settings") then
      Net.advance_key_test_queue(p.id, false, short_msg)
      return
    end
    if (api_keys.screen == "first_run" or api_keys.screen == "settings") then
      api_keys.key_validating = false
      api_keys.key_error      = short_msg
      -- Show error popup.
      api_keys.show_key_error_popup = true
      api_keys.key_error_provider   = label
      api_keys.key_error_detail     = detail_msg
      api_keys.key_error_hint       = hint
      api_keys.key_error_url        = nil
      api_keys.key_error_url_label  = nil
    else
      -- Append rather than clobber: if the user somehow triggered a key test
      -- while a conversation was on screen, wiping S.display_messages would
      -- destroy their chat. Log.add_error is the shared append path.
      Log.add_error(short_msg)
    end
  end
end

-- =============================================================================
-- Net.is_auth_error
-- =============================================================================
-- Returns true if the parsed response represents an authentication error
-- for the given provider. Each provider has a different error envelope
-- format. `prov` is the full provider table (from PROVIDERS) so we can
-- dispatch on id for hosted providers and on is_custom for any of the
-- user-configured OpenAI-compatible endpoints.
function Net.is_auth_error(resp, prov)
  if type(resp) ~= "table" then return false end
  if prov.id == "anthropic" then
    return resp.type == "error"
      and type(resp.error) == "table" and resp.error ~= JSON.NULL
      and resp.error.type == "authentication_error"
  elseif prov.id == "openai" or prov.id == "deepseek" or prov.is_custom then
    -- Custom OpenAI-compatible servers usually pass errors through unchanged.
    -- DeepSeek follows the same envelope conventions.
    return type(resp.error) == "table" and resp.error ~= JSON.NULL
      and (resp.error.code == "invalid_api_key"
        or resp.error.type == "invalid_request_error"
           and type(resp.error.message) == "string"
           and resp.error.message:lower():find("api key"))
  elseif prov.id == "google" then
    return type(resp.error) == "table" and resp.error ~= JSON.NULL
      and (resp.error.status == "UNAUTHENTICATED"
        or resp.error.code == 401)
  end
  return false
end

-- =============================================================================
-- Net.advance_key_test_queue
-- =============================================================================
-- Records a result for the just-tested provider and fires the next test in
-- api_keys.test_queue. When the queue is exhausted, sets the flag to open the
-- results popup. Returns true if a next test was started, false if done.
function Net.advance_key_test_queue(prov_id, ok, error_msg)
  -- Record result.
  local p = PROVIDERS.get(prov_id)
  api_keys.test_results[prov_id] = {
    ok        = ok,
    label     = p and p.label or prov_id,
    error     = error_msg,
    url       = p and p.console_url or nil,
    url_label = p and p.console_label or nil,
  }
  if api_keys.key_warnings then
    local idx = PROVIDERS._by_id and PROVIDERS._by_id[prov_id]
    if idx then api_keys.key_warnings[idx] = nil end
  end
  -- Remove the completed entry from the front of the queue.
  if #api_keys.test_queue > 0 then
    table.remove(api_keys.test_queue, 1)
  end
  -- Fire next test if any remain.
  if #api_keys.test_queue > 0 then
    local nxt = api_keys.test_queue[1]
    api_keys.key_validating_idx = nxt.idx
    S.api_key = S.api_key_map[nxt.prov.id]
    prefs.provider_idx = nxt.idx
    MODELS.refresh()
    Code.safe_write(tmp.out, "")
    Net.fire_key_test(nxt.prov)
    return true
  end
  -- Queue exhausted: stop validating, restore active provider, show results.
  api_keys.key_validating     = false
  api_keys.key_validating_idx = nil
  api_keys.show_test_results  = true
  S.status = "idle"
  -- Restore the active-provider snapshot taken when the queue was kicked
  -- off (UI: Test API Keys click handler). Each queued provider had to
  -- temporarily own prefs.provider_idx so fire_key_test would target it;
  -- restoring here puts the user back on whichever provider they had
  -- selected before clicking Test, instead of leaving them parked on
  -- the last queue entry.
  if api_keys._test_orig_provider_idx then
    prefs.provider_idx = api_keys._test_orig_provider_idx
    api_keys._test_orig_provider_idx = nil
    MODELS.refresh()
  end
  -- Restore active provider key.
  S.api_key = S.api_key_map[PROVIDERS.active().id]
  Code.safe_write(tmp.out, "")

  -- If a Google key test succeeded in this queue, kick off tier detection so
  -- the free-tier warning fires via the Test API Keys button path too (the
  -- single-key Save path in fire_key_test already handles this; the queue
  -- path returns early before reaching it).
  local gres = api_keys.test_results and api_keys.test_results.google
  if gres and gres.ok and S.api_key_map.google then
    Store.set_gemini_paid_tier(nil)
    Net.fire_gemini_tier_test()
  end

  return false
end

-- =============================================================================
-- Net.handle_key_test
-- =============================================================================
-- Called by Net.try_finish_curl when S.key_test_pending is true. Checks whether the
-- validation request succeeded or returned an auth error, and shows the
-- appropriate message. Provider-aware: uses S.key_test_provider to identify
-- the provider being tested and its console URL.
function Net.handle_key_test(raw)
  S.key_test_pending = false
  local prov_id = S.key_test_provider or PROVIDERS.active().id
  local p       = PROVIDERS.get(prov_id) or PROVIDERS.active()
  S.key_test_provider = nil

  -- Parse the response using the JSON decoder.
  local resp = JSON.decode(raw)
  -- Custom (local LLM) test response check. Two shapes possible:
  --   * Default GET /v1/models path -- expect a `data` array.
  --   * Opt-in inference test (Test Connection checkbox) -- expect a
  --     chat/completions response with a `choices` array.
  -- Either way: must parse as JSON, must not carry a top-level error
  -- envelope. p.use_inference_test is set on the throwaway provider
  -- record by custom_conn_test_register when the user ticked the box.
  local custom_unreachable = false
  if p.is_custom then
    if type(resp) ~= "table" then
      custom_unreachable = true
    elseif type(resp.error) == "table" and resp.error ~= JSON.NULL then
      custom_unreachable = true
    elseif p.use_inference_test then
      if type(resp.choices) ~= "table" then
        custom_unreachable = true
      end
    elseif type(resp.data) ~= "table" then
      -- Server responded but the body isn't a /v1/models listing -> not
      -- OpenAI-compatible, or we hit the wrong route.
      custom_unreachable = true
    end
  end
  -- ---------- Custom-LLM connection test mode (Test Connection button) ------
  -- When the custom_conn_test is active, record pass/fail and finish.
  if api_keys.custom_conn_test and api_keys.custom_conn_test.active
     and api_keys.screen == "custom_llm" and p.is_custom then
    local err_msg = nil
    if custom_unreachable then
      local emsg = (type(resp) == "table" and type(resp.error) == "table"
                    and resp.error ~= JSON.NULL and type(resp.error.message) == "string")
                   and resp.error.message or nil
      local probe = p.use_inference_test and "/v1/chat/completions"
                                          or "/v1/models"
      err_msg = RA.t("settings.custom.error.endpoint_unexpected_probe",
        { probe = probe },
        "Endpoint reachable but " .. probe .. " returned an unexpected response.")
        .. (emsg and (" " .. RA.t("settings.api_key.error.server_said",
          { message = emsg }, "Server said: " .. emsg)) or "")
    elseif Net.is_auth_error(resp, p) then
      err_msg = RA.t("settings.api_key.error.auth_failed_short", nil,
        "Authentication failed.")
    end
    CTX.custom_conn_test_advance(err_msg == nil, err_msg)
    Code.safe_write(tmp.out, "")
    return
  end

  -- ---------- Multi-key test mode (Test API Keys button) ----------
  -- When the test queue is active, record pass/fail and advance to the next
  -- provider instead of performing the normal single-key flow.
  if #api_keys.test_queue > 0 and (api_keys.screen == "first_run" or api_keys.screen == "settings") then
    local err_msg = nil
    if custom_unreachable then
      local emsg = (type(resp) == "table" and type(resp.error) == "table"
                    and resp.error ~= JSON.NULL and type(resp.error.message) == "string")
                   and resp.error.message or nil
      err_msg = RA.t("settings.api_key.error.custom_models_unexpected", nil,
        "The endpoint responded but /v1/models returned an unexpected response.")
        .. (emsg and (" " .. RA.t("settings.api_key.error.server_said",
          { message = emsg }, "Server said: " .. emsg)) or "")
    elseif Net.is_auth_error(resp, p) then
      err_msg = RA.t("settings.api_key.error.auth_failed_short", nil,
        "Authentication failed. The key may have expired or been revoked.")
    end
    Net.advance_key_test_queue(p.id, err_msg == nil, err_msg)
    return
  end

  if custom_unreachable then
    S.status = "error"
    if (api_keys.screen == "first_run" or api_keys.screen == "settings") then
      api_keys.key_validating     = false
      api_keys.key_validating_idx = nil
      -- Same restore-on-failure pattern as the auth-error branch above.
      if api_keys._test_orig_provider_idx then
        local saved = api_keys._test_orig_provider_idx
        api_keys._test_orig_provider_idx = nil
        local saved_prov = PROVIDERS[saved]
        if saved_prov and Store.provider_has_usable_credentials(saved_prov) then
          prefs.provider_idx = saved
          MODELS.refresh()
          S.api_key = S.api_key_map and S.api_key_map[saved_prov.id] or nil
          if Store and Store.save_config then Store.save_config() end
        end
      end
      local emsg = (type(resp) == "table" and type(resp.error) == "table"
                    and resp.error ~= JSON.NULL and type(resp.error.message) == "string")
                   and resp.error.message or nil
      local detail = RA.t("settings.api_key.error.custom_model_test_failed", nil,
        "The endpoint responded but the model test failed.")
        .. (emsg and ("\n\n" .. RA.t("settings.api_key.error.server_said",
          { message = emsg }, "Server said: " .. emsg)) or "")
      -- Show error popup.
      api_keys.show_key_error_popup = true
      api_keys.key_error_provider   = p.label
        or RA.t("settings.api_key.provider.custom", nil, "Custom LLM")
      api_keys.key_error_detail     = detail
      api_keys.key_error_hint       =
        RA.t("settings.api_key.error.custom_connect_hint", nil,
          "Check that the server is running, the URL and port are correct, and the model identifier matches what the server expects.")
      api_keys.key_error_url        = nil
      api_keys.key_error_url_label  = nil
    end
    Code.safe_write(tmp.out, "")
    return
  end

  if Net.is_auth_error(resp, p) then
    -- Key is invalid: clear it and prompt again.
    S.api_key = nil
    S.api_key_map[p.id] = nil
    if p.key_extstate then Key.clear(p.key_extstate) end
    -- Restore the active-provider snapshot taken when the Save handler
    -- flipped to test this key. If the original provider still has a
    -- working key, put the user back there so a failed OpenAI key test
    -- doesn't strand them on a broken OpenAI configuration when they
    -- were happily on Claude before. If the snapshotted provider lost
    -- its key (e.g. user wiped Claude before pasting OpenAI), leave
    -- prefs.provider_idx alone -- restoring would also break.
    if api_keys._test_orig_provider_idx then
      local saved = api_keys._test_orig_provider_idx
      api_keys._test_orig_provider_idx = nil
      local saved_prov = PROVIDERS[saved]
      if saved_prov and Store.provider_has_usable_credentials(saved_prov) then
        prefs.provider_idx = saved
        MODELS.refresh()
        S.api_key = S.api_key_map and S.api_key_map[saved_prov.id] or nil
        if Store and Store.save_config then Store.save_config() end
      end
    end
    S.status = "error"
    if (api_keys.screen == "first_run" or api_keys.screen == "settings") then
      api_keys.key_validating = false
      local idx = PROVIDERS._by_id[p.id]
      if idx and api_keys.key_errors then
        api_keys.key_errors[idx] =
          RA.t("settings.api_key.error.didnt_work_short", nil,
            "That key didn't work. It may have expired or been entered incorrectly.")
      end
      if idx and api_keys.key_warnings then
        api_keys.key_warnings[idx] = nil
      end
      -- Clear the failed key out of the input buffer so the user can
      -- either paste a fresh key or just click Save and exit. Without
      -- this, the bad key stays in the field as password bullets and
      -- a no-edit Save would re-test (and re-fail) it.
      if idx and api_keys.key_bufs then
        api_keys.key_bufs[idx] = ""
      end
      api_keys.key_error = RA.t("settings.api_key.error.didnt_work_provider",
        { provider = p.label },
        "That " .. p.label .. " key didn't work. It may have expired or been entered incorrectly. Please paste a valid key and try again.")
      -- Show error popup.
      api_keys.show_key_error_popup = true
      api_keys.key_error_provider   = p.label
      api_keys.key_error_detail     = RA.t("settings.api_key.error.auth_detail",
        { provider = p.label },
        "The " .. p.label .. " API key failed authentication. The key may have expired, been revoked, or was entered incorrectly.")
      api_keys.key_error_hint       = RA.t("settings.api_key.error.auth_hint", nil,
        "Double-check the key for typos, or generate a new one at your provider's console.")
      api_keys.key_error_url        = p.console_url
      api_keys.key_error_url_label  = p.console_label
    else
      -- Append rather than clobber: preserves any conversation state that
      -- happens to be on screen when a key test triggers.
      Log.add_error(RA.t("settings.api_key.error.auth_chat",
        { provider = p.label },
        "That " .. p.label .. " key didn't work. It may have expired or been "
          .. "entered incorrectly.\n\nClick the Settings button to try again.\n\n"
          .. "You can find or create a key here:"),
        p.console_url, p.console_label)
    end
    return
  end

  -- If we got here, the key works (even a rate-limit means auth succeeded).
  -- Persist the tested key now that validation has confirmed it works. Custom
  -- providers may have no key at all -- skip the save in that case.
  if S.api_key and p.key_extstate then
    Key.save(S.api_key, p.key_extstate)
    S.api_key_map[p.id] = S.api_key
  end
  S.status = "idle"
  if (api_keys.screen == "first_run" or api_keys.screen == "settings") then
    -- Also persist any other newly entered keys that passed format validation
    -- (they were stored in S.api_key_map during submit but not yet saved to ExtState).
    for i, prov in ipairs(PROVIDERS) do
      if prov.id ~= p.id then
        local buf = api_keys.key_bufs[i] or ""
        local trimmed = buf:match("^%s*(.-)%s*$") or ""
        if trimmed ~= "" and S.api_key_map[prov.id] == trimmed then
          Key.save(trimmed, prov.key_extstate)
        end
      end
    end
    local was_reentry = api_keys.is_reentry
    -- Leave the key screen and enter the main UI.
    api_keys.screen         = nil
    api_keys.is_reentry     = false
    api_keys.key_validating = false
    api_keys.key_error      = nil
    api_keys.key_bufs       = {}
    api_keys.key_errors     = {}
    api_keys.key_warnings   = {}
    api_keys.key_focused    = false
    api_keys.custom_edit = nil
    UI.show_float_toast(was_reentry
      and RA.t("settings.toast.saved", nil, "Settings saved")
      or RA.t("settings.api_key.toast.validated", nil,
        "API key validated"), "ok")
    if not was_reentry then
      -- First-run: set the active provider to the one just validated.
      -- Drop any test-snapshot since first-run is intentionally choosing
      -- the new provider as active; restoring would defeat the purpose.
      api_keys._test_orig_provider_idx = nil
      local prov_idx = PROVIDERS._by_id[p.id]
      if prov_idx then
        prefs.provider_idx = prov_idx
        MODELS.refresh()
        if Store and Store.save_config then Store.save_config() end
      end
    elseif api_keys._test_orig_provider_idx then
      -- Settings re-entry: restore the active-provider snapshot taken
      -- when the Save handler flipped to test the new key, so testing
      -- e.g. a fresh OpenAI key while currently on Claude doesn't
      -- silently switch the active provider as a side effect of Save.
      -- If the snapshotted provider lost its key during this Save (user
      -- wiped it in the same submission), leave provider_idx pointing
      -- at the just-validated provider so the user retains a working
      -- configuration -- restoring would land them on a no-key slot.
      local saved = api_keys._test_orig_provider_idx
      api_keys._test_orig_provider_idx = nil
      local saved_prov = PROVIDERS[saved]
      if saved_prov and Store.provider_has_usable_credentials(saved_prov) then
        prefs.provider_idx = saved
        MODELS.refresh()
        if Store and Store.save_config then Store.save_config() end
      end
    end
    S.api_key = S.api_key_map[PROVIDERS.active().id]
    S.refocus_prompt   = true
    if Diag.uploader_enabled and Diag.capture_current_chat then
      Diag.capture_current_chat()
    end
    S.display_messages = {}
    S.history          = {}
    S.scroll_to_bottom = true
    -- Settings provider-switch implicitly starts a new chat. Rotate chat_id
    -- to match what Net.clear_conversation does at the canonical "+ New Chat"
    -- entry point.
    if Diag.uploader_enabled then
      Diag.rotate_chat_id()
    end
  end

  -- Clear the response file so the next Net.send_to_api call doesn't pick up
  -- the stale key-test response before the new curl has written its output.
  Code.safe_write(tmp.out, "")

  -- Detect Gemini free vs paid tier by testing the Pro model. Fires whenever
  -- a Google key ended up persisted by this key-test flow -- not just when
  -- Google was the tested provider. On first-run / Settings, Save & Continue
  -- tests only the FIRST valid key and side-saves the rest (see the loop
  -- above). Without this broader trigger, a Gemini key pasted alongside
  -- another provider never gets its tier detected and the free-tier popup
  -- never fires. fire_gemini_tier_test guards against double-firing via
  -- the S.curl_pid check at its top.
  if S.api_key_map.google then
    Store.set_gemini_paid_tier(nil)
    Net.fire_gemini_tier_test()
  end
end

-- =============================================================================
-- Net.fire_gemini_tier_test
-- =============================================================================
-- Fires a 1-token request using the Pro model to detect free vs paid tier.
-- Free tier: response body contains positive quota evidence
-- ("free_tier" metric text, or a quota limit/value of 0). Plain 429/403
-- responses are ambiguous: paid accounts can hit transient per-minute
-- throttles, and treating those as "free" hides Pro/caching until manual
-- reclassification.
-- Paid tier: request succeeds (Pro accessible).
function Net._gemini_error_has_free_tier_signal(err)
  if type(err) ~= "table" then return false end
  local saw_free_tier, saw_quota_context, saw_zero_limit = false, false, false
  local seen = {}

  local function scan(node, key_hint)
    if saw_free_tier or (saw_quota_context and saw_zero_limit) then return end
    local t = type(node)
    local key = tostring(key_hint or ""):lower()
    if key:find("quota", 1, true) then saw_quota_context = true end
    if t == "table" then
      if seen[node] then return end
      seen[node] = true
      for k, v in pairs(node) do scan(v, k) end
    elseif t == "string" then
      local text = node:lower()
      if text:find("free_tier", 1, true)
         or text:find("free-tier", 1, true)
         or text:find("freetier", 1, true) then
        saw_free_tier = true
      end
      if text:find("quota", 1, true) then saw_quota_context = true end
      if (key:find("limit", 1, true)
          or key:find("quota", 1, true))
         and tonumber(text) == 0 then
        saw_zero_limit = true
      end
    elseif t == "number" then
      if (key:find("limit", 1, true)
          or key:find("quota", 1, true))
         and node == 0 then
        saw_zero_limit = true
      end
    end
  end

  scan(err, nil)
  return saw_free_tier or (saw_quota_context and saw_zero_limit)
end

function Net.fire_gemini_tier_test()
  -- Don't fire while another request is in-flight.
  if S.curl_pid then return end
  local google_key = S.api_key_map.google
  if not google_key then return end

  -- Find the Pro model ID from the provider's full model list.
  local google_prov = PROVIDERS.get("google")
  if not google_prov then return end
  local pro_id
  for _, m in ipairs(google_prov.models) do
    if m.paid_only then pro_id = m.id; break end
  end
  if not pro_id then return end

  -- Pin thinkingLevel=LOW (the lowest setting Gemini Pro allows -- there is
  -- no "off" for Pro models) so the tier-test request doesn't burn 20-60s on
  -- internal reasoning before hitting the 1-token output cap. Without this,
  -- Pro defaults to MEDIUM thinking and the tier test routinely exceeds
  -- curl --max-time 30, leaving us at the mercy of the 180s watchdog and
  -- producing the "ambiguous (timeout)" classification on slow connections.
  -- The tier test only needs to know whether Pro is *callable*, not whether
  -- it produces a useful response, so cheap thinking is fine.
  local body = '{"contents":[{"role":"user","parts":[{"text":"hi"}]}],'
    .. '"generationConfig":{"maxOutputTokens":1,'
    .. '"thinkingConfig":{"thinkingLevel":"LOW","includeThoughts":false}}}'
  if not Code.safe_write(tmp.body, body) then return end

  -- Write the Gemini auth header to a temp file so it stays off the command
  -- line (not visible in ps/Task Manager). Uses tmp.gemini_auth to avoid
  -- trampling the main request's tmp.auth.
  if not Code.safe_write(tmp.gemini_auth, "x-goog-api-key: " .. google_key) then return end

  local endpoint = str_format(google_prov.endpoint_tpl, pro_id)
  local CONNECT_TIMEOUT_SECS = 10

  os.remove(tmp.exit)
  os.remove(tmp.err)
  -- Clear any stale tmp.pid from a previous real curl. This path does not
  -- launch curl with PID capture (no Start-Process -PassThru / $! plumbing),
  -- so leaving an old PID on disk would let Net.kill_curl `taskkill` an
  -- unrelated process if the user clicks Cancel during the tier test (or
  -- worse, a recycled PID owned by some other application).
  os.remove(tmp.pid)
  Code.safe_write(tmp.out, "")
  Code.safe_write(tmp.err, "")
  S.curl_debug = {
    launched_at_utc = os.date("!%Y-%m-%dT%H:%M:%SZ"),
    method = "POST",
    provider_id = "google",
    provider_label = google_prov.label,
    model_id = pro_id,
    model_label = "Gemini tier probe",
    endpoint = Net._debug_endpoint(google_prov, endpoint),
    connect_timeout_s = CONNECT_TIMEOUT_SECS,
    curl_timeout_s = 30,
    request_body_bytes = #body,
    is_turn_post = false,
    probe_kind = "gemini_tier_test",
  }

  if RA.IS_WINDOWS then
    local function ps_escape(path) return path:gsub("'", "''") end
    local cmd_line = str_format(
      'curl -sS --connect-timeout %d --max-time 30'
      .. ' -X POST """%s"""'
      .. ' -H """content-type: application/json"""'
      .. ' -H @"""%s"""'
      .. ' -d @"""%s""" -o """%s""" 2> """%s"""'
      .. ' & call echo ^%%errorlevel^%% > """%s""" & del """%s"""',
      CONNECT_TIMEOUT_SECS, endpoint, tmp.gemini_auth, tmp.body, tmp.out,
      tmp.err, tmp.exit, tmp.gemini_auth)
    local ps_cmd = str_format(
      'powershell -NoProfile -WindowStyle Hidden'
      .. ' -Command "Start-Process cmd -ArgumentList \'/c %s\''
      .. ' -WindowStyle Hidden"',
      ps_escape(cmd_line))
    reaper.ExecProcess(ps_cmd, 5000)
  else
    local function sq(path) return "'" .. path:gsub("'", "'\\''") .. "'" end
    -- Wrap entire pipeline in a subshell so & backgrounds curl+echo together.
    local unix_curl = str_format(
      '(curl -sS --connect-timeout %d --max-time 30'
      .. ' -X POST %s'
      .. ' -H "content-type: application/json"'
      .. ' -H @%s'
      .. ' -d @%s -o %s 2> %s ; rc=$? ; rm -f %s ; echo $rc > %s) &',
      CONNECT_TIMEOUT_SECS, sq(endpoint),
      sq(tmp.gemini_auth),
      sq(tmp.body), sq(tmp.out), sq(tmp.err),
      sq(tmp.gemini_auth), sq(tmp.exit))
    os.execute(unix_curl)
  end

  S.gemini_tier_pending = true
  S.curl_pid            = true
  S.send_time           = time_precise()
  -- Sticky floating toast so the user sees something is happening. Replaced
  -- by handle_gemini_tier_test (and the timeout / curl-exit branches) once
  -- the test resolves, with a result-specific message.
  if UI and UI.show_float_toast then
    UI.show_float_toast(RA.t("gemini.toast.verifying_tier", nil,
      "Verifying Gemini tier..."), "ok", true)
  end
end

-- =============================================================================
-- Net.handle_gemini_tier_test
-- =============================================================================
-- Parses the Pro model test response. Paid is set only on a positive signal
-- (successful generation); free is set on an explicit 429/403 error or the
-- legacy "free_tier" substring. Ambiguous responses leave S.gemini_paid_tier
-- unchanged (and do NOT persist) so the next session or Test-API-Keys click
-- retries instead of inheriting a bad classification. The Pro filter stays
-- engaged in the meantime (it gates on `~= true`), so users on the free tier
-- still don't see Pro -- they just don't get the "(Free)" label or the
-- explanatory popup until detection succeeds.
function Net.handle_gemini_tier_test(raw)
  S.gemini_tier_pending = false
  local is_paid, is_free, provider_unavailable
  if raw and #raw > 0 then
    local ok, resp = pcall(JSON.decode, raw)
    if ok and type(resp) == "table" and resp ~= JSON.NULL then
      if type(resp.error) == "table" and resp.error ~= JSON.NULL then
        local code   = tonumber(resp.error.code)
        local status = type(resp.error.status) == "string" and resp.error.status or ""
        if Net._gemini_error_has_free_tier_signal(resp.error) then
          is_free = true
        elseif code == 503 or status == "UNAVAILABLE" then
          provider_unavailable = true
        end
      elseif type(resp.candidates) == "table" and #resp.candidates > 0 then
        is_paid = true
      end
    end
  end
  local interpretation
  if is_paid then
    Store.set_gemini_paid_tier(true)
    interpretation = "paid"
    if UI and UI.show_float_toast then
      UI.show_float_toast(RA.t("gemini.toast.pro_available", nil,
        "Gemini Pro available"), "ok")
    end
  elseif is_free then
    Store.set_gemini_paid_tier(false)
    S.show_gemini_free_warn = true
    interpretation = "free"
    -- Free-tier popup handles the user-facing notice; just clear the
    -- in-flight sticky toast so it doesn't sit there indefinitely.
    S.float_toast = nil
  else
    -- Ambiguous: leave S.gemini_paid_tier and persisted State.json entry
    -- untouched so the next opportunity (app restart, Test API Keys click)
    -- can retry. Persisting `false` here would bake in a wrong answer that
    -- only manual ExtState surgery could undo.
    interpretation = "ambiguous"
    if UI and UI.show_float_toast then
      UI.show_float_toast(provider_unavailable
        and RA.t("gemini.toast.service_unavailable", nil,
          "Gemini service unavailable - tier check will retry")
        or RA.t("gemini.toast.verify_failed_retry", nil,
          "Couldn't verify Gemini tier - will retry on next start"), "err")
    end
  end
  Log.line("TIER-TEST", string.format("interpreted as: %s (raw bytes=%d)",
    interpretation, raw and #raw or 0))
  if PROVIDERS.active().id == "google" then MODELS.refresh() end
  Code.safe_write(tmp.out, "")  -- clear stale tier test response
end

-- =============================================================================
-- Gemini explicit context caching
-- =============================================================================
-- Explicit caching lets us pay a discounted rate on the tokens that make up
-- the system prompt + pinned API reference, instead of billing them as fresh
-- input tokens on every turn. The cache has a TTL (1h) and is bound to a
-- specific model id, so it must be recreated on model switch.
--
-- Lifecycle:
--   ensure()     - called at send time; fires an async create if eligible and
--                  we don't already have a live cache. Never blocks the send.
--   invalidate() - clears local state and fires a fire-and-forget DELETE so
--                  the cache stops accruing storage charges server-side.
--   is_usable()  - checked in build_body_google to decide whether to emit
--                  cachedContent and skip the inline api_ref + systemInstruction.
--
-- The first send after (re)creation goes out WITHOUT cache because creation
-- is async and completes in parallel. Subsequent sends benefit.
-- =============================================================================

-- Minimum input tokens to qualify for explicit caching on Gemini. Flash
-- family is 1024; Pro family is 4096. The API ref alone clears both, but
-- we include system_instruction in the cache too for a bigger discount.
local GEMINI_CACHE_TTL_SECS  = 3600  -- 1 hour
local GEMINI_CACHE_SAFETY    = 60    -- treat as expired if within 60s of TTL

-- =============================================================================
-- Net.gemini_cache_is_usable
-- =============================================================================
-- True when we have a live, non-expired cache that matches the current model.
function Net.gemini_cache_source_signature(api_ref)
  local sys = tostring((Net.system_prompt_text and Net.system_prompt_text())
    or SYSTEM_PROMPT or "")
  local ref = tostring(api_ref or "")
  if S.gemini_cache_sig_value
      and S.gemini_cache_sig_sys == sys
      and S.gemini_cache_sig_ref == ref then
    return S.gemini_cache_sig_value
  end
  local h = 5381
  local function fold(s)
    for i = 1, #s do
      h = (h * 33 + s:byte(i)) % 4294967296
    end
  end
  fold(sys)
  h = (h * 33 + 10) % 4294967296
  fold(ref)
  local signature = tostring(#sys) .. ":" .. tostring(#ref)
    .. ":" .. str_format("%08x", h)
  S.gemini_cache_sig_sys = sys
  S.gemini_cache_sig_ref = ref
  S.gemini_cache_sig_value = signature
  return signature
end

function Net.gemini_cache_is_usable()
  if not S.gemini_cache_name then return false end
  if S.gemini_paid_tier ~= true then return false end
  if not S.api_ref_message or S.api_ref_message == "" then return false end
  local p = PROVIDERS.active()
  if p.id ~= "google" then return false end
  if S.gemini_cache_model ~= MODELS.active_id() then return false end
  if S.gemini_cache_signature
      ~= Net.gemini_cache_source_signature(S.api_ref_message) then
    return false
  end
  if os.time() >= (S.gemini_cache_expires - GEMINI_CACHE_SAFETY) then
    return false
  end
  return true
end

function Net.gemini_cache_debug_state(stage, used_cache, reported_read_tokens)
  local p = PROVIDERS.active()
  local provider_id = p and p.id or ""
  local active_model = MODELS.active_id and MODELS.active_id() or ""
  local has_name = type(S.gemini_cache_name) == "string"
    and S.gemini_cache_name ~= ""
  local has_api_ref = type(S.api_ref_message) == "string"
    and S.api_ref_message ~= ""
  local current_signature = has_api_ref
    and Net.gemini_cache_source_signature(S.api_ref_message)
    or ""
  local expires_in = (tonumber(S.gemini_cache_expires) or 0) - os.time()
  local status, reason
  if provider_id ~= "google" then
    status, reason = "disabled", "provider_not_google"
  elseif S.gemini_paid_tier ~= true then
    status = "disabled"
    reason = (S.gemini_paid_tier == false)
      and "paid_tier_false"
      or "paid_tier_unknown"
  elseif not has_api_ref then
    status, reason = "disabled", "api_ref_missing"
  elseif used_cache == true then
    local reported = tonumber(reported_read_tokens)
    if reported and reported <= 0 then
      status, reason = "used_unreported", "cached_content_sent_no_token_report"
    elseif reported and reported > 0 then
      status, reason = "used", "cached_content_sent_reported"
    else
      status, reason = "used", "cached_content_sent"
    end
  elseif S.gemini_cache_creating then
    status, reason = "pending", "create_in_flight"
  elseif not has_name then
    status, reason = "miss", "not_created"
  elseif S.gemini_cache_model ~= active_model then
    status, reason = "miss", "model_mismatch"
  elseif S.gemini_cache_signature ~= current_signature then
    status, reason = "miss", "source_mismatch"
  elseif expires_in <= GEMINI_CACHE_SAFETY then
    status, reason = "miss", "expired_or_near_expiry"
  else
    status, reason = "ready", "usable"
  end
  return {
    stage = stage or "",
    provider = provider_id,
    status = status,
    reason = reason,
    used = used_cache == true,
    paid_tier = S.gemini_paid_tier == true and "true"
      or S.gemini_paid_tier == false and "false"
      or "unknown",
    cache_name_present = has_name,
    cache_signature_present = type(S.gemini_cache_signature) == "string"
      and S.gemini_cache_signature ~= "",
    creating = S.gemini_cache_creating == true,
    api_ref_present = has_api_ref,
    active_model = active_model,
    cache_model = S.gemini_cache_model or "",
    expires_in_s = expires_in > 0 and math_floor(expires_in) or 0,
    reported_read_tokens = tonumber(reported_read_tokens) or 0,
    create_reason = S.gemini_cache_last_create_reason or "",
  }
end

-- =============================================================================
-- Net.gemini_cache_should_create
-- =============================================================================
-- True when the conditions for caching are met but no live cache exists yet.
local function gemini_cache_should_create()
  if S.gemini_cache_creating then return false end
  if S.gemini_paid_tier ~= true then return false end
  -- Treat empty string the same as nil. CTX.docs() normally returns nil on
  -- failure, but a partial-load failure path that produces "" would
  -- otherwise queue a Gemini cache create with a zero-token body, which
  -- the API rejects under its min-tokens limit -- wasted curl cycle.
  if not S.api_ref_message or S.api_ref_message == "" then return false end
  local p = PROVIDERS.active()
  if p.id ~= "google" then return false end
  if Net.gemini_cache_is_usable() then return false end
  return true
end

-- =============================================================================
-- Net.fire_gemini_cache_delete
-- =============================================================================
-- Fire-and-forget DELETE against cachedContents/NAME. We don't poll for
-- completion -- if it fails the cache will expire on its own via TTL.
function Net.fire_gemini_cache_delete(cache_name)
  if not cache_name or cache_name == "" then return end
  local google_key = S.api_key_map and S.api_key_map.google
  if not google_key then return end
  -- Write key to temp file so it stays off the command line.
  if not Code.safe_write(tmp.cache_delete_auth, "x-goog-api-key: " .. google_key) then return end
  local url = str_format(
    "https://generativelanguage.googleapis.com/v1beta/%s",
    cache_name)
  if RA.IS_WINDOWS then
    local cmd_line = str_format(
      'curl -s -X DELETE -H @"""%s""" """%s""" & del """%s"""',
      tmp.cache_delete_auth, url, tmp.cache_delete_auth)
    local ps_cmd = str_format(
      'powershell -NoProfile -WindowStyle Hidden'
      .. ' -Command "Start-Process cmd -ArgumentList \'/c %s\''
      .. ' -WindowStyle Hidden"',
      cmd_line:gsub("'", "''"))
    reaper.ExecProcess(ps_cmd, 2000)
  else
    local function sq(path) return "'" .. path:gsub("'", "'\\''") .. "'" end
    os.execute(str_format(
      '(curl -s -X DELETE -H @%s %s > /dev/null 2>&1 ; rm -f %s) &',
      sq(tmp.cache_delete_auth), sq(url), sq(tmp.cache_delete_auth)))
  end
end

-- atexit: persist the active Gemini context cache reference so the next
-- launch can reuse it instead of paying to recreate. Server-side TTL
-- (1h) cleans up orphans if the user never reopens.
reaper.atexit(function()
  if S.gemini_cache_name then
    local ok, err = pcall(Net.gemini_cache_persist)
    if not ok then
      Log.line("GEMINI", "cache_persist (atexit) failed: " .. tostring(err))
    end
  end
end)

-- =============================================================================
-- Net.gemini_cache_invalidate
-- =============================================================================
-- Clears local cache state and issues a server-side DELETE so the old cache
-- stops accruing storage charges. Safe to call when no cache exists.
function Net.gemini_cache_invalidate()
  local old_name = S.gemini_cache_name
  local had_create = S.gemini_cache_creating == true
  S.gemini_cache_name    = nil
  S.gemini_cache_expires = 0
  -- A cache-create curl cannot be cancelled after launch. Keep it marked as
  -- creating so a new create cannot reuse the same output files before the old
  -- response lands; the poll path will discard and delete any returned name.
  if had_create then
    S.gemini_cache_create_aborted = true
  else
    S.gemini_cache_model   = nil
    S.gemini_cache_signature = nil
  end
  Net.gemini_cache_clear_persisted()
  if old_name then
    Net.fire_gemini_cache_delete(old_name)
  end
end

-- =============================================================================
-- Net.gemini_cache_persist / restore / clear_persisted
-- =============================================================================
-- Survives the cache reference (name/model/expires) across script restarts via
-- State.json. Without this, every restart re-creates a fresh cache while the
-- prior one continues billing storage server-side until its TTL expires --
-- typically ~$0.01 per restart on Gemini Pro and a 1-3s extra cold-start.
function Net.gemini_cache_persist()
  if not S.gemini_cache_name or S.gemini_cache_name == "" then return end
  if Store and Store.set_gemini_cache_state then
    local err = Store.set_gemini_cache_state(
      S.gemini_cache_name,
      S.gemini_cache_model or "",
      S.gemini_cache_signature or "",
      S.gemini_cache_expires or 0)
    if not err then return end
  end
  reaper.SetExtState(CFG.EXT_NS, "gemini_cache_name",
    S.gemini_cache_name, true)
  reaper.SetExtState(CFG.EXT_NS, "gemini_cache_model",
    S.gemini_cache_model or "", true)
  reaper.SetExtState(CFG.EXT_NS, "gemini_cache_signature",
    S.gemini_cache_signature or "", true)
  reaper.SetExtState(CFG.EXT_NS, "gemini_cache_expires",
    tostring(S.gemini_cache_expires or 0), true)
end

function Net.gemini_cache_clear_persisted()
  if Store and Store.clear_gemini_cache_state then
    local err = Store.clear_gemini_cache_state()
    if not err then return end
  end
  reaper.DeleteExtState(CFG.EXT_NS, "gemini_cache_name",    true)
  reaper.DeleteExtState(CFG.EXT_NS, "gemini_cache_model",   true)
  reaper.DeleteExtState(CFG.EXT_NS, "gemini_cache_signature", true)
  reaper.DeleteExtState(CFG.EXT_NS, "gemini_cache_expires", true)
end

function Net.gemini_cache_restore()
  local name, model, signature, expires
  if Store and Store.gemini_cache_state then
    name, model, signature, expires = Store.gemini_cache_state()
  end
  if not name or name == "" then
    name = reaper.GetExtState(CFG.EXT_NS, "gemini_cache_name")
    model = reaper.GetExtState(CFG.EXT_NS, "gemini_cache_model")
    signature = reaper.GetExtState(CFG.EXT_NS, "gemini_cache_signature")
    expires = tonumber(reaper.GetExtState(CFG.EXT_NS, "gemini_cache_expires")) or 0
  end
  if not name or name == "" then return end
  -- Discard expired caches (or those within the safety window). Server-side
  -- TTL has already collected them.
  if os.time() >= (expires - GEMINI_CACHE_SAFETY) then
    Net.gemini_cache_clear_persisted()
    return
  end
  S.gemini_cache_name    = name
  S.gemini_cache_model   = (model ~= "") and model or nil
  S.gemini_cache_signature = (signature ~= "") and signature or nil
  S.gemini_cache_expires = expires
  Log.line("GEMINI_CACHE", "restored " .. name
    .. " (model=" .. tostring(S.gemini_cache_model)
    .. ", signature=" .. tostring(S.gemini_cache_signature)
    .. ", expires_in=" .. tostring(expires - os.time()) .. "s)")
end

-- =============================================================================
-- Net.fire_gemini_cache_create
-- =============================================================================
-- Async POST /v1beta/cachedContents. Writes the body to tmp.cache_body and
-- launches curl in the background, with output going to tmp.cache_out and
-- exit code to tmp.cache_exit. The main loop polls completion via
-- Net.try_finish_gemini_cache_create.
--
-- Body contains: model id, systemInstruction (including Custom Instructions
-- when enabled), contents (the api_ref priming exchange), and a TTL. Minimum
-- token counts are naturally met since the api ref alone is ~8k tokens.
function Net.fire_gemini_cache_create()
  if S.gemini_cache_creating then
    S.gemini_cache_last_create_reason = "already_creating"
    return
  end
  if not gemini_cache_should_create() then
    S.gemini_cache_last_create_reason = "not_eligible"
    return
  end

  local google_key = S.api_key_map and S.api_key_map.google
  if not google_key or google_key == "" then
    S.gemini_cache_last_create_reason = "api_key_map_missing"
    return
  end

  local model_id = MODELS.active_id()
  if not model_id then
    S.gemini_cache_last_create_reason = "model_missing"
    return
  end
  local source_signature = Net.gemini_cache_source_signature(S.api_ref_message)

  -- Build the create body: system_instruction + the same user/model priming
  -- exchange we'd otherwise inline into every request. Custom Instructions
  -- are already folded into Net.system_prompt_text().
  local body = str_format(
    '{"model":"models/%s",'
    .. '"systemInstruction":{"parts":[{"text":"%s"}]},'
    .. '"contents":[{"role":"user","parts":[{"text":"%s"}]},'
    .. '{"role":"model","parts":[{"text":"Understood."}]}],'
    .. '"ttl":"%ds"}',
    model_id,
    JSON.escape(Net.system_prompt_text()),
    JSON.escape(S.api_ref_message),
    GEMINI_CACHE_TTL_SECS)

  if not Code.safe_write(tmp.cache_body, body) then
    S.gemini_cache_last_create_reason = "cache_body_write_failed"
    return
  end

  -- Write auth header to temp file (keeps key off command line). This path
  -- intentionally uses a cache-create-specific auth file because cache DELETE
  -- and normal Gemini side requests can overlap with this background curl.
  if not Code.safe_write(tmp.cache_auth, "x-goog-api-key: " .. google_key) then
    S.gemini_cache_last_create_reason = "auth_write_failed"
    return
  end

  local url = "https://generativelanguage.googleapis.com/v1beta/cachedContents"

  os.remove(tmp.cache_exit)
  Code.safe_write(tmp.cache_out, "")
  Code.safe_write(tmp.cache_err, "")

  if RA.IS_WINDOWS then
    local cmd_line = str_format(
      'curl -sS --connect-timeout 10 --max-time 30'
      .. ' -X POST """%s"""'
      .. ' -H """content-type: application/json"""'
      .. ' -H @"""%s"""'
      .. ' -d @"""%s""" -o """%s"""'
      .. ' 2> """%s"""'
      .. ' & call echo ^%%errorlevel^%% > """%s"""'
      .. ' & del """%s"""',
      url, tmp.cache_auth, tmp.cache_body, tmp.cache_out,
      tmp.cache_err, tmp.cache_exit, tmp.cache_auth)
    local ps_cmd = str_format(
      'powershell -NoProfile -WindowStyle Hidden'
      .. ' -Command "Start-Process cmd -ArgumentList \'/c %s\''
      .. ' -WindowStyle Hidden"',
      cmd_line:gsub("'", "''"))
    reaper.ExecProcess(ps_cmd, 5000)
  else
    local function sq(path) return "'" .. path:gsub("'", "'\\''") .. "'" end
    local unix_curl = str_format(
      '(curl -sS --connect-timeout 10 --max-time 30'
      .. ' -X POST %s'
      .. ' -H "content-type: application/json"'
      .. ' -H @%s'
      .. ' -d @%s -o %s 2> %s ; rc=$? ; rm -f %s ; echo $rc > %s) &',
      sq(url), sq(tmp.cache_auth),
      sq(tmp.cache_body), sq(tmp.cache_out), sq(tmp.cache_err),
      sq(tmp.cache_auth), sq(tmp.cache_exit))
    os.execute(unix_curl)
  end

  S.gemini_cache_creating   = true
  S.gemini_cache_started_at = reaper.time_precise()
  S.gemini_cache_model      = model_id  -- remember intended model for poll
  S.gemini_cache_signature  = source_signature
  S.gemini_cache_last_create_reason = "launched"
end

-- =============================================================================
-- Net.gemini_cache_ensure
-- =============================================================================
-- Called before building a Gemini request body. If we should have a cache but
-- don't (yet), fire an async create. Never blocks; the current send proceeds
-- with whatever state exists right now.
function Net.gemini_cache_ensure()
  if S.gemini_cache_creating then
    Net.try_finish_gemini_cache_create()
  end
  if S.gemini_cache_name
      and S.gemini_paid_tier == true
      and S.api_ref_message and S.api_ref_message ~= ""
      and not Net.gemini_cache_is_usable() then
    Net.gemini_cache_invalidate()
  end
  if gemini_cache_should_create() then
    Net.fire_gemini_cache_create()
  elseif Net.gemini_cache_should_renew() then
    Net.fire_gemini_cache_renew()
  elseif not Net.gemini_cache_is_usable() then
    local gc = Net.gemini_cache_debug_state("ensure", false)
    S.gemini_cache_last_create_reason = gc and gc.reason or "not_eligible"
  end
end

-- =============================================================================
-- Net.gemini_cache_should_renew / fire_gemini_cache_renew
-- =============================================================================
-- Bumps the server-side TTL of the active cache before it expires, instead of
-- waiting for expiry and paying to recreate. Without this, mid-session caches
-- silently expire after 1h and the next send rebuilds from scratch.
--
-- Renew threshold: remaining TTL < 15 min, no renew already in flight.
-- Fire-and-forget PATCH, optimistic local bump. If the server-side renew
-- fails for any reason, the next send will hit a 404 cache_miss and the
-- existing invalidate -> recreate path picks up cleanly.
local GEMINI_CACHE_RENEW_THRESHOLD = 15 * 60  -- 15 minutes
local GEMINI_CACHE_RENEW_DEDUPE    = 5 * 60   -- don't re-fire renew within 5 min

function Net.gemini_cache_should_renew()
  if not S.gemini_cache_name then return false end
  if S.gemini_cache_creating then return false end
  if not Net.gemini_cache_is_usable() then return false end
  -- Throttle: at most one renew attempt per dedupe window so a burst of sends
  -- doesn't fire 10 PATCHes back-to-back.
  local now = os.time()
  if (S.gemini_cache_last_renew or 0) > now - GEMINI_CACHE_RENEW_DEDUPE then
    return false
  end
  local remaining = (S.gemini_cache_expires or 0) - now
  return remaining > 0 and remaining < GEMINI_CACHE_RENEW_THRESHOLD
end

function Net.fire_gemini_cache_renew()
  local cache_name = S.gemini_cache_name
  if not cache_name or cache_name == "" then return end
  local google_key = S.api_key_map and S.api_key_map.google
  if not google_key then return end
  if not Code.safe_write(tmp.cache_renew_auth, "x-goog-api-key: " .. google_key) then return end
  local body = str_format('{"ttl":"%ds"}', GEMINI_CACHE_TTL_SECS)
  if not Code.safe_write(tmp.cache_renew_body, body) then return end
  local url = str_format(
    "https://generativelanguage.googleapis.com/v1beta/%s",
    cache_name)
  if RA.IS_WINDOWS then
    local cmd_line = str_format(
      'curl -s -X PATCH """%s"""'
      .. ' -H """content-type: application/json"""'
      .. ' -H @"""%s"""'
      .. ' -d @"""%s""" -o NUL'
      .. ' & del """%s""" & del """%s"""',
      url, tmp.cache_renew_auth, tmp.cache_renew_body,
      tmp.cache_renew_auth, tmp.cache_renew_body)
    local ps_cmd = str_format(
      'powershell -NoProfile -WindowStyle Hidden'
      .. ' -Command "Start-Process cmd -ArgumentList \'/c %s\''
      .. ' -WindowStyle Hidden"',
      cmd_line:gsub("'", "''"))
    reaper.ExecProcess(ps_cmd, 2000)
  else
    local function sq(path) return "'" .. path:gsub("'", "'\\''") .. "'" end
    os.execute(str_format(
      '(curl -s -X PATCH -H "content-type: application/json"'
      .. ' -H @%s -d @%s %s > /dev/null 2>&1 ; rm -f %s %s) &',
      sq(tmp.cache_renew_auth), sq(tmp.cache_renew_body), sq(url),
      sq(tmp.cache_renew_auth), sq(tmp.cache_renew_body)))
  end
  -- Optimistically bump local expiry. If the PATCH fails server-side, the
  -- next send hits 404 and Net.gemini_cache_invalidate clears state cleanly.
  S.gemini_cache_expires    = os.time() + GEMINI_CACHE_TTL_SECS
  S.gemini_cache_last_renew = os.time()
  Net.gemini_cache_persist()
  Log.line("GEMINI_CACHE", "renew fired for " .. cache_name
    .. " (new TTL " .. GEMINI_CACHE_TTL_SECS .. "s, optimistic)")
end

-- =============================================================================
-- Net.try_finish_gemini_cache_create
-- =============================================================================
-- Polled from the main loop while S.gemini_cache_creating is true. Reads the
-- response file, parses the cache name and expireTime, and stores them for
-- subsequent send_to_api calls to pick up via gemini_cache_is_usable.
function Net.try_finish_gemini_cache_create()
  if not S.gemini_cache_creating then return end

  -- Watchdog: if the cache-create curl hasn't resolved within 45 seconds
  -- (curl's own --max-time is 30s; we allow 15s of slack for PowerShell
  -- launch delay and fs lag), give up and unstick state so caching stays
  -- functional for the rest of the session.
  local started = S.gemini_cache_started_at or 0
  if started > 0 and (reaper.time_precise() - started) > 45 then
    S.gemini_cache_creating = false
    S.gemini_cache_create_aborted = false
    S.gemini_cache_model    = nil
    S.gemini_cache_signature = nil
    S.gemini_cache_last_create_reason = "watchdog_timeout"
    os.remove(tmp.cache_exit)
    Code.safe_write(tmp.cache_out, "")
    return
  end

  -- Exit code first (network error path). A nonzero code means curl failed
  -- outright; an exit code 0 means curl completed, so we must parse the
  -- response body even if it isn't JSON -- otherwise a proxy HTML page
  -- would silently pin us in the "creating" state forever.
  local curl_done = false
  do
    local ok_ef, ef = pcall(io.open, tmp.cache_exit, "r")
    if ok_ef and ef then
      local exit_str = ef:read("*a"); ef:close()
      local exit_code = tonumber(exit_str:match("(%d+)"))
      if exit_code and exit_code ~= 0 then
        local aborted = S.gemini_cache_create_aborted == true
        S.gemini_cache_creating = false
        S.gemini_cache_create_aborted = false
        S.gemini_cache_model    = nil
        S.gemini_cache_signature = nil
        S.gemini_cache_last_create_reason = aborted
          and "aborted"
          or ("curl_exit_" .. tostring(exit_code))
        os.remove(tmp.cache_exit)
        return
      elseif exit_code == 0 then
        curl_done = true
        os.remove(tmp.cache_exit)
      end
    end
  end

  -- Response body. If curl hasn't exited yet, bail out rather than trying to
  -- infer completeness from the partially written output file. A partial body
  -- can temporarily look JSON-ish and still decode as non-JSON, which would
  -- discard an otherwise healthy in-flight cache create.
  if not curl_done then return end

  local ok_f, f = pcall(io.open, tmp.cache_out, "r")
  if not ok_f or not f then return end
  local raw = f:read("*a"); f:close()

  local aborted = S.gemini_cache_create_aborted == true
  S.gemini_cache_creating = false
  S.gemini_cache_create_aborted = false
  Code.safe_write(tmp.cache_out, "")

  local resp = JSON.decode(raw)
  if aborted then
    if type(resp) == "table"
        and type(resp.name) == "string"
        and resp.name ~= "" then
      Net.fire_gemini_cache_delete(resp.name)
    end
    S.gemini_cache_model = nil
    S.gemini_cache_signature = nil
    S.gemini_cache_last_create_reason = "aborted"
    return
  end

  if type(resp) ~= "table" then
    -- Non-JSON response (e.g. proxy HTML); caching stays unusable this turn
    -- but the "creating" flag is already cleared so future sends can retry.
    S.gemini_cache_model = nil
    S.gemini_cache_signature = nil
    S.gemini_cache_last_create_reason = "non_json_response"
    return
  end

  -- Error envelope: {"error":{"code":N,"message":"...","status":"..."}}
  if type(resp.error) == "table" and resp.error ~= JSON.NULL then
    S.gemini_cache_model = nil
    S.gemini_cache_signature = nil
    local err = resp.error
    S.gemini_cache_last_create_reason =
      "api_error_" .. tostring(err.status or err.code or "unknown")
    return
  end

  -- Success: {"name":"cachedContents/abc","model":"models/...","expireTime":"..."}
  if type(resp.name) == "string" and resp.name ~= "" then
    S.gemini_cache_name = resp.name
    S.gemini_cache_signature = S.gemini_cache_signature
      or Net.gemini_cache_source_signature(S.api_ref_message)
    -- We set ttl=3600s in the create request, so expires = now + TTL is
    -- accurate. The server also returns expireTime (RFC3339 UTC) but parsing
    -- it via os.time() applies local-timezone offset and skews the result.
    S.gemini_cache_expires = os.time() + GEMINI_CACHE_TTL_SECS
    Net.gemini_cache_persist()  -- survive script restart
    S.gemini_cache_last_create_reason = "success"
  else
    S.gemini_cache_model = nil
    S.gemini_cache_signature = nil
    S.gemini_cache_last_create_reason = "missing_cache_name"
  end
end

-- =============================================================================
-- Net.send_to_api
-- =============================================================================
function Net.should_auto_inject_theme(user_text)
  local lt = tostring(user_text or ""):lower()
  local function term_pattern(term)
    local parts = {}
    for part in tostring(term or ""):gmatch("%S+") do
      parts[#parts + 1] = part:gsub("([^%w])", "%%%1")
    end
    return table.concat(parts, "%s+")
  end
  local function has_term(term)
    local pat = term_pattern(term)
    if pat == "" then return false end
    return lt:find("%f[%w]" .. pat .. "%f[%W]") ~= nil
  end
  local function has_any(terms)
    for _, term in ipairs(terms) do
      if has_term(term) then return true end
    end
    return false
  end

  -- Appearance action words. Keep these token-bounded so audio/DSP words
  -- like "coloration" do not look like REAPER theme-edit requests.
  local has_appearance = has_any({
    "color", "colors", "colour", "colours", "background",
    "darker", "lighter", "bright", "brighter", "brighten",
    "appearance",
  })

  -- Path A: "theme" as a standalone token + appearance word.
  local has_theme_word = has_term("theme")

  -- Path B: REAPER UI element name + appearance action (covers "make the
  -- arrange darker", "change waveform color", "mixer background", etc.).
  local has_ui_element = has_any({
    "arrange", "mixer", "track panel", "tcp", "mcp",
    "waveform", "waveforms", "peaks", "cursor", "grid",
    "meter", "meters", "timeline", "ruler", "transport",
    "marker", "markers", "region", "regions", "envelope",
    "envelopes", "midi editor",
  })

  return has_appearance and (has_theme_word or has_ui_element)
end

function Net._token_estimate_codepoint_is_cjk(cp)
  cp = tonumber(cp) or 0
  return (cp >= 0x3400 and cp <= 0x4DBF)   -- CJK extension A
    or (cp >= 0x4E00 and cp <= 0x9FFF)     -- CJK unified ideographs
    or (cp >= 0xF900 and cp <= 0xFAFF)     -- CJK compatibility ideographs
    or (cp >= 0x20000 and cp <= 0x2EBEF)   -- CJK extensions B-F
    or (cp >= 0x3040 and cp <= 0x30FF)     -- Hiragana + Katakana
    or (cp >= 0xAC00 and cp <= 0xD7AF)     -- Hangul syllables
    or (cp >= 0xFF00 and cp <= 0xFFEF)     -- Fullwidth forms
end

function Net.estimate_request_tokens_from_body(body)
  body = tostring(body or "")
  if body == "" then return 0 end
  if not body:find("[\128-\255]") then
    return math_floor(#body / 4)
  end
  local ascii_bytes, other_bytes, cjk_chars = 0, 0, 0
  local ok = pcall(function()
    for _, cp in utf8.codes(body) do
      if Net._token_estimate_codepoint_is_cjk(cp) then
        cjk_chars = cjk_chars + 1
      elseif cp < 0x80 then
        ascii_bytes = ascii_bytes + 1
      elseif cp < 0x800 then
        other_bytes = other_bytes + 2
      elseif cp < 0x10000 then
        other_bytes = other_bytes + 3
      else
        other_bytes = other_bytes + 4
      end
    end
  end)
  if not ok then return math_floor(#body / 4) end
  return math_floor(ascii_bytes / 4)
    + math_floor(other_bytes / 4)
    + cjk_chars
end

-- Entry point for every user-initiated send.
--
-- Flow:
--   1. Capture the active project tab (EnumProjects(-1)).
--   2. Build a fresh session snapshot if "Send snapshot" is on.
--   3. Load the API reference into the pinned message slot on first send of the
--      session if "Always include REAPER API reference" is on. The pinned message is prepended to every
--      API call by Net.build_body() outside the sliding window, keeping its cache
--      position stable.
--   4. Push the user text to S.history (snapshot and API ref are NOT stored here).
  --   5. Preflight token estimation: abort with a friendly error if the request
  --      would exceed the model's context window (UTF-8-aware rough heuristic).
--   6. Fire curl. The snapshot is injected by Net.build_body(), not stored in S.history.
function Net.send_to_api(user_text)
  if not RA.code_runtime_loaded() then
    return RA.fail_code_runtime_unavailable("before sending", "idle")
  end
  if not RA.context_loaded() then
    return RA.fail_context_unavailable("before sending", "idle")
  end

  -- Probe compatibility: open a turn handle at the outermost boundary.
  -- Probe is currently an in-line no-op compatibility surface so older
  -- instrumentation call sites stay harmless while the local
  -- probe module is retired. If a previous turn somehow didn't reach an
  -- end_turn site (re-entrance, missed exit path), close it as "aborted"
  -- before clobbering S.probe_turn with the new handle.
  if S.probe_turn then
    Probe.end_turn(S.probe_turn, "aborted")
    S.probe_turn = nil
  end
  local probe_turn = Probe.start_turn(user_text)
  S.probe_turn = probe_turn
  S._custom_instr_prompt_key = nil
  S._custom_instr_prompt_block = nil
  -- Probe timing: preempt covers all per-turn setup
  -- before the first body build (state resets, snapshot capture,
  -- ref/midi/theme auto-injection, sticky eviction, preempt bucket
  -- injection). Ends just before Net.build_body is first called.
  Probe.mark_phase_start(probe_turn, "preempt")

  S.status                = "waiting"
  S.request_start_time    = reaper.time_precise()
  S.pending_code          = nil
  S.lua_defer_run         = nil
  S.docs_already_sent     = false
  S.docs_extended_already_sent = false
  S.docs_section_sent     = {}
  S.session_already_sent  = false
  S.tracks_already_sent   = false
  S.fx_params_already_sent = false
  S.plugin_ref_sent        = {}
  S.pending_resolves       = {}
  S.pending_plugin_ref_names = {}
  S.pending_pref_plugin_types = {}
  S.reset_turn_retries()
  S._context_reuse_hint    = nil
  S._irrelevant_context_hint = nil
  S._timecode_context_hint = nil
  S._jsfx_context_hint = nil
  S._mixed_output_hint     = nil
  S._fx_inspect_dropped    = nil
  S.fx_list_already_sent   = false
  S.fx_chains_already_sent = false
  S.track_flags_already_sent = false
  S.midi_already_sent      = false
  S.pref_plugins_sent      = {}
  S.theme_already_sent     = false
  S.fx_inspect_already_sent = false
  -- Defensive: clear any leftover deferred-assemble or silent-inspect flag
  -- from a cancelled prior turn so this turn isn't poisoned.
  S._fx_params_pending_assemble  = nil
  S._fx_inspect_silent_for_fx_params = nil
  S.pending_orig_prompt   = user_text
  Code.maybe_update_latest_from_user(user_text)
  Code.maybe_mark_latest_candidate_working(user_text)
  S.pending_typed_action_expected = false
  S.pending_typed_action_response_format = false
  S.pending_typed_action_profile = nil
  S.pending_answer_only_followup = nil
  S.retry_count           = 0          -- reset retry counter for each new user send
  S.retry_max             = CFG.MAX_RETRIES
  S.retry_scheduled       = false
  S.retry_saved_body      = nil
  S.retry_saved_provider_idx = nil
  S.retry_saved_model_idx    = nil
  S.retry_saved_thinking_idx = nil

  -- Capture current attachments and clear the queue before any early returns.
  local msg_attachments = #S.attachments > 0 and S.attachments or nil
  S.attachments = {}

  -- Warn if PDFs are attached to a provider that doesn't support them.
  if msg_attachments and PROVIDERS.active().id == "openai" then
    for _, att in ipairs(msg_attachments) do
      if att.kind == "pdf" then
        local fallback = "ChatGPT does not support PDF attachments. "
          .. "The file name will be sent but its content cannot be read. "
          .. "Try Claude or Gemini for PDF support."
        Log.add_error((RA and RA.t and RA.t(
          "attach.error.openai_pdf_unsupported", nil, fallback)) or fallback)
        break
      end
    end
  end

  -- 1. Reset FX cache event tracking for this exchange.
  S._fx_cache_events = {}  -- keyed by type: { hit = {name, ...}, cached = {...}, annotated = {...} }

  -- 1b. Capture the active project.
  S.pending_project = reaper.EnumProjects(-1)
  local skip_local_answer = S.skip_local_answer_once
  S.skip_local_answer_once = nil
  if not skip_local_answer
      and Net.try_local_jsfx_capability_overview(user_text, msg_attachments,
        probe_turn) then
    return true
  end
  if not skip_local_answer and Net.try_local_read_answer(user_text, msg_attachments, probe_turn) then
    return true
  end
  if not skip_local_answer
      and Net.try_local_panner_lfo_clarification(user_text, msg_attachments,
        probe_turn) then
    return true
  end
  if not skip_local_answer
      and Net.try_local_selected_track_rename_count_guard(user_text,
        msg_attachments, probe_turn) then
    return true
  end

  -- 1c. JSFX intent detection. Used by the snapshot tracks-trim and the
  -- plugin_ref / pref / docs preempt skip. Mirrored to S.pending_jsfx_intent
  -- so the JSFX validator-retry path, which rebuilds the snapshot from
  -- outside Net.send_to_api, can keep the same minimal-tracks trim.
  -- The detector is conservative (literal "jsfx" / "eel2" / "reajs" /
  -- "@init"-style markers only) so non-JSFX prompts that happen to
  -- contain DSP words like "shimmer" or "harmonizer" still get full
  -- plugin treatment.
  local jsfx_intent = CTX.prompt_indicates_jsfx(user_text)
  S.pending_jsfx_intent = jsfx_intent or nil
  local drum_edit_intent = CTX.prompt_indicates_drum_edit(user_text)
  S.pending_drum_edit_intent = drum_edit_intent or nil
  local answer_only_reason = nil
  if not msg_attachments and Code.history_has_prior_assistant(S.history) then
    if Code.prompt_is_answer_only_followup(user_text) then
      answer_only_reason = "answer-only follow-up"
    elseif Code.prompt_is_ideation_advice_followup
        and Code.prompt_is_ideation_advice_followup(user_text) then
      answer_only_reason = "ideation/advice follow-up"
    end
  end
  local answer_only_followup = answer_only_reason ~= nil
  S.pending_answer_only_followup = answer_only_followup or nil
  if answer_only_followup then
    Log.line("CTX",
      answer_only_reason .. ": suppressing snapshot and pinned references")
  end

  -- 2. Build a fresh session snapshot if enabled.
  local snapshot_opts = nil
  if jsfx_intent or drum_edit_intent then
    snapshot_opts = {
      minimal_tracks = jsfx_intent or nil,
      drum_edit = drum_edit_intent or nil,
    }
  end
  local snapshot = (not answer_only_followup) and prefs.include_snapshot
    and CTX.build_snapshot(S.pending_project, snapshot_opts)
    or nil
  S.pending_snapshot    = snapshot        -- saved for potential docs follow-up
  S.pending_attachments = msg_attachments -- saved for beta-header fallback rebuild

  -- 3. Load the API reference into the pinned slot on first send of the session.
  local ref_injected = false
  if not answer_only_followup and prefs.include_api_ref and not S.api_ref_message then
    local ref_content, ref_err = CTX.docs()
    if ref_content then
      S.api_ref_message = ref_content
      ref_injected    = true
    else
      Log.add_error(ref_err)
    end
  end
  if not answer_only_followup and S.api_ref_message then ref_injected = true end

  -- 3a. MIDI auto-inject: if the user prompt contains the word "midi" as a
  -- standalone token (case-insensitive), or common music-note terms in a
  -- clearly musical context, pre-load the MIDI reference into the pinned slot.
  -- This avoids a context_needed round-trip when the prompt is clearly
  -- MIDI-related. The model can also request it explicitly via
  -- <context_needed>midi</context_needed> for prompts that imply MIDI without
  -- saying it (e.g. "transpose those notes"). Once loaded, it stays loaded
  -- for the rest of the session and is cached at the top of the prefix.
  local midi_injected = false
  if not answer_only_followup and not S.midi_ref_message then
    -- Match "midi" with non-letter boundaries on both sides (Lua has no \b).
    local lower_text = user_text:lower()
    local has_midi = false
    if lower_text == "midi" or lower_text:match("^midi[^%a]")
       or lower_text:match("[^%a]midi$") or lower_text:match("[^%a]midi[^%a]") then
      has_midi = true
    end
    if not has_midi then
      has_midi = Code.prompt_has_midi_workflow_intent(lower_text)
    end
    if has_midi then
      local mref_content, mref_err = CTX.midi()
      if mref_content then
        S.midi_ref_message = mref_content
        midi_injected = true
      else
        Log.add_error(mref_err)
      end
    end
  end
  if not answer_only_followup and S.midi_ref_message then midi_injected = true end

  -- 3b. Gemini: kick off an async context cache create if eligible and no
  -- live cache exists yet. Non-blocking -- this send proceeds without the
  -- cache if it's not ready, and subsequent sends pick it up when it lands.
  if not answer_only_followup and PROVIDERS.active().id == "google" then
    Net.gemini_cache_ensure()
  end

  -- 3c. Theme auto-inject: detect requests to change REAPER's UI appearance.
  -- Two paths:
  --   A) Prompt contains "theme" + any color/appearance word.
  --   B) Prompt contains a REAPER UI element name + a color/appearance action.
  -- This avoids a context_needed round-trip. The model can also request the
  -- bucket explicitly via <context_needed>theme</context_needed>.
  local theme_injected = false
  if not answer_only_followup and not S.theme_already_sent then
    if Net.should_auto_inject_theme(user_text) then
      local th_content, th_err = CTX.theme()
      if th_content then
        S.theme_ref_message = th_content
          .. "\n\n(Theme reference is loaded above. Do NOT request "
          .. "<context_needed>theme</context_needed> or "
          .. "<context_needed>prompt_bundle:theme</context_needed> or "
          .. "<context_needed>session</context_needed> -- you have "
          .. "everything needed. Proceed directly with the color change code.)"
        Net.copin_theme_bundle()
        theme_injected = true
        S.theme_already_sent = true
      end
    end
  end
  if not answer_only_followup and S.theme_ref_message then theme_injected = true end

  -- Preemptive bucket injection. If the user's prompt mentions a plugin
  -- type they have a saved preferred plugin for ("add a compressor",
  -- "change the eq band 2 freq"), inject the preferred_plugins content
  -- into sticky_context right here so the model sees it on the FIRST
  -- API call. Saves one <context_needed> round trip in the common case.
  -- No-op when the user has no preferred_types configured or when their
  -- prompt mentions no matching keyword. See CTX.preempt_buckets_for_prompt.
  --
  -- Bump the turn counter and prune stale sticky_context entries first, so
  -- preempt's relevance-driven re-touches happen against a fresh state and
  -- this turn's adds don't get accidentally evicted by their own arrival.
  local active_provider = PROVIDERS.active()
  local active_model = MODELS[prefs.model_idx] or MODELS[1]
  local typed_action_profile =
    Code.typed_actions_model_profile(active_provider.id,
      active_model and active_model.id or nil)
  local typed_action_response_format =
    active_provider.id == "openai"
  local typed_action_plan_prompt =
    CTX.prompt_indicates_typed_action_plan(user_text)
  -- Contract eligibility is separate from execution eligibility. Auto-run and
  -- backup checks still gate execution below; Auto-run-off users should still
  -- get a reviewable structured edit instead of the heavier ReaScript path.
  local typed_action_contract =
    Code.typed_actions_prompt_contract(user_text, {
      response_format = typed_action_response_format,
      profile = typed_action_profile,
    })
  local reascript_prompt = false
  do
    local lt = user_text:lower()
    local edit_verb =
         lt:find("%f[%w]create%f[%W]") ~= nil
      or lt:find("%f[%w]add%f[%W]") ~= nil
      or lt:find("%f[%w]make%f[%W]") ~= nil
      or lt:find("%f[%w]insert%f[%W]") ~= nil
      or lt:find("%f[%w]rename%f[%W]") ~= nil
      or lt:find("%f[%w]delete%f[%W]") ~= nil
      or lt:find("%f[%w]remove%f[%W]") ~= nil
      or lt:find("%f[%w]route%f[%W]") ~= nil
      or lt:find("%f[%w]send%f[%W]") ~= nil
      or lt:find("%f[%w]split%f[%W]") ~= nil
      or lt:find("%f[%w]select%f[%W]") ~= nil
    local edit_noun =
         lt:find("%f[%w]track%f[%W]") ~= nil
      or lt:find("%f[%w]tracks%f[%W]") ~= nil
      or lt:find("%f[%w]item%f[%W]") ~= nil
      or lt:find("%f[%w]items%f[%W]") ~= nil
      or lt:find("%f[%w]marker%f[%W]") ~= nil
      or lt:find("%f[%w]region%f[%W]") ~= nil
      or lt:find("%f[%w]midi%f[%W]") ~= nil
      or lt:find("%f[%w]fx%f[%W]") ~= nil
      or lt:find("%f[%w]effect%f[%W]") ~= nil
      or lt:find("%f[%w]plugin%f[%W]") ~= nil
      or lt:find("%f[%w]send%f[%W]") ~= nil
      or lt:find("%f[%w]bus%f[%W]") ~= nil
      or lt:find("%f[%w]folder%f[%W]") ~= nil
      or lt:find("%f[%w]envelope%f[%W]") ~= nil
      or lt:find("%f[%w]automation%f[%W]") ~= nil
    local qna_prompt =
         lt:find("^%s*how%s+") ~= nil
      or lt:find("^%s*what%s+") ~= nil
      or lt:find("^%s*why%s+") ~= nil
      or lt:find("^%s*where%s+") ~= nil
      or lt:find("^%s*when%s+") ~= nil
      or lt:find("^%s*is%s+") ~= nil
      or lt:find("^%s*are%s+") ~= nil
    reascript_prompt =
         lt:find("reaper lua script", 1, true) ~= nil
      or lt:find("reascript", 1, true) ~= nil
      or lt:find("lua script", 1, true) ~= nil
      or (lt:find("write", 1, true) ~= nil
          and lt:find("script", 1, true) ~= nil
          and lt:find("reaper", 1, true) ~= nil)
      or (edit_verb and edit_noun and not qna_prompt)
      or Code.prompt_likely_needs_lua_action(user_text)
  end
  local preempted_context = nil
  if not answer_only_followup then
    Net.sticky_evict(user_text)
  end
  if not answer_only_followup
     and not typed_action_contract
     and not typed_action_plan_prompt then
    preempted_context = CTX.preempt_buckets_for_prompt(user_text)
  elseif typed_action_plan_prompt then
    Log.line("PREEMPT",
      "skipped context preempt (typed-action plan prompt)")
  end
  if preempted_context and #preempted_context > 0 then
    for _, key in ipairs(preempted_context) do
      if key == "recent_reaper_changes" then
        user_text = "(INTERNAL CONTEXT NOTE -- DO NOT MENTION THIS: "
          .. "Recent REAPER changes are pinned above. Use that bucket "
          .. "for recent or version-specific REAPER feature facts; it "
          .. "overrides stale training data.)\n\n" .. user_text
        break
      end
    end
  end
  if not typed_action_contract
     and not typed_action_plan_prompt
     and not answer_only_followup
     and reascript_prompt then
    if S.midi_ref_message
       and Code.prompt_has_midi_workflow_intent(user_text) then
      Log.line("PREEMPT",
        "skipped docs preempt (midi ref covers workflow)")
    else
      local docs_already = S.api_ref_message ~= nil
      Net.copin_docs_core(preempted_context)
      if not docs_already and S.api_ref_message then
        Log.line("PREEMPT",
          "injected docs (explicit ReaScript/Lua-script prompt)")
      end
    end
  end
  -- Re-evaluate ref-injected flags: preempt's copin_docs_core (and the
  -- chain-phrase preempt path generally) can set S.api_ref_message AFTER
  -- the initial ref_injected probe ran above. Without this, the ctx_label
  -- assembled below misses the "api_ref" tag for any session where docs
  -- was co-pinned only via the preempt path -- the request ships docs
  -- correctly but the Details / Context display omits it. Mirror midi /
  -- theme for symmetry (no preempt path sets them today, but future
  -- co-pin helpers should not need a second touch-up here).
  if not answer_only_followup and S.api_ref_message   then ref_injected   = true end
  if not answer_only_followup and S.midi_ref_message  then midi_injected  = true end
  if not answer_only_followup and S.theme_ref_message then theme_injected = true end

  -- 4. Build the history content: just "USER REQUEST:\n" + prompt.
  -- The API ref is no longer stored in history -- it lives in S.api_ref_message
  -- and is prepended by Net.build_body() on every call. Theme ref likewise
  -- lives in S.theme_ref_message.
  --
  -- Sticky context (plugin_ref, preferred_plugins, fx_params) is emitted by
  -- Net.build_body_* as a pinned user/assistant pair after the api_ref pin,
  -- rather than baked into each user message here. That way the content sits
  -- in a stable prefix position and the providers' caches treat it as part
  -- of the cached prefix, rather than re-writing it into every new turn's
  -- cache breakpoint.
  -- If the previous generated-code execution failed, prepend the error so
  -- the model can self-correct when the user types a follow-up like
  -- "fix that". Cleared after this send -- carrying it indefinitely would
  -- pollute unrelated subsequent prompts.
  -- Snapshot last_run_error before clearing so the two rollback blocks
  -- below can restore it. Without this, a token-budget overflow or
  -- fire_curl failure permanently loses the prior-run error context, so
  -- the next "fix that" retry would send the prompt with no error to fix.
  local _saved_last_run_error = S.last_run_error
  local history_text
  if S.last_run_error and S.last_run_error ~= "" then
    history_text = "PREVIOUS_RUN_ERROR (the code you generated last turn "
      .. "failed when executed):\n" .. S.last_run_error
      .. "\n\nUSER REQUEST:\n" .. user_text
    S.last_run_error = nil
  else
    history_text = "USER REQUEST:\n" .. user_text
  end

  do
    local latest_note = Code.latest_code_followup_note(user_text, {
      had_last_run_error = _saved_last_run_error ~= nil
        and _saved_last_run_error ~= "",
    })
    if latest_note then
      history_text = latest_note .. "\n\n" .. history_text
    end
  end

  if answer_only_followup then
    history_text = "(INTERNAL ANSWER-ONLY FOLLOW-UP NOTE -- DO NOT MENTION "
      .. "THIS: This is a conversational follow-up about prior output. "
      .. "Answer from the prior user and assistant messages actually present "
      .. "in this conversation. If you explain generated code or choices, "
      .. "cite the names, values, and operations that appear in the prior "
      .. "code or prose. Be explicit when a choice was a heuristic, and do "
      .. "not invent authoritative external rationale or claim a standard "
      .. "unless it was already established above. Do not ask for project "
      .. "snapshot, API docs, plugin refs, or other external context unless "
      .. "the user asks for a new edit.)\n\n" .. history_text
  end

  if not typed_action_contract and reascript_prompt then
    local ref_note = S.api_ref_message
      and (" Core REAPER API docs are already pinned above, so do NOT "
        .. "emit <context_needed>docs</context_needed>.")
      or ""
    history_text = "(INTERNAL OUTPUT NOTE -- DO NOT MENTION THIS: "
      .. "If you generate Lua/ReaScript for this request, return the "
      .. "entire runnable script inside one complete ```lua ... ``` "
      .. "code fence. Do not return bare Lua." .. ref_note .. ")\n\n"
      .. history_text
  end

  local screen_reader_summary_requested =
    S.screen_reader_mode and not typed_action_contract
  if screen_reader_summary_requested then
    history_text = "(INTERNAL SCREEN READER OUTPUT NOTE -- DO NOT MENTION "
      .. "THIS: Include one short plain-language summary line for the "
      .. "accessible UI in this exact XML-like form: "
      .. "<screen_reader_summary>Summary here.</screen_reader_summary>. "
      .. "Keep it under 16 words. If you generate runnable code, summarize "
      .. "what the code is for; do not claim it already ran. The user is "
      .. "using Screen Reader Mode and may be using a screen reader. Keep "
      .. "visible replies brief and plain: one or two short paragraphs, or "
      .. "at most three short bullets. Avoid Markdown formatting, headings, "
      .. "and long capability lists unless the user specifically asks. If "
      .. "you generate code, still include the complete runnable code block "
      .. "and keep surrounding prose short. Do not say Lua, JSFX, or action "
      .. "plans auto-run in Screen Reader Mode. Screen Reader Mode presents "
      .. "explicit Read or Save Code, Read or Save JSFX, or Read or Save "
      .. "Edit Details before Run Code, Add JSFX, or Run Edit buttons unless "
      .. "Auto-run is enabled. If asked to explain the safest Screen Reader "
      .. "Mode workflow, name those real controls, say to read/review first, "
      .. "then use Run Code, Add JSFX, or Run Edit only if it matches the "
      .. "request. Undo appears only after a run, add, or apply succeeds. Do "
      .. "not invent UI details such as a Save to file button, a scrollable "
      .. "text area label, a script-name label, or guaranteed ReaAssist "
      .. "comments in all code.)\n\n"
      .. history_text
  end

  if not typed_action_contract
     and type(preempted_context) == "table"
     and #preempted_context > 0 then
    local seen_resolve, resolved_tags = {}, {}
    for _, key in ipairs(preempted_context) do
      if type(key) == "string" then
        local tkey = key:match("^pref:(.+)$")
        if tkey and not seen_resolve[tkey] then
          seen_resolve[tkey] = true
          resolved_tags[#resolved_tags + 1] = "resolve:" .. tkey
        end
      end
    end
    if #resolved_tags > 0 then
      table.sort(resolved_tags)
      history_text = "(INTERNAL CONTEXT NOTE -- DO NOT MENTION THIS: "
        .. "The generic plugin type(s) for this request are already "
        .. "resolved and pinned above: " .. tbl_concat(resolved_tags, ", ")
        .. ". Do NOT emit <context_needed> for these resolve tags. "
        .. "Use the pinned plugin_ref / preferred-plugin content now.)\n\n"
        .. history_text
    end
  end

  if typed_action_contract then
    history_text = history_text .. "\n\n" .. typed_action_contract
    S.pending_typed_action_expected = true
    S.pending_typed_action_response_format = typed_action_response_format
    S.pending_typed_action_profile =
      typed_action_profile and typed_action_profile.key or nil
  end

  -- Collect sticky labels for the Show Details display (the content itself
  -- is emitted downstream by build_body_*).
  local custom_instr_blob = Net.custom_instructions_prompt_block_for_request()
  local sticky_labels = {}
  if not answer_only_followup then
    for key, _ in pairs(S.sticky_context) do
      sticky_labels[#sticky_labels+1] = key
    end
  end

  -- Context label for Show Details display.
  local ctx_parts = {}
  if answer_only_followup then
    ctx_parts[#ctx_parts+1] = "answer-only follow-up"
    ctx_parts[#ctx_parts+1] = "refs/snapshot suppressed"
  elseif prefs.include_snapshot and not S.pending_answer_only_followup then
    ctx_parts[#ctx_parts+1] = "snapshot"
  end
  if screen_reader_summary_requested then
    ctx_parts[#ctx_parts+1] = "screen_reader"
  end
  if ref_injected   then ctx_parts[#ctx_parts+1] = "api_ref" end
  if midi_injected  then ctx_parts[#ctx_parts+1] = "midi"    end
  if theme_injected then ctx_parts[#ctx_parts+1] = "theme"   end
  if custom_instr_blob then ctx_parts[#ctx_parts+1] = "custom_instr" end
  if typed_action_contract then ctx_parts[#ctx_parts+1] = "typed_actions" end
  if msg_attachments then
    for _, a in ipairs(msg_attachments) do ctx_parts[#ctx_parts+1] = a.name end
  end
  -- Append sticky context labels so Show Details reflects what was re-injected.
  table.sort(sticky_labels)
  for _, lbl in ipairs(sticky_labels) do ctx_parts[#ctx_parts+1] = lbl end
  local ctx_label = #ctx_parts > 0 and tbl_concat(ctx_parts, " + ") or "none"

  -- Push to history (without snapshot) and display (bare prompt).
  S.history[#S.history+1] = { role = "user", content = history_text }
  local suppress_user_display = S.suppress_user_display_once
  S.suppress_user_display_once = nil
  local disp_idx = #S.display_messages + 1
  -- Build a summary of attachments for display in the chat bubble.
  local attach_summary = nil
  if msg_attachments then
    local parts = {}
    for _, a in ipairs(msg_attachments) do
      parts[#parts+1] = a.name
    end
    attach_summary = parts
  end
  S.display_messages[disp_idx] = {
    role           = "user",
    content        = user_text,
    ctx_label      = ctx_label,
    model_label    = PROVIDERS.active().label .. " " .. (function()
      -- Fall back to MODELS[1] (or "?") when MODELS[prefs.model_idx] is
      -- nil. Indexing nil here used to throw on a custom provider whose
      -- models array was cleared mid-session, or briefly after a
      -- provider switch where prefs.model_idx temporarily points past
      -- the new provider's list before MODELS.refresh re-clamps it.
      local _m = MODELS[prefs.model_idx] or MODELS[1]
      return _m and _m.label or "?"
    end)(),
    provider_id    = PROVIDERS.active().id,
    thinking_label = (function()
      local p = PROVIDERS.active()
      if p.thinking_levels and prefs.thinking_idx > 0 then
        local tl = p.thinking_levels[prefs.thinking_idx]
        if tl then return tl.label end
      end
    end)(),
    attach_names   = attach_summary,
    from_card      = S.from_card or nil,
    hidden                  = suppress_user_display or nil,
    local_retry_escalation  = suppress_user_display or nil,
  }
  S.from_card = false
  S.pending_display_idx = disp_idx

  -- 5. Preflight token estimation: abort before sending if the request would
  -- exceed the model's context window. Uses a ~4 chars/token heuristic; false
  -- positives are acceptable -- better to warn than waste API time. For
  -- attachments, add their estimated token counts directly.
  --
  -- Per-model context_window on the active model wins. Built-in providers
  -- now carry context_window on each model entry where it differs from the
  -- 200K default (Sonnet/Opus 1M, GPT-5.4 mini 400K, GPT-5.6 1.05M,
  -- Gemini 3.x 1,048,576, DeepSeek V4 Flash 1M); a provider-level
  -- field is honored as a fallback if a model row omits it. Custom
  -- providers always carry context_window per-model (set by the user on
  -- the API Keys page from each loaded model's actual server-side limit;
  -- exceeding it on a local llama.cpp server either truncates the prompt
  -- or starts evicting tokens from the front of the cache). Final fallback
  -- is 200K, the floor every cloud provider we ship still honors. A model
  -- without context_window AND a provider with no fallback (e.g. Claude
  -- Haiku 4.5) lands on the 200K default.
  local active_provider     = PROVIDERS.active()
  local active_model        = MODELS[prefs.model_idx] or MODELS[1]
  local MODEL_CONTEXT_LIMIT = (active_model and tonumber(active_model.context_window))
                              or tonumber(active_provider.context_window)
                              or 200000
  local CHARS_PER_TOKEN     = 4       -- ~4 for prose, ~3 for code, ~5 for JSON keys; 4 is a safe middle
  -- Probe timing: preempt ends here. body_build is
  -- timed inside Net.build_body itself (entry/exit wrap), so the
  -- gap between mark_phase_end("preempt") and Net.build_body's
  -- internal mark_phase_start("body_build") is negligible.
  Probe.mark_phase_end(probe_turn, "preempt")
  -- Gemini explicit cache eligibility can appear late in preempt: the
  -- ReaScript prompt path may co-pin API docs after the early ensure above.
  -- Re-check here, once all static refs for this request are settled.
  if not answer_only_followup and PROVIDERS.active().id == "google" then
    Net.gemini_cache_ensure()
  end
  local body = Net.build_body(Net.trimmed_history(), snapshot, msg_attachments)
  -- Probe byte accounting for the request body.
  -- Pre-escape source bytes (raw strings before JSON encoding inflates
  -- them) for each known source bucket, plus the final assembled
  -- JSON body bytes. Captures only the initial request -- multi-request
  -- turns (context_needed re-fires, retries) re-build the body with
  -- inline build_body calls and are NOT accumulated here. body_build
  -- phase latency does accumulate across all such calls (instrumented
  -- inside Net.build_body itself).
  do
    local sys = Net.system_prompt_text()
    if sys then
      local sys_bytes = #sys
      if custom_instr_blob then
        sys_bytes = math_max(0, sys_bytes - #custom_instr_blob)
      end
      if sys_bytes > 0 then
        Probe.add_bytes(probe_turn, "system_prompt", sys_bytes)
      end
    end
    local static_total = 0
    if not answer_only_followup and S.api_ref_message then
      static_total = static_total + #S.api_ref_message
    end
    if not answer_only_followup and S.midi_ref_message then
      static_total = static_total + #S.midi_ref_message
    end
    if not answer_only_followup and S.theme_ref_message then
      static_total = static_total + #S.theme_ref_message
    end
    if static_total > 0 then Probe.add_bytes(probe_turn, "static_refs", static_total) end
    if custom_instr_blob then
      Probe.add_bytes(probe_turn, "custom_instructions", #custom_instr_blob)
    end
    local sticky_total = 0
    if not answer_only_followup then
      for _, content in pairs(S.sticky_context or {}) do
        if type(content) == "string" then
          sticky_total = sticky_total + #content
        end
      end
    end
    if sticky_total > 0 then Probe.add_bytes(probe_turn, "sticky_refs", sticky_total) end
    if snapshot then Probe.add_bytes(probe_turn, "snapshot", #snapshot) end
    if msg_attachments then
      local att_total = 0
      for _, a in ipairs(msg_attachments) do
        if a.b64       then att_total = att_total + #a.b64
        elseif a.data  then att_total = att_total + #a.data
        end
      end
      if att_total > 0 then Probe.add_bytes(probe_turn, "attachments", att_total) end
    end
    Probe.set_body_total(probe_turn, #body)
  end
  local estimated_tokens = Net.estimate_request_tokens_from_body(body)
  -- Base64 inflates size ~33%, so compensate: attachment tokens are more accurate
  -- than the chars/4 heuristic on the inflated base64. Subtract the base64 size
  -- contribution and add the pre-computed token estimates instead.
  --
  -- Text attachments are inlined into the body as raw UTF-8 (not base64), so
  -- they are ALREADY counted by the #body/4 heuristic above. Re-adding a.tokens
  -- for text attachments would double-count them and trigger false-positive
  -- context overflows for large pasted logs. Skip them here.
  --
  -- Read the contribution from a.b64 (the encoded string actually inlined into
  -- the body), NOT a.data: Attach.pump_encoding nils out a.data once encoding
  -- is complete to avoid carrying two copies of large attachments in memory.
  if msg_attachments then
    for _, a in ipairs(msg_attachments) do
      if a.kind ~= "text" and a.b64 then
        local b64_chars_est = math_floor(#a.b64 / CHARS_PER_TOKEN)
        estimated_tokens = estimated_tokens - b64_chars_est + a.tokens
      end
    end
  end
  -- Reserve output space inside the context window. Each cloud model has
  -- its own published output ceiling (max_output, 64K-128K); reserve that
  -- so a maxed-out reply doesn't blow the model's context window. Custom
  -- local LLMs often have tight context windows (16K-32K) where reserving
  -- the full output cap would leave almost no room for the API ref + prompt
  -- -- cap the reserve at 10% of context. The custom server enforces its
  -- own real limit (finish_reason=length if output overflows), so the reserve
  -- only needs to guarantee a short reply has room.
  local cloud_output_cap = (active_model and tonumber(active_model.max_output)) or 16384
  local output_reserve = active_provider.is_custom
    and math_min(cloud_output_cap, math_floor(MODEL_CONTEXT_LIMIT * 0.1))
    or cloud_output_cap
  local token_budget   = MODEL_CONTEXT_LIMIT - output_reserve

  if estimated_tokens > token_budget then
    -- Roll back the history and display entries we just pushed, AND restore the
    -- user's typed prompt + attachments to the input area so they don't lose
    -- their work. The user can trim attachments or clear and retry without
    -- re-typing.
    S.history[#S.history]          = nil
    tbl_remove(S.display_messages, disp_idx)
    S.pending_display_idx        = nil
    S.status    = "error"
    S.send_time = nil
    S.input_buf = user_text
    if msg_attachments then S.attachments = msg_attachments end
    -- Clear the pending_* / event-tracking state populated earlier in this
    -- function (lines ~16555-16585) so a context-needed handler firing later
    -- doesn't pick up stale snapshot/project/prompt from a turn that never
    -- actually sent. The _already_sent resets at ~16549-16580 are
    -- intentionally left applied; the next attempt should re-run those
    -- buckets fresh.
    S.pending_orig_prompt  = nil
    S.pending_typed_action_expected = false
    S.pending_typed_action_response_format = false
    S.pending_typed_action_profile = nil
    S.pending_answer_only_followup = nil
    S.pending_project      = nil
    S.pending_snapshot     = nil
    S.pending_attachments  = nil
    S._fx_cache_events     = nil
    -- Restore last_run_error so a "fix that" retry still has the prior-run
    -- error context.
    S.last_run_error       = _saved_last_run_error
    Log.add_error(str_format(
      "Your message is too large to send (about %dk tokens, limit is ~%dk)."
      .. "\n\nYour message and attachments have been restored to the input box. "
      .. "To make it fit:\n"
      .. "- Remove large attachments\n"
      .. "- Turn off \"Always include REAPER API reference\" or Send snapshot to reduce size\n"
      .. "- Or click + new chat to start fresh",
      math_floor(estimated_tokens / 1000),
      math_floor(token_budget / 1000)))
    S.scroll_to_bottom = true
    -- Probe lifecycle: turn aborted before any HTTP traffic.
    Probe.end_turn(probe_turn, "aborted")
    S.probe_turn = nil
    return
  end

  -- 6. Fire the API call (reuse the body already built by the preflight check).
  local fired, fire_reason = Net.fire_curl(body)
  if not fired then
    -- Roll back on failure and restore the user's input so they can retry.
    S.history[#S.history]          = nil
    tbl_remove(S.display_messages, disp_idx)
    S.pending_display_idx        = nil
    S.status    = "error"
    S.send_time = nil
    S.input_buf = user_text
    if msg_attachments then S.attachments = msg_attachments end
    -- Clear pending_* / event-tracking state and restore last_run_error;
    -- mirrors the token-budget rollback above.
    S.pending_orig_prompt  = nil
    S.pending_typed_action_expected = false
    S.pending_typed_action_response_format = false
    S.pending_typed_action_profile = nil
    S.pending_answer_only_followup = nil
    S.pending_project      = nil
    S.pending_snapshot     = nil
    S.pending_attachments  = nil
    S._fx_cache_events     = nil
    S.last_run_error       = _saved_last_run_error
    if fire_reason ~= "call_cap_exceeded" then
      Log.add_error(
        "Couldn't send. Another request may still be in progress. "
        .. "Wait a moment and try again.")
    end
    -- Probe lifecycle: turn ended at fire_curl failure. No
    -- early-return here -- the original code falls through to the
    -- shared scroll_to_bottom assignment, so we let it. The natural-
    -- end Probe.end_turn below is idempotent and a no-op after this.
    Probe.end_turn(probe_turn, "error")
    S.probe_turn = nil
  end

  S.scroll_to_bottom = true
  -- Probe lifecycle note: on the success path of send_to_api, the turn
  -- is NOT ended here. The request was just
  -- handed off to curl; the response is still pending. The turn
  -- handle stays alive on S.probe_turn and is ended at the canonical
  -- "turn completed successfully" site inside Net.try_finish_curl.
  -- Error/cancel exit paths close it at their own branch points.
end

function Net.resend_saved_prompt(user_text, attachments)
  user_text = tostring(user_text or ""):match("^%s*(.-)%s*$")
  if user_text == "" then return false, "No saved message to resend." end
  local queued = S.attachments or {}
  S.attachments = type(attachments) == "table" and attachments or {}
  local ok, err = pcall(Net.send_to_api, user_text)
  S.attachments = queued
  if not ok then
    return false, tostring(err or "Could not resend the message.")
  end
  return true
end

-- =============================================================================
-- Net.clear_conversation
-- =============================================================================
-- Resets all conversation, token, cost, and pending state. The API reference
-- file content cache is preserved (file doesn't change). S.api_ref_message is
-- cleared so it is re-pinned on the next send; the Gemini explicit cache is
-- app-scoped static reference state and remains usable when its source
-- signature still matches.
function Net.clear_conversation(opts)
  local clear_gemini_cache =
    type(opts) == "table" and opts.clear_gemini_cache == true
  -- =========================================================================
  -- CLEAR CONVERSATION -- reset every conversation-scoped piece of S.* state.
  -- =========================================================================
  -- IMPORTANT: When you add a new conversation-scoped field to S (anything
  -- that grows with messages, tracks per-turn flags, holds pending follow-up
  -- data, or accumulates session totals like token/cost counters), add it
  -- below. Do NOT add app-scoped state here (UI prefs, model picks, cache
  -- warmth, network in-flight tracking) -- those should survive a chat clear.
  -- =========================================================================
  -- Conversation history + display
  if Diag.uploader_enabled and Diag.capture_current_chat then
    Diag.capture_current_chat()
  end
  S.history              = {}
  S.display_messages     = {}
  S.sticky_context       = {}
  S.sticky_context_age   = {}
  S.sticky_context_order = {}
  -- Per-key source tag: "preempt" (pinned by CTX.preempt_buckets_for_prompt
  -- in the same pre-request batch as other stable bundles), "copin" (pinned
  -- by a deterministic mid-flow path like the dispatcher write-intent paths
  -- or the helper-validator retry), or "context_needed" (pulled in response
  -- to a model <context_needed> tag). Drives the prompt_bundle:plugin_helpers
  -- routing in Net.sticky_parts: only "preempt" promotes helpers to the
  -- stable rung; the others keep helpers in the growing rung where mid-
  -- session pins don't invalidate the bigger stable bundle.
  S.sticky_pin_source    = {}
  S.turn_counter         = 0
  S.history_trim_start   = nil
  S.last_run_error       = nil
  S.lua_defer_run        = nil
  -- Pending follow-up state (mid-flight when clear is hit)
  Net._restore_typed_action_escalation_model()
  S.pending_code         = nil
  S.pending_orig_prompt  = nil
  S.pending_typed_action_expected = false
  S.pending_typed_action_response_format = false
  S.pending_typed_action_profile = nil
  S.pending_answer_only_followup = nil
  S.pending_snapshot     = nil
  S.pending_project      = nil
  S.pending_display_idx  = nil
  S.pending_resolves          = {}
  S.pending_plugin_ref_names  = {}
  S.pending_pref_plugin_types = {}
  S.pending_attachments       = nil
  S.pending_provider_idx      = nil
  S.pending_model_idx         = nil
  S.pending_thinking_idx      = nil
  S.pending_jsfx_intent       = nil
  S.pending_drum_edit_intent  = nil
  -- Per-turn one-shot guards
  S.docs_already_sent          = false
  S.docs_extended_already_sent = false
  S.docs_section_sent          = {}
  S.session_already_sent       = false
  S.tracks_already_sent        = false
  S.fx_params_already_sent     = false
  S.fx_list_already_sent       = false
  S.fx_chains_already_sent     = false
  S.track_flags_already_sent   = false
  S.midi_already_sent          = false
  S.theme_already_sent         = false
  S.fx_inspect_already_sent    = false
  S.plugin_ref_sent            = {}
  S.pref_plugins_sent          = {}
  Net._clear_turn_budget_confirmation()
  S.reset_turn_retries()
  S._context_reuse_hint        = nil
  S._irrelevant_context_hint   = nil
  S._timecode_context_hint     = nil
  S._jsfx_context_hint         = nil
  S._mixed_output_hint         = nil
  S._fx_inspect_dropped        = nil
  -- Defensive clear of fx_inspect -> fx_params handoff state (also reset per
  -- send_to_api; mirroring here keeps mid-flow clears from poisoning the
  -- next conversation).
  S._fx_params_pending_assemble       = nil
  S._fx_inspect_silent_for_fx_params  = nil
  S._resolve_deep_scan_attempted      = nil
  -- Pinned ref slots -- force reload on next send if relevant prefs are on
  S.api_ref_message      = nil
  S.midi_ref_message     = nil
  S.theme_ref_message    = nil
  -- Session-level docs flag: cleared with the chat since history (where the
  -- inlined docs content lived) is about to be wiped. Next send will either
  -- re-pin via the pref or wait for the model to re-request docs.
  S.docs_fetched_session = false
  -- Prompt bundles live in the sticky context, which this clear wipes --
  -- reset the sent-set to match. Leaving it populated made the dispatcher
  -- tell the model a bundle was "already present in PINNED REFERENCES"
  -- after "+ New Chat" when it no longer was, and loop detection's
  -- had_sticky check read the same stale set.
  S.prompt_bundle_sent = {}
  -- Resolve popup state (could be open mid-clear; close it cleanly)
  S.resolve_popup             = nil
  S.open_resolve_popup        = false
  S.resolve_popup_text        = ""
  S.resolve_popup_error       = nil
  S.resolve_popup_matches     = {}
  S.resolve_popup_sel         = 0
  S.resolve_popup_last_filter = nil
  S.resolve_popup_refocus     = false
  -- Keep app-scoped Gemini static-reference caches across chat clears. They
  -- contain only the system prompt + API reference, not user conversation
  -- content, and Net.gemini_cache_is_usable verifies the source signature
  -- before reuse. Explicit test/reset paths can still force invalidation.
  if clear_gemini_cache then
    Net.gemini_cache_invalidate()
  end
  -- Session totals
  S.session_tok_in       = 0
  S.session_tok_out      = 0
  S.session_cost         = 0
  -- Retry / attachment state
  S.retry_count          = 0
  S.retry_max            = CFG.MAX_RETRIES
  S.retry_scheduled      = false
  S.retry_saved_body     = nil
  S.retry_saved_provider_idx = nil
  S.retry_saved_model_idx    = nil
  S.retry_saved_thinking_idx = nil
  S.attachments          = {}
  S.attach_error         = nil
  S.attach_error_time    = 0
  -- UI / status
  S.status               = "idle"
  S.scroll_to_bottom     = true
  S.wrap_cache           = {}  -- invalidate per-bubble text-wrap cache
  Code.safe_write(tmp.out, "")
  -- Diag uploader: rotate chat_id so subsequent feedback events from this
  -- new conversation group correctly. Guarded by the same uploader_enabled
  -- gate the main-loop Diag.tick() call uses (module may be disabled / not
  -- loaded if RA.JSON wasn't available at dofile time).
  if Diag.uploader_enabled then
    Diag.rotate_chat_id()
  end
end

-- =============================================================================
-- CodeRuntime sidecar load (eager, fail-closed)
-- =============================================================================
-- Loads generated-code validation/execution into a narrow environment. If it
-- cannot load, chat and recovery still start, but generated-code run paths and
-- typed-action paths are blocked before any validators can be bypassed.
RA.CodeRuntime = RA.CodeRuntime or { loaded = false, error = nil }

function RA.code_runtime_unavailable_message(action)
  local suffix = action and tostring(action) or "before running generated code"
  return "Code runtime unavailable; repair or update ReaAssist " .. suffix .. "."
end

function RA.code_runtime_loaded()
  return RA.CodeRuntime and RA.CodeRuntime.loaded == true
end

function RA.fail_code_runtime_unavailable(action, status)
  local msg = RA.code_runtime_unavailable_message(action)
  if Log and Log.add_error then Log.add_error(msg) end
  if S then
    S.status = status or "idle"
    S.scroll_to_bottom = true
  end
  return false
end

function RA.install_code_runtime_fallbacks(reason)
  RA.CodeRuntime = RA.CodeRuntime or {}
  RA.CodeRuntime.loaded = false
  RA.CodeRuntime.error = tostring(reason or "unknown error")

  -- Keep UI/status call sites safe in degraded mode while every generated-code
  -- or typed-action path reports a blocked runtime.
  function Code.classify_lua_artifact()
    return {
      kind = "unknown",
      runnable = false,
      manual_run_only = true,
      reason = "code_runtime_unavailable",
    }
  end

  function Code.lua_artifact_block_message()
    return RA.code_runtime_unavailable_message("before running generated code")
  end

  function Code.scan_risky()
    return RA.code_runtime_unavailable_message("before scanning generated code")
  end

  function Code.scan_forbidden_sandbox_globals()
    return RA.code_runtime_unavailable_message("before scanning generated code")
  end

  function Code.run()
    return RA.fail_code_runtime_unavailable("before running generated code", "idle")
  end

  function Code.safety_backup()
    return nil, "code_runtime_unavailable"
  end

  function Code.safety_backup_can_proceed(err)
    return err == nil or err == "unchanged"
  end

  function Code.apply_run_result_to_message(msg)
    if type(msg) == "table" then
      msg.run_status = "blocked"
      msg.run_error = RA.code_runtime_unavailable_message("before running generated code")
      msg.auto_ran = false
    end
  end

  function Code.validate_jsfx()
    return {{
      severity = "fatal",
      code = "code_runtime_unavailable",
      line = 1,
      message = RA.code_runtime_unavailable_message("before validating JSFX"),
    }}
  end

  function Code.jsfx_findings_have_gate()
    return true
  end

  function Code.inspect_typed_actions()
    return {
      present = false,
      valid = false,
      action_count = 0,
      reason = "code_runtime_unavailable",
    }
  end

  function Code.typed_actions_user_failure_message()
    return RA.code_runtime_unavailable_message("before applying structured edits")
  end

  function Code.typed_actions_display_text()
    return RA.code_runtime_unavailable_message("before displaying structured edits")
  end

  function Code.typed_actions_artifact_text()
    return nil
  end

  function Code.typed_actions_action_count()
    return 0
  end

  function Code.typed_actions_op_counts_text()
    return ""
  end

  function Code.typed_actions_kind_label()
    return "Structured edit"
  end
end

function RA.load_code_runtime()
  RA.CodeRuntime = RA.CodeRuntime or {}
  local path = RA.RESOURCES_DIR .. "CodeRuntime.lua"
  -- CodeRuntime uses JSON for typed-action extraction; pass it explicitly
  -- because JSON is local to this chunk.
  local env = setmetatable({ JSON = JSON }, { __index = _G })
  local chunk, load_err = loadfile(path, "t", env)
  if not chunk then
    RA.install_code_runtime_fallbacks(load_err)
    return false
  end
  local ok, err = pcall(chunk)
  if ok then
    RA.CodeRuntime.loaded = true
    RA.CodeRuntime.error = nil
    return true
  end
  RA.install_code_runtime_fallbacks(err)
  return false
end

RA.load_code_runtime()
-- =============================================================================
-- Code.tokenize_lua  /  Code.tokenize_jsfx
-- =============================================================================
-- Lightweight syntax highlighter for the chat code blocks. Used by default
-- for every code block until the user clicks the per-block Edit button to
-- switch that block to a plain editable widget. The tokenizer walks the source
-- character by character (no PCRE/lpeg) and emits a flat list of {type, text} tokens that
-- the renderer then paints with TextColored + SameLine. Token text may span
-- newlines (long strings, block comments) -- the renderer slices on \n.
--
-- Token types: "kw" (keyword), "str" (string), "num", "com" (comment),
--              "api" (known library: reaper, ImGui, math, ...), "id", "ws",
--              "other" (operators / punctuation -- rendered in default color).
--
-- Limitations on purpose (keep the tokenizer ~120 lines):
--   * No nested long brackets [==[ ... ]==] -- only [[ ... ]] is recognised.
--   * No multi-character escape parsing inside strings; we just walk past \X.
--   * JSFX/EEL gets a separate, simpler tokenizer (//, /* */, # for hex).
local LUA_KEYWORDS = {
  ["and"]=1, ["break"]=1, ["do"]=1, ["else"]=1, ["elseif"]=1, ["end"]=1,
  ["false"]=1, ["for"]=1, ["function"]=1, ["goto"]=1, ["if"]=1, ["in"]=1,
  ["local"]=1, ["nil"]=1, ["not"]=1, ["or"]=1, ["repeat"]=1, ["return"]=1,
  ["then"]=1, ["true"]=1, ["until"]=1, ["while"]=1,
}
local LUA_API_NAMES = {
  reaper=1, ImGui=1, gfx=1, math=1, string=1, table=1, io=1, os=1,
  bit=1, debug=1, coroutine=1, package=1, _G=1, _ENV=1,
  ipairs=1, pairs=1, next=1, select=1, type=1, tostring=1, tonumber=1,
  pcall=1, xpcall=1, error=1, assert=1, print=1, require=1, setmetatable=1,
  getmetatable=1, rawget=1, rawset=1, rawequal=1, rawlen=1, unpack=1,
  load=1, loadstring=1, loadfile=1, dofile=1,
}

-- Detects a Lua long-bracket open at position i. Returns the level (number of
-- "=" between the brackets) if `[`, optional `=...`, `[` is present, else nil.
-- Used by the tokenizer to handle [[...]], [=[...]=], [==[...]==], etc.
local function _long_bracket_open_level(src, i)
  if src:sub(i, i) ~= "[" then return nil end
  local j = i + 1
  while src:sub(j, j) == "=" do j = j + 1 end
  if src:sub(j, j) ~= "[" then return nil end
  return j - i - 1
end

function Code.tokenize_lua(src)
  local tokens = {}
  local i, n = 1, #src
  while i <= n do
    local c = src:sub(i, i)
    -- Whitespace run (preserve verbatim so indentation lines up).
    if c == " " or c == "\t" or c == "\n" or c == "\r" then
      local j = i + 1
      while j <= n do
        local cj = src:sub(j, j)
        if cj ~= " " and cj ~= "\t" and cj ~= "\n" and cj ~= "\r" then break end
        j = j + 1
      end
      tokens[#tokens+1] = { type = "ws", text = src:sub(i, j - 1) }
      i = j
    -- Block comment --[[ ... ]] (or --[=[ ... ]=], --[==[ ... ]==], etc.)
    elseif c == "-" and src:sub(i + 1, i + 1) == "-"
       and _long_bracket_open_level(src, i + 2) then
      local lvl   = _long_bracket_open_level(src, i + 2)
      local close = src:find("]" .. ("="):rep(lvl) .. "]",
        i + 2 + lvl + 1, true)
      local stop  = close and (close + lvl + 1) or n
      tokens[#tokens+1] = { type = "com", text = src:sub(i, stop) }
      i = stop + 1
    -- Line comment --
    elseif c == "-" and src:sub(i + 1, i + 1) == "-" then
      local nl   = src:find("\n", i, true)
      local stop = nl and (nl - 1) or n
      tokens[#tokens+1] = { type = "com", text = src:sub(i, stop) }
      i = stop + 1
    -- Long-bracket string [[ ... ]] (or [=[ ... ]=], [==[ ... ]==], etc.)
    elseif c == "[" and _long_bracket_open_level(src, i) then
      local lvl   = _long_bracket_open_level(src, i)
      local close = src:find("]" .. ("="):rep(lvl) .. "]",
        i + lvl + 2, true)
      local stop  = close and (close + lvl + 1) or n
      tokens[#tokens+1] = { type = "str", text = src:sub(i, stop) }
      i = stop + 1
    -- Quoted string ('...' or "...")
    elseif c == '"' or c == "'" then
      local quote = c
      local j = i + 1
      while j <= n do
        local cj = src:sub(j, j)
        if cj == "\\" then
          j = j + 2
        elseif cj == quote then
          j = j + 1
          break
        elseif cj == "\n" then
          break  -- unterminated; stop at newline
        else
          j = j + 1
        end
      end
      tokens[#tokens+1] = { type = "str", text = src:sub(i, j - 1) }
      i = j
    -- Number (hex, decimal, optional fractional and exponent parts).
    elseif c:match("%d") then
      local rest = src:sub(i)
      local num  = rest:match("^0[xX][%dA-Fa-f]+") or
                   rest:match("^%d+%.?%d*[eE][%+%-]?%d+") or
                   rest:match("^%d+%.?%d*")
      if num and #num > 0 then
        tokens[#tokens+1] = { type = "num", text = num }
        i = i + #num
      else
        tokens[#tokens+1] = { type = "other", text = c }
        i = i + 1
      end
    -- Identifier or keyword.
    elseif c:match("[_%a]") then
      local rest  = src:sub(i)
      local ident = rest:match("^[_%a][_%w]*") or c
      local ttype
      if LUA_KEYWORDS[ident] then
        ttype = "kw"
      elseif LUA_API_NAMES[ident] then
        ttype = "api"
      else
        ttype = "id"
      end
      tokens[#tokens+1] = { type = ttype, text = ident }
      i = i + #ident
      -- Chain api highlight through dotted accesses so
      -- "reaper.InsertTrackAtIndex" renders the whole path in fn_amber,
      -- not just the module prefix. Tags the ".method" tail as api too.
      if ttype == "api" then
        while i <= n and src:sub(i, i) == "." do
          local next_ident = src:sub(i + 1):match("^[_%a][_%w]*")
          if not next_ident then break end
          tokens[#tokens+1] = { type = "api", text = "." }
          tokens[#tokens+1] = { type = "api", text = next_ident }
          i = i + 1 + #next_ident
        end
      end
    -- Anything else: single-char "other" token (operators, punctuation).
    else
      tokens[#tokens+1] = { type = "other", text = c }
      i = i + 1
    end
  end
  return tokens
end

local JSFX_KEYWORDS = {
  ["if"]=1, ["else"]=1, ["while"]=1, ["loop"]=1, ["function"]=1,
  ["local"]=1, ["global"]=1, ["instance"]=1, ["this"]=1,
}

function Code.tokenize_jsfx(src)
  -- Each token: { type, text, pos, line, col }. Line/col track the original
  -- source so static-validator rules report findings at user-readable
  -- positions. Types: ws, com, str, num, kw (JSFX_KEYWORDS + @sections),
  -- id, other.
  local tokens = {}
  local i, n = 1, #src
  local line, col = 1, 1
  local function advance(len)
    for k = i, i + len - 1 do
      if src:sub(k, k) == "\n" then line = line + 1; col = 1
      else col = col + 1 end
    end
    i = i + len
  end
  while i <= n do
    local sl, sc, sp = line, col, i
    local c = src:sub(i, i)
    local tok
    if c == " " or c == "\t" or c == "\n" or c == "\r" then
      local j = i
      while j <= n and src:sub(j, j):match("[ \t\n\r]") do j = j + 1 end
      tok = { type = "ws", text = src:sub(i, j - 1) }; advance(j - i)
    elseif c == "/" and src:sub(i + 1, i + 1) == "*" then
      local close = src:find("*/", i + 2, true)
      local stop = close and (close + 1) or n
      tok = { type = "com", text = src:sub(i, stop) }; advance(stop - i + 1)
    elseif c == "/" and src:sub(i + 1, i + 1) == "/" then
      local nl = src:find("\n", i, true)
      local stop = nl and (nl - 1) or n
      tok = { type = "com", text = src:sub(i, stop) }; advance(stop - i + 1)
    elseif c == "@" then
      local sect = src:sub(i):match("^@%w+") or "@"
      tok = { type = "kw", text = sect }; advance(#sect)
    elseif c == '"' or c == "'" then
      local q = c
      local j = i + 1
      while j <= n do
        local cj = src:sub(j, j)
        if cj == "\\" then j = j + 2
        elseif cj == q then j = j + 1; break
        elseif cj == "\n" then break
        else j = j + 1 end
      end
      tok = { type = "str", text = src:sub(i, j - 1) }; advance(j - i)
    elseif c:match("%d") then
      local rest = src:sub(i)
      local num = rest:match("^0[xX][%dA-Fa-f]+")
               or rest:match("^%d+%.?%d*[eE][%+%-]?%d+")
               or rest:match("^%d+%.?%d*")
      if num and #num > 0 then
        tok = { type = "num", text = num }; advance(#num)
      else
        tok = { type = "other", text = c }; advance(1)
      end
    elseif c:match("[_%a]") then
      local ident = src:sub(i):match("^[_%a][_%w]*") or c
      tok = {
        type = JSFX_KEYWORDS[ident] and "kw" or "id",
        text = ident,
      }; advance(#ident)
    else
      tok = { type = "other", text = c }; advance(1)
    end
    tok.line, tok.col, tok.pos = sl, sc, sp
    tokens[#tokens + 1] = tok
  end
  return tokens
end

-- =============================================================================
-- Code.validate_jsfx
-- =============================================================================
-- Defined in Resources/CodeRuntime.lua; tokenizers above stay here for UI
-- syntax highlighting.

-- =============================================================================
-- Net.process_response_buckets: handle <context_needed> on-demand buckets
-- =============================================================================
-- Parses any <context_needed>...</context_needed> tag in the model response and,
-- if fresh bucket data is needed, assembles the enriched history and fires a
-- follow-up curl request. Returns true when the follow-up was fired (caller
-- should bail); false when the normal final-response path should continue.
function Net.process_response_buckets(text)
  if not RA.code_runtime_loaded() then
    return RA.fail_code_runtime_unavailable("while processing context requests", "idle")
  end
  if not RA.context_loaded() then
    return RA.fail_context_unavailable("while processing context requests", "idle")
  end

  -- Handle <context_needed> on-demand buckets: session, docs, plugin_ref,
  -- fx_params:Name[, Name2]. Buckets can be combined in one tag (comma-separated).
  -- Each is guarded by a one-shot flag so the same bucket is never injected twice
  -- in one turn, preventing infinite follow-up loops.
  local scan_text = text
  do
    local trimmed = tostring(text or ""):match("^%s*(.-)%s*$") or ""
    local inline_tag = trimmed:match(
      "^`%s*(<%s*context_needed%s*>.-<%s*/%s*context_needed%s*>)%s*`$")
    local fenced_tag = trimmed:match(
      "^```[%w_-]*%s*(<%s*context_needed%s*>.-<%s*/%s*context_needed%s*>)%s*```$")
    if inline_tag or fenced_tag then
      scan_text = inline_tag or fenced_tag
      Log.line("CONTEXT_NEEDED",
        "whole response wrapped context tag in code markup; treating as bare tag")
    end
  end
  --
  -- Strip inline code spans and fenced code blocks BEFORE looking for
  -- <context_needed> tags. Models often quote the tag syntax in
  -- explanations ("your reply must be `<context_needed>docs</context_needed>`
  -- with no other content"), and those quoted tags are demonstrations,
  -- not real requests. Parsing them fires a wasted bucket-fetch round
  -- trip, which the loop detector then flags as duplicate context and
  -- aborts the turn with a user-facing error. A compliant model's real
  -- request emits the bare tag per the system-prompt rule "AND NOTHING
  -- ELSE," or the tolerated whole-reply quoted/fenced form normalized
  -- above, so the request still matches after scrubbing; only the
  -- demonstration-quoted form inside other content gets filtered out.
  local scrubbed = scan_text
    :gsub("```.-```", "")     -- fenced code blocks (non-greedy)
    :gsub("`[^`]*`", "")      -- inline code spans
  -- Models occasionally emit two separate <context_needed> tags in one
  -- response instead of one comma-joined tag. Collect all of them and merge
  -- their payloads with a comma so the existing token parser handles them
  -- uniformly. Without this, only the first tag was processed and the rest
  -- vanished silently, leaving the model stuck waiting for context.
  local merged = {}
  -- Tolerate stray whitespace inside the tag delimiters (e.g. "< context_needed>"):
  -- some quantized models tokenize "<context_needed>" as separate pieces and
  -- decode with a space, which would otherwise fall through as visible chat.
  for cap in scrubbed:gmatch("<%s*context_needed%s*>%s*(.-)%s*<%s*/%s*context_needed%s*>") do
    if cap ~= "" then merged[#merged+1] = cap end
  end
  if #merged == 0 then
    local dangling = scrubbed:match(
      "^%s*<%s*context_needed%s*>%s*([^<\r\n]-)%s*$")
    if dangling and dangling ~= "" then
      merged[#merged+1] = dangling
      Log.line("CONTEXT_NEEDED",
        "unterminated context tag; treating as request (\""
        .. dangling .. "\")")
    end
  end
  local bucket_str = (#merged > 0) and tbl_concat(merged, ", ") or nil
  if not (bucket_str and S.pending_orig_prompt) then return false end
  if S.pending_answer_only_followup then
    Log.line("CONTEXT_NEEDED",
      "suppressed context request on answer-only follow-up (\""
      .. bucket_str .. "\")")
    return false
  end

  -- Mixed-output detection. The system prompt requires a bare <context_needed>
  -- tag with no prose. Models violate this routinely with polite hedges like
  -- "I need to see which tracks have FX before I can act." + tag. Old behavior
  -- surfaced the prose and dropped the tag, forcing the user to nag the model
  -- two or three times before it complied with a bare tag. New behavior: fire
  -- the bucket fetch anyway (the prose is hidden because intermediate bucket-
  -- fetch turns aren't displayed) and append a reminder to the follow-up so
  -- the model self-corrects on subsequent turns. The CONTEXT_LOOP detector
  -- below catches the pathological case (model keeps re-requesting already-
  -- pinned data). Threshold: 40 non-whitespace characters of non-tag,
  -- non-code content -- short tags like "Fetching..." don't need the hint.
  local non_tag = scrubbed:gsub("<%s*context_needed%s*>.-<%s*/%s*context_needed%s*>", "")
  local non_ws_count = 0
  for _ in non_tag:gmatch("%S") do
    non_ws_count = non_ws_count + 1
    if non_ws_count > 40 then break end
  end
  local raw_non_tag = scan_text:gsub("<%s*context_needed%s*>.-<%s*/%s*context_needed%s*>", "")
  local has_final_payload =
       raw_non_tag:find("```%s*[%w_-]*%s*\n") ~= nil
    or raw_non_tag:find("reaper%.") ~= nil
    or raw_non_tag:find('"actions"%s*:') ~= nil
  if non_ws_count > 40 then
    Log.line("CONTEXT_NEEDED",
      "tag emitted alongside prose; firing fetch with reminder (\""
      .. bucket_str .. "\")")
    S._mixed_output_hint = true
  end

  local wants_docs        = false
  local wants_docs_extended = false
  local wants_docs_section = false
  local docs_section_names  = {}  -- canonical section names to fetch this turn
  local bogus_docs_sections = {}  -- raw payloads that failed allowlist; for nudge
  local wants_session     = false
  local wants_tracks      = false
  local wants_fx_params   = false
  local wants_plugin_ref  = false
  local plugin_ref_names  = {}  -- plugin names for plugin_ref scoped bucket
  local curated_pref_hints = {} -- {tkey, ident, curated} tuples accumulated by
                                -- the resolve handler when a user-pref ident
                                -- matches CURATED_IDENT; finalize emits a
                                -- slim pref:<tkey> hint for each so the model
                                -- knows the curated content IS the user's pref
  local wants_fx_list     = false
  local wants_fx_chains   = false
  local wants_track_flags = false
  local wants_midi        = false
  local wants_recent_reaper_changes = false
  local wants_pref_plugins = false
  local wants_theme       = false
  local wants_fx_inspect  = false
  -- Sentinel: set when the model emits a <context_needed> for data already
  -- in sticky_context (typically from preempt injection or an earlier
  -- turn's fetch). We still need to fire a follow-up turn -- the model's
  -- response so far is just the context_needed tag, not code -- but we
  -- don't fetch anything new. The reinforcement hint tells the model the
  -- data is already available and nudges it to write code. Weak models
  -- (GPT-5 mini, Flash 3.5) hit this path routinely after preempt injection.
  local wants_preempt_hint = false
  local wants_prompt_bundle = false
  local pref_plugin_types = {}  -- type keys for preferred_plugins scoped bucket
  local fx_filter_names   = {}  -- plugin names to match; populated from the colon payload
  local fx_list_search    = {}  -- search terms for fx_list bucket
  local fx_inspect_names  = {}  -- search terms for fx_inspect bucket
  local prompt_bundle_names = {}  -- bundle names for prompt_bundle scoped bucket

  -- Parse comma-separated bucket tokens. Plain keywords ("session", "docs") are
  -- handled directly. Scoped keywords ("fx_params:VintageVerb") split on ":".
  -- Two-pass approach: pass 1 finds fx_params and its inline payload; pass 2
  -- collects subsequent non-keyword tokens as additional plugin name filters,
  -- so "fx_params:Plugin1, Plugin2" correctly builds filter = {Plugin1, Plugin2}.
  local recognised_keywords = { session=true, tracks=true, docs=true, docs_extended=true, recent_reaper_changes=true, fx_params=true, plugin_ref=true, fx_list=true, fx_chains=true, track_flags=true, midi=true, preferred_plugins=true, pref=true, theme=true, fx_inspect=true, resolve=true, prompt_bundle=true }
  -- Hoisted out of the resolve branch so the pre-pass (just below) and the
  -- popup-bail scan-ahead can both reference it.
  local VALID_RESOLVE_TYPES = {
    eq=true, compressor=true, multiband_compressor=true, reverb=true,
    delay=true, saturation=true, limiter=true, gate=true, chorus=true,
    phaser=true, deesser=true, pitch_correction=true,
    pitch_shift=true, synth=true, custom=true,
  }
  local raw_tokens = {}
  for tok in bucket_str:gmatch("[^,]+") do
    raw_tokens[#raw_tokens+1] = tok:match("^%s*(.-)%s*$")
  end
  local prompt_l = tostring(S.pending_orig_prompt or ""):lower()
  local timecode_context_intent =
    CTX and CTX.prompt_indicates_timecode_generator
    and CTX.prompt_indicates_timecode_generator(prompt_l)
  local function add_timecode_context_hint(tok)
    if not timecode_context_intent then return end
    S._timecode_context_hint = S._timecode_context_hint or {}
    S._timecode_context_hint[#S._timecode_context_hint+1] = tok
  end
  local function prompt_likely_reaper_action()
    if timecode_context_intent then
      return true
    end
    return prompt_l:find("%f[%w]create")
        or prompt_l:find("%f[%w]make")
        or prompt_l:find("%f[%w]build")
        or prompt_l:find("%f[%w]add")
        or prompt_l:find("%f[%w]insert")
        or prompt_l:find("%f[%w]route")
        or prompt_l:find("%f[%w]set%s+up")
        or prompt_l:find("%f[%w]lay%s+out")
  end

  -- JSFX authoring/install prompts get prompt_bundle:jsfx pre-pinned. Weak
  -- models sometimes ask for prompt_bundle:plugin anyway because the JSFX is
  -- also being added to a track. Drop that wrong bundle and nudge them to
  -- emit the requested JSFX artifact now.
  if S.pending_jsfx_intent then
    local kept, dropped = {}, {}
    for _, tok in ipairs(raw_tokens) do
      local kw, payload = tok:match("^([^:]+):?(.*)$")
      kw = kw and kw:match("^%s*(.-)%s*$"):lower() or ""
      payload = payload and payload:match("^%s*(.-)%s*$"):lower() or ""
      if kw == "prompt_bundle" and payload == "plugin" then
        dropped[#dropped+1] = tok
      else
        kept[#kept+1] = tok
      end
    end
    if #dropped > 0 then
      Log.line("DISPATCH",
        "dropped JSFX-inapplicable prompt bundle request: "
        .. tbl_concat(dropped, ", "))
      raw_tokens = kept
      S._jsfx_context_hint = S._jsfx_context_hint or {}
      for _, dropped_tok in ipairs(dropped) do
        S._jsfx_context_hint[#S._jsfx_context_hint+1] = dropped_tok
      end
      if #raw_tokens == 0 then
        if has_final_payload then
          Log.line("DISPATCH",
            "JSFX-inapplicable prompt bundle request accompanied by final payload; continuing final response")
          return false
        end
        wants_preempt_hint = true
      end
    end
  end

  -- Drop a common weak-model false positive: `prompt_bundle:plugin` for pure
  -- project-layout requests such as "nested session outline". Real FX/plugin
  -- prompts keep the bundle; the normal dispatcher below still handles them.
  do
    local function prompt_mentions_plugin_surface()
      if timecode_context_intent then
        return false
      end
      if prompt_l:find("trackfx", 1, true)
         or prompt_l:find("takefx", 1, true)
         or prompt_l:find("plugin", 1, true)
         or prompt_l:find("plug%-in")
         or prompt_l:find("fabfilter", 1, true)
         or prompt_l:find("pro%-q")
         or prompt_l:find("reacomp", 1, true)
         or prompt_l:find("reaeq", 1, true)
         or prompt_l:find("reagate", 1, true)
         or prompt_l:find("readelay", 1, true)
         or prompt_l:find("reaverbate", 1, true) then
        return true
      end
      if prompt_l:find("%f[%w]fx%f[%W]")
         and not prompt_l:find("%f[%w]fx%s+bus%f[%W]") then
        return true
      end
      local fx_terms = {
        "effect", "effects", "reverb", "delay", "compressor",
        "compression", "equalizer", "filter", "gate", "limiter",
        "saturation", "saturator", "distortion", "chorus", "phaser",
        "flanger", "de%-esser", "deesser", "pitch correction",
        "autotune", "sidechain", "ducking", "synth",
      }
      for _, term in ipairs(fx_terms) do
        if prompt_l:find(term) then return true end
      end
      return false
    end
    if not prompt_mentions_plugin_surface() then
      local kept, dropped = {}, {}
      for _, tok in ipairs(raw_tokens) do
        local kw, payload = tok:match("^([^:]+):?(.*)$")
        kw = kw and kw:match("^%s*(.-)%s*$"):lower() or ""
        payload = payload and payload:match("^%s*(.-)%s*$"):lower() or ""
        if kw == "prompt_bundle" and payload == "plugin" then
          dropped[#dropped+1] = tok
        else
          kept[#kept+1] = tok
        end
      end
      if #dropped > 0 then
        Log.line("DISPATCH",
          "dropped irrelevant prompt bundle request: "
          .. tbl_concat(dropped, ", "))
        for _, dropped_tok in ipairs(dropped) do
          add_timecode_context_hint(dropped_tok)
        end
        raw_tokens = kept
        if #raw_tokens == 0 then
          if has_final_payload then
            Log.line("DISPATCH",
              "irrelevant-only prompt bundle request accompanied by final payload; continuing final response")
            return false
          elseif prompt_likely_reaper_action() then
            if not (S.api_ref_message or S.docs_already_sent) then
              raw_tokens[#raw_tokens+1] = "docs"
              Log.line("DISPATCH",
                "irrelevant-only prompt bundle request on action prompt; fetching docs instead")
            else
              wants_preempt_hint = true
              S._irrelevant_context_hint = S._irrelevant_context_hint or {}
              for _, dropped_tok in ipairs(dropped) do
                S._irrelevant_context_hint[#S._irrelevant_context_hint+1] =
                  dropped_tok
              end
              Log.line("DISPATCH",
                "irrelevant-only prompt bundle request on action prompt with docs already pinned; nudging model")
            end
          end
        end
      end
    end
  end

  if timecode_context_intent then
    local kept, suppressed = {}, {}
    for _, tok in ipairs(raw_tokens) do
      local kw, payload = tok:match("^([^:]+):?(.*)$")
      kw = kw and kw:match("^%s*(.-)%s*$"):lower() or ""
      payload = payload and payload:match("^%s*(.-)%s*$") or ""
      local suppress = false
      if kw == "docs" and payload ~= "" then
        local canonical = CTX.docs_section_canonical(payload)
        suppress = canonical == "items"
          or (canonical == "routing" and S.docs_section_sent
            and S.docs_section_sent[canonical] == true)
      elseif kw == "session" then
        suppress = S.pending_snapshot ~= nil
      elseif kw == "docs" and payload == "" then
        suppress = S.api_ref_message ~= nil or S.docs_already_sent
      elseif kw == "docs_extended" then
        suppress = S.docs_extended_already_sent == true
      end
      if suppress then
        suppressed[#suppressed+1] = tok
      else
        kept[#kept+1] = tok
      end
    end
    if #suppressed > 0 then
      Log.line("DISPATCH",
        "suppressed native timecode context request: "
        .. tbl_concat(suppressed, ", "))
      for _, tok in ipairs(suppressed) do
        add_timecode_context_hint(tok)
      end
      if #kept == 0 then
        if has_final_payload then
          S._timecode_context_hint = nil
          Log.line("DISPATCH",
            "native timecode context request accompanied by final payload; continuing final response")
          return false
        end
        wants_preempt_hint = true
      end
      raw_tokens = kept
    end
  end

  -- Expand scoped-continuation. The system prompt teaches scoped
  -- continuation for plugin_ref/fx_list/preferred_plugins (e.g.
  -- "preferred_plugins:eq, compressor"). Pre-rewriting keeps the pinned-token
  -- de-dup pass from dropping the scoped head and orphaning the continuation.
  local prev_scoped_kw = nil
  local continuation_scopes = {
    docs = true,
    fx_params = true,
    fx_list = true,
    fx_inspect = true,
    plugin_ref = true,
    preferred_plugins = true,
    pref = true,
    prompt_bundle = true,
    resolve = true,
  }
  for i, tok in ipairs(raw_tokens) do
    local has_colon = tok:find(":", 1, true) ~= nil
    if has_colon then
      local hkw = (tok:match("^([^:]+)") or ""):match("^%s*(.-)%s*$"):lower()
      prev_scoped_kw = continuation_scopes[hkw] and hkw or nil
    elseif prev_scoped_kw and not recognised_keywords[tok:lower()] then
      if prev_scoped_kw ~= "resolve" or VALID_RESOLVE_TYPES[tok:lower()] then
        raw_tokens[i] = prev_scoped_kw .. ":" .. tok
      end
      -- prev_scoped_kw stays live so "plugin_ref:A, B, C" all expand.
    else
      prev_scoped_kw = nil
    end
  end

  -- Pre-pass: drop tokens whose data is already in pinned context. The
  -- model occasionally re-requests data already listed in the PINNED
  -- REFERENCES manifest (observed: a turn 2 tag that named session +
  -- 3 already-pinned bundles alongside a legitimate resolve, costing a
  -- wasted inner round-trip). Per-bucket gates inside the main loop
  -- already drop most of these silently, but coverage is uneven (some
  -- gates set wants_preempt_hint, others fall through; `session` checks
  -- session_already_sent but not whether the snapshot is on this very
  -- turn). The pre-pass unifies the de-dup, logs the dropped list so
  -- the redundancy is visible at a glance, and sets the reuse hint so
  -- an all-redundant tag still fires a "use the data you have"
  -- follow-up instead of leaking the model's tag-only response.
  --
  -- Scope: only static buckets that map 1:1 to pinned slots (sticky
  -- bundles, static refs, or the snapshot attached to this turn).
  -- Most dynamic buckets (fx_list, fx_chains, fx_inspect, track_flags,
  -- resolve:*) are NOT pre-deduped -- their data is live and the model is
  -- allowed to re-emit them to get a fresh read. Scoped fx_params is the
  -- exception: preempt may have already pinned the exact live instance for
  -- this turn, and re-requesting it just burns a follow-up round-trip.
  local dropped_pinned = {}
  do
    local function token_already_pinned(kw, payload)
      if kw == "session" then
        -- Snapshot is attached to the current user message already
        -- (S.pending_snapshot is set whenever build_snapshot ran for
        -- this turn). A re-fetch would just rebuild the same snapshot
        -- the model is about to read.
        return S.pending_snapshot ~= nil
      elseif kw == "tracks" then
        return S.tracks_already_sent == true
      elseif kw == "docs" and payload == "" then
        return S.api_ref_message ~= nil or S.docs_already_sent
      elseif kw == "docs" and payload ~= "" then
        local canonical = CTX.docs_section_canonical(payload)
        return canonical
          and S.docs_section_sent
          and S.docs_section_sent[canonical] == true
      elseif kw == "docs_extended" then
        return S.docs_extended_already_sent == true
      elseif kw == "recent_reaper_changes" then
        return S.sticky_context
          and S.sticky_context["recent_reaper_changes"] ~= nil
      elseif kw == "midi" then
        return S.midi_ref_message ~= nil or S.midi_already_sent
      elseif kw == "theme" then
        return S.theme_ref_message ~= nil or S.theme_already_sent
      elseif kw == "prompt_bundle" and payload ~= "" then
        local pkey = payload:lower()
        return S.sticky_context
          and S.sticky_context["prompt_bundle:" .. pkey] ~= nil
      elseif kw == "plugin_ref" and payload ~= "" then
        return (S.plugin_ref_sent and S.plugin_ref_sent[payload] == true)
          or (S.sticky_context and S.sticky_context["plugin_ref:" .. payload] ~= nil)
      elseif (kw == "preferred_plugins" or kw == "pref") and payload ~= "" then
        return (S.pref_plugins_sent and S.pref_plugins_sent[payload] == true)
          or (S.sticky_context and S.sticky_context["pref:" .. payload] ~= nil)
      elseif kw == "fx_list" and payload ~= "" then
        local fl_key = "fx_list:" .. CTX.fx_filter_key({ payload })
        return S.sticky_context and S.sticky_context[fl_key] ~= nil
      elseif kw == "fx_chains" then
        return S.fx_chains_already_sent == true
      elseif kw == "track_flags" then
        return S.track_flags_already_sent == true
      elseif kw == "fx_params" and payload ~= "" then
        local fp_key = "fx:" .. CTX.fx_filter_key({ CTX.fx_filter_parse(payload) })
        return S.sticky_context
          and (S.sticky_context[fp_key] ~= nil
            or CTX.sticky_has_fx_params_for_ident(payload))
      elseif kw == "fx_params" and payload == "" then
        return S.fx_params_already_sent == true
      elseif kw == "fx_list" and payload == "" then
        return S.fx_list_already_sent == true
          or (S.sticky_context and S.sticky_context["fx_list"] ~= nil)
      elseif kw == "fx_inspect" and payload == "" then
        return S.fx_inspect_already_sent == true
      end
      return false
    end
    local kept = {}
    for _, tok in ipairs(raw_tokens) do
      local kw, payload = tok:match("^([^:]+):?(.*)$")
      kw = kw and kw:match("^%s*(.-)%s*$"):lower() or ""
      payload = payload and payload:match("^%s*(.-)%s*$") or ""
      if token_already_pinned(kw, payload) then
        dropped_pinned[#dropped_pinned+1] = tok
      else
        kept[#kept+1] = tok
      end
    end
    if #dropped_pinned > 0 then
      if #kept == 0 then
        Log.line("CONTEXT_ALREADY_PINNED",
          "all requested tags already present: "
          .. tbl_concat(dropped_pinned, ", "))
      else
        Log.line("DISPATCH",
          "dropped already-pinned tokens (" .. #dropped_pinned .. "/"
          .. (#dropped_pinned + #kept) .. "): "
          .. tbl_concat(dropped_pinned, ", "))
      end
      S._context_reuse_hint = S._context_reuse_hint or {}
      for _, t in ipairs(dropped_pinned) do
        S._context_reuse_hint[#S._context_reuse_hint+1] = t
      end
      -- All tokens dropped -> no real fetch will fire below. If the model
      -- also emitted a runnable/structured final payload, ignore the stale
      -- tag and let the normal final-response path strip it, validate code,
      -- and continue. Plain prose is not enough: models often narrate
      -- "let me check..." while still failing to produce a usable answer.
      -- In that case, fire a follow-up turn carrying the reuse hint instead
      -- of falling through to display the non-answer.
      if #kept == 0 then
        if has_final_payload then
          S._context_reuse_hint = nil
          S._mixed_output_hint = nil
          Log.line("CONTEXT_ALREADY_PINNED",
            "all requested tags already present; ignoring stale tag and continuing final response")
          return false
        end
        if prompt_likely_reaper_action()
           and not (S.api_ref_message or S.docs_already_sent) then
          kept[#kept+1] = "docs"
          Log.line("CONTEXT_ALREADY_PINNED",
            "redundant-only context request on action prompt; fetching docs instead")
        else
          wants_preempt_hint = true
        end
      end
    end
    raw_tokens = kept
  end

  local last_scoped = nil  -- tracks which scoped keyword ("fx_params"/"fx_list") was last seen

  for tok_idx, tok in ipairs(raw_tokens) do
    local kw, payload = tok:match("^([^:]+):?(.*)$")
    kw = kw and kw:match("^%s*(.-)%s*$"):lower() or ""
    payload = payload and payload:match("^%s*(.-)%s*$") or ""

    if kw == "session" and not S.session_already_sent then
      wants_session = true
      last_scoped = nil
    elseif kw == "tracks" and not S.tracks_already_sent then
      wants_tracks = true
      last_scoped = nil
    elseif kw == "docs" and payload ~= "" then
      -- docs:<section> -- on-demand API ref section. MUST come before the
      -- bare-docs branch below: that branch matches kw=="docs" regardless
      -- of payload and would silently drop the section name. Validate via
      -- the allowlist; unknown names land in bogus_docs_sections so the
      -- handler can emit a recoverable nudge instead of a silent drop.
      local canonical = CTX.docs_section_canonical(payload)
      if canonical then
        S.docs_section_sent = S.docs_section_sent or {}
        if not S.docs_section_sent[canonical] then
          wants_docs_section = true
          docs_section_names[#docs_section_names+1] = canonical
        end
      else
        bogus_docs_sections[#bogus_docs_sections+1] = payload
      end
      last_scoped = "docs"  -- enables "docs:items, envelopes" continuation
    elseif kw == "docs" and not S.docs_already_sent then
      wants_docs = true
      last_scoped = nil
    elseif kw == "docs_extended" and not S.docs_extended_already_sent then
      wants_docs_extended = true
      last_scoped = nil
    elseif kw == "recent_reaper_changes" then
      if not (S.sticky_context and S.sticky_context["recent_reaper_changes"]) then
        wants_recent_reaper_changes = true
      else
        wants_preempt_hint = true
        S._context_reuse_hint = S._context_reuse_hint or {}
        S._context_reuse_hint[#S._context_reuse_hint+1] =
          "recent_reaper_changes"
      end
      last_scoped = nil
    elseif kw == "plugin_ref" then
      last_scoped = "plugin_ref"
      if payload ~= "" and not S.plugin_ref_sent[payload] then
        wants_plugin_ref = true
        plugin_ref_names[#plugin_ref_names+1] = payload
      end
    elseif kw == "fx_list" then
      local fl_key = payload ~= "" and ("fx_list:" .. CTX.fx_filter_key({ payload }))
        or "fx_list"
      if not (S.sticky_context and S.sticky_context[fl_key]) then
        wants_fx_list = true
      end
      last_scoped = "fx_list"
      if payload ~= "" then
        fx_list_search[#fx_list_search+1] = payload
      end
    elseif kw == "fx_chains" and not S.fx_chains_already_sent then
      wants_fx_chains = true
      last_scoped = nil
    elseif kw == "track_flags" and not S.track_flags_already_sent then
      wants_track_flags = true
      last_scoped = nil
    elseif kw == "fx_params" and not S.fx_params_already_sent then
      wants_fx_params = true
      last_scoped = "fx_params"
      if payload ~= "" then
        fx_filter_names[#fx_filter_names+1] = CTX.fx_filter_parse(payload)
      end
    elseif kw == "midi" and not S.midi_already_sent then
      wants_midi = true
      last_scoped = nil
    elseif kw == "preferred_plugins" or kw == "pref" then
      last_scoped = kw
      if payload ~= "" and not S.pref_plugins_sent[payload] then
        wants_pref_plugins = true
        pref_plugin_types[#pref_plugin_types+1] = payload
      end
    elseif kw == "theme" and not S.theme_already_sent then
      wants_theme = true
      last_scoped = nil
    elseif kw == "fx_inspect" and not S.fx_inspect_already_sent then
      wants_fx_inspect = true
      last_scoped = "fx_inspect"
      if payload ~= "" then
        fx_inspect_names[#fx_inspect_names+1] = payload
      end
    elseif kw == "prompt_bundle" then
      last_scoped = "prompt_bundle"
      if payload ~= "" then
        local pb_name = payload:lower()
        local pb_key = "prompt_bundle:" .. pb_name
        if not (S.sticky_context and S.sticky_context[pb_key]) then
          wants_prompt_bundle = true
          prompt_bundle_names[#prompt_bundle_names+1] = pb_name
        else
          -- Already pinned (typically via JSFX-family co-pin: when
          -- prompt_bundle:jsfx_pitch was pre-pinned alongside jsfx_pitch,
          -- the base bundle and the family bundle are both in sticky_context).
          -- Without this branch the request
          -- silently drops -- fine for the dedupe but the model is still
          -- waiting for permission to write code, so the turn stalls. Fire
          -- a follow-up with the reuse hint so the model proceeds without
          -- a second round-trip.
          wants_preempt_hint     = true
          S._context_reuse_hint  = S._context_reuse_hint or {}
          S._context_reuse_hint[#S._context_reuse_hint+1] = pb_key
        end
      end
    elseif kw == "resolve" then
      -- resolve:<type> -- chokepoint for "give me a plugin of TYPE without
      -- specifying which". Translates the request into an underlying bucket
      -- based on what the user has installed/configured:
      --
      --   pref set for type     -> route through preferred_plugins:<type>
      --   eq + ReEQ installed   -> route through plugin_ref:ReEQ (EQ only)
      --   otherwise             -> block the round and raise the resolve
      --                            popup so the user can pick a plugin.
      --                            Returns immediately -- no follow-up curl
      --                            fires until the user clicks.
      --
      -- Supported types must match the set the system prompt is allowed to
      -- emit (see System_Prompt.md "resolve:Type bucket").
      last_scoped = nil
      local rtype = payload:lower()
      if not VALID_RESOLVE_TYPES[rtype] then
        Log.line("RESOLVE", "unsupported type: " .. tostring(rtype))
      else
        -- Dedupe: if the data this resolve would fetch is already in
        -- sticky_context (from preempt injection or an earlier turn),
        -- skip the fetch and set a reinforcement hint. Covers the common
        -- case where preempt injected plugin_ref:ReEQ for "eq" but the
        -- model still emits <context_needed>resolve:eq</context_needed>
        -- anyway -- weak models (mini, flash) ignore pinned sticky data
        -- and re-request. Firing the follow-up with just the hint ("you
        -- already have this data above, use it now") nudges the model
        -- into writing code without another full bucket-fetch round trip.
        local already_covered = false
        if rtype == "eq" and S.plugin_ref_sent and S.plugin_ref_sent["ReEQ"] then
          already_covered = true
        elseif S.pref_plugins_sent and S.pref_plugins_sent[rtype] then
          already_covered = true
        end
        if already_covered then
          Log.line("RESOLVE", rtype
            .. " -> already covered by sticky (dedupe; no fetch)")
          wants_preempt_hint = true
          S._context_reuse_hint = S._context_reuse_hint or {}
          S._context_reuse_hint[#S._context_reuse_hint+1] = "resolve:" .. rtype
        else
        local pref = FXCache.get_preferred_types()
        local pref_ident = pref and pref[rtype]
        -- Dev-only FabFilter hide: treat a matching pref as absent so the
        -- resolve path falls through to the popup branch below (same gate
        -- applied in CTX.preferred_plugins / load_pref_plugins / preempt).
        -- Without this, the resolve handler would still load the real
        -- pref content + mark pref_plugins_sent, and a second resolve
        -- request from the model would hit the dedupe branch and loop.
        if reaper.GetExtState(CFG.EXT_NS, "dev_hide_fabfilter") == "1"
           and _is_fabfilter_ident(pref_ident) then
          pref_ident = nil
        end
        if pref_ident and pref_ident ~= "" then
          Log.line("RESOLVE", rtype .. " -> user_pref ("
            .. tostring(pref_ident) .. ")")
          -- If the user's preferred plugin matches a curated section in
          -- Plugin_Ref.md, route through plugin_ref:<Name>
          -- instead of the live-scan preferred_plugins:<type> bucket.
          -- The curated ref carries verified indices, scale formulas, and
          -- per-recipe normalized values that the live param scan lacks.
          -- Mirrors the preempt path's curated handling so both routes
          -- deliver the same content for the same pref identifier. Uses
          -- the prefix/vendor-tolerant lookup (preferred_types may store
          -- canonicalized "VST3: Pro-Q 4" instead of bare "Pro-Q 4").
          local curated = CTX.curated_for_ident(pref_ident)
          if curated then
            if not S.plugin_ref_sent[curated] then
              wants_plugin_ref = true
              plugin_ref_names[#plugin_ref_names+1] = curated
              curated_pref_hints[#curated_pref_hints+1] = {
                tkey = rtype, ident = pref_ident, curated = curated,
              }
            end
            -- Mark pref_plugins_sent so a same-turn re-emission of
            -- resolve:<rtype> hits the already_covered branch above (the
            -- model already has the user's pref data, just under a
            -- plugin_ref: key instead of a pref: key).
            S.pref_plugins_sent[rtype] = true
          elseif not S.pref_plugins_sent[rtype] then
            wants_pref_plugins = true
            pref_plugin_types[#pref_plugin_types+1] = rtype
          end
        elseif rtype == "eq" and Code.is_reeq_installed() then
          -- Mid-session ReEQ catch. If the user just installed ReEQ via
          -- ReaPack while the script was already running, CTX._installed_fx_list
          -- is stale and Code.ensure_preferred_from_chains (which walks that
          -- cached list) won't find it. Code.is_reeq_installed() bypasses
          -- the cache via a direct filesystem check, so we catch it here.
          -- ReEQ is the only bundled/special-case plugin -- other types
          -- hit the resolve popup below if their chain came up empty.
          Log.line("RESOLVE", "eq -> reeq (mid-session filesystem check)")
          if not S.plugin_ref_sent["ReEQ"] then
            wants_plugin_ref = true
            plugin_ref_names[#plugin_ref_names+1] = "ReEQ"
          end
          -- Invalidate the cached FX list then rerun chains so pref_types.eq
          -- commits for future turns (no re-route through this branch).
          CTX._installed_fx_list = nil
          Code.ensure_preferred_from_chains()
        else
          -- Block the round: raise the modal and bail out without firing
          -- a follow-up. pending_orig_prompt / pending_snapshot stay intact
          -- so the popup's action buttons can resume the turn.
          -- Drop chat status to idle so the UI isn't stuck on "waiting";
          -- the popup itself is modal so the user can't send anything else.
          --
          -- Before bailing, scan the rest of raw_tokens for any OTHER
          -- resolve:Type tokens and stash their types in S.pending_resolves.
          -- After the popup resumes, resolve_popup_resume will append
          -- "resolve:<type>" for each queued type to its synthesized tag,
          -- so the model gets all originally-requested data in one round-trip
          -- instead of having to re-emit the dropped tokens itself.
          Log.line("RESOLVE", rtype .. " -> popup")
          S.pending_resolves = {}
          for ahead = tok_idx + 1, #raw_tokens do
            local at = raw_tokens[ahead]
            local akw, apayload = at:match("^([^:]+):?(.*)$")
            akw = akw and akw:match("^%s*(.-)%s*$"):lower() or ""
            apayload = apayload and apayload:match("^%s*(.-)%s*$"):lower() or ""
            if akw == "resolve" and apayload ~= "" and VALID_RESOLVE_TYPES[apayload] then
              S.pending_resolves[#S.pending_resolves+1] = apayload
            end
          end
          -- Stash any wants_* state already accumulated in this parse round
          -- (from tokens BEFORE this popup-triggering one). Without this, a
          -- plugin_ref:Name or preferred_plugins:type processed earlier in
          -- the same loop is silently lost when the function returns -- the
          -- locals plugin_ref_names / pref_plugin_types are discarded with
          -- the call frame. resolve_popup_resume re-emits these as buckets
          -- in its synthesized tag so the data is restored on the next pass.
          S.pending_plugin_ref_names = {}
          for _, n in ipairs(plugin_ref_names) do
            S.pending_plugin_ref_names[#S.pending_plugin_ref_names+1] = n
          end
          S.pending_pref_plugin_types = {}
          for _, t in ipairs(pref_plugin_types) do
            S.pending_pref_plugin_types[#S.pending_pref_plugin_types+1] = t
          end
          S.resolve_popup      = { type = rtype }
          S.open_resolve_popup = true
          S.status             = "idle"
          return true
        end
        end  -- if already_covered (dedupe)
      end
    elseif last_scoped and not recognised_keywords[kw] then
      -- Non-keyword token after a scoped keyword: additional name filter.
      -- e.g. "fx_list:Pro-Q, Valhalla" -> fx_list_search = {Pro-Q, Valhalla}
      local name = tok:match("^%s*(.-)%s*$")
      if last_scoped == "fx_params" then
        fx_filter_names[#fx_filter_names+1] = CTX.fx_filter_parse(name)
      elseif last_scoped == "fx_list" then
        fx_list_search[#fx_list_search+1] = name
      elseif last_scoped == "preferred_plugins" then
        if not S.pref_plugins_sent[name] then
          wants_pref_plugins = true
          pref_plugin_types[#pref_plugin_types+1] = name
        end
      elseif last_scoped == "plugin_ref" then
        if not S.plugin_ref_sent[name] then
          wants_plugin_ref = true
          plugin_ref_names[#plugin_ref_names+1] = name
        end
      elseif last_scoped == "fx_inspect" then
        fx_inspect_names[#fx_inspect_names+1] = name
      elseif last_scoped == "prompt_bundle" then
        local nlo = name:lower()
        if not S.prompt_bundle_sent[nlo] then
          wants_prompt_bundle = true
          prompt_bundle_names[#prompt_bundle_names+1] = nlo
        else
          -- Continuation-token form ("prompt_bundle:jsfx_pitch, jsfx") --
          -- same dedupe-with-hint behaviour as the explicit colon form
          -- above.
          wants_preempt_hint     = true
          S._context_reuse_hint  = S._context_reuse_hint or {}
          S._context_reuse_hint[#S._context_reuse_hint+1] =
            "prompt_bundle:" .. nlo
        end
      elseif last_scoped == "docs" then
        -- Continuation of a "docs:items, envelopes" tag. Each subsequent
        -- bare token is another section name (with the same allowlist gate).
        local canonical = CTX.docs_section_canonical(name)
        if canonical then
          S.docs_section_sent = S.docs_section_sent or {}
          if not S.docs_section_sent[canonical] then
            wants_docs_section = true
            docs_section_names[#docs_section_names+1] = canonical
          end
        else
          bogus_docs_sections[#bogus_docs_sections+1] = name
        end
      end
    end
  end

  -- If fx_list was requested (now or earlier this turn), skip fx_params -
  -- the plugin likely isn't loaded yet, so fx_params will fail. The AI
  -- should use runtime helpers (find_param, set_param_display) instead.
  if wants_fx_params and wants_fx_list then
    wants_fx_params = false
    fx_filter_names = {}
  end
  -- fx_inspect supersedes fx_list (it includes the identifier in its output).
  if wants_fx_inspect and wants_fx_list then
    wants_fx_list = false
    fx_list_search = {}
  end
  if S.midi_ref_message
     and Code.prompt_has_midi_workflow_intent(S.pending_orig_prompt)
     and wants_docs_section
     and not wants_docs_extended
     and #bogus_docs_sections == 0 then
    local midi_ref_covers_sections = true
    for _, nm in ipairs(docs_section_names) do
      if nm ~= "items" and nm ~= "tempo" then
        midi_ref_covers_sections = false
        break
      end
    end
    if midi_ref_covers_sections then
      local suppressed = {}
      for _, nm in ipairs(docs_section_names) do
        suppressed[#suppressed+1] = "docs:" .. nm
      end
      if #suppressed > 0 then
        Log.line("DISPATCH",
          "suppressed MIDI-covered docs request: "
          .. tbl_concat(suppressed, ", "))
        wants_docs_section = false
        docs_section_names = {}
        S._midi_docs_suppressed_hint = tbl_concat(suppressed, ", ")
        wants_preempt_hint = true
      end
    end
  end

  if wants_docs or wants_docs_extended or wants_docs_section or wants_session or wants_tracks or wants_fx_params or wants_plugin_ref or wants_fx_list or wants_fx_chains or wants_track_flags or wants_midi or wants_recent_reaper_changes or wants_pref_plugins or wants_theme or wants_fx_inspect or wants_preempt_hint or wants_prompt_bundle or #bogus_docs_sections > 0 then
    -- Collects bucket keys that were fetched-and-stickied this turn. Used to
    -- emit a brief model-facing pointer ("<context_needed> satisfied; data
    -- is in PINNED REFERENCES above") so the model doesn't re-request.
    -- Declared up here, ABOVE early bucket branches: the write-intent
    -- plugin_helpers co-pin appends to fetched_to_sticky, and inline buckets
    -- such as tracks append to history_content before the main docs/session
    -- assembly below.
    local fetched_to_sticky = {}
    local history_content = ""
    -- Build a fresh session snapshot if requested and not already present.
    if wants_session then
      S.session_already_sent = true
      S.pending_project  = CTX.resolve_pending_project()
      -- Carry JSFX intent across the rebuild so the trimmed track-listing
      -- (selected only) used on the original turn stays trimmed on this
      -- retry/follow-up. Otherwise the rebuild would inject the full
      -- ~80-track listing on top of the cached prefix, busting the cache
      -- rung and re-sending tracks the JSFX writer never reads.
      S.pending_snapshot = CTX.build_snapshot(S.pending_project,
        S.pending_jsfx_intent and { minimal_tracks = true } or nil)
    end
    if wants_tracks then
      S.tracks_already_sent = true
      S.pending_project = CTX.resolve_pending_project()
      history_content = history_content
        .. CTX.tracks(S.pending_project, { full = true }) .. "\n\n"
    end

    -- Build the fx_params block for the requested plugins.
    -- Assembly is deferred into finalize_context so that any auto-inspect
    -- triggered below (to populate the cache for enum/range annotations)
    -- completes first.
    if wants_fx_params then
      S.fx_params_already_sent = true
      S.pending_project = CTX.resolve_pending_project()
      -- Co-pin plugin helpers when the prompt looks like a write intent
      -- ("set X to Y", "change A to B", numeric-with-unit patterns). fx_params
      -- on a pure read ("what is X set to?") doesn't need helpers; on a
      -- read-then-write request, the model gets back live values AND will
      -- need set_param_display etc. to write the new ones. Co-pinning
      -- here means the helpers ride the same follow-up build instead of
      -- requiring an extra <context_needed>prompt_bundle:plugin_helpers
      -- round-trip after the model sees fx_params.
      if Code.prompt_has_param_write_intent(S.pending_orig_prompt) then
        Net.copin_plugin_bundle(fetched_to_sticky)
        Net.copin_docs_core(fetched_to_sticky)
        Net.copin_plugin_helpers(fetched_to_sticky)
      end

      -- Auto-cache: if any matched FX has no cached param data, route the
      -- first uncached plugin through fx_inspect (silent: result populates
      -- the cache but is not appended to history_content, since fx_params
      -- already covers it with live values). Skip when the user explicitly
      -- requested fx_inspect this turn -- their inspect handles caching.
      -- The hidden temp track avoids touching the user's live FX, which
      -- would visibly cycle params and glitch audio.
      --
      -- INVARIANT: this `not wants_fx_inspect` guard is load-bearing for
      -- the silent-flag contract. If the auto-inspect ran alongside an
      -- explicit fx_inspect:X, S._fx_inspect_silent_for_fx_params (a
      -- single boolean) would silence both -- the user's explicit Foo
      -- inspection would never pin to sticky and the model would get no
      -- inspect data for it. If you ever remove this guard, you must
      -- replace the boolean with a per-name silent set (S._fx_inspect_
      -- silent_names = {name=true}) and gate every silent-flag read on
      -- per-name membership; the bool no longer captures the right
      -- granularity once mixed lists are possible.
      if not wants_fx_inspect then
        local _proj = S.pending_project
        local _tc = R_CountTracks(_proj)
        -- Auto-inspect ignores any per-filter @track scope: caching one
        -- instance's params for a plugin populates the FX cache used by
        -- every other instance, and inspecting the wrong instance is fine
        -- here because we only use the result to backfill enum/range
        -- annotations, not to answer the user's track-specific question.
        local _names_only = CTX.fx_filter_names_only(fx_filter_names)
        local found_search = nil
        for _ti = 0, _tc - 1 do
          if found_search then break end
          local _tr = R_GetTrack(_proj, _ti)
          if _tr then
            local _fc = R_TrackFX_GetCount(_tr)
            for _fi = 0, _fc - 1 do
              local _, _fxnm = R_TrackFX_GetFXName(_tr, _fi, "")
              if CTX.fx_name_matches(_fxnm, _names_only) then
                local _ck, _cp = FXCache.find_plugin(_fxnm)
                if not _cp then
                  -- Use the user's filter term that matched as the search
                  -- input for fx_inspect_load (cleaner than full bracketed
                  -- VST3 identifier).
                  for _, fn in ipairs(_names_only) do
                    if _fxnm:lower():find(fn:lower(), 1, true) then
                      found_search = fn; break
                    end
                  end
                  found_search = found_search or _fxnm
                  break
                end
              end
            end
          end
        end
        if found_search then
          Log.line("FX_PARAMS",
            "uncached match -- auto-inspecting (silent): " .. found_search)
          fx_inspect_names[#fx_inspect_names+1] = found_search
          wants_fx_inspect = true
          S._fx_inspect_silent_for_fx_params = true
        end
      end

      -- Defer assembly into finalize_context (after any auto-inspect
      -- populates the cache).
      S._fx_params_pending_assemble = {
        proj   = S.pending_project,
        names  = fx_filter_names,
        fp_key = #fx_filter_names > 0
          and ("fx:" .. CTX.fx_filter_key(fx_filter_names)) or "fx_params",
      }
    end

    -- Assemble enriched history content: small inline-only buckets + USER
    -- REQUEST. Big sticky-backed buckets (plugin_ref / pref_plugins /
    -- fx_inspect / fx_params / docs_extended) write to S.sticky_context ONLY
    -- -- no inline duplication in history_content. On the follow-up build,
    -- Net.sticky_text() emits them as the pinned message, so the model sees
    -- each bucket exactly once per turn (in the well-cached pinned slot),
    -- not twice. Saves the bucket's size in input tokens per follow-up turn
    -- -- on a ~3K-token fx_inspect that's ~$0.02 of cache-write cost on
    -- Sonnet. See fetched_to_sticky below for the model-facing ack.
    -- CTX.docs/CTX.plugin_ref return nil + error on failure; show the error
    -- and proceed without the missing bucket rather than blocking the follow-up.
    if wants_docs then
      S.docs_already_sent = true
      local ref_content, ref_err = CTX.docs()
      if ref_content then
        -- Pin docs to the persistent api_ref slot rather than inlining into
        -- this turn's history_content. Inlining was load-bearing on the
        -- bare /docs follow-up but fragile across multi-step turns: any
        -- subsequent <context_needed> in the same turn (e.g. session,
        -- fx_chains) rebuilds history_content from scratch and the docs
        -- inline disappears, forcing the model to re-emit
        -- <context_needed>docs</context_needed>. Since docs is already
        -- flagged sent, the second request loops and the turn aborts.
        -- Promoting to S.api_ref_message routes docs through the static
        -- pinned slot (same path as midi/theme refs and the docs-gate
        -- auto-retry), so it survives every follow-up build in this turn
        -- and stays pinned for the rest of the session.
        S.api_ref_message      = ref_content
        S.docs_fetched_session = true
        fetched_to_sticky[#fetched_to_sticky+1] = "docs"
      else
        Log.add_error(ref_err)
        wants_docs = false  -- clear flag so ctx_label is not updated below
      end
    end
    if wants_docs_extended then
      S.docs_extended_already_sent = true
      local ext_content, ext_err = CTX.docs_extended()
      if ext_content then
        -- Sticky only. Emitted by Net.sticky_text() on the follow-up build
        -- in the pinned slot; no duplicate inline copy in history_content.
        Net.sticky_set("docs_extended", ext_content)
        fetched_to_sticky[#fetched_to_sticky+1] = "docs_extended"
      else
        Log.add_error(ext_err)
        wants_docs_extended = false
      end
    end
    if wants_docs_section then
      -- Each section is loaded + sticky_set under its own "docs:<name>" key
      -- so it lands in sticky_growing alongside docs_extended (see
      -- Net.sticky_parts). Per-name sent-flag dedups intra-turn re-emits;
      -- the eviction exemption keeps the section alive session-wide.
      S.docs_section_sent = S.docs_section_sent or {}
      for _, name in ipairs(docs_section_names) do
        local sec_content, sec_err = CTX.docs_section(name)
        if sec_content then
          Net.sticky_set("docs:" .. name, sec_content)
          S.docs_section_sent[name] = true
          fetched_to_sticky[#fetched_to_sticky+1] = "docs:" .. name
        else
          Log.add_error(sec_err or ("Failed to load docs:" .. name))
        end
      end
    end
    if wants_recent_reaper_changes then
      local recent_content, recent_err = CTX.recent_reaper_changes()
      if recent_content then
        Net.sticky_set("recent_reaper_changes", recent_content, "context_needed")
        fetched_to_sticky[#fetched_to_sticky+1] = "recent_reaper_changes"
      else
        Log.add_error(recent_err or "Failed to load recent_reaper_changes")
        wants_recent_reaper_changes = false
      end
    end
    if #bogus_docs_sections > 0 then
      -- Recoverable nudge for unknown section names. Without this, the
      -- model sees no acknowledgment of its <context_needed>docs:<bogus>
      -- and may keep re-emitting the same invalid tag. Inject a brief
      -- ack listing the valid section names so the model can correct.
      local valid = CTX.docs_section_list()
      for _, raw in ipairs(bogus_docs_sections) do
        Log.line("DOCS-SECTION", "unknown name '" .. tostring(raw)
          .. "'; valid: " .. valid)
        fetched_to_sticky[#fetched_to_sticky+1] =
          "(docs:" .. raw .. " is not a valid section; valid: " .. valid
          .. ". Use plain `docs` for the core reference.)"
      end
    end
    if wants_plugin_ref then
      local rp_content, rp_err = CTX.plugin_ref(plugin_ref_names)
      if rp_content then
        -- Mark each injected plugin name as sent this turn so later round-
        -- trips within the same user turn don't re-inject the same content,
        -- while still allowing plugin_ref for OTHER plugin names to fire.
        -- (Was a coarse boolean flag that blocked plugin_ref for ANY
        -- subsequent name once the first was sent -- caused resolve:eq ->
        -- ReEQ to silently drop when Pro-C 3 had been injected earlier in
        -- the same turn.) Marked only on fetch success: a disk error here
        -- used to lock the name out for the rest of the turn, so the next
        -- intra-turn retry would re-emit <context_needed>plugin_ref:Foo
        -- and get nothing back.
        for _, nm in ipairs(plugin_ref_names) do S.plugin_ref_sent[nm] = true end
        -- Sticky only -- emitted by Net.sticky_text() as the pinned message
        -- on the follow-up build.
        local rp_key = #plugin_ref_names > 0
          and ("plugin_ref:" .. tbl_concat(plugin_ref_names, "/")) or "plugin_ref"
        Net.sticky_set(rp_key, rp_content)
        fetched_to_sticky[#fetched_to_sticky+1] = rp_key
        -- Co-pin plugin bundle + docs core (same rationale as the preempt
        -- path). docs core matters here too: plugin_ref payload is rich
        -- enough that the model often skips emitting <context_needed>docs
        -- </context_needed> and the docs-gate has to retry.
        Net.copin_plugin_bundle(fetched_to_sticky)
        Net.copin_docs_core(fetched_to_sticky)
        -- Co-pin plugin helpers when the prompt has write intent. Curated
        -- plugin_ref data carries verified anchors but NOT a per-arbitrary-
        -- value mapping (Pro-C 3 Release is non-linear; the ref shows
        -- 100ms/200ms/500ms/1sec/2sec anchors but interpolating between
        -- them gives wrong values). Without helpers in the same follow-up
        -- build, the model sees a non-anchor target ("247ms"), notices it
        -- doesn't match any anchor, and either makes a second round-trip
        -- for plugin_helpers OR (observed live) skips the round-trip and
        -- linearly interpolates -- which crashes the displayed value on
        -- non-linear curves. Co-pinning here makes set_param_display the
        -- easy path for non-anchor curated targets, no extra round-trip.
        if Code.prompt_has_param_write_intent(S.pending_orig_prompt) then
          Net.copin_plugin_helpers(fetched_to_sticky)
        end
      else
        Log.add_error(rp_err)
        wants_plugin_ref = false  -- clear flag so ctx_label is not updated below
      end
    end
    -- Curated user-pref slim hints: when the resolve handler routed a
    -- preferred plugin through plugin_ref:<Name> (because pref_ident
    -- matched CURATED_IDENT), pin a small pref:<tkey> entry pointing at
    -- the curated bundle just emitted above. Without this, the model sees
    -- plugin_ref:Pro-G in sticky but can't tell whether Pro-G is the
    -- user's saved preference or curated default content -- weak models
    -- defensively re-emit <context_needed>resolve:gate</context_needed>.
    -- Format mirrors the preempt path's hint byte-for-byte so byte-prefix
    -- caching stays stable when the same hint comes from either route.
    if wants_plugin_ref and #curated_pref_hints > 0 then
      CTX.populate_installed_fx()
      for _, h in ipairs(curated_pref_hints) do
        local pp_key = "pref:" .. h.tkey
        if not S.sticky_context[pp_key] then
          local exact_ident = nil
          if Code.resolve_chain_entry and CTX._installed_fx_list then
            exact_ident = Code.resolve_chain_entry(h.ident, CTX._installed_fx_list)
          end
          if exact_ident and FXCache and FXCache.canonicalize_identifier then
            exact_ident = FXCache.canonicalize_identifier(h.tkey, exact_ident)
          elseif h.ident and FXCache and FXCache.canonicalize_identifier then
            local canonical_ident = FXCache.canonicalize_identifier(h.tkey, h.ident)
            if canonical_ident ~= h.ident then exact_ident = canonical_ident end
          end
          local hint = "PREFERRED PLUGINS:\n"
            .. "  " .. h.tkey .. " = " .. (exact_ident or h.ident or h.curated) .. "\n"
            .. "(User's saved preference; full parameter reference is pinned "
            .. "as plugin_ref:" .. h.curated .. ".)"
          Net.sticky_set(pp_key, hint)
          fetched_to_sticky[#fetched_to_sticky+1] = pp_key
        end
      end
    end
    if wants_prompt_bundle then
      -- Per-name dedup like plugin_ref. Fetched content goes into
      -- sticky_context so it stays pinned for the rest of the conversation
      -- (subsequent turns see the bundle without re-fetching). Any bundles
      -- that fail to load are dropped with a user-visible error; successful
      -- ones still pin so the turn can proceed with partial coverage.
      local ok = 0
      for _, nm in ipairs(prompt_bundle_names) do
        local pb_content, pb_err = CTX.prompt_bundle(nm)
        if pb_content then
          S.prompt_bundle_sent[nm] = true
          local pb_key = "prompt_bundle:" .. nm
          -- Tag as "context_needed": the model asked for this bundle
          -- mid-flow, so it's a reactive pin. Affects plugin_helpers
          -- routing in Net.sticky_parts -- helpers pulled this way
          -- stays in the growing rung instead of invalidating the
          -- larger stable bundle on a turn we didn't plan to.
          Net.sticky_set(pb_key, pb_content, "context_needed")
          fetched_to_sticky[#fetched_to_sticky+1] = pb_key
          ok = ok + 1
        else
          Log.add_error(pb_err)
        end
      end
      if ok == 0 then wants_prompt_bundle = false end
    end
    if wants_fx_list then
      local fl_key = #fx_list_search > 0
        and ("fx_list:" .. CTX.fx_filter_key(fx_list_search))
        or "fx_list"
      if S.sticky_context and S.sticky_context[fl_key] then
        wants_fx_list = false
        S._context_reuse_hint = S._context_reuse_hint or {}
        S._context_reuse_hint[#S._context_reuse_hint+1] = fl_key
      end
    end
    if wants_fx_list then
      local fl_content, fl_result = CTX.installed_fx(fx_list_search)
      if fl_content then
        S.fx_list_already_sent = true
        local fl_key = #fx_list_search > 0
          and ("fx_list:" .. CTX.fx_filter_key(fx_list_search))
          or "fx_list"
        Net.sticky_set(fl_key, fl_content .. "\n"
          .. "Use the identifiers above with TrackFX_AddByName. Set parameters using find_param and set_param_display at runtime. Do NOT request fx_params.\n\n"
        )
        fetched_to_sticky[#fetched_to_sticky+1] = fl_key
        Net.copin_plugin_bundle(fetched_to_sticky)
        Net.copin_docs_core(fetched_to_sticky)
        -- Zero-match notice is embedded in fl_content so the assistant
        -- sees it and can self-correct. No user-facing error needed.
      else
        Log.add_error(fl_result)
        wants_fx_list = false
      end
    end
    if wants_fx_chains then
      S.fx_chains_already_sent = true
      local proj = CTX.resolve_pending_project()
      history_content = history_content .. CTX.fx(proj) .. "\n\n"
    end
    if wants_track_flags then
      S.track_flags_already_sent = true
      local proj = CTX.resolve_pending_project()
      history_content = history_content .. CTX.track_flags(proj) .. "\n\n"
    end
    -- MIDI ref is loaded into the persistent slot (S.midi_ref_message)
    -- rather than injected into history_content. The follow-up call's
    -- build_body_* will pick it up and prepend it as a synthetic
    -- user/assistant pair, just like the api_ref. From this turn forward
    -- it lives in the static cache prefix slot.
    if wants_midi then
      S.midi_already_sent = true
      local mref_content, mref_err = CTX.midi()
      if mref_content then
        S.midi_ref_message = mref_content
      else
        Log.add_error(mref_err)
        wants_midi = false  -- clear flag so ctx_label is not updated below
      end
    end
    -- Theme color reference: loaded into the persistent slot
    -- (S.theme_ref_message) rather than into history_content, matching the
    -- MIDI pattern. build_body_* will prepend it on every subsequent call.
    if wants_theme then
      S.theme_already_sent = true
      local th_content, th_err = CTX.theme()
      if th_content then
        S.theme_ref_message = th_content
          .. "\n\n(Theme reference is loaded above. Do NOT request "
          .. "<context_needed>theme</context_needed> or "
          .. "<context_needed>prompt_bundle:theme</context_needed> or "
          .. "<context_needed>session</context_needed> -- you have "
          .. "everything needed. Proceed directly with the color change code.)"
        Net.copin_theme_bundle(fetched_to_sticky)
      else
        Log.add_error(th_err)
        wants_theme = false
      end
    end
    -- Preferred plugins: load only the requested type sections.
    if wants_pref_plugins then
      local pp_content, pp_err = CTX.preferred_plugins(pref_plugin_types)
      if pp_content then
        -- Mark each injected type as sent this turn (per-type dedup, mirrors
        -- the plugin_ref_sent pattern). Was a coarse boolean that blocked
        -- preferred_plugins for ANY type once one had been sent in the turn
        -- -- caused the resolve:compressor follow-up to silently no-op
        -- after preferred_plugins:eq had fired in the same turn. Marked
        -- only on fetch success so an intra-turn retry can re-fetch a type
        -- that failed the first time.
        for _, t in ipairs(pref_plugin_types) do S.pref_plugins_sent[t] = true end
        -- Sticky only -- pinned-slot emission on follow-up build.
        local pp_key = #pref_plugin_types > 0
          and ("pref:" .. tbl_concat(pref_plugin_types, "/")) or "pref_plugins"
        Net.sticky_set(pp_key, pp_content)
        fetched_to_sticky[#fetched_to_sticky+1] = pp_key
        -- Co-pin plugin bundle + docs core (every pref-plugin pin drives a
        -- plugin task that needs both the workflow guide and reaper.*
        -- signatures).
        Net.copin_plugin_bundle(fetched_to_sticky)
        Net.copin_docs_core(fetched_to_sticky)
        -- Co-pin plugin helpers when the prompt looks like a write intent.
        -- preferred_plugins for non-curated types returns live-scan param
        -- data without verified anchors; if the user asked for a specific
        -- value that doesn't match a cached point, the model needs
        -- set_param_display to probe at runtime. Pure "what plugin is my
        -- preferred X?" or generic "add a compressor" requests skip this.
        if Code.prompt_has_param_write_intent(S.pending_orig_prompt) then
          Net.copin_plugin_helpers(fetched_to_sticky)
        end
      else
        Log.add_error(pp_err)
        wants_pref_plugins = false
      end
    end
    -- (fx_params content is assembled in finalize_context, after any
    -- auto-inspect populates the cache.)

    -- fx_inspect: temporarily load a plugin to discover its parameters.
    -- Phase 1 runs here (add temp track + plugin); phase 2 (read params +
    -- cleanup) runs inside finalize_context after a one-frame defer.
    if wants_fx_inspect then
      S.fx_inspect_already_sent = true
      -- Multi-plugin fx_inspect is NOT supported. fx_inspect_load picks the
      -- single best_id from installed_fx's combined output, silently
      -- dropping the rest. That bug let the model use one plugin's data
      -- (e.g. Pro-C 3 Side Chain EQ "Band 1 Slope") for a different plugin
      -- (e.g. Pro-Q 4's main "Band 1 Slope") with disastrously wrong norms.
      -- Truncate to the first name, log the drop, and inject a warning into
      -- history_content so the model re-requests the missing plugins.
      if #fx_inspect_names > 1 then
        local dropped = {}
        for i = 2, #fx_inspect_names do
          dropped[#dropped+1] = fx_inspect_names[i]
        end
        Log.line("FX_INSPECT", str_format(
          "multi-plugin request: keeping '%s'; dropped %s. "
          .. "Re-request hint will be injected into the follow-up turn.",
          fx_inspect_names[1], tbl_concat(dropped, ", ")))
        while #fx_inspect_names > 1 do
          table.remove(fx_inspect_names)
        end
        S._fx_inspect_dropped = dropped  -- one-shot, consumed below
      end
      -- fx_inspect IS the "ADD + CONFIGURE with values" signal -- the model
      -- requested it specifically because the user asked to set specific
      -- param values that need runtime probing. Always co-pin plugin_helpers
      -- here so the follow-up build contains both fx_inspect data AND helper
      -- definitions in one round-trip (no second context_needed for helpers
      -- after the model sees the param map).
      Net.copin_plugin_bundle(fetched_to_sticky)
      Net.copin_docs_core(fetched_to_sticky)
      Net.copin_plugin_helpers(fetched_to_sticky)
      local tmp_tr, fx_idx, identifier, err, cached, undo_open =
        CTX.fx_inspect_load(fx_inspect_names)
      if err then
        if S._fx_inspect_silent_for_fx_params then
          -- Silent auto-cache trigger from fx_params: don't surface the
          -- inspect error to the model. fx_params still emits live values
          -- (just without enum/range annotations).
          Log.line("FX_PARAMS",
            "silent auto-inspect failed (continuing): " .. err)
        else
          history_content = history_content .. "FX INSPECT ERROR: " .. err .. "\n\n"
        end
      elseif cached then
        -- Cache hit: format cached data directly, no temp track needed.
        if S._fx_cache_events then
          local t = S._fx_cache_events
          t.hit = t.hit or {}
          t.hit[#t.hit+1] = identifier
        end
        if not S._fx_inspect_silent_for_fx_params then
          local inspect_data = CTX.format_fx_params(
            identifier, cached.params, cached.max_group, fx_inspect_names, true)
          -- Sticky only -- pinned-slot emission on follow-up build.
          local fi_key = "fx_inspect:" .. tbl_concat(fx_inspect_names, "/")
          Net.sticky_set(fi_key, inspect_data)
          fetched_to_sticky[#fetched_to_sticky+1] = fi_key
        end
      else
        S._fx_inspect_tmp = {
          tr = tmp_tr, fx = fx_idx,
          id = identifier, names = fx_inspect_names,
          undo_open = undo_open ~= false,
        }
      end
    end

    -- Finalize: assemble remaining context, update labels, fire API.
    -- Wrapped in a function so it can be deferred one frame when fx_inspect
    -- needs REAPER to finish initialising the plugin before reading params.
    local finalize_context
    finalize_context = function()
      -- fx_inspect phase 2: read params from temp plugin, remove temp track.
      -- If the shallow scan detects readback lag (e.g. Soundtoys VST3),
      -- kick off a coroutine-paced deep scan and defer the rest of
      -- finalize_context until it completes (or is cancelled).
      if S._fx_inspect_tmp then
        local fi = S._fx_inspect_tmp
        local function close_fx_inspect_undo(label)
          if fi and fi.undo_open then
            reaper.Undo_EndBlock(label or "ReaAssist: fx_inspect", 0)
            fi.undo_open = false
          end
        end
        -- ValidatePtr2: try_inspect_read already checks, but finalize_context
        -- can also be entered directly (np>0 path) with no validation gap, or
        -- after a deep scan where on_complete may have already deleted fi.tr.
        -- A stale handle here would crash scan_fx_params on the first
        -- TrackFX_* call.
        if not reaper.ValidatePtr2(0, fi.tr, "MediaTrack*") then
          reaper.PreventUIRefresh(-1)
          close_fx_inspect_undo("ReaAssist: fx_inspect (invalid track)")
          S._fx_inspect_tmp = nil
          if not S._fx_inspect_silent_for_fx_params then
            history_content = history_content
              .. "FX INSPECT ERROR: temporary track was invalidated before params could be read.\n\n"
          end
        else
        -- Wrap the shallow scan in xpcall so a thrown error (stale FX
        -- handle, REAPER returning nil from a probe, etc.) does not skip
        -- the cleanup at the end of this block, which would leave an
        -- orphaned hidden temp track plus a stuck PreventUIRefresh(-1)
        -- imbalance.
        local _scan_ok, params_list, max_group, total_count, needs_deep =
          xpcall(function()
            return CTX.scan_fx_params(fi.tr, fi.fx)
          end, debug.traceback)
        if not _scan_ok then
          -- params_list holds the error+traceback string in the failure case.
          local err_msg = tostring(params_list or "scan threw")
          Log.line("FX_INSPECT", "shallow scan threw: " .. err_msg)
          if reaper.ValidatePtr2(0, fi.tr, "MediaTrack*") then
            reaper.DeleteTrack(fi.tr)
          end
          reaper.PreventUIRefresh(-1)
          close_fx_inspect_undo("ReaAssist: fx_inspect (scan error)")
          S._fx_inspect_tmp = nil
          if not S._fx_inspect_silent_for_fx_params then
            history_content = history_content
              .. "FX INSPECT ERROR: shallow scan failed unexpectedly.\n\n"
          end
          -- Fall through to fx_params assemble + rest of finalize. Use a
          -- dummy nil set so subsequent statements that read these locals
          -- don't reference the error string.
          params_list, max_group, total_count, needs_deep = nil, nil, nil, nil
          goto fx_inspect_done
        end

        if needs_deep and not S._deep_scan_started then
          S._deep_scan_started = true
          S._deep_scan_label   = fi.id
          Log.line("DEEP_SCAN", "chat: auto-triggering deep scan for " .. fi.id)
          local _started_ok = CTX.start_deep_scan({
            tr           = fi.tr,
            fx_idx       = fi.fx,
            identifier   = fi.id,
            search_names = fi.names,
            origin       = "chat",
            on_complete  = function(dparams, dmax, dcount)
              FXCache.put_plugin(fi.id, dparams, dcount, dmax, false)
              if S._fx_cache_events then
                local t = S._fx_cache_events
                t.cached = t.cached or {}
                t.cached[#t.cached+1] = fi.id
              end
              if not S._fx_inspect_silent_for_fx_params then
                local inspect_data = CTX.format_fx_params(
                  fi.id, dparams, dmax, fi.names, true)
                -- Sticky only -- pinned-slot emission on follow-up build.
                local fi_key = "fx_inspect:" .. tbl_concat(fi.names, "/")
                Net.sticky_set(fi_key, inspect_data)
                fetched_to_sticky[#fetched_to_sticky+1] = fi_key
              end
              if reaper.ValidatePtr2(0, fi.tr, "MediaTrack*") then
                reaper.DeleteTrack(fi.tr)
              end
              -- PreventUIRefresh(-1) already done by scan_fx_params_deep_body;
              -- see comment there about avoiding double-release crashes.
              -- Undo setup was closed before this deferred scan started;
              -- this is only a legacy guard if older state is somehow live.
              close_fx_inspect_undo("ReaAssist: fx_inspect deep")
              S._fx_inspect_tmp   = nil
              S._deep_scan_started = false
              S._deep_scan_label   = nil
              finalize_context()
            end,
            on_cancel    = function(reason)
              if reaper.ValidatePtr2(0, fi.tr, "MediaTrack*") then
                reaper.DeleteTrack(fi.tr)
              end
              -- PreventUIRefresh(-1) already done by scan_fx_params_deep_body.
              close_fx_inspect_undo("ReaAssist: fx_inspect (cancelled)")
              S._fx_inspect_tmp   = nil
              S._deep_scan_started = false
              S._deep_scan_label   = nil
              if reason == "cancelled" then
                -- User cancelled: abort the whole turn. The chat Cancel
                -- button already resets status/display; just bail.
                -- Clear leftover deferred-assemble + silent flag so they
                -- don't poison the next turn.
                S._fx_params_pending_assemble  = nil
                S._fx_inspect_silent_for_fx_params = nil
                return
              end
              if S._fx_inspect_silent_for_fx_params then
                Log.line("FX_PARAMS",
                  "silent auto-inspect deep scan failed (continuing): "
                  .. tostring(reason))
              else
                history_content = history_content
                  .. "FX INSPECT ERROR: Deep scan failed ("
                  .. tostring(reason) .. ").\n\n"
              end
              finalize_context()
            end,
          })
          if not _started_ok then
            -- start_deep_scan rejected the request (already active, missing
            -- opts, or _estimate_deep_probes threw). Neither on_complete nor
            -- on_cancel will fire, so unwind the resources fx_inspect_load
            -- set up: hidden temp track, PreventUIRefresh(+1), and any
            -- legacy open Undo block. Without this the UI stops repainting
            -- and stale cleanup state can bleed into the session.
            Log.line("DEEP_SCAN", "chat: start_deep_scan returned false for "
              .. fi.id .. "; unwinding fx_inspect resources")
            if reaper.ValidatePtr2(0, fi.tr, "MediaTrack*") then
              reaper.DeleteTrack(fi.tr)
            end
            reaper.PreventUIRefresh(-1)
            close_fx_inspect_undo("ReaAssist: fx_inspect (start_deep_scan failed)")
            S._fx_inspect_tmp    = nil
            S._deep_scan_started = false
            S._deep_scan_label   = nil
            if not S._fx_inspect_silent_for_fx_params then
              history_content = history_content
                .. "FX INSPECT ERROR: deep scan could not start (see debug log).\n\n"
            end
            -- Bypass shallow-success path; continue with the rest of
            -- finalize_context (fx_params assemble, sticky build, etc.).
            params_list, max_group, total_count, needs_deep = nil, nil, nil, nil
            goto fx_inspect_done
          end
          return  -- coroutine runs; on_complete will re-call finalize_context
        end

        -- Shallow scan succeeded: cache, format, append inline.
        FXCache.put_plugin(fi.id, params_list, total_count, max_group, false)
        if S._fx_cache_events then
          local t = S._fx_cache_events
          t.cached = t.cached or {}
          t.cached[#t.cached+1] = fi.id
        end
        reaper.DeleteTrack(fi.tr)
        reaper.PreventUIRefresh(-1)
        close_fx_inspect_undo("ReaAssist: fx_inspect")
        if not S._fx_inspect_silent_for_fx_params then
          local inspect_data = CTX.format_fx_params(
            fi.id, params_list, max_group, fi.names, true)
          -- Sticky only -- pinned-slot emission on follow-up build.
          local fi_key = "fx_inspect:" .. tbl_concat(fi.names, "/")
          Net.sticky_set(fi_key, inspect_data)
          fetched_to_sticky[#fetched_to_sticky+1] = fi_key
        end
        S._fx_inspect_tmp = nil
        ::fx_inspect_done::
        end  -- end of ValidatePtr2 else
      end

      -- Assemble fx_params content now (any auto-inspect above has populated
      -- the cache, so enum/range annotations are picked up by CTX.fx_params).
      if S._fx_params_pending_assemble then
        local a = S._fx_params_pending_assemble
        local fx_str = CTX.fx_params(a.proj, a.names)
        -- Sticky only -- pinned-slot emission on follow-up build.
        Net.sticky_set(a.fp_key, fx_str)
        fetched_to_sticky[#fetched_to_sticky+1] = a.fp_key
        S._fx_params_pending_assemble = nil
      end

      -- Sticky context (plugin_ref, preferred_plugins, fx_params, fx_inspect)
      -- is emitted by Net.build_body_* as a pinned user/assistant pair after
      -- the api_ref pin -- no longer re-injected into per-turn history content.
      -- This keeps the moving cache breakpoint from having to re-write sticky
      -- bytes on every turn. See Net.sticky_text().
      -- Loop-recovery hint: prepended when the previous response from the
      -- model was a duplicate <context_needed> for already-provided data.
      -- See LOOP DETECTION in process_response_buckets. Carries the actual
      -- re-requested tags so the message names them rather than relying on
      -- generic "plugin parameter / preferred plugins" copy that doesn't
      -- match docs:* / midi / api_ref shapes.
      local reuse_hint_fired = false
      if S._midi_docs_suppressed_hint then
        history_content = history_content
          .. "(NOTE: You requested <context_needed>"
          .. S._midi_docs_suppressed_hint
          .. "</context_needed>, but the pinned `midi` reference is the "
          .. "intended reference for this MIDI note/item workflow. Do NOT "
          .. "request docs, docs:items, or docs:tempo solely for MIDI item "
          .. "or note code. Use the pinned MIDI reference plus the prompt's "
          .. "track-creation rules and generate the code now.)\n\n"
        S._midi_docs_suppressed_hint = nil
        reuse_hint_fired = true
      end
      if S._timecode_context_hint and #S._timecode_context_hint > 0 then
        local tags_str = tbl_concat(S._timecode_context_hint, ", ")
        history_content = history_content
          .. "(NOTE: You requested <context_needed>"
          .. tags_str
          .. "</context_needed>, but for this native SMPTE/LTC/MTC "
          .. "timecode-generator request those tags are already covered by "
          .. "the pinned docs/session/routing references or are not "
          .. "applicable. Do NOT request prompt_bundle:plugin, docs:items, "
          .. "docs:routing, session, docs, or docs_extended again for this "
          .. "turn. Generate the runnable Lua now. Use REAPER's native "
          .. "timecode-generator action lookup with broad fallback pairs "
          .. "(`timecode`+`generator`, then `smpte`+`generator`, then "
          .. "`ltc`/`mtc`+`generator`). Do not create a helper target track "
          .. "before running the action; let the native action create or "
          .. "choose the generator item track, then detect which track "
          .. "actually received the generated timecode item before routing, "
          .. "preferably using GetSelectedMediaItem followed by "
          .. "GetMediaItemTrack/GetMediaItem_Track. Do not identify it by "
          .. "source filename or fall back to a pre-created track if "
          .. "detection fails. Route the final generator track to hardware "
          .. "outputs 3/4 with "
          .. "CreateTrackSend(track, nil), send category 1, I_DSTCHAN = 2, "
          .. "and B_MAINSEND disabled.)\n\n"
        S._timecode_context_hint = nil
        reuse_hint_fired = true
      end
      if S._irrelevant_context_hint and #S._irrelevant_context_hint > 0 then
        local tags_str = tbl_concat(S._irrelevant_context_hint, ", ")
        history_content = history_content
          .. "(NOTE: You requested <context_needed>"
          .. tags_str
          .. "</context_needed>, but that context is not applicable to this "
          .. "request. This is a native REAPER workflow, not an FX/plugin "
          .. "workflow. The relevant docs/session/routing references are "
          .. "already pinned above. USE THEM NOW to generate runnable Lua. "
          .. "Do NOT emit another <context_needed> tag for these tags.)\n\n"
        S._irrelevant_context_hint = nil
        reuse_hint_fired = true
      end
      if S._jsfx_context_hint and #S._jsfx_context_hint > 0 then
        local tags_str = tbl_concat(S._jsfx_context_hint, ", ")
        history_content = history_content
          .. "(NOTE: You requested <context_needed>"
          .. tags_str
          .. "</context_needed>, but this is a JSFX authoring/install "
          .. "request. The pinned JSFX bundle is the applicable reference. "
          .. "Do NOT request prompt_bundle:plugin or any other "
          .. "<context_needed> tag for this turn. Generate the requested "
          .. "```jsfx code block now. If the user also asked to create a "
          .. "track and add the JSFX, include exactly one complete ```lua "
          .. "companion block after the JSFX that creates/resolves the "
          .. "track, adds the saved JSFX by its ReaAssist path, and adds "
          .. "any requested marker.)\n\n"
        S._jsfx_context_hint = nil
        reuse_hint_fired = true
      end
      if S._context_reuse_hint and #S._context_reuse_hint > 0 then
        local tags_str = tbl_concat(S._context_reuse_hint, ", ")
        history_content = history_content
          .. "(NOTE: The reference/context data you requested ("
          .. tags_str
          .. ") is already present in PINNED REFERENCES above. "
          .. "USE IT NOW to generate the code. Do NOT emit another "
          .. "<context_needed> tag for these tags.)\n\n"
        S._context_reuse_hint = nil  -- one-shot
        reuse_hint_fired = true
      end
      if S._mixed_output_hint then
        history_content = history_content
          .. "(NOTE: Your previous reply emitted prose alongside the "
          .. "<context_needed> tag. The fetch was honored anyway, but the "
          .. "prose was hidden from the user. Per the system prompt, when "
          .. "you need data your entire reply must be the bare tag -- no "
          .. "prose before or after. On future turns, emit ONLY the tag.)\n\n"
        S._mixed_output_hint = nil  -- one-shot
      end
      if S._fx_inspect_dropped then
        history_content = history_content
          .. "(NOTE: fx_inspect can only load ONE plugin per call. Loaded data "
          .. "for the first name above; NOT loaded: "
          .. tbl_concat(S._fx_inspect_dropped, ", ")
          .. ". To get parameters for the missing plugin(s), emit a separate "
          .. "<context_needed>fx_inspect:Name</context_needed> for each one in "
          .. "your follow-up turn -- or <context_needed>plugin_ref:Name"
          .. "</context_needed> if it's a curated plugin (Pro-Q 4, Pro-C 3, "
          .. "Pro-G, Pro-L 2, ReaEQ, ReaComp, etc.). DO NOT infer the missing "
          .. "plugin's parameters, indices, or enum mappings from the loaded "
          .. "plugin's data; they are unrelated.)\n\n"
        S._fx_inspect_dropped = nil  -- one-shot
      end
      -- Pointer to the pinned sticky slot. Each fetched bucket (plugin_ref /
      -- pref_plugins / fx_inspect / fx_params / docs_extended) lives ONLY
      -- in Net.sticky_text() now -- no inline duplication in this message.
      -- The pointer tells the model its <context_needed> was satisfied and
      -- to read the data above so it doesn't re-emit another context_needed.
      if #fetched_to_sticky > 0 then
        Log.line("DISPATCH",
          "fetched_to_sticky=[" .. tbl_concat(fetched_to_sticky, ", ") .. "]")
        -- Suppress when the loop-recovery hint above already fired -- it
        -- carries stronger imperative wording naming the same tags.
        if not reuse_hint_fired then
          history_content = history_content
            .. "(The data for <context_needed> tag(s) "
            .. tbl_concat(fetched_to_sticky, ", ")
            .. " is now present in PINNED REFERENCES above. USE IT NOW to "
            .. "generate the code. Do NOT emit another <context_needed> tag "
            .. "for these tags.)\n\n"
        end
      end
      history_content = history_content .. "USER REQUEST:\n" .. S.pending_orig_prompt

      -- Update the Show Details context label to reflect all injected buckets.
      if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
        local dmsg = S.display_messages[S.pending_display_idx]
        -- Build updated label: start from existing, append newly injected buckets.
        local parts = {}
        local existing = dmsg.ctx_label or ""
        if existing ~= "" then parts[#parts+1] = existing end
        if wants_session and not existing:find("snapshot") then
          parts[#parts+1] = "snapshot"
        end
        if wants_tracks then parts[#parts+1] = "tracks" end
        -- "docs" and "api_ref" alias the same content; skip if either is
        -- already in the chip label so we don't render both.
        if wants_docs and not existing:find("api_ref", 1, true)
                      and not existing:find("docs",    1, true) then
          parts[#parts+1] = "docs"
        end
        if wants_docs_extended then parts[#parts+1] = "docs_extended" end
        if wants_plugin_ref then
          parts[#parts+1] = #plugin_ref_names > 0
            and ("plugin_ref:" .. tbl_concat(plugin_ref_names, "/")) or "plugin_ref"
        end
        if wants_fx_list then
          parts[#parts+1] = #fx_list_search > 0
            and ("fx_list:" .. tbl_concat(fx_list_search, "/")) or "fx_list"
        end
        if wants_fx_chains   then parts[#parts+1] = "fx_chains" end
        if wants_track_flags then parts[#parts+1] = "track_flags" end
        if wants_fx_params then
          parts[#parts+1] = #fx_filter_names > 0
            and ("fx:" .. CTX.fx_filter_key(fx_filter_names)) or "fx_params"
        end
        if wants_midi  then parts[#parts+1] = "midi" end
        if wants_theme then parts[#parts+1] = "theme" end
        if wants_recent_reaper_changes then
          parts[#parts+1] = "recent_reaper_changes"
        end
        if wants_pref_plugins then
          parts[#parts+1] = #pref_plugin_types > 0
            and ("pref:" .. tbl_concat(pref_plugin_types, "/")) or "pref_plugins"
        end
        if wants_fx_inspect and not S._fx_inspect_silent_for_fx_params then
          parts[#parts+1] = #fx_inspect_names > 0
            and ("fx_inspect:" .. tbl_concat(fx_inspect_names, "/")) or "fx_inspect"
        end
        -- Append sticky context labels not already covered by fresh buckets.
        local existing_joined = tbl_concat(parts, " + ")
        local sticky_keys = {}
        for skey in pairs(S.sticky_context) do sticky_keys[#sticky_keys+1] = skey end
        table.sort(sticky_keys)
        for _, skey in ipairs(sticky_keys) do
          if not existing_joined:find(skey, 1, true) then
            parts[#parts+1] = skey
          end
        end
        dmsg.ctx_label = #parts > 0 and tbl_concat(parts, " + ") or ""
      end

      -- Clear the silent-inspect flag now that all gating consumers
      -- (history append, sticky context, ctx_label) have read it.
      S._fx_inspect_silent_for_fx_params = nil

      local fallback = "Tried to load additional project info but the "
        .. "follow-up request didn't go through. Please try again."
      Net.fire_validator_retry({
        kind = "docs",
        history_content = history_content,
        ctx_label = "docs",
        failure_message = (RA and RA.t and RA.t(
          "response.context_followup_failed", nil, fallback)) or fallback,
      })
    end  -- finalize_context

    -- If fx_inspect loaded a plugin, poll until it's initialised (params
    -- readable) before finalizing. Heavy plugins (large sample libs, complex
    -- synths) may need more than one frame. Max ~1 second (30 retries).
    if S._fx_inspect_tmp then
      local inspect_retries = 0
      local function try_inspect_read()
        local fi = S._fx_inspect_tmp
        -- Guard: S._fx_inspect_tmp could have been cleared between defer
        -- cycles by another path (dev_signal cancel, project switch handler,
        -- etc.). Without this, the timeout branch's fi.tr / fi.names derefs
        -- below would crash 30 frames later.
        if not fi then
          S._fx_inspect_tmp = nil
          return
        end
        -- ValidatePtr2 before touching fi.tr: across up to 30 defer cycles
        -- (~1s) the user could switch projects or delete the track, leaving
        -- a dangling pointer that would crash TrackFX_GetNumParams.
        if not reaper.ValidatePtr2(0, fi.tr, "MediaTrack*") then
          reaper.PreventUIRefresh(-1)
          if fi.undo_open then
            reaper.Undo_EndBlock("ReaAssist: fx_inspect (invalid track)", 0)
            fi.undo_open = false
          end
          S._fx_inspect_tmp = nil
          -- Honor the silent-inspect contract: when this inspect was an
          -- auto-trigger from fx_params (not user-requested), do not leak
          -- "FX INSPECT ERROR" prose into history_content (which becomes
          -- the model prompt). Mirrors the timeout branch below.
          if not S._fx_inspect_silent_for_fx_params then
            history_content = history_content
              .. "FX INSPECT ERROR: temporary track was invalidated before params could be read.\n\n"
          end
          finalize_context()
          return
        end
        local np = R_TrackFX_GetNumParams(fi.tr, fi.fx) or 0
        if np > 0 then
          finalize_context()
        elseif inspect_retries < 30 then
          inspect_retries = inspect_retries + 1
          reaper.defer(try_inspect_read)
        else
          -- Timed out - clean up and report.
          if reaper.ValidatePtr2(0, fi.tr, "MediaTrack*") then
            reaper.DeleteTrack(fi.tr)
          end
          reaper.PreventUIRefresh(-1)
          if fi.undo_open then
            reaper.Undo_EndBlock("ReaAssist: fx_inspect (timeout)", 0)
            fi.undo_open = false
          end
          S._fx_inspect_tmp = nil
          if S._fx_inspect_silent_for_fx_params then
            Log.line("FX_PARAMS",
              "silent auto-inspect timed out (continuing): "
              .. tbl_concat(fi.names, ", "))
          else
            history_content = history_content
              .. "FX INSPECT ERROR: Plugin did not initialise in time ("
              .. tbl_concat(fi.names, ", ") .. "). "
              .. "Try adding the plugin manually first, then use fx_params.\n\n"
          end
          finalize_context()
        end
      end
      reaper.defer(try_inspect_read)
    else
      finalize_context()
    end
    return true
  end

  -- LOOP DETECTION: tag was non-empty (#raw_tokens > 0) but produced no
  -- wants_* -- meaning every requested bucket was either gated by a *_sent
  -- flag or is an unknown name. The model is re-asking for context it
  -- already has (or inventing bucket names). One recovery attempt if a
  -- sticky sent-set was the blocker (clear it + retry with a "use it" hint);
  -- otherwise surface a clean error with recovery buttons instead of
  -- dumping the raw tag as the assistant reply.
  if #raw_tokens > 0 then
    -- "had_sticky" -> the previous turn or earlier in this turn injected
    -- some piece of pinned data, so the model's re-request is plausibly
    -- about that already-pinned data and worth one retry with a hint.
    -- Detection has to cover both the per-name dedup tables and the
    -- one-shot booleans -- the model could be re-asking for a single
    -- bucket (docs, session, midi, theme, fx_*) just as easily as a
    -- named one (plugin_ref:X, prompt_bundle:X, preferred_plugins:X).
    local had_sticky =
         next(S.plugin_ref_sent)
      or next(S.pref_plugins_sent)
      or next(S.prompt_bundle_sent)
      or S.docs_already_sent
      or S.docs_extended_already_sent
      or next(S.docs_section_sent)
      or S.session_already_sent
      or S.fx_params_already_sent
      or S.fx_list_already_sent
      or S.fx_chains_already_sent
      or S.track_flags_already_sent
      or S.midi_already_sent
      or S.theme_already_sent
      or S.fx_inspect_already_sent
    if had_sticky and (S.context_loop_retries or 0) < 1 then
      S.context_loop_retries = (S.context_loop_retries or 0) + 1
      Log.line("CONTEXT_LOOP",
        "model re-requested already-provided context; clearing all sent flags + adding hint")
      -- Clear every gating flag that the per-token elseif chain checks,
      -- so whatever bucket the model re-emitted falls through ungated on
      -- the recursive pass and triggers a fresh fetch + follow-up call
      -- with the "use it" hint. Earlier versions only cleared the per-
      -- name dedup tables (plugin_ref_sent, pref_plugins_sent, eventually
      -- prompt_bundle_sent), which fixed plugin-shaped loops but missed
      -- the simpler one-shot booleans (docs / session / midi / theme /
      -- fx_*). Sonnet-class models have been observed re-emitting any of these
      -- under the right conditions, so we now clear the full set.
      S.plugin_ref_sent              = {}
      S.pref_plugins_sent            = {}
      S.prompt_bundle_sent           = {}
      S.docs_already_sent            = false
      S.docs_extended_already_sent   = false
      S.docs_section_sent            = {}
      S.session_already_sent         = false
      S.tracks_already_sent          = false
      S.fx_params_already_sent       = false
      S.fx_list_already_sent         = false
      S.fx_chains_already_sent       = false
      S.track_flags_already_sent     = false
      S.midi_already_sent            = false
      S.theme_already_sent           = false
      S.fx_inspect_already_sent      = false
      S._context_reuse_hint = S._context_reuse_hint or {}
      for _, t in ipairs(raw_tokens) do
        S._context_reuse_hint[#S._context_reuse_hint+1] = t
      end
      return Net.process_response_buckets(text)
    else
      Log.line("CONTEXT_LOOP",
        "unresolvable context loop; aborting turn with user error")
      Net._restore_pending_user_history()
      local fallback = "The model re-requested context that was already provided. "
        .. "Try rephrasing your request, or switch to a different model."
      Log.add_error((RA and RA.t and RA.t(
        "response.context_loop", nil, fallback)) or fallback)
      S.status = "idle"
      return true  -- treat as handled so caller doesn't display the raw tag
    end
  end
  return false
end

-- =============================================================================
-- Net.resolve_popup_resume: resume a turn blocked by the resolve-type popup
-- =============================================================================
-- Called by the popup's action buttons once the user picks a plugin. Synthesizes
-- a <context_needed>plugin_ref:<identifier>> tag and re-enters the dispatcher so
-- the follow-up API call fires with the correct plugin reference injected.
--
-- The caller is responsible for persisting the user's choice to preferred_types
-- if they want the next turn to resolve without a popup (see popup "Use this"
-- button handler).
-- Returns true iff `name` matches a section in the curated plugin_ref cache
-- (after alias resolution). Used by resolve_popup_resume to decide whether
-- to inject the picked plugin via plugin_ref:<identifier> (curated -- has
-- recipes/golden-ratios) or preferred_plugins:<type> (third-party -- live
-- params from the just-saved preference + FX cache scan).
local function _is_in_plugin_ref(name)
  if not name or name == "" then return false end
  -- Trigger lazy-load of the cache if not yet built. CTX.plugin_ref builds
  -- it on first call; the probe arg returns a no-match string but populates
  -- CTX._plugin_ref_cache as a side effect.
  if not CTX._plugin_ref_cache then
    local ok_probe, probe_err = pcall(CTX.plugin_ref, {"__probe__"})
    if not ok_probe then
      Log.line("PLUGIN_REF",
        "plugin_ref probe failed: " .. tostring(probe_err))
    end
  end
  if not CTX._plugin_ref_cache then return false end
  local k = name:lower():match("^%s*(.-)%s*$") or ""
  local aliases = (CTX and CTX.PLUGIN_REF_ALIASES) or {}
  k = aliases[k] or k
  return CTX._plugin_ref_cache[k] ~= nil
end

function Net.resolve_popup_resume(identifier)
  if not RA.code_runtime_loaded() then
    return RA.fail_code_runtime_unavailable("before resuming plugin resolution", "idle")
  end
  if not RA.context_loaded() then
    return RA.fail_context_unavailable("before resuming plugin resolution", "idle")
  end

  -- Capture popup type, pending resolves, and any wants_* state stashed by a
  -- popup-bailed parse loop BEFORE clearing state. The popup may already
  -- have been cleared by the typed-pick handler (which clears it early so
  -- the chat status doesn't keep saying "Waiting for selection..." through
  -- a slow scan); in that case we read the type from S.resolve_pending_type
  -- which the typed-pick handler stashed for exactly this purpose.
  local resolve_type    = (S.resolve_popup and S.resolve_popup.type)
                       or S.resolve_pending_type
                       or nil
  S.resolve_pending_type = nil
  local pending         = S.pending_resolves or {}
  local pending_pr      = S.pending_plugin_ref_names or {}
  local pending_pp      = S.pending_pref_plugin_types or {}
  S.pending_resolves          = {}
  S.pending_plugin_ref_names  = {}
  S.pending_pref_plugin_types = {}

  -- Clear popup state. pending_orig_prompt / pending_snapshot / pending_display_idx
  -- stay intact -- the dispatcher re-enters finalize_context which uses them.
  S.resolve_popup        = nil
  S.resolve_popup_text   = ""
  S.resolve_popup_error  = nil
  S.resolve_popup_matches     = {}
  S.resolve_popup_sel         = 0
  S.resolve_popup_last_filter = nil
  S.resolve_popup_refocus     = false
  S.status               = "waiting"
  -- Clear the per-name sent set so the synthesized plugin_ref actually injects
  -- (a previous turn in this session may have sent plugin_ref for other names).
  S.plugin_ref_sent = {}

  -- Build the synthesized tag. For the picked plugin:
  --   * Curated (in plugin_ref.md, e.g. ReaEQ/ReaComp/ReEQ) -> plugin_ref:<id>
  --     gives the model recipes + verified normalized values.
  --   * Third-party (e.g. VST3: Pro-C 3) -> preferred_plugins:<type>
  --     surfaces live params from the just-completed FX cache scan. Falling
  --     back to plugin_ref here would inject "no reference data for: <id>" --
  --     a useless placeholder that wastes a round-trip.
  -- Then append any resolve:<type> tokens that were dropped when this popup
  -- bailed the parser loop, so the model gets all originally-requested data
  -- without having to re-emit them itself.
  local synth = {}
  -- 1) Any wants_* state that was lost when an earlier popup bailed the loop.
  -- Re-emit as explicit buckets so the data the user already picked is
  -- restored without another popup.
  for _, n in ipairs(pending_pr) do
    synth[#synth+1] = "plugin_ref:" .. n
  end
  for _, t in ipairs(pending_pp) do
    synth[#synth+1] = "preferred_plugins:" .. t
  end
  -- 2) The bucket for the plugin the user just picked in THIS popup.
  if resolve_type and not _is_in_plugin_ref(identifier) then
    synth[#synth+1] = "preferred_plugins:" .. resolve_type
  else
    synth[#synth+1] = "plugin_ref:" .. identifier
  end
  -- 3) Any resolve:Type tokens that were dropped when this popup bailed the
  -- loop. They go LAST so any popup they trigger re-stashes (1) and (2)'s
  -- buckets correctly via the bail-stash code in the resolve branch.
  for _, ptype in ipairs(pending) do
    synth[#synth+1] = "resolve:" .. ptype
  end

  local fake_text = "<context_needed>" .. tbl_concat(synth, ", ") .. "</context_needed>"
  local fired = Net.process_response_buckets(fake_text)
  if not fired then
    -- Dispatcher didn't fire the follow-up. Safety net: drop back to idle
    -- so the user isn't stuck watching "waiting" forever.
    Log.line("RESOLVE", "resume: dispatcher didn't fire for " .. identifier
      .. " -- aborting turn")
    S.status = "idle"
    local fallback = "Couldn't resume the request after your selection. "
      .. "Please try sending the message again."
    Log.add_error((RA and RA.t and RA.t(
      "response.resume_failed", nil, fallback)) or fallback)
  end
end

-- =============================================================================
-- Called by the main loop (throttled to CFG.POLL_THROTTLE) while waiting for
-- a curl response. Handles in order:
--   1. Watchdog timeout: fires an error if the per-provider timeout is exceeded.
--   2. Exit code file: detects curl network errors and captures diagnostics.
--   3. Partial-read guard: waits for closing brace before parsing.
--   4. JSON decode and API error envelope detection (auth, rate-limit, overload).
--   5. Auto-retry on 529 (overloaded_error) with exponential backoff (2s, 4s, 8s).
--   6. <context_needed> detection: injects requested buckets and fires a follow-up.
--   7. Normal final response: updates display, S.history, token counters, and cost.
-- Watchdog timeout check. Returns true if the request has exceeded the
-- per-provider poll timeout and the timeout has been surfaced to the user
-- (via tier-test abort, key-test abort, or chat error). Caller should
-- return immediately on true.
--
-- Must stay above the curl --max-time set in Net.fire_curl so curl gets the
-- chance to write its exit code before the watchdog fires. Custom providers
-- use their user-configured request_timeout + 15s slack.
function Net._handle_watchdog_timeout()
  local p_active = PROVIDERS[S.pending_provider_idx] or PROVIDERS.active()
  local poll_timeout = (p_active.is_custom
    and ((tonumber(p_active.request_timeout) or 600) + 15))
    or (prefs.cloud_request_timeout or CFG.CLOUD_TIMEOUT_DEFAULT)
  local elapsed = S.send_time and (time_precise() - S.send_time) or 0
  if not S.send_time or elapsed <= poll_timeout then
    return false
  end
  local timeout_msg
  if p_active.id == "google" then
    timeout_msg = RA.t("network.timeout.gemini", nil,
      "The request timed out while waiting for Google's Gemini service. "
        .. "Gemini may be overloaded or temporarily unavailable. If the rest "
        .. "of your internet is working, this is a provider-side availability "
        .. "issue, not a problem with your prompt, API key, or ReaAssist.\n\n"
        .. "Try again in a moment. If it keeps happening, switch to a faster "
        .. "Gemini model or another provider for this request.")
  else
    timeout_msg = RA.t("network.timeout.generic", nil,
      "The request timed out. The server may be busy, or your internet "
        .. "connection may have dropped.\n\n"
        .. "Try sending your message again.")
  end
  local debug = Net._curl_failure_debug(nil, timeout_msg, "watchdog_timeout")
  debug.elapsed_s = elapsed
  debug.poll_timeout_s = poll_timeout
  -- Kill the orphaned curl before clearing state. curl's own --max-time is
  -- far above this watchdog, so without an explicit kill the process keeps
  -- running and its late write into tmp.out/tmp.exit can be parsed as the
  -- NEXT request's response. kill_curl reads tmp.pid itself and arms the
  -- deferred-kill watchdog when the pid file hasn't landed yet. Skip for
  -- tier tests: they never capture a PID, and kill_curl's early bail would
  -- clear S.gemini_tier_pending before the tier branch below can log it.
  if not S.gemini_tier_pending then
    Net.kill_curl()
  end
  S.curl_pid  = nil
  S.send_time = nil
  if S.gemini_tier_pending then
    -- Tier test timed out: ambiguous result. Don't persist `false` -- a
    -- transient timeout shouldn't bake in a wrong tier classification.
    -- Pro filter still treats `nil` as "not paid" (gates on `~= true`),
    -- so the user doesn't gain Pro access; they just get a retest on
    -- next opportunity instead of being stuck.
    S.gemini_tier_pending = false
    Log.line("TIER-TEST", "interpreted as: ambiguous (timeout; not persisted)")
    if UI and UI.show_float_toast then
      UI.show_float_toast(RA.t("gemini.toast.tier_timeout", nil,
        "Gemini tier check timed out - will retry"), "err")
    end
    if p_active.id == "google" then MODELS.refresh() end
    return true
  end
  if S.key_test_pending then
    local test_prov_id = S.key_test_provider
    S.key_test_pending  = false
    S.key_test_provider = nil
    S.status = "error"
    if api_keys.custom_conn_test and api_keys.custom_conn_test.active
       and api_keys.screen == "custom_llm" then
      CTX.custom_conn_test_advance(false,
        Custom.t("settings.custom.error.response_timeout", nil,
          "Timed out waiting for response."))
      return true
    end
    if #api_keys.test_queue > 0 and (api_keys.screen == "first_run" or api_keys.screen == "settings") and test_prov_id then
      Net.advance_key_test_queue(test_prov_id, false,
        RA.t("network.key_test.timeout_short", nil,
          "The server took too long to respond."))
      return true
    end
    -- Append rather than clobber: preserves chat history if the key test
    -- somehow fires while a conversation is on screen.
    Log.add_error(
      RA.t("network.key_test.timeout_detail", nil,
        "The server took too long to respond while checking your key. "
          .. "Your key is stored for this session but has not been permanently "
          .. "saved yet. Try sending a message to test it. Once verified, "
          .. "it will be saved automatically."
          .. "\n\nIf that doesn't work, click the Settings button to re-enter your key."))
    return true
  end
  if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
    S.display_messages[S.pending_display_idx].ctx_label = "timeout"
  end
  Log.add_error(timeout_msg, nil, nil, nil,
    { error_kind = "watchdog_timeout", error_debug = debug })
  return true
end

function Net._handle_curl_launch_failure()
  if not S.curl_pid or S.gemini_tier_pending then return false end

  if not S.send_time then
    S.curl_pid           = nil
    S.curl_exited_clean  = false
    S.status             = "idle"
    Log.line("CURL", "cleared stale in-flight request with no send timestamp")
    return true
  end

  if (time_precise() - S.send_time) < 3.0 then return false end

  local pid_file = io.open(tmp.pid, "r")
  if pid_file then pid_file:close(); return false end

  local exit_file = io.open(tmp.exit, "r")
  if exit_file then exit_file:close(); return false end

  local out_file = io.open(tmp.out, "r")
  local out = out_file and (out_file:read("*a") or "") or ""
  if out_file then out_file:close() end
  if #out >= 2 then return false end

  local err_file = io.open(tmp.err, "r")
  local err = err_file and (err_file:read("*a") or "") or ""
  if err_file then err_file:close() end
  if #err > 0 then return false end

  S.curl_pid           = nil
  S.send_time          = nil
  S.curl_exited_clean  = false
  S.status             = "idle"
  Log.line("CURL", "network request launcher did not create a pid, exit, or response file")
  Log.add_error(RA.t("network.launch_failed", nil,
    "ReaAssist could not start the network request. Please try sending again."))
  return true
end

-- Check curl's exit-code tmp file. Returns true if curl exited with a
-- non-zero code and the network error has been surfaced (tier abort, key-test
-- abort, or chat error). Caller should return on true. Exit code 0 sets
-- S.curl_exited_clean so the response file becomes eligible for parsing, and
-- returns false so the caller continues parsing.
function Net._handle_curl_exit_failure()
  local ok_ef, ef = pcall(io.open, tmp.exit, "r")
  if not (ok_ef and ef) then return false end
  local exit_str = ef:read("*a"); ef:close()
  local exit_code = tonumber(exit_str:match("(%d+)"))
  if not exit_code then return false end
  if exit_code == 0 then
    -- curl finished cleanly. Only now may tmp.out be parsed, so non-JSON
    -- responses (captive portals, proxy HTML) surface as a clear error instead
    -- of looping until the watchdog fires.
    S.curl_exited_clean = true
    os.remove(tmp.exit)
    os.remove(tmp.err)
    return false
  end
  S.curl_pid  = nil
  S.send_time = nil
  os.remove(tmp.exit)
  local p_active = PROVIDERS[S.pending_provider_idx] or PROVIDERS.active()
  local prov_label = p_active.label
  local curl_errors = {
    [5]  = RA.t("network.curl.proxy", { provider = prov_label },
      "Can't reach the proxy configured for " .. prov_label .. ". "
        .. "Check your network or proxy settings and try again."),
    [6]  = RA.t("network.curl.provider_unreachable", { provider = prov_label },
      "Can't reach the " .. prov_label .. " servers. Please check your "
        .. "internet connection and try again."),
    [7]  = RA.t("network.curl.refused", nil,
      "The server refused the connection. It may be temporarily "
        .. "down. Try again in a few minutes."),
    [18] = RA.t("network.curl.closed_early", nil,
      "The connection closed before the full response arrived. "
        .. "Try sending your message again."),
    [23] = RA.t("network.curl.write_failed", nil,
      "ReaAssist could not write the server response to its temporary "
        .. "file. Check that your REAPER resource folder is writable."),
    [28] = RA.t("network.curl.timeout", nil,
      "The connection timed out. Please check your internet "
        .. "connection and try again."),
    [35] = RA.t("network.curl.secure_failed", nil,
      "Couldn't establish a secure connection. A firewall or "
        .. "network setting may be blocking it."),
    [52] = RA.t("network.curl.no_response", nil,
      "The server closed the connection without sending a response. "
        .. "Try again in a moment."),
    [56] = RA.t("network.curl.dropped", nil,
      "The connection dropped while ReaAssist was receiving the "
        .. "response. Try again in a moment."),
    [60] = RA.t("network.curl.certificate", nil,
      "There's an issue with the server's security certificate. "
        .. "Please check that your computer's date and time are correct."),
    [77] = RA.t("network.curl.cert_bundle", nil,
      "curl could not read its certificate bundle. Check your curl "
        .. "or system certificate installation."),
    [92] = RA.t("network.curl.http2", nil,
      "The HTTP/2 connection failed while talking to the server. "
        .. "Try again; if it repeats, switch networks or disable VPN/proxy."),
  }
  local detail = curl_errors[exit_code]
    or RA.t("network.curl.generic", nil,
      "A network error occurred. Please check your internet "
        .. "connection and try again.")
  local debug = Net._curl_failure_debug(exit_code, detail)
  Log.line("CURL", string.format("exit=%s (%s), provider=%s, model=%s",
    tostring(exit_code), tostring(debug.exit_meaning),
    tostring(debug.provider_id or "?"), tostring(debug.model_id or "?")))
  if S.gemini_tier_pending then
    -- Tier test curl errored: ambiguous result. Same rationale as the
    -- watchdog branch above -- don't persist a wrong classification on
    -- a transient network failure. Retest fires on next opportunity.
    S.gemini_tier_pending = false
    Log.line("TIER-TEST", string.format(
      "interpreted as: ambiguous (curl exit=%d; not persisted)", exit_code))
    if UI and UI.show_float_toast then
      UI.show_float_toast(RA.t("gemini.toast.tier_failed", nil,
        "Gemini tier check failed - will retry"), "err")
    end
    if p_active.id == "google" then MODELS.refresh() end
    return true
  end
  if S.key_test_pending then
    local test_prov_id = S.key_test_provider
    local test_prov    = test_prov_id and PROVIDERS.get(test_prov_id) or nil
    local was_custom   = test_prov and test_prov.is_custom or false
    S.key_test_pending  = false
    S.key_test_provider = nil
    S.status = "error"
    if api_keys.custom_conn_test and api_keys.custom_conn_test.active
       and api_keys.screen == "custom_llm" then
      CTX.custom_conn_test_advance(false, detail)
      return true
    end
    if #api_keys.test_queue > 0 and (api_keys.screen == "first_run" or api_keys.screen == "settings") and test_prov_id then
      Net.advance_key_test_queue(test_prov_id, false, detail)
      return true
    end
    -- On the API key entry screen, surface the error inline (popup) instead
    -- of dumping it into the chat -- the user hasn't left the screen so a
    -- chat message would be invisible. Custom LLM path almost always lands
    -- here when a port is mistyped, so this is the common case.
    if (api_keys.screen == "first_run" or api_keys.screen == "settings") then
      api_keys.key_validating     = false
      api_keys.key_validating_idx = nil
      local key_prov_label = (test_prov and test_prov.label)
        or (was_custom and RA.t("settings.api_key.provider.custom", nil,
          "Custom LLM"))
        or RA.t("settings.api_key.provider.generic", nil,
          "the provider")
      if not was_custom then
        api_keys.key_error = detail
      end
      api_keys.show_key_error_popup = true
      api_keys.key_error_provider   = key_prov_label
      api_keys.key_error_detail     = detail
      api_keys.key_error_hint       = was_custom
        and RA.t("settings.api_key.error.custom_network_hint", nil,
          "Check that the server is running and the URL/port is correct.")
        or RA.t("settings.api_key.error.builtin_network_hint", nil,
          "Check your internet connection and try again.")
      api_keys.key_error_url        = nil
      api_keys.key_error_url_label  = nil
      return true
    end
    -- Append rather than clobber (see timeout branch above).
    Log.add_error(detail .. "\n\n"
      .. RA.t("network.curl.back_online_settings", nil,
        "Once you're back online, click the Settings button to try again."),
      nil, nil, nil, { error_kind = "curl_exit", error_debug = debug })
    return true
  end
  if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
    S.display_messages[S.pending_display_idx].ctx_label = "network error"
  end
  Log.add_error(detail, nil, nil, nil,
    { error_kind = "curl_exit", error_debug = debug })
  return true
end

function Net._transient_non_json_response_reason(raw)
  local lraw = tostring(raw or ""):lower()
  if lraw:find("upstream connect error", 1, true) then
    return "upstream connect error"
  end
  if lraw:find("disconnect/reset before headers", 1, true) then
    return "upstream reset before headers"
  end
  if lraw:find("reset reason:", 1, true)
     and lraw:find("connection termination", 1, true) then
    return "connection termination"
  end
  return nil
end

function Net._schedule_transient_json_retry(raw, debug)
  local reason = Net._transient_non_json_response_reason(raw)
  if not reason or not S.retry_saved_body then return false end
  local max_retries = CFG.MAX_RETRIES
  if (S.retry_count or 0) >= max_retries then return false end

  S.retry_count = (S.retry_count or 0) + 1
  S.retry_max = max_retries
  local delay = CFG.RETRY_DELAY_BASE * (2 ^ (S.retry_count - 1))
  local jitter = CFG.RETRY_JITTER_SECS or 0
  if jitter > 0 then delay = delay + (math.random() * jitter) end
  S.retry_scheduled = true
  S.retry_fire_time = time_precise() + delay
  S.status = "waiting"
  if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
    S.display_messages[S.pending_display_idx].ctx_label =
      str_format("retrying in %.1fs (%d/%d)", delay, S.retry_count, max_retries)
  end
  if debug then
    debug.transient_non_json_reason = reason
    debug.retry_count = S.retry_count
    debug.retry_max = max_retries
  end
  return true
end

function Net._response_shape_summary(value)
  local tv = type(value)
  if tv ~= "table" then return tv end
  if JSON and value == JSON.NULL then return "null" end
  local parts, count = {}, 0
  for k, v in pairs(value) do
    count = count + 1
    if count > 16 then
      parts[#parts + 1] = "..."
      break
    end
    parts[#parts + 1] = tostring(k) .. ":" .. type(v)
  end
  table.sort(parts)
  return "{" .. tbl_concat(parts, ", ") .. "}"
end

function Net._handle_unexpected_response_shape(raw, resp, p, expected_shape)
  Code.safe_write(tmp.log, raw)
  if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
    S.display_messages[S.pending_display_idx].ctx_label = "error"
  end

  local debug = Net._curl_failure_debug(nil, "Unexpected response shape",
    "unexpected_response_shape")
  debug.expected_shape = expected_shape
  debug.response_bytes = #raw
  debug.response_head = Net._debug_scrub(raw:sub(1, 2048))
  debug.response_shape = Net._response_shape_summary(resp)
  if type(resp) == "table" and type(resp.choices) == "table" then
    debug.choices_count = #resp.choices
    if type(resp.choices[1]) == "table" then
      debug.first_choice_shape = Net._response_shape_summary(resp.choices[1])
      if type(resp.choices[1].message) == "table" then
        debug.first_message_shape =
          Net._response_shape_summary(resp.choices[1].message)
      end
    end
  end
  local kind = Net.normalize_error_kind("unexpected_response_shape",
    "unexpected_response_shape")
  debug.normalized_error_kind = kind
  local extra = { error_kind = kind, error_debug = debug }
  if p and p.is_custom then
    local fallback =
      "The custom provider returned JSON, but not in the OpenAI-compatible "
      .. "chat-completions shape ReaAssist expected. Check that this provider "
      .. "points to a chat-completions endpoint for the selected model, then "
      .. "try again.\n\nDetails were saved to the debug log."
    Log.add_error((RA and RA.t and RA.t(
      "response.custom_unexpected_shape", nil, fallback)) or fallback,
      nil, nil, nil, extra)
  else
    Log.add_error(RA.t("response.unexpected", nil,
      "Got an unexpected response from the server. This is likely a "
        .. "temporary issue.\n\nPlease try again."),
      nil, nil, nil, extra)
  end
end

-- JSON decode failed. Log raw body, tag the display entry, and show an
-- error. If the response looks like HTML, surface the proxy/captive-portal
-- explanation instead of a generic "unreadable JSON" message.
function Net._handle_json_decode_error(raw, decode_err)
  Code.safe_write(tmp.log, raw)
  local debug = Net._curl_failure_debug(nil, "JSON decode failed",
    "json_decode_error")
  debug.decode_error = decode_err and tostring(decode_err) or nil
  debug.response_bytes = #raw
  debug.response_head = Net._debug_scrub(raw:sub(1, 2048))
  if Net._schedule_transient_json_retry(raw, debug) then return end
  if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
    S.display_messages[S.pending_display_idx].ctx_label = "error"
  end
  local extra = { error_kind = "json_decode_error", error_debug = debug }
  local raw_head = raw:sub(1, 256):lower()
  local looks_html = raw_head:find("<!doctype", 1, true)
                  or raw_head:find("<html",     1, true)
                  or raw_head:find("<head",     1, true)
                  or raw_head:find("502 bad",   1, true)
                  or raw_head:find("503 ",      1, true)
                  or raw_head:find("504 ",      1, true)
  local looks_5xx = raw_head:find("502", 1, true)
                 or raw_head:find("503", 1, true)
                 or raw_head:find("504", 1, true)
  if looks_html then
    local p = PROVIDERS[S.pending_provider_idx] or PROVIDERS.active()
    if p and p.id == "google" and looks_5xx then
      local fallback =
        "Google's Gemini service returned a 5xx provider error instead "
        .. "of a JSON API response. This usually means Gemini is overloaded "
        .. "or temporarily unavailable, not that your prompt, API key, or "
        .. "ReaAssist failed.\n\n"
        .. "Wait a moment and retry. If it keeps happening, switch to a "
        .. "faster Gemini model or another provider for this request."
      Log.add_error(
        (RA and RA.t and RA.t("response.html_gemini_5xx", nil, fallback))
          or fallback,
        nil, nil, nil, extra)
    else
      local fallback =
        "The server returned an HTML page instead of a JSON response. This "
        .. "usually means a proxy, firewall, or captive portal (hotel/coffee "
        .. "shop Wi-Fi) is intercepting the request, or the API endpoint is "
        .. "temporarily down behind a 5xx gateway error.\n\n"
        .. "Try a different network, disable any VPN/proxy, or wait a few "
        .. "minutes and retry."
      Log.add_error(
        (RA and RA.t and RA.t("response.html_non_json", nil, fallback))
          or fallback,
        nil, nil, nil, extra)
    end
  else
    local fallback = "Got an unreadable response from the server. This is usually "
      .. "a temporary glitch."
    if decode_err then
      fallback = fallback .. "\n\nTechnical detail: " .. decode_err
        .. "\n\nPlease try again."
      Log.add_error((RA and RA.t and RA.t(
        "response.unreadable_detail", { detail = decode_err }, fallback))
          or fallback, nil, nil, nil, extra)
    else
      fallback = fallback .. "\n\nPlease try again."
      Log.add_error((RA and RA.t and RA.t(
        "response.unreadable", nil, fallback)) or fallback,
        nil, nil, nil, extra)
    end
  end
end

-- Unified API error handler used by all providers. Maps error types to
-- user-facing messages; provider-specific billing/console links are pulled
-- from the `p` provider record so the same handler works for all three.
--
-- inner_type: provider-specific error code string (e.g. "rate_limit_error",
--   "insufficient_quota", "RESOURCE_EXHAUSTED"). is_overloaded triggers the
--   exponential-backoff auto-retry (up to CFG.MAX_RETRIES). is_auth wipes
--   the stored key and prompts re-entry.
function Net._recoverable_openai_throttle(p, inner_type, api_err)
  if not p or p.id ~= "openai" then return false end
  local code = tostring(inner_type or "")
  if code ~= "rate_limit_exceeded" and code ~= "rate_limit_error" then return false end
  local lmsg = tostring(api_err or ""):lower()
  if lmsg:find("billing", 1, true)
      or lmsg:find("credit", 1, true)
      or lmsg:find("insufficient_quota", 1, true)
      or lmsg:find("exceeded your current quota", 1, true) then
    return false
  end
  return true
end

function Net._retry_after_hint_seconds(api_err)
  local lmsg = tostring(api_err or ""):lower()
  local n = tonumber(lmsg:match("try again in%s+([%d%.]+)%s*ms"))
  if n then return n / 1000 end
  n = tonumber(lmsg:match("try again in%s+([%d%.]+)%s*s"))
  if n then return n end
  n = tonumber(lmsg:match("try again in%s+([%d%.]+)%s*sec"))
  if n then return n end
  return nil
end

function Net._recoverable_anthropic_server_error(inner_type, api_err)
  if tostring(inner_type or "") ~= "api_error" then return false end
  local lmsg = tostring(api_err or ""):lower()
  return lmsg:find("internal server error", 1, true) ~= nil
end

function Net._overload_retry_policy(p, inner_type, api_err)
  local max_retries = CFG.MAX_RETRIES
  local jitter = 0
  local min_delay = nil
  if p and p.id == "google"
     and (tostring(inner_type) == "UNAVAILABLE" or tostring(inner_type) == "503") then
    max_retries = CFG.GEMINI_OVERLOAD_MAX_RETRIES or max_retries
    jitter = CFG.RETRY_JITTER_SECS or 0
  elseif p and p.id == "anthropic"
     and Net._recoverable_anthropic_server_error(inner_type, api_err) then
    jitter = CFG.RETRY_JITTER_SECS or 0
  elseif Net._recoverable_openai_throttle(p, inner_type, api_err) then
    max_retries = CFG.OPENAI_THROTTLE_MAX_RETRIES or max_retries
    jitter = CFG.RETRY_JITTER_SECS or 0
    min_delay = Net._retry_after_hint_seconds(api_err)
  end
  return max_retries, CFG.RETRY_DELAY_BASE, jitter, min_delay
end

function Net._google_capacity_recovery(p)
  if not p or p.id ~= "google" or not S.pending_orig_prompt then return nil end
  local models = p.models or {}
  local current_model = models[S.pending_model_idx or prefs.model_idx] or nil
  local current_id = current_model and current_model.id or nil
  local function model_price(m)
    return tonumber(m and m.price_in) or 0
  end
  local function stronger_flash(a, b)
    if not a then return b end
    if not b then return a end
    local ap, bp = model_price(a), model_price(b)
    if bp ~= ap then return (bp > ap) and b or a end
    return b
  end
  local function best_flash_below(max_price)
    local best
    for _, m in ipairs(models) do
      if m ~= current_model and m.is_flash and not m.paid_only then
        local price = model_price(m)
        if not max_price or price < max_price then
          best = stronger_flash(best, m)
        end
      end
    end
    return best
  end
  local fallback
  if current_model and current_model.is_flash and not current_model.paid_only then
    fallback = best_flash_below(model_price(current_model))
  elseif current_model and model_price(current_model) > 0 then
    fallback = best_flash_below(model_price(current_model))
  else
    fallback = best_flash_below(nil)
  end
  local recovery = {
    provider_id = "google",
    model_id = current_id,
    recovery_prompt = S.pending_orig_prompt,
    recovery_attachments = S.pending_attachments,
  }
  if fallback then
    recovery.fallback_provider_id = "google"
    recovery.fallback_model_id = fallback.id
    recovery.fallback_label = fallback.label or fallback.id
  end
  return recovery
end

function Net.normalize_error_kind(raw_kind, failure_kind)
  if type(Diag) == "table"
     and type(Diag.normalize_error_kind) == "function" then
    return Diag.normalize_error_kind(raw_kind, { failure_kind = failure_kind })
  end
  local k = tostring(raw_kind or failure_kind or ""):lower():gsub("%s+", "_")
  if k ~= "" then return k:gsub("[^a-z0-9_]+", "_") end
  return "provider_api_error"
end

function Net._pending_turn_state_keys()
  local out = {}
  if S.pending_orig_prompt then out[#out + 1] = "orig_prompt" end
  if S.pending_display_idx then out[#out + 1] = "display_idx" end
  if S.pending_snapshot then out[#out + 1] = "snapshot" end
  if S.pending_project then out[#out + 1] = "project" end
  if S.pending_attachments and #S.pending_attachments > 0 then
    out[#out + 1] = "attachments"
  end
  if S.retry_scheduled then out[#out + 1] = "retry_scheduled" end
  if #out == 0 then return nil end
  return out
end

function Net._provider_rate_limit_message(api_err)
  local retry_after = Net._retry_after_hint_seconds(api_err)
  local wait_s = retry_after and math.max(1, math.ceil(retry_after)) or 30
  local calls = tonumber(S.api_calls_this_turn) or 0
  if calls > 1 then
    return RA.t("response.provider_rate_limited_many",
      { calls = calls, seconds = wait_s },
      "The provider is rate-limiting ReaAssist right now. This turn already used "
        .. tostring(calls)
        .. " hidden context/retry API calls, so the throttle can appear even "
        .. "though you only sent one visible message.\n\nWait about "
        .. tostring(wait_s)
        .. " seconds before trying again. ReaAssist keeps the original prompt "
        .. "attached during automatic throttle retries; if this message appears, "
        .. "those retries have already been exhausted for this turn."
        .. "\n\nIf this keeps happening, try switching models in the dropdown.")
  end
  return RA.t("response.provider_rate_limited_one",
    { seconds = wait_s },
    "The provider is rate-limiting ReaAssist right now. This can happen after recent internal retries or provider throughput bursts, even if this is your first visible message in a while.\n\nWait about "
      .. tostring(wait_s)
      .. " seconds before trying again. ReaAssist keeps the original prompt attached during automatic throttle retries; if this message appears, those retries have already been exhausted for this turn.\n\nIf this keeps happening, try switching models in the dropdown.")
end

function Net._provider_error_extra(p, inner_type, effective_type, api_err, failure_kind)
  local idx = S.pending_model_idx
  if not idx and type(prefs) == "table" then idx = prefs.model_idx end
  local model_id = nil
  if p and type(p.models) == "table" and idx then
    local m = p.models[idx]
    model_id = m and m.id or nil
  end
  local provider_id = p and (p.is_custom and "custom" or p.id) or nil
  if p and p.is_custom then model_id = "custom" end
  local kind = effective_type
  if kind == nil or kind == "" then kind = inner_type end
  if kind == nil or kind == "" then kind = "api_error" end
  local raw_type = inner_type and tostring(inner_type) or nil
  if raw_type == "" then raw_type = nil end
  local mapped_type = effective_type and tostring(effective_type) or nil
  if mapped_type == "" then mapped_type = nil end
  local normalized_kind = Net.normalize_error_kind(kind, failure_kind)
  return {
    error_kind = normalized_kind,
    error_debug = {
      failure_kind = failure_kind or "provider_api_error",
      normalized_error_kind = normalized_kind,
      provider_id = provider_id,
      model_id = model_id,
      error_type = raw_type,
      effective_type = mapped_type,
      raw_provider_error_type = raw_type,
      raw_effective_error_type = mapped_type,
      response_head = api_err,
      api_calls_this_turn = S.api_calls_this_turn,
      max_api_calls_per_turn = CFG.MAX_CALLS_PER_TURN,
      retry_count = S.retry_count,
      retry_max = S.retry_max,
      retry_after_s = Net._retry_after_hint_seconds(api_err),
      retry_scheduled = S.retry_scheduled == true,
      retry_fire_in_s = S.retry_scheduled and S.retry_fire_time
        and math.max(0, S.retry_fire_time - time_precise()) or nil,
      request_elapsed_s = S.request_start_time
        and (time_precise() - S.request_start_time) or nil,
      session_status_before = S.status or nil,
      pending_display_idx = S.pending_display_idx,
      pending_turn_state = Net._pending_turn_state_keys(),
    },
  }
end

function Net._handle_api_error(p, inner_type, api_err, is_overloaded, is_auth)
  -- Auto-retry on overload (Anthropic 529, or provider-specific equivalents).
  local max_retries, retry_base, retry_jitter, retry_min_delay =
    Net._overload_retry_policy(p, inner_type, api_err)
  if is_overloaded and S.retry_count < max_retries then
    S.retry_count = S.retry_count + 1
    S.retry_max = max_retries
    local delay = retry_base * (2 ^ (S.retry_count - 1))
    if retry_min_delay and retry_min_delay > delay then delay = retry_min_delay end
    if retry_jitter > 0 then delay = delay + (math.random() * retry_jitter) end
    S.retry_scheduled = true
    S.retry_fire_time = time_precise() + delay
    S.status = "waiting"
    if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
      S.display_messages[S.pending_display_idx].ctx_label =
        str_format("retrying in %.1fs (%d/%d)", delay, S.retry_count, max_retries)
    end
    return
  end

  if Net._recoverable_openai_throttle(p, inner_type, api_err) then
    if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
      S.display_messages[S.pending_display_idx].ctx_label = "provider throttle"
    end
    Log.add_error(RA.t("response.openai_throttle_exhausted", nil,
      "OpenAI is throttling this request because the account/model "
        .. "token-per-minute limit is temporarily saturated. This is a "
        .. "provider-side throughput limit, not a Lua or prompt failure.\n\n"
        .. "ReaAssist retried with exponential backoff and OpenAI still returned "
        .. "a rate-limit error. Wait a minute and retry, or switch to a smaller "
        .. "model for this request."),
      nil, nil, nil,
      Net._provider_error_extra(p, inner_type, "rate_limit_exceeded", api_err,
        "provider_throttle"))
    return
  end

  if p and p.id == "google" and is_overloaded then
    if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
      S.display_messages[S.pending_display_idx].ctx_label = "provider capacity"
    end
    local recovery = Net._google_capacity_recovery(p)
    local msg
    if recovery and recovery.fallback_model_id then
      msg = RA.t("response.google_503_recovery", {
          label = recovery.fallback_label or "the fallback model",
        },
        "Google's Gemini service returned 503 UNAVAILABLE: this model is currently at capacity or temporarily unavailable. This is a provider-side availability issue, not a problem with your prompt, API key, or ReaAssist.\n\nReaAssist retried with exponential backoff and Google still returned 503 UNAVAILABLE. You can retry the same model, or switch to "
          .. tostring(recovery.fallback_label or "the fallback model")
          .. " and resend the same message.")
    elseif recovery then
      msg = RA.t("response.google_503_retry", nil,
        "Google's Gemini service returned 503 UNAVAILABLE: this model is currently at capacity or temporarily unavailable. This is a provider-side availability issue, not a problem with your prompt, API key, or ReaAssist.\n\nReaAssist retried with exponential backoff and Google still returned 503 UNAVAILABLE. You can retry the same message.")
    else
      msg = RA.t("response.google_503", nil,
        "Google's Gemini service returned 503 UNAVAILABLE: this model is currently at capacity or temporarily unavailable. This is a provider-side availability issue, not a problem with your prompt, API key, or ReaAssist.\n\nReaAssist retried with exponential backoff and Google still returned 503 UNAVAILABLE. You can wait and retry later.")
    end
    local extra = Net._provider_error_extra(p, inner_type, "UNAVAILABLE",
      api_err, "provider_capacity")
    if type(recovery) == "table" then
      for k, v in pairs(recovery) do extra[k] = v end
    end
    Log.add_error(msg, nil, nil, recovery and "google_model_capacity" or nil,
      extra)
    return
  end

  if is_auth then
    if p.key_extstate ~= nil then
      S.api_key = nil
      S.api_key_map[p.id] = nil
      Key.clear(p.key_extstate)
    end
    if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
      S.display_messages[S.pending_display_idx].ctx_label = "auth error"
    end
    local extra = Net._provider_error_extra(p, inner_type, inner_type, api_err,
      "provider_auth_error")
    extra.storage_note = RA.t("response.api_key_storage_note_v2", nil,
      "Your key was stored locally with reversible obfuscation, not OS-vault "
        .. "encryption. The install-path binding is why it cannot be decoded "
        .. "after being copied or moved.")
    Log.add_error(RA.t("response.api_key_invalid",
      { provider = p.label },
      "Your " .. p.label .. " API key isn't working. It may have expired or been "
        .. "entered incorrectly.\n\n"
        .. "Click the Settings button below to enter a new one.\n\n"
        .. "You can find or create a key here:"),
      p.console_url, p.console_label, nil, extra)
    return
  end

  -- Error map. Messages that reference provider name or billing URL are
  -- rebuilt with p fields; others are constant but kept together here so
  -- the table stays a single source of truth.
  local error_info = {
    -- Anthropic
    rate_limit_error      = { label = "provider throttle",
      msg_fn = Net._provider_rate_limit_message },
    credit_balance_error  = { label = "out of credits",
      msg = RA.t("response.credits_exhausted", { provider = p.label },
        "Your " .. p.label .. " account has run out of credits."
          .. "\n\nTo continue using ReaAssist, add funds to your account:"),
      link_url = p.billing_url, link_label = p.billing_label },
    overloaded_error      = { label = "overloaded",
      msg = RA.t("response.provider_overloaded", nil,
        "The servers are busy right now. Wait a moment and try again; this usually clears up quickly.") },
    api_error             = { label = "provider service error",
      msg = RA.t("response.provider_internal_error", nil,
        "The provider service returned a temporary internal server error. "
          .. "This is a provider-side service issue, not a problem with your "
          .. "prompt, API key, or ReaAssist.\n\n"
          .. "ReaAssist retried with exponential backoff and the provider still "
          .. "failed. Wait a moment and try again, or switch models for this request.") },
    invalid_request_error = { label = "invalid request",
      msg = RA.t("response.context_too_long", nil,
        "This conversation has gotten too long for the model to handle."
          .. "\n\nTo fix this:\n- Click + new chat to start fresh\n"
          .. "- Try a shorter message\n"
          .. "- Turn off \"Always include REAPER API reference\" or Send snapshot to reduce size") },
    not_found_error       = { label = "model not found",
      msg = RA.t("response.model_not_found", nil,
        "That model doesn't seem to exist anymore. It may have been "
          .. "renamed or retired.\n\nTry picking a different one from the dropdown below.") },
    permission_error      = { label = "permission denied",
      msg = RA.t("response.permission_denied", nil,
        "Your API key doesn't have access to this model. This usually "
          .. "means it requires a higher account tier.\n\nTry a different model, "
          .. "or check your plan here:"),
      link_url = p.billing_url, link_label = p.billing_label },
    -- OpenAI
    rate_limit_exceeded   = { label = "provider throttle",
      msg = RA.t("response.openai_rate_limit", nil,
        "OpenAI is throttling this request because the account/model "
          .. "token-per-minute limit is temporarily saturated. This is a "
          .. "provider-side throughput limit, not a Lua or prompt failure.\n\n"
          .. "Wait a minute and try again, or switch to a smaller model for this request.") },
    server_error          = { label = "provider service error",
      msg = RA.t("response.provider_server_error", nil,
        "The provider service returned a temporary server error. "
          .. "This is a provider-side service issue, not a problem with your "
          .. "prompt, API key, or ReaAssist.\n\n"
          .. "ReaAssist retried with exponential backoff and the provider still "
          .. "failed. Wait a moment and try again, or switch models for this request.") },
    overloaded            = { label = "provider busy",
      msg = RA.t("response.provider_busy", nil,
        "The provider service is busy right now. This is a provider-side "
          .. "capacity issue, not a problem with your prompt, API key, or ReaAssist.\n\n"
          .. "ReaAssist retried with exponential backoff and the provider still "
          .. "failed. Wait a moment and try again, or switch models for this request.") },
    insufficient_quota    = { label = "out of credits",
      msg = RA.t("response.credits_exhausted", { provider = p.label },
        "Your " .. p.label .. " account has run out of credits."
          .. "\n\nTo continue using ReaAssist, add funds to your account:"),
      link_url = p.billing_url, link_label = p.billing_label },
    model_not_found       = { label = "model not found",
      msg = RA.t("response.model_not_found", nil,
        "That model doesn't seem to exist anymore. It may have been "
          .. "renamed or retired.\n\nTry picking a different one from the dropdown below.") },
    -- Google
    RESOURCE_EXHAUSTED    = { label = "provider throttle",
      msg_fn = Net._provider_rate_limit_message },
    RESOURCE_EXHAUSTED_BILLING = { label = "out of quota",
      msg = RA.t("response.google_quota_exhausted", nil,
        "Your Google account has exhausted its Gemini quota."
          .. "\n\nIf you're on the free tier, you may need to enable billing. "
          .. "If you're on a paid plan, add funds or check your usage limits:"),
      link_url = p.billing_url, link_label = p.billing_label },
    NOT_FOUND             = { label = "model not found",
      msg = RA.t("response.google_model_not_found", nil,
        "That model doesn't seem to exist anymore. Try picking a different one.") },
    PERMISSION_DENIED     = { label = "permission denied",
      msg = RA.t("response.google_permission_denied", nil,
        "Your API key doesn't have access to this model."),
      link_url = p.billing_url, link_label = p.billing_label },
  }

  -- Reclassify generic error types into funding errors when the message
  -- mentions credits/quota/billing -- gives the user actionable billing links
  -- instead of a misleading "try again later" or "conversation too long".
  -- Anthropic in particular returns invalid_request_error for both context-
  -- window overflow AND "Your credit balance is too low..."; without this
  -- the credits case shows the context-overflow copy.
  local effective_type = inner_type
  if api_err then
    local lmsg = api_err:lower()
    if inner_type == "rate_limit_error" and lmsg:find("credit") then
      effective_type = "credit_balance_error"
    elseif inner_type == "invalid_request_error"
       and (lmsg:find("credit") or lmsg:find("balance") or lmsg:find("billing")) then
      effective_type = "credit_balance_error"
    elseif inner_type == "rate_limit_exceeded"
       and (lmsg:find("quota") or lmsg:find("billing") or lmsg:find("exceeded your current")) then
      effective_type = "insufficient_quota"
    elseif inner_type == "RESOURCE_EXHAUSTED"
       and (lmsg:find("quota") or lmsg:find("billing") or lmsg:find("limit.*exceed")) then
      effective_type = "RESOURCE_EXHAUSTED_BILLING"
    end
  end

  local is_throttle =
    effective_type == "rate_limit_error"
    or effective_type == "rate_limit_exceeded"
    or effective_type == "RESOURCE_EXHAUSTED"
  if is_throttle
      and S.retry_saved_body
      and (S.retry_count or 0) < math.min(CFG.MAX_RETRIES or 1, 3) then
    S.retry_count = (S.retry_count or 0) + 1
    S.retry_max = math.min(CFG.MAX_RETRIES or 1, 3)
    local delay = Net._retry_after_hint_seconds(api_err) or 30
    delay = math.max(5, math.min(90, math.ceil(delay)))
    S.retry_scheduled = true
    S.retry_fire_time = time_precise() + delay
    S.status = "waiting"
    if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
      S.display_messages[S.pending_display_idx].ctx_label =
        str_format("rate-limit retry in %.0fs (%d/%d)",
          delay, S.retry_count, S.retry_max)
    end
    return
  end

  local info  = error_info[effective_type]
  local label = info and info.label or "api error"
  local msg   = info and (info.msg or (info.msg_fn and info.msg_fn(api_err)))
    or ("Something went wrong. Please try again."
      .. (api_err and ("\n\nDetails: " .. api_err) or ""))
  if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
    S.display_messages[S.pending_display_idx].ctx_label = label
  end
  if api_err and not info then
    msg = msg .. "\n\nDetails: " .. api_err
  end
  Log.add_error(msg, info and info.link_url, info and info.link_label, nil,
    Net._provider_error_extra(p, inner_type, effective_type, api_err,
      "provider_api_error"))
end

function Net.response_file_ready_to_parse(raw)
  if type(raw) ~= "string" or #raw < 2 then return false, "empty" end
  return true, nil
end

function Net.try_finish_curl()
  if not S.curl_pid then return end

  if Net._handle_curl_launch_failure() then return end

  if Net._handle_watchdog_timeout() then return end

  if Net._handle_curl_exit_failure() then return end

  if not S.curl_exited_clean then return end

  -- Read the response file (pcall handles transient AV scanner file locks).
  local ok_f, f = pcall(io.open, tmp.out, "r")
  if not ok_f or not f then return end
  local raw = f:read("*a"); f:close()
  local ready, reason = Net.response_file_ready_to_parse(raw)
  if not ready then
    return
  end

  local elapsed = S.send_time and (time_precise() - S.send_time) or nil
  S.curl_pid  = nil
  S.send_time = nil

  Log.response(raw, elapsed)

  if S.gemini_tier_pending then
    Net.handle_gemini_tier_test(raw)
    return
  end

  if S.key_test_pending then
    Net.handle_key_test(raw)
    return
  end

  if not RA.code_runtime_loaded() then
    RA.fail_code_runtime_unavailable("while processing the response", "idle")
    return
  end
  if not RA.context_loaded() then
    RA.fail_context_unavailable("while processing the response", "idle")
    return
  end

  -- Probe timing: end curl_wait and start response_parse.
  -- Placed after the early-return paths above (gemini tier test, key
  -- test) so those don't attribute curl_wait time to a regular turn.
  Probe.mark_phase_end(S.probe_turn, "curl_wait")
  Probe.mark_phase_start(S.probe_turn, "response_parse")
  local resp, decode_err = JSON.decode(raw)
  Probe.mark_phase_end(S.probe_turn, "response_parse")
  if not resp or type(resp) ~= "table" then
    Net._handle_json_decode_error(raw, decode_err)
    return
  end

  -- ==========================================================================
  -- Provider-specific error handling and response extraction.
  -- Each provider has different error envelope formats and response structures.
  -- The dispatch calls a provider-specific handler that either:
  --   (a) handles the error (shows UI feedback) and returns, or
  --   (b) extracts text and tokens and falls through to the common post-parse flow.
  -- Uses the provider/model snapshot from send time, not current UI state,
  -- so a mid-request provider switch doesn't corrupt parsing.
  -- ==========================================================================
  local p = PROVIDERS[S.pending_provider_idx] or PROVIDERS.active()


  -- ---------------------------------------------------------------------------
  -- Provider-specific error detection and response extraction.
  -- Each block either calls Net._handle_api_error + return, or sets text/tokens and
  -- falls through to the common post-parse flow below.
  -- ---------------------------------------------------------------------------
  -- empty_reason carries provider-specific context for the empty-text path so
  -- the post-parse error message can name the actual cause (length cap hit on
  -- reasoning tokens, content filter, refusal) instead of the generic fallback.
  local text, raw_tok_in, raw_tok_out, tok_in_read, tok_in_create
  local empty_reason, refusal_text, reasoning_only_tokens

  if p.id == "anthropic" then
    -- Anthropic error envelope: {"type":"error","error":{"type":"...","message":"..."}}
    if resp.type == "error" and type(resp.error) == "table" and resp.error ~= JSON.NULL then
      local it = resp.error.type
      local em = type(resp.error.message) == "string" and resp.error.message or ""
      Net._handle_api_error(p, it, em,
        it == "overloaded_error"
          or Net._recoverable_anthropic_server_error(it, em),
        it == "authentication_error")
      return
    end
    -- Validate structure.
    if resp.type ~= "message" or type(resp.content) ~= "table" then
      Code.safe_write(tmp.log, raw)
      if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
        S.display_messages[S.pending_display_idx].ctx_label = "error"
      end
      Log.add_error(RA.t("response.unexpected", nil,
        "Got an unexpected response from the server. This is likely a "
          .. "temporary issue.\n\nPlease try again."))
      return
    end
    -- Extract text. Also count thinking / redacted_thinking blocks so they
    -- aren't silently dropped if a future build enables extended thinking on
    -- Claude (today thinking_levels=nil for the Claude provider, so this path
    -- only activates if/when that changes -- but the count goes into the log
    -- so we'll know the moment it does, and tool-use turns won't break by
    -- surprise from missing-thinking-block 400s).
    local text_parts = {}
    local thinking_blocks = 0
    for _, block in ipairs(resp.content) do
      if type(block) == "table" then
        if block.type == "text" and type(block.text) == "string" then
          text_parts[#text_parts+1] = block.text
        elseif block.type == "thinking" or block.type == "redacted_thinking" then
          thinking_blocks = thinking_blocks + 1
        end
      end
    end
    if thinking_blocks > 0 then
      Log.line("ANTHROPIC", "received " .. thinking_blocks
        .. " thinking block(s) (not preserved in history; enable a thinking-aware "
        .. "history adapter before using extended thinking with tool use)")
    end
    -- "\n\n" between content blocks rather than a single "\n": a code
    -- fence at the end of one block plus prose at the start of the next
    -- would otherwise concatenate to "```\nLine of prose" and break the
    -- fence. Anthropic almost always returns a single text block today,
    -- but the join cost is identical and the multi-block case is safer.
    text = #text_parts > 0 and tbl_concat(text_parts, "\n\n") or nil
    -- Diagnostic fields for the empty-text branch. Anthropic uses
    --   stop_reason="max_tokens" -> output cap hit
    --   stop_reason="refusal"    -> model declined the request
    if resp.stop_reason == "max_tokens" then
      empty_reason = "length"
    elseif resp.stop_reason == "refusal" then
      empty_reason = "refusal"
    end
    -- Tokens: Anthropic includes cache breakdown.
    local usage     = type(resp.usage) == "table" and resp.usage or {}
    local base      = tonumber(usage.input_tokens)                or 0
    tok_in_create   = tonumber(usage.cache_creation_input_tokens) or 0
    tok_in_read     = tonumber(usage.cache_read_input_tokens)     or 0
    raw_tok_in      = base + tok_in_create + tok_in_read
    raw_tok_out     = tonumber(usage.output_tokens) or 0

  elseif p.id == "openai" or p.id == "deepseek" or p.is_custom then
    -- OpenAI error envelope: {"error":{"type":"...","message":"...","code":"..."}}
    -- Custom OpenAI-compatible endpoints (Ollama, LM Studio, vLLM, OpenRouter,
    -- etc.) and DeepSeek follow the same wire format, so they share this branch.
    if type(resp.error) == "table" and resp.error ~= JSON.NULL then
      local code = resp.error.code or resp.error.type or ""
      local em = type(resp.error.message) == "string" and resp.error.message or ""
      local is_auth = (code == "invalid_api_key")
        or (em:lower():find("api key", 1, true) ~= nil)
      local is_overloaded = (code == "server_error" or code == "overloaded")
        or Net._recoverable_openai_throttle(p, code, em)
      Net._handle_api_error(p, code, em, is_overloaded, is_auth)
      return
    end
    -- Validate structure: {"choices":[{"message":{"content":"..."}}]}
    if type(resp.choices) ~= "table" or #resp.choices == 0
       or type(resp.choices[1].message) ~= "table" then
      Net._handle_unexpected_response_shape(raw, resp, p,
        "choices[1].message.content")
      return
    end
    local choice  = resp.choices[1]
    local message = choice.message
    text = message.content
    -- Capture diagnostic fields so the empty-text branch can name the cause:
    --   finish_reason="length"  -> reasoning/output budget exhausted
    --   finish_reason="content_filter" -> safety filter blocked output
    --   message.refusal (string) -> model declined the request
    if type(message.refusal) == "string" and message.refusal ~= "" then
      refusal_text = message.refusal
      empty_reason = "refusal"
    elseif choice.finish_reason == "length" then
      empty_reason = "length"
    elseif choice.finish_reason == "content_filter" then
      empty_reason = "content_filter"
    end
    -- Tokens: OpenAI usage. prompt_tokens is the TOTAL input (including cached),
    -- and prompt_tokens_details.cached_tokens is the portion served from the
    -- automatic prefix cache. GPT-5.6+ also reports cache_write_tokens in the
    -- same object; those tokens are billed at the model's 1.25x write rate.
    --
    -- DeepSeek reports cache hits at the top level of usage as
    -- prompt_cache_hit_tokens / prompt_cache_miss_tokens (not nested under
    -- prompt_tokens_details). Caching is automatic on prefix and there is no
    -- separate cache-write fee, so tok_in_create also stays 0.
    local usage   = type(resp.usage) == "table" and resp.usage or {}
    raw_tok_in    = tonumber(usage.prompt_tokens)     or 0
    raw_tok_out   = tonumber(usage.completion_tokens) or 0
    if p.id == "deepseek" then
      tok_in_read = tonumber(usage.prompt_cache_hit_tokens) or 0
      tok_in_create = 0
    else
      local details = type(usage.prompt_tokens_details) == "table"
                      and usage.prompt_tokens_details or {}
      tok_in_read   = tonumber(details.cached_tokens) or 0
      tok_in_create = p.id == "openai"
        and (tonumber(details.cache_write_tokens) or 0) or 0
    end
    -- Reasoning-token count for the length-cap error path. Lets the user see
    -- exactly how much of the cap went to internal reasoning vs visible output.
    local cdet    = type(usage.completion_tokens_details) == "table"
                    and usage.completion_tokens_details or {}
    reasoning_only_tokens = tonumber(cdet.reasoning_tokens) or 0

  elseif p.id == "google" then
    -- Gemini error envelope: {"error":{"code":N,"message":"...","status":"..."}}
    if type(resp.error) == "table" and resp.error ~= JSON.NULL then
      local status = resp.error.status or ""
      local code   = resp.error.code or 0
      local msg    = resp.error.message or ""
      local is_auth = (status == "UNAUTHENTICATED" or code == 401)
      local is_overloaded = (code == 503 or status == "UNAVAILABLE")
      -- Cache miss: the cachedContent we referenced no longer exists server-
      -- side (TTL expired, or deleted out-of-band). Drop local cache state
      -- so the next send rebuilds without the stale reference. We don't
      -- auto-retry here because reconstructing the body would require
      -- re-plumbing attachments; a manual resend costs one click and is rare.
      local cache_miss = S.gemini_cache_name
        and (code == 404 or status == "NOT_FOUND"
             or (msg:find("[Cc]ached") and msg:find("[Nn]ot found")))
      if cache_miss then
        Net.gemini_cache_invalidate()
        if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
          S.display_messages[S.pending_display_idx].ctx_label = "cache expired"
        end
        Log.add_error(RA.t("response.gemini_cache_expired", nil,
          "The Gemini context cache expired between sends. "
            .. "Please send your message again; a fresh cache will be "
            .. "created automatically."))
        S.status = "error"
        return
      end
      -- Fallback free-tier detection on a paid_only model. Only persist the
      -- "free" classification on positive quota evidence; paid accounts can
      -- return transient 429/RESOURCE_EXHAUSTED during throughput bursts.
      local cur_model = p.models[S.pending_model_idx or prefs.model_idx]
        or MODELS[S.pending_model_idx or prefs.model_idx]
      if cur_model and cur_model.paid_only
         and Net._gemini_error_has_free_tier_signal(resp.error) then
        Store.set_gemini_paid_tier(false)
        MODELS.refresh()
        if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
          S.display_messages[S.pending_display_idx].ctx_label = "api error"
        end
        Log.add_error(RA.t("response.gemini_paid_required", nil,
          "Gemini Pro requires a paid Google account. "
            .. "Your account appears to be on the free tier.\n\n"
            .. "The model has been switched to Flash Lite. "
            .. "To use Pro, enable billing at aistudio.google.com/apikey."))
        return
      end
      Net._handle_api_error(p, status, resp.error.message, is_overloaded, is_auth)
      return
    end
    -- Validate structure: {"candidates":[{"content":{"parts":[{"text":"..."}]}}]}
    -- Note: when finishReason is MAX_TOKENS/SAFETY/RECITATION, the candidate
    -- may be present without a `content` block, so we treat that as the
    -- empty-text case (with an explanatory empty_reason) rather than as a
    -- malformed response.
    if type(resp.candidates) ~= "table" or #resp.candidates == 0 then
      Code.safe_write(tmp.log, raw)
      if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
        S.display_messages[S.pending_display_idx].ctx_label = "error"
      end
      Log.add_error(RA.t("response.unexpected", nil,
        "Got an unexpected response from the server. This is likely a "
          .. "temporary issue.\n\nPlease try again."))
      return
    end
    local cand    = resp.candidates[1]
    local content = type(cand.content) == "table" and cand.content or nil
    -- Extract text from all parts (if a content block exists at all).
    if content and type(content.parts) == "table" then
      local text_parts = {}
      for _, part in ipairs(content.parts) do
        if type(part) == "table" and type(part.text) == "string" then
          text_parts[#text_parts+1] = part.text
        end
      end
      text = #text_parts > 0 and tbl_concat(text_parts, "\n") or nil
    end
    -- Diagnostic fields for the empty-text branch.
    if cand.finishReason == "MAX_TOKENS" then
      empty_reason = "length"
    elseif cand.finishReason == "SAFETY" or cand.finishReason == "RECITATION" then
      empty_reason = "content_filter"
    end
    -- Tokens: Gemini usageMetadata. promptTokenCount is the TOTAL input
    -- (including cached), and cachedContentTokenCount is the portion served
    -- from an explicit context cache (billed at a discounted rate).
    local usage   = type(resp.usageMetadata) == "table" and resp.usageMetadata or {}
    raw_tok_in    = tonumber(usage.promptTokenCount)     or 0
    raw_tok_out   = tonumber(usage.candidatesTokenCount) or 0
    tok_in_read   = tonumber(usage.cachedContentTokenCount) or 0
    tok_in_create = 0  -- Gemini has no per-turn cache-create token cost
    -- Gemini reports thinking tokens separately in thoughtsTokenCount.
    reasoning_only_tokens = tonumber(usage.thoughtsTokenCount) or 0
  end

  -- Probe request metadata and usage capture.
  -- Fires after each successful response extraction by any provider
  -- branch. Multi-request turns (context-needed re-fires, validator
  -- retries) accumulate one entry per HTTP round-trip in the turn's
  -- requests array. Provider-internal early-return retry paths
  -- (e.g., beta-header rejection -> retry) bypass this site by
  -- design; those provider-internal retries are intentionally outside
  -- this per-turn request summary.
  do
    local model_entry = MODELS[S.pending_model_idx or prefs.model_idx]
                     or MODELS[1]
    local thinking_lvl
    if p.thinking_levels and prefs.thinking_idx and prefs.thinking_idx > 0 then
      local tl = p.thinking_levels[prefs.thinking_idx]
      if tl then thinking_lvl = tl.id or tl.label end
    end
    Probe.add_request(S.probe_turn, {
      provider       = p.id,
      model          = model_entry and (model_entry.id or model_entry.label),
      thinking_level = thinking_lvl,
    })
    local total_in     = tonumber(raw_tok_in)    or 0
    local cache_read   = tonumber(tok_in_read)   or 0
    local cache_create = tonumber(tok_in_create) or 0
    local uncached_in  = total_in - cache_read - cache_create
    if uncached_in < 0 then uncached_in = 0 end
    Probe.add_request_usage(S.probe_turn, nil, {
      cache_read   = cache_read,
      cache_create = cache_create,
      uncached_in  = uncached_in,
      output       = tonumber(raw_tok_out) or 0,
    })
  end

  -- Spend preflight for any same-turn continuation must include this call,
  -- even when the response is only <context_needed> or an empty/repairable
  -- result that returns before the normal visible-response accounting block.
  Net._record_turn_budget_usage(p, raw_tok_in, raw_tok_out,
    tok_in_read, tok_in_create)
  Net._record_display_usage(p, raw_tok_in, raw_tok_out,
    tok_in_read, tok_in_create,
    (not text or text == "") and "response_empty" or "response")

  -- Common post-parse: clean up text.
  if text then
    text = text:gsub("\n\n\n+", "\n\n")
    -- Collapse double-newlines between consecutive list items to single newlines.
    text = text:gsub("(\n[%*%-][^\n]*)\n\n([%*%-])", "%1\n%2")
    text = text:match("^(.-)%s*$") or ""
  end

  if not text or text == "" then
    Code.safe_write(tmp.log, raw)

    -- Empty-text-from-length auto-retry. When the model burned the full
    -- output budget on internal reasoning and emitted no visible reply
    -- (observed on gpt-5.4-mini with reasoning_effort=medium and a 16K
    -- cap; mostly defanged by the no-cap-sent change for cloud, but the
    -- failure can still happen at the model's real 128K ceiling on long
    -- complex prompts), silently re-fire the same user prompt with
    -- thinking forced to "none" and a terse "code-only" repair nudge.
    -- Single retry per user prompt -- if even thinking-off doesn't fit,
    -- fall through to the visible error so the user can intervene.
    -- Skipped when the active provider doesn't expose thinking levels
    -- (Anthropic today): nothing to retry-with-different-thinking.
    local _retry_prov = PROVIDERS[S.pending_provider_idx] or PROVIDERS.active()
    -- "Thinking off" is provider-specific. For OpenAI/Gemini, override_idx=0
    -- omits the reasoning_effort field which is effectively off. For
    -- DeepSeek, omitting the "thinking" field falls through to its
    -- server-side default (enabled), so a 0 override would NOT actually
    -- disable reasoning -- it would re-fire with thinking still on and
    -- usually fail the length cap again. Find the "off" entry by value
    -- ("none" for OpenAI, "disabled" for DeepSeek) and use its idx;
    -- providers without an explicit off entry (Gemini's Minimal/Low/Med/
    -- High) fall back to 0 = omit, matching the existing behavior.
    local _retry_off_idx = 0
    if _retry_prov.thinking_levels then
      for _i, _tl in ipairs(_retry_prov.thinking_levels) do
        if _tl.value == "none" or _tl.value == "disabled" then
          _retry_off_idx = _i; break
        end
      end
    end
    -- Don't fire the retry if we are already at the provider's off entry
    -- (the prior request already had thinking off and still hit the cap;
    -- another retry with the same setting won't change anything).
    local _cur_idx = S.thinking_override_idx
      or S.pending_thinking_idx or prefs.thinking_idx
    local _cur_tl  = _retry_prov.thinking_levels
                     and _retry_prov.thinking_levels[_cur_idx]
    local _cur_is_off = _cur_tl
                        and (_cur_tl.value == "none"
                             or _cur_tl.value == "disabled")
    if empty_reason == "length"
       and not S.length_retry_used
       and _retry_prov.thinking_levels
       and not _cur_is_off
       and _cur_idx > 0 then
      S.length_retry_used     = true
      S.thinking_override_idx = _retry_off_idx  -- provider-aware "off"
      local detail = ""
      if reasoning_only_tokens and reasoning_only_tokens > 0 then
        detail = " (" .. reasoning_only_tokens
          .. " reasoning tokens, " .. (raw_tok_out or 0) .. " visible)"
      end
      Log.line("LENGTH-RETRY",
        "empty response from length cap" .. detail
        .. "; retrying with thinking=none (user-invisible)")
      local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT MENTION "
        .. "ANY OF THIS IN YOUR VISIBLE REPLY: Your previous reply consumed "
        .. "the entire output token budget on internal reasoning and "
        .. "produced zero visible output. This retry is firing with "
        .. "reasoning disabled. Deliver the answer concisely: a short "
        .. "lead sentence, the code block, and the standard tip line. "
        .. "Skip recap tables, explanations of decision steps, and any "
        .. "prose beyond what the user actually needs. Respond as if this "
        .. "is your FIRST reply -- do NOT apologize, do NOT say 'let me "
        .. "try again', do NOT mention the retry.)\n\n"
        .. "USER REQUEST:\n" .. (S.pending_orig_prompt or "")
      Net.fire_validator_retry({
        kind = "length",
        history_content = history_content,
        ctx_label = "length_retry",
        retry_failed_key = "retry.reason.after_empty_length_capped_reply",
        retry_failed_label = "after empty length-capped reply",
        failure_message = "Auto-retry after empty length-capped reply did not go through. Please resend the last message.",
      })
      return
    end

    -- Pick a precise label and message based on what the parser captured.
    -- recovery_kind = "token_limit" tells Log.add_error to render the inline
    -- Lower-Thinking + Retry recovery row. (Bump-Max-Tokens was retired
    -- alongside the Max Tokens dropdown -- max_tokens is now per-model
    -- metadata, already at the model's published ceiling for cloud.)
    local label, msg, recovery_kind
    if empty_reason == "length" then
      label = "out of tokens"
      recovery_kind = "token_limit"
      local detail = ""
      if reasoning_only_tokens and reasoning_only_tokens > 0 then
        detail = str_format(
          " (%d of %d output tokens went to internal reasoning)",
          reasoning_only_tokens, raw_tok_out or 0)
      end
      local pending_provider = PROVIDERS[S.pending_provider_idx]
        or PROVIDERS.active()
      local pending_thinking_idx = S.pending_thinking_idx or prefs.thinking_idx
      local has_thinking = pending_provider.thinking_levels
        and pending_thinking_idx > 0
      msg = "The model hit its output token limit before producing any "
        .. "visible response" .. detail .. ".\n"
        .. (has_thinking
          and "Try lowering the Thinking level, or rephrase your message to require less reasoning."
          or  "Try rephrasing your message to require a shorter response, or switch to a different model.")
    elseif empty_reason == "content_filter" then
      label = "filtered"
      msg = "The provider's safety filter blocked the response.\n\n"
        .. "Try rephrasing your message."
    elseif empty_reason == "refusal" then
      label = "refused"
      msg = "The model declined to answer this request."
        .. (refusal_text and ("\n\nDetails: " .. refusal_text) or "")
    else
      -- Generic empty response with finish_reason=stop -- the provider
      -- said "done" but produced no visible content. Observed as
      -- transient flakiness on ChatGPT (completion=3, body empty). Fire
      -- one hidden auto-retry before surfacing the user-facing error;
      -- if the retry also comes back empty, fall through to the error
      -- and the user gets the recovery row. Same scrub-and-rebuild
      -- pattern as the length-cap retry above.
      if not S.empty_retry_used then
        S.empty_retry_used = true
        local empty_retry_thinking_note = ""
        local empty_retry_provider = PROVIDERS[S.pending_provider_idx]
          or PROVIDERS.active()
        if empty_retry_provider.id == "google"
           and empty_retry_provider.thinking_levels then
          S.thinking_override_idx = 1 -- lowest Gemini level; Pro bumps to LOW
          empty_retry_thinking_note =
            "; retrying with lowest Gemini thinking level"
        end
        Log.line("EMPTY-RETRY",
          "empty response from provider; retrying once (user-invisible)"
          .. empty_retry_thinking_note)
        local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
          .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: Your previous "
          .. "reply was empty -- finish_reason=stop with no content. "
          .. "Generate the response now. Respond as if this is your "
          .. "FIRST reply -- do NOT apologize, do NOT mention a retry.)\n\n"
          .. "USER REQUEST:\n" .. (S.pending_orig_prompt or "")
        Net.fire_validator_retry({
          history_content = history_content,
          ctx_label = "empty_retry",
          retry_failed_key = "retry.reason.after_empty_response",
          retry_failed_label = "after empty response",
          failure_message = "Auto-retry after empty response did not go through. Please resend the last message.",
        })
        return
      end
      label = "error"
      recovery_kind = "token_limit"
      local pending_provider2 = PROVIDERS[S.pending_provider_idx]
        or PROVIDERS.active()
      local pending_thinking_idx2 = S.pending_thinking_idx or prefs.thinking_idx
      local has_thinking2 = pending_provider2.thinking_levels
        and pending_thinking_idx2 > 0
      msg = "The model's response was empty after processing, even after a "
        .. "retry. This can happen when the model uses all its output for "
        .. "internal reasoning.\n"
        .. (has_thinking2
          and "Try lowering the Thinking level, or rephrase your message to require less reasoning."
          or  "Try rephrasing your message, or switch to a different model.")
    end

    if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
      local dmsg = S.display_messages[S.pending_display_idx]
      dmsg.ctx_label = label
      if S.request_start_time then
        dmsg.response_time = reaper.time_precise() - S.request_start_time
      end
    end
    -- This branch ends the turn with a visible error after recording
    -- response_time above, so clear the live elapsed timer before surfacing it.
    S.request_start_time = nil
    -- Pop the orphan user message that fired this empty turn. Without
    -- this, the user's manual retry (via the recovery row or by
    -- resending) appends a fresh user entry on top of the orphan and
    -- the next request's history shows the same user prompt twice
    -- (observed: msg [8] bare + msg [9] with snapshot). Auto-retry
    -- paths above (length-cap retry) already do their own pop, so
    -- this only fires when we're returning to idle without an internal
    -- retry. Defensive role check so we never pop an assistant entry.
    if #S.history > 0 and S.history[#S.history].role == "user" then
      S.history[#S.history] = nil
    end
    Log.add_error(msg, nil, nil, recovery_kind)
    return
  end

  -- Dispatch any <context_needed> request to the bucket handler. Returns true
  -- if a follow-up was fired (we bail and wait for the next poll tick).
  if Net.process_response_buckets(text) then return end

  -- Strip any leftover <context_needed> tag. Reaches here only when the
  -- bucket handler returned false (no follow-up fired), which now also
  -- includes the mixed-output case where the model emitted both the tag and
  -- substantive prose. The tag is then noise in the visible reply -- pull it
  -- out (and any trailing whitespace it leaves behind) so the user sees the
  -- prose cleanly.
  text = text:gsub("<%s*context_needed%s*>.-<%s*/%s*context_needed%s*>%s*", "")
  text = text:match("^%s*(.-)%s*$") or ""

  -- Normal final response: update token counters, build display entry, extract code.

  -- Ensure ctx_label is set on the user display entry.
  if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
    local dmsg = S.display_messages[S.pending_display_idx]
    if not dmsg.ctx_label then dmsg.ctx_label = prefs.include_snapshot and "snapshot" or "" end
    if S.request_start_time then
      dmsg.response_time = reaper.time_precise() - S.request_start_time
      -- DO NOT nil request_start_time here. The docs-gate auto-retry below
      -- re-fires a curl after this cleanup runs, and the in-flight
      -- "Thinking..." timer reads request_start_time to stay ticking
      -- across the silent retry. Nil-ing here would freeze the timer at
      -- 0:00 for the duration of the retry. The same logic applies to
      -- S.pending_display_idx (see comment below). Both are cleared at
      -- end-of-turn (status -> idle) at the bottom of Net.process_response.
    end
    if S._fx_cache_events then
      local parts = {}
      local order = { "hit", "cached" }
      local labels = { hit = "Hit", cached = "Cached" }
      for _, key in ipairs(order) do
        local names = S._fx_cache_events[key]
        if names and #names > 0 then
          parts[#parts+1] = labels[key] .. " (" .. tbl_concat(names, ", ") .. ")"
          -- Probe privacy: log the COUNT only, not the
          -- plugin names. Privacy contract bars surfacing
          -- plugin/track names through the diagnostics record.
          for _ = 1, #names do
            Probe.add_fx_cache(S.probe_turn, key)
          end
        end
      end
      if #parts > 0 then
        dmsg.fx_cache_label = tbl_concat(parts, ", ")
      end
    end
    -- Mirror the details bubble into the debug log so users sharing the log
    -- see the same per-exchange metadata (cost, tokens, FX cache) as the UI.
    Log.exchange_summary(dmsg)
  end
  S._fx_cache_events = nil
  -- DO NOT nil S.pending_display_idx here. The docs-gate auto-retry below
  -- re-fires a curl, and Net.fire_curl reads pending_display_idx to
  -- increment dmsg.api_calls (the silent-retry counter shown in Details).
  -- The retry's response also re-enters this block to overwrite dmsg with
  -- the FINAL request's tokens / cost / time -- which is what the user
  -- actually got -- and the docs-gate appends "+ docs" to ctx_label via
  -- the same idx. Nil-ing here breaks all three. End-of-turn cleanup at
  -- the bottom of Net.process_response handles the actual clear.

  -- Before appending the assistant turn, strip any bucket content that was
  -- baked into the user history entry during mid-turn context fetches.
  -- Sticky data (plugin_ref / pref_plugins / fx_params / fx_inspect) lives
  -- in S.sticky_context and is emitted as a pinned prefix slot by
  -- build_body_*, so keeping it in history would duplicate those bytes on
  -- every subsequent turn's cache breakpoint. Restoring history[last] to
  -- just "USER REQUEST: <text>" keeps the moving cache prefix lean.
  Net._restore_pending_user_history()

  -- Store assistant turn in history.
  S.history[#S.history+1] = { role = "assistant", content = text }
  -- Capture the row index now so per-turn run metadata writes below
  -- (run status, validation status, and truncation state) all target the
  -- same row even if some sub-call appends a defensive history entry
  -- between here and the end of try_finish_curl.
  local _asst_hist_idx = #S.history
  S.history[_asst_hist_idx].run_status = "no_code"
  -- Snapshot the user prompt for filters and sticky-context pruning below;
  -- the cleanup block at the end nils S.pending_orig_prompt.
  local _turn_user_intent = S.pending_orig_prompt

  -- Extract fenced code blocks.
  -- A response may contain both a JSFX block and a Lua block (e.g. "create this
  -- effect and add it to track 5"). Extract them separately so JSFX can be
  -- auto-saved and the Lua companion script can be auto-run.
  local explanation = text

  -- 1. Extract JSFX blocks (```jsfx or ```eel fences).
  -- Some small/fast models occasionally glue the closing fence directly to
  -- the last code token. Accept that as a fence typo, but still require an
  -- explicit runnable language label so prose fences cannot execute.
  local function collect_labelled_fences(label, split_label)
    local parts = {}
    for block in text:gmatch("```" .. label .. "[ \t\r]*\n(.-)%s*```") do
      parts[#parts+1] = block
    end
    if split_label and #parts == 0 then
      for block in text:gmatch("```[ \t\r]*\n" .. label .. "[ \t\r]*\n(.-)%s*```") do
        parts[#parts+1] = block
      end
    end
    return parts
  end
  local jsfx_parts = {}
  jsfx_parts = collect_labelled_fences("jsfx", true)
  if #jsfx_parts == 0 then
    jsfx_parts = collect_labelled_fences("eel", true)
  end
  local jsfx_code = #jsfx_parts > 0 and tbl_concat(jsfx_parts, "\n\n") or nil

  -- 2. Extract Lua blocks (```lua or ```reascript fences).
  local lua_parts = {}
  lua_parts = collect_labelled_fences("lua", true)
  if #lua_parts == 0 then
    lua_parts = collect_labelled_fences("reascript", true)
  end
  local lua_code = #lua_parts > 0 and tbl_concat(lua_parts, "\n\n") or nil
  local lua_artifact_info = nil
  local jsfx_wrong_artifact_gate_hit = false

  if S.pending_jsfx_intent and lua_code and not jsfx_code then
    if not S.jsfx_wrong_artifact_retry_used then
      S.jsfx_wrong_artifact_retry_used = true
      Log.line("JSFX-WRONG-ARTIFACT-RETRY",
        "JSFX request returned Lua/ReaScript; retrying for JSFX fence")
      local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
        .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: The user asked you "
        .. "to create/write/return JSFX, but your previous reply returned "
        .. "Lua/ReaScript instead. Regenerate from scratch as exactly ONE "
        .. "```jsfx code block. Do NOT return Lua, do NOT call reaper.*, "
        .. "and do NOT include a Lua companion unless the user explicitly "
        .. "asked to load the generated JSFX onto a track. The first line "
        .. "inside the fence must be desc:. Use JSFX/EEL2 sections such as "
        .. "@init, @slider, and @sample as needed. Respond as if this is "
        .. "your FIRST reply -- do NOT apologize, do NOT mention a retry.)\n\n"
        .. "USER REQUEST:\n" .. (S.pending_orig_prompt or "")
      Net.fire_validator_retry({
        kind = "jsfx",
        history_content = history_content,
        ctx_label = "jsfx_artifact_retry",
        retry_failed_key = "retry.reason.after_jsfx_wrong_artifact",
        retry_failed_label = "after JSFX request returned Lua",
        failure_message = "Auto-retry after JSFX request returned Lua did not go through. Please resend the last message.",
      })
      return
    end
    jsfx_wrong_artifact_gate_hit = true
    lua_code = nil
    Log.line("JSFX-WRONG-ARTIFACT-VALIDATOR",
      "JSFX request still returned Lua/ReaScript after retry; auto-run blocked")
    Log.add_error("The model returned Lua/ReaScript for a JSFX request even after a retry. Auto-run is blocked; ask again or switch to a stronger model for this JSFX.")
  end

  if S.pending_jsfx_intent
      and jsfx_code and not lua_code
      and Code.prompt_requests_jsfx_track_companion
      and Code.prompt_requests_jsfx_track_companion(S.pending_orig_prompt) then
    if (S.jsfx_companion_validator_retries or 0) < 2 then
      S.jsfx_companion_retry_used = true
      S.jsfx_companion_validator_retries =
        (S.jsfx_companion_validator_retries or 0) + 1
      Log.line("JSFX-COMPANION-RETRY",
        "JSFX track-install request returned no Lua companion; retrying")
      local jsfx_ref = "ReaAssist/<saved JSFX filename>.jsfx"
      if Code.derive_filename_jsfx then
        local derived = Code.derive_filename_jsfx(jsfx_code)
        if derived and derived ~= "" then
          jsfx_ref = "ReaAssist/" .. derived
        end
      end
      local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
        .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: The user asked "
        .. "for a JSFX and also asked for it to be put on a track. Your "
        .. "previous reply included the JSFX but omitted the Lua companion "
        .. "that creates/selects the requested track, adds the saved JSFX "
        .. "with `reaper.TrackFX_AddByName(track, \"" .. jsfx_ref
        .. "\", false, -1)`, and performs any requested REAPER actions "
        .. "such as markers. Store the TrackFX_AddByName return value and "
        .. "check it immediately with `if fx < 0 then "
        .. "reaper.ShowMessageBox(...); return end`; never leave the "
        .. "AddByName result unassigned or unchecked. Regenerate the full "
        .. "answer with exactly one "
        .. "```jsfx block followed by exactly one complete ```lua block. "
        .. "Keep the same JSFX design unless a syntax/safety fix is needed. "
        .. "Respond as if this is your FIRST reply -- do NOT apologize, "
        .. "do NOT mention a retry.)\n\nPrevious JSFX:\n```jsfx\n"
        .. jsfx_code
        .. "\n```\n\nUSER REQUEST:\n" .. (S.pending_orig_prompt or "")
      Net.fire_validator_retry({
        kind = "jsfx",
        history_content = history_content,
        ctx_label = "jsfx_companion_retry",
        retry_failed_key = "retry.reason.after_missing_jsfx_companion",
        retry_failed_label = "after missing JSFX companion Lua",
        failure_message = "Auto-retry after missing JSFX companion Lua did not go through. Please resend the last message.",
      })
      return
    end
    Log.line("JSFX-COMPANION-VALIDATOR",
      "JSFX track-install request still omitted companion Lua after retry")
  end

  -- Recover once when a model returns apparent Lua but omits or breaks the
  -- ```lua fence. Never execute unfenced text directly: bare-Lua recovery is
  -- gated by a sandboxed syntax check, then the model must re-emit the same
  -- script through the normal fenced extraction path.
  if not lua_code and not jsfx_code and not S.pending_jsfx_intent then
    local function retry_lua_fence_retry(kind, previous_lua, ctx_label,
                                         log_tag, log_message, user_note,
                                         fail_message)
      local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
        .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: "
        .. user_note
        .. " Re-send the EXACT SAME script inside ONE complete "
        .. "```lua ... ``` block. Do NOT change logic, names, positions, "
        .. "plugins, parameters, values, or comments. Do NOT emit "
        .. "<context_needed> -- all reference data is already pinned. "
        .. "Respond as if this is your FIRST reply -- do NOT apologize, "
        .. "do NOT mention a retry.)\n\nPrevious " .. kind
        .. " Lua:\n```text\n"
        .. previous_lua
        .. "\n```\n\nUSER REQUEST:\n" .. (S.pending_orig_prompt or "")
      Net.fire_validator_retry({
        kind = "parse",
        log_tag = log_tag,
        log_message = log_message,
        history_content = history_content,
        ctx_label = ctx_label,
        failure_message = fail_message,
      })
      return true
    end

    local fence_retry_used = S.bare_lua_retry_used
      or S.unclosed_fence_retry_used
    local unclosed_lua = text:match("```lua[ \t\r]*\n(.+)$")
      or text:match("```reascript[ \t\r]*\n(.+)$")
      or text:match("```[ \t\r]*\nlua[ \t\r]*\n(.+)$")
      or text:match("```[ \t\r]*\nreascript[ \t\r]*\n(.+)$")
    if unclosed_lua and not fence_retry_used then
      S.unclosed_fence_retry_used = true
      if retry_lua_fence_retry("incomplete fenced", unclosed_lua,
          "unclosed_fence_retry", "UNCLOSED-FENCE-RETRY",
          "lua fence was opened but not closed; asking model to resend exactly",
          "Your previous reply opened a Lua code fence but did not close it, "
            .. "so ReaAssist could not safely extract the script.",
          (RA and RA.retry_failed and RA.retry_failed(
            "retry.reason.after_unclosed_lua_fence",
            "after unclosed Lua fence"))
            or "Auto-retry after unclosed Lua fence did not go through. Please resend the last message.") then
        return
      end
    end

    local bare_lua = Code.bare_lua_retry_candidate(text)
    if bare_lua and not fence_retry_used then
      S.bare_lua_retry_used = true
      if retry_lua_fence_retry("unfenced", bare_lua,
          "bare_lua_retry", "BARE-LUA-RETRY",
          "valid-looking bare Lua without fence; asking model to wrap exactly",
          "Your previous reply appears to be valid Lua, but it was not "
            .. "inside a ```lua code fence, so ReaAssist cannot safely "
            .. "extract or run it.",
          (RA and RA.retry_failed and RA.retry_failed(
            "retry.reason.after_unfenced_lua_response",
            "after unfenced Lua response"))
            or "Auto-retry after unfenced Lua response did not go through. Please resend the last message.") then
        return
      end
    end

    local early_typed_actions_present = false
    if type(Code.inspect_typed_actions) == "function" then
      local early_typed_metrics = Code.inspect_typed_actions(text, {
        allow_raw_json = S.pending_typed_action_response_format == true,
        user_text = S.pending_orig_prompt or "",
      })
      early_typed_actions_present =
        early_typed_metrics and early_typed_metrics.present == true
    end
    local no_code_action_prompt = not lua_code
        and not jsfx_code
        and not early_typed_actions_present
        and not S.pending_typed_action_expected
        and not S.no_code_action_retry_used
        and (not Code.prompt_is_question_or_readonly
          or not Code.prompt_is_question_or_readonly(S.pending_orig_prompt))
        and Code.prompt_likely_needs_lua_action(S.pending_orig_prompt)
    local no_code_provider = PROVIDERS[S.pending_provider_idx]
      or PROVIDERS.active() or {}
    local no_code_model = MODELS[S.pending_model_idx or prefs.model_idx]
      or MODELS[prefs.model_idx] or MODELS[1] or {}
    local force_no_code_action_retry =
      (Code.prompt_requests_sidechain_ducking
        and Code.prompt_requests_sidechain_ducking(S.pending_orig_prompt)
        and Code.model_validator_enabled(no_code_provider.id,
          no_code_model.id, "sidechain_ducking_requires_send"))
      or (Code.prompt_requests_podcast_bus_all_sources
        and Code.prompt_requests_podcast_bus_all_sources(S.pending_orig_prompt)
        and Code.model_validator_enabled(no_code_provider.id,
          no_code_model.id, "podcast_bus_routes_all_sources"))
    local action_requires_lua_retry =
      Code.model_validator_enabled(no_code_provider.id,
        no_code_model.id, "action_requires_lua")
    local no_code_reply_is_clarification =
      Code.no_code_reply_is_clarification(text)
    if no_code_action_prompt
        and no_code_reply_is_clarification
        and not force_no_code_action_retry
        and not action_requires_lua_retry then
      Log.line("NO-CODE-ACTION-RETRY",
        "action prompt returned clarification; not retrying")
    elseif no_code_action_prompt then
      S.no_code_action_retry_used = true
      local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
        .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: The user asked "
        .. "for a REAPER action that changes project state, but your "
        .. "previous reply only described what should happen and did not "
        .. "include runnable code. Regenerate the full response as a "
        .. "fenced ```lua script that performs the requested action. "
        .. "Do not answer with a prose-only summary. Respond as if this "
        .. "is your FIRST reply -- do NOT apologize, do NOT mention a "
        .. "retry.)\n\nPrevious reply:\n"
        .. text
        .. "\n\nUSER REQUEST:\n" .. (S.pending_orig_prompt or "")
      Net.fire_validator_retry({
        kind = "empty",
        log_tag = "NO-CODE-ACTION-RETRY",
        log_message = "action prompt returned prose only; retrying with Lua requirement",
        history_content = history_content,
        ctx_label = "no_code_action_retry",
        retry_failed_key = "retry.reason.after_prose_only_action_response",
        retry_failed_label = "after prose-only action response",
        failure_message = "Auto-retry after prose-only action response did not go through. Please resend the last message.",
      })
      return
    end
  end

  local validator_gate_hit = false

  -- Per-model validator: DeepSeek can confuse regions with point markers.
  -- If the user explicitly asks for a region, require the REAPER region
  -- boolean to be true and retry once before auto-run.
  if lua_code
      and not S.region_marker_retry_used
      and Code.prompt_requests_region_creation(S.pending_orig_prompt) then
    local region_provider = PROVIDERS[S.pending_provider_idx]
      or PROVIDERS.active() or {}
    local region_model = MODELS[S.pending_model_idx or prefs.model_idx]
      or MODELS[prefs.model_idx] or MODELS[1] or {}
    if Code.model_validator_enabled(region_provider.id, region_model.id,
        "region_requires_region_flag")
        and not Code.lua_creates_requested_region(lua_code) then
      S.region_marker_retry_used = true
      S.region_marker_validator_retries =
        (S.region_marker_validator_retries or 0) + 1
      local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
        .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: The user asked for "
        .. "a region, but your previous Lua created a point marker or used "
        .. "the region boolean as false. Regenerate the full script. Use "
        .. "`reaper.AddProjectMarker(0, true, start_time, end_time, name, -1)` "
        .. "or the equivalent region API with the second boolean set to "
        .. "`true`. Preserve the requested region name, start time, and "
        .. "end time. Respond as if this is your FIRST reply -- do NOT "
        .. "apologize, do NOT mention a retry.)\n\nPrevious Lua to fix:\n"
        .. "```lua\n" .. lua_code .. "\n```\n\nUSER REQUEST:\n"
        .. (S.pending_orig_prompt or "")
      Net.fire_validator_retry({
        kind = "region_marker",
        log_tag = "REGION-MARKER-RETRY",
        log_message = "region prompt produced marker-mode API call; retrying with hint",
        history_content = history_content,
        ctx_label = "region_marker_retry",
        retry_failed_key = "retry.reason.after_marker_vs_region_response",
        retry_failed_label = "after marker-vs-region response",
        failure_message = "Auto-retry after marker-vs-region response did not go through. Please resend the last message.",
      })
      return
    end
  end

  -- The inverse marker/region failure is common on tiny models: the user asks
  -- for a point marker, but the script passes `true` as the isrgn flag and
  -- creates a zero-length region instead. Retry once before auto-run.
  if lua_code
      and not S.region_marker_retry_used
      and type(Code.prompt_requests_point_marker_creation) == "function"
      and Code.prompt_requests_point_marker_creation(S.pending_orig_prompt)
      and type(Code.lua_creates_region_for_point_marker) == "function"
      and Code.lua_creates_region_for_point_marker(lua_code) then
    S.region_marker_retry_used = true
    S.region_marker_validator_retries =
      (S.region_marker_validator_retries or 0) + 1
    local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
      .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: The user asked for "
      .. "a point marker, but your previous Lua set the marker/region "
      .. "boolean to true and created a region. Regenerate the full script. "
      .. "For a point marker, use `reaper.AddProjectMarker(0, false, "
      .. "time, 0, name, -1)` or `reaper.AddProjectMarker2(0, false, "
      .. "time, 0, name, -1, 0)`. Preserve the requested marker name and "
      .. "exact time. Respond as if this is your FIRST reply -- do NOT "
      .. "apologize, do NOT mention a retry.)\n\nPrevious Lua to fix:\n"
      .. "```lua\n" .. lua_code .. "\n```\n\nUSER REQUEST:\n"
      .. (S.pending_orig_prompt or "")
    Net.fire_validator_retry({
      kind = "region_marker",
      log_tag = "POINT-MARKER-RETRY",
      log_message = "point-marker prompt used region-mode API call; retrying with hint",
      history_content = history_content,
      ctx_label = "point_marker_retry",
      retry_failed_key = "retry.reason.after_point_marker_as_region",
      retry_failed_label = "after point marker was created as a region",
      failure_message = "Auto-retry after point marker was created as a region did not go through. Please resend the last message.",
    })
    return
  end

  -- MARKER/REGION PAIR VALIDATOR: A point marker and a region are different
  -- timeline objects. If the user asks for "marker Verse at 8" and also a
  -- "Verse region from 8 to 24", creating only the region loses the marker.
  local marker_pair_gate_hit = false
  if lua_code and not S.marker_pair_retry_used then
    local marker_pair_bad =
      Code.find_missing_point_markers_for_region_marker_pairs(
        lua_code, S.pending_orig_prompt)
    if marker_pair_bad and #marker_pair_bad > 0 then
      if (S.marker_pair_validator_retries or 0) < 1 then
        S.marker_pair_retry_used = true
        S.marker_pair_validator_retries =
          (S.marker_pair_validator_retries or 0) + 1
        local names = {}
        for _, e in ipairs(marker_pair_bad) do
          names[#names + 1] = tostring(e.name)
        end
        local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
          .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: The user asked for "
          .. "both point marker(s) and region(s), but your previous Lua only "
          .. "created region object(s) for these requested marker name(s): "
          .. tbl_concat(names, ", ") .. ". A region does not count as a "
          .. "marker. Regenerate the full script and create BOTH objects: "
          .. "a point marker with `reaper.AddProjectMarker(0, false, "
          .. "marker_time, 0, name, -1)` or equivalent, AND the requested "
          .. "region with the region boolean true. Preserve all requested "
          .. "marker names/times, region names/bounds, project tempo, and "
          .. "the no-track constraint. Respond as if this is your FIRST "
          .. "reply -- do NOT apologize, do NOT mention a retry.)\n\n"
          .. "Previous Lua to fix:\n```lua\n" .. lua_code
          .. "\n```\n\nUSER REQUEST:\n" .. (S.pending_orig_prompt or "")
        Net.fire_validator_retry({
          kind = "marker_pair",
          log_tag = "MARKER-PAIR-VALIDATOR",
          log_message = "requested marker name(s) only created as region(s): "
            .. tbl_concat(names, ", ") .. "; retrying with hint",
          history_content = history_content,
          ctx_label = "marker_pair_retry",
          retry_failed_key = "retry.reason.after_missing_point_marker",
          retry_failed_label = "after missing point marker",
          failure_message = "Auto-retry after missing point marker did not go through. Please resend the last message.",
        })
        return
      end
      marker_pair_gate_hit = true
      validator_gate_hit = true
      Log.line("MARKER-PAIR-VALIDATOR",
        "requested marker+region pair still missing point marker after retry")
      local names = {}
      for _, e in ipairs(marker_pair_bad) do names[#names + 1] = tostring(e.name) end
      Log.add_error((RA and RA.t and RA.t(
        "validator.missing_point_marker_blocked",
        { names = tbl_concat(names, ", ") },
        "The model created a region but omitted the separately requested "
          .. "point marker(s), even after a retry: "
          .. tbl_concat(names, ", ")
          .. ". Auto-run is blocked; add the missing point marker(s) before "
          .. "running manually."))
        or ("The model created a region but omitted the separately requested point marker(s), even after a retry: "
          .. tbl_concat(names, ", ")
          .. ". Auto-run is blocked; add the missing point marker(s) before running manually."))
    end
  end

  -- High-confidence void-return API assignment validator. Some REAPER API
  -- calls mutate project state but do not return the object just created; if a
  -- model assigns that nil return and then uses it as a track/item handle, the
  -- script can silently do nothing. Retry once with the documented pattern.
  if lua_code and not S.void_return_retry_used then
    local stripped = lua_code
      :gsub("%-%-%[%[.-%]%]", "")
      :gsub("%-%-[^\n]*", "")
    local void_funcs = {
      InsertTrackAtIndex = "InsertTrackAtIndex returns no track. Call it as a statement, then call reaper.GetTrack(0, index).",
    }
    local bad_name, bad_note
    for name, note in pairs(void_funcs) do
      local call_pat = "reaper%." .. name .. "%s*%("
      local assign_target = "[%a_][%w_%.%[%]%\"']*"
      local local_assign = "local%s+" .. assign_target .. "%s*=%s*" .. call_pat
      local plain_assign = "[\n;]%s*" .. assign_target .. "%s*=%s*" .. call_pat
      if stripped:find(local_assign) or stripped:find(plain_assign) then
        bad_name, bad_note = name, note
        break
      end
    end
    if bad_name then
      S.void_return_retry_used = true
      S.void_return_validator_retries =
        (S.void_return_validator_retries or 0) + 1
      Log.line("VOID-RETURN-RETRY",
        "void-return API assignment to reaper." .. bad_name
        .. "; retrying with hint")
      local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
        .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: Your previous "
        .. "reply assigned the return value of reaper." .. bad_name .. "(), "
        .. "but that function does not return the object you need. "
        .. bad_note .. " Preserve the user's requested tracks, names, "
        .. "plugins, parameter values, MIDI notes, markers, routing, and "
        .. "ordering. Only fix the void-return API usage unless another "
        .. "change is required to make the script valid. Respond as if "
        .. "this is your FIRST reply -- do NOT apologize, do NOT mention "
        .. "a retry.)\n\nPrevious Lua to fix:\n```lua\n"
        .. lua_code
        .. "\n```\n\nUSER REQUEST:\n" .. (S.pending_orig_prompt or "")
      Net.fire_validator_retry({
        kind = "api",
        history_content = history_content,
        ctx_label = "void_return_retry",
        retry_failed_key = "retry.reason.after_void_return_api_assignment",
        retry_failed_label = "after void-return API assignment",
        failure_message = "Auto-retry after void-return API assignment did not go through. Please resend the last message.",
      })
      return
    end
  end

  if lua_code and type(Code.find_forbidden_track_creation) == "function" then
    local forbidden_track_creation =
      Code.find_forbidden_track_creation(lua_code, S.pending_orig_prompt)
    if forbidden_track_creation and #forbidden_track_creation > 0
        and not S.forbidden_track_creation_retry_used then
      S.forbidden_track_creation_retry_used = true
      S.forbidden_track_creation_validator_retries =
        (S.forbidden_track_creation_validator_retries or 0) + 1
      Log.line("FORBIDDEN-TRACK-CREATION-RETRY",
        "script inserted tracks after prompt forbade new bus/track; retrying")
      local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
        .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: The user explicitly "
        .. "said not to create a new bus, track, or return, but your "
        .. "previous script inserted a new track. Regenerate the FULL "
        .. "script without reaper.InsertTrackAtIndex or track-creation "
        .. "actions. Operate only on existing named tracks from the session "
        .. "snapshot; if a required existing track is missing, show a clear "
        .. "message and stop instead of creating it. Preserve the requested "
        .. "master-send, marker, routing, pan, level, MIDI, plugin, and "
        .. "selection changes. Respond as if this is your FIRST reply -- "
        .. "do NOT apologize, do NOT mention a retry.)\n\nPrevious Lua to "
        .. "fix:\n```lua\n"
        .. lua_code
        .. "\n```\n\nUSER REQUEST:\n" .. (S.pending_orig_prompt or "")
      Net.fire_validator_retry({
        kind = "api",
        history_content = history_content,
        ctx_label = "forbidden_track_creation_retry",
        retry_failed_key = "retry.reason.after_forbidden_track_creation",
        retry_failed_label = "after forbidden track creation",
        failure_message = "Auto-retry after forbidden track creation did not go through. Please resend the last message.",
      })
      return
    elseif forbidden_track_creation and #forbidden_track_creation > 0 then
      validator_gate_hit = true
      Log.line("FORBIDDEN-TRACK-CREATION-VALIDATOR",
        "track insertion persisted after explicit no-new-track prompt; auto-run blocked")
      Log.add_error("The script creates a new track even though the user explicitly asked not to create a new bus, track, or return. Auto-run is blocked; remove the track creation and operate on existing tracks only.")
    end
  end

  local action_relevance_gate_hit = false
  if lua_code
      and type(Code.find_action_request_relevance_violations) == "function" then
    local relevance = Code.find_action_request_relevance_violations(
      lua_code, S.pending_orig_prompt, S.pending_snapshot)
    if relevance and #relevance > 0 then
      local details, has_retryable = {}, false
      for _, finding in ipairs(relevance) do
        details[#details + 1] = "  - line " .. tostring(finding.line or "?")
          .. ": " .. tostring(finding.kind or "relevance")
          .. " (" .. tostring(finding.detail or "review required") .. ")"
        if not finding.review_only then has_retryable = true end
      end
      local detail_text = tbl_concat(details, "\n")
      if has_retryable and not S.action_relevance_retry_used then
        S.action_relevance_retry_used = true
        S.action_relevance_validator_retries =
          (S.action_relevance_validator_retries or 0) + 1
        Log.line("ACTION-RELEVANCE-RETRY",
          "generated action did not match request/session; retrying\n"
            .. detail_text)
        local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
          .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: Your previous "
          .. "script did not stay within the user's requested action. "
          .. "Regenerate the FULL script and perform only the requested "
          .. "task. Do not introduce plugins the request did not ask for, "
          .. "do not target literal track names absent from both the request "
          .. "and SESSION CONTEXT, and do not run Save, Record, Undo, Redo, "
          .. "transport, deletion, or global-toggle actions unless the user "
          .. "explicitly requested that exact effect. Item removal action "
          .. "40006 deletes selected media items; it is not track deletion. "
          .. "Preserve every requested rename, color, pan, routing, MIDI, "
          .. "JSFX, marker, region, timing, plugin, and parameter detail. "
          .. "Respond as if this is your FIRST reply -- do NOT apologize "
          .. "and do NOT mention a retry.\n\nDetected mismatch(es):\n"
          .. detail_text .. "\n\nPrevious Lua to fix:\n"
          .. lua_code .. "\n\nUSER REQUEST:\n"
          .. (S.pending_orig_prompt or "")
        Net.fire_validator_retry({
          kind = "action_relevance",
          history_content = history_content,
          ctx_label = "action_relevance_retry",
          retry_failed_key = "retry.reason.after_action_relevance",
          retry_failed_label = "after action relevance mismatch",
          failure_message = "Auto-retry after an action relevance mismatch did not go through. Please resend the last message.",
        })
        return
      end

      action_relevance_gate_hit = true
      Log.line("ACTION-RELEVANCE-VALIDATOR",
        "auto-run requires review\n" .. detail_text)
      Log.add_error((RA and RA.t and RA.t(
        "auto_run.blocked.relevance", nil,
        "Auto-run was blocked because the generated action did not clearly "
          .. "match the request and captured session. Review the target "
          .. "tracks, plugins, and REAPER actions before running it manually."))
        or "Auto-run was blocked because the generated action did not clearly "
          .. "match the request and captured session. Review it before "
          .. "running manually.")
    end
  end

  if lua_code and type(Code.find_inert_track_duplication) == "function" then
    local inert_track_duplication =
      Code.find_inert_track_duplication(lua_code, S.pending_orig_prompt)
    if inert_track_duplication and #inert_track_duplication > 0
        and not S.track_duplication_retry_used then
      S.track_duplication_retry_used = true
      S.track_duplication_validator_retries =
        (S.track_duplication_validator_retries or 0) + 1
      Log.line("TRACK-DUPLICATION-RETRY",
        "track duplicate prompt created a blank/non-duplicate track; retrying")
      local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
        .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: The user asked you "
        .. "to duplicate, copy, or clone a track, but your previous script "
        .. "created a blank track or otherwise did not use a true track "
        .. "duplication path. Regenerate the FULL script so the duplicate "
        .. "preserves the source track's FX, sends/routing, envelopes, "
        .. "settings, and folder state where practical. Use REAPER's native "
        .. "`Track: Duplicate tracks` action (`reaper.Main_OnCommand(40062, 0)`) "
        .. "with careful track selection restoration, or use a full "
        .. "`GetTrackStateChunk`/`SetTrackStateChunk` clone. Do not replace "
        .. "track duplication with `reaper.InsertTrackAtIndex` plus manual "
        .. "name/color/folder-depth writes. Preserve the requested item moves, "
        .. "deletions, renaming, folder placement, validation, and selection "
        .. "changes. Respond as if this is your FIRST reply -- do NOT "
        .. "apologize, do NOT mention a retry.)\n\nPrevious Lua to fix:\n```lua\n"
        .. lua_code
        .. "\n```\n\nUSER REQUEST:\n" .. (S.pending_orig_prompt or "")
      Net.fire_validator_retry({
        kind = "api",
        history_content = history_content,
        ctx_label = "track_duplication_retry",
        retry_failed_key = "retry.reason.after_inert_track_duplication",
        retry_failed_label = "after inert track duplication",
        failure_message = "Auto-retry after inert track duplication did not go through. Please resend the last message.",
      })
      return
    elseif inert_track_duplication and #inert_track_duplication > 0 then
      validator_gate_hit = true
      Log.line("TRACK-DUPLICATION-VALIDATOR",
        "track duplicate prompt still lacks a true duplication path; auto-run blocked")
      Log.add_error("The script does not truly duplicate the requested track. Auto-run is blocked; use Track: Duplicate tracks or a full track-state clone so FX, sends/routing, envelopes, settings, and folder state are preserved.")
    end
  end

  if lua_code and type(Code.find_forbidden_fx_addition) == "function" then
    local forbidden_fx =
      Code.find_forbidden_fx_addition(lua_code, S.pending_orig_prompt)
    if forbidden_fx and #forbidden_fx > 0
        and not S.forbidden_fx_retry_used then
      S.forbidden_fx_retry_used = true
      S.forbidden_fx_validator_retries =
        (S.forbidden_fx_validator_retries or 0) + 1
      Log.line("FORBIDDEN-FX-RETRY",
        "script added FX after prompt forbade effects/plugins; retrying")
      local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
        .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: The user explicitly "
        .. "said not to add effects, FX, or plugins, but your previous "
        .. "script added an FX/plugin. Regenerate the FULL script without "
        .. "TrackFX_AddByName, TakeFX_AddByName, FX parameter writes, or "
        .. "plugin helper text. Only perform the requested track property, "
        .. "routing, marker, item, MIDI, or selection changes. Preserve the "
        .. "user's exact no-new-tracks/no-sends/no-markers/no-effects "
        .. "constraints. Respond as if this is your FIRST reply -- do NOT "
        .. "apologize, do NOT mention a retry.)\n\nPrevious Lua to fix:\n```lua\n"
        .. lua_code
        .. "\n```\n\nUSER REQUEST:\n" .. (S.pending_orig_prompt or "")
      Net.fire_validator_retry({
        kind = "api",
        history_content = history_content,
        ctx_label = "forbidden_fx_retry",
        retry_failed_key = "retry.reason.after_forbidden_fx_addition",
        retry_failed_label = "after forbidden FX addition",
        failure_message = "Auto-retry after forbidden FX addition did not go through. Please resend the last message.",
      })
      return
    elseif forbidden_fx and #forbidden_fx > 0 then
      validator_gate_hit = true
      Log.line("FORBIDDEN-FX-VALIDATOR",
        "FX addition persisted after explicit no-effects prompt; auto-run blocked")
      Log.add_error("The script adds an FX/plugin even though the user explicitly asked for no effects, FX, or plugins. Auto-run is blocked; remove the FX addition and keep only the requested non-plugin changes.")
    end
  end

  if lua_code and type(Code.find_unrequested_instrument_fx_addition) == "function" then
    local unrequested_instrument_fx =
      Code.find_unrequested_instrument_fx_addition(lua_code, S.pending_orig_prompt)
    if unrequested_instrument_fx and #unrequested_instrument_fx > 0
        and not S.forbidden_fx_retry_used then
      S.forbidden_fx_retry_used = true
      S.forbidden_fx_validator_retries =
        (S.forbidden_fx_validator_retries or 0) + 1
      Log.line("UNREQUESTED-INSTRUMENT-FX-RETRY",
        "script added an instrument plugin for an instrument-named track; retrying")
      local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
        .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: The user named "
        .. "instrument/source tracks, but did not ask you to load a virtual "
        .. "instrument, synth plugin, sampler, VSTi, or sound source. Your "
        .. "previous script added an instrument plugin anyway. Regenerate "
        .. "the FULL script without adding ReaSynth, Twin, Serum, Kontakt, "
        .. "or any VSTi/VST3i instrument. Keep only the explicitly requested "
        .. "track creation, ReaEQ/ReaComp/other named FX, pan, level, routing, "
        .. "marker, item, MIDI, and selection changes. Respond as if this is "
        .. "your FIRST reply -- do NOT apologize, do NOT mention a retry.)\n\n"
        .. "Previous Lua to fix:\n```lua\n"
        .. lua_code
        .. "\n```\n\nUSER REQUEST:\n" .. (S.pending_orig_prompt or "")
      Net.fire_validator_retry({
        kind = "api",
        history_content = history_content,
        ctx_label = "unrequested_instrument_fx_retry",
        retry_failed_key = "retry.reason.after_unrequested_instrument_fx",
        retry_failed_label = "after unrequested instrument plugin",
        failure_message = "Auto-retry after unrequested instrument plugin did not go through. Please resend the last message.",
      })
      return
    elseif unrequested_instrument_fx and #unrequested_instrument_fx > 0 then
      validator_gate_hit = true
      Log.line("UNREQUESTED-INSTRUMENT-FX-VALIDATOR",
        "unrequested instrument plugin persisted after retry; auto-run blocked")
      Log.add_error("The script adds an instrument plugin even though the user only named instrument/source tracks and did not ask to load a synth, VSTi, sampler, or sound source. Auto-run is blocked; remove the unrequested instrument plugin.")
    end
  end

  -- High-confidence create-track intent validator. Some weaker models answer a
  -- "create tracks" prompt by fetching GetTrack(0, 0/1) and renaming those
  -- handles, which passes syntax but does nothing in an empty project.
  if lua_code
      and not S.track_creation_retry_used
      and Code.prompt_requests_track_creation(S.pending_orig_prompt)
      and not Code.lua_creates_tracks(lua_code) then
    S.track_creation_retry_used = true
    S.track_creation_validator_retries =
      (S.track_creation_validator_retries or 0) + 1
    Log.line("TRACK-CREATION-RETRY",
      "track-creation prompt without InsertTrackAtIndex; retrying with hint")
    local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
      .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: The user asked you "
      .. "to create one or more tracks, but your previous script only "
      .. "looked up existing tracks with reaper.GetTrack(...) and renamed "
      .. "them. That is inert when the project has no matching existing "
      .. "tracks. For each requested new track, call "
      .. "reaper.InsertTrackAtIndex(index, true) as a statement, then get "
      .. "the created track with reaper.GetTrack(0, index) and set its "
      .. "name. Preserve the requested order, exact track names, plugins, "
      .. "sends, markers, MIDI notes, and selections. Respond as if this "
      .. "is your FIRST reply -- do NOT apologize, do NOT mention a "
      .. "retry.)\n\nPrevious Lua to fix:\n```lua\n"
      .. lua_code
      .. "\n```\n\nUSER REQUEST:\n" .. (S.pending_orig_prompt or "")
    Net.fire_validator_retry({
      kind = "api",
      history_content = history_content,
      ctx_label = "track_creation_retry",
      retry_failed_key = "retry.reason.after_inert_track_creation_script",
      retry_failed_label = "after inert track-creation script",
      failure_message = "Auto-retry after inert track-creation script did not go through. Please resend the last message.",
    })
    return
  end

  -- Per-model validator: Nano can create a MIDI/instrument idea correctly but
  -- leave the new destination track unnamed. For everyday project hygiene,
  -- generated instrument/part tracks should get an obvious name.
  if lua_code
      and not S.track_name_retry_used
      and Code.prompt_requests_inferred_created_track_name(
        S.pending_orig_prompt)
      and Code.lua_creates_tracks(lua_code) then
    local name_provider = PROVIDERS[S.pending_provider_idx]
      or PROVIDERS.active() or {}
    local name_model = MODELS[S.pending_model_idx or prefs.model_idx]
      or MODELS[prefs.model_idx] or MODELS[1] or {}
    if Code.model_validator_enabled(name_provider.id, name_model.id,
        "created_track_inferred_name")
        and not Code.lua_names_created_track(lua_code) then
      S.track_name_retry_used = true
      S.track_creation_validator_retries =
        (S.track_creation_validator_retries or 0) + 1
      Log.line("TRACK-NAME-RETRY",
        "created instrument/MIDI track without P_NAME; retrying with hint")
      local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
        .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: Your previous "
        .. "script created a new track for an instrument, part, or MIDI "
        .. "idea, but did not name the track. Regenerate the full script. "
        .. "After creating the destination track, call "
        .. "reaper.GetSetMediaTrackInfo_String(track, \"P_NAME\", name, true) "
        .. "with an obvious name from the user's request. For a drum MIDI "
        .. "idea, use a track name containing \"Drum\". Preserve the MIDI "
        .. "notes, item length, timing, pitches, velocities, FX, routing, "
        .. "and selections from the requested task. Respond as if this is "
        .. "your FIRST reply -- do NOT apologize, do NOT mention a retry.)"
        .. "\n\nPrevious Lua to fix:\n```lua\n"
        .. lua_code
        .. "\n```\n\nUSER REQUEST:\n" .. (S.pending_orig_prompt or "")
      Net.fire_validator_retry({
        kind = "api",
        history_content = history_content,
        ctx_label = "track_name_retry",
        retry_failed_key = "retry.reason.after_unnamed_created_track",
        retry_failed_label = "after unnamed created track",
        failure_message = "Auto-retry after unnamed created track did not go through. Please resend the last message.",
      })
      return
    end
  end

  if lua_code
      and Code.prompt_requests_track_creation(S.pending_orig_prompt) then
    local bad_created_track_indices =
      Code.find_track_creation_index_misuse(lua_code, S.pending_orig_prompt,
        S.pending_snapshot)
    if bad_created_track_indices and #bad_created_track_indices > 0
        and not S.track_creation_index_retry_used then
      S.track_creation_index_retry_used = true
      S.track_creation_validator_retries =
        (S.track_creation_validator_retries or 0) + 1
      local finding = bad_created_track_indices[1]
      Log.line("TRACK-CREATION-INDEX-RETRY",
        "new-track GetTrack index can be nil on line "
        .. tostring(finding.line or "?") .. "; retrying with creation-index hint")
      local details = {}
      for _, e in ipairs(bad_created_track_indices) do
        details[#details + 1] =
          "line " .. tostring(e.line or "?")
          .. " fetches GetTrack(0, " .. tostring(e.api_idx)
          .. ") before that API index exists; expected "
          .. tostring(e.expected_api_idx)
      end
      local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
        .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: The user asked you "
        .. "to create one or more tracks, but your previous script used a "
        .. "GetTrack index that can be nil immediately after insertion. For "
        .. "new tracks created at the start of a project, use consecutive "
        .. "0-based API indices: first new track InsertTrackAtIndex(0, true) "
        .. "then GetTrack(0, 0); second new track InsertTrackAtIndex(1, true) "
        .. "then GetTrack(0, 1), and so on. Affected line(s): "
        .. tbl_concat(details, "; ") .. ". Preserve the requested order, "
        .. "exact track names, plugins, sends, MIDI notes, markers, and "
        .. "settings. Respond as if this is your FIRST reply -- do NOT "
        .. "apologize, do NOT mention a retry.)\n\nPrevious Lua to fix:\n```lua\n"
        .. lua_code
        .. "\n```\n\nUSER REQUEST:\n" .. (S.pending_orig_prompt or "")
      Net.fire_validator_retry({
        kind = "api",
        history_content = history_content,
        ctx_label = "track_creation_index_retry",
        retry_failed_key = "retry.reason.after_new_track_index_mismatch",
        retry_failed_label = "after new-track index mismatch",
        failure_message = "Auto-retry after new-track index mismatch did not go through. Please resend the last message.",
      })
      return
    elseif bad_created_track_indices and #bad_created_track_indices > 0 then
      validator_gate_hit = true
      Log.line("TRACK-CREATION-INDEX-VALIDATOR",
        "new-track GetTrack index mismatch persisted after retry; auto-run blocked")
      Log.add_error((RA and RA.t and RA.t(
        "validator.track_creation_index_blocked", nil,
        "The script appears to fetch a newly-created track with "
          .. "a GetTrack index that does not exist yet. Auto-run is blocked; "
          .. "review and correct the InsertTrackAtIndex/GetTrack pairing "
          .. "before running manually."))
        or "The script appears to fetch a newly-created track with a GetTrack index that does not exist yet. Auto-run is blocked; review and correct the InsertTrackAtIndex/GetTrack pairing before running manually.")
    end
  end

  -- Literal GetTrack index validator. SESSION CONTEXT track rows are 1-based
  -- for readability, but reaper.GetTrack uses 0-based API indices. Small
  -- models sometimes copy "track 1/2" directly into GetTrack(0, 1/2), which
  -- either targets the wrong track or returns nil and blocks auto-run behind a
  -- message box.
  if lua_code then
    local bad_track_indices =
      Code.find_literal_gettrack_index_mismatches(lua_code, S.pending_snapshot)
    if bad_track_indices and #bad_track_indices > 0
        and not S.track_index_retry_used then
      S.track_index_retry_used = true
      S.track_index_validator_retries =
        (S.track_index_validator_retries or 0) + 1
      local finding = bad_track_indices[1]
      Log.line("TRACK-INDEX-RETRY",
        "literal GetTrack index mismatch on line "
        .. tostring(finding.line or "?") .. "; retrying with 0-based hint")
      local details = {}
      for _, e in ipairs(bad_track_indices) do
        details[#details + 1] =
          "line " .. tostring(e.line or "?")
          .. " uses GetTrack(0, " .. tostring(e.api_idx)
          .. "), expected API index " .. tostring(e.expected_api_idx)
          .. " (" .. tostring(e.reason or "mismatch") .. ")"
      end
      local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
        .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: Your previous "
        .. "reply used SESSION CONTEXT's 1-based track numbers directly "
        .. "inside reaper.GetTrack. REAPER's GetTrack API is 0-based: "
        .. "SESSION track 1 -> reaper.GetTrack(0, 0), SESSION track 2 -> "
        .. "reaper.GetTrack(0, 1), and so on. Fix only the track index "
        .. "resolution unless another change is required to make the "
        .. "script valid. Preserve the requested tracks, names, plugins, "
        .. "sends, MIDI notes, markers, routing, and ordering. Affected "
        .. "line(s): " .. tbl_concat(details, "; ") .. ". Respond as if "
        .. "this is your FIRST reply -- do NOT apologize, do NOT mention "
        .. "a retry.)\n\nPrevious Lua to fix:\n```lua\n"
        .. lua_code
        .. "\n```\n\nUSER REQUEST:\n" .. (S.pending_orig_prompt or "")
      Net.fire_validator_retry({
        kind = "api",
        history_content = history_content,
        ctx_label = "track_index_retry",
        retry_failed_key = "retry.reason.after_literal_track_index_mismatch",
        retry_failed_label = "after literal track-index mismatch",
        failure_message = "Auto-retry after literal track-index mismatch did not go through. Please resend the last message.",
      })
      return
    elseif bad_track_indices and #bad_track_indices > 0 then
      validator_gate_hit = true
      Log.line("TRACK-INDEX-VALIDATOR",
        "literal GetTrack index mismatch persisted after retry; auto-run blocked")
      local user_lines = {}
      for _, e in ipairs(bad_track_indices) do
        user_lines[#user_lines + 1] =
          "line " .. tostring(e.line or "?")
        Log.line("TRACK-INDEX-VALIDATOR",
          "persisted literal GetTrack mismatch line "
          .. tostring(e.line or "?")
          .. ": used API index " .. tostring(e.api_idx)
          .. ", expected " .. tostring(e.expected_api_idx)
          .. " (" .. tostring(e.reason or "mismatch") .. ")")
      end
      Log.add_error((RA and RA.t and RA.t(
        "validator.track_index_blocked",
        { lines = tbl_concat(user_lines, ", ") },
        "I blocked this script because its track targeting still "
          .. "does not match the current session after an automatic correction "
          .. "attempt. Affected line(s): " .. tbl_concat(user_lines, ", ")
          .. ". Ask ReaAssist to regenerate it before running."))
        or ("I blocked this script because its track targeting still does not match the current session after an automatic correction attempt. Affected line(s): "
          .. tbl_concat(user_lines, ", ")
          .. ". Ask ReaAssist to regenerate it before running."))
    end
  end

  -- Numeric target consistency validator. If the user explicitly targeted
  -- "on track N" / "to track N", a generated script should not add a hard
  -- abort that requires an unrelated snapshot-derived track name.
  if lua_code and not validator_gate_hit then
    local bad_target_guards =
      Code.find_numeric_track_target_name_guard_mismatches(lua_code,
        S.pending_orig_prompt)
    if bad_target_guards and #bad_target_guards > 0
        and not S.target_consistency_retry_used then
      S.target_consistency_retry_used = true
      S.target_consistency_validator_retries =
        (S.target_consistency_validator_retries or 0) + 1
      local finding = bad_target_guards[1]
      Log.line("TARGET-CONSISTENCY-RETRY",
        "numeric track target got hard name guard on line "
        .. tostring(finding.line or "?") .. "; retrying with target hint")
      local details = {}
      for _, e in ipairs(bad_target_guards) do
        details[#details + 1] =
          "line " .. tostring(e.line or "?")
          .. " requires Track " .. tostring(e.display_idx)
          .. " to be named `" .. tostring(e.guard_name or "") .. "`"
      end
      local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
        .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: The user targeted "
        .. "a numbered session track, but your previous Lua added a hard "
        .. "track-name check for a name the user did not ask for. Preserve "
        .. "the numbered target, the requested plugin, and all requested "
        .. "settings, but remove the abort based on the snapshot-derived "
        .. "track name. You may still show a friendly error if Track "
        .. tostring(finding.display_idx or "?")
        .. " does not exist. Affected line(s): "
        .. tbl_concat(details, "; ") .. ". Respond as if this is your "
        .. "FIRST reply -- do NOT apologize, do NOT mention a retry.)"
        .. "\n\nPrevious Lua to fix:\n```lua\n"
        .. lua_code
        .. "\n```\n\nUSER REQUEST:\n" .. (S.pending_orig_prompt or "")
      Net.fire_validator_retry({
        kind = "api",
        history_content = history_content,
        ctx_label = "target_consistency_retry",
        retry_failed_key = "retry.reason.after_numeric_target_name_guard_mismatch",
        retry_failed_label = "after numeric target/name-guard mismatch",
        failure_message = "Auto-retry after numeric target/name-guard mismatch did not go through. Please resend the last message.",
      })
      return
    elseif bad_target_guards and #bad_target_guards > 0 then
      validator_gate_hit = true
      Log.line("TARGET-CONSISTENCY-VALIDATOR",
        "numeric target/name-guard mismatch persisted after retry; auto-run blocked")
      local user_lines = {}
      for _, e in ipairs(bad_target_guards) do
        user_lines[#user_lines + 1] =
          "line " .. tostring(e.line or "?")
        Log.line("TARGET-CONSISTENCY-VALIDATOR",
          "persisted hard name guard line " .. tostring(e.line or "?")
          .. ": Track " .. tostring(e.display_idx or "?")
          .. " required name `" .. tostring(e.guard_name or "") .. "`")
      end
      Log.add_error((RA and RA.t and RA.t(
        "validator.target_name_guard_blocked",
        { lines = tbl_concat(user_lines, ", ") },
        "I blocked this script because the user targeted a "
          .. "numbered track, but the script still requires that track to "
          .. "have a specific name the user did not request. Affected line(s): "
          .. tbl_concat(user_lines, ", ")
          .. ". Ask ReaAssist to regenerate it before running."))
        or ("I blocked this script because the user targeted a numbered track, but the script still requires that track to have a specific name the user did not request. Affected line(s): "
          .. tbl_concat(user_lines, ", ")
          .. ". Ask ReaAssist to regenerate it before running."))
    end
  end

  if lua_code then
    local repaired_insert_lua, did_insert_repair, insert_order_finding =
      Code.repair_repeated_zero_track_insertion_order(
        lua_code, S.pending_orig_prompt)
    if did_insert_repair then
      lua_code = repaired_insert_lua
      lua_artifact_info = nil
      Log.line("TRACK-ORDER-REPAIR",
        "rewrote repeated InsertTrackAtIndex(0) loop near line "
        .. tostring(insert_order_finding and insert_order_finding.line or "?")
        .. " to append requested tracks in forward order")
    end

    local repaired_folder_lua, did_folder_repair, bad_folder_boundary =
      Code.repair_folder_child_boundary_misuse(lua_code, S.pending_orig_prompt)
    if did_folder_repair then
      lua_code = repaired_folder_lua
      lua_artifact_info = nil
      local finding = bad_folder_boundary and bad_folder_boundary[1] or {}
      Log.line("FOLDER-BOUNDARY-REPAIR",
        "moved folder close from "
        .. tostring(finding.name_display or finding.name or "outside track")
        .. " to " .. tostring(finding.expected_name_display
          or finding.expected_name or "last child"))
    end
    if did_folder_repair then bad_folder_boundary = nil end
    if bad_folder_boundary and #bad_folder_boundary > 0
        and not S.folder_boundary_retry_used then
      S.folder_boundary_retry_used = true
      local finding = bad_folder_boundary[1]
      local history_content
      if finding.reason == "missing_parent_folder_track" then
        Log.line("FOLDER-PARENT-RETRY",
          "explicit folder parent appears omitted near line "
          .. tostring(finding.line or "?") .. "; retrying with folder-parent hint")
        history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
          .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: The user asked for "
          .. "a separate folder parent track named `"
          .. tostring(finding.parent_display
            or finding.expected_name_display
            or finding.expected_name
            or "the requested folder")
          .. "`. Your previous script appears to create only the child "
          .. "tracks and open the folder on `"
          .. tostring(finding.name_display
            or finding.name
            or "the first child")
          .. "`. Create the folder parent track before the child tracks, "
          .. "name it exactly as requested, set that parent to "
          .. "I_FOLDERDEPTH 1, set the last requested child to "
          .. "I_FOLDERDEPTH -1, and leave outside tracks at 0 unless they "
          .. "start or close another folder. Preserve the requested order, "
          .. "exact track names, plugins, sends, MIDI notes, markers, and "
          .. "settings. Respond as if this is your FIRST reply -- do NOT "
          .. "apologize, do NOT mention a retry.)\n\n"
          .. "Previous Lua to fix:\n```lua\n"
          .. lua_code
          .. "\n```\n\nUSER REQUEST:\n" .. (S.pending_orig_prompt or "")
      elseif finding.reason == "last_child_not_closed" then
        Log.line("FOLDER-BOUNDARY-RETRY",
          "folder opened without final child close near line "
          .. tostring(finding.line or "?") .. "; retrying with folder-depth hint")
        history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
          .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: The user asked for "
          .. "specific child tracks inside a folder. REAPER's I_FOLDERDEPTH "
          .. "closes the folder on the last child track. Your previous script "
          .. "opened the folder but never set a negative I_FOLDERDEPTH on the "
          .. "last requested child `"
          .. tostring(finding.expected_name_display
            or finding.expected_name or "the last child")
          .. "`. Set that last child to I_FOLDERDEPTH -1 and leave outside "
          .. "tracks at 0 unless they start or close another folder. Preserve "
          .. "the requested order, exact track names, plugins, sends, MIDI "
          .. "notes, markers, and settings. Respond as if this is your FIRST "
          .. "reply -- do NOT apologize, do NOT mention a retry.)\n\n"
          .. "Previous Lua to fix:\n```lua\n"
          .. lua_code
          .. "\n```\n\nUSER REQUEST:\n" .. (S.pending_orig_prompt or "")
      else
        Log.line("FOLDER-BOUNDARY-RETRY",
          "folder close appears on outside track line "
          .. tostring(finding.line or "?") .. "; retrying with folder-depth hint")
        history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
          .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: The user asked for "
          .. "specific child tracks inside a folder. REAPER's I_FOLDERDEPTH "
          .. "closes the folder on the last child track, not on the following "
          .. "outside track. In this request, the last requested child is `"
          .. tostring(finding.expected_name_display
            or finding.expected_name or "the last child")
          .. "`, but your previous script put the negative folder depth on `"
          .. tostring(finding.name_display or finding.name or "another track")
          .. "`. Move the negative I_FOLDERDEPTH close to the last child and "
          .. "leave the outside track at 0 unless it starts/closes another "
          .. "folder. Preserve the requested order, exact track names, plugins, "
          .. "sends, MIDI notes, markers, and settings. Respond as if this is "
          .. "your FIRST reply -- do NOT apologize, do NOT mention a retry.)\n\n"
          .. "Previous Lua to fix:\n```lua\n"
          .. lua_code
          .. "\n```\n\nUSER REQUEST:\n" .. (S.pending_orig_prompt or "")
      end
      Net.fire_validator_retry({
        kind = "api",
        history_content = history_content,
        ctx_label = "folder_boundary_retry",
        retry_failed_key = "retry.reason.after_folder_boundary_mismatch",
        retry_failed_label = "after folder-boundary mismatch",
        failure_message = "Auto-retry after folder-boundary mismatch did not go through. Please resend the last message.",
      })
      return
    elseif bad_folder_boundary and #bad_folder_boundary > 0 then
      validator_gate_hit = true
      Log.line("FOLDER-BOUNDARY-VALIDATOR",
        "folder close stayed on outside track after retry; auto-run blocked")
      local finding = bad_folder_boundary[1]
      if finding.reason == "missing_parent_folder_track" then
        local parent_name = tostring(finding.parent_display
          or finding.expected_name_display
          or finding.expected_name
          or "requested folder")
        Log.add_error((RA and RA.t and RA.t(
          "validator.folder_parent_missing_blocked",
          { parent = parent_name },
          "The script appears to omit the requested folder parent track `"
            .. parent_name
            .. "` and open the folder on a child track instead. Auto-run is blocked; review I_FOLDERDEPTH before running manually."))
          or ("The script appears to omit the requested folder parent track `"
            .. parent_name
            .. "` and open the folder on a child track instead. Auto-run is blocked; review I_FOLDERDEPTH before running manually."))
      elseif finding.reason == "last_child_not_closed" then
        local last_child = tostring(finding.expected_name_display
          or finding.expected_name or "last child")
        Log.add_error((RA and RA.t and RA.t(
          "validator.folder_not_closed_blocked",
          { last_child = last_child },
          "The script appears to open a folder but never closes "
            .. "it on the requested last child `" .. last_child
            .. "`. Auto-run is blocked; review I_FOLDERDEPTH before running manually."))
          or ("The script appears to open a folder but never closes it on the requested last child `"
            .. last_child
            .. "`. Auto-run is blocked; review I_FOLDERDEPTH before running manually."))
      else
        local track_name = tostring(finding.name_display
          or finding.name or "an outside track")
        local last_child = tostring(finding.expected_name_display
          or finding.expected_name or "last child")
        Log.add_error((RA and RA.t and RA.t(
          "validator.folder_closed_wrong_track_blocked",
          { track = track_name, last_child = last_child },
          "The script appears to close a folder on `" .. track_name
            .. "` instead of the requested last child `" .. last_child
            .. "`. Auto-run is blocked; review I_FOLDERDEPTH before running manually."))
          or ("The script appears to close a folder on `" .. track_name
            .. "` instead of the requested last child `" .. last_child
            .. "`. Auto-run is blocked; review I_FOLDERDEPTH before running manually."))
      end
    end
  end

  -- High-confidence track-property flag validator. SetMediaTrackInfo_Value
  -- accepts numeric values; Lua booleans silently fail on flags like B_MUTE.
  if lua_code then
    local findings = Code.find_boolean_setmediatrackinfo_value_args
      and Code.find_boolean_setmediatrackinfo_value_args(lua_code) or nil
    if findings and findings[1] then
      local finding = findings[1]
      if not S.setmedia_bool_retry_used then
        S.setmedia_bool_retry_used = true
        S.setmedia_bool_validator_retries =
          (S.setmedia_bool_validator_retries or 0) + 1
        Log.line("SETMEDIA-BOOL-RETRY",
          "SetMediaTrackInfo_Value received boolean for "
          .. tostring(finding.parm or "?") .. " on line "
          .. tostring(finding.line or "?") .. "; retrying with numeric flag hint")
        local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
          .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: "
          .. "Your previous reply passed Lua boolean `"
          .. tostring(finding.bool or "true/false")
          .. "` to `reaper.SetMediaTrackInfo_Value(..., \""
          .. tostring(finding.parm or "B_*")
          .. "\", ...)`. `SetMediaTrackInfo_Value` takes numeric values; "
          .. "for track flags such as B_MUTE, B_MAINSEND, B_PHASE, and "
          .. "similar B_/I_ properties, use `1` for on/true and `0` for "
          .. "off/false. Preserve the user's requested tracks, names, "
          .. "plugins, parameter values, MIDI notes, markers, routing, and "
          .. "ordering. Only fix numeric-vs-boolean track property writes "
          .. "unless another change is required to make the script valid. "
          .. "Respond as if this is your FIRST reply -- do NOT apologize, "
          .. "do NOT mention a retry.)\n\nPrevious Lua to fix:\n```lua\n"
          .. lua_code
          .. "\n```\n\nUSER REQUEST:\n" .. (S.pending_orig_prompt or "")
        Net.fire_validator_retry({
          kind = "api",
          history_content = history_content,
          ctx_label = "setmedia_bool_retry",
          retry_failed_key = "retry.reason.after_setmedia_bool_write",
          retry_failed_label = "after boolean SetMediaTrackInfo_Value write",
          failure_message = "Auto-retry after boolean SetMediaTrackInfo_Value write did not go through. Please resend the last message.",
        })
        return
      end
      validator_gate_hit = true
      Log.line("SETMEDIA-BOOL-VALIDATOR",
        "boolean SetMediaTrackInfo_Value write persisted after retry; auto-run blocked")
      Log.add_error((RA and RA.t and RA.t(
        "validator.setmedia_bool_blocked", nil,
        "The script still passes Lua true/false to reaper.SetMediaTrackInfo_Value for a track property after a retry. Auto-run is blocked; change those writes to numeric 1 or 0 before running manually."))
        or "The script still passes Lua true/false to reaper.SetMediaTrackInfo_Value for a track property after a retry. Auto-run is blocked; change those writes to numeric 1 or 0 before running manually.")
    end
  end

  -- High-confidence track-selection write validator. REAPER selection should be
  -- changed through SetTrackSelected; writing B_SELECTED/I_SELECTED via
  -- SetMediaTrackInfo_Value can appear to work in code but fail to persist in
  -- real project state.
  if lua_code then
    local stripped = lua_code
      :gsub("%-%-%[%[.-%]%]", "")
      :gsub("%-%-[^\n]*", "")
    local bad_selection_key
    for _, key in ipairs({ "B_SELECTED", "I_SELECTED" }) do
      local pat = "reaper%.SetMediaTrackInfo_Value%s*%([^%)]-[\"']"
        .. key .. "[\"']"
      if stripped:find(pat) then
        bad_selection_key = key
        break
      end
    end
    local bad_selection_bool =
      Code.find_nil_prone_settrackselected_args(stripped)
    if bad_selection_key or bad_selection_bool then
      local retry_note
      if bad_selection_key then
        retry_note = "Your previous reply used "
          .. "reaper.SetMediaTrackInfo_Value(..., \""
          .. tostring(bad_selection_key)
          .. "\", ...) to select or unselect tracks. For track selection "
          .. "writes, use reaper.SetTrackSelected(track, true/false) instead."
      else
        local finding = bad_selection_bool and bad_selection_bool[1] or {}
        Log.line("TRACK-SELECTION-RETRY",
          "SetTrackSelected boolean argument can be nil on line "
          .. tostring(finding.line or "?") .. "; retrying with boolean hint")
        retry_note = "Your previous reply passed a value that can be nil "
          .. "as the second argument to reaper.SetTrackSelected(...). "
          .. "The second argument must always be a Lua boolean. Normalize "
          .. "the selection expression before the call, for example by "
          .. "using an explicit true/false value or comparing the variable "
          .. "to true."
      end
      if not S.track_selection_retry_used then
        S.track_selection_retry_used = true
        S.track_selection_validator_retries =
          (S.track_selection_validator_retries or 0) + 1
        if bad_selection_key then
          Log.line("TRACK-SELECTION-RETRY",
            "selection write via " .. tostring(bad_selection_key)
            .. "; retrying with SetTrackSelected hint")
        else
          local finding = bad_selection_bool and bad_selection_bool[1] or {}
          Log.line("TRACK-SELECTION-RETRY",
            "SetTrackSelected boolean argument can be nil on line "
            .. tostring(finding.line or "?") .. "; retrying with boolean hint")
        end
        local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
          .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: " .. retry_note .. " "
          .. "Preserve the user's requested tracks, names, plugins, parameter "
          .. "values, MIDI notes, markers, routing, and ordering. Only fix the "
          .. "track-selection API usage unless another change is required to "
          .. "make the script valid. Respond as if this is your FIRST reply -- "
          .. "do NOT apologize, do NOT mention a retry.)\n\nPrevious Lua to fix:\n```lua\n"
