      validator_gate_hit = true
      Log.line("TRACK-PAN-VALIDATOR",
        "track-pan API misuse persisted after retry; auto-run blocked")
      Log.add_error((RA and RA.t and RA.t(
        "validator.track_pan_blocked", nil,
        "The script still uses the wrong API or table-key shape for a track-pan request after a retry. Auto-run is blocked; write track pan with reaper.SetMediaTrackInfo_Value(track, \"D_PAN\", value) and bracket any track-handle table keys before running manually."))
        or "The script still uses the wrong API or table-key shape for a track-pan request after a retry. Auto-run is blocked; write track pan with reaper.SetMediaTrackInfo_Value(track, \"D_PAN\", value) and bracket any track-handle table keys before running manually.")
    end
  end

  -- Preflight: does the extracted lua_code actually parse as Lua?
  -- Empty-env load() does a pure syntax check (the env is only touched
  -- at execution time, not during compilation). If it fails, the fence
  -- was either mis-tagged by the model (e.g. ```lua wrapping prose /
  -- pseudo-code / a rule list) or contains a genuine syntax error that
  -- would fail at runtime anyway. Either way, it should not reach the
  -- Run button, the Save-as-.lua button, the auto-run path, or the
  -- JSFX-companion slot. Dropping lua_code here lets the raw fence
  -- fall through to the explanation text so the user still SEES what
  -- the model wrote; they just can't execute it. Complements the
  -- fence-label filter above: that stops correctly-labeled ```text
  -- fences from being mis-extracted, this stops ```lua-labeled blocks
  -- that aren't actually Lua from being mis-executed.
  if lua_code then
    lua_artifact_info = Code.classify_lua_artifact(lua_code,
      { context_text = text })
    if not lua_artifact_info.parse_ok then
      local parse_err = lua_artifact_info.parse_err
      Log.line("EXTRACT",
        "```lua block did not parse; dropping from extraction. err="
        .. tostring(parse_err))
      -- One-shot hidden retry with the parser error fed back in. Without
      -- this, a model that emits a Lua block with a missing `end` (or
      -- similar trivial syntax error) produces a "plain text" reply from
      -- the user's perspective: the fence is dropped, the explanation
      -- text remains, no Run button, no script ran. Same recovery shape
      -- as the helper / defer / api validators.
      if not S.parse_retry_used then
        S.parse_retry_used = true
        Log.line("PARSE-RETRY",
          "regenerating after Lua parse error (user-invisible)")
        local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
          .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: Your previous "
          .. "reply contained a ```lua code block that failed Lua's "
          .. "syntax check. Parser error:\n  "
          .. tostring(parse_err)
          .. "\n\nMost commonly this is a missing `end` to close a `for`, "
          .. "`if`, `while`, or `function` block, or an extra `end` that "
          .. "closes too early. Regenerate the FULL script in ONE complete "
          .. "```lua ... ``` block, end-balanced. Do NOT split the script "
          .. "across multiple fences. Do NOT emit <context_needed> -- "
          .. "all reference data is already pinned. Respond as if this is "
          .. "your FIRST reply -- do NOT apologize, do NOT mention a "
          .. "retry.)\n\n"
          .. "USER REQUEST:\n" .. (S.pending_orig_prompt or "")
        Net.fire_validator_retry({
          kind = "parse",
          history_content = history_content,
          ctx_label = "parse_retry",
          retry_failed_key = "retry.reason.after_lua_parse_error",
          retry_failed_label = "after Lua parse error",
          failure_message = "Auto-retry after Lua parse error did not go through. Please resend the last message.",
        })
        return
      end
      lua_code = nil
    elseif not lua_artifact_info.runnable then
      Log.line("EXTRACT",
        "```lua block classified as non-runnable "
        .. tostring(lua_artifact_info.kind) .. ": "
        .. tostring(lua_artifact_info.reason))
    end
  end

  if lua_code and type(Code.scan_forbidden_sandbox_globals) == "function" then
    local sandbox_forbidden = Code.scan_forbidden_sandbox_globals(lua_code)
    if sandbox_forbidden and (S.sandbox_global_validator_retries or 0) < 1 then
      S.sandbox_global_validator_retries =
        (S.sandbox_global_validator_retries or 0) + 1
      Log.line("SANDBOX-GLOBAL-RETRY",
        "forbidden globals in generated Lua (" .. tostring(sandbox_forbidden)
        .. "); retrying with hint (user-invisible)")
      local sandbox_user_text = (Net.retry_user_request_context
        and Net.retry_user_request_context()) or (S.pending_orig_prompt or "")
      local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
        .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: Your previous "
        .. "Lua script referenced Lua APIs that are unavailable in "
        .. "ReaAssist's execution sandbox: "
        .. tostring(sandbox_forbidden) .. ". Regenerate the FULL script "
        .. "without those APIs. Do not use `os`, `io`, `debug`, `package`, "
        .. "`require`, `dofile`, `loadfile`, `loadstring`, `load`, `_G`, "
        .. "`getfenv`, `setfenv`, `rawget`, or `rawset`. If you need a "
        .. "changing random seed, use "
        .. "`math.randomseed(math.floor((reaper.time_precise() or 0) * 1000000) % 2147483647)` "
        .. "instead of `os.time()`. Respond as if this is your FIRST "
        .. "reply -- do NOT apologize, do NOT mention a retry.)\n\n"
        .. "Previous Lua to fix:\n```lua\n" .. lua_code .. "\n```\n\n"
        .. "USER REQUEST:\n" .. sandbox_user_text
      Net.fire_validator_retry({
        kind = "sandbox_global",
        history_content = history_content,
        ctx_label = "sandbox_retry",
        retry_failed_key = "retry.reason.for_sandbox_forbidden_globals",
        retry_failed_label = "for sandbox-forbidden Lua APIs",
        failure_message = "Auto-retry for sandbox-forbidden Lua APIs did not go through. Please resend the last message.",
      })
      return
    end
  end

  -- If we have both JSFX and Lua, the display code block shows the JSFX
  -- (the Lua companion is a small helper that runs silently).
  local code, code_type
  if jsfx_code then
    code = jsfx_code
    code_type = "jsfx"
  elseif lua_code then
    code = lua_code
    code_type = "lua"
  end
  local typed_action_expected = S.pending_typed_action_expected == true
  local typed_action_response_format =
    S.pending_typed_action_response_format == true
  local typed_action_profile =
    Code.typed_actions_model_profile_by_key(S.pending_typed_action_profile)
  if type(typed_action_profile) ~= "table" then
    local pending_provider = PROVIDERS[S.pending_provider_idx] or PROVIDERS.active() or {}
    local pending_model = MODELS[S.pending_model_idx or prefs.model_idx]
      or MODELS[prefs.model_idx] or MODELS[1] or {}
    typed_action_profile =
      Code.typed_actions_model_profile(pending_provider.id, pending_model.id)
  end
  local typed_action_metrics = Code.inspect_typed_actions(text, {
    allow_raw_json = typed_action_response_format,
    user_text = S.pending_orig_prompt or "",
  })
  if (typed_action_metrics.present or typed_action_expected)
     and code_type == "lua" then
    typed_action_metrics.fallback_to_lua = true
  end
  local typed_action_semantic_block_reason = nil

  -- TYPED-ACTION FORMAT VALIDATOR: Typed-action output is intentionally
  -- strict; the executor/parser only accepts a `reaassist-actions` fence.
  -- If the model understood the schema but wrapped the valid JSON in a
  -- generic json/unlabeled fence, retry once with a format-only correction
  -- instead of accepting the wrong contract or surfacing an empty response.
  local typed_action_wrong_fence =
    (not typed_action_response_format
     and not typed_action_metrics.present and not code)
    and Code.find_typed_actions_wrong_fence(text) or nil
  if typed_action_expected and typed_action_wrong_fence then
    if (S.typed_action_format_validator_retries or 0) < 1 then
      S.typed_action_format_validator_retries =
        (S.typed_action_format_validator_retries or 0) + 1
      Log.line("TYPED-ACTION-FORMAT-VALIDATOR",
        "valid typed-action JSON was emitted under `"
        .. tostring(typed_action_wrong_fence.label)
        .. "` fence; retrying with exact fence label (user-invisible)")
      local prior_json = typed_action_wrong_fence.raw or ""
      if #prior_json > 10000 then
        prior_json = prior_json:sub(1, 10000) .. "\n..."
      end
      local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
        .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: Your previous reply "
        .. "produced a valid typed-action JSON object, but used the wrong "
        .. "fence label `" .. tostring(typed_action_wrong_fence.label)
        .. "`. The contract requires exactly one fenced block labelled "
        .. "`reaassist-actions` and no `json` fence. Re-emit the same JSON "
        .. "plan inside a ```reaassist-actions fence. Do not write Lua, "
        .. "ReaScript, JSFX, prose, apologies, or any other code fence.)\n\n"
        .. "VALID ACTION JSON FROM YOUR PREVIOUS REPLY:\n"
        .. prior_json .. "\n\nUSER REQUEST:\n"
        .. (S.pending_orig_prompt or "")
      Net.fire_validator_retry({
        kind = "typed_action_format",
        history_content = history_content,
        ctx_label = "typed_action_format_retry",
        retry_failed_key = "retry.reason.for_typed_action_fence_label",
        retry_failed_label = "for typed-action fence label",
        failure_message = "Auto-retry for typed-action fence label did not go through. Please resend the last message.",
      })
      return
    end
    typed_action_metrics.error = "wrong_fence_label"
  end

  -- If the gated contract was active and the model ignored it entirely, retry
  -- once with a format-only correction. This catches Lua/prose fallbacks on
  -- exact-fit routing/stock-FX requests without changing the normal Lua path
  -- for unsupported work.
  if typed_action_expected
     and not typed_action_metrics.present
     and not typed_action_wrong_fence then
    if (S.typed_action_format_validator_retries or 0) < 1 then
      S.typed_action_format_validator_retries =
        (S.typed_action_format_validator_retries or 0) + 1
      Log.line("TYPED-ACTION-FORMAT-VALIDATOR",
        "typed-action contract was active but no action block was emitted; "
        .. "retrying with contract-only correction (user-invisible)")
      local retry_contract =
        Code.typed_actions_prompt_contract(S.pending_orig_prompt or "",
          {
            force_enabled = true,
            response_format = typed_action_response_format,
            profile = typed_action_profile,
          }) or ""
      local reemit_hint = typed_action_response_format
        and "full plan as the raw JSON object required by the active response schema. "
            .. "Do not write Lua, ReaScript, JSFX, prose, apologies, markdown, "
            .. "raw text outside the JSON object, or any code fence.)"
        or "full plan as exactly one ```reaassist-actions fenced JSON object. "
            .. "Do not write Lua, ReaScript, JSFX, prose, apologies, raw JSON, "
            .. "or any other code fence.)"
      local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
        .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: Your previous reply "
        .. "did not include the required typed-action block. This request is "
        .. "an exact fit for the active TYPED ACTION CONTRACT. Re-emit the "
        .. reemit_hint
        .. (retry_contract ~= "" and ("\n\n" .. retry_contract) or "")
        .. "\n\nUSER REQUEST:\n" .. (S.pending_orig_prompt or "")
      Net.fire_validator_retry({
        kind = "typed_action_format",
        history_content = history_content,
        ctx_label = "typed_action_format_retry",
        retry_failed_key = "retry.reason.for_missing_typed_action_block",
        retry_failed_label = "for missing typed-action block",
        failure_message = "Auto-retry for missing typed-action block did not go through. Please resend the last message.",
      })
      return
    end
    if typed_action_metrics.error == "" then
      typed_action_metrics.error = "missing_action_block"
    end
    if not code and Net._try_typed_action_lua_fallback(
        "typed_action_format_retry_failed",
        typed_action_metrics.error) then
      return
    end
  end

  -- TYPED-ACTION SCHEMA VALIDATOR: once the gated contract is active, an
  -- invalid reaassist-actions block is more useful as a hidden repair turn
  -- than as a raw JSON blob in chat. This stays independent from the wrong-
  -- fence retry so we can measure format mistakes separately from schema
  -- mistakes in probe/bench.
  if typed_action_expected
     and typed_action_metrics.present
     and not typed_action_metrics.valid
     and not code then
    local schema_err = tostring(typed_action_metrics.error or "invalid_plan")
    local schema_detail = Code._typed_action_schema_retry_detail(text, {
      allow_raw_json = typed_action_response_format,
      user_text = S.pending_orig_prompt or "",
    })
    local _, selected_index_required =
      Code._typed_action_selected_indexes_from_user_text(
        S.pending_orig_prompt or "")
    local fast_schema_escalate =
      type(typed_action_profile) == "table"
      and typed_action_profile.schema_fast_escalate == true
    if (selected_index_required or fast_schema_escalate)
       and (S.typed_action_schema_validator_retries or 0) < 1
       and type(typed_action_profile) == "table"
       and type(typed_action_profile.fallback) == "table"
       and Net._try_escalate_typed_actions(
          selected_index_required
            and "typed_action_selected_index_schema_failed"
            or "typed_action_schema_fast_escalated",
          schema_detail ~= "" and schema_detail or schema_err) then
      return
    end
    if (S.typed_action_schema_validator_retries or 0) < 1 then
      S.typed_action_schema_validator_retries =
        (S.typed_action_schema_validator_retries or 0) + 1
      Log.line("TYPED-ACTION-SCHEMA-VALIDATOR",
        "invalid typed-action block (" .. schema_err
        .. "); retrying with schema correction (user-invisible)")
      local retry_contract =
        Code.typed_actions_prompt_contract(S.pending_orig_prompt or "",
          {
            force_enabled = true,
            response_format = typed_action_response_format,
            profile = typed_action_profile,
          }) or ""
      local reemit_hint = typed_action_response_format
        and "as the raw JSON object required by the active response schema. "
            .. "Do not write Lua, ReaScript, JSFX, prose, apologies, markdown, "
            .. "raw text outside the JSON object, or any code fence.)"
        or "as exactly one ```reaassist-actions fenced JSON object using only "
            .. "version=1 and supported v1 actions. Do not write Lua, ReaScript, "
            .. "JSFX, prose, apologies, or any other code fence.)"
      local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
        .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: Your previous reply "
        .. (typed_action_response_format
            and "produced typed-action JSON, but it failed validation "
            or "produced a `reaassist-actions` block, but it failed validation ")
        .. "with error `" .. schema_err .. "`. Details: "
        .. schema_detail .. ". Re-emit the full plan "
        .. reemit_hint
        .. (retry_contract ~= "" and ("\n\n" .. retry_contract) or "")
        .. "\n\n"
        .. "USER REQUEST:\n" .. (S.pending_orig_prompt or "")
      Net.fire_validator_retry({
        kind = "typed_action_schema",
        history_content = history_content,
        ctx_label = "typed_action_schema_retry",
        retry_failed_key = "retry.reason.for_typed_action_schema",
        retry_failed_label = "for typed-action schema",
        failure_message = "Auto-retry for typed-action schema did not go through. Please resend the last message.",
      })
      return
    end
    if Net._try_escalate_typed_actions(
        "typed_action_schema_retry_failed",
        schema_detail ~= "" and schema_detail or schema_err) then
      return
    end
  end

  -- TYPED-ACTION SEMANTIC VALIDATOR: reject valid JSON that is obviously
  -- wrong for the requested structured edit before it mutates the project. Model profiles
  -- can add extra prompt help or fallback policy, but the local semantic
  -- preflight runs for every typed-action plan that carries user text because
  -- execution uses the same fail-closed check.
  if typed_action_expected
     and typed_action_metrics.present
     and typed_action_metrics.valid
     and not code then
    local plan, plan_errors = Code.typed_actions_plan_from_text(text, {
      allow_raw_json = typed_action_response_format,
      user_text = S.pending_orig_prompt or "",
    })
    local semantic_ok, semantic_errors
    if plan then
      semantic_ok, semantic_errors = Code.validate_typed_actions_semantics(plan, {
        profile = typed_action_profile,
        user_text = S.pending_orig_prompt or "",
        selected_track_count = type(reaper.CountSelectedTracks) == "function"
          and reaper.CountSelectedTracks(0) or nil,
      })
    else
      semantic_ok = false
      semantic_errors = plan_errors
    end
    if not semantic_ok then
      local semantic_detail = Code.format_typed_action_semantic_errors(
        semantic_errors, 4)
      local missing_action_family =
        Code.typed_action_semantic_detail_missing_action_family(
          semantic_detail)
      local fast_semantic_escalate =
        type(typed_action_profile) == "table"
        and typed_action_profile.semantic_fast_escalate == true
        and missing_action_family
      if fast_semantic_escalate
         and type(typed_action_profile.fallback) == "table"
         and Net._try_escalate_typed_actions(
          "typed_action_semantic_fast_escalated", semantic_detail) then
        return
      end
      if (S.typed_action_semantic_validator_retries or 0)
          < (type(typed_action_profile) == "table"
            and tonumber(typed_action_profile.semantic_max_retries)
            or 1) then
        S.typed_action_semantic_validator_retries =
          (S.typed_action_semantic_validator_retries or 0) + 1
        Log.line("TYPED-ACTION-SEMANTIC-VALIDATOR",
          "typed-action plan failed semantic checks (" .. semantic_detail
          .. "); retrying with concrete correction (user-invisible)")
        local retry_from_scratch =
          Code.typed_action_semantic_retry_from_scratch(
            typed_action_profile, semantic_detail)
        local prior_json = ""
        if not retry_from_scratch then
          prior_json = tostring(text or ""):match("^%s*(.-)%s*$") or ""
          if #prior_json > 10000 then
            prior_json = prior_json:sub(1, 10000) .. "\n..."
          end
        end
        local retry_contract =
          Code.typed_actions_prompt_contract(S.pending_orig_prompt or "",
            {
              force_enabled = true,
              response_format = typed_action_response_format,
              profile = typed_action_profile,
            }) or ""
        local reemit_hint = typed_action_response_format
          and "raw JSON object required by the active response schema"
          or "single ```reaassist-actions fenced JSON object"
        local action_kind_hint = ""
        if missing_action_family then
          action_kind_hint = " Do not represent requested FX, parameter "
            .. "changes, or sends as track.ensure actions; use fx.add_stock, "
            .. "fx.set_param, and send.create."
        end
        local retry_instruction = retry_from_scratch
          and "Do not copy, expand, or repair the previous bad plan. "
            .. "Solve the original user request from scratch and emit the "
            .. "complete plan as a "
          or "Re-emit the complete corrected plan as a "
        local prior_section = retry_from_scratch and "" or
          ("PREVIOUS ACTION PLAN:\n" .. prior_json .. "\n\n")
        local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
          .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: Your previous "
          .. "typed-action plan was valid JSON, but it was semantically "
          .. "wrong for the requested structured edit. Problems: "
          .. semantic_detail .. "." .. action_kind_hint .. " "
          .. retry_instruction .. reemit_hint
          .. ". Do not write Lua, ReaScript, JSFX, prose, "
          .. "apologies, or omit any actions.)\n\n"
          .. (retry_contract ~= "" and (retry_contract .. "\n\n") or "")
          .. prior_section
          .. "USER REQUEST:\n" .. (S.pending_orig_prompt or "")
        Net.fire_validator_retry({
          kind = "typed_action_semantic",
          history_content = history_content,
          ctx_label = "typed_action_semantic_retry",
          retry_failed_key = "retry.reason.for_typed_action_semantics",
          retry_failed_label = "for typed-action semantics",
          failure_message = "Auto-retry for typed-action semantics did not go through. Please resend the last message.",
        })
        return
      end
      if Net._try_escalate_typed_actions(
          "typed_action_semantic_retry_failed", semantic_detail) then
        return
      end
      if missing_action_family
         and Net._try_typed_action_lua_fallback(
           "typed_action_semantic_exhausted", semantic_detail) then
        return
      end
      typed_action_semantic_block_reason = semantic_detail
      typed_action_metrics.valid = false
      typed_action_metrics.error = "semantic_mismatch"
    end
  end
  typed_action_metrics.retry_count =
    (S.typed_action_retry_offset or 0)
    + (S.typed_action_format_validator_retries or 0)
    + (S.typed_action_schema_validator_retries or 0)
    + (S.typed_action_semantic_validator_retries or 0)
    + (S.typed_action_escalation_count or 0)
  typed_action_metrics.escalated = S.typed_action_escalation_used == true
  typed_action_metrics.escalation_model = S.typed_action_escalation_model

  -- No unlabeled-fence fallback. Previously we extracted ANY ```<lang>
  -- fence as code and tagged it "lua" unless its first line was "desc:",
  -- which meant the model could return ```text (explanatory / pasteable
  -- rule text, per the system-prompt "Use ```text for non-runnable code"
  -- guidance) and we'd dutifully try to execute it as Lua -- producing
  -- "syntax error near 'safety'" and similar compile errors. Any response
  -- that wants to deliver runnable code MUST fence it as lua / reascript /
  -- jsfx / eel. Other fence labels are treated as illustration and stay
  -- in the explanation text.

  -- Strip all fences and unparsed context_needed tags from the explanation text.
  -- Typed-action-only responses also strip their JSON block; the gated
  -- executor below will replace an otherwise empty explanation with a concise
  -- status after it runs.
  if code or typed_action_metrics.present then
    if typed_action_metrics.raw_json then
      explanation = ""
    else
      explanation = text
        :gsub("```[^\n]*\n.-%s*```", "")
        :gsub("\n\n\n+", "\n\n")
        :match("^%s*(.-)%s*$")
    end
  end
  explanation = explanation
    :gsub("<%s*context_needed%s*>.-<%s*/%s*context_needed%s*>%s*", "")
    :gsub("\n\n\n+", "\n\n")
    :match("^%s*(.-)%s*$")
  if typed_action_semantic_block_reason then
    local detail = tostring(typed_action_semantic_block_reason)
    local base = (RA and RA.t and RA.t(
      "typed_actions.error.blocked_before_change", nil,
      "I blocked this structured edit before it changed the project because the plan did not match the request safely. No changes were made."))
      or "I blocked this structured edit before it changed the project because the plan did not match the request safely. No changes were made."
    local detail_text = (RA and RA.t and RA.t(
      "typed_actions.error.details", { detail = detail },
      "Details: " .. detail)) or ("Details: " .. detail)
    explanation = base .. " " .. detail_text
  end

  -- If explanation AND code are both empty after stripping (e.g. model replied
  -- with only a <context_needed> tag whose buckets were already sent), surface
  -- an error instead of a blank bubble.
  local typed_action_ready =
    typed_action_expected
    and typed_action_metrics.present
    and typed_action_metrics.valid
    and not code
  if (not explanation or explanation == "")
     and not code
     and not typed_action_ready then
    Code.safe_write(tmp.log, raw)
    if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
      S.display_messages[S.pending_display_idx].ctx_label = "error"
    end
    Log.add_error(
      "The model's response was empty after processing. This can happen "
      .. "when the model uses all its output for internal reasoning.\n\n"
      .. "Try lowering the Thinking level or increasing the Max Output "
      .. "Tokens on the Settings page.")
    return
  end

  -- Docs gate: if the model emitted reaper.* code without the API reference
  -- ever being provided this session (via the "Always include API ref" pref,
  -- which populates S.api_ref_message, or a prior
  -- <context_needed>docs</context_needed> request, which inlines docs into
  -- history and flips S.docs_fetched_session), the function signatures are
  -- almost certainly guessed.
  --
  -- Recovery strategy: silently force-fetch docs and re-fire the same user
  -- prompt, exactly as if the model had emitted <context_needed>docs
  -- </context_needed> itself. The user never sees the bad response;
  -- instead they see a "docs" bucket appear in the Show Details chip and
  -- the (correct) regenerated reply lands on the next round-trip. This
  -- matches the existing context-bucket recovery flow in
  -- Net.process_response_buckets so the control flow is familiar.
  --
  -- Known failure mode on weaker models like Kimi k2.6: silently guess at
  -- reaper.* calls instead of asking for docs, then fabricate an excuse
  -- ("docs are pre-pinned in your preferences") when questioned. Auto-
  -- retry fixes it without the user having to notice or intervene.
  --
  -- Detection: bare `reaper.<ident>` anywhere in lua_code. JSFX code uses
  -- EEL2 syntax (no reaper.* namespace) so jsfx_code is exempt.
  --
  -- Fallback: if CTX.docs() itself fails (disk read error, missing file),
  -- fall back to the old behaviour -- block auto-run and surface a visible
  -- error so the user can investigate. Flag docs_gate_hit for chat-bubble
  -- banner rendering on that fallback path.
  local docs_gate_hit = false
  -- "docs available" means the model has been given SOME flavor of API
  -- reference: full core (S.api_ref_message), the in-session core flag
  -- (S.docs_fetched_session), or any on-demand docs:<x> section already
  -- pinned via S.docs_section_sent. The original gate only checked the
  -- first two and would fire a wasted retry every time a fresh session
  -- used a section without first hitting core -- adding ~22 KB of
  -- redundant core docs to a turn the section had already covered.
  -- The API VALIDATOR below catches hallucinated calls regardless of
  -- which slice of docs is pinned, so the gate's role is just "confirm
  -- the model actually consulted docs at all" -- a single section is
  -- enough to satisfy that.
  local docs_available = S.api_ref_message ~= nil
    or S.docs_fetched_session
    or (S.docs_section_sent and next(S.docs_section_sent) ~= nil)
    or (S.midi_ref_message ~= nil
      and Code.prompt_has_midi_workflow_intent(S.pending_orig_prompt)
      and Code.lua_uses_only_midi_ref_covered_calls(lua_code))
  if lua_code and not docs_available
     and lua_code:find("reaper%.[%w_]") then
    local ref_content, ref_err = CTX.docs()
    if ref_content then
      Log.line("DOCS-GATE",
        "reaper.* calls detected with no docs available; auto-fetching "
        .. "docs, pinning for the rest of session, retrying (user-invisible)")
      S.docs_already_sent    = true
      S.docs_fetched_session = true
      -- Promote the fetched docs from a one-shot history inline into the
      -- persistent pinned-ref slot. From this send forward, every build
      -- includes docs in the PINNED REFERENCES manifest -- the model sees
      -- `docs` listed and complies on subsequent turns without triggering
      -- the gate again. Calibrates automatically per model: compliant
      -- models (Gemini, Claude) never trigger this; models that bias to
      -- action on "obvious" reaper.* calls (Kimi k2.6) take one retry
      -- hit per session, then get docs pinned permanently. Costs one
      -- round-trip once; saves it on every subsequent turn.
      S.api_ref_message = ref_content

      -- Build the replacement user history content: a short, model-only
      -- nudge + the original user prompt. The docs themselves are NOT
      -- embedded here: S.api_ref_message was just pinned above, so every
      -- build (including this retry) already carries the full reference
      -- in the pinned-refs slot. Inlining a second copy doubled ~22 KB on
      -- the retry AND persisted it in S.history, re-billing it on every
      -- later turn -- contradicting the "API ref is never stored in
      -- history" invariant. The nudge is phrased so the model treats this
      -- as its FIRST attempt from the user's perspective -- no
      -- meta-commentary about a retry, no apology, no mention that docs
      -- was previously missing. The user never saw the bad reply and
      -- shouldn't be confused by a reply that explains the invisible
      -- recovery.
      local history_content =
        "(INTERNAL NOTE TO THE MODEL -- DO NOT MENTION ANY OF THIS IN "
        .. "YOUR VISIBLE REPLY: Your previous reply wrote reaper.* calls "
        .. "without first requesting <context_needed>docs</context_needed>. "
        .. "The API reference is now pinned above. Regenerate the code "
        .. "using the documented function signatures. For ordered track "
        .. "creation, append tracks in forward order at reaper.CountTracks(0); "
        .. "do not repeatedly insert at index 0 or reverse the name list. "
        .. "Respond as if this is your FIRST reply to the user's request. "
        .. "Do NOT apologize, do NOT say 'let me try again' or 'on second "
        .. "thought', do NOT mention that docs was missing, do NOT mention "
        .. "a retry, do NOT re-emit a <context_needed>docs</context_needed> "
        .. "tag. Just deliver the correct code with a normal brief "
        .. "description, as if you had gotten it right on the first try.)\n\n"
        .. "USER REQUEST:\n" .. (S.pending_orig_prompt or "")

      -- Scrub the bad turn from history before firing the retry. By the
      -- time the gate runs, the response handler has already appended
      -- the assistant entry, so S.history tail is:
      --    [..., user_original, assistant_bad]
      -- We pop BOTH so the retry sees a clean prefix, then append the
      -- enriched user message. Without popping the assistant, the retry
      -- body carries the guessed code as a prior assistant turn, which
      -- (a) poisons prefix caching across retries and (b) fights the
      -- "respond as if this is your first reply" nudge by leaving an
      -- earlier reply visible in history.
      if #S.history > 0 and S.history[#S.history].role == "assistant" then
        S.history[#S.history] = nil
      end
      if #S.history > 0 and S.history[#S.history].role == "user" then
        S.history[#S.history] = nil
      end
      S.history[#S.history+1] = { role = "user", content = history_content }

      -- Reflect the docs inject in the pending user bubble's Show
      -- Details chip so the user can see (if they look) that docs
      -- was added to this turn.
      if S.pending_display_idx
         and S.display_messages[S.pending_display_idx] then
        local dmsg = S.display_messages[S.pending_display_idx]
        local existing = dmsg.ctx_label or ""
        if not existing:find("docs", 1, true) then
          dmsg.ctx_label = existing ~= ""
            and (existing .. " + docs") or "docs"
        end
        dmsg.docs_retry = true
      end

      -- Match the bucket-recovery flow: fire a hidden follow-up. No UI error,
      -- no display_message append -- the next response produces the real
      -- assistant reply.
      Net.fire_validator_retry({
        history_content = history_content,
        ctx_label = "docs",
        retry_failed_key = "retry.reason.with_api_reference",
        retry_failed_label = "with API reference",
        failure_message = "Auto-retry with API reference did not go through. Please resend the last message.",
      })
      return
    end
    -- Docs fetch failed: keep the old block-and-surface behaviour so the
    -- user knows something is wrong and can fix it manually.
    docs_gate_hit = true
    Log.line("DOCS-GATE",
      "reaper.* calls detected but CTX.docs() failed ("
      .. tostring(ref_err) .. "); auto-run blocked, message flagged")
    Log.add_error(
      "The model wrote reaper.* code without requesting the API "
      .. "reference, and ReaAssist could not auto-fetch the reference "
      .. "to retry (" .. tostring(ref_err) .. "). Auto-run is blocked; "
      .. "review the code carefully before clicking Run manually.")
  end

  -- GLOBAL-API-PREFIX VALIDATOR: Models occasionally typo the REAPER API
  -- global itself (`rearga.PreventUIRefresh`) while the method name is real.
  -- The normal API validator only sees `reaper.*` calls, so catch near-`rea*`
  -- globals that prefix real REAPER methods before the script reaches runtime.
  local unavailable_global_gate_hit = false
  if lua_code and not docs_gate_hit then
    local global_bad = Code.find_mistyped_reaper_globals(lua_code)
    if global_bad and #global_bad > 0 then
      if (S.unavailable_global_validator_retries or 0) < 1 then
        S.unavailable_global_validator_retries =
          (S.unavailable_global_validator_retries or 0) + 1
        local lines = {}
        for _, e in ipairs(global_bad) do
          lines[#lines + 1] = "  - line " .. tostring(e.line)
            .. ": `" .. tostring(e.global) .. "." .. tostring(e.name)
            .. "(...)` should be `reaper." .. tostring(e.name) .. "(...)`"
        end
        Log.line("GLOBAL-API-VALIDATOR",
          "mistyped reaper global(s): " .. #global_bad
          .. "; retrying with hint (user-invisible)")
        local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
          .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: Your previous "
          .. "reply misspelled the REAPER API global before real API "
          .. "method names:\n"
          .. tbl_concat(lines, "\n") .. "\n\n"
          .. "Regenerate the full script. Every REAPER API call must use "
          .. "the exact global `reaper`, never a variant such as `rearga`, "
          .. "`repaer`, `reaperl`, or `reel`. Respond as if this is your FIRST "
          .. "reply -- do NOT apologize, do NOT mention a retry.)\n\n"
          .. "USER REQUEST:\n" .. (S.pending_orig_prompt or "")
        Net.fire_validator_retry({
          kind = "unavailable_global",
          history_content = history_content,
          ctx_label = "api_retry",
          retry_failed_key = "retry.reason.for_mistyped_reaper_global",
          retry_failed_label = "for mistyped reaper global",
          failure_message = "Auto-retry for mistyped reaper global did not go through. Please resend the last message.",
        })
        return
      end
      unavailable_global_gate_hit = true
      validator_gate_hit = true
      local user_lines = {}
      for _, e in ipairs(global_bad) do
        user_lines[#user_lines + 1] = "line " .. tostring(e.line)
          .. " uses `" .. tostring(e.global) .. "."
          .. tostring(e.name) .. "` instead of `reaper."
          .. tostring(e.name) .. "`"
      end
      Log.line("GLOBAL-API-VALIDATOR",
        "mistyped reaper global persists after retry; auto-run blocked")
      Log.add_error((RA and RA.t and RA.t(
        "validator.mistyped_reaper_global_blocked",
        { lines = tbl_concat(user_lines, "; ") },
        "The model misspelled the REAPER API global, even "
          .. "after a retry: " .. tbl_concat(user_lines, "; ")
          .. ". Auto-run is blocked; review and edit the code before "
          .. "clicking Run manually."))
        or ("The model misspelled the REAPER API global, even after a retry: "
          .. tbl_concat(user_lines, "; ")
          .. ". Auto-run is blocked; review and edit the code before clicking Run manually."))
    end
  end

  -- API VALIDATOR: After the docs-gate, scan generated lua_code for
  -- reaper.X calls where X isn't a real function on this user's machine.
  -- Catches model hallucinations the docs-gate can't (docs-gate only
  -- fires when docs is missing; this fires when docs IS pinned but the
  -- model still emitted a fake function name -- "GetProjectMarkerByIndex"
  -- instead of "EnumProjectMarkers", etc.). Authoritative source is the
  -- live `reaper` table introspected by Code.find_unknown_reaper_calls,
  -- so the check covers core API + every extension actually installed
  -- on this machine.
  --
  -- Recovery: synthesize a retry hint listing the bad calls plus close-
  -- match suggestions, scrub the bad assistant turn from history, and
  -- fire a follow-up. Single retry per user prompt (S.api_validator_retries
  -- caps it). If the retry still produces bad calls, surface a visible
  -- error and block auto-run -- the user sees what was wrong instead of
  -- the script crashing at runtime with "attempt to call a nil value".
  -- Skipped when docs_gate_hit is already set: that path is already
  -- blocking auto-run and surfacing a fetch-failure error; no point
  -- retrying again.
  if lua_code and not docs_gate_hit and not unavailable_global_gate_hit then
    local unknown, total_scanned = Code.find_unknown_reaper_calls(lua_code)
    local bad_lua_calls =
      Code.find_unavailable_lua_library_calls
      and Code.find_unavailable_lua_library_calls(lua_code)
      or nil
    if not unknown and not bad_lua_calls then
      -- Pass log: prove the validator actively ran on this response and
      -- found nothing wrong. Skipped when total_scanned == 0 (no reaper.*
      -- calls in the script -- e.g. pure math/string code) since there
      -- was nothing to validate.
      if total_scanned > 0 then
        Log.line("API-VALIDATOR",
          "scanned " .. total_scanned .. " reaper.* call(s), all valid")
      end
    end
    if unknown or bad_lua_calls then
      if (S.api_validator_retries or 0) < 1 then
        S.api_validator_retries = (S.api_validator_retries or 0) + 1
        -- Build per-bad-name suggestion lines for the retry hint.
        local sug_lines = {}
        for _, bad in ipairs(unknown or {}) do
          local matches = Code.suggest_reaper_alternatives(bad, 6)
          local prefixed = {}
          for _, m in ipairs(matches) do prefixed[#prefixed+1] = "reaper." .. m end
          sug_lines[#sug_lines+1] = "  - reaper." .. bad
            .. (#prefixed > 0
                and (" (closest real names: " .. tbl_concat(prefixed, ", ") .. ")")
                or " (no close matches in this user's installed REAPER + extensions)")
        end
        for _, bad in ipairs(bad_lua_calls or {}) do
          sug_lines[#sug_lines+1] = "  - line " .. tostring(bad.line)
            .. ": `" .. tostring(bad.call) .. "(...)` is unavailable. "
            .. tostring(bad.message)
        end
        Log.line("API-VALIDATOR",
          "invalid generated calls (reaper=" .. tostring(unknown and #unknown or 0)
          .. ", lua=" .. tostring(bad_lua_calls and #bad_lua_calls or 0)
          .. "): " .. tbl_concat(sug_lines, " | ")
          .. "; retrying with hint (user-invisible)")
        local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT MENTION "
          .. "ANY OF THIS IN YOUR VISIBLE REPLY: Your previous reply called "
          .. "REAPER API functions or Lua library members that will not run "
          .. "inside ReaAssist on this user's machine. These calls would crash "
          .. "at runtime:\n"
          .. tbl_concat(sug_lines, "\n") .. "\n\n"
          .. "Regenerate the code using only real reaper.* functions and Lua "
          .. "library members that exist in Lua 5.4. Cross-check every call "
          .. "before emitting. For dB conversion, use the exponent operator, "
          .. "for example `10 ^ (db / 20)`, not `math.pow(...)`. Respond as if this is your FIRST "
          .. "reply to the user's request -- do NOT apologize, do NOT say "
          .. "'let me try again' or 'on second thought', do NOT mention "
          .. "that prior calls were wrong, do NOT mention a retry. Just "
          .. "deliver the correct code with a normal brief description.)\n\n"
          .. "USER REQUEST:\n" .. (S.pending_orig_prompt or "")
        Net.fire_validator_retry({
          kind = "api",
          history_content = history_content,
          ctx_label = "api_retry",
          retry_failed_key = "retry.reason.for_invalid_reaper_calls",
          retry_failed_label = "for invalid reaper.* calls",
          failure_message = "Auto-retry for invalid reaper.* calls did not go through. Please resend the last message.",
        })
        return
      end
      -- Retry already used and the model STILL produced bad calls. Block
      -- auto-run and surface the diagnostic so the user can review/edit
      -- before clicking Run manually.
      validator_gate_hit = true
      Log.line("API-VALIDATOR",
        "invalid generated calls persist after retry; auto-run blocked")
      local call_parts = {}
      for _, bad in ipairs(unknown or {}) do
        call_parts[#call_parts + 1] = "reaper." .. tostring(bad)
      end
      for _, bad in ipairs(bad_lua_calls or {}) do
        call_parts[#call_parts + 1] = tostring(bad.call)
      end
      local calls = tbl_concat(call_parts, ", ")
      Log.add_error((RA and RA.t and RA.t(
        "validator.invalid_reaper_calls_blocked", { calls = calls },
        "The model emitted Lua/ReaScript calls that will not run "
          .. "in ReaAssist, even after a retry: " .. calls
          .. ". Auto-run is blocked; review and edit the code before clicking "
          .. "Run manually, or retry with a stronger model."))
        or ("The model emitted Lua/ReaScript calls that will not run in ReaAssist, even after a retry: "
          .. calls
          .. ". Auto-run is blocked; review and edit the code before clicking Run manually, or retry with a stronger model."))
    end
  end

  -- TOOLBAR ACTION VALIDATOR: toolbar toggle scripts have a nasty failure
  -- mode when the same action is both the long-lived defer watcher and the
  -- click-to-toggle state mutation. A second toolbar click re-enters the
  -- script through REAPER's action context while the old instance is still
  -- alive, so ExtState "running/request_close" guards often produce apparent
  -- double-click requirements or stale toolbar state. Also enforce REAPER's
  -- I_FREEMODE rule: call UpdateTimeline after changing fixed-lane mode.
  local toolbar_gate_hit = false
  if lua_code and not docs_gate_hit and not validator_gate_hit then
    local toolbar_bad = Code.find_toolbar_toggle_action_issues(lua_code)
    if toolbar_bad and #toolbar_bad > 0 then
      if (S.toolbar_validator_retries or 0) < 1 then
        S.toolbar_validator_retries =
          (S.toolbar_validator_retries or 0) + 1
        local lines = {}
        for _, e in ipairs(toolbar_bad) do
          lines[#lines + 1] = "  - [" .. tostring(e.code) .. "] "
            .. tostring(e.message)
        end
        Log.line("TOOLBAR-ACTION-VALIDATOR",
          "fragile toolbar action pattern (" .. #toolbar_bad
          .. " finding(s)); retrying with hint (user-invisible)")
        local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
          .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: Your previous "
          .. "reply used a fragile REAPER toolbar/action script pattern:\n"
          .. tbl_concat(lines, "\n") .. "\n\n"
          .. "Regenerate the FULL script. For toolbar toggle actions, do "
          .. "not make the same REAPER action both a long-lived watcher and "
          .. "the click-to-toggle project-state mutator. Prefer a one-shot "
          .. "toolbar action: read the live project/track state, toggle the "
          .. "selected track(s), refresh toolbar state from live data, then "
          .. "exit. If a watcher is truly required, keep it observational "
          .. "only or explain that it must be installed/launched from the "
          .. "REAPER action context, not auto-run from ReaAssist. If you "
          .. "write I_FREEMODE, call reaper.UpdateTimeline() after the "
          .. "writes. Respond as if this is your FIRST reply -- do NOT "
          .. "apologize, do NOT mention a retry.)\n\nPrevious Lua to fix:\n"
          .. "```lua\n" .. lua_code .. "\n```\n\nUSER REQUEST:\n"
          .. (S.pending_orig_prompt or "")
        Net.fire_validator_retry({
          kind = "toolbar_action",
          history_content = history_content,
          ctx_label = "toolbar_retry",
          retry_failed_key = "retry.reason.after_fragile_toolbar_action_pattern",
          retry_failed_label = "after fragile toolbar action pattern",
          failure_message = "Auto-retry after fragile toolbar action pattern did not go through. Please resend the last message.",
        })
        return
      end
      toolbar_gate_hit = true
      validator_gate_hit = true
      local user_lines = {}
      for _, e in ipairs(toolbar_bad) do
        user_lines[#user_lines + 1] = tostring(e.code)
      end
      Log.line("TOOLBAR-ACTION-VALIDATOR",
        "fragile toolbar action pattern persisted after retry: "
        .. tbl_concat(user_lines, ", ") .. "; auto-run blocked")
      Log.add_error((RA and RA.t and RA.t(
        "validator.toolbar_action_blocked",
        { codes = tbl_concat(user_lines, ", ") },
        "The model emitted a fragile toolbar/action script even "
          .. "after a retry: " .. tbl_concat(user_lines, ", ")
          .. ". Auto-run is blocked because this pattern can require repeated "
          .. "toolbar clicks or leave stale toolbar state. Review the script "
          .. "before saving/installing it as a REAPER action."))
        or ("The model emitted a fragile toolbar/action script even after a retry: "
          .. tbl_concat(user_lines, ", ")
          .. ". Auto-run is blocked because this pattern can require repeated toolbar clicks or leave stale toolbar state. Review the script before saving/installing it as a REAPER action."))
    end
  end

  -- MIDI-ITEM VALIDATOR: AddMediaItemToTrack creates a plain media item, not
  -- a MIDI item. MIDI_InsertNote also expects PPQ positions, not seconds or
  -- beats. Lower-tier models can otherwise "succeed" with zero notes or notes
  -- crammed near time zero. Retry once when the user's task is clearly to
  -- create MIDI content and either pattern appears.
  -- NOTE: do NOT add `and not S.midi_item_retry_used` here. The retry sets
  -- that flag, so gating the whole block on it made the second-strike
  -- branch below unreachable on the retried response -- persisting MIDI
  -- misuse auto-ran silently. The `midi_item_validator_retries < 1` check
  -- inside is what caps the retry count.
  if lua_code and not docs_gate_hit and not validator_gate_hit then
    local prompt_l = tostring(S.pending_orig_prompt or ""):lower()
    local wants_new_midi_item =
      Code.prompt_requests_new_midi_content(S.pending_orig_prompt)
      or (prompt_l:find("midi%s+item")
        and (prompt_l:find("create") or prompt_l:find("add")
          or prompt_l:find("insert") or prompt_l:find("new")))
    local stripped = lua_code
      :gsub("%-%-%[%[.-%]%]", "")
      :gsub("%-%-[^\n]*", "")
    local plain_item_midi =
      wants_new_midi_item
      and stripped:find("reaper%.AddMediaItemToTrack%s*%(")
      and not stripped:find("reaper%.CreateNewMIDIItemInProj%s*%(")
      and (stripped:find("reaper%.MIDI_InsertNote%s*%(")
        or stripped:find("reaper%.MIDI_InsertCC%s*%(")
        or stripped:find("reaper%.MIDI_SetAllEvts%s*%("))
    local literal_ppq_midi =
      Code.find_literal_midi_insertnote_ppq_misuse(lua_code,
        S.pending_orig_prompt)
    local project_time_var_midi =
      Code.find_midi_insertnote_project_time_variable_misuse
      and Code.find_midi_insertnote_project_time_variable_misuse(lua_code,
        S.pending_orig_prompt)
    local table_pitch_midi =
      Code.find_midi_insertnote_table_pitch_misuse(lua_code,
        S.pending_orig_prompt)
    local kick_pitch_midi =
      Code.find_kick_midi_wrong_pitch_misuse
      and Code.find_kick_midi_wrong_pitch_misuse(lua_code,
        S.pending_orig_prompt)
    local named_note_octave_midi =
      Code.find_midi_named_note_octave_misuse
      and Code.find_midi_named_note_octave_misuse(lua_code,
        S.pending_orig_prompt)
    local seconds_as_qn_midi =
      Code.find_midi_seconds_as_qn_offset_misuse
      and Code.find_midi_seconds_as_qn_offset_misuse(lua_code,
        S.pending_orig_prompt)
    local eighth_spacing_midi =
      Code.find_midi_eighth_spacing_misuse
      and Code.find_midi_eighth_spacing_misuse(lua_code,
        S.pending_orig_prompt)
    local bad_midi_item_track_arg =
      Code.find_create_new_midi_item_bad_track_arg(lua_code,
        S.pending_orig_prompt)
    local bad_takeismidi_arg =
      Code.find_takeismidi_media_item_arg
      and Code.find_takeismidi_media_item_arg(lua_code,
        S.pending_orig_prompt)
    if plain_item_midi or literal_ppq_midi or project_time_var_midi
       or table_pitch_midi
       or kick_pitch_midi or named_note_octave_midi
       or seconds_as_qn_midi or eighth_spacing_midi
       or bad_midi_item_track_arg
       or bad_takeismidi_arg then
      local midi_issue = plain_item_midi and "plain_item"
        or (literal_ppq_midi and "literal_ppq"
          or (project_time_var_midi and "project_time_var"
            or (table_pitch_midi and "table_pitch"
              or (kick_pitch_midi and "kick_pitch"
                or (named_note_octave_midi and "named_note_octave"
                or (seconds_as_qn_midi and "seconds_as_qn"
                or (eighth_spacing_midi and "eighth_spacing"
                  or (bad_midi_item_track_arg and "bad_track_arg"
                    or "takeismidi_item_arg"))))))))
      if (S.midi_item_validator_retries or 0) < 1 then
        S.midi_item_retry_used = true
        S.midi_item_validator_retries =
          (S.midi_item_validator_retries or 0) + 1
        local midi_retry_kind =
          midi_issue == "plain_item" and "midi_item"
          or (midi_issue == "literal_ppq" and "midi_insertnote_ppq"
            or (midi_issue == "project_time_var" and "midi_insertnote_project_time"
              or (midi_issue == "table_pitch" and "midi_insertnote_table_pitch"
                or (midi_issue == "kick_pitch" and "midi_kick_pitch"
                  or (midi_issue == "named_note_octave" and "midi_named_note_octave"
                  or (midi_issue == "seconds_as_qn" and "midi_seconds_as_qn"
                  or (midi_issue == "eighth_spacing" and "midi_eighth_spacing"
                    or (midi_issue == "bad_track_arg" and "midi_item_track_arg"
                      or "midi_takeismidi_arg"))))))))
        local log_msg
        if midi_issue == "plain_item" then
          log_msg = "plain media item used as MIDI item; retrying with hint"
        elseif midi_issue == "literal_ppq" then
          log_msg = "literal project-time-like PPQ values used; retrying with hint"
        elseif midi_issue == "project_time_var" then
          log_msg = "project-time variables used as MIDI PPQ; retrying with hint"
        elseif midi_issue == "table_pitch" then
          log_msg = "table-valued MIDI note pitch used; retrying with hint"
        elseif midi_issue == "kick_pitch" then
          log_msg = "non-GM kick MIDI pitch used; retrying with hint"
        elseif midi_issue == "named_note_octave" then
          log_msg = "C4/E4/G4 triad used C3 octave MIDI pitches; retrying with hint"
        elseif midi_issue == "seconds_as_qn" then
          log_msg = "seconds-per-beat values used as project-QN MIDI offsets; retrying with hint"
        elseif midi_issue == "eighth_spacing" then
          log_msg = "quarter-note MIDI spacing used for requested eighths; retrying with hint"
        elseif midi_issue == "bad_track_arg" then
          log_msg = "invalid CreateNewMIDIItemInProj track argument used; retrying with hint"
        else
          log_msg = "TakeIsMIDI called on media item handle; retrying with hint"
        end
        Log.line("MIDI-ITEM-VALIDATOR", log_msg)
        local issue_text
        if midi_issue == "plain_item" then
          issue_text = "Your previous reply created a plain media item with "
            .. "reaper.AddMediaItemToTrack(), then attempted to insert MIDI "
            .. "events into its active take. AddMediaItemToTrack does not "
            .. "create a MIDI take. Use "
            .. "reaper.CreateNewMIDIItemInProj(track, start_seconds, "
            .. "end_seconds, false), get its active take, verify "
            .. "reaper.TakeIsMIDI(take), convert absolute project-time note "
            .. "start/end seconds with MIDI_GetPPQPosFromProjTime, then "
            .. "insert the notes."
        else
          if midi_issue == "literal_ppq" then
            issue_text = "Your previous reply passed beat/second-looking "
              .. "numbers directly to reaper.MIDI_InsertNote. MIDI_InsertNote "
              .. "start/end positions are PPQ, not seconds or beats. Use "
              .. "reaper.CreateNewMIDIItemInProj(track, start_seconds, "
              .. "end_seconds, false), get the active MIDI take, convert each "
              .. "absolute project-time note start/end second with "
              .. "reaper.MIDI_GetPPQPosFromProjTime(take, seconds), then pass "
              .. "those PPQ values to MIDI_InsertNote."
          elseif midi_issue == "project_time_var" then
            issue_text = "Your previous reply calculated MIDI note starts and "
              .. "ends as project-time variables, then passed those variables "
              .. "directly to reaper.MIDI_InsertNote. MIDI_InsertNote start/end "
              .. "positions are PPQ, not seconds. Use "
              .. "reaper.CreateNewMIDIItemInProj(track, start_seconds, "
              .. "end_seconds, false), get the active MIDI take, convert each "
              .. "absolute project-time note start/end second with "
              .. "reaper.MIDI_GetPPQPosFromProjTime(take, seconds), then pass "
              .. "those PPQ variables to MIDI_InsertNote."
          elseif midi_issue == "table_pitch" then
            issue_text = "Your previous reply built a chord/arpeggio pitch "
              .. "table with one extra wrapper level, so the value passed as "
              .. "the pitch argument to reaper.MIDI_InsertNote is a table, "
              .. "not a number. Bad: `local chords = { {{48, 51, 55}, "
              .. "{53, 56, 60}} }`; then `chord[i]` is a table. Good: "
              .. "`local chords = { {48, 51, 55}, {53, 56, 60} }`; then "
              .. "`chord[i]` is a numeric MIDI pitch. Regenerate the MIDI "
              .. "script with one scalar pitch row per chord."
          elseif midi_issue == "kick_pitch" then
            issue_text = "Your previous reply created a kick-only MIDI pattern "
              .. "but inserted a non-kick note pitch. For an unspecified kick "
              .. "MIDI pattern, use General MIDI kick pitch 36 for every kick "
              .. "hit unless the user explicitly asks for a different pitch."
          elseif midi_issue == "named_note_octave" then
            issue_text = "Your previous reply created the requested C4/E4/G4 "
              .. "triad using MIDI pitches 48, 52, and 55. In this context, "
              .. "C4 is MIDI pitch 60, E4 is 64, and G4 is 67. Regenerate "
              .. "the MIDI script with the requested C4/E4/G4 triad at "
              .. "pitches 60, 64, and 67; do not use 48, 52, or 55 for "
              .. "those note names."
          elseif midi_issue == "seconds_as_qn" then
            issue_text = "Your previous reply calculated seconds with "
              .. "`60 / bpm`, then used those second values as project "
              .. "quarter-note offsets with MIDI_GetPPQPosFromProjQN. "
              .. "MIDI_GetPPQPosFromProjQN expects project QN units: an "
              .. "eighth-note offset is 0.5 QN and a quarter-note offset is "
              .. "1.0 QN. Either use QN offsets such as `i * 0.5`, or keep "
              .. "the second-based math and convert note starts with "
              .. "MIDI_GetPPQPosFromProjTime."
          elseif midi_issue == "eighth_spacing" then
            issue_text = "Your previous reply used quarter-note or fixed "
              .. "0.5-second spacing for note starts even though the user "
              .. "requested eighth-note placement. For requested next-eighth, "
              .. "every-eighth, or eighth-note patterns, advance each note "
              .. "start by the tempo-derived eighth-note interval. In PPQ, "
              .. "use the eighth-note PPQ length, for example "
              .. "`pos_ppq = ppq_start + i * ppq_per_en`; in seconds, use "
              .. "`30 / bpm` seconds per eighth note. Keep note duration "
              .. "separate from note spacing."
          elseif midi_issue == "bad_track_arg" then
            issue_text = "Your previous reply called "
              .. "reaper.CreateNewMIDIItemInProj with a project id or boolean "
              .. "as the first argument. The first argument must be a "
              .. "MediaTrack handle. For a new MIDI idea or pattern, create "
              .. "and name a track first with InsertTrackAtIndex/GetTrack, "
              .. "then call reaper.CreateNewMIDIItemInProj(track, "
              .. "start_seconds, end_seconds, false)."
          else
            issue_text = "Your previous reply called reaper.TakeIsMIDI with "
              .. "a MediaItem variable instead of a MediaItem_Take. "
              .. "Create the MIDI item with reaper.CreateNewMIDIItemInProj, "
              .. "then call reaper.GetActiveTake(item) into a variable named "
              .. "take, verify reaper.TakeIsMIDI(take), and pass that take "
              .. "to MIDI_GetPPQPosFromProjTime and MIDI_InsertNote. Never "
              .. "call reaper.TakeIsMIDI(item)."
          end
        end
        local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
          .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: "
          .. issue_text .. " Preserve the user's requested tracks, names, "
          .. "note pitches, note times, markers, routing, plugins, and "
          .. "ordering. Respond as if this is your FIRST reply -- do NOT "
          .. "apologize, do NOT mention a retry.)\n\n"
          .. "Previous Lua to fix:\n```lua\n"
          .. lua_code
          .. "\n```\n\nUSER REQUEST:\n" .. (S.pending_orig_prompt or "")
        Net.fire_validator_retry({
          kind = midi_retry_kind,
          history_content = history_content,
          ctx_label = "midi_item_retry",
          retry_failed_key = "retry.reason.after_midi_validator_issue",
          retry_failed_label = "after MIDI validator issue",
          failure_message = "Auto-retry after MIDI validator issue did not go through. Please resend the last message.",
        })
        return
      end
      validator_gate_hit = true
      if midi_issue == "plain_item" then
        Log.line("MIDI-ITEM-VALIDATOR",
          "plain media item MIDI pattern persisted after retry; auto-run blocked")
        Log.add_error((RA and RA.t and RA.t(
          "validator.midi_plain_item_blocked", nil,
          "The script creates a plain media item with "
            .. "AddMediaItemToTrack but then inserts MIDI into it. "
            .. "Auto-run is blocked because this produces an item with no MIDI "
            .. "notes. Use CreateNewMIDIItemInProj for new MIDI items."))
          or "The script creates a plain media item with AddMediaItemToTrack but then inserts MIDI into it. Auto-run is blocked because this produces an item with no MIDI notes. Use CreateNewMIDIItemInProj for new MIDI items.")
      elseif midi_issue == "literal_ppq" then
        Log.line("MIDI-ITEM-VALIDATOR",
          "literal MIDI_InsertNote PPQ misuse persisted after retry; auto-run blocked")
        Log.add_error((RA and RA.t and RA.t(
          "validator.midi_literal_ppq_blocked", nil,
          "The script passes beat or second-looking numbers "
            .. "directly to MIDI_InsertNote. Auto-run is blocked because MIDI "
            .. "note start/end positions must be PPQ. Convert project time with "
            .. "MIDI_GetPPQPosFromProjTime before inserting notes."))
          or "The script passes beat or second-looking numbers directly to MIDI_InsertNote. Auto-run is blocked because MIDI note start/end positions must be PPQ. Convert project time with MIDI_GetPPQPosFromProjTime before inserting notes.")
      elseif midi_issue == "project_time_var" then
        Log.line("MIDI-ITEM-VALIDATOR",
          "project-time MIDI_InsertNote variables persisted after retry; auto-run blocked")
        Log.add_error((RA and RA.t and RA.t(
          "validator.midi_project_time_ppq_blocked", nil,
          "The script passes project-time variables directly to MIDI_InsertNote. "
            .. "Auto-run is blocked because MIDI note start/end positions must "
            .. "be PPQ. Convert project time with MIDI_GetPPQPosFromProjTime "
            .. "before inserting notes."))
          or "The script passes project-time variables directly to MIDI_InsertNote. Auto-run is blocked because MIDI note start/end positions must be PPQ. Convert project time with MIDI_GetPPQPosFromProjTime before inserting notes.")
      elseif midi_issue == "table_pitch" then
        Log.line("MIDI-ITEM-VALIDATOR",
          "table-valued MIDI note pitch persisted after retry; auto-run blocked")
        Log.add_error((RA and RA.t and RA.t(
          "validator.midi_table_pitch_blocked", nil,
          "The script passes a table as the MIDI_InsertNote pitch "
            .. "argument. Auto-run is blocked because note pitch must be a "
            .. "number from 0 to 127."))
          or "The script passes a table as the MIDI_InsertNote pitch argument. Auto-run is blocked because note pitch must be a number from 0 to 127.")
      elseif midi_issue == "kick_pitch" then
        Log.line("MIDI-ITEM-VALIDATOR",
          "non-GM kick MIDI pitch persisted after retry; auto-run blocked")
        Log.add_error((RA and RA.t and RA.t(
          "validator.midi_kick_pitch_blocked", nil,
          "The script inserts a non-kick MIDI note for a kick-only pattern. "
            .. "Auto-run is blocked because the generated kick hits would be "
            .. "on the wrong GM drum pitch. Use MIDI pitch 36 for kick hits "
            .. "unless the user explicitly asks for another pitch."))
          or "The script inserts a non-kick MIDI note for a kick-only pattern. Auto-run is blocked because the generated kick hits would be on the wrong GM drum pitch. Use MIDI pitch 36 for kick hits unless the user explicitly asks for another pitch.")
      elseif midi_issue == "named_note_octave" then
        Log.line("MIDI-ITEM-VALIDATOR",
          "C4/E4/G4 triad octave mismatch persisted after retry; auto-run blocked")
        Log.add_error((RA and RA.t and RA.t(
          "validator.midi_named_note_octave_blocked", nil,
          "The script inserts C3 octave MIDI pitches for a requested "
            .. "C4/E4/G4 triad. Auto-run is blocked because the generated "
            .. "notes would be an octave lower than requested. Use MIDI "
            .. "pitches 60, 64, and 67 for C4, E4, and G4 in this context."))
          or "The script inserts C3 octave MIDI pitches for a requested C4/E4/G4 triad. Auto-run is blocked because the generated notes would be an octave lower than requested. Use MIDI pitches 60, 64, and 67 for C4, E4, and G4 in this context.")
      elseif midi_issue == "seconds_as_qn" then
        Log.line("MIDI-ITEM-VALIDATOR",
          "seconds-per-beat values persisted as project-QN MIDI offsets; auto-run blocked")
        Log.add_error((RA and RA.t and RA.t(
          "validator.midi_seconds_as_qn_blocked", nil,
          "The script calculates seconds from BPM, then uses those values as "
            .. "project QN offsets with MIDI_GetPPQPosFromProjQN. Auto-run "
            .. "is blocked because the generated note timing would be too "
            .. "early. Use QN offsets such as 0.5 per eighth note, or convert "
            .. "seconds with MIDI_GetPPQPosFromProjTime."))
          or "The script calculates seconds from BPM, then uses those values as project QN offsets with MIDI_GetPPQPosFromProjQN. Auto-run is blocked because the generated note timing would be too early. Use QN offsets such as 0.5 per eighth note, or convert seconds with MIDI_GetPPQPosFromProjTime.")
      elseif midi_issue == "eighth_spacing" then
        Log.line("MIDI-ITEM-VALIDATOR",
          "quarter-note MIDI spacing persisted for requested eighths; auto-run blocked")
        Log.add_error((RA and RA.t and RA.t(
          "validator.midi_eighth_spacing_blocked", nil,
          "The script advances MIDI note starts by quarter-note or fixed "
            .. "half-second spacing even though the request asks for "
            .. "eighth-note placement. Auto-run is blocked because the timing "
            .. "would be wrong. Use tempo-derived eighth-note spacing for the "
            .. "note starts."))
          or "The script advances MIDI note starts by quarter-note or fixed half-second spacing even though the request asks for eighth-note placement. Auto-run is blocked because the timing would be wrong. Use tempo-derived eighth-note spacing for the note starts.")
      elseif midi_issue == "bad_track_arg" then
        Log.line("MIDI-ITEM-VALIDATOR",
          "invalid CreateNewMIDIItemInProj track argument persisted after retry; auto-run blocked")
        Log.add_error((RA and RA.t and RA.t(
          "validator.midi_bad_track_arg_blocked", nil,
          "The script passes a project id or boolean as the first "
            .. "argument to CreateNewMIDIItemInProj. Auto-run is blocked because "
            .. "that argument must be a MediaTrack handle."))
          or "The script passes a project id or boolean as the first argument to CreateNewMIDIItemInProj. Auto-run is blocked because that argument must be a MediaTrack handle.")
      else
        Log.line("MIDI-ITEM-VALIDATOR",
          "TakeIsMIDI media item argument persisted after retry; auto-run blocked")
        Log.add_error((RA and RA.t and RA.t(
          "validator.midi_takeismidi_item_arg_blocked", nil,
          "The script calls TakeIsMIDI with a MediaItem instead of a "
            .. "MediaItem_Take. Auto-run is blocked because this crashes at "
            .. "runtime. Get the active take from the item first."))
          or "The script calls TakeIsMIDI with a MediaItem instead of a MediaItem_Take. Auto-run is blocked because this crashes at runtime. Get the active take from the item first.")
      end
    end
  end

  -- MIDI INPUT DEVICE FILTER VALIDATOR: REAPER's track record input can target
  -- one physical MIDI input or all physical MIDI inputs, but it cannot encode
  -- "all devices except X" in one I_RECINPUT value. Lower-tier models have
  -- invented P_MIDI_MAP / 4096+256 map-mode shapes, or backed off to a
  -- diagnostic GetMIDIInputName script that never applies the requested
  -- routing. Retry once with the real constraint, then block the false-done
  -- script before it reaches auto-run.
  local midi_input_gate_hit = false
  if lua_code and not docs_gate_hit and not validator_gate_hit then
    local midi_input_bad = Code.find_midi_input_device_filter_misuse(
      lua_code, S.pending_orig_prompt)
    if midi_input_bad and #midi_input_bad > 0 then
      if (S.midi_input_validator_retries or 0) < 1 then
        S.midi_input_retry_used = true
        S.midi_input_validator_retries =
          (S.midi_input_validator_retries or 0) + 1
        local kinds = {}
        for _, issue in ipairs(midi_input_bad) do
          kinds[#kinds + 1] = tostring(issue.kind or "unknown")
        end
        Log.line("MIDI-INPUT-VALIDATOR",
          "unsafe/incomplete MIDI input filter (" .. tbl_concat(kinds, ", ")
          .. "); retrying with grounded input-routing constraint")
        local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
          .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: The user asked "
          .. "for MIDI input-device filtering, such as all MIDI inputs "
          .. "except one named device, or only one named MIDI device. "
          .. "Your previous Lua used an unsupported/incomplete shape: "
          .. tbl_concat(kinds, ", ") .. ". REAPER track I_RECINPUT can "
          .. "select one physical MIDI input or all physical MIDI inputs. "
          .. "It cannot represent all MIDI devices except X as one track "
          .. "input. Do NOT use P_MIDI_MAP, a comma-separated device map, "
          .. "or 4096+256. For one named physical device, enumerate "
          .. "reaper.GetMIDIInputName and match the device NAME "
          .. "case-insensitively with substring tolerance, then set "
          .. "I_RECINPUT = 4096 + (device_index * 32) + channel, where "
          .. "channel is an integer 0..16, and channel 0 means all "
          .. "channels. For an all-except request, either create helper "
          .. "input tracks for the allowed device names and route their "
          .. "MIDI to the target track, or explain that the direct "
          .. "single-track all-except setting is not scriptable and offer "
          .. "that helper-track workaround. If you create helper tracks, "
          .. "skip devices by NAME match every run, not by hard-coded "
          .. "index, because REAPER device indexes can change after "
          .. "hot-plug or restart. Respond as if this is your FIRST "
          .. "reply -- do NOT apologize, do NOT mention a "
          .. "retry.)\n\nPrevious Lua to fix:\n```lua\n"
          .. lua_code
          .. "\n```\n\nUSER REQUEST:\n" .. (S.pending_orig_prompt or "")
        Net.fire_validator_retry({
          kind = "midi_input_exclusion",
          history_content = history_content,
          ctx_label = "midi_input_retry",
          retry_failed_key = "retry.reason.after_midi_input_routing_issue",
          retry_failed_label = "after MIDI input routing issue",
          failure_message = "Auto-retry after MIDI input routing issue did not go through. Please resend the last message.",
        })
        return
      end
      midi_input_gate_hit = true
      validator_gate_hit = true
      local semantic_only = false
      local kinds = {}
      for _, issue in ipairs(midi_input_bad) do
        kinds[#kinds + 1] = tostring(issue.kind or "unknown")
        if issue.kind == "inspection_only" then semantic_only = true end
      end
      local block_debug = {
        failure_kind = semantic_only
          and "semantic_incomplete" or "validator_blocked",
        source = "midi_input_device_filter_validator",
        validation_block_kind = "midi_input_validator",
        findings = kinds,
        generated_code_bytes = type(lua_code) == "string" and #lua_code or 0,
      }
      Log.line("MIDI-INPUT-VALIDATOR",
        "MIDI input filtering issue persisted after retry; auto-run blocked: "
        .. tbl_concat(kinds, ", "))
      Log.add_error((RA and RA.t and RA.t(
        "validator.midi_input_filter_blocked", nil,
        "The script does not safely implement the requested MIDI "
          .. "input-device filter. REAPER cannot encode 'all MIDI devices "
          .. "except one named device' as a single track I_RECINPUT value, and "
          .. "the generated Lua still uses an unsupported map or only lists "
          .. "devices. Auto-run is blocked; use a name-matched helper-track "
          .. "workaround or set a single named input directly."))
        or "The script does not safely implement the requested MIDI input-device filter. REAPER cannot encode 'all MIDI devices except one named device' as a single track I_RECINPUT value, and the generated Lua still uses an unsupported map or only lists devices. Auto-run is blocked; use a name-matched helper-track workaround or set a single named input directly.",
        nil, nil, nil,
        { error_kind = semantic_only and "semantic_incomplete"
            or "validator_blocked",
          error_debug = block_debug })
      if S.history[_asst_hist_idx] then
        S.history[_asst_hist_idx].run_status = semantic_only
          and "semantic_incomplete" or "blocked_midi_input_validator"
        S.history[_asst_hist_idx].validation_status = "blocked"
        S.history[_asst_hist_idx].validation_block_kind =
          "midi_input_validator"
        S.history[_asst_hist_idx].error_kind = semantic_only
          and "semantic_incomplete" or "validator_blocked"
        S.history[_asst_hist_idx].error_debug = block_debug
        S.history[_asst_hist_idx].code_bytes = #lua_code
        S.history[_asst_hist_idx].code_type  = "lua"
      end
    end
  end

  -- ACTION-ID VALIDATOR: Main_OnCommand accepts any integer, so guessed
  -- native action IDs pass the API-name validator and then silently do the
  -- wrong thing or nothing at all. Allow only literal IDs from the documented
  -- common-action list, or IDs the user explicitly provided.
  local action_gate_hit = false
  if lua_code and not docs_gate_hit and not validator_gate_hit then
    local action_user_text = Net.retry_user_request_context()
    local action_bad = Code.find_unverified_main_oncommand_ids(
      lua_code, action_user_text)
    if action_bad and #action_bad > 0 then
      if (S.action_validator_retries or 0) < 1 then
        S.action_validator_retries = (S.action_validator_retries or 0) + 1
        local lines, summary = {}, {}
        for _, e in ipairs(action_bad) do
          lines[#lines + 1] = "  - line " .. tostring(e.line) .. ": reaper."
            .. e.fn .. "(" .. tostring(e.id) .. ", ...)"
          summary[#summary + 1] = e.fn .. "(" .. tostring(e.id) .. ")"
        end
        Log.line("ACTION-VALIDATOR",
          "unverified numeric Main_OnCommand ID(s) (" .. #action_bad
          .. "): " .. tbl_concat(summary, ", ")
          .. "; retrying with hint (user-invisible)")
        local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT MENTION "
          .. "ANY OF THIS IN YOUR VISIBLE REPLY: Your previous reply passed "
          .. "literal numeric REAPER action ID(s) to Main_OnCommand / "
          .. "Main_OnCommandEx that are NOT in the documented common-action "
          .. "allowlist and were NOT explicitly provided by the user:\n"
          .. tbl_concat(lines, "\n") .. "\n\n"
          .. "Do not guess native numeric action IDs. Use direct REAPER API "
          .. "calls when possible. For native built-in actions that are not "
          .. "in the common-action allowlist, look them up at runtime by exact "
          .. "Action List text with reaper.SectionFromUniqueID(0) plus "
          .. "reaper.kbd_enumerateActions(...), then call Main_OnCommand with "
          .. "the returned variable. Use reaper.NamedCommandLookup only for "
          .. "named SWS/extension/custom actions. For drum-hit/transient "
          .. "stretch-marker requests, prefer REAPER's Dynamic Split / "
          .. "transient-detection action via Action List lookup; do NOT "
          .. "substitute a simple Lua energy-threshold detector unless the "
          .. "user explicitly asked for a custom approximation. If the exact "
          .. "native action cannot be found by text in the provided context, "
          .. "ask the user to confirm it instead of emitting runnable code "
          .. "with a guessed ID. Respond as if this is your FIRST reply -- "
          .. "do NOT apologize, do NOT mention a retry.)\n\n"
          .. "USER REQUEST:\n" .. action_user_text
        Net.fire_validator_retry({
          kind = "action",
          history_content = history_content,
          ctx_label = "action_retry",
          retry_failed_key = "retry.reason.for_unverified_main_oncommand_ids",
          retry_failed_label = "for unverified Main_OnCommand ID(s)",
          failure_message = "Auto-retry for unverified Main_OnCommand ID(s) did not go through. Please resend the last message.",
        })
        return
      end
      action_gate_hit = true
      -- Keep older chained validator guards suppressed without touching every
      -- downstream condition; _any_gate_hit below also includes action_gate_hit.
      validator_gate_hit = true
      local user_lines = {}
      for _, e in ipairs(action_bad) do
        user_lines[#user_lines + 1] = "reaper." .. e.fn .. "("
          .. tostring(e.id) .. ", ...) at line " .. tostring(e.line)
      end
      Log.line("ACTION-VALIDATOR",
        "unverified numeric Main_OnCommand ID(s) persist after retry: "
        .. tbl_concat(user_lines, "; ") .. "; auto-run blocked")
      Log.add_error((RA and RA.t and RA.t(
        "validator.action_id_blocked",
        { ids = tbl_concat(user_lines, "; ") },
        "The model emitted unverified numeric REAPER action ID(s), "
          .. "even after a retry: " .. tbl_concat(user_lines, "; ")
          .. ". Main_OnCommand accepts any integer, so this can silently run "
          .. "the wrong action or do nothing. Auto-run is blocked; confirm the "
          .. "exact Action List ID or rewrite the script with direct REAPER API "
          .. "calls before running it."))
        or ("The model emitted unverified numeric REAPER action ID(s), even after a retry: "
          .. tbl_concat(user_lines, "; ")
          .. ". Main_OnCommand accepts any integer, so this can silently run the wrong action or do nothing. Auto-run is blocked; confirm the exact Action List ID or rewrite the script with direct REAPER API calls before running it."))
    end
  end

  -- TEMPO-MARKER VALIDATOR: For "move this bar/beat line to the
  -- transient/edit cursor" prompts, inserting a marker at the bar's existing
  -- TimeMap2_beatsToTime position with measurepos/beatpos left at -1 does not
  -- move the bar line. Retry with the correct anchor-at-target-time shape.
  local tempo_marker_gate_hit = false
  if lua_code and not docs_gate_hit and not validator_gate_hit then
    local tempo_marker_user_text = Net.retry_user_request_context()
    local tempo_marker_bad = Code.find_bad_tempo_marker_alignment_scripts(
      lua_code, tempo_marker_user_text)
    if tempo_marker_bad and #tempo_marker_bad > 0 then
      if (S.tempo_marker_validator_retries or 0) < 1 then
        S.tempo_marker_validator_retries =
          (S.tempo_marker_validator_retries or 0) + 1
        local lines = {}
        for _, e in ipairs(tempo_marker_bad) do
          local source = e.source_line
            and (" (time from line " .. tostring(e.source_line) .. ")") or ""
          lines[#lines + 1] = "  - line " .. tostring(e.line) .. source
        end
        Log.line("TEMPO-MARKER-VALIDATOR",
          "tempo marker inserted at old bar/beat position for alignment prompt ("
          .. #tempo_marker_bad .. " finding(s)); retrying with hint "
          .. "(user-invisible)")
        local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT MENTION "
          .. "ANY OF THIS IN YOUR VISIBLE REPLY: Your previous reply tried to "
          .. "move a bar/beat line to the transient or edit cursor by computing "
          .. "the bar's existing time with TimeMap2_beatsToTime, then calling "
          .. "SetTempoTimeSigMarker with that old time and measurepos/beatpos "
          .. "left at -1. That inserts a marker at the bar's current position "
          .. "and does not anchor the bar/beat to the transient.\n\n"
          .. "Affected SetTempoTimeSigMarker line(s):\n"
          .. tbl_concat(lines, "\n") .. "\n\n"
          .. "Regenerate using the correct branch for the user's intent. If "
          .. "the user wants a bar/beat line moved onto a position, make a "
          .. "real tempo-map edit: calculate the tempo for the preceding span "
          .. "so the target measure/beat lands at the cursor or transient, "
          .. "then update/insert that preceding tempo marker. Do not call "
          .. "SetTempoTimeSigMarker with both target_time and measure/beat "
          .. "values; that API uses either a time position with "
          .. "measurepos=-1/beatpos=-1, or a measure/beat position with "
          .. "timepos=-1. If the user only wants a new tempo marker at a free "
          .. "time position without moving a bar/beat, then "
          .. "measurepos=-1 and beatpos=-1 are valid. If the project already "
          .. "has tempo changes inside the span you would need to retime, ask "
          .. "before editing the tempo map. Do not guess action IDs; for "
          .. "action workflows, look up exact Action List text at runtime or "
          .. "ask the user to confirm. Respond as if this is your FIRST reply "
          .. "-- do NOT apologize, do NOT mention a retry.)\n\n"
          .. "USER REQUEST:\n" .. tempo_marker_user_text
        Net.fire_validator_retry({
          kind = "tempo_marker",
          history_content = history_content,
          ctx_label = "tempo_marker_retry",
          retry_failed_key = "retry.reason.for_tempo_marker_bar_alignment",
          retry_failed_label = "for tempo-marker bar alignment",
          failure_message = "Auto-retry for tempo-marker bar alignment did not go through. Please resend the last message.",
        })
        return
      end
      tempo_marker_gate_hit = true
      validator_gate_hit = true
      Log.line("TEMPO-MARKER-VALIDATOR",
        "tempo marker old-bar insertion persisted after retry; auto-run blocked")
      Log.add_error((RA and RA.t and RA.t(
        "validator.tempo_marker_alignment_blocked", nil,
        "The model tried to align a bar/beat line to the cursor "
          .. "by inserting a tempo marker at the bar's existing position even "
          .. "after a retry. Auto-run is blocked; anchor the intended measure/"
          .. "beat at the edit cursor or transient instead."))
        or "The model tried to align a bar/beat line to the cursor by inserting a tempo marker at the bar's existing position even after a retry. Auto-run is blocked; anchor the intended measure/beat at the edit cursor or transient instead.")
    end
  end

  if lua_code and not docs_gate_hit and not validator_gate_hit
     and type(Code.find_explicit_second_marker_region_misuse) == "function" then
    local explicit_marker_user_text = Net.retry_user_request_context()
    local explicit_marker_bad =
      Code.find_explicit_second_marker_region_misuse(
        lua_code, explicit_marker_user_text)
    if explicit_marker_bad and #explicit_marker_bad > 0 then
      if not S.explicit_seconds_marker_retry_used
         and (S.explicit_seconds_marker_validator_retries or 0) < 1 then
        S.explicit_seconds_marker_retry_used = true
        S.explicit_seconds_marker_validator_retries =
          (S.explicit_seconds_marker_validator_retries or 0) + 1
        local details = {}
        for _, e in ipairs(explicit_marker_bad) do
          details[#details + 1] = tostring(e.kind) .. " " .. tostring(e.name)
