        local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT MENTION "
          .. "ANY OF THIS IN YOUR VISIBLE REPLY: Your previous reply tried to "
          .. "quantize/edit drums by writing media-item D_POSITION values. "
          .. "That treats item starts as drum hits, can do nothing when item "
          .. "starts are already on-grid, and is not the requested "
          .. "phase-safe drum editing workflow.\n\n"
          .. "Affected whole-item position write line(s):\n"
          .. tbl_concat(lines, "\n") .. "\n\n"
          .. "Regenerate without moving whole media items unless the user "
          .. "explicitly asked for whole-item movement. Use explicit guide "
          .. "track/item hit points and apply one shared source-time -> "
          .. "target-time timing map to all drum items with stretch markers. "
          .. "Prefer REAPER's Dynamic Split / transient engine or existing "
          .. "guide stretch markers. For every grouped drum item overlapping "
          .. "a guide hit, insert or move a stretch marker at the same "
          .. "original project time and move it to the same snapped project "
          .. "time, preserving srcpos when moving existing markers. Count "
          .. "only real changes where abs(new_pos - old_pos) is greater than "
          .. "a tiny tolerance; do not report attempted writes as moved. If "
          .. "you cannot safely create/identify guide hit points, ask the user "
          .. "to run/open Dynamic Split or confirm the action path instead of "
          .. "emitting a no-op script. Respond as if this is your FIRST reply "
          .. "-- do NOT apologize, do NOT mention a retry.)\n\n"
          .. "USER REQUEST:\n" .. drum_quantize_user_text
        Net.fire_validator_retry({
          kind = "drum_quantize",
          history_content = history_content,
          ctx_label = "drum_quantize_retry",
          retry_failed_key = "retry.reason.for_whole_item_drum_quantize",
          retry_failed_label = "for whole-item drum quantize",
          failure_message = "Auto-retry for whole-item drum quantize did not go through. Please resend the last message.",
        })
        return
      end
      drum_quantize_gate_hit = true
      validator_gate_hit = true
      Log.line("DRUM-QUANTIZE-VALIDATOR",
        "whole-item D_POSITION write for drum quantize/edit persisted after "
        .. "retry; auto-run blocked")
      Log.add_error((RA and RA.t and RA.t(
        "validator.drum_whole_item_quantize_blocked", nil,
        "The model tried to quantize/edit drums by moving whole "
          .. "media items even after a retry. That can do nothing or move the "
          .. "wrong musical material. Auto-run is blocked; use a shared "
          .. "guide-track stretch-marker timing map instead."))
        or "The model tried to quantize/edit drums by moving whole media items even after a retry. That can do nothing or move the wrong musical material. Auto-run is blocked; use a shared guide-track stretch-marker timing map instead.")
    end
  end

  -- DRUM-MARKER-SYNC VALIDATOR: A drum stretch-marker script that does not
  -- normalize the marker set in the edit range can leave guide tracks with
  -- extra Dynamic Split markers and non-guide tracks with a different map,
  -- causing phase and stretch-ratio mismatches.
  local drum_marker_sync_gate_hit = false
  if lua_code and not docs_gate_hit and not validator_gate_hit then
    local drum_marker_sync_user_text = Net.retry_user_request_context()
    local drum_marker_sync_bad =
      Code.find_unsynced_drum_stretch_marker_scripts(
        lua_code, drum_marker_sync_user_text)
    if drum_marker_sync_bad and #drum_marker_sync_bad > 0 then
      if (S.drum_marker_sync_validator_retries or 0) < 1 then
        S.drum_marker_sync_validator_retries =
          (S.drum_marker_sync_validator_retries or 0) + 1
        local lines = {}
        for _, e in ipairs(drum_marker_sync_bad) do
          lines[#lines + 1] = "  - line " .. tostring(e.line)
        end
        Log.line("DRUM-MARKER-SYNC-VALIDATOR",
          "drum stretch-marker script lacked range normalization ("
          .. #drum_marker_sync_bad .. " finding(s)); retrying with hint "
          .. "(user-invisible)")
        local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT MENTION "
          .. "ANY OF THIS IN YOUR VISIBLE REPLY: Your previous reply added or "
          .. "moved drum stretch markers without first normalizing the marker "
          .. "set across every affected drum item. This can leave guide tracks "
          .. "with extra Dynamic Split markers while non-guide tracks get a "
          .. "different marker map, creating phase drift and extreme stretch "
          .. "ratios.\n\n"
          .. "Affected SetTakeStretchMarker line(s):\n"
          .. tbl_concat(lines, "\n") .. "\n\n"
          .. "Regenerate so the final marker set is identical on every "
          .. "affected drum item, including guide tracks. Guide tracks are "
          .. "analysis sources only. After deriving the guide source-time -> "
          .. "target-time map, delete/replace stretch markers in the edit "
          .. "range on every affected item, then insert the same sorted, "
          .. "de-duplicated map plus unchanged boundary anchors. Compute each "
          .. "marker as pos = target_project_time - item_position and srcpos "
          .. "= source_project_time - item_position; do not preserve arbitrary "
          .. "existing guide-track srcpos. Merge/skip hits whose snapped target "
          .. "times collide or cross. If the user did not authorize replacing "
          .. "markers in the range, ask one question instead of emitting code. "
          .. "Respond as if this is your FIRST reply -- do NOT apologize, do "
          .. "NOT mention a retry.)\n\n"
          .. "USER REQUEST:\n" .. drum_marker_sync_user_text
        Net.fire_validator_retry({
          kind = "drum_marker_sync",
          history_content = history_content,
          ctx_label = "drum_marker_sync_retry",
          retry_failed_key = "retry.reason.for_unsynchronized_drum_stretch_markers",
          retry_failed_label = "for unsynchronized drum stretch markers",
          failure_message = "Auto-retry for unsynchronized drum stretch markers did not go through. Please resend the last message.",
        })
        return
      end
      drum_marker_sync_gate_hit = true
      validator_gate_hit = true
      Log.line("DRUM-MARKER-SYNC-VALIDATOR",
        "drum stretch-marker script without range normalization persisted "
        .. "after retry; auto-run blocked")
      Log.add_error((RA and RA.t and RA.t(
        "validator.drum_marker_sync_blocked", nil,
        "The model tried to write drum stretch markers without "
          .. "normalizing the same marker map across every affected drum item. "
          .. "Auto-run is blocked; the final stretch markers must be identical "
          .. "on guide and non-guide tracks."))
        or "The model tried to write drum stretch markers without normalizing the same marker map across every affected drum item. Auto-run is blocked; the final stretch markers must be identical on guide and non-guide tracks.")
    end
  end

  -- ARITY VALIDATOR: After the API validator passes, scan high-confidence
  -- fixed-arity calls (TrackFX_SetParamNormalized, etc.) for wrong arg
  -- counts. Catches a class the API validator can't: the NAME is real, but
  -- the call was emitted with the wrong number of arguments -- often a
  -- model dropping the param-index and passing a value where pidx belongs,
  -- which crashes inside reaper.defer with "bad argument #N (number has no
  -- integer representation)". Same recovery shape as the other validators.
  local arity_gate_hit = false
  if lua_code and not docs_gate_hit and not validator_gate_hit then
    local arity_bad = Code.find_reaper_arity_mismatches(lua_code) or {}
    local marker2_isrgn_bad = type(Code.find_addprojectmarker2_isrgn_misuse) == "function"
      and Code.find_addprojectmarker2_isrgn_misuse(lua_code) or nil
    if marker2_isrgn_bad then
      for _, e in ipairs(marker2_isrgn_bad) do
        arity_bad[#arity_bad + 1] = e
      end
    end
    if arity_bad and #arity_bad > 0 then
      if (S.arity_validator_retries or 0) < 1 then
        S.arity_validator_retries = (S.arity_validator_retries or 0) + 1
        local lines = {}
        for _, e in ipairs(arity_bad) do
          lines[#lines+1] = "  - reaper." .. e.name
            .. " requires " .. e.expected .. "; call site has "
            .. e.got .. "."
        end
        Log.line("ARITY-VALIDATOR",
          "fixed-arity reaper.* calls with wrong arg count ("
          .. #arity_bad .. "): "
          .. (function()
              local names = {}
              for _, e in ipairs(arity_bad) do
                names[#names+1] = e.name .. "(got " .. e.got
                  .. "/expected " .. e.expected .. ")"
              end
              return tbl_concat(names, ", ")
            end)()
          .. "; retrying with hint (user-invisible)")
        local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT MENTION "
          .. "ANY OF THIS IN YOUR VISIBLE REPLY: Your previous reply called "
          .. "REAPER API function(s) with the WRONG number of arguments. "
          .. "These would crash at runtime:\n"
          .. tbl_concat(lines, "\n") .. "\n\n"
          .. "Common cause: dropping a required argument from a fixed "
          .. "signature call. Examples: `reaper.SetCurrentBPM(project, "
          .. "bpm, wantUndo)` has 3 args; "
          .. "`reaper.GetSetMediaTrackInfo_String(track, parmname, "
          .. "value, setNewValue)` has 4 args; "
          .. "`reaper.AddProjectMarker2(project, isrgn, pos, rgnend, "
          .. "name, wantidx, color)` has 7 args; pass `0` for the default "
          .. "marker color, and pass `false` as the second arg for a point "
          .. "marker (`true` only for regions); or use `AddProjectMarker` "
          .. "with 6 args; "
          .. "`reaper.TrackFX_SetParamNormalized(track, fx_index, "
          .. "param_index, value)` has 4 args. Check the API reference "
          .. "for the correct signature and regenerate the code. If docs, "
          .. "midi, session, or prompt bundles are already pinned above, "
          .. "use them now; do NOT request context again. Respond as if "
          .. "this is your FIRST reply -- do NOT apologize, do NOT mention "
          .. "a retry.)\n\n"
          .. "Previous Lua to fix:\n```lua\n"
          .. lua_code
          .. "\n```\n\n"
          .. "USER REQUEST:\n" .. (S.pending_orig_prompt or "")
        Net.fire_validator_retry({
          kind = "arity",
          history_content = history_content,
          ctx_label = "arity_retry",
          retry_failed_key = "retry.reason.for_reaper_arity_mismatch",
          retry_failed_label = "for reaper.* arity mismatch",
          failure_message = "Auto-retry for reaper.* arity mismatch did not go through. Please resend the last message.",
        })
        return
      end
      arity_gate_hit = true
      Log.line("ARITY-VALIDATOR",
        "fixed-arity reaper.* calls with wrong arg count persist after "
        .. "retry; auto-run blocked")
      local user_lines = {}
      for _, e in ipairs(arity_bad) do
        user_lines[#user_lines+1] = "reaper." .. e.name .. " (got "
          .. e.got .. ", expected " .. e.expected .. ")"
      end
      Log.add_error((RA and RA.t and RA.t(
        "validator.reaper_arity_blocked",
        { calls = tbl_concat(user_lines, "; ") },
        "The model emitted REAPER API call(s) with the wrong "
          .. "number of arguments, even after a retry: "
          .. tbl_concat(user_lines, "; ")
          .. ". Auto-run is blocked; review and edit the code before clicking "
          .. "Run manually."))
        or ("The model emitted REAPER API call(s) with the wrong number of arguments, even after a retry: "
          .. tbl_concat(user_lines, "; ")
          .. ". Auto-run is blocked; review and edit the code before clicking Run manually."))
    end
  end

  -- MEDIA-ITEM LABEL VALIDATOR: visible arrange item labels live on takes,
  -- not MediaItems. A script that writes MediaItem P_NAME can appear to
  -- "label" chord-chart items in prose while leaving the arrange view blank.
  -- Retry once with the concrete AddTakeToMediaItem / take-name sequence.
  local media_item_label_gate_hit = false
  if lua_code and not docs_gate_hit and not validator_gate_hit
     and not arity_gate_hit then
    local label_bad = Code.find_media_item_p_name_misuse(lua_code)
    if label_bad and #label_bad > 0 then
      if (S.media_item_label_validator_retries or 0) < 1 then
        S.media_item_label_validator_retries =
          (S.media_item_label_validator_retries or 0) + 1
        S.media_item_label_retry_used = true
        Log.line("MEDIA-ITEM-LABEL-VALIDATOR",
          "MediaItem P_NAME used for visible item label; retrying with hint")
        local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
          .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: Your previous reply "
          .. "called reaper.GetSetMediaItemInfo_String(item, \"P_NAME\", ...). "
          .. "MediaItem string params do not include P_NAME; they accept "
          .. "P_NOTES, P_EXT:..., and GUID. Visible arrange item labels live "
          .. "on the active take. If you create a plain item with "
          .. "reaper.AddMediaItemToTrack(item_track), call "
          .. "reaper.AddTakeToMediaItem(item), then name that returned take "
          .. "with reaper.GetSetMediaItemTakeInfo_String(take, \"P_NAME\", "
          .. "label, true). If you create a MIDI item with "
          .. "reaper.CreateNewMIDIItemInProj(track, start, finish, false), "
          .. "get its active take and name the take. Preserve the user's "
          .. "requested item labels, timing, colors, track names, and ordering. "
          .. "Respond as if this is your FIRST reply -- do NOT apologize, do "
          .. "NOT mention a retry.)\n\n"
          .. "Previous Lua to fix:\n```lua\n"
          .. lua_code
          .. "\n```\n\nUSER REQUEST:\n" .. (S.pending_orig_prompt or "")
        Net.fire_validator_retry({
          kind = "media_item_label",
          history_content = history_content,
          ctx_label = "media_item_label_retry",
          retry_failed_key = "retry.reason.for_media_item_label_misuse",
          retry_failed_label = "for MediaItem item-label misuse",
          failure_message = "Auto-retry for MediaItem item-label misuse did not go through. Please resend the last message.",
        })
        return
      end
      media_item_label_gate_hit = true
      validator_gate_hit = true
      Log.line("MEDIA-ITEM-LABEL-VALIDATOR",
        "MediaItem P_NAME persisted after retry; auto-run blocked")
      Log.add_error((RA and RA.t and RA.t(
        "validator.media_item_label_blocked", nil,
        "The script tries to label MediaItems with P_NAME. "
          .. "Auto-run is blocked because MediaItem string params accept only "
          .. "P_NOTES/P_EXT/GUID; visible arrange labels live on the take. "
          .. "Use AddTakeToMediaItem or CreateNewMIDIItemInProj, then call "
          .. "GetSetMediaItemTakeInfo_String(take, \"P_NAME\", label, true)."))
        or "The script tries to label MediaItems with P_NAME. Auto-run is blocked because MediaItem string params accept only P_NOTES/P_EXT/GUID; visible arrange labels live on the take. Use AddTakeToMediaItem or CreateNewMIDIItemInProj, then call GetSetMediaItemTakeInfo_String(take, \"P_NAME\", label, true).")
    end
  end

  -- SEND-INDEX VALIDATOR: CreateTrackSend returns the new send index.
  -- If the model ignores that return value and later uses hard-coded
  -- send indices while setting send properties, it can silently set the
  -- wrong send when multiple sends exist on the same source track. Same
  -- recovery shape as the other validators: one hidden retry, then block
  -- auto-run if the pattern persists.
  local sendidx_gate_hit = false
  if lua_code and not docs_gate_hit and not validator_gate_hit
     and not arity_gate_hit and not media_item_label_gate_hit then
    local sendidx_bad = Code.find_untracked_createtracksend_results(lua_code)
    if sendidx_bad and #sendidx_bad > 0 then
      if (S.sendidx_validator_retries or 0) < 1 then
        S.sendidx_validator_retries =
          (S.sendidx_validator_retries or 0) + 1
        local lines = {}
        for _, e in ipairs(sendidx_bad) do
          if e.kind == "multi_assign" then
            lines[#lines+1] = "  - line " .. tostring(e.create_line)
              .. " assigns CreateTrackSend with multiple return variables (`"
              .. tostring(e.sendidx) .. "`), but it returns one integer"
          elseif e.kind == "duplicate" then
            lines[#lines+1] = "  - lines " .. tostring(e.create_line)
              .. " and " .. tostring(e.set_line)
              .. " both create a send from `" .. tostring(e.source)
              .. "` to `" .. tostring(e.dest) .. "`"
          elseif e.kind == "zero_check" then
            lines[#lines+1] = "  - line " .. tostring(e.set_line)
              .. " treats returned send index `" .. tostring(e.sendidx)
              .. "` as failed when it is 0, but the first valid send index is 0"
          else
            lines[#lines+1] = "  - source `" .. tostring(e.source)
              .. "` uses literal send index " .. tostring(e.sendidx)
              .. " after an ignored CreateTrackSend result"
          end
        end
        Log.line("SENDIDX-VALIDATOR",
          "unsafe CreateTrackSend result handling ("
          .. #sendidx_bad .. "); retrying with hint (user-invisible)")
        local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT MENTION "
          .. "ANY OF THIS IN YOUR VISIBLE REPLY: Your previous reply called "
          .. "reaper.CreateTrackSend(...) with unsafe return-value handling. "
          .. "CreateTrackSend returns exactly ONE value: the new send index. "
          .. "It does NOT return `ok, sendidx`, so `local _, sidx = "
          .. "reaper.CreateTrackSend(...)` makes sidx nil. It is also unsafe "
          .. "to ignore the return value and later use hard-coded send indices. "
          .. "Do not call CreateTrackSend twice for the same source and "
          .. "destination unless the user explicitly asked for duplicate sends. "
          .. "A returned send index of 0 is valid for the first send; only -1 "
          .. "means failure. "
          .. "You MUST store the one returned integer and use it when setting "
          .. "send attributes.\n\n"
          .. "Affected send property call(s):\n"
          .. tbl_concat(lines, "\n") .. "\n\n"
          .. "Use this pattern:\n"
          .. "  local sidx = reaper.CreateTrackSend(src, dst)\n"
          .. "  if sidx >= 0 then\n"
          .. "    reaper.SetTrackSendInfo_Value(src, 0, sidx, \"D_VOL\", amp)\n"
          .. "  end\n\n"
          .. "Regenerate the code with every configured send using its own "
          .. "returned send index variable. Respond as if this is your FIRST "
          .. "reply -- do NOT apologize, do NOT mention a retry.)\n\n"
          .. "USER REQUEST:\n" .. (S.pending_orig_prompt or "")
        Net.fire_validator_retry({
          kind = "sendidx",
          history_content = history_content,
          ctx_label = "sendidx_retry",
          retry_failed_key = "retry.reason.for_ignored_createtracksend_result",
          retry_failed_label = "for ignored CreateTrackSend result",
          failure_message = "Auto-retry for ignored CreateTrackSend result did not go through. Please resend the last message.",
        })
        return
      end
      sendidx_gate_hit = true
      Log.line("SENDIDX-VALIDATOR",
        "unsafe CreateTrackSend result handling persists after retry; auto-run blocked")
      local user_lines = {}
      for _, e in ipairs(sendidx_bad) do
        if e.kind == "multi_assign" then
          user_lines[#user_lines+1] =
            "line " .. tostring(e.create_line)
            .. " uses multiple assignment for CreateTrackSend"
        elseif e.kind == "zero_check" then
          user_lines[#user_lines+1] =
            "line " .. tostring(e.set_line)
            .. " rejects valid send index 0"
        else
          user_lines[#user_lines+1] = tostring(e.source)
            .. " send index " .. tostring(e.sendidx)
        end
      end
      Log.add_error((RA and RA.t and RA.t(
        "validator.send_index_blocked",
        { details = tbl_concat(user_lines, "; ") },
        "The model created sends with unsafe CreateTrackSend "
          .. "return-value handling, even after a retry: "
          .. tbl_concat(user_lines, "; ")
          .. ". Auto-run is blocked; review and edit the code before clicking "
          .. "Run manually."))
        or ("The model created sends with unsafe CreateTrackSend return-value handling, even after a retry: "
          .. tbl_concat(user_lines, "; ")
          .. ". Auto-run is blocked; review and edit the code before clicking Run manually."))
    end
  end

  -- TIMECODE-WORKFLOW VALIDATOR: native timecode generator actions are
  -- selection-sensitive, and hardware output sends use category 1. Catch the
  -- common partial-success shape where the item lands on one track while the
  -- script routes an empty helper track, or where category 0 leaves the
  -- hardware send on its default output pair.
  local timecode_workflow_gate_hit = false
  if lua_code and not docs_gate_hit and not validator_gate_hit
     and not arity_gate_hit and not media_item_label_gate_hit
     and not sendidx_gate_hit then
    local workflow_bad = Code.find_timecode_generator_workflow_misuse(
      lua_code, S.pending_orig_prompt or "")
    if workflow_bad and #workflow_bad > 0 then
      if (S.timecode_workflow_validator_retries or 0) < 1 then
        S.timecode_workflow_validator_retries =
          (S.timecode_workflow_validator_retries or 0) + 1
        local lines = {}
        for _, e in ipairs(workflow_bad) do
          if e.kind == "hardware_category" then
            lines[#lines + 1] = "  - line " .. tostring(e.set_line)
              .. " sets hardware send `" .. tostring(e.sendidx)
              .. "` with category 0; hardware outputs require category 1"
          elseif e.kind == "route_before_action" then
            lines[#lines + 1] = "  - line " .. tostring(e.line)
              .. " routes a track before the native timecode action runs"
          elseif e.kind == "precreated_track_before_timecode_action" then
            lines[#lines + 1] = "  - line " .. tostring(e.line)
              .. " creates a helper target track before the native timecode "
              .. "action; the native action can create/use a separate item "
              .. "track, leaving a blank extra track behind"
          elseif e.kind == "missing_generated_item_track_detection" then
            lines[#lines + 1] = "  - line " .. tostring(e.line)
              .. " routes the pre-created track without first detecting which "
              .. "track actually received the native timecode generator item"
          elseif e.kind == "precreated_track_without_item_move" then
            lines[#lines + 1] = "  - line " .. tostring(e.line)
              .. " detects the generated item track but leaves the item on "
              .. "that track instead of moving it onto the pre-created target "
              .. "track before routing"
          elseif e.kind == "missing_exclusive_selection" then
            lines[#lines + 1] = "  - line " .. tostring(e.line)
              .. " runs the native timecode action without first selecting "
              .. "only the intended target track"
          elseif e.kind == "overconstrained_action_lookup" then
            lines[#lines + 1] = "  - line " .. tostring(e.line)
              .. " requires timecode plus generator plus SMPTE/LTC/MTC in "
              .. "one action-name match; that can miss REAPER's native "
              .. "timecode generator action"
          else
            lines[#lines + 1] = "  - line "
              .. tostring(e.line or e.set_line or "?")
              .. ": unsafe native timecode generator workflow"
          end
        end
        Log.line("TIMECODE-WORKFLOW-VALIDATOR",
          "unsafe native timecode workflow (" .. #workflow_bad
          .. "); retrying with track/send hint (user-invisible)")
        local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
          .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: The user asked for "
          .. "a native SMPTE/LTC/MTC timecode generator routed only to "
          .. "hardware outputs 3 and 4. Your previous reply used an unsafe "
          .. "native workflow:\n"
          .. tbl_concat(lines, "\n") .. "\n\n"
          .. "Regenerate the FULL Lua script with these exact requirements:\n"
          .. "1. Do NOT use TrackFX_AddByName/TakeFX_AddByName; this is not "
          .. "an FX plugin.\n"
          .. "2. Do NOT create a helper/target track before running the "
          .. "native timecode-generator action. For this standalone insert "
          .. "request, let the native action create or choose the generator "
          .. "item track, then rename and route that actual track. A "
          .. "pre-created helper track can be left blank.\n"
          .. "3. Find the native action with broad fallback pairs: first "
          .. "try an action whose text contains `timecode` and `generator`; "
          .. "if not found, try `smpte` and `generator`; then try "
          .. "`ltc`/`mtc` and `generator`. Do NOT require `timecode`, "
          .. "`generator`, and `smpte`/`ltc`/`mtc` all in the same match, "
          .. "because REAPER action names vary by install/localization.\n"
          .. "4. Run the verified native timecode generator action, then "
          .. "detect which track actually received the generated timecode "
          .. "item. Prefer `local item = reaper.GetSelectedMediaItem(0, 0)` "
          .. "immediately after Main_OnCommand, then "
          .. "`generator_track = item and reaper.GetMediaItemTrack(item)`. "
          .. "A before/after item-count fallback is allowed only if it "
          .. "ultimately resolves a specific MediaItem with GetMediaItemTrack. "
          .. "Do NOT use source filenames to identify the item, and do NOT "
          .. "fall back to the pre-created target track unless that exact "
          .. "track demonstrably received the new item. If you cannot detect "
          .. "the item track, show an error and return before routing.\n"
          .. "5. Route the detected `generator_track` and optionally rename "
          .. "that track. Do not create, route, or leave behind a blank helper "
          .. "target track.\n"
          .. "6. For the hardware output send, use:\n"
          .. "   local sidx = reaper.CreateTrackSend(generator_track, nil)\n"
          .. "   if sidx < 0 then ... return end\n"
          .. "   reaper.SetTrackSendInfo_Value(generator_track, 1, sidx, "
          .. "\"I_SRCCHAN\", 0)\n"
          .. "   reaper.SetTrackSendInfo_Value(generator_track, 1, sidx, "
          .. "\"I_DSTCHAN\", 2)\n"
          .. "Category 1 is required because nil destination creates a "
          .. "hardware output. Category 0 is only for normal track-to-track "
          .. "sends and will leave the hardware send at its default 1/2 "
          .. "destination.\n"
          .. "7. Disable `B_MAINSEND` on the generator track so it does not "
          .. "also feed the master/main outputs.\n\n"
          .. "Respond as if this is your FIRST reply -- do NOT apologize, do "
          .. "NOT mention a retry.)\n\n"
          .. "USER REQUEST:\n" .. (S.pending_orig_prompt or "")
        Net.fire_validator_retry({
          kind = "timecode_workflow",
          history_content = history_content,
          ctx_label = "timecode_workflow_retry",
          retry_failed_key = "retry.reason.for_timecode_generator_workflow_repair",
          retry_failed_label = "for native timecode generator workflow repair",
          failure_message = "Auto-retry for native timecode generator workflow repair did not go through. Please resend the last message.",
        })
        return
      end
      timecode_workflow_gate_hit = true
      Log.line("TIMECODE-WORKFLOW-VALIDATOR",
        "unsafe native timecode workflow persists after retry; auto-run blocked")
      local user_lines = {}
      for _, e in ipairs(workflow_bad) do
        if e.kind == "hardware_category" then
          user_lines[#user_lines + 1] =
            "line " .. tostring(e.set_line)
            .. " uses send category 0 for a hardware output"
        elseif e.kind == "route_before_action" then
          user_lines[#user_lines + 1] =
            "line " .. tostring(e.line)
            .. " routes before the native action creates/inserts the item"
        elseif e.kind == "precreated_track_before_timecode_action" then
          user_lines[#user_lines + 1] =
            "line " .. tostring(e.line)
            .. " creates a helper target track before the native timecode action"
        elseif e.kind == "missing_generated_item_track_detection" then
          user_lines[#user_lines + 1] =
            "line " .. tostring(e.line)
            .. " routes the pre-created track without detecting the generated item track"
        elseif e.kind == "precreated_track_without_item_move" then
          user_lines[#user_lines + 1] =
            "line " .. tostring(e.line)
            .. " detects the item track but does not move the generated item onto the pre-created target track before routing"
        elseif e.kind == "missing_exclusive_selection" then
          user_lines[#user_lines + 1] =
            "line " .. tostring(e.line)
            .. " runs the native action without exclusive target-track selection"
        elseif e.kind == "overconstrained_action_lookup" then
          user_lines[#user_lines + 1] =
            "line " .. tostring(e.line)
            .. " requires too many words in one timecode-generator action lookup"
        end
      end
      Log.add_error((RA and RA.t and RA.t(
        "validator.timecode_generator_workflow_blocked",
        { details = tbl_concat(user_lines, "; ") },
        "The model still did not safely find, insert, or bind the native timecode generator item to the routed hardware-output track, even after a retry: "
          .. tbl_concat(user_lines, "; ")
          .. ". Auto-run is blocked; review the generated action lookup, track selection, and hardware output send category before running manually."))
        or ("The model still did not safely find, insert, or bind the native timecode generator item to the routed hardware-output track, even after a retry: "
          .. tbl_concat(user_lines, "; ")
          .. ". Auto-run is blocked; review the generated action lookup, track selection, and hardware output send category before running manually."))
    end
  end

